function Deps.detect_platform()
  local os_str  = reaper.GetOS() or ""
  local app_ver = reaper.GetAppVersion() or ""
  -- Capture EVERYTHING after the last slash, hyphens included. REAPER's
  -- Linux build labels arch as e.g. "7.20/linux-aarch64", and the
  -- previous /([%w_]+)$ pattern (no hyphens in class) failed to match
  -- the prefixed form -- silently falling through to linux-x64 on ARM.
  local arch = app_ver:match("/([^/]+)$") or ""
  if os_str == "Win64" then
    return arch:find("x86", 1, true) and not arch:find("x86_64", 1, true)
           and "win-x86" or "win-x64"
  elseif os_str == "Win32" then
    return "win-x86"
  elseif os_str == "OSX64" then
    return "mac-x64"
  elseif os_str == "OSX32" then
    return "mac-x86"
  elseif os_str == "macOS-arm64" then
    return "mac-arm64"
  elseif os_str == "Other" then
    -- Substring checks rather than equality so "linux-aarch64",
    -- "aarch64", "linux-armv7l", "armv7l" etc. all map cleanly.
    if     arch:find("aarch64", 1, true) then return "linux-arm64"
    elseif arch:find("armv7",   1, true) then return "linux-arm32"
    elseif arch:find("i686",    1, true) or arch:find("i386", 1, true) then
      return "linux-x86"
    else return "linux-x64"  -- best guess for x86_64 / x64 / unspecified
    end
  end
  return nil
end

function Deps.parse_version(s)
  -- Accepts "v0.10.0.5", "0.10.0.5", "0.10". Returns numeric component table.
  local t = {}
  for n in tostring(s or ""):gsub("^v", ""):gmatch("(%d+)") do
    t[#t + 1] = tonumber(n)
  end
  return t
end

function Deps.cmp_version(a, b)
  -- -1 if a < b, 0 if equal, 1 if a > b. Pads missing components with 0.
  local n = math.max(#a, #b)
  for i = 1, n do
    local ai, bi = a[i] or 0, b[i] or 0
    if ai < bi then return -1 end
    if ai > bi then return  1 end
  end
  return 0
end

function Deps.check_imgui_status()
  -- Returns "ok" | "missing" | "too_old" [, installed_version_string]
  if not reaper.ImGui_CreateContext then return "missing" end
  if not reaper.ImGui_GetVersion    then return "ok" end  -- pre-version-API; assume OK
  local ok, _, _, reaimgui_ver = pcall(reaper.ImGui_GetVersion)
  if not ok or not reaimgui_ver then return "ok" end
  local installed = Deps.parse_version(reaimgui_ver)
  if Deps.cmp_version(installed, Deps.REAIMGUI.min_version_num) < 0 then
    return "too_old", reaimgui_ver
  end
  return "ok"
end

function Deps.check_jsapi_status()
  -- Presence-only check (upstream is frozen at v1.310 since 2021).
  if SupportExtFlag("optoutjsapi") then return "ok" end
  return reaper.JS_ReaScriptAPI_Version and "ok" or "missing"
end

function Deps.check_sws_status()
  -- Returns "ok" | "missing" | "too_old" [, installed_version_string].
  if SupportExtFlag("optoutsws") then return "ok" end
  if not reaper.CF_GetSWSVersion then return "missing" end
  local ok, ver = pcall(reaper.CF_GetSWSVersion)
  if not ok or not ver or ver == "" then
    ok, ver = pcall(reaper.CF_GetSWSVersion, "")
  end
  if not ok or not ver or ver == "" then return "ok" end
  local installed = Deps.parse_version(ver)
  if Deps.cmp_version(installed, Deps.SWS.min_version_num) < 0 then
    return "too_old", ver
  end
  return "ok", ver
end

-- Build the install queue for the current platform. Order: ReaImGui
-- first (UI dependency, blocks anything from rendering), SWS second
-- when REQUIRE_SWS_EXTENSION is enabled (expanded script API surface),
-- JS_API last
-- (file dialogs, only blocks save/attach UX). Each queue item carries
-- everything the install pipeline needs: dep table, asset filename,
-- expected SHA, full destination path under UserPlugins/, and the
-- "kind" of install (missing vs. too_old) for messaging.
--
-- Skips deps whose platform has no upstream binary (e.g. js_ReaScriptAPI
-- on linux-arm64): the script still works on those platforms via the
-- existing fallback paths (GetUserInputs save, no-op attach), so we
-- silently drop the unsupported dep rather than block the install flow.
function Deps.build_queue(platform)
  local queue = {}
  local user_plugins = reaper.GetResourcePath() .. "/UserPlugins/"

  local imgui_status, imgui_ver = Deps.check_imgui_status()
  if imgui_status ~= "ok" then
    local entry = Deps.REAIMGUI.assets[platform]
    if entry then
      queue[#queue + 1] = {
        dep           = Deps.REAIMGUI,
        kind          = imgui_status,             -- "missing" or "too_old"
        installed_ver = imgui_ver,
        asset         = entry[1],
        expected_sha  = entry[2],
        dest_path     = user_plugins .. entry[1],
      }
    end
  end

  if REQUIRE_SWS_EXTENSION and not SupportExtFlag("optoutsws") then
    local sws_status, sws_ver = Deps.check_sws_status()
    if sws_status ~= "ok" then
      local entry = Deps.SWS.assets[platform]
      if entry then
        queue[#queue + 1] = {
          dep           = Deps.SWS,
          kind          = sws_status,             -- "missing" or "too_old"
          installed_ver = sws_ver,
          asset         = entry[1],
          expected_sha  = entry[2],
          dest_path     = user_plugins .. entry[1],
        }
      end
    end
  end

  local jsapi_status = Deps.check_jsapi_status()
  if jsapi_status ~= "ok" then
    local entry = Deps.JSAPI.assets[platform]
    if entry then
      queue[#queue + 1] = {
        dep           = Deps.JSAPI,
        kind          = jsapi_status,             -- always "missing"
        installed_ver = nil,
        asset         = entry[1],
        expected_sha  = entry[2],
        dest_path     = user_plugins .. entry[1],
      }
    end
  end

  return queue
end

function Deps.cleanup_stale_backups(platform)
  if not platform then return end
  local user_plugins = reaper.GetResourcePath() .. "/UserPlugins/"
  local deps = { Deps.REAIMGUI, Deps.SWS, Deps.JSAPI }
  for _, dep in ipairs(deps) do
    local entry = dep.assets[platform]
    if entry then
      local dest = user_plugins .. entry[1]
      local f = io.open(dest, "rb")
      if f then
        f:close()
        -- Left by successful loaded-DLL replacement when the OS keeps the
        -- old mapped binary open until REAPER exits. Safe best-effort only:
        -- never delete the backup if the real dependency file is absent.
        os.remove(dest .. ".bak")
      end
    end
  end
end

-- =============================================================================
-- gfx-based ReaImGui installer UI
-- =============================================================================
-- Polished dark-themed installer that auto-runs (no confirmation prompt).
-- The user already opted in by launching ReaAssist; the UI's job is to
-- show what is happening and surface failures.

local InstallerGfx = {
  W = 640, H = 380,
  -- Theme colors lifted from PALETTE_DARK (kept in sync by hand; this
  -- block runs before COL is built so we can't reference it directly).
  C_BG_TOP    = 0x0B0B0BFF,
  C_BG_BOT    = 0x2A2A2AFF,
  C_TEXT      = 0xFFFFFFFF,
  C_TEXT_DIM  = 0xB0BEC5FF,
  C_TEXT_VDIM = 0x78909CFF,
  C_ACCENT    = 0x83BCEBFF,  -- ice blue (ASSIST)
  C_ACCENT_DK = 0x4A7DA8FF,
  C_SUCCESS   = 0x66CC66FF,
  C_ERROR     = 0xFF6060FF,
  C_BORDER    = 0x37474FFF,
  C_BAR_BG    = 0x363636FF,
  C_BTN_BG    = 0x37474FFF,
  C_BTN_HOV   = 0x455A64FF,
  C_BTN_PRI   = 0x5D809CFF,
  C_BTN_PRIH  = 0x7A9BB2FF,
  -- State
  -- State machine progression (per queue item):
  --   init -> starting (pre-spawn) -> running (script alive, pre-download)
  --     -> downloading -> verifying -> installing -> ok
  --   on ok: if more items in queue, restart at "init" for next item;
  --          on last item, transition to "done"
  --   any phase + failure -> error
  --   user opt-in screen: disclose (initial state set by .start when the
  --     installer is invoked because at least one dep needs install).
  -- The downloading/verifying/installing phase names are also written by
  -- the background pipeline script as marker file content; poll_pipeline
  -- promotes those phase names to InstallerGfx.state so render_running
  -- can drive the progress bar from the live phase.
  state             = "init",   -- see comment above for the full set
  -- Live human-readable status text; mirrors the marker phase from
  -- poll_pipeline (e.g. "Downloading from GitHub..."). Drawn under the
  -- progress bar in render_running.
  status            = "",
  error_msg         = nil,
  error_step        = nil,
  platform          = nil,
  -- Install queue: ordered list of items to install. Each item is the
  -- table built by Deps.build_queue (dep / kind / installed_ver / asset
  -- / expected_sha / dest_path). The pipeline runs once per item.
  queue             = nil,
  queue_idx         = 0,        -- 1-based index of current item
  _last_mouse_cap   = 0,
  _frame_count      = 0,
}

-- Helper: current queue item (the one being installed right now).
function InstallerGfx.current()
  if not InstallerGfx.queue then return nil end
  return InstallerGfx.queue[InstallerGfx.queue_idx]
end

function InstallerGfx.color(rgba)
  local r = math.floor(rgba / 0x1000000) % 256 / 255
  local g = math.floor(rgba / 0x10000)   % 256 / 255
  local b = math.floor(rgba / 0x100)     % 256 / 255
  local a =          (rgba % 256)        / 255
  gfx.set(r, g, b, a)
end

function InstallerGfx.set_font(idx, sz, bold)
  -- Use cross-platform sans-serif. REAPER substitutes if exact face missing.
  -- "Arial" is universally present (or has a near-identical substitute) on
  -- Windows, macOS, and most Linux distros.
  local flags = bold and string.byte("b") or 0
  gfx.setfont(idx, "Arial", sz, flags)
end

function InstallerGfx.draw_gradient_bg()
  local r1 = math.floor(InstallerGfx.C_BG_TOP / 0x1000000) % 256
  local g1 = math.floor(InstallerGfx.C_BG_TOP / 0x10000)   % 256
  local b1 = math.floor(InstallerGfx.C_BG_TOP / 0x100)     % 256
  local r2 = math.floor(InstallerGfx.C_BG_BOT / 0x1000000) % 256
  local g2 = math.floor(InstallerGfx.C_BG_BOT / 0x10000)   % 256
  local b2 = math.floor(InstallerGfx.C_BG_BOT / 0x100)     % 256
  for y = 0, gfx.h - 1 do
    local t = y / (gfx.h - 1)
    gfx.set((r1 + (r2-r1)*t)/255, (g1 + (g2-g1)*t)/255, (b1 + (b2-b1)*t)/255, 1.0)
    gfx.line(0, y, gfx.w, y)
  end
end

function InstallerGfx.draw_text_center(text, y, color, font_idx)
  InstallerGfx.color(color)
  gfx.setfont(font_idx)
  local tw = gfx.measurestr(text)
  gfx.x = math.floor((gfx.w - tw) / 2)
  gfx.y = y
  gfx.drawstr(text)
end

function InstallerGfx.draw_progress_bar(x, y, w, h, progress)
  -- Track
  InstallerGfx.color(InstallerGfx.C_BAR_BG)
  gfx.rect(x, y, w, h, 1)
  -- Fill (ice blue)
  if progress > 0 then
    InstallerGfx.color(InstallerGfx.C_ACCENT)
    gfx.rect(x, y, math.floor(w * math.min(1, progress)), h, 1)
  end
  -- Border
  InstallerGfx.color(InstallerGfx.C_BORDER)
  gfx.rect(x, y, w, h, 0)
end

-- Indeterminate progress bar: a sliding ice-blue band that moves
-- left-to-right and bounces back. Used while curl is downloading and we
-- can't safely poll the partial file size (NTFS share-mode contention).
-- All inputs are time-derived; no file system access.
function InstallerGfx.draw_indeterminate_bar(x, y, w, h)
  -- Track
  InstallerGfx.color(InstallerGfx.C_BAR_BG)
  gfx.rect(x, y, w, h, 1)
  -- Sliding band: 30% of the bar's width, period ~1.6s round trip.
  local band_w = math.floor(w * 0.30)
  local t = (reaper.time_precise() % 1.6) / 1.6   -- 0..1
  -- Bounce: 0->1->0
  local pos_t = (t < 0.5) and (t * 2) or ((1.0 - t) * 2)
  local band_x = x + math.floor((w - band_w) * pos_t)
  InstallerGfx.color(InstallerGfx.C_ACCENT)
  gfx.rect(band_x, y, band_w, h, 1)
  -- Border
  InstallerGfx.color(InstallerGfx.C_BORDER)
  gfx.rect(x, y, w, h, 0)
end

function InstallerGfx.button(x, y, w, h, label, is_primary)
  local mx, my = gfx.mouse_x, gfx.mouse_y
  local hovered = mx >= x and mx < x + w and my >= y and my < y + h
  local now_down = (gfx.mouse_cap & 1) == 1
  local was_down = (InstallerGfx._last_mouse_cap & 1) == 1
  local clicked = hovered and was_down and not now_down
  -- Background
  if is_primary then
    InstallerGfx.color(hovered and InstallerGfx.C_BTN_PRIH or InstallerGfx.C_BTN_PRI)
  else
    InstallerGfx.color(hovered and InstallerGfx.C_BTN_HOV or InstallerGfx.C_BTN_BG)
  end
  gfx.rect(x, y, w, h, 1)
  -- Border
  InstallerGfx.color(InstallerGfx.C_BORDER)
  gfx.rect(x, y, w, h, 0)
  -- Label
  InstallerGfx.color(InstallerGfx.C_TEXT)
  gfx.setfont(2)
  local tw, th = gfx.measurestr(label)
  gfx.x = x + math.floor((w - tw) / 2)
  gfx.y = y + math.floor((h - th) / 2)
  gfx.drawstr(label)
  return clicked
end

-- Choose the gfx window title based on the queue's contents. Single-dep
-- queues name the dep directly; mixed queues use the generic phrase.
local function _installer_window_title(queue)
  if not queue or #queue == 0 then return "Install Dependencies" end
  if #queue == 1 then
    local item = queue[1]
    return ((item.kind == "too_old") and "Update " or "Install ") .. item.dep.name
  end
  return "Install Dependencies"
end

function InstallerGfx.start(queue)
  InstallerGfx.platform  = Deps.detect_platform()
  -- Defensive: build_queue would have filtered empty queues out before
  -- calling .start, so #queue is at least 1 here. The platform check
  -- could still come back nil on a totally unrecognized OS string.
  if not InstallerGfx.platform or not queue or #queue == 0 then
    reaper.ShowMessageBox(
      "ReaAssist could not auto-install its dependencies on this platform.\n\n" ..
      "Detected: " .. tostring(reaper.GetOS()) .. " / " .. tostring(reaper.GetAppVersion()) .. "\n\n" ..
      "Please install manually:\n" ..
      "  ReaImGui:        https://github.com/cfillion/reaimgui/releases\n" ..
      "  js_ReaScriptAPI: https://github.com/juliansader/ReaExtensions\n\n" ..
      "Place the appropriate binaries in:\n" ..
      reaper.GetResourcePath() .. "/UserPlugins/",
      "ReaAssist - Manual Install Required", 0)
    return
  end
  InstallerGfx.queue     = queue
  InstallerGfx.queue_idx = 1
  -- Start on the disclosure screen so the user can read what's about to
  -- be installed (third-party binaries, sources, licenses, destinations)
  -- before we touch UserPlugins/. Click Install to proceed.
  InstallerGfx.state     = "disclose"
  -- Center on whichever monitor the user's mouse is on. The trick to
  -- get the active monitor's work-area bounds via reaper.my_getViewport
  -- is to pass a deliberately huge target rect (-10000..10000) along
  -- with a 1-pixel source rect at the mouse position; the returned rect
  -- is the bounds of the work area on that monitor (taskbar excluded).
  -- We then center our window within those bounds.
  local mx, my = reaper.GetMousePosition()
  -- my_getViewport returns 4 values: x1, y1, x2, y2 (the input rect
  -- clamped to the work area of the screen containing the source rect).
  local sx1, sy1, sx2, sy2 = reaper.my_getViewport(
    -10000, -10000, 10000, 10000,
    mx, my, mx + 1, my + 1, true)
  local x = sx1 + math.floor((sx2 - sx1 - InstallerGfx.W) / 2)
  local y = sy1 + math.floor((sy2 - sy1 - InstallerGfx.H) / 2)
  -- Pre-init font slots (some REAPER builds need these registered before
  -- the first measurestr call to return correct widths).
  gfx.init(_installer_window_title(queue), InstallerGfx.W, InstallerGfx.H, 0,
           math.max(0, x), math.max(0, y))
  InstallerGfx.set_font(1, 28, true)   -- title
  InstallerGfx.set_font(2, 16)         -- body / button labels (16pt for legibility)
  InstallerGfx.set_font(3, 13)         -- small / detail (1pt up from 12 for legibility)
  InstallerGfx.set_font(4, 11)         -- footer
  InstallerGfx.set_font(5, 16, true)   -- subtitle emphasis
  InstallerGfx.set_font(6, 16)         -- instructions body (2pt up from 14)
  InstallerGfx.set_font(7, 20, true)   -- "ReaAssist is not running yet" emphasis
  reaper.defer(InstallerGfx.tick)
end

function InstallerGfx.tick()
  -- Window closed by user (Esc / X button) -> abort
  local char = gfx.getchar()
  if char < 0 then return end

  InstallerGfx._frame_count = InstallerGfx._frame_count + 1

  -- Render current state
  InstallerGfx.draw_gradient_bg()
  if     InstallerGfx.state == "disclose" then
    InstallerGfx.render_disclose()
  elseif InstallerGfx.state == "done"     then
    InstallerGfx.render_done()
  elseif InstallerGfx.state == "error"    then
    InstallerGfx.render_error()
  else
    InstallerGfx.render_running()
  end
  gfx.update()

  -- Advance state machine. Download + SHA verify + atomic install all run
  -- inside ONE async background script (PowerShell on Windows, sh on
  -- macOS/Linux). The main thread only polls a single result marker each
  -- tick. Synchronous certutil / shasum / os.rename calls would otherwise
  -- block REAPER's main thread for several seconds because Windows
  -- Defender holds the freshly-written DLL open while it scans.
  if     InstallerGfx.state == "disclose"    then
    -- No auto-advance; render_disclose handles its own button input.
  elseif InstallerGfx.state == "init"        then
    InstallerGfx.status = "Preparing..."
    if InstallerGfx._frame_count >= 2 then
      InstallerGfx.state = "starting"
      InstallerGfx.status = "Starting installer..."
    end
  elseif InstallerGfx.state == "starting"    then
    if InstallerGfx._frame_count >= 4 then InstallerGfx.spawn_pipeline() end
  elseif InstallerGfx.state == "running"
      or InstallerGfx.state == "downloading"
      or InstallerGfx.state == "verifying"
      or InstallerGfx.state == "installing" then
    -- Pipeline is alive (state was either set to "running" by spawn_pipeline
    -- or promoted to a phase name by an earlier poll_pipeline tick). Keep
    -- polling the marker each frame; poll_pipeline updates state as the
    -- background script advances through phases and transitions to "done"
    -- or "error" when the final marker arrives.
    InstallerGfx.poll_pipeline()
  end

  InstallerGfx._last_mouse_cap = gfx.mouse_cap
  reaper.defer(InstallerGfx.tick)
end

function InstallerGfx.render_running()
  local item = InstallerGfx.current()
  local n    = #InstallerGfx.queue
  -- Title: "Installing ReaImGui" / "Updating ReaImGui" / "(2 of 2) Installing
  -- js_ReaScriptAPI" depending on queue size and item kind.
  local prefix = (n > 1)
    and string.format("(%d of %d) ", InstallerGfx.queue_idx, n)
    or  ""
  local verb  = (item.kind == "too_old") and "Updating " or "Installing "
  InstallerGfx.draw_text_center(prefix .. verb .. item.dep.name, 38,
                                 InstallerGfx.C_TEXT, 1)
  -- Subtitle: missing vs upgrading
  local subtitle = (item.kind == "too_old")
    and ("from " .. tostring(item.installed_ver) .. " to " .. item.dep.pinned_version)
    or  (item.dep.name .. " " .. item.dep.pinned_version)
  InstallerGfx.draw_text_center(subtitle, 80, InstallerGfx.C_TEXT_DIM, 3)
  -- Asset file name
  InstallerGfx.draw_text_center(item.asset, 102, InstallerGfx.C_TEXT_VDIM, 4)
  -- Progress bar. During "downloading" we can't safely poll the .tmp file
  -- (curl holds it open with NTFS share-mode that makes io.open / seek
  -- slow enough to starve the main thread); instead show an animated
  -- indeterminate band that visibly moves left-to-right. The other
  -- states have known durations / discrete steps so a fractional fill
  -- works fine for them.
  local bar_w = gfx.w - 120
  if InstallerGfx.state == "downloading" then
    InstallerGfx.draw_indeterminate_bar(60, 145, bar_w, 14)
  else
    local progress = 0.05
    if     InstallerGfx.state == "starting"    then progress = 0.20
    elseif InstallerGfx.state == "verifying"   then progress = 0.85
    elseif InstallerGfx.state == "installing"  then progress = 0.95
    end
    InstallerGfx.draw_progress_bar(60, 145, bar_w, 14, progress)
  end
  -- Live status text
  InstallerGfx.draw_text_center(InstallerGfx.status or "...", 178, InstallerGfx.C_TEXT, 2)
  -- Attribution footer (per current item)
  InstallerGfx.draw_text_center(
    item.dep.name .. " by " .. item.dep.author .. " \xE2\x80\xA2 " .. item.dep.license,
    gfx.h - 38, InstallerGfx.C_TEXT_VDIM, 4)
  InstallerGfx.draw_text_center(item.dep.source_url,
                                 gfx.h - 22, InstallerGfx.C_TEXT_VDIM, 4)
end

function InstallerGfx.render_disclose()
  local queue = InstallerGfx.queue
  if #queue == 1 then
    InstallerGfx._render_disclose_single(queue[1])
  else
    InstallerGfx._render_disclose_multi(queue)
  end

  -- Buttons (shared layout for both single and multi).
  local btn_w, btn_h = 130, 36
  local gap = 14
  local btn_y = gfx.h - 60
  local total_w = btn_w * 2 + gap
  local btn_x = math.floor((gfx.w - total_w) / 2)
  if InstallerGfx.button(btn_x, btn_y, btn_w, btn_h, "Install", true) then
    InstallerGfx.state        = "init"
    InstallerGfx._frame_count = 0
  end
  if InstallerGfx.button(btn_x + btn_w + gap, btn_y, btn_w, btn_h, "Quit", false) then
    gfx.quit()
  end
end

-- Single-dep disclose view: labeled rows (Dependency: / By: / License:
-- / Source: / Install to:) with the dep name in the title. This is the
-- pre-bundling polish layout; restored for single-dep queues so it
-- doesn't read as plural when only one extension is needed.
function InstallerGfx._render_disclose_single(item)
  local is_update = (item.kind == "too_old")
  local title = is_update
    and ("Update " .. item.dep.name .. "?")
    or  ("Install " .. item.dep.name .. "?")
  local subtitle = is_update
    and ("Your installed " .. item.dep.name .. " ("
         .. tostring(item.installed_ver) .. ") is older than "
         .. "ReaAssist requires.")
    or  ("ReaAssist requires the " .. item.dep.name .. " extension to run.")
  InstallerGfx.draw_text_center(title,    38, InstallerGfx.C_ACCENT, 1)
  InstallerGfx.draw_text_center(subtitle, 80, InstallerGfx.C_TEXT, 5)

  -- Disclosure block: name / author / license / source / destination.
  -- Labels left-justified within the block, values left-justified after
  -- a fixed gap from the widest label. The whole block is then centered
  -- horizontally in the window by measuring its total width once.
  local rows = {
    {"Dependency:", item.dep.name .. " " .. item.dep.pinned_version},
    {"By:",         item.dep.author},
    {"License:",    item.dep.license},
    {"Source:",     item.dep.source_url},
    {"Install to:", "UserPlugins/" .. item.asset},
  }
  gfx.setfont(3)
  local label_w_max, value_w_max = 0, 0
  for _, r in ipairs(rows) do
    local lw = gfx.measurestr(r[1]); if lw > label_w_max then label_w_max = lw end
    local vw = gfx.measurestr(r[2]); if vw > value_w_max then value_w_max = vw end
  end
  local row_gap = 20
  local block_w = label_w_max + row_gap + value_w_max
  local label_x = math.floor((gfx.w - block_w) / 2)
  local value_x = label_x + label_w_max + row_gap
  local y = 118
  for _, r in ipairs(rows) do
    InstallerGfx.color(InstallerGfx.C_TEXT_VDIM)
    gfx.x = label_x; gfx.y = y; gfx.drawstr(r[1])
    InstallerGfx.color(InstallerGfx.C_TEXT)
    gfx.x = value_x; gfx.y = y; gfx.drawstr(r[2])
    y = y + 22
  end
end

-- Multi-dep disclose view: each queue item gets two centered lines
-- (name + version, then author / license / source on one dim line)
-- with a shared "Will install to: REAPER UserPlugins/" footer.
function InstallerGfx._render_disclose_multi(queue)
  local any_install = false
  for _, item in ipairs(queue) do
    if item.kind ~= "too_old" then any_install = true; break end
  end
  -- Mixed queues default to "Install Dependencies?". An all-update
  -- multi-dep queue is vanishingly rare in practice but still correct.
  local title = any_install and "Install Dependencies?"
                            or  "Update Dependencies?"
  InstallerGfx.draw_text_center(title, 38, InstallerGfx.C_ACCENT, 1)
  InstallerGfx.draw_text_center(
    "ReaAssist needs the following extensions:",
    80, InstallerGfx.C_TEXT, 5)

  local y = 118
  for _, item in ipairs(queue) do
    local line1 = item.dep.name .. " " .. item.dep.pinned_version
    if item.kind == "too_old" then
      line1 = line1 .. "  (was " .. tostring(item.installed_ver) .. ")"
    end
    InstallerGfx.draw_text_center(line1, y, InstallerGfx.C_TEXT, 5)
    y = y + 22
    local line2 = "by " .. item.dep.author .. " \xE2\x80\xA2 "
               .. item.dep.license .. " \xE2\x80\xA2 "
               .. item.dep.source_url
    InstallerGfx.draw_text_center(line2, y, InstallerGfx.C_TEXT_DIM, 3)
    y = y + 30
  end

  InstallerGfx.draw_text_center(
    "Will install to: REAPER UserPlugins/", y + 4,
    InstallerGfx.C_TEXT_VDIM, 3)
end

function InstallerGfx.render_done()
  local queue = InstallerGfx.queue
  local n     = #queue

  -- Title: pluralize and pick verb based on whether any items were
  -- updates rather than fresh installs.
  local any_update = false
  for _, item in ipairs(queue) do
    if item.kind == "too_old" then any_update = true; break end
  end
  local noun = (n > 1) and "Dependencies" or "Dependency"
  local verb = any_update and "Updated" or "Installed"
  local title = noun .. " " .. verb
  InstallerGfx.draw_text_center(title, 36, InstallerGfx.C_SUCCESS, 1)

  -- Body: list what was installed/updated. "ReaImGui v0.10.0.5 and
  -- js_ReaScriptAPI v1.310 were installed." for two items; the single
  -- item form drops the "and".
  local names = {}
  for _, item in ipairs(queue) do
    names[#names + 1] = item.dep.name .. " " .. item.dep.pinned_version
  end
  local list  = (#names == 2) and (names[1] .. " and " .. names[2])
             or  table.concat(names, ", ")
  local was_were = (n > 1) and "were" or "was"
  local body = list .. " " .. was_were .. " "
            .. (any_update and "installed/updated." or "installed.")
  InstallerGfx.draw_text_center(body, 78, InstallerGfx.C_TEXT, 2)

  -- Make absolutely clear ReaAssist itself is NOT yet running. Bigger,
  -- emphasized "next steps" block so a user who closes the window
  -- without reading still has the text linger long enough to register.
  InstallerGfx.draw_text_center("ReaAssist is not running yet.", 116,
                                 InstallerGfx.C_ACCENT, 7)

  -- Instruction list. Centered as a block: measure the widest line,
  -- center the block's left edge, then draw lines left-justified within.
  local extn_word = (n > 1) and "extensions" or "extension"
  local steps = {
    "1.  Close and reopen REAPER (so the new " .. extn_word .. " loads).",
    "2.  Open the Action list (Actions menu, or shortcut '?').",
    "3.  Search for 'ReaAssist' and run it.",
  }
  gfx.setfont(6)
  local max_w = 0
  for _, line in ipairs(steps) do
    local w = gfx.measurestr(line)
    if w > max_w then max_w = w end
  end
  local step_x = math.floor((gfx.w - max_w) / 2)
  local step_y = 162
  InstallerGfx.color(InstallerGfx.C_TEXT_DIM)
  for _, line in ipairs(steps) do
    gfx.x = step_x; gfx.y = step_y; gfx.drawstr(line)
    step_y = step_y + 24
  end

  -- Single Close button: closes the installer window only. The user
  -- quits REAPER themselves via the OS chrome (red button on macOS,
  -- X on Windows / Linux) per step 1 above. An earlier version had a
  -- "Close REAPER" convenience button that fired Main_OnCommand(40004)
  -- to quit REAPER in one click; on macOS Tahoe that path raced the
  -- gfx teardown and left REAPER's extension state half-finalized,
  -- which then surfaced on the next launch as a ReaImGui context
  -- that ImGui_CreateContext returned but failed in-frame validation.
  -- Native Cocoa termination (red button / Cmd+Q) does not have this
  -- problem because it sequences the shutdown through AppKit.
  local btn_w, btn_h = 150, 36
  local btn_x = math.floor((gfx.w - btn_w) / 2)
  local btn_y = gfx.h - 70
  if InstallerGfx.button(btn_x, btn_y, btn_w, btn_h, "Close", true) then
    gfx.quit()
  end
end

function InstallerGfx.render_error()
  local item = InstallerGfx.current()
  local dep_name = item and item.dep.name or "dependency"
  InstallerGfx.draw_text_center("Installation Failed", 50, InstallerGfx.C_ERROR, 1)
  InstallerGfx.draw_text_center(
    "Failed installing " .. dep_name
      .. " (" .. (InstallerGfx.error_step or "unknown") .. ")",
    95, InstallerGfx.C_TEXT_DIM, 3)
  -- Wrap and draw error message lines
  local y = 125
  for line in (InstallerGfx.error_msg or ""):gmatch("([^\n]*)\n?") do
    if line ~= "" then
      InstallerGfx.draw_text_center(line, y, InstallerGfx.C_TEXT, 3)
      y = y + 18
    end
    if y > gfx.h - 90 then break end
  end
  -- Retry + Close
  local btn_w, btn_h = 110, 36
  local gap = 14
  local btn_y = gfx.h - 60
  local total_w = btn_w * 2 + gap
  local btn_x = math.floor((gfx.w - total_w) / 2)
  if InstallerGfx.button(btn_x, btn_y, btn_w, btn_h, "Retry", true) then
    InstallerGfx.state         = "init"
    InstallerGfx._frame_count  = 0
    InstallerGfx.error_msg     = nil
    InstallerGfx.error_step    = nil
  end
  if InstallerGfx.button(btn_x + btn_w + gap, btn_y, btn_w, btn_h, "Close", false) then
    gfx.quit()
  end
end

function InstallerGfx.fail(step, msg)
  InstallerGfx.state      = "error"
  InstallerGfx.error_step = step
  InstallerGfx.error_msg  = msg
  -- Best-effort cleanup of any pipeline files this run produced. Each
  -- field is only set after spawn_pipeline got far enough to create
  -- the file; absent paths just no-op via os.remove. Uses the run-
  -- tokenized paths captured by spawn_pipeline (the legacy ".tmp"
  -- suffix is no longer accurate after the per-run-token change).
  if InstallerGfx.tmp_path    then os.remove(InstallerGfx.tmp_path)    end
  if InstallerGfx.marker_path then os.remove(InstallerGfx.marker_path) end
  if InstallerGfx.script_path then os.remove(InstallerGfx.script_path) end
end

-- All-in-one async install pipeline. Writes a self-contained PowerShell
-- (Windows) or sh (macOS/Linux) script to a temp file that downloads,
-- SHA-256 verifies, atomically installs, and on macOS strips the Gate-
-- keeper quarantine xattr -- then writes a single result marker to
-- signal completion. The main thread only polls that one marker file.
--
-- Why bundled into one script: doing these steps as separate Lua-side
-- ExecProcess calls blocks the REAPER main thread for several seconds
-- per call, because Windows Defender holds the freshly-written DLL open
-- while it scans, and certutil/os.rename then wait for share-mode
-- access. Bundling moves that contention entirely off the main thread.
function InstallerGfx.spawn_pipeline()
  local item = InstallerGfx.current()
  if not item then
    InstallerGfx.fail("setup", "Install queue was empty; nothing to do.")
    return
  end
  -- Per-run token in tmp / marker / script paths so a cancelled-then-
  -- rerun cycle cannot have the OLD background script's marker write
  -- race with this run's poll. os.time() resolution is 1s; pair with a
  -- microsecond fraction of time_precise() so two spawns in the same
  -- second still get distinct tokens.
  local run_token = string.format("%d_%06d",
    os.time(),
    math.floor((reaper.time_precise() % 1) * 1000000))
  local tmp         = item.dest_path .. ".tmp."           .. run_token
  local marker      = item.dest_path .. ".marker."        .. run_token
  local script_base = item.dest_path .. ".install_script." .. run_token
  local url         = item.dep.url_base .. "/" .. item.asset
  local expected    = item.expected_sha:lower()

  -- Best-effort cleanup of any stale .bak from a prior failed run. The
  -- per-run-token .tmp / .marker / .script paths above can't collide
  -- with prior runs by construction, so they don't need pre-removal.
  os.remove(item.dest_path .. ".bak")

  local script_path
  local os_str = reaper.GetOS() or ""
  if os_str:match("^Win") then
    -- Defensive guard limited to characters that BOTH have cmd meaning
    -- AND cannot legitimately appear in a Windows file/directory name
    -- (Windows reserves " < > | * ? for filenames, of which the first
    -- four are also cmd metacharacters). Other cmd-significant chars
    -- like & ^ ( ) % ARE valid in Windows paths -- "Program Files (x86)",
    -- user dirs like "R&D", etc. -- and are protected by the triple-
    -- quoted argument passing through PowerShell -> cmd -> powershell,
    -- so we must NOT reject them or valid installs would fail to launch.
    for _, c in ipairs({'"', '<', '>', '|'}) do
      if item.dest_path:find(c, 1, true)
          or marker:find(c, 1, true)
          or tmp:find(c, 1, true) then
        InstallerGfx.fail("setup", string.format(
          "Install path contains a character ('%s') unsafe for the "
          .. "Windows command line. Please install %s manually.",
          c, item.dep.name))
        return
      end
    end
    script_path = script_base .. ".ps1"
    -- Per-phase status markers let the Lua side render an accurate
    -- status string AND prove the script actually started (vs. silently
    -- failing to launch). The "ok" / "*_failed" / "error:" markers are
    -- final and trigger state transition; intermediate phase markers
    -- (running / downloading / verifying / installing) update both the
    -- on-screen status text AND InstallerGfx.state, which drives the
    -- progress bar fill in render_running.
    local script = table.concat({
      "$ErrorActionPreference = 'Stop'",
      "$marker = "   .. Shell.ps_quote(marker),
      -- WriteAllText is atomic at the OS level (one CreateFile + WriteFile
      -- pair); Out-File opens the file truncating then writes, leaving a
      -- brief window where a concurrent reader sees the file as empty.
      -- Our 250ms poll easily hits that window during rapid phase
      -- transitions (e.g. installing -> ok), causing a false "unknown
      -- error" report even though the install succeeded.
      "function Mark($s) {",
      "  [System.IO.File]::WriteAllText($marker, $s + \"`r`n\", [System.Text.Encoding]::ASCII)",
      "}",
      "Mark 'running'",
      "try {",
      "  $tmp = "      .. Shell.ps_quote(tmp),
      "  $dest = "     .. Shell.ps_quote(item.dest_path),
      "  $url = "      .. Shell.ps_quote(url),
      "  $expected = " .. Shell.ps_quote(expected),
      "  Mark 'downloading'",
      "  & curl.exe -fsSL --max-time 60 -o $tmp $url",
      "  if ($LASTEXITCODE -ne 0) { Mark \"download_failed:$LASTEXITCODE\"; return }",
      "  Mark 'verifying'",
      "  function Get-Sha256Hex($path) {",
      "    if (Get-Command Get-FileHash -ErrorAction SilentlyContinue) {",
      "      try {",
      "        $fileHash = Get-FileHash -Algorithm SHA256 $path",
      "        if ($fileHash -and $fileHash.Hash) { return $fileHash.Hash.ToLowerInvariant() }",
      "      } catch { }",
      "    }",
      "    $stream = [System.IO.File]::OpenRead($path)",
      "    try {",
      "      $sha = [System.Security.Cryptography.SHA256]::Create()",
      "      try {",
      "        $hashBytes = $sha.ComputeHash($stream)",
      "      } finally {",
      "        $sha.Dispose()",
      "      }",
      "    } finally {",
      "      $stream.Dispose()",
      "    }",
      "    return ([System.BitConverter]::ToString($hashBytes) -replace '-', '').ToLowerInvariant()",
      "  }",
      "  $actual = Get-Sha256Hex $tmp",
      "  if ($actual -ne $expected) {",
      "    Mark \"verify_failed:$actual\"",
      "    Remove-Item $tmp -Force -ErrorAction SilentlyContinue",
      "    return",
      "  }",
      "  Mark 'installing'",
      "  if (Test-Path $dest) {",
      "    $backup = \"$dest.bak\"",
      "    if (Test-Path $backup) { Remove-Item $backup -Force }",
      "    Move-Item $dest $backup",
      -- Inner try/catch: if moving tmp into place fails, restore the
      -- backup so the user keeps their previous (working) DLL rather
      -- than being left with a stranded .bak and no DLL at all.
      "    try {",
      "      Move-Item $tmp $dest",
      "    } catch {",
      "      Move-Item $backup $dest -Force -ErrorAction SilentlyContinue",
      "      throw",
      "    }",
      "    Remove-Item $backup -Force -ErrorAction SilentlyContinue",
      "  } else {",
      "    Move-Item $tmp $dest",
      "  }",
      "  Mark 'ok'",
      "} catch {",
      "  Mark ('error:' + $_.ToString())",
      "}",
    }, "\n")
    local sf = io.open(script_path, "w")
    if not sf then InstallerGfx.fail("setup", "Could not write install script."); return end
    sf:write(script); sf:close()
    -- Spawn the script async. Mirrors the proven Net.fire_curl pattern:
    -- outer powershell launches `cmd /c <command>` via Start-Process
    -- with -WindowStyle Hidden so there's no flash AND the outer call
    -- only blocks until Start-Process returns (~1-2s). The inner cmd
    -- invokes powershell -File against the script with triple-quoted
    -- path so spaces survive the powershell -> cmd -> powershell layers.
    local inner_cmd = string.format(
      'powershell -NoProfile -ExecutionPolicy Bypass -File """%s"""',
      script_path)
    local launch = string.format(
      'powershell -NoProfile -WindowStyle Hidden -Command ' ..
      '"Start-Process cmd -ArgumentList \'/c %s\' -WindowStyle Hidden"',
      Shell.ps_escape(inner_cmd))
    reaper.ExecProcess(launch, 5000)
  else
    script_path = script_base .. ".sh"
    local script = table.concat({
      "#!/bin/sh",
      "TMP=" .. Shell.sh_quote(tmp),
      "DEST=" .. Shell.sh_quote(item.dest_path),
      "URL=" .. Shell.sh_quote(url),
      "EXPECTED=" .. Shell.sh_quote(expected),
      "MARKER=" .. Shell.sh_quote(marker),
      "mark() { printf '%s' \"$1\" > \"$MARKER\"; }",
      "mark running",
      "mark downloading",
      "if ! curl -fsSL --max-time 60 -o \"$TMP\" \"$URL\"; then",
      "  mark \"download_failed:$?\"; exit 0",
      "fi",
      "mark verifying",
      -- Try GNU sha256sum first (default on most Linux distros) then
      -- fall back to BSD shasum -a 256 (default on macOS). Either tool
      -- prints "<hex>  filename" on its first line.
      "if command -v sha256sum >/dev/null 2>&1; then",
      "  ACTUAL=$(sha256sum \"$TMP\" 2>/dev/null | awk '{print $1}')",
      "else",
      "  ACTUAL=$(shasum -a 256 \"$TMP\" 2>/dev/null | awk '{print $1}')",
      "fi",
      "if [ \"$ACTUAL\" != \"$EXPECTED\" ]; then",
      "  mark \"verify_failed:$ACTUAL\"; rm -f \"$TMP\"; exit 0",
      "fi",
      "mark installing",
      -- Install with explicit failure detection. Without these checks, a
      -- failed mv (disk full, permissions) would silently fall through to
      -- "mark ok" since && chains don't propagate failure to the script's
      -- exit status. Mirror the PowerShell script's try/catch behaviour.
      "do_install() {",
      "  if [ -f \"$DEST\" ]; then",
      "    rm -f \"$DEST.bak\"",
      "    mv \"$DEST\" \"$DEST.bak\" || return 1",
      "    mv \"$TMP\" \"$DEST\" || { mv \"$DEST.bak\" \"$DEST\"; return 1; }",
      "    rm -f \"$DEST.bak\"",
      "  else",
      "    mv \"$TMP\" \"$DEST\" || return 1",
      "  fi",
      "}",
      "if ! do_install; then",
      "  mark \"error:could not move binary into UserPlugins\"",
      "  rm -f \"$TMP\" 2>/dev/null",
      "  exit 0",
      "fi",
      "case \"$(uname)\" in Darwin) xattr -d com.apple.quarantine \"$DEST\" 2>/dev/null || true ;; esac",
      "mark ok",
    }, "\n")
    local sf = io.open(script_path, "w")
    if not sf then InstallerGfx.fail("setup", "Could not write install script."); return end
    sf:write(script); sf:close()
    os.execute("chmod +x " .. Shell.sh_quote(script_path))
    os.execute(string.format("(sh %s) &", Shell.sh_quote(script_path)))
  end

  InstallerGfx.pipeline_started_at = reaper.time_precise()
  InstallerGfx.marker_path         = marker
  InstallerGfx.script_path         = script_path
  InstallerGfx.tmp_path            = tmp
  -- Initial post-spawn state. The background script overwrites the
  -- marker file with phase names ("running", "downloading", ...) which
  -- poll_pipeline promotes to InstallerGfx.state for progress-bar
  -- rendering. Until the first marker lands we sit in "running".
  InstallerGfx.state               = "running"
  InstallerGfx.status              = "Downloading & installing " .. item.dep.name .. "..."
end

-- Non-blocking poll for the result marker. Throttled to ~4 Hz so we are
-- not hammering the file system while the background script does its work.
function InstallerGfx.poll_pipeline()
  local now = reaper.time_precise()
  if (InstallerGfx._last_marker_poll or 0) > 0
     and (now - InstallerGfx._last_marker_poll) < 0.25 then
    return
  end
  InstallerGfx._last_marker_poll = now

  -- Hard timeout safety
  if now - (InstallerGfx.pipeline_started_at or 0) > 120 then
    InstallerGfx.fail("timeout",
      "Install timed out after 2 minutes. Check your network connection and try again.")
    return
  end

  local mf = io.open(InstallerGfx.marker_path, "r")
  if not mf then return end  -- script hasn't written its first marker yet
  local content = (mf:read("*a") or ""):gsub("[\r\n%s]+$", "")
  mf:close()

  -- Empty content = we caught the file mid-overwrite during a phase
  -- transition. Treat as "still running" and re-poll next tick.
  if content == "" then return end

  -- Intermediate phase markers: promote to InstallerGfx.state (drives
  -- the progress-bar fill in render_running) and update the on-screen
  -- status text. Don't transition out of the running pipeline or delete
  -- the marker -- the script overwrites it on the next phase.
  local PHASE_LABELS = {
    running     = "Starting installer...",
    downloading = "Downloading from GitHub...",
    verifying   = "Verifying checksum...",
    installing  = "Installing to UserPlugins...",
  }
  if PHASE_LABELS[content] then
    InstallerGfx.state  = content
    InstallerGfx.status = PHASE_LABELS[content]
    return
  end

  -- Final markers (ok / *_failed / error): cleanup + state transition.
  os.remove(InstallerGfx.script_path)
  os.remove(InstallerGfx.marker_path)

  if content == "ok" then
    -- Current queue item finished. If there are more items, advance and
    -- restart the pipeline state machine for the next item; otherwise
    -- transition to the unified "done" view.
    if InstallerGfx.queue_idx < #InstallerGfx.queue then
      InstallerGfx.queue_idx         = InstallerGfx.queue_idx + 1
      InstallerGfx.state             = "init"
      InstallerGfx._frame_count      = 0
      InstallerGfx._last_marker_poll = 0
      InstallerGfx.status            = "Preparing next dependency..."
    else
      InstallerGfx.state  = "done"
      InstallerGfx.status = "Done."
    end
    return
  end

  local item = InstallerGfx.current()
  local kind, detail = content:match("^([^:]+):(.*)$")
  kind   = kind   or content
  detail = detail or ""
  if kind == "download_failed" then
    InstallerGfx.fail("download", string.format(
      "Could not download %s from GitHub (curl exit code %s).\nCheck your network connection and try again.",
      (item and item.dep.name) or "dependency", detail))
  elseif kind == "verify_failed" then
    InstallerGfx.fail("verify", string.format(
      "SHA-256 checksum mismatch for %s.\nExpected: %s...\nGot:      %s...",
      (item and item.asset) or "asset",
      ((item and item.expected_sha) or ""):sub(1, 16),
      (detail or ""):sub(1, 16)))
  else
    InstallerGfx.fail("install",
      "Install failed: " .. (content ~= "" and content or "unknown error"))
  end
end

-- Main dispatch. Build a queue of dependencies that need install for the
-- current platform; if any need install, run the gfx installer and stop
-- script execution here. The script will resume normal startup after the
-- user restarts REAPER with the new extension(s) loaded.
local _platform = Deps.detect_platform()
local _queue    = _platform and Deps.build_queue(_platform) or {}
if #_queue > 0 then
  InstallerGfx.start(_queue)
  return
end
-- Fallback: unrecognized platform but at least one dep check failed.
-- Shouldn't normally hit this path (build_queue returns {} for missing
-- assets, not an empty platform), but guard the case where GetOS is
-- something neither Win/OSX/macOS-arm64/Other.
if not _platform
   and (Deps.check_imgui_status() ~= "ok"
        or Deps.check_jsapi_status() ~= "ok"
        or (REQUIRE_SWS_EXTENSION and Deps.check_sws_status() ~= "ok")) then
  InstallerGfx.start({})  -- triggers the unsupported-platform message
  return
end
Deps.cleanup_stale_backups(_platform)

end -- do (closes the dependency-installer scope)

local ImGui = reaper  -- secondary alias used for ImGui calls (reads as ImGui.ImGui_*)

-- =============================================================================
-- RA: shared-state namespace for cross-file access
-- =============================================================================
-- Shared state namespace read by both files (main + Resources/UI.lua).
-- Covers items that would otherwise be bare globals: the ImGui context,
-- UI-scale helper, path constants, OS flags, shared font handles, and
-- the sel_cb EEL callback. Pre-existing namespaces (S, CFG, TK, COL,
-- FONT, prefs, Log, Net, UI, Render, ...) stay as plain globals.
RA = {}


-- =============================================================================
-- LOCAL ALIASES
-- Lua resolves local variables faster than global/table lookups.
-- Caching frequently-called functions here gives a measurable speedup in the
-- snapshot inner loops (track/FX/item iteration) and the per-character JSON
-- decode path. Standard library aliases also benefit the draw loop helpers.
-- =============================================================================

-- Short alias for the reaper global -- matches the style of companion scripts
-- and makes the declaration block below more readable.
local R = reaper

-- Standard library
local str_format  = string.format
local str_find    = string.find
local str_sub     = string.sub
local str_byte    = string.byte
local str_char    = string.char
local str_match   = string.match
local tbl_concat  = table.concat
local tbl_remove  = table.remove
local math_floor  = math.floor
local math_min    = math.min
local math_max    = math.max

-- REAPER timing (called every loop frame and in the single-instance handshake)
local time_precise = R.time_precise

-- REAPER track / item API -- called repeatedly in snapshot inner loops
local R_CountTracks              = R.CountTracks
local R_GetTrack                 = R.GetTrack
local R_GetTrackName             = R.GetTrackName
local R_CountTrackMediaItems     = R.CountTrackMediaItems
local R_GetMediaTrackInfo_Value  = R.GetMediaTrackInfo_Value
local R_IsTrackSelected          = R.IsTrackSelected
local R_TrackFX_GetCount         = R.TrackFX_GetCount
local R_TrackFX_GetFXName        = R.TrackFX_GetFXName
local R_TrackFX_GetNumParams     = R.TrackFX_GetNumParams
local R_TrackFX_GetParamName     = R.TrackFX_GetParamName
local R_TrackFX_GetParam         = R.TrackFX_GetParam
local R_TrackFX_GetFormattedParamValue = R.TrackFX_GetFormattedParamValue
local R_CountSelectedMediaItems  = R.CountSelectedMediaItems
local R_GetSelectedMediaItem     = R.GetSelectedMediaItem
local R_GetMediaItemInfo_Value   = R.GetMediaItemInfo_Value
local R_GetMediaItem_Track       = R.GetMediaItem_Track
local R_EnumProjectMarkers3      = R.EnumProjectMarkers3
local R_CountProjectMarkers      = R.CountProjectMarkers

-- ImGui hot-path aliases. Names match upstream with ImGui_ stripped so
-- call sites stay self-documenting (PushStyleColor(ctx, ...)).
local PushStyleColor     = reaper.ImGui_PushStyleColor
local PopStyleColor      = reaper.ImGui_PopStyleColor
local PushStyleVar       = reaper.ImGui_PushStyleVar
local PushFont           = reaper.ImGui_PushFont
local PopFont            = reaper.ImGui_PopFont
local Text               = reaper.ImGui_Text
local SameLine           = reaper.ImGui_SameLine
local CalcTextSize       = reaper.ImGui_CalcTextSize
local GetCursorPosX      = reaper.ImGui_GetCursorPosX
local SetCursorPosX      = reaper.ImGui_SetCursorPosX
local Dummy              = reaper.ImGui_Dummy

-- =============================================================================
-- Action context (single call, used for toolbar IDs and script path)
-- =============================================================================
-- Destructured once here; avoids a duplicate get_action_context() call.
-- SECTION_ID and CMD_ID are main-file-only (toolbar-toggle use).
-- script_path is cross-file and lives on RA; it is assigned inside
-- the `do` block below via `RA.script_path = asp:match(...)`.
local SECTION_ID, CMD_ID
do
  local _, asp
  _, asp, SECTION_ID, CMD_ID = reaper.get_action_context()
  RA.script_path = asp:match("^(.+[\\/])")
  -- Collapse any `X/../` segments in the action-context path. REAPER
  -- stores action paths verbatim, so if a previous relauncher bug (or
  -- any other code) ever called AddRemoveReaScript with a dot-dot
  -- path, this instance's asp may contain those segments; everything
  -- downstream that concatenates RA.script_path (the relauncher
  -- registration, the "running" ExtState comparison, etc.) inherits
  -- them unless we normalize once here. Loop until the pattern stops
  -- matching so sequences like `a/b/../c/../d/` fully resolve.
  -- Bounded: each match shortens the path by at least 4 chars, so 32
  -- iterations covers any plausible path depth. The cap is purely
  -- defensive against pathological action-registry strings.
  for _ = 1, 32 do
    local normalized, n = RA.script_path:gsub("[^\\/]+[\\/]%.%.[\\/]", "")
    RA.script_path = normalized
    if n == 0 then break end
  end
  local fn = asp:match("[^\\/]+$") or ""
  if not fn:lower():find("reaassist") then
    reaper.ShowMessageBox(
      "This script has been modified and cannot run.",
      "Error", 0)
    return
  end
end

-- Compute the relauncher script path for later on-demand use by
-- Updater.try_auto_restart. The relauncher is only needed when an
-- update / repair completes and we want to re-fire ReaAssist from
-- a separate script context (firing Main_OnCommand on ReaAssist's
-- own CMD_ID from inside ReaAssist's running defer chain triggers
-- REAPER's re-entrance handling, which the single-instance handshake
-- interprets as a toggle-off). Registering the relauncher as an
-- action lazily -- at fire time, not at startup -- keeps it out of
-- the user's Actions list for sessions where no auto-restart ever
-- happens. advance_after_rename checks the file's existence before
-- scheduling restart so the done-view messaging can still pick the
-- right copy ("Restarting..." vs "Close and reopen...") without
-- touching REAPER's action registry until the restart actually fires.
local RELAUNCHER_PATH
do
  -- RA.script_path was set in the previous `do` block; RA.SEP lives
  -- further down in the OS-detection block, so hard-code the
  -- separator here rather than defer this path resolution.
  local sep = package.config:sub(1, 1)
  -- One-shot cleanup of dirty action registrations left behind by an
  -- earlier relauncher bug where REAASSIST_PATH and relauncher_path
  -- were concatenated with `..` segments. REAPER keyed them as
  -- separate actions from the normalized versions, so users ended up
  -- with duplicate entries in the Actions list. Remove-by-path with
  -- commit=true persists the cleanup; subsequent launches no-op.
  reaper.AddRemoveReaScript(false, 0,
    RA.script_path .. "Resources" .. sep .. ".." .. sep .. "ReaAssist.lua",
    true)
  reaper.AddRemoveReaScript(false, 0,
    RA.script_path .. "Resources" .. sep .. ".." .. sep
      .. "Resources" .. sep .. "Relaunch.lua",
    true)

  RELAUNCHER_PATH = RA.script_path .. "Resources" .. sep
                 .. "Relaunch.lua"

  -- Defensively unregister any stale relauncher entry. commit=false
  -- was supposed to make the previous run's try_auto_restart
  -- registration session-only, but REAPER persists the action path to
  -- reaper-kb.ini anyway so a fresh REAPER session still sees it in
  -- the Actions list. Always removing at startup with commit=true
  -- flushes that stale row; try_auto_restart re-registers on demand
  -- if and when the next auto-restart actually needs the helper. No-
  -- op if nothing is registered, so cheap on normal launches.
  reaper.AddRemoveReaScript(false, 0, RELAUNCHER_PATH, true)
end

-- =============================================================================
-- OS detection
-- =============================================================================
-- Used for platform-specific curl invocation, font selection, and path separators.
RA.IS_WINDOWS = reaper.GetOS():match("Win") ~= nil
RA.IS_MACOS = reaper.GetOS():match("OS")  ~= nil  -- "OSX" or "macOS"
RA.SEP = RA.IS_WINDOWS and "\\" or "/"

-- JSFX auto-save directory: Effects/ReaAssist/ inside the REAPER resource path.
-- Created on startup so auto-saved JSFX effects have a consistent home.
local JSFX_DIR = reaper.GetResourcePath() .. RA.SEP .. "Effects" .. RA.SEP .. "ReaAssist"
reaper.RecursiveCreateDirectory(JSFX_DIR, 0)

-- Resources directory: holds all .md reference files, the system prompt, the
-- bundled ReEQ source, and runtime-created files (FX cache, debug log).
-- Created on startup so the first file write never fails on a fresh install.
RA.RESOURCES_DIR = RA.script_path .. "Resources" .. RA.SEP
reaper.RecursiveCreateDirectory(RA.RESOURCES_DIR, 0)

RA.FX_CACHE_PATH = RA.RESOURCES_DIR .. "FX_Cache.json"

-- =============================================================================
-- Toolbar toggle support
-- =============================================================================
-- Reflects the script's on/off state in the REAPER toolbar button.
local function set_toolbar(state)
  if SECTION_ID and CMD_ID and SECTION_ID ~= -1 and CMD_ID ~= -1 then
    reaper.SetToggleCommandState(SECTION_ID, CMD_ID, state and 1 or 0)
    reaper.RefreshToolbar2(SECTION_ID, CMD_ID)
  end
end

-- =============================================================================
-- Single-instance handshake
-- =============================================================================
-- If a second instance is launched, it signals the first to close and exits.
-- ExtState key "running" stores "instance_id|timestamp" so stale locks from
-- hard crashes (process kill, BSOD) can be detected. If the lock is older than
-- STALE_LOCK_SECS (15 seconds; see Single-instance handshake block below),
-- it is treated as stale and claimed by this instance.
-- "request_close" carries the new instance's ID. The running instance checks
-- that the value differs from its own ID to avoid self-shutdown from stale
-- signals. A non-empty, non-self value triggers a graceful close.
CFG = {
  EXT_NS            = "reaassist",
  VERSION           = "1.2.1", -- public release version
  CURL_TIMEOUT      = 1800,      -- curl --max-time HARD CEILING (cloud providers). Stays high (30 min) so curl never bites before the watchdog -- the user-facing timeout is enforced by the watchdog using prefs.cloud_request_timeout, which the user can change in Settings AND can extend mid-request via the "Extend by 60s" button.
  CLOUD_TIMEOUT_DEFAULT = 180,   -- default value for prefs.cloud_request_timeout (the user-facing watchdog timeout for cloud providers)
  CLOUD_TIMEOUT_MIN     = 30,    -- min/max for the Settings input
  CLOUD_TIMEOUT_MAX     = 1800,
  EXTEND_BY_SECS    = 60,        -- "Extend by Ns" button bumps timeout by this many seconds per click
  EXTEND_SHOW_BEFORE_TIMEOUT = 30,  -- show the Extend button when within this many seconds of timeout
  UI_SCALE_OPTIONS   = { 0.75, 0.85, 1.0, 1.25, 1.5, 2.0 },  -- UI zoom choices
  UI_SCALE_LABELS    = { "75%", "85%", "100%", "125%", "150%", "200%" },
  CHAT_FONT_SIZES    = { 10, 12, 14 },   -- Small, Medium, Large (px before SC).
  -- Details-card mono font, indexed the same as CHAT_FONT_SIZES so
  -- the Chat Font preference scales both together. Sized -1 px vs the
  -- chat text to preserve the "secondary info" visual hierarchy the
  -- details card has always had (was a fixed SC(11) against chat 12).
  DETAILS_FONT_SIZES = { 9, 11, 13 },
  CHAT_FONT_LABELS   = { "Small", "Medium", "Large" },
  REPLY_LANGUAGE_LABELS = {
    "English", "Spanish", "French", "German", "Italian", "Portuguese",
  },
  REPLY_LANGUAGE_CODES = {
    "English", "Spanish", "French", "German", "Italian", "Portuguese",
  },
  MAX_HISTORY_TURNS = 6,         -- sliding window size (keep even)
  MAX_DISPLAY_MSGS  = 120,       -- soft cap on display_messages; oldest pruned
  MAX_CACHED_PARAMS = 80,        -- per-plugin cap in scan_fx_params / scan_fx_params_deep_body / _estimate_deep_probes (cache file size + LLM context budget)
  WIN_W             = 600,       -- initial window width (user can resize)
  WIN_H             = 800,       -- initial window height
  MAX_API_REF_BYTES = 512 * 1024, -- reject API ref files larger than 512 KB
  POLL_THROTTLE     = 0.1,       -- min interval between poll-loop file checks
  MAX_RETRIES       = 3,         -- max auto-retries on transient overload failures
  GEMINI_OVERLOAD_MAX_RETRIES = 1, -- fail fast on Gemini 503 high-demand windows; offer Flash 3 recovery instead of long hidden waits
  OPENAI_THROTTLE_MAX_RETRIES = 4, -- OpenAI TPM/rate-limit throttles are often sub-minute token-bucket recoveries
  RETRY_DELAY_BASE  = 2,         -- base seconds for exponential backoff
  RETRY_JITTER_SECS = 1,         -- random retry jitter to avoid synchronized retry spikes
  MAX_CALLS_PER_TURN = 15,       -- hard cap on POSTs in a single user turn
                                 -- (initial send + every silent context fetch
                                 -- and validator retry combined). Trips before
                                 -- a stuck small/local model can rack up real
                                 -- cost. Per-vector caps still apply; this is
                                 -- the aggregate backstop. Per-provider tuning
                                 -- is intentionally not exposed in v1.
  -- Auto-update / repair / bootstrap URL. Points at the raw GitHub base
  -- for the release tag or test branch. Current setting is the `test`
  -- branch for pre-release smoke testing; switch to a pinned tag like
  -- `v1.0.0` before public release so rolling heads cannot mutate under
  -- users mid-session. The manifest file at UPDATE_BASE_URL/UPDATE_MANIFEST
  -- lists the target version and every updatable file with its SHA-256,
  -- used by three flows:
  --   1. Update flow:  server version > CFG.VERSION -> prompt & download
  --   2. Repair flow:  version matches but local files differ -> prompt & download
  --   3. Bootstrap:    critical files missing at launch -> recovery screen
  -- Generate manifest.json per release by running:
  --   python .tools/gen_manifest.py --out manifest.json
  -- Then commit + push the manifest alongside the release tag.
  UPDATE_BASE_URL   = "https://raw.githubusercontent.com/michaelbriggsaudio/mbriggs-reaper/main/ReaAssist",
  UPDATE_MANIFEST   = "manifest.json",
  UPDATE_CURL_TIMEOUT = 15,      -- seconds; short timeout for lightweight checks
  -- Pure-Lua SHA-256 work budget per tick_sha_diff() call, in seconds.
  -- The verifier loops over small (16-block) chunks until this budget is
  -- spent or the file's hash state exhausts. Time-based instead of fixed
  -- block count so the per-frame cost adapts to the host CPU: a 10x slower
  -- machine processes 10x fewer blocks per frame, takes 10x longer wall
  -- clock, but never stalls a single frame past the budget. 5 ms keeps
  -- well inside a 16.67 ms 60 Hz frame, with headroom for the ImGui
  -- redraw and any other per-frame work.
  UPDATE_SHA_TIME_BUDGET = 0.005,
  -- Higher per-frame budget for verifies the user is actively waiting on
  -- (manual "Check for Updates" click or forced repair). The background
  -- piggyback check stays at the conservative 5 ms budget because the user
  -- is reading the chat response and any frame stutter is visible. A
  -- manual / forced verify happens behind a "Checking..." toast, so trading
  -- a little frame smoothness for ~2-3x faster wall-clock is the right
  -- call. 12 ms keeps each frame well under the 16.67 ms 60 Hz budget; on
  -- a slower main loop the value still bounds per-frame cost without
  -- starving ImGui.
  UPDATE_SHA_TIME_BUDGET_MANUAL = 0.012,
  -- Watchdog seconds for the native SHA-256 subprocess (PowerShell
  -- Get-FileHash on Windows, sha256sum / shasum on POSIX). Native hashing
  -- of ~3.6 MB across 23 files is sub-second; the dominant cost is process
  -- spawn (~200 ms warm) and I/O. 15 s gives generous slack for cold spawn
  -- on slow disks or AV scanning, after which tick_native_sha falls back
  -- to the pure-Lua incremental verifier as the reliability floor.
  UPDATE_NATIVE_SHA_TIMEOUT = 15,
  -- Seconds to wait after the first idle->waiting (Send) edge before firing
  -- the once-per-session update check. The chat curl's own PowerShell-launch
  -- ExecProcess freezes the main thread for ~1-3 s cold; firing the update
  -- check on the immediately-next frame stacks another ~200 ms PS-spawn onto
  -- the perceived Send-press freeze. Deferring lets the chat-curl freeze
  -- complete and lands the update spawn during "Thinking..." where the
  -- spinner is up and a brief hitch goes unnoticed. 400 ms covers the warm
  -- chat-curl PS exit (~200 ms) with margin and is short enough that the
  -- update check still completes well before the typical chat response.
  UPDATE_CHECK_DEFER = 0.4,
  _PRODUCT          = "ReaAssist",  -- product identity token
}
if CFG.EXT_NS ~= CFG._PRODUCT:lower() then return end

