-- Look up the explainer line for the current (provider, model, thinking) pick.
-- Returns the string from UI.COMBO_HINTS or nil if any layer is absent (custom
-- provider, missing thinking_level, uncovered combo). Callers render nothing
-- when nil.
function UI.combo_hint(provider, model, thinking_level)
  if not (provider and model) then return nil end
  if provider.is_custom then return nil end
  local p_tbl = UI.COMBO_HINTS[provider.id];  if not p_tbl then return nil end
  local m_tbl = p_tbl[model.id];              if not m_tbl then return nil end
  local key = thinking_level and thinking_level.value
  if not key then return nil end
  return m_tbl[key]
end

-- Look up the visual tone for the current (provider, model, thinking) pick.
-- Returns "warn" for combos that should carry the triangle-alert badge, or nil
-- for normal rows. Custom providers are skipped because their model/tuning
-- semantics are user-defined.
function UI.combo_tone(provider, model, thinking_level)
  if not (provider and model) then return nil end
  if provider.is_custom then return nil end
  local p_tbl = UI.COMBO_TONES[provider.id]; if not p_tbl then return nil end
  local m_tbl = p_tbl[model.id];             if not m_tbl then return nil end
  local key = thinking_level and thinking_level.value
  if not key then return nil end
  return m_tbl[key]
end


-- Floating toast: a top-level rounded bubble near the bottom-center of the
-- ReaAssist window. Draws its OWN window on top of whatever's below, so it's
-- visible regardless of scroll position or which settings page is current.
-- Animation: 180ms fade-in, 1.6s hold, 500ms fade-out (2.3s total).
-- Sticky=true skips the hold/fade-out and keeps the toast visible until the
-- caller replaces it (by firing another show_float_toast) or clears it
-- (S.float_toast = nil). Used by the Settings "Check for Updates" button
-- to show "Checking for updates..." throughout the async manifest fetch.
function UI.show_float_toast(text, kind, sticky)
  local now = reaper.time_precise()
  local FADE_IN, HOLD, FADE_OUT = 0.18, 1.6, 0.5
  S.float_toast = {
    text            = text,
    kind            = kind or "ok",  -- "ok" (green accent) | "err" (red accent)
    sticky          = sticky == true,
    start_at        = now,
    fade_in_end_at  = now + FADE_IN,
    hold_end_at     = now + FADE_IN + HOLD,
    fade_out_end_at = now + FADE_IN + HOLD + FADE_OUT,
    fade_in_s       = FADE_IN,
    fade_out_s      = FADE_OUT,
  }
end

-- =============================================================================
-- Utility: UI.open_url
-- =============================================================================
-- Opens a URL in the user's default browser. Tries SWS CF_ShellExecute first
-- (available when the SWS extension is installed), then falls back to
-- platform-native commands.
function UI.open_url(url)
  -- Only allow http(s) / mailto: / tel: URLs. Reject file://, javascript:,
  -- data:, and other schemes that could execute local code or inject
  -- content. mailto: + tel: are safe schemes handled by the OS shell
  -- (mail client / dialer) and are used by the Credits screen's contact
  -- links.
  if not (url:match("^https?://")
       or url:match("^mailto:")
       or url:match("^tel:")) then
    return
  end
  if reaper.CF_ShellExecute then
    reaper.CF_ShellExecute(url)
  else
    -- Sanitise: strip any characters that could enable shell injection.
    -- Excluded: $, (, ), %, `, ", \, ', and non-printable chars.
    -- $() = command substitution on Unix; %VAR% = expansion on Windows;
    -- backtick/backslash/quotes could break quoting boundaries.
    local safe = url:gsub("[^%w%-%.%_%~%:%/%?%#%[%]%@%!%&%*%+%,%;%=%{%}]", "")
    if RA.IS_WINDOWS then
      os.execute('start "" "' .. safe .. '"')
    else
      -- Single quotes disable all shell interpretation (no $(), no \, no `).
      os.execute("open '" .. safe .. "' 2>/dev/null || xdg-open '" .. safe .. "' &")
    end
  end
end

-- =============================================================================
-- Attachment system (base64, file I/O, screenshot, clipboard, attach helpers)
-- =============================================================================
-- Wrapped in do...end to keep internal helpers out of the main-chunk local
-- count (Lua 5.x limit: 200 locals per function/chunk).
Attach = {}
do -- attachment system scope

local b64_chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
Attach.base64_encode = function(data, start_pos, end_pos)
  if not data or #data == 0 then return "" end
  start_pos = start_pos or 1
  end_pos   = end_pos   or #data
  local out = {}
  local i = start_pos
  while i <= end_pos - 2 do
    local a, b, c = str_byte(data, i, i + 2)
    local n = a * 65536 + b * 256 + c
    out[#out+1] = str_sub(b64_chars, math_floor(n / 262144) + 1, math_floor(n / 262144) + 1)
    out[#out+1] = str_sub(b64_chars, math_floor(n / 4096) % 64 + 1, math_floor(n / 4096) % 64 + 1)
    out[#out+1] = str_sub(b64_chars, math_floor(n / 64) % 64 + 1, math_floor(n / 64) % 64 + 1)
    out[#out+1] = str_sub(b64_chars, n % 64 + 1, n % 64 + 1)
    i = i + 3
  end
  local remain = end_pos - i + 1
  if remain == 2 then
    local a, b = str_byte(data, i, i + 1)
    local n = a * 65536 + b * 256
    out[#out+1] = str_sub(b64_chars, math_floor(n / 262144) + 1, math_floor(n / 262144) + 1)
    out[#out+1] = str_sub(b64_chars, math_floor(n / 4096) % 64 + 1, math_floor(n / 4096) % 64 + 1)
    out[#out+1] = str_sub(b64_chars, math_floor(n / 64) % 64 + 1, math_floor(n / 64) % 64 + 1)
    out[#out+1] = "="
  elseif remain == 1 then
    local a = str_byte(data, i)
    local n = a * 65536
    out[#out+1] = str_sub(b64_chars, math_floor(n / 262144) + 1, math_floor(n / 262144) + 1)
    out[#out+1] = str_sub(b64_chars, math_floor(n / 4096) % 64 + 1, math_floor(n / 4096) % 64 + 1)
    out[#out+1] = "=="
  end
  return tbl_concat(out)
end

-- Chunked base64 encoder for large attachments. Pure Lua base64 over a 10MB
-- file is ~13M operations and freezes the UI thread for hundreds of ms in a
-- single synchronous pass -- catastrophic for low-latency audio. Instead we
-- pre-encode at attach time, processing one ~256KB chunk per main-loop frame
-- via Attach.pump_encoding(). The Send button stays disabled until every
-- binary attachment has finished encoding.
--
-- Chunk size is 3-byte aligned (every base64 group is 3 input bytes -> 4
-- output chars) so each chunk produces padding-free output that can be
-- concatenated directly. The very last chunk may include 1-2 leftover bytes
-- and gets the standard '='/'==' padding from base64_encode.
local B64_CHUNK_BYTES = math_floor(256 * 1024 / 3) * 3  -- ~256KB, 3-aligned

-- Attach.pump_encoding() -- called once per main-loop frame.
-- Encodes one chunk for the first attachment that still needs encoding.
-- Returns true while any work remains, false when all attachments are done.
Attach.pump_encoding = function()
  for _, att in ipairs(S.attachments) do
    if att.kind ~= "text" and not att.b64 then
      if not att.b64_pos then
        att.b64_pos   = 1
        att.b64_parts = {}
      end
      local len       = #att.data
      local remaining = len - att.b64_pos + 1
      local take      = (remaining <= B64_CHUNK_BYTES) and remaining or B64_CHUNK_BYTES
      att.b64_parts[#att.b64_parts+1] = Attach.base64_encode(att.data, att.b64_pos, att.b64_pos + take - 1)
      att.b64_pos = att.b64_pos + take
      if att.b64_pos > len then
        -- Encoding complete: flatten to a single string and free the source
        -- bytes so we don't carry around two copies of a 10MB file in memory.
        att.b64       = tbl_concat(att.b64_parts)
        att.b64_parts = nil
        att.b64_pos   = nil
        att.data      = nil
      end
      return true  -- one chunk per frame is enough
    end
  end
  return false
end

-- Attach.all_encoded() -- true when every binary attachment has finished
-- base64 encoding. Used by the Send button can_send check to block sending
-- until pre-encoding completes.
Attach.all_encoded = function()
  for _, att in ipairs(S.attachments) do
    if att.kind ~= "text" and not att.b64 then return false end
  end
  return true
end

-- Attach.encoding_progress() -> {bytes_done, bytes_total} or nil if no work
-- pending. Used by the attachment strip to draw a progress indicator.
Attach.encoding_progress = function()
  local done, total = 0, 0
  local any_pending = false
  for _, att in ipairs(S.attachments) do
    if att.kind ~= "text" then
      if att.b64 then
        -- Already encoded -- we no longer have att.data, but we tracked the
        -- byte count by counting base64 chars * 3 / 4 (close enough for the
        -- progress display).
        local approx_bytes = math_floor(#att.b64 * 3 / 4)
        done  = done  + approx_bytes
        total = total + approx_bytes
      else
        any_pending = true
        local len = #att.data
        total = total + len
        done  = done  + (att.b64_pos or 1) - 1
      end
    end
  end
  if not any_pending then return nil end
  return done, total
end

-- =============================================================================
-- Attachment utilities
-- =============================================================================
-- Supported image MIME types for the AI provider vision endpoints.
local IMAGE_EXTENSIONS = {
  jpg = "image/jpeg", jpeg = "image/jpeg", png = "image/png",
  gif = "image/gif", webp = "image/webp",
}
-- Text file extensions that are read as UTF-8 text and sent as text blocks.
local TEXT_EXTENSIONS = {
  lua = true, txt = true, csv = true, py = true, js = true, ts = true,
  json = true, xml = true, html = true, css = true, md = true, yaml = true,
  yml = true, ini = true, cfg = true, conf = true, sh = true, bat = true,
  log = true, rpp = true, reascript = true, c = true, cpp = true, h = true,
  jsfx = true, ["jsfx-inc"] = true, eel = true,
}

-- get_file_extension(path) -> lowercase extension without dot, or ""
local function get_file_extension(path)
  local ext = path:match("%.([^%.]+)$")
  return ext and ext:lower() or ""
end

-- get_filename(path) -> filename with extension
local function get_filename(path)
  return path:match("[^\\/]+$") or path
end

-- Maximum size (bytes) for text attachments. Files larger than this are
-- rejected to avoid blowing up token budgets and provider context windows.
local TEXT_ATTACH_MAX_BYTES = 200 * 1024  -- 200 KB

-- is_likely_binary(path) -> true if the file appears to be binary.
-- Reads the first 512 bytes and checks for null bytes, which are absent
-- in well-formed UTF-8 / ASCII text but common in binary formats.
local function is_likely_binary(path)
  local f = io.open(path, "rb")
  if not f then return false end
  local head = f:read(512)
  f:close()
  if not head then return false end
  return head:find("\0") ~= nil
end

-- classify_file(path) -> "image", "pdf", "text", or "unsupported" + media_type
-- Only files with a recognised text extension (or that pass a binary sniff
-- test) are treated as text. Unknown extensions default to "unsupported" to
-- prevent binary files from being shoved into the prompt as garbage.
local function classify_file(path)
  local ext = get_file_extension(path)
  if IMAGE_EXTENSIONS[ext] then return "image", IMAGE_EXTENSIONS[ext] end
  if ext == "pdf" then return "pdf", "application/pdf" end
  if TEXT_EXTENSIONS[ext] then return "text", nil end
  -- Unknown extension: attempt a binary sniff. If the file looks like text,
  -- allow it; otherwise reject it as unsupported.
  if ext ~= "" and not is_likely_binary(path) then return "text", nil end
  return "unsupported", nil
end

-- read_file_binary(path) -> data string or nil, error
local function read_file_binary(path)
  local f, err = io.open(path, "rb")
  if not f then return nil, err end
  local data = f:read("*a")
  f:close()
  return data
end

-- read_file_text(path) -> text string or nil, error
local function read_file_text(path)
  local f, err = io.open(path, "r")
  if not f then return nil, err end
  local text = f:read("*a")
  f:close()
  return text
end

-- read_image_dimensions(data, media_type) -> width, height or nil, nil
-- Reads pixel dimensions from PNG/JPEG/GIF/WebP file headers without
-- decoding the full image. Returns nil if the format is unrecognized.
local function read_image_dimensions(data, media_type)
  if not data or #data < 24 then return nil, nil end

  -- PNG: bytes 1-8 are signature, IHDR chunk starts at byte 9.
  -- Width at bytes 17-20, height at bytes 21-24 (big-endian uint32).
  if media_type == "image/png" then
    if str_sub(data, 1, 4) == "\137PNG" then
      local w = str_byte(data,17)*16777216 + str_byte(data,18)*65536
             + str_byte(data,19)*256 + str_byte(data,20)
      local h = str_byte(data,21)*16777216 + str_byte(data,22)*65536
             + str_byte(data,23)*256 + str_byte(data,24)
      if w > 0 and h > 0 then return w, h end
    end
  end

  -- JPEG: scan for SOF0/SOF2 marker (0xFF 0xC0 or 0xFF 0xC2).
  -- Height at marker+5 (2 bytes), width at marker+7 (2 bytes), big-endian.
  if media_type == "image/jpeg" then
    local pos = 1
    local len = #data
    while pos < len - 10 do
      if str_byte(data, pos) == 0xFF then
        local marker = str_byte(data, pos + 1)
        if marker == 0xC0 or marker == 0xC2 then
          local h = str_byte(data, pos+5)*256 + str_byte(data, pos+6)
          local w = str_byte(data, pos+7)*256 + str_byte(data, pos+8)
          if w > 0 and h > 0 then return w, h end
        end
        -- Skip to next marker using segment length
        if marker ~= 0x00 and marker ~= 0xFF and marker ~= 0xD8 and marker ~= 0xD9 then
          if pos + 3 <= len then
            local seg_len = str_byte(data, pos+2)*256 + str_byte(data, pos+3)
            -- A valid JPEG segment includes the 2-byte length field
            -- itself; seg_len < 2 is malformed and would either loop
            -- forever (seg_len = 0) or rewind into the marker we just
            -- read. Bail rather than risk the loop on hostile input.
            if seg_len < 2 then break end
            pos = pos + 2 + seg_len
          else
            break
          end
        else
          pos = pos + 1
        end
      else
        pos = pos + 1
      end
    end
  end

  -- GIF: width at bytes 7-8, height at bytes 9-10 (little-endian uint16).
  if media_type == "image/gif" then
    if str_sub(data, 1, 3) == "GIF" then
      local w = str_byte(data,7) + str_byte(data,8)*256
      local h = str_byte(data,9) + str_byte(data,10)*256
      if w > 0 and h > 0 then return w, h end
    end
  end

  -- WebP: "RIFF" at 1-4, "WEBP" at 9-12. VP8 chunk has dimensions.
  if media_type == "image/webp" then
    if str_sub(data, 1, 4) == "RIFF" and str_sub(data, 9, 12) == "WEBP" then
      local chunk = str_sub(data, 13, 16)
      if chunk == "VP8 " and #data >= 30 then
        -- Lossy VP8: width at 27-28, height at 29-30 (little-endian, masked)
        local w = (str_byte(data,27) + str_byte(data,28)*256) % 16384
        local h = (str_byte(data,29) + str_byte(data,30)*256) % 16384
        if w > 0 and h > 0 then return w, h end
      elseif chunk == "VP8L" and #data >= 26 then
        -- Lossless VP8L: packed bits at byte 22-25
        local b1,b2,b3,b4 = str_byte(data,22,25)
        local w = (b1 + (b2 % 64) * 256) + 1
        local h = (math_floor(b2/64) + b3*4 + (b4 % 16)*1024) + 1
        if w > 0 and h > 0 then return w, h end
      end
    end
  end

  return nil, nil
end

-- Estimate token cost for an attachment. Returns estimated tokens (number).
-- Images: based on pixel dimensions (tokens ~ width*height/750).
-- PDFs: ~1500 tokens per page; estimated from file size (~50KB per page).
-- Text: ~4 chars per token.
local function estimate_attachment_tokens(attachment)
  if attachment.kind == "image" then
    -- Try to read actual dimensions from the image header.
    -- Claude resizes images so the longest side is at most 1568px before
    -- calculating tokens. Apply the same scaling here for accuracy.
    local w, h = read_image_dimensions(attachment.data, attachment.media_type)
    if w and h then
      local MAX_SIDE = 1568
      if w > MAX_SIDE or h > MAX_SIDE then
        local scale = MAX_SIDE / math_max(w, h)
        w = math_floor(w * scale)
        h = math_floor(h * scale)
      end
      return math_max(85, math_floor(w * h / 750))
    end
    -- Fallback: rough estimate from file size (conservative 2 bytes/pixel
    -- for PNG screenshots which compress heavily).
    local pixels = #attachment.data / 2
    return math_max(85, math_floor(pixels / 750))
  elseif attachment.kind == "pdf" then
    local pages = math_max(1, math_floor(#attachment.data / 50000))
    return pages * 1500
  elseif attachment.kind == "text" then
    return math_floor(#attachment.data / 4)
  end
  return 0
end

-- Estimate USD cost for attachment tokens given the current model.
local function estimate_attachment_cost(tokens)
  local model = MODELS[prefs.model_idx]
  if not model then return 0 end
  return tokens * model.price_in / 1000000
end

-- Max attachment size (bytes) -- warn above 5MB, reject above 10MB.
-- Claude resizes images internally, so >10MB rarely adds value.
local ATTACH_WARN_BYTES  = 5 * 1024 * 1024
local ATTACH_MAX_BYTES   = 10 * 1024 * 1024
local ATTACH_MAX_COUNT   = 10  -- max attachments per message

-- =============================================================================
-- Screenshot capture
-- =============================================================================
-- Captures the screen to a temporary PNG file for use as an attachment.
-- Windows: uses PowerShell + .NET GDI to capture the REAPER main window
--   region specifically (requires js_ReaScriptAPI for JS_Window_GetRect;
--   falls back to full primary screen if the extension is not installed).
-- macOS: uses the built-in screencapture utility (silent, no shutter sound).
--   This captures all screens, not just the REAPER window -- macOS does not
--   expose a simple per-window capture via shell without extra dependencies.
-- Linux: not currently supported (returns nil).
-- Returns the PNG file path on success, or nil + error string.
local function capture_screenshot()
  local png_path = tmp.screenshot

  if RA.IS_WINDOWS then
    local hwnd = reaper.GetMainHwnd()
    if not hwnd then return nil, "Could not find REAPER main window." end

    local ps_script
    if reaper.JS_Window_GetRect then
      local _, left, top, right, bottom = reaper.JS_Window_GetRect(hwnd)
      local w = right - left
      local h = bottom - top
      if w <= 0 or h <= 0 then return nil, "Invalid window dimensions." end
      -- Minimized REAPER on Windows reports rect coords near (-32000,
      -- -32000) -- the standard ShowWindow(SW_MINIMIZE) sentinel. The
      -- positive w/h above passes the previous guard, but CopyFromScreen
      -- from those coordinates produces a uniformly black bitmap that
      -- attaches as a useless screenshot. Treat any far-off-screen
      -- origin as minimized/hidden and refuse the capture so the user
      -- gets a clear error instead of a black image.
      if left < -10000 or top < -10000 then
        return nil, "REAPER window is minimized or off-screen. "
          .. "Restore it before taking a screenshot."
      end
      ps_script = str_format(
        "Add-Type -AssemblyName System.Drawing; "
        .. "$bmp = New-Object System.Drawing.Bitmap(%d, %d); "
        .. "$g = [System.Drawing.Graphics]::FromImage($bmp); "
        .. "$g.CopyFromScreen(%d, %d, 0, 0, $bmp.Size); "
        .. "$g.Dispose(); "
        .. "$bmp.Save('%s', [System.Drawing.Imaging.ImageFormat]::Png); "
        .. "$bmp.Dispose(); "
        .. "Write-Output 'OK'",
        w, h, left, top, png_path:gsub("'", "''"))
    else
      ps_script =
        "Add-Type -AssemblyName System.Drawing; "
        .. "Add-Type -AssemblyName System.Windows.Forms; "
        .. "$bounds = [System.Windows.Forms.Screen]::PrimaryScreen.Bounds; "
        .. "$bmp = New-Object System.Drawing.Bitmap($bounds.Width, $bounds.Height); "
        .. "$g = [System.Drawing.Graphics]::FromImage($bmp); "
        .. "$g.CopyFromScreen($bounds.Location, [System.Drawing.Point]::Empty, $bounds.Size); "
        .. "$g.Dispose(); "
        .. "$bmp.Save('" .. png_path:gsub("'", "''") .. "', "
        .. "[System.Drawing.Imaging.ImageFormat]::Png); "
        .. "$bmp.Dispose(); "
        .. "Write-Output 'OK'"
    end

    local ps_cmd = 'powershell -NoProfile -WindowStyle Hidden -Command "' .. ps_script .. '"'
    local result = reaper.ExecProcess(ps_cmd, 10000)
    if not result or not result:match("OK") then
      os.remove(png_path)
      return nil, "Screenshot capture failed. PowerShell returned: "
        .. tostring(result and result:sub(1, 200) or "nil")
    end

    local f = io.open(png_path, "rb")
    if f then
      local size = f:seek("end")
      f:close()
      if size and size > 0 then
        return png_path
      end
    end
    os.remove(png_path)
    return nil, "Screenshot produced an empty file."

  elseif RA.IS_MACOS then
    -- screencapture -x: silent (no shutter sound). Captures all screens.
    -- Absolute path because REAPER's os.execute / ExecProcess on some
    -- macOS configs (notably Tahoe) doesn't reliably resolve PATH-based
    -- binaries; mirrors the /usr/bin/curl pattern in the installer.
    local sq_path = "'" .. png_path:gsub("'", "'\\''") .. "'"
    local ok, _, code = os.execute("/usr/sbin/screencapture -x " .. sq_path)
    if ok then
      local f = io.open(png_path, "rb")
      if f then
        local size = f:seek("end")
        f:close()
        if size and size > 0 then return png_path end
      end
    end
    os.remove(png_path)
    -- Surface the actionable cause via a modal popup. Since macOS 10.15,
    -- screencapture from a child process is denied when the parent app
    -- (REAPER) lacks Screen Recording permission -- with no Lua-level
    -- error, the file just never appears or comes back empty. The
    -- transient inline error in the attachment row is too short to fit
    -- the recovery steps, so use reaper.MB to deliver them.
    reaper.MB(
      "Screenshot capture failed (exit " .. tostring(code or "?") .. ").\n\n"
      .. "On macOS this usually means REAPER does not have Screen Recording "
      .. "permission. To grant it:\n\n"
      .. "1. Open System Settings > Privacy & Security > Screen Recording.\n"
      .. "2. Enable REAPER in the list.\n"
      .. "3. Quit and reopen REAPER (macOS requires this before the new "
      .. "permission takes effect).\n"
      .. "4. Try the screenshot attachment again.\n\n"
      .. "On macOS Sequoia / Tahoe you may also see a one-time \"bypass "
      .. "the system private window picker\" prompt the first time the "
      .. "capture runs -- click Allow.",
      "ReaAssist", 0)
    return nil, "Screenshot capture failed (see popup for details)."
  end

  return nil, "Screenshot capture is not supported on Linux."
end

-- =============================================================================
-- Clipboard image paste
-- =============================================================================
-- Checks if the clipboard contains an image and returns it as a PNG file path.
-- Windows: uses PowerShell with .NET to read the clipboard.
-- macOS: uses osascript to read clipboard image data and write it as PNG.
local function get_clipboard_image()
  local png_path = tmp.clipboard

  if RA.IS_WINDOWS then
    local ps_cmd = 'powershell -NoProfile -WindowStyle Hidden -Command "'
      .. "Add-Type -AssemblyName System.Windows.Forms; "
      .. "Add-Type -AssemblyName System.Drawing; "
      .. "$img = [System.Windows.Forms.Clipboard]::GetImage(); "
      .. "if ($img -ne $null) { "
      .. "$img.Save('" .. png_path:gsub("'", "''") .. "', "
      .. "[System.Drawing.Imaging.ImageFormat]::Png); "
      .. "Write-Output 'OK' "
      .. '} else { Write-Output \'EMPTY\' }"'

    local result = reaper.ExecProcess(ps_cmd, 5000)
    if result and result:match("OK") then
      local f = io.open(png_path, "rb")
      if f then
        local size = f:seek("end")
        f:close()
        if size and size > 0 then return png_path end
      end
    end
    os.remove(png_path)
    return nil

  elseif RA.IS_MACOS then
    -- Use osascript to grab clipboard image data as PNG and write to file.
    local sq_path = png_path:gsub("'", "'\\''")
    local cmd = "osascript -e '"
      .. 'try\n'
      .. '  set imgData to the clipboard as «class PNGf»\n'
      .. '  set fp to open for access POSIX file "' .. sq_path .. '" with write permission\n'
      .. '  set eof fp to 0\n'
      .. '  write imgData to fp\n'
      .. '  close access fp\n'
      .. '  return "OK"\n'
      .. 'on error\n'
      .. '  return "EMPTY"\n'
      .. "end try'"
    local handle = io.popen(cmd)
    if handle then
      local result = handle:read("*a")
      handle:close()
      if result and result:match("OK") then
        local f = io.open(png_path, "rb")
        if f then
          local size = f:seek("end")
          f:close()
          if size and size > 0 then return png_path end
        end
      end
    end
    os.remove(png_path)
    return nil
  end

  return nil
end

-- Attach.file(path) -> true on success, false + sets S.attach_error on failure.
-- Reads the file, classifies it, estimates cost, and adds to the queue.
Attach.file = function(path)
  if #S.attachments >= ATTACH_MAX_COUNT then
    S.attach_error = str_format("Maximum %d attachments per message.", ATTACH_MAX_COUNT)
    S.attach_error_time = time_precise()
    return false
  end

  local kind, media_type = classify_file(path)

  if kind == "unsupported" then
    local ext = get_file_extension(path)
    S.attach_error = str_format(
      "Unsupported file type%s. Supported: images, PDFs, and common text formats.",
      ext ~= "" and (" (." .. ext .. ")") or "")
    S.attach_error_time = time_precise()
    return false
  end

  local data, err
  if kind == "text" then
    data, err = read_file_text(path)
  else
    data, err = read_file_binary(path)
  end

  if not data then
    S.attach_error = "Could not read file: " .. tostring(err)
    S.attach_error_time = time_precise()
    return false
  end

  -- Text-specific size cap: prevents token budget blow-ups from large logs,
  -- data files, etc. Binary attachments (images, PDFs) use the general cap.
  if kind == "text" and #data > TEXT_ATTACH_MAX_BYTES then
    S.attach_error = str_format("Text file too large (%.0f KB, max %d KB).",
      #data / 1024, TEXT_ATTACH_MAX_BYTES / 1024)
    S.attach_error_time = time_precise()
    return false
  end

  if #data > ATTACH_MAX_BYTES then
    S.attach_error = str_format("File too large (%.1f MB, max %d MB).",
      #data / 1048576, ATTACH_MAX_BYTES / 1048576)
    S.attach_error_time = time_precise()
    return false
  end

  if #data == 0 then
    S.attach_error = "File is empty."
    S.attach_error_time = time_precise()
    return false
  end

  local entry = {
    kind       = kind,
    name       = get_filename(path),
    data       = data,
    media_type = media_type,
    path       = path,
  }
  entry.tokens = estimate_attachment_tokens(entry)
  entry.cost   = estimate_attachment_cost(entry.tokens)

  S.attachments[#S.attachments+1] = entry

  if #data > ATTACH_WARN_BYTES then
    S.attach_error = str_format("Large file (%.1f MB), estimated cost: %s",
      #data / 1048576, MODELS.format_cost(entry.cost))
    S.attach_error_time = time_precise()
  end

  return true
end

-- Attach.screenshot() -> true on success, false on failure (sets S.attach_error)
Attach.screenshot = function()
  if #S.attachments >= ATTACH_MAX_COUNT then
    S.attach_error = str_format("Maximum %d attachments per message.", ATTACH_MAX_COUNT)
    S.attach_error_time = time_precise()
    return false
  end

  local png_path, err = capture_screenshot()
  if not png_path then
    S.attach_error = err or "Screenshot failed."
    S.attach_error_time = time_precise()
    return false
  end

  local data = read_file_binary(png_path)
  os.remove(png_path)  -- clean up temp file

  if not data or #data == 0 then
    S.attach_error = "Screenshot produced an empty file."
    S.attach_error_time = time_precise()
    return false
  end

  if #data > ATTACH_MAX_BYTES then
    S.attach_error = str_format("Screenshot too large (%.1f MB, max %d MB).",
      #data / 1048576, ATTACH_MAX_BYTES / 1048576)
    S.attach_error_time = time_precise()
    return false
  end

  local entry = {
    kind       = "image",
    name       = "Screenshot",
    data       = data,
    media_type = "image/png",
    path       = nil,
  }
  entry.tokens = estimate_attachment_tokens(entry)
  entry.cost   = estimate_attachment_cost(entry.tokens)

  S.attachments[#S.attachments+1] = entry
  return true
end

-- Attach.clipboard() -> true if an image was found and attached, false otherwise
Attach.clipboard = function()
  if #S.attachments >= ATTACH_MAX_COUNT then
    S.attach_error = str_format("Maximum %d attachments per message.", ATTACH_MAX_COUNT)
    S.attach_error_time = time_precise()
    return false
  end

  local png_path = get_clipboard_image()
  if not png_path then
    S.attach_error = "No image found in clipboard."
    S.attach_error_time = time_precise()
    return false
  end

  local data = read_file_binary(png_path)
  os.remove(png_path)  -- clean up temp file

  if not data or #data == 0 then
    S.attach_error = "Clipboard image is empty."
    S.attach_error_time = time_precise()
    return false
  end

  if #data > ATTACH_MAX_BYTES then
    S.attach_error = str_format("Clipboard image too large (%.1f MB, max %d MB).",
      #data / 1048576, ATTACH_MAX_BYTES / 1048576)
    S.attach_error_time = time_precise()
    return false
  end

  local entry = {
    kind       = "image",
    name       = "Clipboard image",
    data       = data,
    media_type = "image/png",
    path       = nil,
  }
  entry.tokens = estimate_attachment_tokens(entry)
  entry.cost   = estimate_attachment_cost(entry.tokens)

  S.attachments[#S.attachments+1] = entry
  return true
end

end -- attachment system scope

-- =============================================================================
-- System prompt
-- =============================================================================
-- Loaded from System_Prompt.md at startup. {VERSION} is replaced
-- with CFG.VERSION.
--
-- Power-user override: if System_Prompt_Custom.md exists in the
-- same Resources/ folder, it is loaded INSTEAD of the stock prompt. The
-- custom file is not in the update manifest, so it survives updates and
-- is never touched by repair. The stock file may still change across
-- updates; advance_after_rename detects that and queues a one-time toast
-- on next launch reminding the user to review the new stock prompt.
local SYSTEM_PROMPT
local SYSTEM_PROMPT_IS_CUSTOM = false
-- Loads the system prompt at the kick-off block (after the bootstrap
-- critical-files check has run) so a missing or token-gutted stock prompt
-- can route into bootstrap recovery instead of returning from the main
-- chunk before recovery has a chance to render. Returns true on success;
-- on failure either sets S.bootstrap_active (stock missing/corrupt, repair
-- can fix it) or shows a message box (custom override is the user's file
-- and bootstrap cannot restore it).
local function load_system_prompt()
  local stock_path  = RA.RESOURCES_DIR .. "System_Prompt.md"
  local custom_path = RA.RESOURCES_DIR .. "System_Prompt_Custom.md"
  local prompt_path = stock_path
  if reaper.file_exists(custom_path) then
    prompt_path = custom_path
    SYSTEM_PROMPT_IS_CUSTOM = true
  end
  local f = io.open(prompt_path, "r")
  if not f then
    if SYSTEM_PROMPT_IS_CUSTOM then
      reaper.ShowMessageBox(
        "Could not load system prompt file:\n" .. prompt_path
        .. "\n\nPlease make sure System_Prompt.md is in the "
        .. "Resources/ subfolder next to ReaAssist.lua.",
        "ReaAssist", 0)
      return false
    end
    S.bootstrap_active = true
    S.bootstrap_missing[#S.bootstrap_missing + 1] =
      "Resources/System_Prompt.md"
    -- Log only; do NOT call Updater._set_failure here. _set_failure
    -- populates update.last_error, which Bootstrap.loop's view selector
    -- reads as "the last repair attempt failed" and routes straight to
    -- render_failed -- skipping the normal recovery prompt that lets
    -- the user click Repair. This is a load-time detection of a
    -- recoverable file (downloading it again will fix it), not a
    -- failed repair, so we leave last_error alone and let the
    -- bootstrap_active + bootstrap_missing entries drive render_prompt.
    Log.line("BOOTSTRAP",
      "system_prompt_load: System_Prompt.md missing; "
      .. "routing to recovery prompt.")
    return false
  end
  local raw = f:read("*a"); f:close()
  -- Strip the HTML comment header (<!-- ... -->) lines so they don't leak
  -- into the prompt sent to the API.
  raw = raw:gsub("<!%-%-.-%-%->\n?", "")
  local sws_required_prompt =
    REQUIRE_SWS_EXTENSION and not SupportExtFlag("optoutsws")
  if sws_required_prompt then
    raw = raw:gsub(
      "%- Extension APIs: avoid SWS %(CF_%*%), js_ReaScriptAPI %(JS_%*%), and other non%-core extension functions unless the user explicitly requests them or the script first checks the function exists %(e%.g%. if reaper%.CF_GetClipboard then %.%.%. end%) and shows a clear error if missing%.",
      "- Extension APIs: SWS Extension is available and required in this build. Treat documented SWS APIs (`CF_*`, `BR_*`, `NF_*`, `FNG_*`) as available after requesting `docs:sws` when needed. js_ReaScriptAPI (`JS_*`) and other non-core extension functions remain optional unless the user explicitly requests them or the script first checks the function exists and shows a clear error if missing."
    )
  end
  SYSTEM_PROMPT = raw:gsub("{VERSION}", CFG.VERSION)
  if sws_required_prompt then
    SYSTEM_PROMPT = SYSTEM_PROMPT .. [[

SWS DOCS ROUTING:
- Before using SWS-only calls, request <context_needed>docs:sws</context_needed> unless that section is already present in context.
- Prefer native REAPER APIs when they are equally direct; use SWS for clipboard, mouse cursor context, GUID helpers, loudness analysis, SWS notes, FX-chain window helpers, and other APIs documented in docs:sws.
]]
  end
  -- Tamper guard for the SHIPPED prompt only: if the stock file has been
  -- gutted, partially truncated, or replaced with junk, route into bootstrap
  -- recovery so repair can restore it. Custom overrides bypass this check;
  -- power users may legitimately rewrite the branding in their own copy.
  --
  -- We require multiple structural anchors (not just the product token) so
  -- a partial corruption that still contains "ReaAssist" somewhere in the
  -- file passes through and produces one bad chat session before the SHA
  -- repair check catches it on the next launch. The anchors below are the
  -- prompt's load-bearing section headers; if any one is missing, the file
  -- is structurally broken and unsafe to feed to a model.
  if not SYSTEM_PROMPT_IS_CUSTOM then
    local required_anchors = {
      CFG._PRODUCT,
      "CORE BEHAVIOR:",
      "CONTEXT BUCKETS",
      "API REF REQUIREMENT",
      "PROMPT BUNDLES",
    }
    for _, anchor in ipairs(required_anchors) do
      if not SYSTEM_PROMPT:find(anchor, 1, true) then
        S.bootstrap_active = true
        S.bootstrap_missing[#S.bootstrap_missing + 1] =
          "Resources/System_Prompt.md (corrupt)"
        -- Log only; see the parallel comment on the missing-file branch
        -- above for why we do NOT call Updater._set_failure here. The
        -- specific anchor is preserved in the debug log for triage.
        Log.line("BOOTSTRAP", string.format(
          "system_prompt_load: System_Prompt.md corrupt "
          .. "(missing anchor %q); routing to recovery prompt.",
          anchor))
        return false
      end
    end
  end
  -- Log custom-prompt usage so support can rule it in/out when triaging
  -- "weird model output" reports. No-op if debug logging is disabled.
  if SYSTEM_PROMPT_IS_CUSTOM then
    Log.line("PROMPT",
      "Using System_Prompt_Custom.md (override active)")
  end
  return true
end

-- CTX is a plain global (cross-file shared state; its `= {}` initializer
-- runs later in this file). Code.auto_save_jsfx invalidates the installed-FX
-- cache after saving a new plugin by touching CTX, which is harmless before
-- the initializer because the touch happens inside a function body, not at
-- load time.

Code = {}

-- Forward declaration so Code.ensure_preferred_from_chains (defined further
-- down) can call _is_fabfilter_ident, which is itself defined later in the
-- file alongside FABFILTER_DEV_STEMS. Without this forward decl, Lua's
-- parser treats the call site as a global lookup and the call resolves to
-- nil at runtime. Assignment happens via the (de-localised) `function
-- _is_fabfilter_ident(ident)` at the original definition site below; that
-- form looks up the existing local in scope and re-binds it instead of
-- shadowing it with a fresh local.
local _is_fabfilter_ident

-- =============================================================================
-- Utility: Code.safe_write
-- =============================================================================
-- Writes content to a file path with crash- and failure-safe semantics:
--   1. Write to <path>.tmp, checking both f:write and f:close for nil+err
--      returns (not just thrown errors -- short writes/disk full/permission
--      failures come back that way in Lua, not as exceptions).
--   2. Rename any existing <path> to <path>.bak so the original is preserved.
--   3. Rename <path>.tmp -> <path>. If that fails, restore from .bak.
--   4. On success, remove .bak.
-- The original file is never destroyed unless the replacement is in place.
-- Returns true on success, shows a message box and returns false on failure.
function Code.safe_write(path, content)
  local tmp_path = path .. ".tmp"
  local bak_path = path .. ".bak"
  local f, err = io.open(tmp_path, "wb")
  if not f then
    reaper.ShowMessageBox(
      "Could not write file:\n" .. tmp_path .. "\n\n" .. tostring(err),
      "ReaAssist - File Error", 0)
    return false
  end
  local w_ok, w_err = pcall(function()
    local ok, perr = f:write(content)
    if not ok then error(perr or "write returned nil", 0) end
  end)
  local c_ok, c_err = pcall(function()
    local ok, perr = f:close()
    if not ok then error(perr or "close returned nil", 0) end
  end)
  if not w_ok or not c_ok then
    os.remove(tmp_path)
    reaper.ShowMessageBox(
      "Failed writing temp file:\n" .. tmp_path .. "\n\n" .. tostring(w_err or c_err),
      "ReaAssist - File Error", 0)
    return false
  end
  -- Preserve the original until the new file is definitely in place. Windows
  -- os.rename fails when the destination exists, so move the original out of
  -- the way first. os.rename returns nil when the source does not exist (a
  -- fresh write); had_original tracks that so restoration is only attempted
  -- when there was actually something to restore.
  os.remove(bak_path)
  local had_original = os.rename(path, bak_path)
  local ok_r, ren_err = os.rename(tmp_path, path)
  if not ok_r then
    if had_original then os.rename(bak_path, path) end
    os.remove(tmp_path)
    reaper.ShowMessageBox(
      "Could not finalize file:\n" .. path .. "\n\n" .. tostring(ren_err),
      "ReaAssist - File Error", 0)
    return false
  end
  os.remove(bak_path)
  return true
end

-- =============================================================================
-- Utility: Code.derive_filename
-- =============================================================================
-- Suggests a .lua filename from code content without an API call.
-- Strategy (in priority order):
--   1. First line if it is a comment: "-- My Script" -> "My Script.lua"
--   2. Undo_EndBlock label: "ReaAssist: Create 20 tracks" -> "Create 20 tracks.lua"
--   3. First function name: "local function do_thing()" -> "do_thing.lua"
--   4. Fallback: "reaassist_script.lua"
-- Result is safe for all OSes: filesystem-unsafe chars stripped,
-- spaces preserved, length capped at 60 chars.
-- Windows reserved device names. Any filename whose stem (case-insensitive,
-- ignoring extension) matches one of these is rejected by Win32 even on NTFS,
-- so we can't write "CON.lua" or "AUX.jsfx". Suffix with "_" to dodge.
local WIN_RESERVED_NAMES = {
  CON=true, PRN=true, AUX=true, NUL=true,
  COM1=true, COM2=true, COM3=true, COM4=true, COM5=true,
  COM6=true, COM7=true, COM8=true, COM9=true,
  LPT1=true, LPT2=true, LPT3=true, LPT4=true, LPT5=true,
  LPT6=true, LPT7=true, LPT8=true, LPT9=true,
}
-- Shared filename sanitizer: strip filesystem-unsafe chars, collapse whitespace,
-- cap at 60 chars. Returns cleaned string (caller appends extension).
local function sanitize_filename(s, fallback)
  s = s:gsub('[<>:"/\\|%?%*]', ""):gsub("%s+", " "):gsub("^ +", ""):gsub(" +$", "")
  -- Strip trailing dots/spaces (Windows truncates them silently, breaking
  -- subsequent open-by-name lookups).
  s = s:gsub("[%. ]+$", "")
  if #s > 60 then s = s:sub(1, 60):gsub("[%. ]+$", "") end
  if s == "" then s = fallback end
  -- Reject Windows reserved device names. Match the stem before any extension
  -- the caller will append, so "CON" alone is enough to trigger.
  if WIN_RESERVED_NAMES[s:upper()] then s = s .. "_" end
  return s
end

function Code.derive_filename(code)
  -- 1. First line comment.
  local first_line = code:match("^%-%-+%s*(.-)%s*[\r\n]")
  if first_line and first_line ~= "" and not first_line:match("^!") then
    return sanitize_filename(first_line, "reaassist_script") .. ".lua"
  end

  -- 2. Undo_EndBlock label: e.g. Undo_EndBlock("ReaAssist: Create 20 tracks", -1)
  --    Strip a leading "ReaAssist: " prefix if present so the filename is clean.
  local undo_label = code:match("Undo_EndBlock%s*%(%s*\"(.-)\"%s*,")
                  or code:match("Undo_EndBlock%s*%(%s*'(.-)'%s*,")
  if undo_label and undo_label ~= "" then
    undo_label = undo_label:gsub("^ReaAssist:%s*", "")
    return sanitize_filename(undo_label, "reaassist_script") .. ".lua"
  end

  -- 3. First function name (covers local function and bare function forms).
  local fn_name = code:match("local%s+function%s+([%w_]+)%s*%(")
               or code:match("^function%s+([%w_]+)%s*%(")
  if fn_name then return sanitize_filename(fn_name, "reaassist_script") .. ".lua" end

  -- 4. Fallback.
  return "reaassist_script.lua"
end

-- =============================================================================
-- Utility: Code.derive_filename_jsfx
-- =============================================================================
-- Suggests a filename from JSFX code content.
-- Uses the desc: line if present, otherwise falls back to a generic name.
function Code.derive_filename_jsfx(code)
  local desc = code:match("^%s*desc:%s*(.-)%s*[\r\n]")
  if desc and desc ~= "" then return sanitize_filename(desc, "reaassist_effect") .. ".jsfx" end
  return "reaassist_effect.jsfx"
end

-- =============================================================================
-- Code.inject_output_ceiling -- runaway-feedback containment layer
-- =============================================================================
-- Defense-in-depth on top of the JSFX validator. The validator catches every
-- known runaway pattern at static-analysis time; this injection adds a hard
-- post-DSP cap on spl0..spl7 in case a future evasion slips through. Cap is
-- user-disableable via the injected slider (drag to 40 = bypass).
--
-- See implementation contract in this conversation's design v2.1-final
-- (gitignored notes). Key points enforced here:
--
--   * JSFX side uses `options:gmem=ReaAssist_Ceiling` (header directive),
--     NOT `gmem_attach()` (which is Lua-side only). Host script calls
--     `reaper.gmem_attach("ReaAssist_Ceiling")` to read the same namespace.
--
--   * Section-aware injection only. Append-only, no rewrites.
--     - Header: insert slider declaration; merge `gmem=ReaAssist_Ceiling`
--       into existing options: line OR insert a new options: line.
--     - @init: append init block (or create section if absent).
--     - @slider: append recompute block (or create section if absent).
--     - @sample: append clamp+engagement block.
--
--   * Bail conditions skip injection (ship original, log warning):
--       - 0 or 2+ @sample sections
--       - source contains `import` directive
--       - source uses `_ra_` identifier prefix already
--       - source already has `options:gmem=...` (any value)
--       - source uses `gmem[...]` anywhere (would silently rebind to our
--         private namespace and break intentional cross-plugin gmem)
--       - all slider slots 1..256 are used
--       - ExtState slot allocator wedged or exhausted
--
--   * Per-FILE alert/mute identity (not per-instance). Multiple track
--     instances of the same saved JSFX file share one gmem block. Documented
--     v1 trade-off; per-instance identity is v2 work.
--
--   * gmem layout (per-file block at base B, stride 8):
--       B+0: engagement flag (set by JSFX, cleared by host on poll)
--       B+1: cumulative engagement-sample count (lifetime)
--       B+2: time_precise() of most recent engagement
--       B+3: running consecutive-engagement count (for sustained-trip mute)
--       B+4: muted latch (set by JSFX after sustained trip; cleared by host
--            on user reset, or by JSFX when slider goes to 40 = off)
--       B+5..B+7: reserved
--     Global: gmem[0] = schema version, gmem[1] = "any engagement" sentinel.
--
--   * Allocation is monotonic via ExtState (`ceiling_next_base`). Starts at
--     8, increments by 8 per save. Slot 0..7 reserved for global metadata.
--     No reuse in v1 (heartbeat/lease scheme deferred). Re-saving the same
--     LLM-generated source ultimately writes a NEW file with a numeric
--     suffix (slot differs => content differs => existing dedup misses).
--     Acceptable v1 trade-off; can add original-content dedup later.
do

local CEILING_NS          = "ReaAssist_Ceiling"
local CEILING_NEXT_BASE   = "ceiling_next_base"
local CEILING_SLOTS_KEY   = "ceiling_slots"
local CEILING_BASE_START  = 8
local CEILING_STRIDE      = 8
local CEILING_BASE_LIMIT  = 8000000  -- well under gmem's 8M cap; defensive
local CEILING_DB_DEFAULT  = 20       -- dBFS, slider default
local CEILING_DB_OFF      = 40       -- slider value at which clamp/mute bypass
local SLIDER_SLOT_MAX     = 256

-- gmem layout offsets (within a slot's 8-deep block; matches the JSFX
-- injection's writes -- keep these in lockstep with render_injection_blocks).
local CEILING_GMEM_ENGFLAG  = 0   -- per-slot engagement flag (set by JSFX)
local CEILING_GMEM_ENGCOUNT = 1   -- per-slot lifetime engagement-sample count
local CEILING_GMEM_MUTE     = 4   -- per-slot mute latch (0/1)
local CEILING_GMEM_GLOBAL_ENG = 1 -- gmem[1] -- global "any-instance engagement"
                                  -- sentinel; cheap-poll fast path. Slot 1 is
                                  -- inside the 0..7 reserved global block, NOT
                                  -- inside a per-slot allocation (allocations
                                  -- start at slot 8).

-- Public so host poll can reference symbolic names.
Code.CEILING_NS              = CEILING_NS
Code.CEILING_GMEM_MUTE       = CEILING_GMEM_MUTE
Code.CEILING_GMEM_ENGFLAG    = CEILING_GMEM_ENGFLAG
Code.CEILING_GMEM_ENGCOUNT   = CEILING_GMEM_ENGCOUNT
Code.CEILING_GMEM_GLOBAL_ENG = CEILING_GMEM_GLOBAL_ENG

-- Replace comment bodies and string literal contents with spaces so token
-- scans (`gmem[`, `import`, `_ra_`, `options:gmem=`) don't match inside
-- strings or comments. Approximate but conservative -- false positives
-- on bail-condition checks just make us bail more often, which is safe.
local function scrub_jsfx(src)
  local out = src:gsub("/%*(.-)%*/", function(body)
    return "/*" .. body:gsub("[^\n\r]", " ") .. "*/"
  end)
  out = out:gsub("//[^\r\n]*", function(s) return string.rep(" ", #s) end)
  out = out:gsub('"([^"\r\n]*)"', function(body)
    return '"' .. string.rep(" ", #body) .. '"'
  end)
  out = out:gsub("'([^'\r\n]*)'", function(body)
    return "'" .. string.rep(" ", #body) .. "'"
  end)
  return out
end

-- Split a string into lines without terminators. Trailing newline produces
-- no empty final element.
local function split_lines(s)
  local out = {}
  for line in (s .. "\n"):gmatch("([^\r\n]*)\r?\n") do
    out[#out + 1] = line
  end
  if out[#out] == "" then out[#out] = nil end
  return out
end

-- Allocate a gmem base for this save. ExtState-backed, monotonic. Returns
-- the base (>=8, multiple of 8) or nil + reason on failure.
local function allocate_ceiling_slot()
  local cur_str = reaper.GetExtState(CFG.EXT_NS, CEILING_NEXT_BASE)
  local cur = tonumber(cur_str)
  if not cur or cur < CEILING_BASE_START then cur = CEILING_BASE_START end
  if cur >= CEILING_BASE_LIMIT then
    return nil, "ExtState slot allocator exhausted"
  end
  -- Persist next base BEFORE returning so a crash mid-save still consumes
  -- the slot rather than handing the same slot to the next call.
  reaper.SetExtState(CFG.EXT_NS, CEILING_NEXT_BASE,
                     tostring(cur + CEILING_STRIDE), true)
  return cur
end

-- ============================================================================
-- Slot metadata tracking
-- ============================================================================
-- Each successful injection records the slot it allocated alongside the
-- saved file path, the JSFX `desc:` name, and the allocation timestamp.
-- The host's defer poll loop iterates this list to know which gmem slots
-- to read when checking for engaged/muted JSFX.
--
-- Storage: ExtState `ceiling_slots` value, JSON-encoded array. ExtState
-- has a 64KB ceiling on values; per-entry size ~150 bytes => ~400 entries
-- comfortably within budget. Allocation is monotonic so the array grows
-- but never reuses slots.

-- Pull the recorded slot list. Empty array if not yet written.
function Code.ceiling_get_slots()
  local raw = reaper.GetExtState(CFG.EXT_NS, CEILING_SLOTS_KEY)
  if not raw or raw == "" then return {} end
  local ok, decoded = pcall(JSON.decode, raw)
  if not ok or type(decoded) ~= "table" then return {} end
  return decoded
end

-- Append a new slot entry to the list. info comes from
-- Code.inject_output_ceiling; saved_path is the path Code.auto_save_jsfx
-- wrote (may be nil if the JSFX was not saved -- e.g. JSFX-only response
-- without a Lua companion -- in which case we skip the record entirely
-- since there's no on-disk file to diagnose later).
function Code.ceiling_record_slot(info, saved_path, desc)
  if not info or not info.slot_base or not saved_path then return end
  local list = Code.ceiling_get_slots()
  list[#list + 1] = {
    slot      = info.slot_base,
    file      = saved_path,
    desc      = desc or "",
    alloc_ts  = os.time(),
  }
  local enc = JSON.encode(list)
  if enc then reaper.SetExtState(CFG.EXT_NS, CEILING_SLOTS_KEY, enc, true) end
end

-- Forget the slot whose recorded file is `path`. Called when the user
-- Reset-All-then-clears or when a saved file is detected missing during a
-- poll (orphaned slot). Allocation never reuses the slot index, so this
-- only prunes the metadata; gmem state for the slot stays whatever the
-- last write left it as.
function Code.ceiling_forget_slot_for_path(path)
  if not path or path == "" then return end
  local list = Code.ceiling_get_slots()
  local kept = {}
  for _, e in ipairs(list) do
    if e.file ~= path then kept[#kept + 1] = e end
  end
  if #kept ~= #list then
    reaper.SetExtState(CFG.EXT_NS, CEILING_SLOTS_KEY, JSON.encode(kept), true)
  end
end

-- Bulk garbage-collect slots in ExtState. Drops any entry whose:
--   (a) recorded file is missing from disk, OR
--   (b) file exists but no longer contains `_ra_slot = <N>;` matching
--       the recorded slot (file was overwritten or re-injected with
--       a different slot allocation).
--
-- Caller MUST have already called `reaper.gmem_attach(CEILING_NS)`
-- so the per-slot mute mirror clears land on the right region. In
-- practice the only caller is the poll loop, which attaches before
-- doing anything else.
--
-- Reads only the first 4 KB of each file -- the marker + `_ra_slot`
-- are emitted at the very top of the @init injection, well within
-- that window. Allocation is monotonic so pruned slot indices are
-- never reused; this just trims the metadata + gmem cruft.
--
-- Returns the number of slots pruned (0 if everything still valid).
function Code.ceiling_gc_slots()
  local list = Code.ceiling_get_slots()
  if #list == 0 then return 0 end
  local kept = {}
  local pruned = 0
  for _, e in ipairs(list) do
    local keep = false
    if e.file and e.file ~= "" and e.slot then
      local f = io.open(e.file, "rb")
      if f then
        local head = f:read(4096) or ""
        f:close()
        -- Match `_ra_slot = N;` (whitespace tolerant). The injector
        -- emits exactly this in @init right under the header marker.
        local pat = "_ra_slot%s*=%s*" .. tostring(e.slot) .. "%s*;"
        if head:find(pat) then keep = true end
      end
    end
    if keep then
      kept[#kept + 1] = e
    else
      pruned = pruned + 1
      -- Zero the mute mirror so an orphaned `1` doesn't pollute any
      -- future allocation that happens to land on a neighbour slot.
      -- Best-effort: if gmem_write isn't available, the metadata
      -- prune still happens.
      if reaper.gmem_write then
        reaper.gmem_write(e.slot + CEILING_GMEM_MUTE, 0)
      end
    end
  end
  if pruned > 0 then
    reaper.SetExtState(CFG.EXT_NS, CEILING_SLOTS_KEY,
      JSON.encode(kept), true)
    if Log and Log.line then
      Log.line("CEILING-GC",
        ("pruned %d stale slot(s); kept %d"):format(pruned, #kept))
    end
  end
  return pruned
end

-- Host-side mute clear: write gmem[slot+4] = 0. Caller must have
-- previously called `reaper.gmem_attach(CEILING_NS)`.
function Code.ceiling_clear_mute(slot)
  if not slot or slot < CEILING_BASE_START then return end
  reaper.gmem_write(slot + CEILING_GMEM_MUTE, 0)
end

-- Render the three injection blocks parameterised on slot base + slider id.
--
-- Slider semantics (UX simplification, 2026-04-29 follow-up):
-- The slider value is ALWAYS the ceiling level in dBFS. There is no magic
-- "off" position. At the slider's max (40 dBFS = 100x linear), the ceiling
-- is so permissive that real audio in normal use never reaches it -- so
-- 40 is "effectively off" without needing a special bypass code path.
-- This avoids the earlier "is 40 really off, or just at +40 dBFS?" UX
-- confusion: now it's unambiguously "the ceiling is at this dBFS value,
-- always."
--
-- The mute latch is cleared on ANY slider change. Touching the control =
-- explicit user acknowledgement that they've seen something happened and
-- want to continue. Simpler than a dedicated reset position on the slider.
--
-- We avoid a `1e30`-style "infinity" literal here because REAPER's JSFX
-- parser rejected it in some contexts (observed: bare `1e30` inside a
-- ternary RHS produced `@init: syntax error`). Always-compute via pow()
-- is defensible regardless of the literal-parsing rules.
local function render_injection_blocks(slot, slider_n)
  -- @init resets local mute state AND clears the gmem mirror slots for
  -- this allocation. Without the gmem clear, gmem state from a previous
  -- session (gmem persists in REAPER project files) could lie to the
  -- host's poll loop on reopen -- the JSFX's _ra_muted is fresh-zero but
  -- gmem[slot+4] could still carry an old `1` from a prior run.
  local INIT_INJ = ([[
// --- ReaAssist output ceiling (auto-injected; do not edit) ---
_ra_slot = %d;
_ra_mute_samples = srate * 0.05;
_ra_sus = 0;
_ra_muted = 0;
_ra_prev_slider = slider%d;
_ra_ceil_lin = pow(10, slider%d/20);
gmem[_ra_slot+0] = 0;
gmem[_ra_slot+1] = 0;
gmem[_ra_slot+4] = 0;
// ----------------------------------------------------------]])
    :format(slot, slider_n, slider_n)

  -- @slider recompute. Mute state cleared via local _ra_muted on any
  -- slider change. gmem[slot+4] is mirrored so a slider-driven reset
  -- stays consistent with the host's view (host poll reads gmem).
  local SLIDER_INJ = ([[
// --- ReaAssist output ceiling recompute (auto-injected) ---
_ra_ceil_lin = pow(10, slider%d/20);
_ra_changed = slider%d != _ra_prev_slider ? 1 : 0;
_ra_muted = _ra_changed ? 0 : _ra_muted;
_ra_sus = _ra_changed ? 0 : _ra_sus;
_ra_prev_slider = slider%d;
gmem[_ra_slot+4] = _ra_muted;
// ----------------------------------------------------------]])
    :format(slider_n, slider_n, slider_n)

  -- NOTE: a previous version injected an @block section to clear the mute
  -- latch on any transport stop edge. Both the && form and a nested-ternary
  -- form caused the per-sample mute logic to stop working entirely, even
  -- though the inner clear should never have fired during sustained
  -- playback. The mechanism remains unidentified -- possibly a section-
  -- ordering quirk specific to this user's REAPER build.
  --
  -- Stop-edge auto-clear is therefore deferred to the host-side path: once
  -- the gmem poll loop lands (next §9 step), the host can write
  -- gmem[B+4] = 0 from Lua when it observes a transport stop, achieving
  -- the same UX without injecting @block code into the JSFX.
  --
  -- Until then, the user can clear a latched mute by moving the ceiling
  -- slider (the @slider injection clears on any slider change). Returning
  -- nil here makes the create-or-append logic in inject_output_ceiling
  -- below skip @block entirely.
  local BLOCK_INJ = nil

  -- @sample: per-channel ceiling clamp + sustained-trip mute.
  --
  -- This block is structurally identical to a standalone test JSFX that
  -- the user verified WORKS (the same logic, in plain globals, not gmem,
  -- with single-line OR-chains). The mute decision uses local _ra_muted
  -- as the source of truth; gmem writes are pure host-visibility mirrors
  -- (the `@slider` inj also writes through to gmem on user reset).
  -- Slot layout matches the host-side poll constants in
  -- `Net.ceiling_*` -- keep in lockstep.
  --   gmem[_ra_slot+0]: engagement flag (set on any engaged sample;
  --                     host clears after consuming the alert)
  --   gmem[_ra_slot+1]: cumulative engagement-sample count (lifetime)
  --   gmem[_ra_slot+4]: mute mirror (latches when _ra_muted goes 1)
  --   gmem[1]:          global "any-instance engagement" sentinel,
  --                     allows host's defer poll to skip the per-slot
  --                     scan when nothing has fired anywhere
  --
  -- The host-side reset (Reset Mute button in the popup) writes
  -- gmem[slot+4] = 0 directly. The injection's @slider section also
  -- mirrors _ra_muted -> gmem[slot+4] every slider change so a slider
  -- nudge from the JSFX side stays consistent with gmem.
  local SAMPLE_INJ = [[
// --- ReaAssist output ceiling (auto-injected; do not edit) ---
_ra_muted ? (
  spl0 = 0; spl1 = 0; spl2 = 0; spl3 = 0;
  spl4 = 0; spl5 = 0; spl6 = 0; spl7 = 0;
) : (
  _ra_eng = (abs(spl0) > _ra_ceil_lin) || (abs(spl1) > _ra_ceil_lin) || (abs(spl2) > _ra_ceil_lin) || (abs(spl3) > _ra_ceil_lin) || (abs(spl4) > _ra_ceil_lin) || (abs(spl5) > _ra_ceil_lin) || (abs(spl6) > _ra_ceil_lin) || (abs(spl7) > _ra_ceil_lin);
  spl0 = abs(spl0) > _ra_ceil_lin ? max(-_ra_ceil_lin, min(_ra_ceil_lin, spl0)) : spl0;
  spl1 = abs(spl1) > _ra_ceil_lin ? max(-_ra_ceil_lin, min(_ra_ceil_lin, spl1)) : spl1;
  spl2 = abs(spl2) > _ra_ceil_lin ? max(-_ra_ceil_lin, min(_ra_ceil_lin, spl2)) : spl2;
  spl3 = abs(spl3) > _ra_ceil_lin ? max(-_ra_ceil_lin, min(_ra_ceil_lin, spl3)) : spl3;
  spl4 = abs(spl4) > _ra_ceil_lin ? max(-_ra_ceil_lin, min(_ra_ceil_lin, spl4)) : spl4;
  spl5 = abs(spl5) > _ra_ceil_lin ? max(-_ra_ceil_lin, min(_ra_ceil_lin, spl5)) : spl5;
  spl6 = abs(spl6) > _ra_ceil_lin ? max(-_ra_ceil_lin, min(_ra_ceil_lin, spl6)) : spl6;
  spl7 = abs(spl7) > _ra_ceil_lin ? max(-_ra_ceil_lin, min(_ra_ceil_lin, spl7)) : spl7;
  _ra_sus = _ra_eng ? _ra_sus + 1 : max(0, _ra_sus - 1);
  _ra_muted = _ra_sus >= _ra_mute_samples ? 1 : _ra_muted;
  // Host-visibility mirrors. Mute logic above already used the local
  // _ra_muted for the per-sample decision; these writes just expose the
  // state to the Lua-side host poll loop.
  gmem[_ra_slot+0] = _ra_eng ? 1 : gmem[_ra_slot+0];
  gmem[_ra_slot+1] = _ra_eng ? gmem[_ra_slot+1] + 1 : gmem[_ra_slot+1];
  gmem[_ra_slot+4] = _ra_muted;
  gmem[1] = _ra_eng ? 1 : gmem[1];
);
// ----------------------------------------------------------]]

  return INIT_INJ, SLIDER_INJ, BLOCK_INJ, SAMPLE_INJ
end

-- Main entry point. Returns (injected_src, info_table) on success, or
-- (nil, skip_reason_string) on bail. Caller is responsible for shipping
-- the original source on bail.
function Code.inject_output_ceiling(src)
  if type(src) ~= "string" or src == "" then
    return nil, "empty source"
  end

  -- Idempotency: if the source already has our injection markers, ship it
  -- back unmodified. Lets the response-handler path inject for the chat
  -- display AND lets auto_save_jsfx call inject again (as a defense) without
  -- double-injecting or burning a second slot allocation.
  if src:find("// --- ReaAssist output ceiling", 1, true) then
    return nil, "already injected"
  end

  -- Split into lines (preserve content; we'll rejoin with \n on output).
  local lines = split_lines(src)
  if #lines == 0 then return nil, "empty source" end

  -- Locate section markers (`@<word>` at column 0).
  local sections = {}        -- ordered list: { name, marker_line }
  local sections_by_name = {}
  for i, line in ipairs(lines) do
    local kw = line:match("^@(%w+)")
    if kw then
      local entry = { name = kw, marker_line = i }
      sections[#sections + 1] = entry
      sections_by_name[kw] = sections_by_name[kw] or {}
      table.insert(sections_by_name[kw], entry)
    end
  end

  -- Compute body ranges: section i's body is lines [marker_line+1 .. next_marker_line-1].
  for i, sec in ipairs(sections) do
    sec.body_start = sec.marker_line + 1
    sec.body_end = (i < #sections) and (sections[i + 1].marker_line - 1) or #lines
  end
  local header_end = (#sections > 0) and (sections[1].marker_line - 1) or #lines

  -- Bail: must have exactly one @sample.
  local sample_entries = sections_by_name.sample
  if not sample_entries then return nil, "no @sample section" end
  if #sample_entries > 1 then return nil, "multiple @sample sections" end

  -- Bail: forbidden tokens in scrubbed source.
  local scrubbed = scrub_jsfx(src)
  if scrubbed:match("[^%w_]import%s") or scrubbed:match("^import%s") then
    return nil, "import directive present"
  end
  if scrubbed:match("[^%w_]_ra_") or scrubbed:match("^_ra_") then
    return nil, "source uses _ra_ identifier prefix"
  end
  if scrubbed:match("options:[^\r\n]*gmem%s*=") then
    return nil, "existing options:gmem= directive"
  end
  if scrubbed:match("gmem%s*%[") then
    return nil, "source already uses gmem[]"
  end

  -- Pick a free slider slot. Also bail if the LLM emitted any slider whose
  -- name suggests it's already trying to be an output ceiling/limit/cap --
  -- shipping a duplicate would put two same-purpose sliders in the UI.
  -- The Prompts.md OUTPUT STAGE rule forbids the LLM from doing this; this
  -- bail is the runtime defense if the rule is violated.
  local used_sliders = {}
  for _, line in ipairs(lines) do
    local n, name = line:match("^slider(%d+):[^>]*>(.*)$")
    if n then
      used_sliders[tonumber(n)] = true
      -- Match patterns like "Safety Output Ceiling", "Output Ceiling",
      -- "Output Limiter", "Master Out", "Final Gain". Lowercased for
      -- case-insensitive comparison. Conservative -- false positives just
      -- skip the injection, which is safer than colliding with a real
      -- output-control slider the LLM legitimately added on user request.
      local lname = (name or ""):lower()
      if lname:find("output ceiling", 1, true)
         or lname:find("output limit", 1, true)
         or lname:find("output cap", 1, true)
         or lname:find("safety ceiling", 1, true)
         or (lname:find("safety", 1, true) and lname:find("output", 1, true)) then
        return nil, "source already declares an output-ceiling slider: \""
          .. (name or "") .. "\""
      end
    end
  end
  local slider_n
  for i = 1, SLIDER_SLOT_MAX do
    if not used_sliders[i] then slider_n = i; break end
  end
  if not slider_n then
    return nil, "all slider slots 1.." .. SLIDER_SLOT_MAX .. " used"
  end

  -- Allocate gmem slot. Persists ExtState before any source mutation; safe
  -- to reach this point only after ALL bail conditions cleared.
  local slot, alloc_err = allocate_ceiling_slot()
  if not slot then return nil, alloc_err end

  -- Locate or merge the header `options:` line.
  local options_line_idx
  for i = 1, header_end do
    if lines[i]:match("^options:") then options_line_idx = i; break end
  end
  if options_line_idx then
    -- In-place edit: append " gmem=ReaAssist_Ceiling" (space-separated per
    -- JSFX options syntax; not comma).
    lines[options_line_idx] = lines[options_line_idx] .. " gmem=" .. CEILING_NS
  end

  -- Build the injection plan. Each entry: { after_line = N, lines = {...} }.
  -- Apply by walking the original line array once and inserting AFTER each
  -- target line. Multiple entries with the same after_line are concatenated
  -- in plan order.
  local plan = {}
  local function add_after(line_no, content_lines)
    plan[line_no] = plan[line_no] or {}
    for _, l in ipairs(content_lines) do
      plan[line_no][#plan[line_no] + 1] = l
    end
  end

  -- Header: options line (if not merged) + slider declaration. The slider
  -- value is unconditionally the ceiling level in dBFS -- no magic "off"
  -- position. Max value (CEILING_DB_OFF dBFS = high linear gain) is
  -- effectively off because real audio in normal use never reaches it.
  --
  -- Collision protection lives in the bail conditions above (specifically
  -- the "safety/output/ceiling slider already present" check). The bundle
  -- forbids the LLM from emitting any output-control slider; the bail is
  -- the runtime defense if it slips through anyway.
  local slider_line = ("slider%d:%d<0,%d,1>Safety Output Ceiling (dBFS)")
    :format(slider_n, CEILING_DB_DEFAULT, CEILING_DB_OFF)
  local header_block = {}
  if not options_line_idx then
    header_block[#header_block + 1] = "options:gmem=" .. CEILING_NS
  end
  header_block[#header_block + 1] = slider_line
  add_after(header_end, header_block)

  -- Render section blocks.
  local INIT_INJ, SLIDER_INJ, BLOCK_INJ, SAMPLE_INJ =
    render_injection_blocks(slot, slider_n)

  local function find_sec(name)
    return sections_by_name[name] and sections_by_name[name][1] or nil
  end

  -- @init injection.
  local init_sec = find_sec("init")
  local created_init = false
  if init_sec then
    add_after(init_sec.body_end, split_lines(INIT_INJ))
  else
    -- No @init -- create one immediately after our header insertions
    -- (which go after `header_end`). Both go through add_after(header_end).
    -- Plan-order ensures: [options/slider header_block] [@init] [INIT_INJ].
    add_after(header_end, { "@init" })
    add_after(header_end, split_lines(INIT_INJ))
    created_init = true
  end

  -- @slider injection.
  local slider_sec = find_sec("slider")
  local created_slider = false
  if slider_sec then
    add_after(slider_sec.body_end, split_lines(SLIDER_INJ))
  else
    -- Create @slider just before @sample's marker line.
    local sample_sec = find_sec("sample")
    add_after(sample_sec.marker_line - 1, { "@slider" })
    add_after(sample_sec.marker_line - 1, split_lines(SLIDER_INJ))
    created_slider = true
  end

  -- @block injection (transport-edge mute clear). v1: skipped entirely;
  -- BLOCK_INJ is nil. See render_injection_blocks for rationale.
  local created_block = false
  if BLOCK_INJ then
    local block_sec = find_sec("block")
    if block_sec then
      add_after(block_sec.body_end, split_lines(BLOCK_INJ))
    else
      local sample_sec = find_sec("sample")
      add_after(sample_sec.marker_line - 1, { "@block" })
      add_after(sample_sec.marker_line - 1, split_lines(BLOCK_INJ))
      created_block = true
    end
  end

  -- @sample injection (always present per bail check above).
  local sample_sec = find_sec("sample")
  add_after(sample_sec.body_end, split_lines(SAMPLE_INJ))

  -- Walk original lines and apply insertions.
  local out = {}
  -- Insert any `after_line = 0` content first (before line 1).
  if plan[0] then
    for _, l in ipairs(plan[0]) do out[#out + 1] = l end
  end
  for i = 1, #lines do
    out[#out + 1] = lines[i]
    if plan[i] then
      for _, l in ipairs(plan[i]) do out[#out + 1] = l end
    end
  end

  -- desc: line lookup -- caller (host poll, popup, diagnose path) wants
  -- the user-facing name without re-parsing.
  local desc = src:match("^%s*desc:%s*(.-)%s*[\r\n]") or ""

  return table.concat(out, "\n"), {
    slot_base       = slot,
    slider_num      = slider_n,
    merged_options  = options_line_idx ~= nil,
    created_init    = created_init,
    created_slider  = created_slider,
    created_block   = created_block,
    desc            = desc,
  }
end

end  -- close ceiling-injection scope

-- =============================================================================
-- Utility: Code.auto_save_jsfx
-- =============================================================================
-- Silently saves JSFX code to Effects/ReaAssist/<derived_name>.jsfx.
-- Returns the saved path on success, nil on failure.
--
-- Filename is derived from `code` directly. The output-ceiling injection
-- step now runs at chat-display time in Net.process_response_content, BEFORE
-- this function is called -- so by the time auto_save_jsfx sees `code`, it
-- already contains the injected ceiling slider, options:gmem= line, and
-- @init/@slider/@block/@sample blocks. The desc: line is untouched by
-- injection, so filename derivation produces the same name either way.
--
-- Dedup compares full content. Two saves of the same LLM source allocate
-- different gmem slots at injection time, so re-saving produces a new
-- numeric-suffixed file rather than reusing the existing one. v1 trade-off.
function Code.auto_save_jsfx(code)
  local base_name = Code.derive_filename_jsfx(code)

  local name = base_name
  local stem = base_name:match("^(.+)%.jsfx$") or base_name
  local dest = JSFX_DIR .. RA.SEP .. name
  -- Check existing files: if one has identical content, return it (no duplicate).
  -- If content differs, skip past it and try the next numeric suffix.
  local n = 1
  local f = io.open(dest, "r")
  while f do
    local existing = f:read("*a")
    f:close()
    if existing == code then
      -- Exact same content already on disk -- reuse it.
      return dest, "ReaAssist/" .. name
    end
    n = n + 1
    name = stem .. "_" .. n .. ".jsfx"
    dest = JSFX_DIR .. RA.SEP .. name
    f = io.open(dest, "r")
  end
  local ok = Code.safe_write(dest, code)
  if ok then
    -- Refresh JSFX list so TrackFX_AddByName can find it immediately.
    if reaper.EnumInstalledFX then
      reaper.EnumInstalledFX(-1)
    end
    -- Invalidate our cached installed-FX list so a follow-up
    -- <context_needed>fx_list:...</context_needed> for the newly saved
    -- plugin actually sees it instead of reporting "not installed".
    CTX._installed_fx_list = nil
    return dest, "ReaAssist/" .. name
  end
  return nil
end

-- =============================================================================
-- ReEQ bundled-install support
-- =============================================================================
-- ReEQ (by Justin Johnson, MIT) is bundled with ReaAssist and installed on
-- demand at the standard ReaPack location so sessions remain portable: anyone
-- with ReEQ from ReaPack will resolve the same `ReJJ/ReEQ/ReEQ.jsfx` path.
--
-- The bundled source lives in <script>/Resources/ReEQ/ and contains:
--   ReEQ.jsfx, LICENSE.txt, Dependencies/{firhalfband,spectrum,svf_filter}.jsfx-inc
-- LICENSE keeps a .txt extension because gen_manifest.py only ships files
-- on a safe-extension whitelist (no-extension files are excluded). The
-- .txt suffix lets the file flow through both ReaPack's index.xml source
-- list and the internal updater's manifest.
--
-- After install we call EnumInstalledFX(-1) so TrackFX_AddByName finds the
-- new JSFX immediately (the FX Browser does not visually refresh until REAPER
-- restarts, but plugin lookup by path works right away).

local REEQ_SRC_DIR  = RA.RESOURCES_DIR .. "ReEQ"
local REEQ_DEST_DIR = reaper.GetResourcePath() .. RA.SEP .. "Effects" .. RA.SEP .. "ReJJ" .. RA.SEP .. "ReEQ"
local REEQ_DEPS     = { "firhalfband.jsfx-inc", "spectrum.jsfx-inc", "svf_filter.jsfx-inc" }

-- Returns true iff the canonical ReEQ.jsfx file is present at the ReaPack path.
function Code.is_reeq_installed()
  local f = io.open(REEQ_DEST_DIR .. RA.SEP .. "ReEQ.jsfx", "r")
  if f then f:close(); return true end
  return false
end

-- Internal: copies a single file if the destination doesn't already exist.
-- Returns true on success (including "already present" no-op), false + err on failure.
local function reeq_copy_file(src, dest)
  local existing = io.open(dest, "r")
  if existing then existing:close(); return true end  -- idempotent: don't overwrite
  local sf, err = io.open(src, "rb")
  if not sf then return false, "Cannot read " .. src .. ": " .. tostring(err) end
  local data = sf:read("*a"); sf:close()
  local df, derr = io.open(dest, "wb")
  if not df then return false, "Cannot write " .. dest .. ": " .. tostring(derr) end
  -- Check write/close return values. A short write (disk full mid-copy)
  -- or a close failure (filesystem flush error) used to leave a corrupt
  -- destination but return true; Code.is_reeq_installed() then sees the
  -- file exists and short-circuits any reinstall, so the user is stuck
  -- with a broken JSFX until they manually delete it. Remove the partial
  -- file on failure so a reinstall can recover.
  local wok, werr = df:write(data)
  local cok, cerr = df:close()
  if not wok or not cok then
    os.remove(dest)
    return false, "Write failed for " .. dest .. ": "
      .. tostring(werr or cerr or "unknown")
  end
  return true
end

-- Installs the bundled ReEQ to {resource_path}/Effects/ReJJ/ReEQ/.
-- Idempotent: skips files that already exist at the destination.
-- Returns (true, nil) on success or (false, error_message) on failure.
function Code.install_reeq()
  -- Sanity check that the bundled source is present.
  local probe = io.open(REEQ_SRC_DIR .. RA.SEP .. "ReEQ.jsfx", "r")
  if not probe then
    return false, "Bundled ReEQ source not found at " .. REEQ_SRC_DIR
  end
  probe:close()

  -- Create destination tree.
  reaper.RecursiveCreateDirectory(REEQ_DEST_DIR .. RA.SEP .. "Dependencies", 0)

  -- Copy main JSFX + LICENSE.txt.
  local ok, err = reeq_copy_file(REEQ_SRC_DIR .. RA.SEP .. "ReEQ.jsfx",
                                 REEQ_DEST_DIR .. RA.SEP .. "ReEQ.jsfx")
  if not ok then return false, err end
  ok, err = reeq_copy_file(REEQ_SRC_DIR .. RA.SEP .. "LICENSE.txt",
                           REEQ_DEST_DIR .. RA.SEP .. "LICENSE.txt")
  if not ok then return false, err end

  -- Copy dependencies.
  for _, dep in ipairs(REEQ_DEPS) do
    ok, err = reeq_copy_file(REEQ_SRC_DIR  .. RA.SEP .. "Dependencies" .. RA.SEP .. dep,
                             REEQ_DEST_DIR .. RA.SEP .. "Dependencies" .. RA.SEP .. dep)
    if not ok then return false, err end
  end

  -- Force REAPER to rescan installed FX so AddByName finds ReEQ immediately.
  -- Same trick used by Code.auto_save_jsfx; the FX Browser doesn't visually
  -- refresh, but lookup-by-path works right away.
  if reaper.EnumInstalledFX then reaper.EnumInstalledFX(-1) end
  CTX._installed_fx_list = nil

  -- Re-run fallback chains now that ReEQ is on disk. Fills pref_types.eq
  -- with the first chain candidate that's installed (ReEQ if the user has
  -- no FabFilter EQ) so the Preferred Plugins page reflects it and preempt
  -- injection fires for "eq" keywords from now on. No-op if the user
  -- already has an EQ preference set.
  Code.ensure_preferred_from_chains()

  return true, nil
end

-- =============================================================================
-- Fallback chains: auto-assign preferred plugins from Plugin_Ref.md
-- =============================================================================
-- PLUGIN AUTO-ASSIGN / POPUP FLOW
-- -------------------------------
-- Single source of truth: the ```chains block in Resources/Plugin_Ref.md.
-- Line format:
--   type: chain1 | chain2 | ... || stock-fallback [optional alias]
--
-- AUTO-ASSIGN CHAIN (left of `||`):
--   Walked at startup by Code.ensure_preferred_from_chains (and again after
--   install_reeq invalidates the FX list cache). First installed entry wins
--   and is written to pref_types[type]. Appears on the Preferred Plugins
--   page. Only high-quality third-party picks belong here -- they commit
--   users silently. Stock REAPER plugins are NEVER in chains.
--
-- STOCK FALLBACK (right of `||`):
--   Offered by the resolve popup as a one-click "Use <name> instead" button
--   when no chain entry is installed and the model emits resolve:<type>.
--   Used for THIS TURN ONLY -- never saved to pref_types, never shown on
--   the Preferred Plugins page. The popup fires again next time the type
--   comes up. Users who want a stock plugin permanent must type it into the
--   Preferred Plugins page themselves.
--
-- DISPLAY ALIAS (in brackets after any entry):
--   Optional. Overrides the button label for stock fallbacks. Example:
--     JS: Liteon/deesser [JSFX De-esser]
--   Shows as "Use JSFX De-esser instead" on the popup button.
--
-- LINE FORMAT EXAMPLES:
--   eq: Pro-Q 4 | ReJJ/ReEQ/ReEQ.jsfx || ReaEQ      -- 2-entry chain + stock
--   chorus:  || JS: SStillwell/chorus_stereo [JSFX Chorus]
--                                                    -- stock-only type
--   custom_thing: MyPlugin                           -- chain-only (rare)
--
-- TO ADD A NEW AUTO-ASSIGN CANDIDATE: add to the matching chain line in
-- Plugin_Ref.md. Entries are format-agnostic (just the plugin name); the
-- resolver tries VST3 > VSTi > VST > AU > CLAP. JSFX entries use the full
-- relative path (e.g. ReJJ/ReEQ/ReEQ.jsfx, or JS: vendor/file for stock).
--
-- TO ADD A NEW PLUGIN TYPE: add to PREF_PLUGIN_DEFAULTS, PREF_PLUGIN_ALIASES,
-- VALID_RESOLVE_TYPES, and add a chain line in Plugin_Ref.md. The popup
-- picks up the stock fallback automatically via Code.get_stock_fallback.
-- See Dev/Plugin Scanner Script/README.md for the full integration recipe.
-- -----------------------------------------------------------------------------

-- Reads the ```chains code block from Resources/Plugin_Ref.md.
-- Line format:
--   type: chain1 | chain2 | ... || stock-fallback
-- Any entry (chain or stock) may have an optional display alias in brackets:
--   JS: Liteon/deesser [JSFX De-esser]
-- Types with no auto-chain are written as:
--   type: || stock-fallback
--
-- Returns { type_key = { chain = {name1, ...}, stock = {add=..., alias=...} } }.
-- Parsed once per session; the file is authoritative.
local _fallback_chains

-- Parse a single entry string like "Pro-Q 4" or "JS: Liteon/deesser [JSFX De-esser]"
-- into { name = "...", alias = "..." or nil }.
local function _parse_chain_entry(s)
  s = s:match("^%s*(.-)%s*$") or ""
  if s == "" then return nil end
  local name, alias = s:match("^(.-)%s*%[(.-)%]%s*$")
  if name and alias and name ~= "" then
    return { name = name:match("^%s*(.-)%s*$"),
             alias = alias:match("^%s*(.-)%s*$") }
  end
  return { name = s, alias = nil }
end

function Code.get_fallback_chains()
  if _fallback_chains then return _fallback_chains end
  _fallback_chains = {}
  local ref_path = RA.RESOURCES_DIR .. "Plugin_Ref.md"
  local f = io.open(ref_path, "r")
  if not f then
    Log.line("CHAIN", "Plugin_Ref.md not found; no fallback chains loaded")
    return _fallback_chains
  end
  local content = f:read("*a")
  f:close()
  local block = content:match("```chains%s*\n(.-)\n```")
  if not block then
    Log.line("CHAIN", "no ```chains block found in Plugin_Ref.md")
    return _fallback_chains
  end
  local loaded = {}
  for line in block:gmatch("[^\n]+") do
    -- Skip comment lines and blank lines.
    local stripped = line:match("^%s*(.-)%s*$") or ""
    if stripped ~= "" and stripped:sub(1, 1) ~= "#" then
      local type_key, rest = line:match("^%s*([%w_]+)%s*:%s*(.*)$")
      if type_key and rest then
        -- Split on "||" to separate auto-chain from stock fallback.
        local chain_str, stock_str = rest:match("^(.-)%s*||%s*(.+)$")
        if not chain_str then
          -- No "||" found -- treat whole line as chain (no stock fallback).
          chain_str, stock_str = rest, nil
        end
        local chain_entries = {}
        for entry in chain_str:gmatch("[^|]+") do
          local parsed = _parse_chain_entry(entry)
          if parsed then chain_entries[#chain_entries+1] = parsed.name end
        end
        local stock = nil
        if stock_str then
          local parsed_stock = _parse_chain_entry(stock_str)
          if parsed_stock then
            stock = { add = parsed_stock.name, alias = parsed_stock.alias }
          end
        end
        if #chain_entries > 0 or stock then
          _fallback_chains[type_key] = {
            chain = chain_entries,
            stock = stock,
          }
          loaded[#loaded+1] = type_key
        end
      end
    end
  end
  Log.line("CHAIN", "loaded chains for types: " .. tbl_concat(loaded, ", "))
  return _fallback_chains
end

-- Code.get_stock_fallback is defined near Code.is_curated_plugin (same file,
-- after PLUGIN_REF_ALIASES declaration) because it reads that alias map to
-- derive the curated section key from the stock AddByName string.

-- Format preference for format-agnostic chain entries. Plugins installed in
-- multiple formats are resolved in this order so VST3 wins over CLAP, etc.
local CHAIN_FORMAT_PREFIXES = {
  "VST3:", "VST3i:", "VSTi:", "VST:", "AU:", "AUi:", "CLAP:", "CLAPi:",
}

-- Test whether a chain entry (plugin name or JSFX path) is installed on the
-- system by searching the enumerated FX list. Returns the full enumerated
-- name on match, or nil. JSFX paths match exactly; plugin names use a
-- case-insensitive substring match plus format-prefix preference.
function Code.resolve_chain_entry(entry, installed_list)
  -- Bundled-ReEQ fallback: check the filesystem regardless of what
  -- installed_list contains. EnumInstalledFX on macOS has been observed
  -- to omit our installed ReEQ.jsfx even after a REAPER restart while
  -- the file is unambiguously present at the canonical install path.
  -- Same coverage gap that the resolve handler already works around
  -- via Code.is_reeq_installed (mid-session filesystem check); we
  -- apply it to the chain walk too so the auto-pref slot populates
  -- without requiring a chat round-trip. Runs before the empty-list
  -- guard so it works even on a fresh launch where EnumInstalledFX
  -- hasn't returned any rows yet.
  if entry == "ReJJ/ReEQ/ReEQ.jsfx" and Code.is_reeq_installed() then
    return entry
  end
  if not installed_list or #installed_list == 0 then return nil end
  if entry:find("/", 1, true) then
    for _, inst in ipairs(installed_list) do
      if inst == entry or inst == "JS: " .. entry then return inst end
    end
    return nil
  end
  local entry_lower = entry:lower()
  local best, best_rank = nil, math.huge
  for _, inst in ipairs(installed_list) do
    if inst:lower():find(entry_lower, 1, true) then
      local rank = math.huge
      for i, p in ipairs(CHAIN_FORMAT_PREFIXES) do
        if inst:sub(1, #p) == p then rank = i; break end
      end
      if rank < best_rank then best, best_rank = inst, rank end
    end
  end
  return best
end

-- Walk every fallback chain and auto-assign pref_types[type] to the first
-- installed entry, ONLY when no existing preference is set. Never overwrites
-- user choices. Called at script load and after installing bundled plugins.
-- Idempotent; returns count of types newly assigned this call.
function Code.ensure_preferred_from_chains()
  local chains = Code.get_fallback_chains()
  if not next(chains) then return 0 end
  CTX.populate_installed_fx()
  local installed = CTX._installed_fx_list or {}
  local cache = FXCache.load()
  cache.preferred_types = cache.preferred_types or {}
  local hide_ff = reaper.GetExtState(CFG.EXT_NS, "dev_hide_fabfilter") == "1"
  -- Dev-only HideFabFilter override: when the flag is on AND the cached
  -- pref for a type is a FabFilter ident (Pro-Q 4 / Pro-C 3 / ...), treat
  -- the cached value as empty so the chain walk falls through to the next
  -- resolvable alternative (ReEQ for eq, etc.). This makes "Hide FabFilter"
  -- actually simulate a no-FabFilter install instead of just hiding the
  -- value at display time. The override is SESSION-ONLY: ephemeral_originals
  -- captures the pre-override values so we can restore them before
  -- persisting to disk -- toggling HideFabFilter back off must restore the
  -- user's real preferred plugin (e.g. Pro-Q 4) cleanly.
  local ephemeral_originals = {}
  local assigned = 0
  local sorted_types = {}
  for k in pairs(chains) do sorted_types[#sorted_types+1] = k end
  table.sort(sorted_types)
  for _, type_key in ipairs(sorted_types) do
    local original = cache.preferred_types[type_key]
    local existing = original
    local overridden = false
    if hide_ff and existing and existing ~= ""
        and _is_fabfilter_ident(existing) then
      existing = ""
      overridden = true
    end
    if not existing or existing == "" then
      local chain_list = chains[type_key].chain or {}
      for _, entry in ipairs(chain_list) do
        if Code.resolve_chain_entry(entry, installed) then
          -- Canonicalize the chain-entry form to AddByName-ready prefixed
          -- form before storing. Chain entries are intentionally format-
          -- agnostic ("Twin 3"), but the model + TrackFX_AddByName work
          -- more reliably with the prefixed form ("VST3i: Twin 3").
          local canonical = FXCache.canonicalize_identifier(type_key, entry)
          cache.preferred_types[type_key] = canonical
          Log.line("PREF", str_format(
            "auto-assigned preferred_types.%s = %s%s%s",
            type_key, canonical,
            (canonical ~= entry) and " (canonicalized from " .. entry .. ")" or "",
            overridden and " (ephemeral; hide_fabfilter override of "
              .. tostring(original) .. ")" or " (from chain)"))
          assigned = assigned + 1
          if overridden then ephemeral_originals[type_key] = original end
          break
        end
      end
    end
  end
  -- One-time-per-session migration of any legacy bare-name entries that
  -- this run didn't touch (entries that already had a value when this
  -- function was called, so the chain-walk above skipped them). Runs
  -- after the chain assignment so newly-assigned entries are already
  -- canonical and the migration finds nothing to do for them.
  FXCache.canonicalize_all_preferred_types()
  if assigned > 0 then
    if next(ephemeral_originals) then
      -- Snapshot-and-restore: write the rolled-back values to disk, then
      -- re-apply the in-memory overrides so the rest of the session keeps
      -- using the simulated alternatives. Both `cache` and the table held
      -- in FXCache._fx_cache_mem are the same Lua table, so restoring
      -- `cache.preferred_types[k]` also updates the module-level cache
      -- that FXCache.load returns to other callers.
      --
      -- Save is wrapped in pcall and the in-memory restore runs
      -- unconditionally: if FXCache.save errors mid-write (disk full /
      -- permission failure surfaces a message-box from Code.safe_write),
      -- we still want the session to keep simulating "no FabFilter".
      -- Without unconditional restore, an error here would leave
      -- cache.preferred_types[k] at the original FabFilter ident (the
      -- value we just swapped in for the save), silently breaking the
      -- HideFabFilter override until the next ReaAssist relaunch.
      local in_memory_values = {}
      for k in pairs(ephemeral_originals) do
        in_memory_values[k] = cache.preferred_types[k]
      end
      for k, original_v in pairs(ephemeral_originals) do
        cache.preferred_types[k] = original_v
      end
      -- FXCache.save returns nil on success or an error STRING on failure
      -- (it does not raise). pcall therefore returns (true, err_string) on
      -- the failure path, so the previous `if not ok` guard alone never
      -- caught a normal save error. Capture the function's return value
      -- too and log when it's non-nil, otherwise the operator triaging a
      -- "HideFabFilter override didn't persist" report would see no log
      -- breadcrumb at all.
      local ok, save_ret = pcall(FXCache.save, cache)
      for k, mem_v in pairs(in_memory_values) do
        cache.preferred_types[k] = mem_v
      end
      if not ok then
        Log.line("PREF", "FXCache.save raised during HideFabFilter "
                       .. "rollback; in-memory override preserved: "
                       .. tostring(save_ret))
      elseif save_ret then
        Log.line("PREF", "FXCache.save failed during HideFabFilter "
                       .. "rollback; in-memory override preserved: "
                       .. tostring(save_ret))
      end
    else
      local save_err = FXCache.save(cache)
      if save_err then
        Log.line("PREF", "FXCache.save failed (HideFabFilter assign): "
                       .. tostring(save_err))
      end
    end
  end
  return assigned
end

-- =============================================================================
-- Utility: Code._save_generated (internal)
-- =============================================================================
-- Shared save-dialog + write flow used by Code.save_file and
-- Code.save_file_jsfx. Opens a native save dialog when js_ReaScriptAPI is
-- present; otherwise falls back to a GetUserInputs prompt and strips path
-- separators from the input so the user cannot escape opts.base_dir.
-- Returns the saved path on success, or nil on cancellation/error.
function Code._save_generated(code, suggested_name, opts)
  local dest_path
  if reaper.JS_Dialog_BrowseForSaveFile then
    local ret, path = reaper.JS_Dialog_BrowseForSaveFile(
      opts.dialog_title, opts.base_dir, suggested_name, opts.filter)
    if ret ~= 1 or not path or path == "" then return nil end
    -- Lower-case the path before matching ext_pattern. Filesystems on
    -- Windows / macOS preserve the typed case, so a user who picks
    -- "MyScript.LUA" in the dialog used to fall through the case-
    -- sensitive `%.lua$` pattern and we'd append .lua, producing the
    -- ugly double-extension MyScript.LUA.lua.
    if not path:lower():match(opts.ext_pattern) then path = path .. opts.ext end
    dest_path = path
  else
    local ret, name = reaper.GetUserInputs(
      opts.fallback_title, 1, opts.fallback_label, suggested_name)
    if not ret or name == "" then return nil end
    if not name:lower():match(opts.ext_pattern) then name = name .. opts.ext end
    name = name:match("[^\\/]+$") or name
    dest_path = opts.base_dir .. RA.SEP .. name
  end
  if Code.safe_write(dest_path, code) then return dest_path end
  return nil
end

-- Save JSFX code to REAPER's Effects folder (thin wrapper over _save_generated).
function Code.save_file_jsfx(code, suggested_name)
  return Code._save_generated(code, suggested_name, {
    dialog_title   = "Save JSFX Effect",
    base_dir       = reaper.GetResourcePath() .. RA.SEP .. "Effects",
    filter         = "JSFX files (.jsfx)\0*.jsfx\0All files\0*.*\0",
    ext            = ".jsfx",
    ext_pattern    = "%.jsfx$",
    fallback_title = "Save JSFX",
    fallback_label = "Filename (saved to REAPER Effects folder):,extrawidth=260",
  })
end

-- Save Lua script to REAPER's Scripts folder (thin wrapper over _save_generated).
function Code.save_file(code, suggested_name)
  return Code._save_generated(code, suggested_name, {
    dialog_title   = "Save Lua Script",
    base_dir       = reaper.GetResourcePath() .. RA.SEP .. "Scripts",
    filter         = "Lua files (.lua)\0*.lua\0All files\0*.*\0",
    ext            = ".lua",
    ext_pattern    = "%.lua$",
    fallback_title = "Save Script",
    fallback_label = "Filename (saved to REAPER Scripts folder):,extrawidth=260",
  })
end

-- Strips API keys and secrets from URLs/error strings before they reach the
-- UI. Covers ?key= / &key= style query params (case-insensitive) and Bearer
-- tokens in headers. Lua patterns do not support alternation, so each secret
-- name is scrubbed with its own gsub; an earlier "one-pattern" attempt used a
-- pipe character that matches literally, so it never fired.
local SCRUB_KEYS = {
  "[Kk][Ee][Yy]",
  "[Tt][Oo][Kk][Ee][Nn]",
  "[Ss][Ee][Cc][Rr][Ee][Tt]",
  "[Aa][Pp][Ii][_]?[Kk][Ee][Yy]",
  "[Aa][Cc][Cc][Ee][Ss][Ss][_][Tt][Oo][Kk][Ee][Nn]",
  "[Pp][Aa][Ss][Ss][Ww][Oo][Rr][Dd]",
}
-- Shared scrubber: both Log.add_error and Diag.add_error route error
-- strings through this before display / storage. SCRUB_KEYS stays a
-- local because nothing else references it.
function Log.scrub_url_secrets(s)
  if not s then return s end
  for _, name in ipairs(SCRUB_KEYS) do
    s = s:gsub("([?&]" .. name .. "=)[^&%s\"']+", "%1***")
  end
  s = s:gsub("([Bb]earer%s+)[^%s\"']+", "%1***")
  return s
end

-- Queue an error message into S.display_messages as an assistant turn,
-- flip S.status to "error", clear in-flight timers, and scroll to bottom.
-- Optional link_url/link_label render a clickable URL beneath the text.
-- Optional `recovery` renders inline recovery buttons scoped by provider/model
-- metadata on the message. `extra` can stamp recovery-specific payload such as
-- a saved prompt or fallback model id.
function Log.add_error(msg, link_url, link_label, recovery, extra)
  S.status             = "error"
  S.send_time          = nil
  S.request_start_time = nil
  local entry = {
    role       = "assistant",
    content    = Log.scrub_url_secrets(msg),
    link_url   = link_url,
    link_label = link_label,
    recovery   = recovery,
  }
  if recovery == "token_limit" or recovery == "google_model_capacity" then
    local p = PROVIDERS.active()
    entry.provider_id = p and p.id or nil
  end
  if type(extra) == "table" then
    for k, v in pairs(extra) do entry[k] = v end
  end
  S.display_messages[#S.display_messages+1] = entry
  S.scroll_to_bottom = true
end

-- =============================================================================
-- Diag -- Diagnostic report builder for bug reports
-- =============================================================================
-- Captures recent code-execution errors and assembles a plain-text diagnostic
-- report the user can copy to their clipboard and paste into a bug report.

-- Schema version stamped into every saved FX cache file. Bump when the
-- on-disk structure changes in a way old code can't safely read. Files
-- with a missing or mismatched version are discarded cleanly on load
-- (fresh scan rebuilds the cache rather than silently misreading it).
-- Declared here (above Diag) because Diag.build_report reads it for the
-- diagnostic report's Plugin System section.
local FXCACHE_VERSION = 1

Diag = { errors = {}, MAX_ERRORS = 20 }

function Diag.add_error(msg, traceback, code)
  local entry = {
    time = os.date("%Y-%m-%d %H:%M:%S"),
    msg  = Log.scrub_url_secrets(tostring(msg)),
    traceback = traceback and Log.scrub_url_secrets(tostring(traceback)) or nil,
    code = code and (code:sub(1, 500) .. (#code > 500 and "..." or "")) or nil,
  }
  Diag.errors[#Diag.errors + 1] = entry
  if #Diag.errors > Diag.MAX_ERRORS then
    table.remove(Diag.errors, 1)
  end
end

-- opts (optional table):
--   skip_followup_note = true  -- omit the trailing "For detailed bugs..."
--                                 guidance paragraph. Used when the report
--                                 is embedded in a pre-filled email body
--                                 that already surfaces its own log-attach
--                                 instruction, so the two don't repeat.
function Diag.build_report(opts)
  local parts = {}
  -- Small pcall wrapper so a broken / missing extension probe can't
  -- crash the report build mid-stream.
  local function _try(fn) local ok, v = pcall(fn); if ok then return v end end
  -- On / Off formatter -- normalises booleans (and nil) to the
  -- ON / OFF convention the rest of the header already uses for
  -- "Auto model" / "Debug logging".
  local function _onoff(v) return v and "ON" or "OFF" end

  parts[#parts + 1] = "=== ReaAssist Diagnostic Report ==="
  parts[#parts + 1] = ""
  parts[#parts + 1] = "ReaAssist version: " .. CFG.VERSION
  parts[#parts + 1] = "REAPER version:    " .. tostring(reaper.GetAppVersion())
  parts[#parts + 1] = "OS:                " .. tostring(reaper.GetOS())
  -- ReaImGui version -- UI / rendering bugs hinge on this. Probe
  -- covers a few possible shapes across ReaImGui releases.
  local imgui_ver = _try(function()
    if not ImGui then return nil end
    if ImGui.ImGui_GetVersion then
      return select(1, ImGui.ImGui_GetVersion())
    end
    if ImGui.ReaImGui_Version then return ImGui.ReaImGui_Version end
  end)
  parts[#parts + 1] = "ReaImGui version:  " .. (imgui_ver and tostring(imgui_ver) or "unknown")
  parts[#parts + 1] = "Provider:          " .. (PROVIDERS.active().label or "unknown")
  parts[#parts + 1] = "Model:             " .. (MODELS.active_id() or "unknown")
  local p = PROVIDERS.active()
  if p.thinking_levels and p.thinking_levels[prefs.thinking_idx] then
    parts[#parts + 1] = "Thinking:          " .. p.thinking_levels[prefs.thinking_idx].label
  end
  -- Gemini paid-tier flag -- only meaningful when the active provider
  -- is Google, since it gates which models are visible and controls
  -- the "free tier data may be used for training" advisory.
  if p and p.id == "google" then
    parts[#parts + 1] = "Gemini paid tier:  " .. _onoff(S.gemini_paid_tier)
  end
  parts[#parts + 1] = "Debug logging:     " .. _onoff(prefs.debug_logging)
  if prefs.debug_logging then
    parts[#parts + 1] = "Log file:          " .. Log.path
    local f = io.open(Log.path, "r")
    if f then
      local size = f:seek("end") or 0
      f:close()
      parts[#parts + 1] = "Log file size:     " .. size .. " bytes"
    end
  end
  -- Current page / screen (which UI view the user was on when they copied
  -- the report). Useful for UI-specific bug reports.
  local screen = "chat"
  if api_keys.screen then
    screen = api_keys.screen
  elseif S.show_bug_report then screen = "bug_report"
  elseif S.show_help       then screen = "help"
  elseif S.show_credits    then screen = "credits"
  end
  parts[#parts + 1] = "Current screen:    " .. screen
  -- Session uptime -- seconds -> human-readable. Helps triage "UI
  -- froze after 6h" / "memory balloon" / long-session issues.
  local uptime_s = math_floor((reaper.time_precise() - (S.session_start_ts or reaper.time_precise())) + 0.5)
  local function _fmt_uptime(sec)
    if sec < 60 then return sec .. "s" end
    if sec < 3600 then
      return string.format("%dm %02ds", math_floor(sec / 60), sec % 60)
    end
    local h = math_floor(sec / 3600)
    local m = math_floor((sec % 3600) / 60)
    return string.format("%dh %02dm", h, m)
  end
  parts[#parts + 1] = "Session uptime:    " .. _fmt_uptime(uptime_s)
  parts[#parts + 1] = ""

  -- Required + optional REAPER extensions. Missing / old extensions
  -- cause a long tail of "button did nothing" / "file dialog didn't
  -- open" bugs that are otherwise a pain to diagnose.
  parts[#parts + 1] = "--- Extensions ---"
  local sws_ok  = reaper.CF_GetSWSVersion ~= nil
  local sws_ver = sws_ok and _try(function() return reaper.CF_GetSWSVersion("") end) or nil
  parts[#parts + 1] = "SWS:               " ..
    (sws_ok and (sws_ver and tostring(sws_ver) or "installed") or "not installed")
  local js_ver = _try(function() return reaper.JS_ReaScriptAPI_Version and reaper.JS_ReaScriptAPI_Version() end)
  parts[#parts + 1] = "js_ReaScriptAPI:   " ..
    (js_ver and tostring(js_ver) or "not installed")
  -- Probe the specific calls ReaAssist uses, so a partially-working
  -- extension (e.g. old SWS / JS build missing a newer symbol) shows
  -- up here too rather than reading as "fully installed."
  parts[#parts + 1] = "CF_ShellExecute:   " ..
    _onoff(reaper.CF_ShellExecute ~= nil)
  parts[#parts + 1] = "CF_LocateInExplorer: " ..
    _onoff(reaper.CF_LocateInExplorer ~= nil)
  parts[#parts + 1] = "JS_Dialog_BrowseForSaveFile: " ..
    _onoff(reaper.JS_Dialog_BrowseForSaveFile ~= nil)
  parts[#parts + 1] = ""

  -- User preferences
  parts[#parts + 1] = "--- Preferences ---"
  parts[#parts + 1] = "Auto-run:          " .. _onoff(prefs.auto_run)
  parts[#parts + 1] = "Auto-backup:       " .. _onoff(prefs.auto_backup)
  parts[#parts + 1] = "Include snapshot:  " .. _onoff(prefs.include_snapshot)
  parts[#parts + 1] = "Include API ref:   " .. _onoff(prefs.include_api_ref)
  parts[#parts + 1] = "Max history turns: " .. CFG.MAX_HISTORY_TURNS
  -- Cloud request timeout (seconds) -- affects "request hung" /
  -- "503 / timeout" bug reports directly.
  if prefs.cloud_request_timeout then
    parts[#parts + 1] = "Cloud timeout:     " .. tostring(prefs.cloud_request_timeout) .. "s"
  end
  parts[#parts + 1] = "API ref loaded:    " .. _onoff(
    S.api_ref_section_cache and S.api_ref_section_cache.core ~= nil)
  parts[#parts + 1] = "UI theme:          " .. tostring(prefs.theme_id or "default")
  local scale_val = CFG.UI_SCALE_OPTIONS[prefs.ui_scale_idx or 3] or 1.0
  parts[#parts + 1] = str_format("UI scale:          %.2fx", scale_val)
  -- API keys configured per provider (without revealing the keys). Helps
  -- diagnose "Test API Keys fails" or wrong-provider-selected reports.
  local configured = {}
  for _, pk in ipairs(PROVIDERS) do
    if S.api_key_map and S.api_key_map[pk.id] and S.api_key_map[pk.id] ~= "" then
      configured[#configured+1] = pk.label or pk.id
    end
  end
  parts[#parts + 1] = "API keys set:      " ..
    (#configured > 0 and tbl_concat(configured, ", ") or "(none)")
  parts[#parts + 1] = ""

  -- Plugin system state (chains, preferences, FX cache). Critical for
  -- diagnosing plugin-resolve / popup / auto-assign bugs.
  parts[#parts + 1] = "--- Plugin System ---"
  local ok_chains, chains = pcall(Code.get_fallback_chains)
  if ok_chains and chains then
    local chain_types = {}
    for k in pairs(chains) do chain_types[#chain_types+1] = k end
    table.sort(chain_types)
    parts[#parts + 1] = "Fallback chains loaded: " .. #chain_types
      .. (#chain_types > 0 and " (" .. tbl_concat(chain_types, ", ") .. ")" or "; check Plugin_Ref.md")
  else
    parts[#parts + 1] = "Fallback chains:        ERROR loading"
  end
  local ok_cache, fx_cache = pcall(FXCache.load)
  if ok_cache and fx_cache then
    local pref_types = fx_cache.preferred_types or {}
    local pref_keys = {}
    for k in pairs(pref_types) do pref_keys[#pref_keys+1] = k end
    table.sort(pref_keys)
    if #pref_keys == 0 then
      parts[#parts + 1] = "Preferred plugins:      (none set)"
    else
      parts[#parts + 1] = "Preferred plugins:"
      for _, k in ipairs(pref_keys) do
        parts[#parts + 1] = "  " .. k .. " = " .. tostring(pref_types[k])
      end
    end
    local plugin_count = 0
    for _ in pairs(fx_cache.plugins or {}) do
      plugin_count = plugin_count + 1
    end
    parts[#parts + 1] = "FX cache size:          " .. plugin_count .. " plugins scanned"
  end
  if CTX._installed_fx_list then
    parts[#parts + 1] = "Installed FX enumerated: " .. #CTX._installed_fx_list
  else
    parts[#parts + 1] = "Installed FX enumerated: (not populated yet this session)"
  end
  if ok_cache and fx_cache then
    parts[#parts + 1] = "FX cache schema:        v" .. tostring(fx_cache._version or "?")
      .. " (expected v" .. FXCACHE_VERSION .. ")"
  end
  -- Plugin_Ref.md status. Missing / unreadable file breaks chains + curated
  -- injection; size signals whether it looks truncated.
  local ref_path = RA.RESOURCES_DIR .. "Plugin_Ref.md"
  local rf = io.open(ref_path, "r")
  if rf then
    local sz = rf:seek("end") or 0
    rf:close()
    parts[#parts + 1] = "Plugin_Ref.md:          present (" .. sz .. " bytes)"
  else
    parts[#parts + 1] = "Plugin_Ref.md:          MISSING at " .. ref_path
  end
  parts[#parts + 1] = ""

  -- Recent errors
  if #Diag.errors > 0 then
    parts[#parts + 1] = "--- Recent Errors (" .. #Diag.errors .. ") ---"
    for i, e in ipairs(Diag.errors) do
      parts[#parts + 1] = ""
      parts[#parts + 1] = "[" .. i .. "] " .. e.time
      parts[#parts + 1] = "  Error: " .. e.msg
      if e.traceback then
        parts[#parts + 1] = "  Traceback: " .. e.traceback
      end
      if e.code then
        parts[#parts + 1] = "  Code snippet: " .. e.code
      end
    end
  else
    parts[#parts + 1] = "--- No recent errors ---"
  end
  parts[#parts + 1] = ""

  -- Recent chat (last 5 exchanges, truncated) with details metadata.
  -- Trailing blank moved INSIDE the `if` so an empty chat doesn't
  -- leave a stray double-blank between "No recent errors" above and
  -- "Session State" below.
  if #S.display_messages > 0 then
    parts[#parts + 1] = "--- Recent Chat (last 5 exchanges, truncated) ---"
    local start = math.max(1, #S.display_messages - 9)
    for i = start, #S.display_messages do
      local m = S.display_messages[i]
      local content = m.content or ""
      if #content > 300 then content = content:sub(1, 300) .. "..." end
      parts[#parts + 1] = ""
      parts[#parts + 1] = "[" .. (m.role or "?") .. "] " .. content
      -- Include exchange details when available (context sent, tokens, cost).
      local details = {}
      if m.ctx_label   then details[#details + 1] = "context: " .. m.ctx_label end
      if m.model_label then details[#details + 1] = "model: " .. m.model_label end
      if m.tok_in      then details[#details + 1] = "in: " .. m.tok_in end
      if m.tok_out     then details[#details + 1] = "out: " .. m.tok_out end
      if m.tok_cache_read and m.tok_cache_read > 0 then
        details[#details + 1] = "cache_read: " .. m.tok_cache_read
      end
      if m.tok_cache_create and m.tok_cache_create > 0 then
        details[#details + 1] = "cache_create: " .. m.tok_cache_create
      end
      if m.cost and m.cost > 0 then
        details[#details + 1] = str_format("cost: $%.4f", m.cost)
      end
      if m.fx_cache_label then
        details[#details + 1] = "fx_cache: " .. m.fx_cache_label
      end
      if #details > 0 then
        parts[#parts + 1] = "  [" .. tbl_concat(details, " | ") .. "]"
      end
      -- Include generated code block if present (truncated).
      if m.code_block then
        local code = m.code_block
        if #code > 800 then code = code:sub(1, 800) .. "\n  ...(truncated)" end
        parts[#parts + 1] = "  Code block:"
        for cline in code:gmatch("[^\n]+") do
          parts[#parts + 1] = "    " .. cline
        end
      end
    end
    parts[#parts + 1] = ""
  end

  -- Status
  parts[#parts + 1] = "--- Session State ---"
  parts[#parts + 1] = "Status: " .. tostring(S.status)
  parts[#parts + 1] = "Messages: " .. #S.display_messages
  parts[#parts + 1] = "History turns: " .. #S.history
  -- In-flight request state. Only meaningful while a request is
  -- actually pending -- `S.send_time` is non-nil for the duration of
  -- the curl call and cleared on completion. Catches "my send is
  -- stuck" reports where the watchdog hasn't tripped yet.
  if S.send_time then
    local elapsed = reaper.time_precise() - S.send_time
    parts[#parts + 1] = str_format("In-flight request: started %.1fs ago", elapsed)
  end

  -- Resolve popup state: useful for diagnosing "popup didn't fire" reports.
  if S.resolve_popup then
    parts[#parts + 1] = "Resolve popup: ACTIVE (type=" ..
      tostring(S.resolve_popup.type) .. ")"
  elseif S.open_resolve_popup then
    parts[#parts + 1] = "Resolve popup: pending open"
  else
    parts[#parts + 1] = "Resolve popup: inactive"
  end

  -- Pending request state: captures an in-flight or stuck turn.
  local pending_bits = {}
  if S.pending_orig_prompt then pending_bits[#pending_bits+1] = "orig_prompt" end
  if S.pending_snapshot    then pending_bits[#pending_bits+1] = "snapshot"    end
  if S.pending_code        then pending_bits[#pending_bits+1] = "code"        end
  if S.pending_resolves and #S.pending_resolves > 0 then
    pending_bits[#pending_bits+1] = "queued_resolves=" ..
      tbl_concat(S.pending_resolves, ",")
  end
  if #pending_bits > 0 then
    parts[#parts + 1] = "Pending turn state: " .. tbl_concat(pending_bits, ", ")
  end

  -- Sticky context keys pinned this session (e.g. plugin_ref:Pro-Q 4). Shows
  -- what the preempt / resolve flow injected so "model got wrong params"
  -- reports can be traced.
  if S.sticky_context and next(S.sticky_context) then
    local sticky_keys = {}
    for k in pairs(S.sticky_context) do sticky_keys[#sticky_keys+1] = k end
    table.sort(sticky_keys)
    parts[#parts + 1] = "Sticky context pinned: " ..
      tbl_concat(sticky_keys, ", ")
  end

  -- Last script execution result (from the most recent generated-code run).
  -- Captures compile + runtime errors from user-run code. Errors get cleared
  -- on next send, so a non-nil here means "the last thing the user saw".
  if S.last_run_error and S.last_run_error ~= "" then
    parts[#parts + 1] = "Last script error: " .. tostring(S.last_run_error)
  end

  -- FX scan state: catches stuck/in-flight rescans.
  if fx_cache_ui and fx_cache_ui.rescan and fx_cache_ui.rescan.active then
    parts[#parts + 1] = "FX scan in progress: " ..
      tostring(fx_cache_ui.rescan.ident or "?")
  end
  if pref_plugins and pref_plugins.scan and pref_plugins.scan.active then
    parts[#parts + 1] = "Preferred-plugins scan in progress: " ..
      tostring(pref_plugins.scan.phase or "?")
  end

  -- Update-check state: "why isn't my update showing" reports.
  if update and update.state and update.state ~= "idle" then
    parts[#parts + 1] = "Update check state: " .. tostring(update.state)
      .. (update.remote_version and (" (remote v" .. update.remote_version .. ")") or "")
  end

  -- Follow-up note block. Skipped when the caller (the Feedback page's
  -- email flow) embeds this report inside an email body that already
  -- surfaces a tailored log-attach instruction of its own -- printing
  -- both creates redundant back-to-back "please attach the log" text.
  -- Default behaviour (used by the standalone Copy button) keeps the
  -- note in so a hand-pasted report carries the instruction with it.
  if not (opts and opts.skip_followup_note) then
    parts[#parts + 1] = ""
    parts[#parts + 1] = "For detailed bugs (wrong model output, multi-turn issues, API errors),"
    parts[#parts + 1] = "also attach the debug log: " .. Log.path
    parts[#parts + 1] = "Enable \"Enable Advanced Log\" on the Report a Bug page if it's off, reproduce, then send."
  end
  parts[#parts + 1] = ""
  parts[#parts + 1] = "=== End Report ==="
  return tbl_concat(parts, "\n")
end

-- =============================================================================
-- Context bucket functions
-- =============================================================================
-- Each takes a project pointer (proj) captured at send time and returns a
-- plain-text string describing a slice of that project's state. Track indices
-- are reported as 1-based for the assistant's benefit (REAPER API is 0-based).
-- =============================================================================
-- Unified FX parameter cache (JSON)
-- =============================================================================
-- Persists plugin parameter metadata (names, indices, defaults, enum values)
-- to FX_Cache.json. Two top-level maps:
--
--   preferred_types  -- user preferences (one plugin per type). Values are
--                       the chain-entry form (format-agnostic), e.g.
--                       "Pro-Q 4" or "ReJJ/ReEQ/ReEQ.jsfx". Populated either
--                       by Code.ensure_preferred_from_chains at startup or
--                       by user edits on the Preferred Plugins page.
--   plugins          -- live-scanned param data keyed by full enumerated FX
--                       name (e.g. "VST3: Pro-Q 4"). Only populated by
--                       user-triggered scans for non-curated plugins.
--
-- Structure:
--   {
--     "preferred_types": { "eq": "Pro-Q 4", ... },
--     "plugins": {
--       "VST3: Some Plugin": {
--         "param_count": 234,
--         "max_group": 24,
--         "params": [
--           { "idx": 0, "name": "1 Frequency", "default": 0.3040,
--             "display": "100.0 Hz" },
--           { "idx": 5, "name": "1 Shape", "default": 0.0,
--             "display": "Bell", "enum": ["Bell","Low Cut",...] }
--         ]
--       }
--     }
--   }

JSON = { NULL = {} }

FXCache = {}

-- In-memory cache. Loaded lazily on first access, invalidated on save.
local _fx_cache_mem = nil

function FXCache.load()
  if _fx_cache_mem then return _fx_cache_mem end
  local ok_f, f = pcall(io.open, RA.FX_CACHE_PATH, "r")
  if not ok_f or not f then
    -- Stamp _version on every fresh-table return so the schema invariant
    -- doesn't depend on a save round-trip to land. Earlier shape varied
    -- per branch (no-file / empty / corrupt / schema-mismatch) which left
    -- a brief window where _fx_cache_mem._version was nil.
    _fx_cache_mem = { _version = FXCACHE_VERSION, preferred_types = {}, plugins = {} }
    return _fx_cache_mem
  end
  local content = f:read("*a")
  f:close()
  if not content or content == "" then
    _fx_cache_mem = { _version = FXCACHE_VERSION, preferred_types = {}, plugins = {} }
    return _fx_cache_mem
  end
  local data, err = JSON.decode(content)
  if not data then
    -- Surface the parse error to the debug log. Without this, the user
    -- silently loses their cache on a truncated or corrupted file with
    -- no breadcrumb to triage from -- only the schema-mismatch branch
    -- below logged.
    Log.line("FX_CACHE", "JSON decode failed (" .. tostring(err)
      .. "); discarding cache")
    _fx_cache_mem = { _version = FXCACHE_VERSION, preferred_types = {}, plugins = {} }
    return _fx_cache_mem
  end
  -- Reject files from a different schema version. Missing _version means
  -- the file was written before this field was added; treat it the same
  -- way -- start fresh rather than silently misread. User's only real
  -- loss is re-scanning plugins on next use.
  if data._version ~= FXCACHE_VERSION then
    Log.line("FX_CACHE", "schema version mismatch (file="
      .. tostring(data._version) .. ", expected=" .. FXCACHE_VERSION
      .. ") -- discarding cache")
    _fx_cache_mem = { _version = FXCACHE_VERSION, preferred_types = {}, plugins = {} }
    return _fx_cache_mem
  end
  -- Ensure required top-level keys exist.
  data.preferred_types = data.preferred_types or {}
  data.plugins = data.plugins or {}
  _fx_cache_mem = data
  return _fx_cache_mem
end

function FXCache.save(cache)
  cache = cache or _fx_cache_mem
  if not cache then return "No cache data to save." end
  -- Stamp the schema version so future builds can reject old files cleanly.
  cache._version = FXCACHE_VERSION
  local json_str, err = JSON.encode(cache, "  ")
  if not json_str then return "JSON encode failed: " .. tostring(err) end
  -- Atomic write: temp file + rename. AV scanners and abrupt exits can
  -- otherwise leave the 60+ KB cache JSON half-written, breaking parse on
  -- the next session.
  local tmp_path = RA.FX_CACHE_PATH .. ".tmp"
  local ok_f, f = pcall(io.open, tmp_path, "w")
  if not ok_f or not f then return "Failed to open " .. tmp_path end
  local ok_w, w_err = pcall(function() f:write(json_str .. "\n") end)
  pcall(function() f:close() end)
  if not ok_w then
    os.remove(tmp_path)
    return "Failed writing " .. tmp_path .. ": " .. tostring(w_err)
  end
  -- Backup-and-restore rename: Windows os.rename cannot overwrite, so the
  -- original cache must be moved out of the way before renaming tmp into
  -- place. If the rename fails (AV lock, disk full, permission flip), the
  -- .bak is restored so the user never loses their existing cache.
  local bak_path = RA.FX_CACHE_PATH .. ".bak"
  os.remove(bak_path)
  local had_existing = os.rename(RA.FX_CACHE_PATH, bak_path)
  local ok_r, ren_err = os.rename(tmp_path, RA.FX_CACHE_PATH)
  if not ok_r then
    os.remove(tmp_path)
    if had_existing then os.rename(bak_path, RA.FX_CACHE_PATH) end
    return "Failed renaming temp cache: " .. tostring(ren_err)
  end
  if had_existing then os.remove(bak_path) end
  _fx_cache_mem = cache
  return nil  -- success
end

function FXCache.get_plugin(identifier)
  local cache = FXCache.load()
  return cache.plugins[identifier]
end

-- Look up a plugin by fuzzy-matching the identifier against cache keys.
-- Uses bidirectional case-insensitive substring match (each direction catches
-- both "Pro-Q 4" in "VST3: Pro-Q 4 (FabFilter)" and vice versa).
function FXCache.find_plugin(name)
  local cache = FXCache.load()
  -- Exact match first.
  if cache.plugins[name] then return name, cache.plugins[name] end
  -- Fuzzy match against all cached identifiers. Pick the longest
  -- matching key (most specific) instead of `pairs`-first match: when
  -- two cached plugins share a common substring (e.g. "Pro-Q" and
  -- "Pro-Q 4 (FabFilter)") `pairs` order is hash-bucket-dependent, so
  -- the same lookup could pick either across saves/reloads. CTX.fx_params
  -- attaches the cached plugin's enum/range data via this lookup, so
  -- non-deterministic resolution corrupts the [enum: ...] annotation
  -- sent to the model.
  local name_lower = name:lower()
  local best_ident, best_data, best_len = nil, nil, -1
  for ident, data in pairs(cache.plugins) do
    local ident_lower = ident:lower()
    if ident_lower:find(name_lower, 1, true)
       or name_lower:find(ident_lower, 1, true) then
      if #ident > best_len then
        best_ident, best_data, best_len = ident, data, #ident
      end
    end
  end
  return best_ident, best_data
end

-- Mutation counter bumped whenever cache.plugins or cache.preferred_types
-- changes. Lets render-side code cheaply cache lists derived from these
-- (FX cache settings page, preempt scans) and invalidate on change
-- without having to thread invalidation calls through every mutator.
FXCache._mutation_count = 0

function FXCache.put_plugin(identifier, params_list, param_count, max_group, needs_deep_scan)
  local cache = FXCache.load()
  cache.plugins[identifier] = {
    param_count      = param_count or 0,
    max_group        = max_group or 0,
    params           = params_list,
    needs_deep_scan  = needs_deep_scan or nil,
  }
  FXCache._mutation_count = FXCache._mutation_count + 1
  return FXCache.save(cache)
end

function FXCache.remove_plugin(identifier)
  local cache = FXCache.load()
  cache.plugins[identifier] = nil
  FXCache._mutation_count = FXCache._mutation_count + 1
  return FXCache.save(cache)
end

function FXCache.clear_plugins()
  local cache = FXCache.load()
  cache.plugins = {}
  FXCache._mutation_count = FXCache._mutation_count + 1
  return FXCache.save(cache)
end

-- Wipe all type->plugin mappings. Used by the "Clear All" button on the
-- Preferred Plugins page. Does NOT touch cache.plugins (scanned param data
-- stays intact so we don't have to re-scan everything when the user reconfigures).
function FXCache.clear_preferred_types()
  local cache = FXCache.load()
  cache.preferred_types = {}
  FXCache._mutation_count = FXCache._mutation_count + 1
  return FXCache.save(cache)
end

-- Canonicalize an identifier to AddByName-ready form by resolving against
-- the installed-FX list (REAPER 7.42+'s EnumInstalledFX). Chain-entry form
-- ("Twin 3", "Pro-Q 4") is portable across plugin-format namespaces and is
-- what shows up in .RfxChain files, but TrackFX_AddByName works most
-- reliably with the prefixed form ("VST3i: Twin 3"). The model also picks
-- the right plugin format when it sees the prefix instead of guessing.
--
-- Returns (canonical, was_upgraded) where was_upgraded is true if the
-- input was a bare chain-entry form that resolved to a prefixed form.
-- If the identifier already has a recognized prefix, returns it as-is
-- (no resolution attempted). If no match in installed-FX, or the FX list
-- isn't available (REAPER < 7.42), returns the identifier unchanged.
--
-- type_key is used as a tie-breaker when multiple format variants of the
-- same plugin are installed (e.g., Twin 3 as both VST3i and AUi on Mac):
-- "synth" prefers instrument-variant prefixes (*i:); other types prefer
-- effect-variant prefixes. Without type_key, picks the first match.
local _ADDBYNAME_PREFIXES = {
  "VST3i", "VST3", "VSTi", "VST",
  "AUi", "AU",
  "CLAPi", "CLAP",
  "LV2i", "LV2",
  "DXi", "DX",
  "JS",
}
local _INSTRUMENT_PREFIXES = {
  VST3i = true, VSTi = true, AUi = true, CLAPi = true,
  LV2i = true, DXi = true,
}
local _INSTRUMENT_TYPES = { synth = true }

local function _identifier_has_addbyname_prefix(identifier)
  local prefix = identifier:match("^([A-Za-z][A-Za-z0-9]*):")
  if not prefix then return false end
  for _, p in ipairs(_ADDBYNAME_PREFIXES) do
    if prefix == p then return true end
  end
  return false
end

local function _strip_vendor_suffix(name)
  -- "VST3: Pro-Q 4 (FabFilter)" -> "VST3: Pro-Q 4". Chain-entry form
  -- doesn't include the vendor, so the canonical form drops it too.
  return (name:gsub("%s*%(.-%)%s*$", ""))
end

function FXCache.canonicalize_identifier(type_key, identifier)
  if not identifier or identifier == "" then return identifier, false end
  if _identifier_has_addbyname_prefix(identifier) then
    return identifier, false
  end
  if not CTX or not CTX.populate_installed_fx then return identifier, false end
  CTX.populate_installed_fx()
  local installed = CTX._installed_fx_list
  if not installed or #installed == 0 then return identifier, false end

  local target = identifier:lower()
  local prefer_instrument = type_key and _INSTRUMENT_TYPES[type_key:lower()] or false
  -- Match against the bare base name (after stripping the AddByName prefix
  -- and a trailing " (Vendor)" suffix) but RETURN the original installed
  -- entry verbatim. EnumInstalledFX is the source of truth for AddByName --
  -- mirroring its exact output keeps the canonicalizer aligned with
  -- Code.resolve_chain_entry (which also returns the full installed
  -- identifier) and avoids ambiguity if two plugins share a stem name
  -- across vendors.
  local best, best_rank = nil, -1
  for _, full in ipairs(installed) do
    local prefix, rest = full:match("^([A-Za-z][A-Za-z0-9]*):%s*(.+)$")
    if prefix and rest then
      local base = _strip_vendor_suffix(rest):lower()
      if base == target then
        local is_instr = _INSTRUMENT_PREFIXES[prefix] == true
        -- Rank prefers (instrument-match for synth-type), then prefers
        -- earlier-in-list (which is roughly REAPER's preferred load order
        -- via _ADDBYNAME_PREFIXES).
        local rank = (prefer_instrument == is_instr) and 1000 or 0
        for i, p in ipairs(_ADDBYNAME_PREFIXES) do
          if prefix == p then rank = rank + (#_ADDBYNAME_PREFIXES - i); break end
        end
        if rank > best_rank then
          best, best_rank = full, rank
        end
      end
    end
  end
  if best then return best, true end
  return identifier, false
end

function FXCache.set_preferred_type(type_key, identifier)
  -- Canonicalize before storing so the on-disk form is AddByName-ready.
  -- Logs the upgrade once (per write) so the operator sees that the legacy
  -- bare-name input was upgraded.
  local canonical, upgraded = FXCache.canonicalize_identifier(type_key, identifier)
  if upgraded then
    Log.line("PREF", str_format(
      "preferred_types.%s = %s -> %s (canonicalized on save)",
      type_key, identifier, canonical))
  end
  local cache = FXCache.load()
  cache.preferred_types[type_key] = canonical
  FXCache._mutation_count = FXCache._mutation_count + 1
  return FXCache.save(cache)
end

-- One-time-per-session migration. Walks cache.preferred_types and upgrades
-- any bare chain-entry forms ("Twin 3") to AddByName-ready prefixed form
-- ("VST3i: Twin 3") via FXCache.canonicalize_identifier. Logs each upgrade
-- as `preferred_types.<type> = old -> new` so legacy data drift is visible
-- once. Saves the cache only if any entry was actually upgraded.
--
-- Idempotent: a second call after the first does nothing because every
-- entry is already prefixed. Safe to call from multiple entry points
-- (Code.ensure_preferred_from_chains startup, render-side first paint).
function FXCache.canonicalize_all_preferred_types()
  if FXCache._canonicalized_session then return 0 end
  if not CTX or not CTX.populate_installed_fx then return 0 end
  CTX.populate_installed_fx()
  if not CTX._installed_fx_list or #CTX._installed_fx_list == 0 then
    -- REAPER < 7.42 or empty FX library. Defer; another call may succeed
    -- once the list is populated. Don't mark as done.
    return 0
  end
  local cache = FXCache.load()
  local upgraded_count = 0
  for type_key, identifier in pairs(cache.preferred_types or {}) do
    local canonical, upgraded = FXCache.canonicalize_identifier(type_key, identifier)
    if upgraded then
      Log.line("PREF", str_format(
        "preferred_types.%s = %s -> %s (canonicalized on load)",
        type_key, identifier, canonical))
      cache.preferred_types[type_key] = canonical
      upgraded_count = upgraded_count + 1
    end
  end
  FXCache._canonicalized_session = true
  if upgraded_count > 0 then
    FXCache._mutation_count = FXCache._mutation_count + 1
    FXCache.save(cache)
  end
  return upgraded_count
end

function FXCache.get_preferred_types()
  local cache = FXCache.load()
  return cache.preferred_types
end

function FXCache.invalidate()
  _fx_cache_mem = nil
  FXCache._mutation_count = (FXCache._mutation_count or 0) + 1
  -- Clear the session migration flag too so a fresh load (e.g., after a
  -- corrupt-cache reset, an external edit, or a manual reload) will
  -- re-run canonicalization on whatever's now on disk.
  FXCache._canonicalized_session = nil
end

-- =============================================================================
-- Context bucket builders (CTX)
-- =============================================================================
-- Stored in a table to conserve top-level local variable slots
-- (Lua 5.x 200-local limit). Each function takes (proj) and returns a string.
CTX = {}

function CTX.reaper_version()
  return "REAPER version: " .. tostring(reaper.GetAppVersion() or "unknown")
end

function CTX.reaassist_version()
  return "ReaAssist version: " .. tostring(CFG.VERSION or "unknown")
end

function CTX.extension_status(user_text)
  local text = tostring(user_text or ""):lower()
  local clean = text:gsub("[_%-%s]+", " ")
  local compact = clean:gsub("%s+", "")
  local wants_imgui = compact:find("reaimgui", 1, true) ~= nil
  local wants_sws = text:find("%f[%w]sws%f[%W]") ~= nil
  local wants_jsapi = compact:find("jsreascriptapi", 1, true) ~= nil
    or clean:find("js reascript api", 1, true) ~= nil
    or clean:find("reascript api", 1, true) ~= nil
  local wants_all = clean:find("%f[%w]extensions?%f[%W]") ~= nil
    and (clean:find("%f[%w]installed%f[%W]") ~= nil
      or clean:find("%f[%w]available%f[%W]") ~= nil
      or clean:find("%f[%w]status%f[%W]") ~= nil
      or clean:find("%f[%w]version%f[%W]") ~= nil
      or clean:find("%f[%w]have%f[%W]") ~= nil)
  if not (wants_imgui or wants_sws or wants_jsapi or wants_all) then
    return nil
  end

  local function try(fn)
    local ok, a, b, c, d = pcall(fn)
    if ok then return a, b, c, d end
  end
  local function fmt(label, installed, version)
    if not installed then return label .. ": not installed" end
    return label .. ": installed"
      .. (version and version ~= "" and (" (" .. tostring(version) .. ")") or "")
  end
  local function imgui_line()
    local installed = reaper.ImGui_CreateContext ~= nil
    local ver = nil
    if installed and reaper.ImGui_GetVersion then
      local a, _, _, d = try(function() return reaper.ImGui_GetVersion() end)
      ver = d or a
    end
    return fmt("ReaImGui", installed, ver)
  end
  local function sws_line()
    local installed = reaper.CF_GetSWSVersion ~= nil
    local ver = nil
    if installed then
      ver = try(function() return reaper.CF_GetSWSVersion("") end)
      if not ver or ver == "" then
        ver = try(function() return reaper.CF_GetSWSVersion() end)
      end
    end
    return fmt("SWS Extension", installed, ver)
  end
  local function jsapi_line()
    local installed = reaper.JS_ReaScriptAPI_Version ~= nil
    local ver = installed and try(function()
      return reaper.JS_ReaScriptAPI_Version()
    end) or nil
    return fmt("js_ReaScriptAPI", installed, ver)
  end

  local lines = {}
  if wants_all or wants_imgui then lines[#lines + 1] = imgui_line() end
  if wants_all or wants_sws then lines[#lines + 1] = sws_line() end
  if wants_all or wants_jsapi then lines[#lines + 1] = jsapi_line() end
  if #lines == 1 then return lines[1] end
  return "ReaAssist extension status:\n" .. tbl_concat(lines, "\n")
end

function CTX.ai_selection_status(user_text)
  local text = tostring(user_text or ""):lower()
  local clean = text:gsub("[_%-%s]+", " ")
  local mentions_model = clean:find("%f[%w]model%f[%W]") ~= nil
  local mentions_provider = clean:find("%f[%w]provider%f[%W]") ~= nil
  local mentions_thinking = clean:find("%f[%w]thinking%f[%W]") ~= nil
    or clean:find("%f[%w]reasoning%f[%W]") ~= nil
  local mentions_ai = clean:find("%f[%w]ai%f[%W]") ~= nil
    or clean:find("%f[%w]llm%f[%W]") ~= nil
    or clean:find("%f[%w]reaassist%f[%W]") ~= nil
  local selection_word = clean:find("%f[%w]selected%f[%W]") ~= nil
    or clean:find("%f[%w]active%f[%W]") ~= nil
    or clean:find("%f[%w]current%f[%W]") ~= nil
    or clean:find("%f[%w]using%f[%W]") ~= nil
    or clean:find("%f[%w]use%f[%W]") ~= nil
    or clean:find("%f[%w]you%f[%W]") ~= nil
  if not (mentions_model or mentions_provider or mentions_thinking) then
    return nil
  end
  if not (selection_word or mentions_ai) then return nil end
  if type(PROVIDERS) ~= "table"
      or type(PROVIDERS.active) ~= "function"
      or type(MODELS) ~= "table"
      or type(prefs) ~= "table" then
    return nil
  end

  local function try(fn)
    local ok, v = pcall(fn)
    if ok then return v end
  end
  local p = try(function() return PROVIDERS.active() end) or {}
  local m = MODELS[prefs.model_idx] or MODELS[1] or {}
  local provider_label = tostring(p.label or p.id or "unknown")
  if p.id and p.id ~= p.label then
    provider_label = provider_label .. " (" .. tostring(p.id) .. ")"
  end
  local model_id = try(function()
    if type(MODELS.active_id) == "function" then return MODELS.active_id() end
  end) or m.id
  local model_label = tostring(m.label or model_id or "unknown")
  if model_id and tostring(model_id) ~= model_label then
    model_label = model_label .. " (" .. tostring(model_id) .. ")"
  end
  local thinking_label = "not available"
  if p.thinking_levels and prefs.thinking_idx and prefs.thinking_idx > 0 then
    local tl = p.thinking_levels[prefs.thinking_idx]
    if tl and tl.label then thinking_label = tostring(tl.label) end
  end
  return "AI selection:\nProvider: " .. provider_label
    .. "\nModel: " .. model_label
    .. "\nThinking: " .. thinking_label
end

function CTX.reaassist_settings_status(user_text)
  local text = tostring(user_text or ""):lower()
  local clean = text:gsub("[_%-%s]+", " ")
  local compact = clean:gsub("%s+", "")
  local mentions_settings = clean:find("%f[%w]settings%f[%W]") ~= nil
    or clean:find("%f[%w]preferences%f[%W]") ~= nil
  local mentions_reaassist = clean:find("%f[%w]reaassist%f[%W]") ~= nil
  local wants_auto_run = compact:find("autorun", 1, true) ~= nil
  local wants_auto_backup = compact:find("autobackup", 1, true) ~= nil
    or ((clean:find("%f[%w]backup%f[%W]") ~= nil
      or clean:find("%f[%w]backups%f[%W]") ~= nil)
      and (mentions_settings or mentions_reaassist
        or clean:find("%f[%w]enabled%f[%W]") ~= nil
        or clean:find("%f[%w]on%f[%W]") ~= nil
        or clean:find("%f[%w]off%f[%W]") ~= nil))
  local wants_snapshot = clean:find("project snapshot", 1, true) ~= nil
    or clean:find("include snapshot", 1, true) ~= nil
    or clean:find("snapshot context", 1, true) ~= nil
  local wants_api_ref = clean:find("api reference", 1, true) ~= nil
    or clean:find("api ref", 1, true) ~= nil
  local wants_structured = clean:find("structured edit", 1, true) ~= nil
    or clean:find("structured edits", 1, true) ~= nil
    or clean:find("typed action", 1, true) ~= nil
    or clean:find("typed actions", 1, true) ~= nil
  local wants_debug = clean:find("debug logging", 1, true) ~= nil
    or clean:find("debug log", 1, true) ~= nil
  local wants_update_check = clean:find("update check", 1, true) ~= nil
    or clean:find("update checking", 1, true) ~= nil
    or clean:find("check for updates", 1, true) ~= nil
  local wants_reply_language = clean:find("reply language", 1, true) ~= nil
    or clean:find("response language", 1, true) ~= nil
    or clean:find("chat language", 1, true) ~= nil
  local wants_summary = mentions_reaassist and mentions_settings
  if not (wants_summary or wants_auto_run or wants_auto_backup
      or wants_snapshot or wants_api_ref or wants_structured
      or wants_debug or wants_update_check or wants_reply_language) then
    return nil
  end
  if type(prefs) ~= "table" then return nil end

  local function onoff(v) return v and "ON" or "OFF" end
  local structured_state = "built in"
  if type(Code) == "table"
      and type(Code.typed_actions_public_force_off) == "function"
      and Code.typed_actions_public_force_off() then
    structured_state = "temporarily disabled"
  end
  if wants_structured and not (wants_summary or wants_auto_run
      or wants_auto_backup or wants_snapshot or wants_api_ref
      or wants_debug or wants_update_check or wants_reply_language) then
    return "Structured track edits: " .. structured_state
  end
  local lang_label = CFG.REPLY_LANGUAGE_LABELS[prefs.reply_language_idx or 1]
    or "English"
  return "ReaAssist settings:\n"
    .. "Auto-run scripts: " .. onoff(prefs.auto_run) .. "\n"
    .. "Auto-backup before run: " .. onoff(prefs.auto_backup) .. "\n"
    .. "Include project snapshot: " .. onoff(prefs.include_snapshot) .. "\n"
    .. "Always include API reference: " .. onoff(prefs.include_api_ref) .. "\n"
    .. "Debug logging: " .. onoff(prefs.debug_logging) .. "\n"
    .. "Check for updates: " .. onoff(prefs.update_check) .. "\n"
    .. "Reply language: " .. lang_label
end

function CTX.diagnostics_status(user_text)
  local text = tostring(user_text or ""):lower()
  local clean = text:gsub("[_%-%s]+", " ")
  local mentions_diag = clean:find("%f[%w]diagnostics?%f[%W]") ~= nil
    or clean:find("automatic diagnostics", 1, true) ~= nil
    or clean:find("anonymous diagnostics", 1, true) ~= nil
  if not mentions_diag then return nil end
  local wants_status = clean:find("%f[%w]status%f[%W]") ~= nil
    or clean:find("%f[%w]tier%f[%W]") ~= nil
    or clean:find("%f[%w]setting%f[%W]") ~= nil
    or clean:find("%f[%w]settings%f[%W]") ~= nil
    or clean:find("%f[%w]selected%f[%W]") ~= nil
    or clean:find("%f[%w]current%f[%W]") ~= nil
    or clean:find("%f[%w]enabled%f[%W]") ~= nil
    or clean:find("%f[%w]on%f[%W]") ~= nil
    or clean:find("%f[%w]off%f[%W]") ~= nil
    or clean:find("%f[%w]basic%f[%W]") ~= nil
    or clean:find("%f[%w]extended%f[%W]") ~= nil
  if not wants_status then return nil end

  local tier = nil
  if type(Diag) == "table" and type(Diag.current_tier) == "function" then
    local ok, value = pcall(Diag.current_tier)
    if ok then tier = value end
  end
  if (tier == nil or tier == "") and type(prefs) == "table" then
    tier = prefs.diag_auto_tier
  end
  tier = tostring(tier or "basic"):lower()
  if tier ~= "basic" and tier ~= "extended" then tier = "off" end

  local label = tier == "extended" and "Extended"
    or tier == "basic" and "Basic"
    or "Off"
  local enabled = tier ~= "off"
  return "Automatic diagnostics: " .. (enabled and "ON" or "OFF")
    .. " (" .. label .. ")"
end

function CTX.tempo(proj)
  -- TimeMap_GetTimeSigAtTime reads the actual tempo map at the edit cursor
  -- position, correctly reflecting any time signature and BPM set via tempo
  -- map points (e.g. 6/8). GetProjectTimeSignature2 only returns the project
  -- default and ignores tempo map entries entirely.
  -- C signature: (proj, time, *timesig_num, *timesig_denom, *tempo)
  -- Lua returns output params in order: num, denom, bpm
  local cursor = reaper.GetCursorPositionEx(proj)
  local num, denom, bpm = reaper.TimeMap_GetTimeSigAtTime(proj, cursor)
  if not bpm or bpm <= 0 then bpm = 120 end  -- defensive fallback
  num   = (type(num)   == "number" and num   > 0) and math_floor(num)   or 4
  denom = (type(denom) == "number" and denom > 0) and math_floor(denom) or 4
  return str_format("Tempo: %.2f BPM | Time Signature: %d/%d", bpm, num, denom)
end

-- Replace pipe characters in track / item names so they don't collide with
-- the pipe-delimited row format the snapshot uses. Pipes are exceedingly
-- rare in real REAPER track names; the substitution keeps the format
-- parseable even when they do appear.
local function _scrub_pipes(s)
  s = tostring(s or "")
  -- gsub allocates a new string regardless of whether it matched; pipes
  -- are exceedingly rare in real REAPER track names, so short-circuit
  -- the common case. Called hundreds of times per snapshot on large
  -- sessions.
  if not s:find("|", 1, true) then return s end
  return (s:gsub("|", "_"))
end

-- Resolve a project pointer for snapshot / context use. S.pending_project
-- is captured at user-send time; long-running scans, popups, or provider
-- round-trips can race with the user closing or swapping the project tab,
-- leaving the cached userdata stale. Walking a snapshot off a stale
-- pointer would emit garbage (or crash on subsequent CTX.* calls). The
-- helper revalidates via ValidatePtr2 before each use; on failure it
-- falls back to the active project so the snapshot is built fresh against
-- the tab the user is now looking at.
local function _resolve_pending_project()
  local p = S.pending_project
  if p and reaper.ValidatePtr2(0, p, "ReaProject*") then
    return p
  end
  if p then
    Log.line("CTX", "pending_project pointer is stale "
      .. "(project tab closed mid-request); falling back to "
      .. "active project")
  end
  return reaper.EnumProjects(-1)
end

-- CTX.tracks(proj, opts)
-- opts.minimal: when true, emit ONLY selected tracks (plus a summary line
-- with the total count). Used by JSFX-intent prompts where the snapshot
-- ships a generic "create me an effect file" request and the per-track
-- listing is dead weight -- the model writes EEL2 against spl0/spl1, not
-- against any specific track. On a 80-track session this drops the tracks
-- block from ~1.1KB to ~80 bytes.
function CTX.tracks(proj, opts)
  local count = R_CountTracks(proj)
  if count == 0 then return "Tracks: none" end
  local minimal = opts and opts.minimal
  local sel_lines = {}
  local lines = {
    str_format("Tracks (N=%d) [idx|name|items|folder_delta]:", count),
  }
  for i = 0, count - 1 do
    -- Long-lived defer scripts can race with project tab close / reload
    -- between R_CountTracks and the following R_GetTrack: the count
    -- snapshot becomes stale and R_GetTrack returns nil for indices the
    -- count thought existed. R_GetTrackName(nil) would then crash.
    local tr = R_GetTrack(proj, i)
    if tr then
      local _, nm      = R_GetTrackName(tr)
      local item_count = R_CountTrackMediaItems(tr)
      local folder_delta =
        math_floor(R_GetMediaTrackInfo_Value(tr, "I_FOLDERDEPTH") or 0)
      if minimal then
        if R_IsTrackSelected(tr) then
          sel_lines[#sel_lines+1] = str_format(
            "%d|%s|%d|%d", i + 1, _scrub_pipes(nm), item_count,
            folder_delta)
        end
      else
        lines[#lines+1] = str_format("%d|%s|%d|%d",
          i + 1, _scrub_pipes(nm), item_count, folder_delta)
      end
    end
  end
  if minimal then
    if #sel_lines == 0 then
      return str_format(
        "Tracks (N=%d): none selected (full list omitted -- JSFX prompt)",
        count)
    end
    local out = {
      str_format(
        "Tracks (N=%d, showing selected only -- JSFX prompt) [idx|name|items|folder_delta]:",
        count),
    }
    for _, ln in ipairs(sel_lines) do out[#out+1] = ln end
    return tbl_concat(out, "\n")
  end
  return tbl_concat(lines, "\n")
end

-- CTX.track_flags(proj) -> string
-- On-demand bucket: returns mute/solo/arm state for all tracks.
function CTX.track_flags(proj)
  local count = R_CountTracks(proj)
  local rows = {}
  for i = 0, count - 1 do
    local tr = R_GetTrack(proj, i)
    if tr then
      local flags = {}
      if R_GetMediaTrackInfo_Value(tr, "B_MUTE")   == 1 then flags[#flags+1] = "muted"  end
      if R_GetMediaTrackInfo_Value(tr, "I_SOLO")   ~= 0 then flags[#flags+1] = "soloed" end
      if R_GetMediaTrackInfo_Value(tr, "I_RECARM") == 1 then flags[#flags+1] = "armed"  end
      if #flags > 0 then
        local _, nm = R_GetTrackName(tr)
        rows[#rows+1] = str_format("%d|%s|%s",
          i + 1, _scrub_pipes(nm), tbl_concat(flags, ","))
      end
    end
  end
  if #rows == 0 then return "Track flags: none (no tracks muted/soloed/armed)" end
  table.insert(rows, 1, "Track flags [idx|name|flags]:")
  return tbl_concat(rows, "\n")
end

function CTX.tracks_matching_flags(proj, opts)
  opts = opts or {}
  local selected_only = opts.selected_only == true
  local wanted_count = (opts.muted and 1 or 0)
    + (opts.soloed and 1 or 0)
    + (opts.armed and 1 or 0)
  if wanted_count == 0 then return CTX.track_flags(proj) end
  local single_label
  if wanted_count == 1 then
    if opts.muted then single_label = opts.invert and "Unmuted tracks" or "Muted tracks"
    elseif opts.soloed then single_label = opts.invert and "Unsoloed tracks" or "Soloed tracks"
    else single_label = opts.invert and "Unarmed tracks" or "Armed tracks" end
    if selected_only then single_label = "Selected " .. single_label:lower() end
  end
  local rows = {}
  local total = 0
  local count = R_CountTracks(proj)
  for i = 0, count - 1 do
    local tr = R_GetTrack(proj, i)
    if tr and (not selected_only or R_IsTrackSelected(tr)) then
      local flags = {}
      local muted_value = R_GetMediaTrackInfo_Value(tr, "B_MUTE")
      local soloed_value = R_GetMediaTrackInfo_Value(tr, "I_SOLO")
      local armed_value = R_GetMediaTrackInfo_Value(tr, "I_RECARM")
      local is_muted = muted_value == true or (tonumber(muted_value) or 0) ~= 0
      local is_soloed = soloed_value == true or (tonumber(soloed_value) or 0) ~= 0
      local is_armed = armed_value == true or (tonumber(armed_value) or 0) ~= 0
      if opts.muted and ((opts.invert and not is_muted)
          or ((not opts.invert) and is_muted)) then
        flags[#flags + 1] = "muted"
      end
      if opts.soloed and ((opts.invert and not is_soloed)
          or ((not opts.invert) and is_soloed)) then
        flags[#flags + 1] = "soloed"
      end
      if opts.armed and ((opts.invert and not is_armed)
          or ((not opts.invert) and is_armed)) then
        flags[#flags + 1] = "armed"
      end
      if #flags > 0 then
        total = total + 1
        if #rows < 40 then
          local _, nm = R_GetTrackName(tr)
          if single_label then
            rows[#rows + 1] = str_format("%d. %s", i + 1,
              nm ~= "" and nm or "(unnamed)")
          else
            rows[#rows + 1] = str_format("%d|%s|%s", i + 1,
              _scrub_pipes(nm), tbl_concat(flags, ","))
          end
        end
      end
    end
  end
  if single_label then
    if total == 0 then return single_label .. ": none" end
    local lines = { str_format("%s: %d", single_label, total) }
    for _, row in ipairs(rows) do lines[#lines + 1] = row end
    if total > #rows then
      lines[#lines + 1] = str_format("(+%d more)", total - #rows)
    end
    return tbl_concat(lines, "\n")
  end
  local label = selected_only and "Selected track flags" or "Track flags"
  if total == 0 then return label .. ": none" end
  table.insert(rows, 1, label .. " [idx|name|flags]:")
  if total > #rows - 1 then
    rows[#rows + 1] = str_format("(+%d more)", total - (#rows - 1))
  end
  return tbl_concat(rows, "\n")
end

function CTX.track_properties(proj, opts)
  local selected_only = opts and opts.selected_only == true
  local source_track = opts and opts.source_track or nil
  local source_name = opts and opts.source_name or nil
  local rows = {}
  local count = R_CountTracks(proj)
  for i = 0, count - 1 do
    local tr = R_GetTrack(proj, i)
    if tr
        and (not selected_only or R_IsTrackSelected(tr))
        and (not source_track or tr == source_track) then
      local _, nm = R_GetTrackName(tr)
      local vol = R_GetMediaTrackInfo_Value(tr, "D_VOL") or 1
      local vol_db = vol > 0 and str_format("%.2f", 20 * math.log(vol, 10))
        or "-inf"
      local pan_pct = str_format("%.0f",
        (R_GetMediaTrackInfo_Value(tr, "D_PAN") or 0) * 100)
      local muted = R_GetMediaTrackInfo_Value(tr, "B_MUTE") == 1
      local soloed = (R_GetMediaTrackInfo_Value(tr, "I_SOLO") or 0) ~= 0
      local armed = R_GetMediaTrackInfo_Value(tr, "I_RECARM") == 1
      local main_send = R_GetMediaTrackInfo_Value(tr, "B_MAINSEND") ~= 0
      rows[#rows+1] = str_format("%d|%s|%s|%s|%s|%s|%s|%s",
        i + 1, _scrub_pipes(nm), vol_db, pan_pct,
        muted and "yes" or "no",
        soloed and "yes" or "no",
        armed and "yes" or "no",
        main_send and "yes" or "no")
    end
  end
  if #rows == 0 then
    if source_track then
      return "Track properties: none on " .. (source_name or "track")
    end
    return selected_only and "Track properties: none on selected tracks"
      or "Track properties: none"
  end
  table.insert(rows, 1,
    "Track properties [idx|name|vol_db|pan_pct|muted|solo|armed|main_send]:")
  return tbl_concat(rows, "\n")
end

function CTX.local_track_label(index, name)
  local nm = tostring(name or "")
  if nm ~= "" then return nm end
  if index then return "Track " .. tostring(index) end
  return "track"
end

function CTX.local_track_property_kind(lt)
  local text = tostring(lt or ""):lower()
  local kinds = {}
  local function add(kind)
    for _, existing in ipairs(kinds) do
      if existing == kind then return end
    end
    kinds[#kinds + 1] = kind
  end
  if text:find("%f[%w]volume%f[%W]")
      or text:find("%f[%w]volumes%f[%W]")
      or text:find("%f[%w]fader%f[%W]")
      or text:find("%f[%w]faders%f[%W]") then
    add("volume")
  end
  if text:find("%f[%w]pan%f[%W]")
      or text:find("%f[%w]pans%f[%W]")
      or text:find("%f[%w]panned%f[%W]") then
    add("pan")
  end
  if text:find("%f[%w]mute%f[%W]")
      or text:find("%f[%w]muted%f[%W]")
      or text:find("%f[%w]unmute%f[%W]")
      or text:find("%f[%w]unmuted%f[%W]") then
    add("mute")
  end
  if text:find("%f[%w]solo%f[%W]")
      or text:find("%f[%w]soloed%f[%W]")
      or text:find("%f[%w]unsolo%f[%W]")
      or text:find("%f[%w]unsoloed%f[%W]") then
    add("solo")
  end
  if text:find("%f[%w]armed%f[%W]")
      or text:find("%f[%w]unarmed%f[%W]")
      or text:find("record arm", 1, true)
      or text:find("record-armed", 1, true) then
    add("armed")
  end
  if text:find("main output", 1, true)
      or text:find("master output", 1, true)
      or text:find("main send", 1, true)
      or text:find("master send", 1, true)
      or text:find("master/parent", 1, true)
      or text:find("parent send", 1, true) then
    add("main_send")
  end
  return #kinds == 1 and kinds[1] or nil
end

function CTX.track_property_answer(source_track, source_index, source_name, kind)
  if not source_track then return nil end
  local label = CTX.local_track_label(source_index, source_name)
  if kind == "volume" then
    local vol = R_GetMediaTrackInfo_Value(source_track, "D_VOL") or 1
    local vol_db = vol > 0 and str_format("%.2f dB",
      20 * math.log(vol, 10)) or "-inf dB"
    return str_format("%s volume is %s.", label, vol_db)
  elseif kind == "pan" then
    local raw_pan_pct = (R_GetMediaTrackInfo_Value(
      source_track, "D_PAN") or 0) * 100
    local pan_pct = raw_pan_pct >= 0
      and math_floor(raw_pan_pct + 0.5)
      or -math_floor(math.abs(raw_pan_pct) + 0.5)
    if pan_pct == 0 then return str_format("%s pan is centered.", label) end
    local side = pan_pct < 0 and "left" or "right"
    return str_format("%s pan is %d%% %s.", label, math.abs(pan_pct), side)
  elseif kind == "mute" then
    local muted = R_GetMediaTrackInfo_Value(source_track, "B_MUTE") == 1
    return str_format("%s is %s.", label, muted and "muted" or "not muted")
  elseif kind == "solo" then
    local soloed = (R_GetMediaTrackInfo_Value(source_track, "I_SOLO") or 0) ~= 0
    return str_format("%s is %s.", label, soloed and "soloed" or "not soloed")
  elseif kind == "armed" then
    local armed = R_GetMediaTrackInfo_Value(source_track, "I_RECARM") == 1
    return str_format("%s is %s.", label,
      armed and "record armed" or "not record armed")
  elseif kind == "main_send" then
    local main_send = R_GetMediaTrackInfo_Value(source_track, "B_MAINSEND") ~= 0
    return main_send
      and str_format("%s sends to the master/parent output.", label)
      or str_format("%s does not send to the master/parent output.", label)
  end
  return nil
end

function CTX.tracks_without_master_output(proj, opts)
  local selected_only = opts and opts.selected_only == true
  local label = selected_only and "Selected tracks without master output"
    or "Tracks without master output"
  local total = 0
  local rows = {}
  local count = R_CountTracks(proj)
  for i = 0, count - 1 do
    local tr = R_GetTrack(proj, i)
    if tr and (not selected_only or R_IsTrackSelected(tr)) then
      if R_GetMediaTrackInfo_Value(tr, "B_MAINSEND") == 0 then
        total = total + 1
        if #rows < 40 then
          local _, nm = R_GetTrackName(tr)
          rows[#rows + 1] = str_format("%d. %s", i + 1,
            nm ~= "" and nm or "(unnamed)")
        end
      end
    end
  end
  if total == 0 then return label .. ": none" end
  local lines = { str_format("%s: %d", label, total) }
  for _, row in ipairs(rows) do lines[#lines + 1] = row end
  if total > #rows then
    lines[#lines + 1] = str_format("(+%d more)", total - #rows)
  end
  return tbl_concat(lines, "\n")
end

function CTX.track_master_output_answer(source_track, source_name)
  if not source_track then return nil end
  local has_master = (R_GetMediaTrackInfo_Value(source_track, "B_MAINSEND") or 0) ~= 0
  if has_master then
    return "Master output: yes, " .. tostring(source_name or "track")
      .. " sends to master"
  end
  return "Master output: no, " .. tostring(source_name or "track")
    .. " does not send to master"
end

function CTX.local_master_output_presence_query(lt)
  local text = tostring(lt or ""):lower()
  text = text:gsub("[%.%?%!]+$", "")
  local track_query =
       text:match("^%s*does%s+(.+)%s+have%s+master%s+output%s*$")
    or text:match("^%s*does%s+(.+)%s+have%s+main%s+output%s*$")
    or text:match("^%s*does%s+(.+)%s+send%s+to%s+master%s*$")
    or text:match("^%s*does%s+(.+)%s+send%s+to%s+the%s+master%s*$")
    or text:match("^%s*is%s+(.+)%s+sent%s+to%s+master%s*$")
    or text:match("^%s*is%s+(.+)%s+sent%s+to%s+the%s+master%s*$")
    or text:match("^%s*is%s+(.+)%s+routed%s+to%s+master%s*$")
    or text:match("^%s*is%s+(.+)%s+routed%s+to%s+the%s+master%s*$")
  if not track_query then return nil end
  track_query = track_query:gsub("^%s+", ""):gsub("%s+$", "")
  if track_query == "" then return nil end
  return track_query
end

-- Cap the per-snapshot FX listing so a 100+ track session doesn't dump
-- 30K+ bytes of FX names every turn. Selected tracks are reported first and
-- always survive the cap; remaining tracks fill up to the limit. The model
-- can request the full listing on demand via <context_needed>fx_chains</...>.
CTX.MAX_FX_REPORT = 30

function CTX.fx(proj, opts)
  local count = R_CountTracks(proj)
  local selected_only = opts and opts.selected_only == true
  local source_track = opts and opts.source_track or nil
  local source_name = opts and opts.source_name or nil
  local sel_with_fx, other_with_fx = {}, {}
  for i = 0, count - 1 do
    local tr = R_GetTrack(proj, i)
    if tr
        and (not selected_only or R_IsTrackSelected(tr))
        and (not source_track or tr == source_track) then
      local fx_count = R_TrackFX_GetCount(tr)
      if fx_count > 0 then
        local _, nm = R_GetTrackName(tr)
        local fx_names = {}
        for f = 0, fx_count - 1 do
          local _, fx_nm = R_TrackFX_GetFXName(tr, f, "")
          -- Include 0-based index so the assistant can pass it directly to TrackFX_* functions.
          fx_names[#fx_names+1] = str_format("[%d]%s", f, _scrub_pipes(fx_nm))
        end
        local entry = str_format("%d|%s|%s",
          i + 1, _scrub_pipes(nm), tbl_concat(fx_names, ","))
        if R_IsTrackSelected(tr) then
          sel_with_fx[#sel_with_fx+1] = entry
        else
          other_with_fx[#other_with_fx+1] = entry
        end
      end
    end
  end
  local total = #sel_with_fx + #other_with_fx
  if total == 0 then
    if source_track then
      return "FX chains: none on " .. (source_name or "track")
    end
    return selected_only and "FX chains: none on selected tracks" or "FX chains: none"
  end
  local lines = { "FX chains [track_idx|track_name|[fx_idx]fx_name,...]:" }
  for _, e in ipairs(sel_with_fx) do lines[#lines+1] = e end
  local remaining = math_max(0, CTX.MAX_FX_REPORT - #sel_with_fx)
  local shown = 0
  for _, e in ipairs(other_with_fx) do
    if shown >= remaining then break end
    lines[#lines+1] = e
    shown = shown + 1
  end
  local omitted = #other_with_fx - shown
  if omitted > 0 then
    lines[#lines+1] = str_format(
      "(+%d more tracks with FX -- request <context_needed>fx_chains</context_needed> for full)",
      omitted)
  end
  return tbl_concat(lines, "\n")
end

function CTX.tracks_without_fx(proj, opts)
  local selected_only = opts and opts.selected_only == true
  local total = 0
  local rows = {}
  local count = R_CountTracks(proj)
  for i = 0, count - 1 do
    local tr = R_GetTrack(proj, i)
    if tr and (not selected_only or R_IsTrackSelected(tr)) then
      local fx_count = R_TrackFX_GetCount(tr) or 0
      if fx_count == 0 then
        total = total + 1
        if #rows < 40 then
          local _, nm = R_GetTrackName(tr)
          rows[#rows + 1] = str_format("%d. %s", i + 1,
            nm ~= "" and nm or "(unnamed)")
        end
      end
    end
  end
  local label = selected_only and "Selected tracks without FX"
    or "Tracks without FX"
  if total == 0 then return label .. ": none" end
  local lines = { str_format("%s: %d", label, total) }
  for _, row in ipairs(rows) do lines[#lines + 1] = row end
  if total > #rows then
    lines[#lines + 1] = str_format("(+%d more)", total - #rows)
  end
  return tbl_concat(lines, "\n")
end

function CTX.local_fx_search_key(s)
  s = tostring(s or ""):lower()
  s = s:gsub("^%w+:%s*", "")
  s = s:gsub("%s*%(.-%)%s*$", "")
  s = s:gsub("[^%a%d]", "")
  return s
end

function CTX.local_fx_search_query(lt)
  local q =
       lt:match("^%s*which%s+tracks%s+have%s+(.+)$")
    or lt:match("^%s*what%s+tracks%s+have%s+(.+)$")
    or lt:match("^%s*list%s+tracks%s+with%s+(.+)$")
    or lt:match("^%s*show%s+tracks%s+with%s+(.+)$")
    or lt:match("^%s*which%s+tracks%s+use%s+(.+)$")
    or lt:match("^%s*what%s+tracks%s+use%s+(.+)$")
    or lt:match("^%s*where%s+is%s+(.+)$")
  if not q then return nil end
  q = q:gsub("[%.%?%!]+$", "")
  q = q:gsub("%s+on%s+them%s*$", "")
  q = q:gsub("%s+inserted%s*$", "")
  q = q:gsub("%s+loaded%s*$", "")
  local original_q = q:gsub("^%s+", ""):gsub("%s+$", "")
  if original_q == "fx" or original_q == "plugin" or original_q == "plugins"
      or original_q == "effect" or original_q == "effects" then
    return "*"
  end
  q = q:gsub("%f[%w]plugins?%f[%W]", " ")
  q = q:gsub("%f[%w]effects?%f[%W]", " ")
  q = q:gsub("%f[%w]fx%f[%W]", " ")
  q = q:gsub("^%s+", ""):gsub("%s+$", "")
  if q == "" then return nil end
  if q == "any" or q == "all" then return "*" end
  return q
end

function CTX.local_fx_search_keys_for_track(query)
  local raw = tostring(query or ""):lower()
  raw = raw:gsub("[%.%?%!]+$", "")
  raw = raw:gsub("^%s+", ""):gsub("%s+$", "")
  raw = raw:gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")
  local seen, keys = {}, {}
  local function add_key(value)
    local key = CTX.local_fx_search_key(value)
    if key ~= "" and not seen[key] then
      keys[#keys + 1] = key
      seen[key] = true
    end
  end
  add_key(query)
  local aliases = {
    comp = { "reacomp", "comp" },
    compression = { "reacomp", "comp" },
    compressor = { "reacomp", "comp" },
    delay = { "readelay", "delay" },
    eq = { "reaeq", "eq" },
    echo = { "readelay", "echo" },
    gate = { "reagate", "gate" },
    limiter = { "realimit", "limit" },
    limit = { "realimit", "limit" },
    reverb = { "reaverbate", "reverb", "verb" },
    verb = { "reaverbate", "verb" },
  }
  for _, value in ipairs(aliases[raw] or {}) do add_key(value) end
  return keys
end

function CTX.local_fx_query_without_track_name(query, track_name)
  local track_tokens = {}
  for word in tostring(track_name or ""):lower():gsub("[^%w]+", " "):gmatch("%w+") do
    track_tokens[word] = true
  end
  local stop = {
    a = true, an = true, any = true, ["do"] = true, does = true, did = true,
    had = true, has = true, have = true, inserted = true, loaded = true,
    on = true, running = true, selected = true, that = true, the = true,
    this = true, track = true, tracks = true, use = true, uses = true,
    using = true, with = true, current = true,
  }
  local out = {}
  for word in tostring(query or ""):lower():gsub("[^%w]+", " "):gmatch("%w+") do
    if not track_tokens[word] and not stop[word] then out[#out + 1] = word end
  end
  local narrowed = tbl_concat(out, " ")
  if narrowed == "" then return nil end
  return narrowed
end

function CTX.fx_on_track_matching(proj, source_track, source_index, source_name, query)
  if not source_track then return nil end
  local keys = CTX.local_fx_search_keys_for_track(query)
  local total, rows = 0, {}
  local fx_count = R_TrackFX_GetCount(source_track) or 0
  for f = 0, fx_count - 1 do
    local _, fx_nm = R_TrackFX_GetFXName(source_track, f, "")
    local fx_key = CTX.local_fx_search_key(fx_nm)
    local matched = false
    for _, q in ipairs(keys) do
      if (#q >= 3 or q == "eq") and fx_key:find(q, 1, true) then
        matched = true
        break
      end
    end
    if matched then
      total = total + 1
      if #rows < CTX.MAX_FX_REPORT then
        rows[#rows + 1] = str_format("%d|%s|%d|%s",
          source_index or 0, _scrub_pipes(source_name or "(unnamed)"),
          f, _scrub_pipes(fx_nm))
      end
    end
  end
  if total == 0 then
    return "FX search: none matching " .. tostring(query or "")
      .. " on " .. tostring(source_name or "track")
  end
  local lines = {
    str_format("FX search: %s on %s (N=%d) [track_idx|track_name|fx_idx|fx_name]:",
      tostring(query or ""), tostring(source_name or "track"), total)
  }
  for _, row in ipairs(rows) do lines[#lines + 1] = row end
  if total > CTX.MAX_FX_REPORT then
    lines[#lines + 1] = str_format("(+%d more)", total - CTX.MAX_FX_REPORT)
  end
  return tbl_concat(lines, "\n")
end

function CTX.fx_on_track_presence(proj, source_track, source_index, source_name, query)
  if not source_track then return nil end
  local keys = CTX.local_fx_search_keys_for_track(query)
  local total, rows = 0, {}
  local fx_count = R_TrackFX_GetCount(source_track) or 0
  for f = 0, fx_count - 1 do
    local _, fx_nm = R_TrackFX_GetFXName(source_track, f, "")
    local fx_key = CTX.local_fx_search_key(fx_nm)
    local matched = false
    for _, q in ipairs(keys) do
      if (#q >= 3 or q == "eq") and fx_key:find(q, 1, true) then
        matched = true
        break
      end
    end
    if matched then
      total = total + 1
      if #rows < CTX.MAX_FX_REPORT then
        rows[#rows + 1] = str_format("%d|%s|%d|%s",
          source_index or 0, _scrub_pipes(source_name or "(unnamed)"),
          f, _scrub_pipes(fx_nm))
      end
    end
  end
  if total == 0 then
    local label = CTX.local_track_label(source_index, source_name)
    local q = tostring(query or ""):lower()
    if q == "" or q == "fx" or q == "plugin" or q == "plugins"
        or q == "effect" or q == "effects" or q == "there fx" then
      return label .. " has no FX."
    end
    return label .. " has no " .. tostring(query or "") .. " FX."
  end
  local lines = {
    str_format("FX presence: yes, %s has %s (N=%d) [track_idx|track_name|fx_idx|fx_name]:",
      tostring(source_name or "track"), tostring(query or ""), total)
  }
  for _, row in ipairs(rows) do lines[#lines + 1] = row end
  if total > CTX.MAX_FX_REPORT then
    lines[#lines + 1] = str_format("(+%d more)", total - CTX.MAX_FX_REPORT)
  end
  return tbl_concat(lines, "\n")
end

function CTX.track_fx_presence_answer(proj, source_track, source_index, source_name)
  if not source_track then return nil end
  local label = CTX.local_track_label(source_index, source_name)
  local fx_count = R_TrackFX_GetCount(source_track) or 0
  if fx_count == 0 then return label .. " has no FX." end
  local names = {}
  for f = 0, fx_count - 1 do
    local _, fx_nm = R_TrackFX_GetFXName(source_track, f, "")
    names[#names + 1] = tostring(fx_nm or "FX")
    if #names >= 3 then break end
  end
  local suffix = fx_count > #names and str_format(", +%d more",
    fx_count - #names) or ""
  return str_format("%s has %d FX: %s%s.", label, fx_count,
    tbl_concat(names, ", "), suffix)
end

function CTX.local_track_target_in_text(facts, query, prefix, force_singular_error)
  local source_track, source_index, source_name, ambiguous, ambiguous_names =
    CTX.local_track_named_in_text(facts, query)
  if ambiguous then
    return nil, nil, nil, CTX.local_track_ambiguity(prefix or "Track target", ambiguous_names)
  end
  if not source_track then
    local text = tostring(query or ""):lower()
    local plural_selected = text:find("%f[%w]selected%s+tracks%f[%W]")
      or text:find("%f[%w]current%s+tracks%f[%W]")
      or text:find("%f[%w]these%s+tracks%f[%W]")
      or text:find("%f[%w]those%s+tracks%f[%W]")
    local singular_selected = not plural_selected
      and (text:find("%f[%w]selected%f[%W]")
        or text:find("%f[%w]current%f[%W]")
        or text:find("%f[%w]this%f[%W]")
        or text:find("%f[%w]that%f[%W]"))
    if singular_selected then
      local singular_text = text:gsub("%f[%w]selected%f[%W]", "selected track")
        :gsub("%f[%w]current%f[%W]", "current track")
        :gsub("%f[%w]this%f[%W]", "this track")
        :gsub("%f[%w]that%f[%W]", "that track")
      local selected_error
      source_track, source_index, source_name, selected_error =
        CTX.local_singular_selected_track_in_text(
          facts, singular_text, prefix or "Track target", true)
      if selected_error and (force_singular_error
          or CTX.local_fx_query_without_track_name(query, "")) then
        return nil, nil, nil, selected_error
      end
    end
  end
  return source_track, source_index, source_name, nil
end

function CTX.local_any_track_target_in_text(facts, query, prefix)
  local source_track, source_index, source_name, missing_index =
    CTX.local_track_index_in_text(facts, query)
  if missing_index then
    return nil, nil, nil, tostring(prefix or "Track target")
      .. ": track " .. tostring(missing_index) .. " not found"
  end
  if source_track then return source_track, source_index, source_name, nil end
  return CTX.local_track_target_in_text(facts, query, prefix, true)
end

function CTX.local_track_fx_query_in_text(facts, query, prefix)
  local source_track, source_index, source_name, target_error =
    CTX.local_track_target_in_text(facts, query, prefix or "FX search")
  if target_error then return nil, nil, nil, nil, target_error end
  if not source_track then return nil end
  local fx_query = CTX.local_fx_query_without_track_name(query, source_name)
  if not fx_query then return nil end
  return source_track, source_index, source_name, fx_query, nil
end

function CTX.local_track_fx_query_from_parts(facts, track_query, fx_query, prefix)
  local source_track, source_index, source_name, target_error =
    CTX.local_track_target_in_text(facts, track_query, prefix or "FX search", true)
  if target_error then return nil, nil, nil, nil, target_error end
  if not source_track then return nil end
  local narrowed_fx_query = CTX.local_fx_query_without_track_name(fx_query, "")
  if not narrowed_fx_query then return nil end
  return source_track, source_index, source_name, narrowed_fx_query, nil
end

function CTX.local_fx_presence_query(lt)
  local text = tostring(lt or ""):lower()
  text = text:gsub("[%.%?%!]+$", "")
  local track_query, fx_query = text:match("^%s*does%s+(.+)%s+have%s+(.+)$")
  if not track_query then
    track_query, fx_query = text:match("^%s*do%s+(.+)%s+have%s+(.+)$")
  end
  if not track_query then
    track_query, fx_query = text:match("^%s*does%s+(.+)%s+use%s+(.+)$")
  end
  if not track_query then
    track_query, fx_query = text:match("^%s*do%s+(.+)%s+use%s+(.+)$")
  end
  if not track_query then
    track_query, fx_query = text:match("^%s*is%s+(.+)%s+using%s+(.+)$")
  end
  if not track_query then
    track_query, fx_query = text:match("^%s*are%s+(.+)%s+using%s+(.+)$")
  end
  if not track_query then
    fx_query, track_query = text:match("^%s*is%s+(.+)%s+on%s+(.+)$")
  end
  if not track_query then
    fx_query, track_query = text:match("^%s*are%s+(.+)%s+on%s+(.+)$")
  end
  if not track_query or not fx_query then return nil end
  track_query = track_query:gsub("^%s+", ""):gsub("%s+$", "")
  fx_query = fx_query:gsub("^%s+", ""):gsub("%s+$", "")
  local fx_clean = CTX.local_fx_query_without_track_name(fx_query, "")
  if not fx_clean then return nil end
  if fx_clean == "fx" or fx_clean == "plugin" or fx_clean == "plugins"
      or fx_clean == "effect" or fx_clean == "effects" then
    return nil
  end
  return track_query, fx_clean
end

function CTX.fx_tracks_with(proj, query)
  local q = CTX.local_fx_search_key(query)
  if q == "" then return nil end
  if #q < 3 and q ~= "eq" then return nil end
  local rows = {}
  local total = 0
  local count = R_CountTracks(proj)
  for i = 0, count - 1 do
    local tr = R_GetTrack(proj, i)
    if tr then
      local fx_count = R_TrackFX_GetCount(tr)
      for f = 0, fx_count - 1 do
        local _, fx_nm = R_TrackFX_GetFXName(tr, f, "")
        local fx_key = CTX.local_fx_search_key(fx_nm)
        if fx_key:find(q, 1, true) then
          total = total + 1
          if #rows < CTX.MAX_FX_REPORT then
            local _, nm = R_GetTrackName(tr)
            rows[#rows + 1] = str_format("%d|%s|%d|%s",
              i + 1, _scrub_pipes(nm), f, _scrub_pipes(fx_nm))
          end
        end
      end
    end
  end
  local master = reaper.GetMasterTrack and reaper.GetMasterTrack(proj)
  if master then
    local fx_count = R_TrackFX_GetCount(master) or 0
    for f = 0, fx_count - 1 do
      local _, fx_nm = R_TrackFX_GetFXName(master, f, "")
      local fx_key = CTX.local_fx_search_key(fx_nm)
      if fx_key:find(q, 1, true) then
        total = total + 1
        if #rows < CTX.MAX_FX_REPORT then
          local _, nm = R_GetTrackName(master)
          if nm == "" or nm:lower() == "master" then nm = "Master" end
          rows[#rows + 1] = str_format("%s|%s|%d|%s",
            "M", _scrub_pipes(nm), f, _scrub_pipes(fx_nm))
        end
      end
    end
  end
  if total == 0 then
    return "FX search: none matching " .. tostring(query or "")
  end
  local lines = {
    str_format("FX search: %s (N=%d) [track_idx|track_name|fx_idx|fx_name]:",
      tostring(query or ""), total)
  }
  for _, row in ipairs(rows) do lines[#lines + 1] = row end
  if total > CTX.MAX_FX_REPORT then
    lines[#lines + 1] = str_format("(+%d more)", total - CTX.MAX_FX_REPORT)
  end
  return tbl_concat(lines, "\n")
end

function CTX.master_fx(proj)
  local master = reaper.GetMasterTrack and reaper.GetMasterTrack(proj)
  if not master then return "FX chains: master track unavailable" end
  local _, nm = R_GetTrackName(master)
  if nm == "" or nm:lower() == "master" then nm = "Master" end
  local fx_count = R_TrackFX_GetCount(master) or 0
  if fx_count == 0 then return "FX chains: none on " .. nm end
  local fx_names = {}
  for f = 0, fx_count - 1 do
    local _, fx_nm = R_TrackFX_GetFXName(master, f, "")
    fx_names[#fx_names + 1] = str_format("[%d]%s", f, _scrub_pipes(fx_nm))
  end
  return "FX chains [track_idx|track_name|[fx_idx]fx_name,...]:\n"
    .. str_format("%s|%s|%s", "M", _scrub_pipes(nm),
      tbl_concat(fx_names, ","))
end

function CTX.master_properties(proj)
  local master = reaper.GetMasterTrack and reaper.GetMasterTrack(proj)
  if not master then return "Master properties: master track unavailable" end
  local _, nm = R_GetTrackName(master)
  if nm == "" or nm:lower() == "master" then nm = "Master" end
  local vol = R_GetMediaTrackInfo_Value(master, "D_VOL") or 1
  local vol_db = vol > 0 and str_format("%.2f", 20 * math.log(vol, 10))
    or "-inf"
  local pan_pct = str_format("%.0f",
    (R_GetMediaTrackInfo_Value(master, "D_PAN") or 0) * 100)
  local muted = R_GetMediaTrackInfo_Value(master, "B_MUTE") == 1
  local soloed = (R_GetMediaTrackInfo_Value(master, "I_SOLO") or 0) ~= 0
  local fx_count = R_TrackFX_GetCount(master) or 0
  return "Master properties [name|vol_db|pan_pct|muted|solo|fx_count]:\n"
    .. str_format("%s|%s|%s|%s|%s|%d", _scrub_pipes(nm), vol_db,
      pan_pct, muted and "yes" or "no", soloed and "yes" or "no",
      fx_count)
end

function CTX.selected(proj)
  local count    = R_CountTracks(proj)
  local selected = {}
  for i = 0, count - 1 do
    local tr = R_GetTrack(proj, i)
    if tr and R_IsTrackSelected(tr) then
      local _, nm = R_GetTrackName(tr)
      selected[#selected+1] = str_format("%q (index %d)", nm, i + 1)
    end
  end
  return #selected > 0
    and ("Selected tracks: " .. tbl_concat(selected, ", "))
    or  "Selected tracks: none"
end

-- Returns a TARGET HINT block for the snapshot when one or more tracks are
-- selected at request time. Lifts snapshot data into instruction-shape so
-- the model writes code targeting the captured track(s) by index/name first
-- and falls back to live GetSelectedTrack() only if the captured target no
-- longer exists. Without this, the model commonly emits pure GetSelectedTrack
-- calls and a script delayed past the user's next click produces "No track
-- selected." Returns "" when no tracks are selected (suppresses the block).
function CTX.target_hint(proj, user_text)
  local count = R_CountTracks(proj)
  local sel = {}
  for i = 0, count - 1 do
    local tr = R_GetTrack(proj, i)
    if tr and R_IsTrackSelected(tr) then
      local _, nm = R_GetTrackName(tr)
      sel[#sel+1] = { idx = i + 1, name = nm }
    end
  end
  if #sel == 0 then return "" end
  -- Suppress on clearly create-new-track prompts. Small models have been
  -- observed obeying the hint over the explicit user request ("Create a
  -- new Twin 3 synth track" emitted code that targeted the existing
  -- selected Vocal track instead). Negative-marker filter is conservative
  -- (only suppresses on unambiguous phrases); requests that operate on
  -- existing tracks still get the hint.
  if user_text and user_text ~= "" then
    local t = user_text:lower()
    if t:find("create%s+a?%s*new%s+track")
       or t:find("create%s+a?%s*new%s+%w+%s+track")
       or t:find("add%s+a?%s*new%s+track")
       or t:find("add%s+a?%s*new%s+%w+%s+track")
       or t:find("insert%s+a?%s*new%s+track")
       or t:find("insert%s+track") then
      return ""
    end
  end
  local lines = { "TARGET HINT:" }
  if #sel == 1 then
    lines[#lines+1] = str_format(
      "Selected track at request time: index %d, name %q.", sel[1].idx, sel[1].name)
  else
    local list = {}
    for _, e in ipairs(sel) do
      list[#list+1] = str_format("index %d, name %q", e.idx, e.name)
    end
    lines[#lines+1] = "Selected tracks at request time: " .. tbl_concat(list, "; ") .. "."
  end
  lines[#lines+1] = "Use this captured target ONLY when: (a) the user "
    .. "request says \"the/this/selected/current\" track, OR (b) the request "
    .. "operates on an existing track AND no prior turn in this conversation "
    .. "already operated on a specific track. A targetless follow-up to a "
    .. "prior turn that targeted Track N continues on Track N -- do NOT "
    .. "switch to this captured target unless the user said "
    .. "\"selected/current/this/the\" track or named a different one. "
    .. "IGNORE this block when the user asks to create, insert, or add a "
    .. "new track -- those should call InsertTrackAtIndex and target the "
    .. "freshly created track, not the captured one. When honoring the "
    .. "hint: validate the target still exists (and preferably still has "
    .. "the same name); fall back to reaper.GetSelectedTrack() only if "
    .. "the captured target is invalid."
  return tbl_concat(lines, "\n")
end

-- Uses GetSet_LoopTimeRange2 (project-aware variant) instead of the non-project
-- GetSet_LoopTimeRange so the correct tab's time selection is always queried.
function CTX.time_selection(proj, opts)
  local ts, te = reaper.GetSet_LoopTimeRange2(proj, false, false, 0, 0, false)
  if te > ts then
    if opts and opts.include_length then
      return str_format("Time selection: %.3fs - %.3fs | length=%.3fs",
        ts, te, te - ts)
    end
    return str_format("Time selection: %.3fs - %.3fs", ts, te)
  end
  return "Time selection: none"
end

-- CTX.cursor(proj) -> string
-- Reports the edit cursor position in seconds. Useful for scripting questions
-- that involve inserting items, markers, or time selections at the cursor.
-- Uses GetCursorPositionEx (project-aware variant) so the correct tab is
-- always queried even if the user has switched projects while waiting.
function CTX.cursor(proj)
  local pos = reaper.GetCursorPositionEx(proj)
  return str_format("Edit cursor: %.3fs", pos)
end

function CTX.project_length(proj)
  local length = reaper.GetProjectLength and tonumber(reaper.GetProjectLength(proj)) or nil
  if not length or length < 0 then
    length = 0
    if reaper.CountMediaItems and reaper.GetMediaItem then
      local n = reaper.CountMediaItems(proj) or 0
      for i = 0, n - 1 do
        local item = reaper.GetMediaItem(proj, i)
        if item then
          local pos = R_GetMediaItemInfo_Value(item, "D_POSITION") or 0
          local len = R_GetMediaItemInfo_Value(item, "D_LENGTH") or 0
          if pos + len > length then length = pos + len end
        end
      end
    end
  end
  return str_format("Project length: %.3fs", length or 0)
end

-- CTX.sample_rate(proj) -> string
-- Reports the project sample rate. Uses GetSetProjectInfo with "PROJECT_SRATE"
-- which is the project-aware API for reading sample rate as a numeric value.
-- Falls back to 44100 if the call returns 0 (e.g. unsaved new project).
function CTX.sample_rate(proj)
  local sr = reaper.GetSetProjectInfo(proj, "PROJECT_SRATE", 0, false)
  if not sr or sr <= 0 then sr = 44100 end
  return str_format("Sample rate: %d Hz", math_floor(sr))
end

-- CTX.play_state(proj) -> string
-- Reports transport state: stopped, playing, recording, or paused.
-- GetPlayStateEx is the project-aware variant; bitmask: bit 0 = playing,
-- bit 1 = paused, bit 2 = recording.
function CTX.play_state(proj)
  local state = reaper.GetPlayStateEx(proj)
  local label
  if     state == 0 then label = "stopped"
  elseif state & 4  ~= 0 then label = "recording"
  elseif state & 2  ~= 0 then label = "paused"
  elseif state & 1  ~= 0 then label = "playing"
  else                        label = "stopped"
  end
  return "Transport: " .. label
end

-- CTX.loop(proj) -> string
-- Reports whether loop is enabled and the loop point range (distinct from the
-- time selection). GetSet_LoopTimeRange2 with is_loop=true returns loop points.
function CTX.loop(proj, opts)
  local ls, le = reaper.GetSet_LoopTimeRange2(proj, false, true, 0, 0, false)
  local enabled = reaper.GetSetRepeatEx(proj, -1) == 1
  if le > ls then
    if opts and opts.include_length then
      return str_format("Loop: %s | %.3fs - %.3fs | length=%.3fs",
        enabled and "enabled" or "disabled", ls, le, le - ls)
    end
    return str_format("Loop: %s | %.3fs - %.3fs",
      enabled and "enabled" or "disabled", ls, le)
  end
  return "Loop: " .. (enabled and "enabled" or "disabled") .. " | no loop points set"
end

function CTX.dynamic_split_settings()
  local resource = reaper.GetResourcePath()
  local ini_path = resource .. RA.SEP .. "reaper.ini"
  local dyn_preset_path = resource .. RA.SEP .. "reaper-dynsplit.ini"
  local function _read_text(path)
    if type(read_file_text) == "function" then return read_file_text(path) end
    local f = io.open(path, "r")
    if not f then return nil end
    local data = f:read("*a")
    f:close()
    return data
  end
  local text = _read_text(ini_path)
  if type(text) ~= "string" or text == "" then
    return "Dynamic Split settings: unavailable"
  end

  local has_dyn = text:find("%[dynamicsplit%]") ~= nil
  local dyn = text:match("%[dynamicsplit%]\r?\n(.-)\r?\n%[")
    or text:match("%[dynamicsplit%]\r?\n(.*)$")
    or ""
  local function kv(src, key)
    return src:match("\n" .. key .. "=([^\r\n]+)")
      or src:match("^" .. key .. "=([^\r\n]+)")
  end
  local function n(src, key)
    return tonumber(kv(src, key) or "")
  end
  local function ms100(v)
    return v and str_format("%.1fms", v / 100) or "?"
  end
  local function db100(v)
    return v and str_format("%.1fdB", v / 100) or "?"
  end
  local function dynsplit_preset_names()
    local preset_text = _read_text(dyn_preset_path)
    if type(preset_text) ~= "string" or preset_text == "" then return "none" end
    local names = {}
    for line in (preset_text .. "\n"):gmatch("([^\r\n]*)\r?\n") do
      local name = line:match("^%s*([^%s]+)%s+")
      if name and name ~= "" then names[#names + 1] = name end
    end
    return #names > 0 and tbl_concat(names, ", ") or "none"
  end

  local sens = n(text, "transientsensitivity")
  local thresh = n(text, "transientthreshold")
  local presets = dynsplit_preset_names()
  if not has_dyn then
    return "Dynamic Split settings [current]: "
      .. "state=not_persisted_likely_defaults"
      .. " | transient_sensitivity="
      .. (sens and str_format("%.1f%%", sens * 100) or "?")
      .. " | transient_threshold="
      .. (thresh and str_format("%.1fdB", thresh) or "?")
      .. " | action_mode=?"
      .. " | min_slice=?"
      .. " | min_silence=?"
      .. " | split_groups=?"
      .. " | saved_presets=" .. presets
  end

  local stretch_mode = n(dyn, "dostretchmarkers")
  local stretch_label = stretch_mode == 3
    and "add stretch markers to selected/grouped"
    or ("raw " .. tostring(stretch_mode or "?"))

  return "Dynamic Split settings [current]: "
    .. "transient_sensitivity="
    .. (sens and str_format("%.1f%%", sens * 100) or "?")
    .. " | transient_threshold="
    .. (thresh and str_format("%.1fdB", thresh) or "?")
    .. " | splitflag=" .. tostring(n(dyn, "splitflag") or "?")
    .. " | action_mode=" .. stretch_label
    .. " | min_slice=" .. ms100(n(dyn, "minslice"))
    .. " | min_silence=" .. ms100(n(dyn, "minsilence"))
    .. " | gate_threshold=" .. db100(n(dyn, "gatethresh"))
    .. " | gate_hysteresis=" .. db100(n(dyn, "gatehyst"))
    .. " | split_groups=" .. tostring(n(dyn, "splitgroups") or "?")
    .. " | snap_offset_window=" .. ms100(n(dyn, "snapoffstime"))
    .. " | saved_presets=" .. presets
end

-- =============================================================================
-- DrumEdit dynamic split profile helper
-- =============================================================================
-- Drum timing edits need deterministic local machinery. The model may choose
-- the workflow, but global Dynamic Split / transient preferences are saved,
-- applied, verified, and restored here rather than in generated ad hoc Lua.
DrumEdit = DrumEdit or {}

DrumEdit.RECOMMENDED_DYNSPLIT_PROFILE = {
  name = "ReaAssist drum guide detection",
  doubles = {
    transientsensitivity = 0.70, -- Transient Detection Settings: Sensitivity
    transientthreshold = -10.0,  -- Transient Detection Settings: Threshold dB
  },
  -- These are the desired Dynamic Split dialog values for the full profile.
  -- The live SWS config API exposes the transient doubles above, but current
  -- REAPER/SWS builds do not expose these Dynamic Split dialog fields as
  -- SNM_*ConfigVar keys. Keep them as an explicit target profile for future
  -- dedicated INI/startup or native-dialog work; do not claim live SWS support.
  dynamic_split = {
    splitflag = 1,        -- split at transients
    minslice = 8900,      -- 89.0 ms
    minsilence = 121000,  -- 1210.0 ms
    postfx = 0,
    minlenLR = 1,
    gatethresh = -2400,
    gatehyst = -600,
    removesilence = 1,
    beatbase = 1,
    snapoffs = 0,
    splitgroups = 1,
    dostretchmarkers = 3, -- add stretch markers to selected/grouped items
    chrommidi = 0,
    padfade = 0,
    snapoffstime = 5000,  -- 50.0 ms, inert while snapoffs=0
    leadpad = 0,
    trailpad = 0,
    lastsplitslider = 100,
    splitcnten = 0,
  },
}

function DrumEdit._config_api(api)
  api = api or reaper
  if type(api) ~= "table" then
    return nil, "REAPER API is unavailable"
  end
  local needed = {
    "SNM_GetDoubleConfigVar",
    "SNM_SetDoubleConfigVar",
  }
  for _, name in ipairs(needed) do
    if type(api[name]) ~= "function" then
      return nil, "SWS config API is unavailable: " .. name
    end
  end
  return api, nil
end

function DrumEdit._sorted_keys(t)
  local keys = {}
  for k in pairs(t or {}) do keys[#keys + 1] = k end
  table.sort(keys)
  return keys
end

function DrumEdit.snapshot_dynamic_split_profile(opts)
  opts = type(opts) == "table" and opts or {}
  local api, err = DrumEdit._config_api(opts.reaper)
  if not api then return nil, err end
  local profile = opts.profile or DrumEdit.RECOMMENDED_DYNSPLIT_PROFILE
  local snap = {
    doubles = {},
    ints = {},
  }
  for _, key in ipairs(DrumEdit._sorted_keys(profile.doubles)) do
    local value = api.SNM_GetDoubleConfigVar(key, -987654321.25)
    if value == -987654321.25 then
      return nil, "Unsupported SWS double config key: " .. key
    end
    snap.doubles[key] = value
  end
  return snap, nil
end

function DrumEdit.apply_dynamic_split_profile(profile, opts)
  opts = type(opts) == "table" and opts or {}
  local api, err = DrumEdit._config_api(opts.reaper)
  if not api then return false, err end
  profile = profile or DrumEdit.RECOMMENDED_DYNSPLIT_PROFILE

  for _, key in ipairs(DrumEdit._sorted_keys(profile.doubles)) do
    api.SNM_SetDoubleConfigVar(key, profile.doubles[key])
  end
  return true, nil
end

function DrumEdit.verify_dynamic_split_profile(profile, opts)
  opts = type(opts) == "table" and opts or {}
  local api, err = DrumEdit._config_api(opts.reaper)
  if not api then return false, err end
  profile = profile or DrumEdit.RECOMMENDED_DYNSPLIT_PROFILE
  local tolerance = tonumber(opts.tolerance) or 0.0001
  local mismatches = {}

  for _, key in ipairs(DrumEdit._sorted_keys(profile.doubles)) do
    local got = api.SNM_GetDoubleConfigVar(key, -999999)
    local want = profile.doubles[key]
    if math.abs((got or 0) - want) > tolerance then
      mismatches[#mismatches + 1] =
        str_format("%s expected %.4f got %.4f", key, want, got or 0)
    end
  end
  if #mismatches > 0 then return false, tbl_concat(mismatches, "; ") end
  return true, nil
end

function DrumEdit.restore_dynamic_split_profile(snapshot, opts)
  opts = type(opts) == "table" and opts or {}
  local api, err = DrumEdit._config_api(opts.reaper)
  if not api then return false, err end
  if type(snapshot) ~= "table" then
    return false, "Missing Dynamic Split settings snapshot"
  end

  for _, key in ipairs(DrumEdit._sorted_keys(snapshot.doubles)) do
    api.SNM_SetDoubleConfigVar(key, snapshot.doubles[key])
  end
  return true, nil
end

-- CTX.markers(proj) -> string
-- Reports all project markers and region start/end points (capped at
-- CTX.MAX_MARKER_REPORT to keep snapshot size bounded on heavily-markered projects).
-- EnumProjectMarkers3 returns (retval, isrgn, pos, rgnend, name, idx).
-- Markers and region boundaries are both reported; regions include an end pos.
CTX.MAX_MARKER_REPORT, CTX.MAX_ITEM_REPORT, CTX.MAX_SEND_REPORT = 20, 5, 40
function CTX.markers(proj)
  local total = R_CountProjectMarkers(proj)
  if total == 0 then return "Markers/regions: none" end

  local lines = {
    str_format("Markers/regions (N=%d) [type|idx|name|pos_s|end_s]:", total)
  }
  local report_n = math_min(total, CTX.MAX_MARKER_REPORT)
  for i = 0, report_n - 1 do
    local _, isrgn, pos, rgnend, name, idx =
      R_EnumProjectMarkers3(proj, i)
    if isrgn then
      lines[#lines+1] = str_format(
        "R|%d|%s|%.3f|%.3f", idx, _scrub_pipes(name), pos, rgnend)
    else
      lines[#lines+1] = str_format(
        "M|%d|%s|%.3f|", idx, _scrub_pipes(name), pos)
    end
  end
  if total > CTX.MAX_MARKER_REPORT then
    lines[#lines+1] = str_format(
      "(+%d more)", total - CTX.MAX_MARKER_REPORT)
  end
  return tbl_concat(lines, "\n")
end

function CTX.local_project_facts(proj)
  proj = proj or reaper.EnumProjects(-1)
  local _, path = reaper.EnumProjects(-1)
  local facts = {
    proj = proj,
    path = path,
    project_name = path and path ~= "" and path:match("[^/\\]+$") or nil,
    track_count = R_CountTracks(proj),
    selected_tracks = {},
  }
  local _, marker_count, region_count = R_CountProjectMarkers(proj)
  facts.marker_count = marker_count or 0
  facts.region_count = region_count or 0
  local selected_count = reaper.CountSelectedTracks(proj)
  for i = 0, selected_count - 1 do
    local tr = reaper.GetSelectedTrack(proj, i)
    if tr then
      local _, name = R_GetTrackName(tr)
      facts.selected_tracks[#facts.selected_tracks + 1] = {
        index = math_floor((R_GetMediaTrackInfo_Value(tr, "IP_TRACKNUMBER") or 0) + 0.5),
        name = name ~= "" and name or "(unnamed)",
      }
    end
  end
  return facts
end

function CTX.local_read_selected_tracks(proj)
  local facts = type(proj) == "table" and proj.selected_tracks and proj
    or CTX.local_project_facts(proj)
  local count = #facts.selected_tracks
  if count == 0 then return "Selected tracks: none" end
  local lines = { str_format("Selected tracks: %d", count) }
  for _, tr in ipairs(facts.selected_tracks) do
    lines[#lines + 1] = str_format("%d. %s", tr.index or 0, tr.name or "(unnamed)")
  end
  return tbl_concat(lines, "\n")
end

function CTX.local_read_selection_summary(proj, facts)
  facts = type(facts) == "table" and facts.selected_tracks and facts
    or CTX.local_project_facts(proj)
  local item_count = R_CountSelectedMediaItems(facts.proj) or 0
  local lines = {
    str_format("Selection: tracks=%d | items=%d",
      #facts.selected_tracks, item_count)
  }
  lines[#lines + 1] = CTX.local_read_selected_tracks(facts)
  lines[#lines + 1] = CTX.selected_items(facts.proj)
  return tbl_concat(lines, "\n")
end

function CTX.local_read_track_list(proj)
  local facts = type(proj) == "table" and proj.track_count and proj
    or CTX.local_project_facts(proj)
  if facts.track_count == 0 then return "Tracks: none" end
  local lines = { str_format("Tracks: %d", facts.track_count) }
  local limit = math_min(facts.track_count, 40)
  for i = 0, limit - 1 do
    local tr = reaper.GetTrack(facts.proj, i)
    if tr then
      local _, name = R_GetTrackName(tr)
      lines[#lines + 1] = str_format("%d. %s", i + 1,
        name ~= "" and name or "(unnamed)")
    end
  end
  if facts.track_count > limit then
    lines[#lines + 1] = str_format("(+%d more)", facts.track_count - limit)
  end
  return tbl_concat(lines, "\n")
end

function CTX.track_folders(proj)
  local count = R_CountTracks(proj)
  if count == 0 then return "Track folders: none" end
  local rows = {}
  local depth = 0
  local has_folder = false
  for i = 0, count - 1 do
    local tr = R_GetTrack(proj, i)
    if tr then
      local _, name = R_GetTrackName(tr)
      local delta = math_floor(R_GetMediaTrackInfo_Value(tr, "I_FOLDERDEPTH") or 0)
      if depth > 0 or delta ~= 0 then has_folder = true end
      rows[#rows + 1] = str_format("%d|%d|%s|%d",
        i + 1, depth, _scrub_pipes(name ~= "" and name or "(unnamed)"), delta)
      depth = math_max(0, depth + delta)
    end
  end
  if not has_folder then return "Track folders: none" end
  table.insert(rows, 1,
    str_format("Track folders (N=%d) [idx|depth|name|folder_delta]:", count))
  return tbl_concat(rows, "\n")
end

function CTX.local_track_named_in_text(facts, lt)
  if type(facts) ~= "table" or not facts.track_count then
    return nil
  end
  local text_key = " " .. tostring(lt or ""):gsub("[^%w]+", " ") .. " "
  local exact_matches = {}
  for i = 0, facts.track_count - 1 do
    local tr = reaper.GetTrack(facts.proj, i)
    if tr then
      local _, name = R_GetTrackName(tr)
      name = tostring(name or "")
      local name_key = name:lower():gsub("[^%w]+", " ")
      name_key = name_key:gsub("^%s+", ""):gsub("%s+$", "")
      if name_key ~= "" and text_key:find(" " .. name_key .. " ", 1, true) then
        exact_matches[#exact_matches + 1] = {
          track = tr,
          index = i + 1,
          name = name ~= "" and name or "(unnamed)",
        }
      end
    end
  end
  if #exact_matches == 1 then
    local m = exact_matches[1]
    return m.track, m.index, m.name, false
  end
  if #exact_matches > 1 then
    local names = {}
    for _, m in ipairs(exact_matches) do names[#names + 1] = m.name end
    return nil, nil, nil, true, names
  end

  local stop = {
    a = true, an = true, ["and"] = true, are = true, armed = true, count = true,
    current = true,
    effect = true, effects = true, fader = true, faders = true, from = true,
    how = true, ["is"] = true, item = true, items = true, list = true,
    main = true, many = true, master = true, media = true, mute = true,
    muted = true, of = true, on = true, output = true, pan = true,
    pans = true, plugin = true, plugins = true, project = true,
    properties = true, property = true, record = true, send = true,
    sends = true, session = true, show = true, solo = true, soloed = true,
    selected = true, that = true, the = true, this = true, to = true, track = true,
    tracks = true, volume = true, volumes = true, what = true,
    whats = true, which = true,
  }
  local query = {}
  for word in tostring(lt or ""):lower():gmatch("%w+") do
    if #word >= 3 and not stop[word] then query[word] = true end
  end

  local best_score, matches = 0, {}
  for i = 0, facts.track_count - 1 do
    local tr = reaper.GetTrack(facts.proj, i)
    if tr then
      local _, name = R_GetTrackName(tr)
      name = tostring(name or "")
      local score = 0
      for token in name:lower():gsub("[^%w]+", " "):gmatch("%w+") do
        if query[token] then score = score + 1 end
      end
      if score > best_score then
        best_score = score
        matches = {
          {
            track = tr,
            index = i + 1,
            name = name ~= "" and name or "(unnamed)",
          },
        }
      elseif score > 0 and score == best_score then
        matches[#matches + 1] = {
          track = tr,
          index = i + 1,
          name = name ~= "" and name or "(unnamed)",
        }
      end
    end
  end
  if best_score <= 0 or #matches == 0 then return nil, nil, nil, false end
  if #matches == 1 then
    local m = matches[1]
    return m.track, m.index, m.name, false
  end
  local names = {}
  for _, m in ipairs(matches) do names[#names + 1] = m.name end
  return nil, nil, nil, true, names
end

function CTX.local_track_ambiguity(prefix, names)
  if type(names) ~= "table" or #names == 0 then
    return tostring(prefix or "Track target") .. ": track name is ambiguous"
  end
  local lines = { tostring(prefix or "Track target") .. ": track name is ambiguous" }
  for i, name in ipairs(names) do
    lines[#lines + 1] = str_format("%d. %s", i, tostring(name or "(unnamed)"))
  end
  return tbl_concat(lines, "\n")
end

function CTX.local_track_index_in_text(facts, lt)
  if type(facts) ~= "table" or not facts.track_count then
    return nil
  end
  local text = tostring(lt or ""):lower()
  local raw = text:match("%f[%w]track%s+index%s*#?%s*(%d+)%f[%W]")
    or text:match("%f[%w]track%s*#%s*(%d+)%f[%W]")
    or text:match("%f[%w]track%s+(%d+)%f[%W]")
  local idx = tonumber(raw)
  if not idx or idx % 1 ~= 0 or idx < 1 then return nil end
  local tr = reaper.GetTrack(facts.proj, idx - 1)
  if not tr then return nil, nil, nil, idx end
  local _, name = R_GetTrackName(tr)
  return tr, idx, name ~= "" and name or "(unnamed)", nil
end

function CTX.local_selected_track_index_in_text(facts, lt)
  if type(facts) ~= "table" or not facts.track_count then
    return nil
  end
  local text = tostring(lt or ""):lower()
  local idx = tonumber(
    text:match("%f[%d](%d+)%s*%a*%s+selected%s+track%f[%W]")
      or text:match("%f[%w]selected%s+track%s*#?%s*(%d+)%f[%W]")
      or text:match("%f[%w]selected%s+index%s*#?%s*(%d+)%f[%W]"))
  if not idx then
    local ordinals = {
      first = 1, second = 2, third = 3, fourth = 4, fifth = 5,
      sixth = 6, seventh = 7, eighth = 8, ninth = 9, tenth = 10,
    }
    for word, n in pairs(ordinals) do
      if text:find("%f[%a]" .. word .. "%s+selected%s+track%f[%W]") then
        idx = n
        break
      end
    end
  end
  if not idx or idx % 1 ~= 0 or idx < 1 then return nil end
  local tr = reaper.GetSelectedTrack(facts.proj, idx - 1)
  if not tr then return nil, nil, nil, idx end
  local project_idx =
    math_floor((R_GetMediaTrackInfo_Value(tr, "IP_TRACKNUMBER") or 0) + 0.5)
  local _, name = R_GetTrackName(tr)
  return tr, project_idx, name ~= "" and name or "(unnamed)", nil
end

function CTX.local_singular_selected_track_in_text(facts, lt, prefix, include_selected)
  if type(facts) ~= "table" or not facts.track_count then
    return nil
  end
  local text = tostring(lt or ""):lower()
  if text:find("%f[%w]selected%s+tracks%f[%W]")
      or text:find("%f[%w]current%s+tracks%f[%W]")
      or text:find("%f[%w]these%s+tracks%f[%W]")
      or text:find("%f[%w]those%s+tracks%f[%W]") then
    return nil
  end
  include_selected = include_selected ~= false
  local refers_to_singular =
       (include_selected and text:find("%f[%w]selected%s+track%f[%W]") ~= nil)
    or text:find("%f[%w]current%s+track%f[%W]") ~= nil
    or text:find("%f[%w]this%s+track%f[%W]") ~= nil
    or text:find("%f[%w]that%s+track%f[%W]") ~= nil
  if not refers_to_singular then return nil end
  if #facts.selected_tracks == 1 then
    local tr = reaper.GetSelectedTrack(facts.proj, 0)
    if tr then
      local project_idx =
        math_floor((R_GetMediaTrackInfo_Value(tr, "IP_TRACKNUMBER") or 0) + 0.5)
      local _, name = R_GetTrackName(tr)
      return tr, project_idx, name ~= "" and name or "(unnamed)", nil
    end
    return nil, nil, nil, tostring(prefix or "Track target")
      .. ": selected track not found"
  end
  if #facts.selected_tracks > 1 then
    local lines = {
      tostring(prefix or "Track target") .. ": selected track is ambiguous",
    }
    for i, tr in ipairs(facts.selected_tracks) do
      lines[#lines + 1] = str_format("%d. %s", i, tr.name or "(unnamed)")
    end
    return nil, nil, nil, tbl_concat(lines, "\n")
  end
  return nil, nil, nil, tostring(prefix or "Track target")
    .. ": selected track not found"
end

function CTX.local_route_endpoint_in_text(facts, text)
  if type(facts) ~= "table" or not facts.track_count then return nil end
  local lt = tostring(text or ""):lower()
  local selected_track, selected_index, selected_name, missing_selected =
    CTX.local_selected_track_index_in_text(facts, lt)
  if missing_selected then
    return nil, nil, nil, "Route: selected track "
      .. tostring(missing_selected) .. " not found"
  end
  if selected_track then return selected_track, selected_index, selected_name end

  selected_track, selected_index, selected_name, missing_selected =
    CTX.local_singular_selected_track_in_text(facts, lt, "Route")
  if missing_selected then return nil, nil, nil, missing_selected end
  if selected_track then return selected_track, selected_index, selected_name end

  local track, index, name, missing_index = CTX.local_track_index_in_text(facts, lt)
  if missing_index then
    return nil, nil, nil, "Route: track " .. tostring(missing_index) .. " not found"
  end
  if track then return track, index, name end

  local ambiguous, ambiguous_names = false, nil
  track, index, name, ambiguous, ambiguous_names =
    CTX.local_track_named_in_text(facts, lt)
  if ambiguous then
    return nil, nil, nil, CTX.local_track_ambiguity("Route", ambiguous_names)
  end
  return track, index, name
end

function CTX.local_route_fragment_for_match(text)
  local s = tostring(text or "")
  s = s:gsub("^%s+", ""):gsub("%s+$", "")
  s = s:gsub("[%.%?%!]+$", "")
  -- Multi-part readbacks often say "what send level goes to X, and what track
  -- is selected?". Keep only the route endpoint before the next question.
  s = s:gsub("%s*,%s*and%s+what.+$", "")
  s = s:gsub("%s+and%s+what.+$", "")
  s = s:gsub("%s*,%s*what.+$", "")
  s = s:gsub("%s*,%s*whether.+$", "")
  s = s:gsub("%s+whether.+$", "")
  s = s:gsub("%s*,%s*which.+$", "")
  s = s:gsub("^the%s+", "")
  return s:gsub("^%s+", ""):gsub("%s+$", "")
end

function CTX.local_read_project_summary(proj)
  local facts = type(proj) == "table" and proj.track_count and proj
    or CTX.local_project_facts(proj)
  local lines = {
    facts.project_name and ("Project: " .. facts.project_name) or "Project: unsaved",
    CTX.tempo(facts.proj),
    str_format("Tracks: %d", facts.track_count),
    str_format("Selected tracks: %d", #facts.selected_tracks),
    str_format("Markers: %d | Regions: %d", facts.marker_count, facts.region_count),
  }
  return tbl_concat(lines, "\n")
end

function CTX.local_installed_plugin_answer(user_text)
  local raw = tostring(user_text or "")
  local lt = raw:lower()
  local mentions_installed = lt:find("installed", 1, true) ~= nil
  local have_plugin_query = lt:find("%f[%w]have%f[%W]") ~= nil
    and (lt:find("plugin", 1, true) ~= nil
      or lt:find("%f[%w]fx%f[%W]") ~= nil
      or lt:find("effect", 1, true) ~= nil)
  local available_plugin_query = lt:find("%f[%w]available%f[%W]") ~= nil
    and (lt:find("plugin", 1, true) ~= nil
      or lt:find("%f[%w]fx%f[%W]") ~= nil
      or lt:find("effect", 1, true) ~= nil)
  if not mentions_installed and not have_plugin_query and not available_plugin_query then
    return nil
  end
  local term =
    raw:match("^[Dd]o%s+I%s+have%s+(.+)%s+installed%??%s*$")
    or raw:match("^[Dd]o%s+I%s+have%s+(.+)%??%s*$")
    or raw:match("^[Ii]s%s+the%s+(.+)%s+plugin%s+installed%??%s*$")
    or raw:match("^[Ii]s%s+(.+)%s+installed%??%s*$")
    or raw:match("^[Ii]s%s+(.+)%s+available%??%s*$")
  term = tostring(term or ""):gsub("^%s+", ""):gsub("%s+$", "")
  term = term:gsub("%?+$", ""):gsub("%s+$", "")
  term = term:gsub("^the%s+", ""):gsub("%s+plugin$", "")
  local term_l = term:lower()
  if term == ""
     or term_l == "plugin"
     or term_l == "plugins"
     or term_l == "fx"
     or term_l == "effects"
     or term_l == "any plugins"
     or term_l == "any effects" then
    return nil
  end
  local term_compact = term_l:gsub("[_%-%s]+", "")
  if term_compact == "reaimgui"
      or term_compact == "jsreascriptapi"
      or term_l == "sws"
      or term_l == "sws extension" then
    return nil
  end
  if type(CTX.populate_installed_fx) ~= "function"
     or not CTX.populate_installed_fx() then
    return "Installed plugin search: unavailable in this REAPER version."
  end
  local matches = {}
  for _, name in ipairs(CTX._installed_fx_list or {}) do
    if CTX.fx_name_matches(name, { term }) then matches[#matches + 1] = name end
  end
  if #matches == 0 then
    return 'Installed plugin search: no matches for "' .. term .. '".'
  end
  local lines = {
    #matches == 1
      and ('Installed plugin: yes, "' .. matches[1] .. '" is available.')
      or ('Installed plugin: found ' .. tostring(#matches)
          .. ' matches for "' .. term .. '":')
  }
  if #matches > 1 then
    for i = 1, math_min(#matches, 8) do
      lines[#lines + 1] = "- " .. matches[i]
    end
    if #matches > 8 then
      lines[#lines + 1] = "... " .. tostring(#matches - 8) .. " more"
    end
  end
  return tbl_concat(lines, "\n")
end

function CTX.local_read_answer(user_text, proj)
  local raw = tostring(user_text or "")
  local lt = raw:lower()
  lt = lt:gsub("^%s*no%s+code%s+this%s+time:%s*", "")
  if lt:match("^%s*$") or #raw > 240 then return nil end
  if lt:find("\n", 1, true) then return nil end
  if lt:find("^%s*how%s+do%s+i")
      or lt:find("^%s*how%s+can%s+i")
      or lt:find("^%s*show%s+me%s+how")
      or lt:find("^%s*show%s+how")
      or lt:find("^%s*can%s+you%s+explain")
      or lt:find("^%s*explain%s+") then
    return nil
  end
  if lt:find("%f[%w]command%f[%W]") then
    return nil
  end
  if lt:find("%f[%w]should%f[%W]")
      or lt:find("shouldn't", 1, true)
      or lt:find("shouldnt", 1, true)
      or lt:find("shouldn\226\128\153t", 1, true)
      or lt:find("%f[%w]recommend%w*%f[%W]")
      or lt:find("%f[%w]best%f[%W]") then
    return nil
  end
  if (lt:find("plugins", 1, true) and lt:find("installed", 1, true))
      or (lt:find("effects", 1, true) and lt:find("installed", 1, true))
      or lt:find("installed fx", 1, true)
      or lt:find("fx installed", 1, true)
      or lt:find("plugin inventory", 1, true)
      or lt:find("fx inventory", 1, true) then
    return "Installed plugin inventory: full installed-plugin lists are not "
      .. "available from the current session. Ask me to check a specific "
      .. "plugin name."
  end
  local installed_plugin_answer = CTX.local_installed_plugin_answer(raw)
  if installed_plugin_answer then return installed_plugin_answer end
  local read_start =
       lt:find("^%s*what") ~= nil
    or lt:find("^%s*what's") ~= nil
    or lt:find("^%s*whats") ~= nil
    or lt:find("^%s*which") ~= nil
    or lt:find("^%s*do%s+") ~= nil
    or lt:find("^%s*does%s+") ~= nil
    or lt:find("^%s*is%s+") ~= nil
    or lt:find("^%s*are%s+") ~= nil
    or lt:find("^%s*how%s+many") ~= nil
    or lt:find("^%s*how%s+long") ~= nil
    or lt:find("^%s*tell%s+me%s+") ~= nil
    or lt:find("^%s*list") ~= nil
    or lt:find("^%s*show") ~= nil
    or lt:find("^%s*where%s+is%s+") ~= nil
    or lt:find("^%s*summarize") ~= nil
    or lt:find("^%s*summary") ~= nil
    or lt:find("^%s*project%s+summary") ~= nil
    or lt:find("^%s*session%s+summary") ~= nil
  if not read_start then return nil end
  local incoming_send_read =
    (lt:find("^%s*what") ~= nil
      or lt:find("^%s*which") ~= nil
      or lt:find("^%s*list") ~= nil
      or lt:find("^%s*show") ~= nil
      or lt:find("^%s*tell%s+me%s+") ~= nil
      or lt:find("^%s*are%s+") ~= nil)
    and (lt:find("tracks send to", 1, true) ~= nil
      or lt:find("tracks send into", 1, true) ~= nil
      or lt:find("tracks route to", 1, true) ~= nil
      or lt:find("tracks route into", 1, true) ~= nil
      or lt:find("tracks routed to", 1, true) ~= nil
      or lt:find("tracks routed into", 1, true) ~= nil
      or lt:find("tracks are routed to", 1, true) ~= nil
      or lt:find("tracks are routed into", 1, true) ~= nil
      or lt:find("tracks sending to", 1, true) ~= nil
      or lt:find("tracks sending into", 1, true) ~= nil
      or lt:find("tracks are sending to", 1, true) ~= nil
      or lt:find("tracks are sending into", 1, true) ~= nil
      or lt:find("tracks feed", 1, true) ~= nil
      or lt:find("tracks feeding", 1, true) ~= nil)
  local receive_from_read =
    (lt:find("^%s*what") ~= nil
      or lt:find("^%s*which") ~= nil
      or lt:find("^%s*list") ~= nil
      or lt:find("^%s*show") ~= nil)
    and (lt:find("tracks receive from", 1, true) ~= nil
      or lt:find("tracks receiving from", 1, true) ~= nil
      or lt:find("tracks are receiving from", 1, true) ~= nil)
  local send_level_read =
    read_start
    and (lt:find("send level", 1, true) ~= nil
      or lt:find("send volume", 1, true) ~= nil
      or lt:find("send gain", 1, true) ~= nil
      or lt:find("level of the send", 1, true) ~= nil
      or lt:find("volume of the send", 1, true) ~= nil
      or lt:find("gain of the send", 1, true) ~= nil)
  local route_yesno_read =
    (lt:find("^%s*does%s+") ~= nil
      or lt:find("^%s*is%s+") ~= nil)
    and (lt:find("%f[%w]send%s+to%f[%W]") ~= nil
      or lt:find("%f[%w]send%s+into%f[%W]") ~= nil
      or lt:find("%f[%w]sending%s+to%f[%W]") ~= nil
      or lt:find("%f[%w]sending%s+into%f[%W]") ~= nil
      or lt:find("%f[%w]routed%s+to%f[%W]") ~= nil
      or lt:find("%f[%w]routed%s+into%f[%W]") ~= nil
      or lt:find("%f[%w]receive%s+from%f[%W]") ~= nil
      or lt:find("%f[%w]receiving%s+from%f[%W]") ~= nil)
  local mutating =
       lt:find("%f[%w]create%f[%W]") ~= nil
    or lt:find("%f[%w]add%f[%W]") ~= nil
    or lt:find("%f[%w]insert%f[%W]") ~= nil
    or lt:find("%f[%w]delete%f[%W]") ~= nil
    or lt:find("%f[%w]remove%f[%W]") ~= nil
    or (lt:find("%f[%w]route%f[%W]") ~= nil
      and not incoming_send_read and not route_yesno_read)
    or (lt:find("%f[%w]routed%f[%W]") ~= nil
      and not incoming_send_read and not route_yesno_read)
    or (lt:find("%f[%w]routing%f[%W]") ~= nil
      and not incoming_send_read and not route_yesno_read)
    or (lt:find("%f[%w]send%f[%W]") ~= nil
      and not incoming_send_read and not send_level_read and not route_yesno_read)
    or (lt:find("%f[%w]sending%f[%W]") ~= nil
      and not incoming_send_read and not route_yesno_read)
    or lt:find("%f[%w]set%f[%W]") ~= nil
    or lt:find("%f[%w]change%f[%W]") ~= nil
    or lt:find("%f[%w]move%f[%W]") ~= nil
  if mutating then return nil end

  proj = proj or reaper.EnumProjects(-1)
  local facts = CTX.local_project_facts(proj)
  local selected_track_phrase = lt:find("selected track", 1, true) ~= nil
    or lt:find("selected tracks", 1, true) ~= nil
  if lt:find("what is selected", 1, true)
      or lt:find("what's selected", 1, true)
      or lt:find("whats selected", 1, true)
      or lt:find("current selection", 1, true)
      or lt:find("selection status", 1, true)
      or lt:find("^%s*is%s+anything%s+selected") then
    return CTX.local_read_selection_summary(proj, facts)
  end
  if lt:find("project summary", 1, true)
      or lt:find("session summary", 1, true)
      or lt:find("project status", 1, true)
      or lt:find("session status", 1, true)
      or lt:find("^%s*summarize")
      or lt:find("^%s*summary") then
    return CTX.local_read_project_summary(facts)
  end
  if lt:find("project name", 1, true)
      or lt:find("project file", 1, true)
      or lt:find("session name", 1, true)
      or lt:find("what project", 1, true)
      or lt:find("which project", 1, true) then
    return facts.project_name and ("Project: " .. facts.project_name)
      or "Project: unsaved"
  end
  if lt:find("reaassist version", 1, true)
      or lt:find("version of reaassist", 1, true) then
    return CTX.reaassist_version()
  end
  if lt:find("reaper version", 1, true)
      or lt:find("version of reaper", 1, true) then
    return CTX.reaper_version()
  end
  local extension_answer = CTX.extension_status(raw)
  if extension_answer then return extension_answer end
  local ai_status = CTX.ai_selection_status(raw)
  if ai_status then return ai_status end
  local settings_status = CTX.reaassist_settings_status(raw)
  if settings_status then return settings_status end
  local diagnostics_status = CTX.diagnostics_status(raw)
  if diagnostics_status then return diagnostics_status end
  if lt:find("%f[%w]tempo%f[%W]")
      or lt:find("%f[%w]bpm%f[%W]")
      or lt:find("song speed", 1, true)
      or lt:find("time signature", 1, true) then
    return CTX.tempo(proj)
  end
  if lt:find("time selection", 1, true) then
    return CTX.time_selection(proj, {
      include_length = lt:find("^%s*how%s+long", 1, false) ~= nil
        or lt:find("%f[%w]duration%f[%W]") ~= nil
        or lt:find("%f[%w]length%f[%W]") ~= nil,
    })
  end
  if lt:find("project length", 1, true)
      or lt:find("project duration", 1, true)
      or lt:find("session length", 1, true)
      or lt:find("session duration", 1, true)
      or lt:find("^%s*how%s+long%s+is%s+this%s+project")
      or lt:find("^%s*how%s+long%s+is%s+the%s+project")
      or lt:find("^%s*how%s+long%s+is%s+this%s+session")
      or lt:find("^%s*how%s+long%s+is%s+the%s+session")
      or lt:find("^%s*how%s+long%s+is%s+this%s+song")
      or lt:find("^%s*how%s+long%s+is%s+the%s+song") then
    return CTX.project_length(proj)
  end
  if lt:find("edit cursor", 1, true)
      or lt:find("cursor position", 1, true)
      or lt:find("play cursor", 1, true)
      or lt:find("playhead", 1, true)
      or lt:find("play head", 1, true) then
    return CTX.cursor(proj)
  end
  if lt:find("sample rate", 1, true) then
    return CTX.sample_rate(proj)
  end
  if lt:find("transport", 1, true)
      or lt:find("play state", 1, true)
      or lt:find("playback state", 1, true) then
    return CTX.play_state(proj)
  end
  if lt:find("loop points", 1, true)
      or lt:find("loop range", 1, true)
      or lt:find("loop status", 1, true)
      or lt:find("loop length", 1, true)
      or lt:find("loop duration", 1, true)
      or lt:find("length of the loop", 1, true)
      or lt:find("duration of the loop", 1, true)
      or lt:find("^%s*how%s+long%s+is%s+the%s+loop") then
    return CTX.loop(proj, {
      include_length = lt:find("^%s*how%s+long", 1, false) ~= nil
        or lt:find("%f[%w]duration%f[%W]") ~= nil
        or lt:find("%f[%w]length%f[%W]") ~= nil,
    })
  end
  if lt:find("dynamic split", 1, true)
      or lt:find("dynamic splitting", 1, true) then
    return CTX.dynamic_split_settings()
  end
  local master_context = lt:find("%f[%w]master%f[%W]") ~= nil
    and lt:find("master output", 1, true) == nil
    and lt:find("master send", 1, true) == nil
    and lt:find("master/parent", 1, true) == nil
  if master_context
      and (lt:find("%f[%w]fx%f[%W]") ~= nil
      or lt:find("%f[%w]plugin%f[%W]") ~= nil
      or lt:find("%f[%w]plugins%f[%W]") ~= nil
      or lt:find("%f[%w]effect%f[%W]") ~= nil
      or lt:find("%f[%w]effects%f[%W]") ~= nil
      or lt:find("on the master", 1, true) ~= nil) then
    return CTX.master_fx(proj)
  end
  if master_context
      and (lt:find("%f[%w]volume%f[%W]") ~= nil
      or lt:find("%f[%w]fader%f[%W]") ~= nil
      or lt:find("%f[%w]pan%f[%W]") ~= nil
      or lt:find("%f[%w]mute%f[%W]") ~= nil
      or lt:find("%f[%w]muted%f[%W]") ~= nil
      or lt:find("%f[%w]solo%f[%W]") ~= nil
      or lt:find("%f[%w]soloed%f[%W]") ~= nil
      or lt:find("%f[%w]properties%f[%W]") ~= nil
      or lt:find("%f[%w]status%f[%W]") ~= nil) then
    return CTX.master_properties(proj)
  end
  local master_output_query = CTX.local_master_output_presence_query(lt)
  if master_output_query then
    local source_track, _, source_name, target_error =
      CTX.local_track_target_in_text(
        facts, master_output_query, "Master output", true)
    if target_error then return target_error end
    if source_track then
      return CTX.track_master_output_answer(source_track, source_name)
    end
  end
  local send_presence_text = lt:gsub("[%.%?%!]+$", "")
  local send_presence_target =
       send_presence_text:match("^%s*does%s+(.+)%s+have%s+any%s+sends%s*$")
    or send_presence_text:match("^%s*does%s+(.+)%s+have%s+sends%s*$")
    or send_presence_text:match("^%s*do%s+(.+)%s+have%s+any%s+sends%s*$")
    or send_presence_text:match("^%s*do%s+(.+)%s+have%s+sends%s*$")
    or send_presence_text:match("^%s*is%s+(.+)%s+sending%s+to%s+any%s+other%s+tracks%s*$")
    or send_presence_text:match("^%s*is%s+(.+)%s+sending%s+to%s+any%s+other%s+track%s*$")
    or send_presence_text:match("^%s*does%s+(.+)%s+send%s+to%s+any%s+other%s+tracks%s*$")
    or send_presence_text:match("^%s*does%s+(.+)%s+send%s+to%s+any%s+other%s+track%s*$")
  if send_presence_target then
    local source_track, source_index, source_name, target_error =
      CTX.local_any_track_target_in_text(facts, send_presence_target, "Sends")
    if target_error then return target_error end
    if source_track then
      return CTX.track_send_presence_answer(
        proj, source_track, source_index, source_name)
    end
  end
  if route_yesno_read then
    local source_fragment, dest_fragment =
      lt:match("^%s*does%s+(.+)%s+send%s+to%s+(.+)%??%s*$")
    if not source_fragment then
      source_fragment, dest_fragment =
        lt:match("^%s*does%s+(.+)%s+send%s+into%s+(.+)%??%s*$")
    end
    if not source_fragment then
      source_fragment, dest_fragment =
        lt:match("^%s*is%s+(.+)%s+sending%s+to%s+(.+)%??%s*$")
    end
    if not source_fragment then
      source_fragment, dest_fragment =
        lt:match("^%s*is%s+(.+)%s+sending%s+into%s+(.+)%??%s*$")
    end
    if not source_fragment then
      source_fragment, dest_fragment =
        lt:match("^%s*is%s+(.+)%s+routed%s+to%s+(.+)%??%s*$")
    end
    if not source_fragment then
      source_fragment, dest_fragment =
        lt:match("^%s*is%s+(.+)%s+routed%s+into%s+(.+)%??%s*$")
    end
    if not source_fragment then
      dest_fragment, source_fragment =
        lt:match("^%s*does%s+(.+)%s+receive%s+from%s+(.+)%??%s*$")
    end
    if not source_fragment then
      dest_fragment, source_fragment =
        lt:match("^%s*is%s+(.+)%s+receiving%s+from%s+(.+)%??%s*$")
    end
    if not source_fragment or not dest_fragment then return nil end
    local source_track, source_index, source_name
    local route_error
    source_track, source_index, source_name, route_error =
      CTX.local_route_endpoint_in_text(facts, source_fragment)
    if route_error then return route_error end
    local dest_track, dest_index, dest_name
    dest_track, dest_index, dest_name, route_error =
      CTX.local_route_endpoint_in_text(facts, dest_fragment)
    if route_error then return route_error end
    if not source_track or not dest_track then return nil end
    return CTX.send_route_answer(proj, source_track, source_name,
      dest_track, dest_name)
  end
  if lt:find("tracks have no sends", 1, true)
      or lt:find("tracks with no sends", 1, true)
      or lt:find("tracks without sends", 1, true)
      or lt:find("tracks dont have sends", 1, true)
      or lt:find("tracks don't have sends", 1, true) then
    return CTX.tracks_without_sends(proj, {
      selected_only = selected_track_phrase,
    })
  end
  if lt:find("%f[%w]sends%f[%W]")
      or incoming_send_read or receive_from_read or send_level_read then
    local dest_fragment =
         lt:match("%f[%w]go%s+to%s+(.+)$")
      or lt:match("%f[%w]goes%s+to%s+(.+)$")
      or lt:match("%f[%w]going%s+to%s+(.+)$")
      or lt:match("%f[%w]send%s+to%s+(.+)$")
      or lt:match("%f[%w]send%s+into%s+(.+)$")
      or lt:match("%f[%w]route%s+to%s+(.+)$")
      or lt:match("%f[%w]routed%s+to%s+(.+)$")
      or lt:match("%f[%w]route%s+into%s+(.+)$")
      or lt:match("%f[%w]feed%s+into%s+(.+)$")
      or lt:match("%f[%w]feeding%s+into%s+(.+)$")
      or lt:match("%f[%w]feed%s+(.+)$")
      or lt:match("%f[%w]feeding%s+(.+)$")
      or lt:match("%f[%w]to%s+(.+)$")
      or lt:match("%f[%w]into%s+(.+)$")
    local source_fragment = lt:match("%f[%w]from%s+(.+)%s+to%s+")
      or lt:match("%f[%w]from%s+(.+)%s+into%s+")
      or lt:match("%f[%w]from%s+(.+)$")
    dest_fragment = CTX.local_route_fragment_for_match(dest_fragment)
    source_fragment = CTX.local_route_fragment_for_match(source_fragment)
    if dest_fragment == "" then dest_fragment = nil end
    if source_fragment == "" then source_fragment = nil end
    local dest_track, dest_index, dest_name
    if dest_fragment then
      local ambiguous, ambiguous_names = false, nil
      dest_track, dest_index, dest_name, ambiguous, ambiguous_names =
        CTX.local_track_named_in_text(facts, dest_fragment)
      if ambiguous then return CTX.local_track_ambiguity("Sends", ambiguous_names) end
      if not dest_track then
        local target_error
        dest_track, dest_index, dest_name, target_error =
          CTX.local_singular_selected_track_in_text(
            facts, dest_fragment, "Sends", false)
        if target_error then return target_error end
      end
    end
    local explicit_source_track, explicit_source_index, explicit_source_name
    if source_fragment then
      local ambiguous, ambiguous_names = false, nil
      explicit_source_track, explicit_source_index, explicit_source_name,
        ambiguous, ambiguous_names =
        CTX.local_track_named_in_text(facts, source_fragment)
      if ambiguous then return CTX.local_track_ambiguity("Sends", ambiguous_names) end
      if not explicit_source_track then
        local target_error
        explicit_source_track, explicit_source_index, explicit_source_name,
          target_error =
          CTX.local_singular_selected_track_in_text(
            facts, source_fragment, "Sends", false)
        if target_error then return target_error end
      end
    end
    local selected_track, selected_index, selected_name, missing_selected =
      CTX.local_selected_track_index_in_text(facts, lt)
    if missing_selected then
      return "Sends: selected track " .. tostring(missing_selected) .. " not found"
    end
    if not selected_track and not dest_track and not explicit_source_track then
      selected_track, selected_index, selected_name, missing_selected =
        CTX.local_singular_selected_track_in_text(
          facts, lt, "Sends", false)
      if missing_selected then return missing_selected end
    end
    local send_opts = {
      dest_track = dest_track,
      dest_index = dest_index,
      dest_name = dest_name,
      selected_only = not selected_track
        and not explicit_source_track
        and (lt:find("selected track", 1, true) ~= nil
          or lt:find("selected tracks", 1, true) ~= nil),
    }
    if explicit_source_track then
      send_opts.source_track = explicit_source_track
      send_opts.source_index = explicit_source_index
      send_opts.source_name = explicit_source_name
    elseif selected_track then
      send_opts.source_track = selected_track
      send_opts.source_index = selected_index
      send_opts.source_name = selected_name
    elseif not send_opts.selected_only and not dest_track then
      local source_track, source_index, source_name, missing_index =
        CTX.local_track_index_in_text(facts, lt)
      if missing_index then
        return "Sends: track " .. tostring(missing_index) .. " not found"
      end
      local ambiguous, ambiguous_names = false, nil
      if not source_track then
        source_track, source_index, source_name, ambiguous, ambiguous_names =
          CTX.local_track_named_in_text(facts, lt)
      end
      if ambiguous then return CTX.local_track_ambiguity("Sends", ambiguous_names) end
      if source_track then
        send_opts.source_track = source_track
        send_opts.source_index = source_index
        send_opts.source_name = source_name
      end
    end
    local answer = CTX.sends(proj, send_opts)
    local dest_pat = tostring(dest_name or ""):lower():gsub("([^%w])", "%%%1")
    local whether_source = dest_track and (
         lt:match("%f[%w]whether%s+(.+)%s+feeds%s+it")
      or lt:match("%f[%w]whether%s+(.+)%s+feeds%s+" .. dest_pat)
      or lt:match("%f[%w]whether%s+(.+)%s+sends%s+to%s+it")
      or lt:match("%f[%w]whether%s+(.+)%s+sends%s+to%s+" .. dest_pat))
    whether_source = CTX.local_route_fragment_for_match(whether_source)
    if whether_source and whether_source ~= "" then
      local src_track, _, src_name
      local route_error
      src_track, _, src_name, route_error =
        CTX.local_route_endpoint_in_text(facts, whether_source)
      if route_error then return route_error end
      if src_track then
        answer = answer .. "\n" .. CTX.send_route_answer(proj, src_track,
          src_name, dest_track, dest_name)
      end
    end
    if lt:find("what track is selected", 1, true)
        or lt:find("what tracks are selected", 1, true)
        or lt:find("which track is selected", 1, true)
        or lt:find("which tracks are selected", 1, true)
        or lt:find("track is selected", 1, true)
        or lt:find("tracks are selected", 1, true) then
      answer = answer .. "\n" .. CTX.local_read_selected_tracks(facts)
    end
    return answer
  end
  if lt:find("tracks have items", 1, true)
      or lt:find("any tracks have items", 1, true)
      or lt:find("any track has items", 1, true)
      or lt:find("tracks have media", 1, true)
      or lt:find("any tracks have media", 1, true)
      or lt:find("any track has media", 1, true)
      or lt:find("tracks with items", 1, true)
      or lt:find("tracks with media", 1, true)
      or lt:find("tracks contain items", 1, true)
      or lt:find("tracks contain media", 1, true) then
    return CTX.tracks_with_items(proj, {
      selected_only = selected_track_phrase,
    })
  end
  if lt:find("selected item", 1, true)
      or lt:find("selected items", 1, true)
      or lt:find("item is selected", 1, true)
      or lt:find("items are selected", 1, true) then
    return CTX.selected_items(proj)
  end
  if lt:find("item count", 1, true)
      or lt:find("number of items", 1, true)
      or lt:find("how many items", 1, true)
      or lt:find("media items", 1, true)
      or lt:find("%f[%w]items%f[%W]") then
    local selected_track, selected_index, selected_name, missing_selected =
      CTX.local_selected_track_index_in_text(facts, lt)
    if missing_selected then
      return "Items: selected track " .. tostring(missing_selected) .. " not found"
    end
    if not selected_track then
      selected_track, selected_index, selected_name, missing_selected =
        CTX.local_singular_selected_track_in_text(
          facts, lt, "Items", false)
      if missing_selected then return missing_selected end
    end
    local item_opts = {
      count_only = lt:find("item count", 1, true) ~= nil
        or lt:find("number of items", 1, true) ~= nil
        or lt:find("how many items", 1, true) ~= nil,
      selected_only = not selected_track
        and (lt:find("selected track", 1, true) ~= nil
          or lt:find("selected tracks", 1, true) ~= nil),
    }
    if selected_track then
      item_opts.source_track = selected_track
      item_opts.source_index = selected_index
      item_opts.source_name = selected_name
    elseif not item_opts.selected_only then
      local source_track, source_index, source_name, missing_index =
        CTX.local_track_index_in_text(facts, lt)
      if missing_index then
        return "Items: track " .. tostring(missing_index) .. " not found"
      end
      local ambiguous, ambiguous_names = false, nil
      if not source_track then
        source_track, source_index, source_name, ambiguous, ambiguous_names =
          CTX.local_track_named_in_text(facts, lt)
      end
      if ambiguous then return CTX.local_track_ambiguity("Items", ambiguous_names) end
      if source_track then
        item_opts.source_track = source_track
        item_opts.source_index = source_index
        item_opts.source_name = source_name
      end
    end
    return CTX.media_items(proj, item_opts)
  end
  local wants_muted_flag =
       lt:find("%f[%w]muted%f[%W]") ~= nil
    or lt:find("%f[%w]mute%f[%W]") ~= nil
    or lt:find("%f[%w]unmuted%f[%W]") ~= nil
  local wants_soloed_flag =
       lt:find("%f[%w]soloed%f[%W]") ~= nil
    or lt:find("%f[%w]solo%f[%W]") ~= nil
    or lt:find("%f[%w]unsoloed%f[%W]") ~= nil
  local wants_armed_flag =
       lt:find("%f[%w]armed%f[%W]") ~= nil
    or lt:find("record armed", 1, true) ~= nil
    or lt:find("record-armed", 1, true) ~= nil
    or lt:find("%f[%w]unarmed%f[%W]") ~= nil
  if (wants_muted_flag or wants_soloed_flag or wants_armed_flag)
      and lt:find("%f[%w]tracks%f[%W]") ~= nil then
    local flag_count = (wants_muted_flag and 1 or 0)
      + (wants_soloed_flag and 1 or 0)
      + (wants_armed_flag and 1 or 0)
    local inverse_flag =
         lt:find("not muted", 1, true) ~= nil
      or lt:find("not mute", 1, true) ~= nil
      or lt:find("%f[%w]unmuted%f[%W]") ~= nil
      or lt:find("not soloed", 1, true) ~= nil
      or lt:find("not solo", 1, true) ~= nil
      or lt:find("%f[%w]unsoloed%f[%W]") ~= nil
      or lt:find("not armed", 1, true) ~= nil
      or lt:find("not record armed", 1, true) ~= nil
      or lt:find("not record-armed", 1, true) ~= nil
      or lt:find("%f[%w]unarmed%f[%W]") ~= nil
    if inverse_flag and flag_count ~= 1 then return nil end
    return CTX.tracks_matching_flags(proj, {
      selected_only = selected_track_phrase,
      muted = wants_muted_flag,
      soloed = wants_soloed_flag,
      armed = wants_armed_flag,
      invert = inverse_flag,
    })
  end
  if not selected_track_phrase
      and (lt:find("track flags", 1, true)
      or lt:find("muted tracks", 1, true)
      or lt:find("tracks are muted", 1, true)
      or lt:find("tracks muted", 1, true)
      or lt:find("soloed tracks", 1, true)
      or lt:find("tracks are soloed", 1, true)
      or lt:find("tracks soloed", 1, true)
      or lt:find("armed tracks", 1, true)
      or lt:find("tracks are armed", 1, true)
      or lt:find("tracks armed", 1, true)
      or lt:find("record armed tracks", 1, true)) then
    return CTX.track_flags(proj)
  end
  if lt:find("empty tracks", 1, true)
      or lt:find("tracks are empty", 1, true)
      or lt:find("tracks empty", 1, true)
      or lt:find("tracks have no items", 1, true)
      or lt:find("any tracks have no items", 1, true)
      or lt:find("any track has no items", 1, true)
      or lt:find("tracks with no items", 1, true)
      or lt:find("tracks without items", 1, true) then
    return CTX.empty_tracks(proj, {
      selected_only = selected_track_phrase,
    })
  end
  if lt:find("tracks have no master output", 1, true)
      or lt:find("tracks with no master output", 1, true)
      or lt:find("tracks without master output", 1, true)
      or lt:find("tracks have no main output", 1, true)
      or lt:find("tracks with no main output", 1, true)
      or lt:find("tracks without main output", 1, true)
      or lt:find("tracks are not sent to master", 1, true)
      or lt:find("tracks not sent to master", 1, true)
      or lt:find("tracks are not sending to master", 1, true)
      or lt:find("tracks not sending to master", 1, true)
      or lt:find("tracks are not routed to master", 1, true)
      or lt:find("tracks not routed to master", 1, true) then
    return CTX.tracks_without_master_output(proj, {
      selected_only = selected_track_phrase,
    })
  end
  local track_property_word =
       lt:find("%f[%w]volume%f[%W]") ~= nil
    or lt:find("%f[%w]volumes%f[%W]") ~= nil
    or lt:find("%f[%w]fader%f[%W]") ~= nil
    or lt:find("%f[%w]faders%f[%W]") ~= nil
    or lt:find("%f[%w]pan%f[%W]") ~= nil
    or lt:find("%f[%w]pans%f[%W]") ~= nil
    or lt:find("%f[%w]mute%f[%W]") ~= nil
    or lt:find("%f[%w]muted%f[%W]") ~= nil
    or lt:find("%f[%w]solo%f[%W]") ~= nil
    or lt:find("%f[%w]soloed%f[%W]") ~= nil
    or lt:find("%f[%w]armed%f[%W]") ~= nil
    or lt:find("record arm", 1, true) ~= nil
    or lt:find("main output", 1, true) ~= nil
    or lt:find("master output", 1, true) ~= nil
    or lt:find("track properties", 1, true) ~= nil
    or lt:find("track property", 1, true) ~= nil
  local wants_track_property_list =
       lt:find("track properties", 1, true) ~= nil
    or lt:find("track property", 1, true) ~= nil
    or lt:find("track volume", 1, true) ~= nil
    or lt:find("track volumes", 1, true) ~= nil
    or lt:find("track fader", 1, true) ~= nil
    or lt:find("track faders", 1, true) ~= nil
    or lt:find("track pan", 1, true) ~= nil
    or lt:find("track pans", 1, true) ~= nil
  if track_property_word then
    local selected_track, selected_index, selected_name, missing_selected =
      CTX.local_selected_track_index_in_text(facts, lt)
    if missing_selected then
      return "Track properties: selected track "
        .. tostring(missing_selected) .. " not found"
    end
    if not selected_track then
      selected_track, selected_index, selected_name, missing_selected =
        CTX.local_singular_selected_track_in_text(
          facts, lt, "Track properties", false)
      if missing_selected then return missing_selected end
    end
    local prop_opts = {
      selected_only = not selected_track
        and (lt:find("selected track", 1, true) ~= nil
          or lt:find("selected tracks", 1, true) ~= nil),
    }
    if selected_track then
      prop_opts.source_track = selected_track
      prop_opts.source_index = selected_index
      prop_opts.source_name = selected_name
    elseif not prop_opts.selected_only then
      local source_track, source_index, source_name, missing_index =
        CTX.local_track_index_in_text(facts, lt)
      if missing_index then
        return "Track properties: track " .. tostring(missing_index) .. " not found"
      end
      local ambiguous, ambiguous_names = false, nil
      if not source_track then
        source_track, source_index, source_name, ambiguous, ambiguous_names =
          CTX.local_track_named_in_text(facts, lt)
      end
      if ambiguous then
        return CTX.local_track_ambiguity("Track properties", ambiguous_names)
      end
      if source_track then
        prop_opts.source_track = source_track
        prop_opts.source_index = source_index
        prop_opts.source_name = source_name
      end
    end
    if not wants_track_property_list
        and not prop_opts.selected_only
        and not prop_opts.source_track then
      return nil
    end
    local property_kind = CTX.local_track_property_kind(lt)
    if property_kind
        and prop_opts.source_track
        and not wants_track_property_list then
      return CTX.track_property_answer(prop_opts.source_track,
        prop_opts.source_index, prop_opts.source_name, property_kind)
    end
    return CTX.track_properties(proj, prop_opts)
  end
  if lt:find("tracks have no fx", 1, true)
      or lt:find("tracks with no fx", 1, true)
      or lt:find("tracks without fx", 1, true)
      or lt:find("tracks have no plugins", 1, true)
      or lt:find("tracks with no plugins", 1, true)
      or lt:find("tracks without plugins", 1, true)
      or lt:find("tracks have no effects", 1, true)
      or lt:find("tracks with no effects", 1, true)
      or lt:find("tracks without effects", 1, true)
      or lt:find("tracks dont have fx", 1, true)
      or lt:find("tracks don't have fx", 1, true) then
    return CTX.tracks_without_fx(proj, {
      selected_only = selected_track_phrase,
    })
  end
  local fx_presence_text = lt:gsub("[%.%?%!]+$", "")
  local generic_fx_presence_target =
       fx_presence_text:match("^%s*are%s+there%s+any%s+fx%s+on%s+(.+)$")
    or fx_presence_text:match("^%s*is%s+there%s+any%s+fx%s+on%s+(.+)$")
    or fx_presence_text:match("^%s*are%s+there%s+any%s+plugins%s+on%s+(.+)$")
    or fx_presence_text:match("^%s*are%s+there%s+any%s+effects%s+on%s+(.+)$")
    or fx_presence_text:match("^%s*does%s+(.+)%s+have%s+any%s+fx%s*$")
    or fx_presence_text:match("^%s*does%s+(.+)%s+have%s+fx%s*$")
    or fx_presence_text:match("^%s*does%s+(.+)%s+have%s+any%s+plugins%s*$")
    or fx_presence_text:match("^%s*does%s+(.+)%s+have%s+plugins%s*$")
    or fx_presence_text:match("^%s*does%s+(.+)%s+have%s+any%s+effects%s*$")
    or fx_presence_text:match("^%s*does%s+(.+)%s+have%s+effects%s*$")
  if generic_fx_presence_target then
    local source_track, source_index, source_name, target_error =
      CTX.local_any_track_target_in_text(
        facts, generic_fx_presence_target, "FX presence")
    if target_error then return target_error end
    if source_track then
      return CTX.track_fx_presence_answer(
        proj, source_track, source_index, source_name)
    end
  end
  local fx_presence_track, fx_presence_query = CTX.local_fx_presence_query(lt)
  if fx_presence_track then
    local source_track, source_index, source_name, narrowed_fx_query, fx_error =
      CTX.local_track_fx_query_from_parts(
        facts, fx_presence_track, fx_presence_query, "FX presence")
    if fx_error then return fx_error end
    if source_track and narrowed_fx_query then
      return CTX.fx_on_track_presence(
        proj, source_track, source_index, source_name, narrowed_fx_query)
    end
  end
  if lt:find("fx chains", 1, true)
      or lt:find("track fx", 1, true)
      or lt:find("have fx", 1, true)
      or lt:find("has fx", 1, true)
      or lt:find("have plugin", 1, true)
      or lt:find("has plugin", 1, true)
      or lt:find("have effect", 1, true)
      or lt:find("has effect", 1, true)
      or lt:find("fx are on", 1, true)
      or lt:find("fx on ", 1, true)
      or lt:find("plugins are on", 1, true)
      or lt:find("plugins on ", 1, true)
      or lt:find("effects are on", 1, true)
      or lt:find("effects on ", 1, true) then
    local selected_track, selected_index, selected_name, missing_selected =
      CTX.local_selected_track_index_in_text(facts, lt)
    if missing_selected then
      return "FX chains: selected track " .. tostring(missing_selected) .. " not found"
    end
    if not selected_track then
      selected_track, selected_index, selected_name, missing_selected =
        CTX.local_singular_selected_track_in_text(
          facts, lt, "FX chains", false)
      if missing_selected then return missing_selected end
    end
    local fx_opts = {
      selected_only = not selected_track
        and (lt:find("selected track", 1, true) ~= nil
          or lt:find("selected tracks", 1, true) ~= nil),
    }
    if selected_track then
      fx_opts.source_track = selected_track
      fx_opts.source_index = selected_index
      fx_opts.source_name = selected_name
    elseif not fx_opts.selected_only then
      local source_track, source_index, source_name, missing_index =
        CTX.local_track_index_in_text(facts, lt)
      if missing_index then
        return "FX chains: track " .. tostring(missing_index) .. " not found"
      end
      local ambiguous, ambiguous_names = false, nil
      if not source_track then
        source_track, source_index, source_name, ambiguous, ambiguous_names =
          CTX.local_track_named_in_text(facts, lt)
      end
      if ambiguous then return CTX.local_track_ambiguity("FX chains", ambiguous_names) end
      if source_track then
        fx_opts.source_track = source_track
        fx_opts.source_index = source_index
        fx_opts.source_name = source_name
      end
    end
    return CTX.fx(proj, fx_opts)
  end
  local fx_query = CTX.local_fx_search_query(lt)
  if fx_query then
    if fx_query ~= "*" then
      local source_track, source_index, source_name, narrowed_fx_query, fx_error =
        CTX.local_track_fx_query_in_text(facts, fx_query)
      if fx_error then return fx_error end
      if source_track and narrowed_fx_query then
        return CTX.fx_on_track_matching(
          proj, source_track, source_index, source_name, narrowed_fx_query)
      end
    end
    return fx_query == "*" and CTX.fx(proj, {}) or CTX.fx_tracks_with(proj, fx_query)
  end
  if lt:find("selected track", 1, true)
      or lt:find("selected tracks", 1, true)
      or lt:find("track is selected", 1, true)
      or lt:find("tracks are selected", 1, true) then
    return CTX.local_read_selected_tracks(facts)
  end
  if lt:find("marker count", 1, true)
      or lt:find("region count", 1, true)
      or lt:find("how many markers", 1, true)
      or lt:find("how many regions", 1, true) then
    return str_format("Markers: %d | Regions: %d",
      facts.marker_count, facts.region_count)
  end
  if lt:find("track count", 1, true)
      or lt:find("number of tracks", 1, true)
      or lt:find("how many tracks", 1, true) then
    return str_format("Track count: %d", facts.track_count)
  end
  if lt:find("folder structure", 1, true)
      or lt:find("track folder", 1, true)
      or lt:find("track folders", 1, true)
      or lt:find("folder tracks", 1, true)
      or lt:find("folders in this project", 1, true)
      or lt:find("folders in the project", 1, true) then
    return CTX.track_folders(proj)
  end
  if lt:find("track names", 1, true)
      or lt:find("list tracks", 1, true)
      or lt:find("show tracks", 1, true)
      or lt:find("show all tracks", 1, true)
      or lt:find("what tracks", 1, true)
      or lt:find("which tracks", 1, true) then
    return CTX.local_read_track_list(facts)
  end
  if lt:find("%f[%w]markers%f[%W]")
      or lt:find("%f[%w]marker%f[%W]")
      or lt:find("%f[%w]regions%f[%W]")
      or lt:find("%f[%w]region%f[%W]") then
    return CTX.markers(proj)
  end
  return nil
end

-- CTX.selected_items(proj) -> string
-- Reports the count and key properties (track, position, length) of selected
-- media items. Capped at CTX.MAX_ITEM_REPORT items to keep snapshot size bounded
-- for projects with large block-selections. Items beyond the cap are noted
-- with a summary count so the assistant knows additional items exist.
--
-- Item indices in output are 1-based (matching REAPER's UI display) even
-- though CountSelectedMediaItems / GetSelectedMediaItem are 0-based.
function CTX.selected_items(proj)
  local count = R_CountSelectedMediaItems(proj)
  if count == 0 then return "Selected items: none" end

  local lines = {
    str_format("Selected items (N=%d) [item_idx|track_idx|track_name|pos_s|len_s]:", count)
  }
  local report_n = math_min(count, CTX.MAX_ITEM_REPORT)
  for i = 0, report_n - 1 do
    local item  = R_GetSelectedMediaItem(proj, i)
    local pos   = R_GetMediaItemInfo_Value(item, "D_POSITION")
    local len   = R_GetMediaItemInfo_Value(item, "D_LENGTH")
    -- GetMediaItem_Track returns the track that owns this item. We resolve its
    -- display name and 1-based index for a human-readable description.
    local track = R_GetMediaItem_Track(item)
    local track_idx = -1
    local track_nm  = "unknown"
    if track then
      -- MediaTrackInfo "IP_TRACKNUMBER" returns the 1-based track number.
      track_idx = math_floor(R_GetMediaTrackInfo_Value(track, "IP_TRACKNUMBER"))
      local _, nm = R_GetTrackName(track)
      track_nm = nm
    end
    lines[#lines+1] = str_format(
      "%d|%d|%s|%.3f|%.3f",
      i + 1, track_idx, _scrub_pipes(track_nm), pos, len)
  end
  if count > CTX.MAX_ITEM_REPORT then
    lines[#lines+1] = str_format(
      "(+%d more)", count - CTX.MAX_ITEM_REPORT)
  end
  return tbl_concat(lines, "\n")
end

function CTX.media_items(proj, opts)
  local selected_only = opts and opts.selected_only == true
  local source_track = opts and opts.source_track or nil
  local source_name = opts and opts.source_name or nil
  local count_only = opts and opts.count_only == true
  local total = 0
  local items = {}
  if source_track then
    total = R_CountTrackMediaItems(source_track)
    local report_n = math_min(total, CTX.MAX_ITEM_REPORT)
    for i = 0, report_n - 1 do
      local item = reaper.GetTrackMediaItem(source_track, i)
      if item then items[#items+1] = item end
    end
  else
    local project_total = reaper.CountMediaItems
      and (reaper.CountMediaItems(proj) or 0)
      or 0
    for i = 0, project_total - 1 do
      local item = reaper.GetMediaItem and reaper.GetMediaItem(proj, i) or nil
      local tr = item and R_GetMediaItem_Track(item) or nil
      if item and (not selected_only or (tr and R_IsTrackSelected(tr))) then
        total = total + 1
        if #items < CTX.MAX_ITEM_REPORT then items[#items+1] = item end
      end
    end
  end
  if count_only then
    if source_track then
      return str_format("Items on %s: %d", source_name or "track", total)
    end
    return selected_only and str_format("Items on selected tracks: %d", total)
      or str_format("Items: %d", total)
  end
  if total == 0 then
    if source_track then
      return "Items: none on " .. (source_name or "track")
    end
    return selected_only and "Items: none on selected tracks" or "Items: none"
  end
  local lines = {
    str_format("Items (N=%d) [item_idx|track_idx|track_name|pos_s|len_s]:", total)
  }
  for i, item in ipairs(items) do
    local pos = R_GetMediaItemInfo_Value(item, "D_POSITION") or 0
    local len = R_GetMediaItemInfo_Value(item, "D_LENGTH") or 0
    local track = R_GetMediaItem_Track(item)
    local track_idx = -1
    local track_nm = "unknown"
    if track then
      track_idx = math_floor(R_GetMediaTrackInfo_Value(track, "IP_TRACKNUMBER") or -1)
      local _, nm = R_GetTrackName(track)
      track_nm = nm
    end
    lines[#lines+1] = str_format("%d|%d|%s|%.3f|%.3f",
      i, track_idx, _scrub_pipes(track_nm), pos, len)
  end
  if total > CTX.MAX_ITEM_REPORT then
    lines[#lines+1] = str_format("(+%d more)", total - CTX.MAX_ITEM_REPORT)
  end
  return tbl_concat(lines, "\n")
end

function CTX.empty_tracks(proj, opts)
  local selected_only = opts and opts.selected_only == true
  local total = 0
  local rows = {}
  local track_count = R_CountTracks(proj)
  for i = 0, track_count - 1 do
    local tr = R_GetTrack(proj, i)
    if tr
        and (not selected_only or R_IsTrackSelected(tr))
        and R_CountTrackMediaItems(tr) == 0 then
      total = total + 1
      if #rows < 40 then
        local _, nm = R_GetTrackName(tr)
        rows[#rows + 1] = str_format("%d. %s", i + 1,
          nm ~= "" and nm or "(unnamed)")
      end
    end
  end
  local label = selected_only and "Empty selected tracks" or "Empty tracks"
  if total == 0 then return label .. ": none" end
  local lines = { str_format("%s: %d", label, total) }
  for _, row in ipairs(rows) do lines[#lines + 1] = row end
  if total > #rows then
    lines[#lines + 1] = str_format("(+%d more)", total - #rows)
  end
  return tbl_concat(lines, "\n")
end

function CTX.tracks_with_items(proj, opts)
  local selected_only = opts and opts.selected_only == true
  local total = 0
  local rows = {}
  local track_count = R_CountTracks(proj)
  for i = 0, track_count - 1 do
    local tr = R_GetTrack(proj, i)
    if tr and (not selected_only or R_IsTrackSelected(tr)) then
      local item_count = R_CountTrackMediaItems(tr) or 0
      if item_count > 0 then
        total = total + 1
        if #rows < 40 then
          local _, nm = R_GetTrackName(tr)
          rows[#rows + 1] = str_format("%d. %s | items=%d", i + 1,
            nm ~= "" and nm or "(unnamed)", item_count)
        end
      end
    end
  end
  local label = selected_only and "Selected tracks with items"
    or "Tracks with items"
  if total == 0 then return label .. ": none" end
  local lines = { str_format("%s: %d", label, total) }
  for _, row in ipairs(rows) do lines[#lines + 1] = row end
  if total > #rows then
    lines[#lines + 1] = str_format("(+%d more)", total - #rows)
  end
  return tbl_concat(lines, "\n")
end

function CTX.sends(proj, opts)
  if not reaper.GetTrackNumSends or not reaper.GetTrackSendInfo_Value then
    return "Sends: unavailable"
  end
  local selected_only = opts and opts.selected_only == true
  local source_track = opts and opts.source_track or nil
  local source_name = opts and opts.source_name or nil
  local dest_track = opts and opts.dest_track or nil
  local dest_name = opts and opts.dest_name or nil
  local total = 0
  local rows = {}
  local track_count = R_CountTracks(proj)
  for i = 0, track_count - 1 do
    local src = R_GetTrack(proj, i)
    if src
        and (not selected_only or R_IsTrackSelected(src))
        and (not source_track or src == source_track) then
      local _, src_name = R_GetTrackName(src)
      local send_count = reaper.GetTrackNumSends(src, 0) or 0
      for si = 0, send_count - 1 do
        local dest = reaper.GetTrackSendInfo_Value(src, 0, si, "P_DESTTRACK")
        if not dest_track or dest == dest_track then
          total = total + 1
          if #rows < CTX.MAX_SEND_REPORT then
            local dest_idx = -1
            local row_dest_name = "unknown"
            if dest then
              dest_idx = math_floor(R_GetMediaTrackInfo_Value(dest, "IP_TRACKNUMBER") or -1)
              local _, nm = R_GetTrackName(dest)
              row_dest_name = nm
            end
            local vol = reaper.GetTrackSendInfo_Value(src, 0, si, "D_VOL") or 1
            local vol_db = vol > 0 and (20 * math.log(vol, 10)) or -150
            local pan = reaper.GetTrackSendInfo_Value(src, 0, si, "D_PAN") or 0
            local mode = math_floor(reaper.GetTrackSendInfo_Value(src, 0, si, "I_SENDMODE") or 0)
            rows[#rows + 1] = str_format("%d|%s|%d|%d|%s|%.2f|%.2f|%d",
              i + 1, _scrub_pipes(src_name), si + 1, dest_idx,
              _scrub_pipes(row_dest_name), vol_db, pan, mode)
          end
        end
      end
    end
  end
  if total == 0 then
    if source_track and dest_track then
      return "Sends: none from " .. (source_name or "track")
        .. " to " .. (dest_name or "track")
    end
    if dest_track then
      return "Sends: none to " .. (dest_name or "track")
    end
    if source_track then
      return "Sends: none on " .. (source_name or "track")
    end
    return selected_only and "Sends: none on selected tracks" or "Sends: none"
  end
  local lines = {
    str_format("Sends (N=%d) [src_idx|src_name|send_idx|dest_idx|dest_name|vol_db|pan|mode]:", total)
  }
  for _, row in ipairs(rows) do lines[#lines + 1] = row end
  if total > CTX.MAX_SEND_REPORT then
    lines[#lines + 1] = str_format("(+%d more)", total - CTX.MAX_SEND_REPORT)
  end
  return tbl_concat(lines, "\n")
end

function CTX.track_send_presence_answer(proj, source_track, source_index, source_name)
  if not source_track then return nil end
  local label = CTX.local_track_label(source_index, source_name)
  if not reaper.GetTrackNumSends or not reaper.GetTrackSendInfo_Value then
    return "Sends: unavailable"
  end
  local send_count = reaper.GetTrackNumSends(source_track, 0) or 0
  if send_count == 0 then return label .. " has no sends to other tracks." end
  local dests = {}
  for si = 0, send_count - 1 do
    local dest = reaper.GetTrackSendInfo_Value(source_track, 0, si, "P_DESTTRACK")
    if dest then
      local _, nm = R_GetTrackName(dest)
      dests[#dests + 1] = CTX.local_track_label(
        math_floor(R_GetMediaTrackInfo_Value(dest, "IP_TRACKNUMBER") or 0),
        nm)
    end
    if #dests >= 3 then break end
  end
  if #dests == 0 then
    return str_format("%s has %d send%s to other tracks.", label, send_count,
      send_count == 1 and "" or "s")
  end
  local suffix = send_count > #dests and str_format(", +%d more",
    send_count - #dests) or ""
  return str_format("%s has %d send%s to %s%s.", label, send_count,
    send_count == 1 and "" or "s", tbl_concat(dests, ", "), suffix)
end

function CTX.tracks_without_sends(proj, opts)
  local selected_only = opts and opts.selected_only == true
  local label = selected_only and "Selected tracks without sends"
    or "Tracks without sends"
  if not reaper.GetTrackNumSends then return label .. ": unavailable" end
  local total = 0
  local rows = {}
  local track_count = R_CountTracks(proj)
  for i = 0, track_count - 1 do
    local tr = R_GetTrack(proj, i)
    if tr and (not selected_only or R_IsTrackSelected(tr)) then
      local send_count = reaper.GetTrackNumSends(tr, 0) or 0
      if send_count == 0 then
        total = total + 1
        if #rows < 40 then
          local _, nm = R_GetTrackName(tr)
          rows[#rows + 1] = str_format("%d. %s", i + 1,
            nm ~= "" and nm or "(unnamed)")
        end
      end
    end
  end
  if total == 0 then return label .. ": none" end
  local lines = { str_format("%s: %d", label, total) }
  for _, row in ipairs(rows) do lines[#lines + 1] = row end
  if total > #rows then
    lines[#lines + 1] = str_format("(+%d more)", total - #rows)
  end
  return tbl_concat(lines, "\n")
end

function CTX.send_route_answer(proj, source_track, source_name, dest_track, dest_name)
  if not source_track or not dest_track then return nil end
  if not reaper.GetTrackNumSends or not reaper.GetTrackSendInfo_Value then
    return "Route: unavailable"
  end
  local send_count = reaper.GetTrackNumSends(source_track, 0) or 0
  for si = 0, send_count - 1 do
    local dest = reaper.GetTrackSendInfo_Value(source_track, 0, si, "P_DESTTRACK")
    if dest == dest_track then
      return "Route: yes, " .. (source_name or "source track")
        .. " sends to " .. (dest_name or "destination track")
        .. str_format(" (send %d)", si + 1)
    end
  end
  return "Route: no, " .. (source_name or "source track")
    .. " does not send to " .. (dest_name or "destination track")
end

-- =============================================================================
-- fx_params helpers
-- =============================================================================

-- CTX.fx_normalize_name(name) -> string
-- Produces a maximally-flexible search key from a raw plugin name string.
-- Transformations applied (in order):
--   1. Lowercase everything.
--   2. Strip the REAPER format prefix (VST:, VST3:, AU:, CLAP:, JS:, etc.)
--      and the vendor/manufacturer suffix in parentheses, e.g. "(Valhalla DSP)".
--      These are added by REAPER and should not affect matching.
--   3. Remove all non-alphanumeric characters (spaces, hyphens, underscores,
--      dots, slashes ...). This makes "Pro-Q 3", "ProQ3", "Pro Q3" all resolve
--      to "proq3", so minor punctuation differences never break a match.
-- The same transformation is applied to both the FX name from REAPER and the
-- search term supplied by the assistant, so matching is symmetric.

-- Returns true when (name, idx) match a VST3 host-appended tail param
-- (Internal / Delta / Wet@>0 / Bypass@>0). Extracted so CTX.fx_params,
-- the shallow scan, the deep scan, and the deep-probe estimator share a
-- single predicate -- previously this was inlined four times with
-- subtly different parenthesisation, and Stage 1 of the review pass
-- found a nil-deref bug in two of those copies.
local function _is_vst3_tail(name, idx)
  return name == "Internal" or name == "Delta"
      or ((name == "Wet" or name == "Bypass") and idx > 0)
end

function CTX.fx_normalize_name(name)
  local s = name:lower()
  -- Strip format prefix (VST3:, VST2:, CLAP:, JS:, etc.) - use %w+ to cover
  -- prefixes that contain digits like "VST3:".
  s = s:gsub("^%w+:%s*", "")
  -- Strip vendor suffix: " (anything)" at the end.
  s = s:gsub("%s*%(.-%)%s*$", "")
  -- Collapse all non-alphanumeric characters so spacing/punctuation is ignored.
  s = s:gsub("[^%a%d]", "")
  return s
end

-- CTX.fx_name_matches(fx_full_name, search_terms) -> bool
-- Returns true if fx_full_name fuzzy-matches ANY entry in the search_terms list.
-- Two levels of matching are attempted, from strictest to most lenient:
--   1. Normalized contains: the normalized search term appears as a substring
--      of the normalized FX name. Catches "VintageVerb" vs "Vintage Verb",
--      "Pro-Q 3" vs "ProQ3", etc.
--   2. Token subset: the normalized FX name contains all of the search term's
--      individual digit-run and alpha-run tokens. Catches abbreviated queries
--      like "reverb" matching "ValhallaVintageVerb" or "q3" matching "ProQ3".
-- Returning on the first match avoids redundant work when multiple terms are
-- provided.
function CTX.fx_name_matches(fx_full_name, search_terms)
  local norm_fx = CTX.fx_normalize_name(fx_full_name)
  for _, term in ipairs(search_terms) do
    local norm_term = CTX.fx_normalize_name(term)
    if norm_term ~= "" then
      -- Level 1: normalized substring match (whole term).
      if norm_fx:find(norm_term, 1, true) then
        return true
      end
      -- Level 2: token subset match. Split norm_term into alpha and digit runs
      -- and check that every token appears as a substring of norm_fx.
      -- Example: term "q 3" -> tokens {"q","3"} -> both in "proq3" -> match.
      local all_match = true
      local token_count = 0
      for token in norm_term:gmatch("[%a]+") do
        token_count = token_count + 1
        if not norm_fx:find(token, 1, true) then all_match = false; break end
      end
      for token in norm_term:gmatch("[%d]+") do
        token_count = token_count + 1
        if not norm_fx:find(token, 1, true) then all_match = false; break end
      end
      if token_count > 0 and all_match then
        return true
      end
      -- Level 3: word-level match. Split the ORIGINAL term on spaces and
      -- normalize each word individually, then check ALL appear in norm_fx.
      -- Catches "Fabfilter ProQ" matching "Pro-Q 4" -- "proq" is in "proq4"
      -- even though the full "fabfilterproq" is not.
      local words = {}
      for w in term:gmatch("%S+") do
        local nw = CTX.fx_normalize_name(w)
        if nw ~= "" then words[#words+1] = nw end
      end
      if #words > 1 then
        local all_words = true
        for _, w in ipairs(words) do
          if not norm_fx:find(w, 1, true) then
            all_words = false
            break
          end
        end
        if all_words then return true end
      end
    end
  end
  return false
end

-- CTX.fx_filter_parse(payload) -> { name, track }
-- Parse a single fx_params payload like "Pro-Q 4" or "Pro-Q 4@2". The "@N"
-- suffix is optional and scopes the lookup to a single 1-based track index
-- (matching the human-facing "Track N" labels in fx_params output). Without
-- "@N" the filter applies to every track. Whitespace around the @ and around
-- the name is ignored; an unparsable "@..." (non-integer or zero) falls back
-- to whole-string-as-name with no scope, so a literal "@" inside an exotic
-- plugin name doesn't cause a silent miss.
function CTX.fx_filter_parse(payload)
  payload = payload or ""
  local nm, tn = payload:match("^(.-)%s*@%s*(%d+)%s*$")
  if nm and nm ~= "" then
    local n = tonumber(tn)
    if n and n >= 1 then
      return { name = nm:match("^%s*(.-)%s*$"), track = n }
    end
  end
  return { name = payload:match("^%s*(.-)%s*$"), track = nil }
end

-- CTX.fx_filter_key(filters) -> string
-- Re-serialize a list of filter records back into "Pro-Q 4@2/Pro-C 3" form
-- for use as a sticky_context key and ctx_label chip. Tolerates legacy
-- string entries (no scope).
function CTX.fx_filter_key(filters)
  local parts = {}
  for _, f in ipairs(filters or {}) do
    local nm, tr
    if type(f) == "string" then nm = f
    else nm, tr = f.name, f.track end
    if nm and nm ~= "" then
      parts[#parts+1] = tr and (nm .. "@" .. tr) or nm
    end
  end
  return tbl_concat(parts, "/")
end

-- CTX.fx_filter_names_only(filters) -> { string, ... }
-- Names-only view, used by callers that need to fuzzy-match without caring
-- about track scope (e.g. the auto-cache trigger in the bucket dispatcher,
-- which inspects any matching plugin to populate the FX cache regardless of
-- which track instance the model asked about).
function CTX.fx_filter_names_only(filters)
  local out = {}
  for _, f in ipairs(filters or {}) do
    local nm = (type(f) == "string") and f or f.name
    if nm and nm ~= "" then out[#out+1] = nm end
  end
  return out
end

-- CTX.fx_params(proj, filter_names) -> string, matched_count
-- On-demand bucket (NOT included in the default session snapshot).
-- Returns current parameter values ONLY for FX whose names fuzzy-match at
-- least one entry in filter_names (see CTX.fx_name_matches above). filter_names
-- entries may be strings ("Pro-Q 4") OR records ({name="Pro-Q 4", track=2})
-- produced by CTX.fx_filter_parse. A record's track field, when present,
-- restricts the match to that single 1-based track index -- so the model can
-- request "fx_params:Pro-Q 4@2" to read only track 2's instance instead of
-- triggering a 200K-token dump across every Pro-Q 4 in the project.
--
-- Identical-state dedup: when multiple matched FX produce byte-identical
-- param bodies (typical for freshly-added EQ instances on N tracks: only the
-- ones actually edited differ from the default), emit the body once and
-- annotate the FX header with "(also identical on tracks 3-10)". Cuts the
-- output for 10x default Pro-Q 4 from ~6000 lines to ~600.
--
-- A non-empty filter_names list is ALWAYS required. Full-session dumps are
-- intentionally not supported: on large sessions they can exceed the model's
-- context limit and cost several dollars per call. The assistant is instructed
-- to always request specific plugin names via fx_params:PluginName.
--
-- FX indices in output are 0-based (matching REAPER API) so the assistant can
-- pass them directly to TrackFX_GetParam / TrackFX_SetParam without adjustment.
-- Parameter values are reported as normalised [0..1] floats followed by the
-- formatted display string (e.g. "-6.0 dB") so the assistant has both.
--
-- Returns two values: the formatted string and the count of FX that matched
-- (0 means no FX matched the filter, which the caller should surface as a
-- friendly error rather than sending an empty block to the assistant).
function CTX.fx_params(proj, filter_names)
  -- Normalize the filter list: callers may pass strings (legacy) or records
  -- (new). Records carry an optional `track` field that scopes the match to
  -- a single 1-based track index. Inlined to avoid blowing past the 200
  -- module-scope-local limit in this large file.
  local filters = {}
  for _, f in ipairs(filter_names or {}) do
    if type(f) == "string" then
      filters[#filters+1] = CTX.fx_filter_parse(f)
    else
      filters[#filters+1] = { name = f.name or "", track = f.track }
    end
  end
  -- Guard: filters must be non-empty. If the assistant somehow emits a bare
  -- <context_needed>fx_params</context_needed> with no plugin name, the
  -- parser catches it before calling this function, but defend here too.
  if #filters == 0 then
    return "FX PARAMETER VALUES: (error: no plugin name specified -- "
      .. "use fx_params:PluginName to request specific plugins)", 0
  end

  -- Format the "(also identical on ...)" annotation. When every duplicate
  -- shares the primary's FX index, collapse to "tracks 3-10" / "tracks 3, 5,
  -- 7-9". When the FX index varies across dups (uncommon: same plugin at
  -- different chain positions on different tracks), emit "Track N FX[I]"
  -- verbatim so the model can disambiguate.
  local function format_dup_list(dups, primary_fx_idx)
    local same_fx = true
    for _, d in ipairs(dups) do
      if d.fx_idx ~= primary_fx_idx then same_fx = false; break end
    end
    if same_fx then
      local nums = {}
      for _, d in ipairs(dups) do nums[#nums+1] = d.track_idx end
      table.sort(nums)
      local out, i = {}, 1
      while i <= #nums do
        local j = i
        while j < #nums and nums[j+1] == nums[j] + 1 do j = j + 1 end
        if j > i then
          out[#out+1] = nums[i] .. "-" .. nums[j]
        else
          out[#out+1] = tostring(nums[i])
        end
        i = j + 1
      end
      return "tracks " .. tbl_concat(out, ", ")
    else
      local out = {}
      for _, d in ipairs(dups) do
        out[#out+1] = "Track " .. d.track_idx .. " FX[" .. d.fx_idx .. "]"
      end
      return tbl_concat(out, ", ")
    end
  end

  local track_count = R_CountTracks(proj)
  -- Re-emit the filters in canonical "Name@Track" form for the header so the
  -- model sees its own scope decisions echoed back (helps it learn the syntax
  -- via positive reinforcement on subsequent turns).
  local header_parts = {}
  for _, f in ipairs(filters) do
    header_parts[#header_parts+1] = f.track and (f.name .. "@" .. f.track) or f.name
  end
  local header = "FX PARAMETER VALUES (filtered: "
    .. tbl_concat(header_parts, ", ") .. "):"
  local lines = { header }

  -- A filter matches a (track_idx_1based, fx_name) pair when the FX name
  -- fuzzy-matches the filter's name AND the filter has either no track scope
  -- or a track scope equal to this track.
  local function matches_any(track_idx_1based, fx_nm)
    for _, f in ipairs(filters) do
      if (not f.track) or f.track == track_idx_1based then
        if CTX.fx_name_matches(fx_nm, { f.name }) then return true end
      end
    end
    return false
  end

  -- Walk all tracks/FX once, building a per-FX "entry" with the parameter
  -- body buffered as a single string. We dedup by (fx_nm, body) below so
  -- N identical instances of a freshly-added EQ collapse to one block.
  local entries = {}
  for ti = 0, track_count - 1 do
    -- Nil-guard R_GetTrack against project-tab close races: track_count
    -- was sampled at the top of fx_params, but on long FX walks the user
    -- can swap or close the project tab mid-loop. R_GetTrackName(nil)
    -- would crash; skipping the iteration is safe.
    local tr = R_GetTrack(proj, ti)
    if tr then
      local _, nm    = R_GetTrackName(tr)
      local fx_count = R_TrackFX_GetCount(tr)
      for fi = 0, fx_count - 1 do
        local _, fx_nm = R_TrackFX_GetFXName(tr, fi, "")
        if matches_any(ti + 1, fx_nm) then
          -- Look up cached enum data for this plugin (if available).
          local cached_key, cached_plugin = FXCache.find_plugin(fx_nm)
          local cached_enums = {}  -- idx -> enum list
          local cached_ranges = {} -- idx -> {display_min, display_max}
          if cached_plugin and cached_plugin.params then
            if S._fx_cache_events then
              local t = S._fx_cache_events
              t.hit = t.hit or {}
              t.hit[#t.hit+1] = cached_key or fx_nm
            end
            for _, cp in ipairs(cached_plugin.params) do
              if cp.enum then cached_enums[cp.idx] = cp.enum end
              if cp.display_min and cp.display_max then
                cached_ranges[cp.idx] = { cp.display_min, cp.display_max }
              end
            end
          end
          local body_lines = {}
          local param_count = R_TrackFX_GetNumParams(tr, fi)
          local param_shown = 0
          for pi = 0, param_count - 1 do
            local _, param_nm = R_TrackFX_GetParamName(tr, fi, pi, "")
            -- Filter MIDI CC automation parameters (VST3 plugins expose 2000+).
            if param_nm:match("^CC %d") or param_nm:match("^MIDI CC") then
              goto continue_param
            end
            -- Filter MIDI message params injected by the host.
            if param_nm == "Channel Pressure" or param_nm == "Poly Pressure"
               or param_nm == "Pitch Bend" or param_nm == "Program Change" then
              goto continue_param
            end
            -- Filter generic unnamed params with no useful display value.
            local _, disp = R_TrackFX_GetFormattedParamValue(tr, fi, pi, "")
            disp = disp or ""  -- ReaImGui binding can return nil on unusual plugins
            if (param_nm:match("^Param %d+$") or param_nm:match("^Parameter %d+$"))
               and (disp == "" or disp:match("^[%d%.%%]*$")) then
              goto continue_param
            end
            -- Filter VST3 host-appended params (Bypass/Wet/Delta/Internal at tail).
            if _is_vst3_tail(param_nm, pi) then
              if disp == "normal" or disp == "-" or disp:match("^%d+$") then
                goto continue_param
              end
            end
            local val, mn, mx = R_TrackFX_GetParam(tr, fi, pi)
            local norm = 0
            if mx ~= mn then norm = (val - mn) / (mx - mn) end
            -- Annotate with [enum:] or [range:] if we have cached data for this param.
            local suffix = ""
            if cached_enums[pi] then
              suffix = "  [enum: " .. tbl_concat(cached_enums[pi], ", ") .. "]"
            elseif cached_ranges[pi] then
              suffix = "  [range: " .. cached_ranges[pi][1] .. ".." .. cached_ranges[pi][2] .. "]"
            end
            -- Display value first (human-readable), normalized in brackets.
            body_lines[#body_lines+1] = str_format(
              "    [%d] %s: %s  [norm: %.4f]%s",
              pi, param_nm, disp, norm, suffix)
            param_shown = param_shown + 1
            ::continue_param::
          end
          if param_shown < param_count then
            body_lines[#body_lines+1] = str_format(
              "    (%d host/uninformative params filtered)",
              param_count - param_shown)
          end
          entries[#entries+1] = {
            track_idx = ti + 1,
            track_nm  = nm,
            fx_idx    = fi,
            fx_nm     = fx_nm,
            body      = tbl_concat(body_lines, "\n"),
          }
        end
      end
    end
  end

  -- Group entries by (fx_nm, body). Order is preserved by the order entries
  -- were inserted (track-major, FX-minor), so the "primary" of each group is
  -- always the first occurrence of that body. Later occurrences become
  -- "(also identical on tracks ...)" annotations on the primary's FX header.
  local groups, group_idx = {}, {}
  for _, e in ipairs(entries) do
    local key = e.fx_nm .. "\0" .. e.body
    local gi = group_idx[key]
    if gi then
      groups[gi].dups[#groups[gi].dups + 1] = e
    else
      groups[#groups+1] = { primary = e, dups = {} }
      group_idx[key] = #groups
    end
  end

  -- Emit. Track headers ride along the primary entries; non-primary entries
  -- are folded into the dedup annotation so identical bodies aren't repeated.
  local last_track_emitted = -1
  for _, g in ipairs(groups) do
    local p = g.primary
    if last_track_emitted ~= p.track_idx then
      last_track_emitted = p.track_idx
      lines[#lines+1] = str_format("Track %d %q:", p.track_idx, p.track_nm)
    end
    local also = ""
    if #g.dups > 0 then
      also = "  (also identical on " .. format_dup_list(g.dups, p.fx_idx) .. ")"
    end
    lines[#lines+1] = str_format("  FX [%d] %s:%s", p.fx_idx, p.fx_nm, also)
    if p.body ~= "" then lines[#lines+1] = p.body end
  end

  if #entries == 0 then
    lines[#lines+1] = "  (no matching FX found on any track -- the plugin is not loaded yet. "
      .. "If fx_list results are available above, use them to write code that adds the plugin and sets parameters "
      .. "using find_param and set_param_display at runtime. Do NOT request fx_list again -- proceed with the code.)"
  end

  return tbl_concat(lines, "\n"), #entries
end

-- =============================================================================
-- CTX.docs / CTX.midi / CTX.theme
-- =============================================================================
-- Loads the REAPER Lua API + workflow reference from a single file in the
-- script's Resources folder (API_Ref.md). The file contains ten buckets
-- delimited by `<!-- SECTION:name -->` markers:
--   core      always-pinned when "Always include REAPER API reference" is
--             on; otherwise fetched on-demand via the docs bucket.
--   extended  less-common API surface; on-demand via docs_extended.
--   items / envelopes / take_fx / routing / tempo / sws
--             on-demand via docs:NAME.
--   midi      MIDI workflow reference; auto-injected on midi prompts or
--             on-demand via the midi bucket. Served by CTX.midi.
--   theme     theme color reference; auto-injected on theme+color prompts
--             or on-demand via the theme bucket. Served by CTX.theme.
-- The whole file is read once per session and parsed into
-- S.api_ref_section_cache, but each bucket is still served individually
-- -- only the requested bucket is sent to the model. Does not take a proj
-- argument because the reference is project-independent.
--
-- The file's leading HTML-comment header sits before the first SECTION
-- marker so it is naturally ignored by the marker parser; it never ships
-- to the model.
--
-- Returns the formatted reference string on success, or nil + error message
-- on failure. Callers MUST check for nil and show the error to the user in
-- chat rather than sending the error text to the assistant.

local function _read_ref_file(path, filename)
  local f = io.open(path, "r")
  if not f then
    return nil, "API reference file not found at:\n" .. path
      .. "\n\nPlace " .. filename .. " in the Resources/ subfolder "
      .. "next to this script, or turn off \"Always include REAPER API reference\" in Settings."
  end
  local content = f:read("*a")
  f:close()
  if #content > CFG.MAX_API_REF_BYTES then
    return nil, str_format(
      "%s is too large (%.1f KB, max %d KB).\n"
      .. "This may not be the correct file.",
      filename, #content / 1024, CFG.MAX_API_REF_BYTES / 1024)
  end
  return content
end

-- The REAPER Lua API + workflow reference lives in a single physical file
-- (Resources/API_Ref.md) with ten buckets delimited by
-- `<!-- SECTION:name -->` ... `<!-- /SECTION:name -->` markers:
--   core      always-pinned default reference (CTX.docs)
--   extended  on-demand via <context_needed>docs_extended</context_needed>
--   items, envelopes, take_fx, routing, tempo, sws
--             on-demand via <context_needed>docs:NAME</context_needed>
--   midi      auto-injected on midi prompts / on-demand via
--             <context_needed>midi</context_needed> (CTX.midi)
--   theme     auto-injected on theme+color prompts / on-demand via
--             <context_needed>theme</context_needed> (CTX.theme)
-- The file is read once per session and parsed into S.api_ref_section_cache
-- keyed by bucket name. Each bucket is still served individually -- only
-- the requested name is sent to the model -- but the loader and cache are
-- unified, replacing what used to be five separate per-file loaders.
local API_REF_FILE = "API_Ref.md"
-- Buckets the model can request. The dispatcher gates docs:<x> against
-- DOCS_SECTION_NAMES (the on-demand-section subset); the loader parses
-- the full set including core/extended/midi/theme.
local API_REF_SECTION_NAMES = {
  core      = true,
  extended  = true,
  items     = true,
  envelopes = true,
  take_fx   = true,
  routing   = true,
  tempo     = true,
  sws       = true,
  midi      = true,
  theme     = true,
}
local DOCS_SECTION_NAMES = {
  items     = true,
  envelopes = true,
  take_fx   = true,
  routing   = true,
  tempo     = true,
  sws       = true,
}
-- Singular / hyphenated / spaced variants the model commonly emits. Map
-- each to its canonical key in DOCS_SECTION_NAMES. Always lookup against
-- a lowercased key.
local DOCS_SECTION_ALIASES = {
  ["take-fx"]  = "take_fx",
  ["takefx"]   = "take_fx",
  ["take fx"]  = "take_fx",
  ["sends"]    = "routing",
  ["receives"] = "routing",
  ["envelope"] = "envelopes",
  ["item"]     = "items",
  ["send"]     = "routing",
  ["receive"]  = "routing",
  ["sws-extension"] = "sws",
  ["sws extension"] = "sws",
  ["sws_ext"]   = "sws",
  ["cf"]        = "sws",
  ["br"]        = "sws",
  ["nf"]        = "sws",
  ["fng"]       = "sws",
}
-- Normalize an incoming docs:<payload> to a canonical section key, or
-- nil if the payload is not a known section. Used by both the dispatcher
-- and the pre-pin scanner so they agree on what's a valid section.
local function _docs_section_canonical(payload)
  if type(payload) ~= "string" or payload == "" then return nil end
  local lower = payload:lower():match("^%s*(.-)%s*$")
  local canonical = DOCS_SECTION_ALIASES[lower] or lower
  if DOCS_SECTION_NAMES[canonical] then return canonical end
  return nil
end
-- Sorted list of canonical on-demand section names for error messages.
local function _docs_section_list()
  local names = {}
  for k in pairs(DOCS_SECTION_NAMES) do names[#names+1] = k end
  table.sort(names)
  return tbl_concat(names, ", ")
end

-- Load and parse the API reference file once per session. After this
-- returns, S.api_ref_section_cache[name] holds the body for each
-- successfully parsed bucket, and S._api_ref_section_err[name] holds
-- the error string for any bucket that failed (file-level read error,
-- duplicate marker, or bucket missing from the allowlist's expected
-- set). S.api_ref_loaded is the sentinel: subsequent calls return
-- without re-reading the file. A missing/corrupt file in this session
-- stays missing -- the user can't fix it mid-session anyway, and the
-- error table holds a clear reason for any CTX.docs* call.
local function _load_api_ref_file()
  if S.api_ref_loaded then return end
  S.api_ref_section_cache = {}
  S._api_ref_section_err  = {}
  local content, err = _read_ref_file(
    RA.RESOURCES_DIR .. API_REF_FILE, API_REF_FILE)
  if not content then
    -- File-level failure: mark every known bucket so any CTX.docs* call
    -- surfaces a real error instead of "section not loaded".
    for name in pairs(API_REF_SECTION_NAMES) do
      S._api_ref_section_err[name] = err
    end
    S.api_ref_loaded = true
    return
  end
  -- Whitespace-tolerant marker pattern (matches both `<!--SECTION:items-->`
  -- and `<!-- SECTION:items -->`). The %1 back-reference forces the
  -- closing marker to name the same section.
  local pattern =
    "<!%-%-%s*SECTION:([%w_]+)%s*%-%->%s*(.-)%s*<!%-%-%s*/SECTION:%1%s*%-%->"
  local seen = {}
  for name, body in content:gmatch(pattern) do
    if not API_REF_SECTION_NAMES[name] then
      S._api_ref_section_err[name] =
        "Unknown section '" .. name .. "' in " .. API_REF_FILE
    elseif seen[name] then
      -- Duplicate marker block: fail loud rather than silently
      -- overwriting. Catches accidental copy/paste in the source file.
      S._api_ref_section_err[name] =
        "Duplicate SECTION:" .. name .. " block in " .. API_REF_FILE
      S.api_ref_section_cache[name] = nil
    else
      seen[name] = true
      S.api_ref_section_cache[name] = body:gsub("%s+$", "")
    end
  end
  -- Mark missing buckets (declared in allowlist but not parsed out).
  for name in pairs(API_REF_SECTION_NAMES) do
    if not S.api_ref_section_cache[name]
        and not S._api_ref_section_err[name] then
      S._api_ref_section_err[name] =
        "Section '" .. name .. "' missing from " .. API_REF_FILE
    end
  end
  S.api_ref_loaded = true
end

function CTX.docs()
  _load_api_ref_file()
  if S._api_ref_section_err.core then
    return nil, S._api_ref_section_err.core
  end
  return "REAPER LUA API REFERENCE:\n" .. S.api_ref_section_cache.core
end

function CTX.docs_extended()
  _load_api_ref_file()
  if S._api_ref_section_err.extended then
    return nil, S._api_ref_section_err.extended
  end
  return "REAPER LUA API REFERENCE (EXTENDED):\n"
    .. S.api_ref_section_cache.extended
end

-- Returns the formatted on-demand section payload, or nil + error string.
-- The caller is responsible for sticky_set'ing it under "docs:<name>" --
-- this loader just produces the content. Section name MUST be a canonical
-- key from DOCS_SECTION_NAMES (use _docs_section_canonical to normalize).
-- Defensive early-out for unknown names: don't trigger a file load on
-- bad input. The dispatcher already validates via _docs_section_canonical,
-- but CTX.docs_section is module-public and could be called directly with
-- a bad name from future code.
function CTX.docs_section(name)
  if not DOCS_SECTION_NAMES[name] then
    return nil, "Unknown docs section: '" .. tostring(name) .. "'. "
      .. "Valid: " .. _docs_section_list() .. "."
  end
  _load_api_ref_file()
  if S._api_ref_section_err[name] then
    return nil, S._api_ref_section_err[name]
  end
  if not S.api_ref_section_cache[name] then
    return nil, "Section '" .. tostring(name) .. "' not loaded."
  end
  return "REAPER LUA API REFERENCE (" .. name:upper() .. "):\n"
    .. S.api_ref_section_cache[name]
end

function CTX.recent_reaper_changes()
  local path = RA.RESOURCES_DIR .. "Reaper_Recent_Changes.md"
  local f = io.open(path, "r")
  if not f then
    return nil, "Recent REAPER changes file not found at:\n" .. path
  end
  local content = f:read("*a") or ""
  f:close()
  content = content:gsub("^%s+", ""):gsub("%s+$", "")
  if content == "" then
    return nil, "Recent REAPER changes file is empty:\n" .. path
  end
  if #content > 65536 then
    return nil, "Recent REAPER changes file is too large ("
      .. tostring(#content) .. " bytes)."
  end
  return "RECENT REAPER CHANGES (OFFICIAL CHANGELOG EXCERPT):\n" .. content
end

-- =============================================================================
-- CTX.prompt_bundle
-- =============================================================================
-- Conditional prompt bundles -- sections of the system prompt that apply only
-- to certain request types. They live in a single physical file
-- (Resources/Prompts.md) with four buckets delimited by
-- `<!-- SECTION:name -->` ... `<!-- /SECTION:name -->` markers:
--   plugin          plugin / FX add + configure workflow
--   plugin_helpers  parameter-helper code patterns (find_param, etc.)
--   jsfx            JSFX (EEL2) generation rules
--   theme           SetThemeColor backup safety rule
-- Each is fetched on-demand when the model emits
-- `<context_needed>prompt_bundle:NAME</context_needed>` so the always-on
-- system prompt can stay small. Once fetched, the bundle pins via
-- sticky_context for the rest of the conversation.
--
-- The whole file is read once per session and parsed into
-- S.prompt_bundle_cache; each bundle is still served individually --
-- only the requested name is sent to the model. Unknown names return
-- nil + error string so callers can surface a clean error.
local PROMPTS_FILE = "Prompts.md"
local PROMPT_BUNDLE_NAMES = {
  plugin         = true,
  plugin_helpers = true,
  jsfx           = true,
  jsfx_pitch     = true,
  theme          = true,
}

local function _prompt_bundle_list()
  local names = {}
  for k in pairs(PROMPT_BUNDLE_NAMES) do names[#names+1] = k end
  table.sort(names)
  return tbl_concat(names, ", ")
end

local function _load_prompts_file()
  if S.prompts_loaded then return end
  S.prompt_bundle_cache = {}
  S._prompt_bundle_err  = {}
  local content, err = _read_ref_file(
    RA.RESOURCES_DIR .. PROMPTS_FILE, PROMPTS_FILE)
  if not content then
    for n in pairs(PROMPT_BUNDLE_NAMES) do S._prompt_bundle_err[n] = err end
    S.prompts_loaded = true
    return
  end
  -- Same whitespace-tolerant pattern as the API ref loader.
  local pattern =
    "<!%-%-%s*SECTION:([%w_]+)%s*%-%->%s*(.-)%s*<!%-%-%s*/SECTION:%1%s*%-%->"
  local seen = {}
  for n, body in content:gmatch(pattern) do
    if not PROMPT_BUNDLE_NAMES[n] then
      S._prompt_bundle_err[n] =
        "Unknown bundle '" .. n .. "' in " .. PROMPTS_FILE
    elseif seen[n] then
      S._prompt_bundle_err[n] =
        "Duplicate SECTION:" .. n .. " block in " .. PROMPTS_FILE
      S.prompt_bundle_cache[n] = nil
    else
      seen[n] = true
      local header = "PROMPT BUNDLE (" .. n:upper() .. "):\n"
      S.prompt_bundle_cache[n] = header .. body:gsub("%s+$", "")
    end
  end
  for n in pairs(PROMPT_BUNDLE_NAMES) do
    if not S.prompt_bundle_cache[n] and not S._prompt_bundle_err[n] then
      S._prompt_bundle_err[n] =
        "Bundle '" .. n .. "' missing from " .. PROMPTS_FILE
    end
  end
  S.prompts_loaded = true
end

function CTX.prompt_bundle(name)
  if type(name) ~= "string" or name == "" then
    return nil, "prompt_bundle requires a bundle name ("
      .. _prompt_bundle_list() .. ")."
  end
  name = name:lower()
  if not PROMPT_BUNDLE_NAMES[name] then
    return nil, "Unknown prompt bundle: '" .. name .. "'. "
      .. "Valid names: " .. _prompt_bundle_list() .. "."
  end
  _load_prompts_file()
  if S._prompt_bundle_err[name] then
    return nil, S._prompt_bundle_err[name]
  end
  if not S.prompt_bundle_cache[name] then
    return nil, "Bundle '" .. name .. "' not loaded."
  end
  return S.prompt_bundle_cache[name]
end

-- =============================================================================
-- CTX.midi
-- =============================================================================
-- Returns the MIDI workflow reference (PPQ explainer, value ranges, function
-- signatures, worked examples). Body content lives in API_Ref.md under
-- SECTION:midi; the unified API-ref loader caches every bucket on first
-- access. Returns the formatted reference string on success, or nil + error
-- message on failure.
function CTX.midi()
  _load_api_ref_file()
  if S._api_ref_section_err.midi then
    return nil, S._api_ref_section_err.midi
  end
  return "REAPER MIDI WORKFLOW REFERENCE:\n" .. S.api_ref_section_cache.midi
end

-- =============================================================================
-- Theme utilities + CTX.theme
-- =============================================================================

-- Restore any saved theme color backups from ExtState.  Called by the Undo
-- button so theme color changes can be reverted.  Returns count restored.
--
-- NOTE: Theme backups use the literal namespace "ReaAssist" (capital R), NOT
-- CFG.EXT_NS ("reaassist"). This is intentional: generated theme-change scripts
-- also write to "ReaAssist" so backup/restore works without the scripts needing
-- to know CFG.EXT_NS. Do NOT change to CFG.EXT_NS without updating the system
-- prompt's theme reference and all generated code patterns.
Theme = {}
function Theme.restore_backups()
  -- Read the manifest of changed keys written by the theme change script.
  local manifest = reaper.GetExtState("ReaAssist", "ThemeBackup__KEYS")
  if manifest == "" then return 0 end
  local keys = {}
  for k in manifest:gmatch("[^,]+") do
    keys[#keys+1] = k:match("^%s*(.-)%s*$")
  end
  if #keys == 0 then return 0 end
  reaper.PreventUIRefresh(1)
  -- Wrap in pcall so a corrupted ext-state value (or any unexpected
  -- SetThemeColor failure) cannot leave PreventUIRefresh suppressed.
  pcall(function()
    for _, ini_key in ipairs(keys) do
      local saved = reaper.GetExtState("ReaAssist", "ThemeBackup_" .. ini_key)
      if saved ~= "" then
        local n = tonumber(saved)
        if n then
          reaper.SetThemeColor(ini_key, n, 0)
        end
        reaper.DeleteExtState("ReaAssist", "ThemeBackup_" .. ini_key, false)
      end
    end
    reaper.DeleteExtState("ReaAssist", "ThemeBackup__KEYS", false)
  end)
  reaper.PreventUIRefresh(-1)
  reaper.ThemeLayout_RefreshAll()
  reaper.UpdateArrange()
  return #keys
end

-- ---------------------------------------------------------------------------
-- Theme.save_to_file() -- write current runtime colors into the .ReaperTheme
-- file so they persist across theme reloads. Only works with unzipped
-- .ReaperTheme files; shows a message for .ReaperThemeZip.
-- Returns true on success, false + error string on failure.
-- ---------------------------------------------------------------------------
function Theme.save_to_file()
  local manifest = reaper.GetExtState("ReaAssist", "ThemeBackup__KEYS")
  if manifest == "" then
    return false, "No theme changes to save."
  end
  local theme_path = reaper.GetLastColorThemeFile()
  if not theme_path or theme_path == "" then
    return false, "Could not determine the current theme file."
  end
  if theme_path:lower():match("%.reaperthemezip$") then
    return false, "Your current theme is a .ReaperThemeZip file which "
      .. "cannot be edited directly.\n\nTo save changes: open the Theme "
      .. "development/tweaker window (Actions > Theme development/tweaker) "
      .. "and click 'Save Theme...' to export as a .ReaperTheme file."
  end
  -- Collect the keys and their current runtime values.
  local keys = {}
  for k in manifest:gmatch("[^,]+") do
    local trimmed = k:match("^%s*(.-)%s*$")
    keys[trimmed] = reaper.GetThemeColor(trimmed, 0)
  end
  -- Read the existing theme file.
  local f, err = io.open(theme_path, "r")
  if not f then return false, "Cannot read theme file: " .. (err or theme_path) end
  local content = f:read("*a")
  f:close()
  -- Update existing keys and track which ones were found.
  local found = {}
  for key, val in pairs(keys) do
    local pattern = "(" .. key:gsub("([%(%)%.%%%+%-%*%?%[%^%$])", "%%%1") .. "=)[^\r\n]*"
    local new_content, count = content:gsub(pattern, "%1" .. tostring(val))
    if count > 0 then
      content = new_content
      found[key] = true
    end
  end
  -- Append any new keys that weren't already in the file.
  local to_append = {}
  for key, val in pairs(keys) do
    if not found[key] then
      to_append[#to_append+1] = key .. "=" .. tostring(val)
    end
  end
  if #to_append > 0 then
    -- Insert before the end of the [color theme] section or at end of file.
    local append_str = table.concat(to_append, "\n") .. "\n"
    -- Find the end of the [color theme] section (next section header or EOF).
    local next_section = content:find("\n%[", 2)
    if next_section then
      content = content:sub(1, next_section - 1) .. append_str .. content:sub(next_section)
    else
      -- No other sections; append at end.
      if content:sub(-1) ~= "\n" then content = content .. "\n" end
      content = content .. append_str
    end
  end
  -- Write back. Use a temp file + rename so a partial write or process kill
  -- mid-write cannot corrupt the user's .ReaperTheme. On Windows os.rename
  -- fails if the destination exists, so we delete the original first; this
  -- leaves a small window where the file is briefly absent, but a complete
  -- file is much better than a half-written one.
  local tmp_path = theme_path .. ".tmp"
  f, err = io.open(tmp_path, "w")
  if not f then return false, "Cannot write theme file: " .. (err or tmp_path) end
  local ok_w, err_w = f:write(content)
  local ok_c, err_c = f:close()
  if not ok_w or not ok_c then
    os.remove(tmp_path)
    return false, "Failed to write theme file: " .. tostring(err_w or err_c or "close failed")
  end
  os.remove(theme_path)
  local ok_r, err_r = os.rename(tmp_path, theme_path)
  if not ok_r then
    os.remove(tmp_path)
    return false, "Failed to replace theme file: " .. tostring(err_r)
  end
  -- Clear backups since the changes are now permanent.
  for key in pairs(keys) do
    reaper.DeleteExtState("ReaAssist", "ThemeBackup_" .. key, false)
  end
  reaper.DeleteExtState("ReaAssist", "ThemeBackup__KEYS", false)
  return true
end

-- theme color ini_key names for SetThemeColor/GetThemeColor, plus usage patterns.
-- On-demand bucket: injected when the user asks about changing theme colors or
-- appearance. Also auto-injected when the prompt contains theme + color keywords.
-- Body content lives in API_Ref.md under SECTION:theme; served by the unified
-- API-ref loader.
--
-- Returns the formatted reference string on success, or nil + error message
-- on failure.
function CTX.theme()
  _load_api_ref_file()
  if S._api_ref_section_err.theme then
    return nil, S._api_ref_section_err.theme
  end
  return "REAPER THEME COLOR REFERENCE:\n" .. S.api_ref_section_cache.theme
end

-- =============================================================================
-- CTX.plugin_ref
-- =============================================================================
-- Loads Plugin_Ref.md and returns ONLY the sections matching
-- the requested plugin names (e.g. {"ReaVerbate", "ReaComp"}). The full file
-- is parsed once into a per-plugin cache; subsequent calls just look up keys.
--
-- The reference file contains curated parameter data for both REAPER's stock
-- plugins (ReaEQ, ReaComp, etc.) and selected third-party plugins ReaAssist
-- ships curated knowledge for (e.g. ReEQ).
--
-- Alias map: common synonyms resolve to the canonical plugin name so the LLM
-- can request plugin_ref:reverb and get ReaVerbate.
--
-- filter_names: list of plugin name strings. If empty/nil, returns an error.

-- Alias map for plugin names -> canonical section header in the .md file.
local PLUGIN_REF_ALIASES = {
  eq         = "reaeq",
  equalizer  = "reaeq",
  equaliser  = "reaeq",
  comp       = "reacomp",
  compressor = "reacomp",
  gate       = "reagate",
  expander   = "reagate",
  delay      = "readelay",
  echo       = "readelay",
  limiter    = "realimit",
  limit      = "realimit",
  pitch      = "reapitch",
  ["pitch shift"] = "reapitch",
  tune       = "reatune",
  tuner      = "reatune",
  ["pitch correction"] = "reatune",
  reverb     = "reaverbate",
  verb       = "reaverbate",
  synth      = "reasynth",
  synthesizer = "reasynth",
  -- Stock-JSFX fallbacks (section keys are short single-word names; aliases
  -- cover common type synonyms AND the full AddByName paths so the LLM can
  -- round-trip a preferred-plugin identifier back to its ref section).
  deesser                     = "deesser",
  ["de-esser"]                = "deesser",
  ["liteon/deesser"]          = "deesser",
  ["js: liteon/deesser"]      = "deesser",
  saturation                  = "saturation",
  saturator                   = "saturation",
  ["loser/saturation"]        = "saturation",
  ["js: loser/saturation"]    = "saturation",
  chorus                      = "chorus",
  chorus_stereo               = "chorus",
  ["sstillwell/chorus_stereo"]     = "chorus",
  ["js: sstillwell/chorus_stereo"] = "chorus",
  phaser                      = "phaser",
  ["guitar/phaser"]           = "phaser",
  ["js: guitar/phaser"]       = "phaser",
  -- Stock multiband compressor (curated section)
  ["reaxcomp"]                = "reaxcomp",
  ["multiband_compressor"]    = "reaxcomp",
  ["multiband compressor"]    = "reaxcomp",
  ["multiband comp"]          = "reaxcomp",
  ["multi-band compressor"]   = "reaxcomp",
  ["mbcomp"]                  = "reaxcomp",
  -- FabFilter Pro-Q series (EQ)
  ["pro-q 4"]                 = "pro-q 4",
  ["pro-q"]                   = "pro-q 4",
  ["fabfilter pro-q 4"]       = "pro-q 4",
  ["vst3: pro-q 4"]           = "pro-q 4",
  ["vst3: pro-q 4 (fabfilter)"] = "pro-q 4",
  -- FabFilter Pro-C (compressor)
  ["pro-c 3"]                 = "pro-c 3",
  ["pro-c"]                   = "pro-c 3",
  ["fabfilter pro-c 3"]       = "pro-c 3",
  ["vst3: pro-c 3"]           = "pro-c 3",
  ["vst3: pro-c 3 (fabfilter)"] = "pro-c 3",
  -- FabFilter Pro-L (limiter)
  ["pro-l 2"]                 = "pro-l 2",
  ["pro-l"]                   = "pro-l 2",
  ["fabfilter pro-l 2"]       = "pro-l 2",
  ["vst3: pro-l 2"]           = "pro-l 2",
  ["vst3: pro-l 2 (fabfilter)"] = "pro-l 2",
  -- FabFilter Pro-MB (multiband compressor)
  ["pro-mb"]                  = "pro-mb",
  ["fabfilter pro-mb"]        = "pro-mb",
  ["vst3: pro-mb"]            = "pro-mb",
  ["vst3: pro-mb (fabfilter)"] = "pro-mb",
  -- FabFilter Pro-R 2 (reverb)
  ["pro-r 2"]                 = "pro-r 2",
  ["pro-r"]                   = "pro-r 2",
  ["fabfilter pro-r 2"]       = "pro-r 2",
  ["vst3: pro-r 2"]           = "pro-r 2",
  ["vst3: pro-r 2 (fabfilter)"] = "pro-r 2",
  -- FabFilter Pro-DS (de-esser)
  ["pro-ds"]                  = "pro-ds",
  ["fabfilter pro-ds"]        = "pro-ds",
  ["vst3: pro-ds"]            = "pro-ds",
  ["vst3: pro-ds (fabfilter)"] = "pro-ds",
  -- FabFilter Pro-G (gate)
  ["pro-g"]                   = "pro-g",
  ["fabfilter pro-g"]         = "pro-g",
  ["vst3: pro-g"]             = "pro-g",
  ["vst3: pro-g (fabfilter)"] = "pro-g",
  -- FabFilter Saturn (saturation)
  ["saturn 2"]                = "saturn 2",
  ["saturn"]                  = "saturn 2",
  ["fabfilter saturn 2"]      = "saturn 2",
  ["vst3: saturn 2"]          = "saturn 2",
  ["vst3: saturn 2 (fabfilter)"] = "saturn 2",
  -- FabFilter Timeless (delay)
  ["timeless 3"]              = "timeless 3",
  ["timeless"]                = "timeless 3",
  ["fabfilter timeless 3"]    = "timeless 3",
  ["vst3: timeless 3"]        = "timeless 3",
  ["vst3: timeless 3 (fabfilter)"] = "timeless 3",
}

-- =============================================================================
-- CURATED_IDENT
-- =============================================================================
-- Maps chain-entry identifiers (as stored in preferred_types) to the matching
-- curated section name in Plugin_Ref.md. Entries here trigger plugin_ref:<Name>
-- injection (verified indices, scale formulas, recipes) instead of the thinner
-- live-scan preferred_plugins:<type>. Chain entries that aren't in this map
-- fall through to live-scan fallback. Extend as more curated plugins are added
-- to Plugin_Ref.md.
local CURATED_IDENT = {
  -- Stock plugins. Multiple ReEQ keys because REAPER's EnumInstalledFX
  -- returns the JSFX file path on Windows ("JS: ReJJ/ReEQ/ReEQ.jsfx") but
  -- the JSFX `desc:` line on macOS ("JS: ReEQ - Parametric Graphic
  -- Equalizer"); whichever string the user picks from the Pref Plugins
  -- autocomplete becomes the saved pref_types value, and we need to
  -- recognise both forms (with and without the "JS: " prefix that the save
  -- path may or may not strip) so the curated plugin_ref:ReEQ content fires
  -- regardless of platform.
  ["ReJJ/ReEQ/ReEQ.jsfx"]                       = "ReEQ",
  ["JS: ReJJ/ReEQ/ReEQ.jsfx"]                   = "ReEQ",
  ["ReEQ - Parametric Graphic Equalizer"]       = "ReEQ",
  ["JS: ReEQ - Parametric Graphic Equalizer"]   = "ReEQ",
  ["ReaEQ"]               = "ReaEQ",
  ["ReaComp"]             = "ReaComp",
  ["ReaXcomp"]            = "ReaXcomp",
  ["ReaGate"]             = "ReaGate",
  ["ReaDelay"]            = "ReaDelay",
  ["ReaLimit"]            = "ReaLimit",
  ["ReaPitch"]            = "ReaPitch",
  ["ReaTune"]             = "ReaTune",
  ["ReaSynth"]            = "ReaSynth",
  ["ReaVerbate"]          = "ReaVerbate",
  -- FabFilter (format-agnostic chain entries)
  ["Pro-Q 4"]             = "Pro-Q 4",
  ["Pro-C 3"]             = "Pro-C 3",
  ["Pro-L 2"]             = "Pro-L 2",
  ["Pro-MB"]              = "Pro-MB",
  ["Pro-R 2"]             = "Pro-R 2",
  ["Pro-DS"]              = "Pro-DS",
  ["Pro-G"]               = "Pro-G",
  ["Saturn 2"]            = "Saturn 2",
  ["Timeless 3"]          = "Timeless 3",
}

-- Curated lookup that tolerates AddByName prefix + vendor suffix on the
-- input. After preferred_types canonicalization, identifiers stored as
-- chain-entry form ("Pro-Q 4") become AddByName form ("VST3: Pro-Q 4"
-- or "VST3: Pro-Q 4 (FabFilter)"). A direct CURATED_IDENT[ident] lookup
-- only matches the bare keys in the table -- which would silently
-- bypass the curated plugin_ref:<Name> path for any canonicalized
-- pref, regressing the Pro-Q / Pro-C / Pro-R routes that depend on it.
--
-- Strategy: try the original ident first (handles ReEQ JSFX paths and
-- the legacy bare-name entries). Then strip a recognized AddByName
-- prefix (matched against PLUGIN_REF_ALIASES so the prefix list stays
-- authoritative in one place) and the trailing " (Vendor)" suffix and
-- retry. Returns nil when neither form matches.
local function _curated_for_ident(ident)
  if not ident or ident == "" then return nil end
  local hit = CURATED_IDENT[ident]
  if hit then return hit end
  -- Strip the prefix only if it looks like an AddByName format prefix
  -- (e.g., "VST3: ", "AUi: "). A leading "ReJJ/" path component must NOT
  -- be touched -- those paths are first-class CURATED_IDENT keys and
  -- the direct lookup above already handles them.
  local stripped = ident:match("^[A-Za-z][A-Za-z0-9]*:%s*(.+)$")
  if stripped then
    -- Drop trailing " (Vendor)" to recover the bare chain-entry form.
    local bare = stripped:gsub("%s*%(.-%)%s*$", "")
    hit = CURATED_IDENT[bare]
    if hit then return hit end
    -- Try without stripping the suffix too (some entries embed parens
    -- in the actual name, though none do today).
    if bare ~= stripped then
      hit = CURATED_IDENT[stripped]
      if hit then return hit end
    end
  end
  return nil
end

-- Build the per-plugin section cache from Plugin_Ref.md. Idempotent;
-- lazy -- call before reading CTX._plugin_ref_cache. Returns true on
-- success, false + error string if the file is missing.
function CTX.ensure_plugin_ref_cache()
  if CTX._plugin_ref_cache then return true end
  local ref_path = RA.RESOURCES_DIR .. "Plugin_Ref.md"
  local f = io.open(ref_path, "r")
  if not f then
    return false, "Plugin reference file not found at:\n" .. ref_path
      .. "\n\nPlace Plugin_Ref.md in the Resources/ subfolder "
      .. "next to this script."
  end
  local content = f:read("*a")
  f:close()

  -- Parse only `<!-- PLUGIN:Name --> ... <!-- /PLUGIN:Name -->` blocks. Other
  -- `## Heading` lines (e.g. "ENUM PARAM NORMS", "FALLBACK CHAINS", or any
  -- future explanatory section) are intentionally NOT cached so they can't
  -- silently become bogus plugin keys reachable via plugin_ref:<heading>.
  -- Marker lines themselves are stripped from the cached body; everything
  -- between (including the `## Name` header) is preserved.
  CTX._plugin_ref_cache = {}
  local cur_name = nil
  local cur_lines = {}
  for line in content:gmatch("[^\n]+") do
    local open_name  = line:match("^<!%-%- PLUGIN:(.-) %-%->%s*$")
    local close_name = line:match("^<!%-%- /PLUGIN:(.-) %-%->%s*$")
    if open_name then
      cur_name = open_name
      cur_lines = {}
    elseif close_name then
      if cur_name then
        CTX._plugin_ref_cache[cur_name:lower()] = tbl_concat(cur_lines, "\n")
      end
      cur_name = nil
      cur_lines = {}
    elseif cur_name then
      cur_lines[#cur_lines+1] = line
    end
  end

  -- Validation: warn if any PLUGIN_REF_ALIASES target doesn't resolve to a
  -- parsed plugin block. Catches typos in the alias map and stale aliases
  -- that point at plugins removed from Plugin_Ref.md. Runs once per
  -- session (this function is idempotent via the cache check at the top).
  local missing, seen = {}, {}
  for _, target in pairs(PLUGIN_REF_ALIASES) do
    if not CTX._plugin_ref_cache[target] and not seen[target] then
      seen[target] = true
      missing[#missing + 1] = target
    end
  end
  if #missing > 0 then
    table.sort(missing)
    Log.line("plugin_ref",
      "alias targets missing from Plugin_Ref.md: " .. tbl_concat(missing, ", "))
  end

  return true
end

-- Whether the given plugin identifier resolves to a curated Plugin_Ref
-- section. Used by the UI to hide Rescan (curated plugins don't benefit
-- from live-scanned cache data -- preempt routes through plugin_ref).
function Code.is_curated_plugin(ident)
  if not ident or ident == "" then return false end
  if not CTX.ensure_plugin_ref_cache() then return false end
  local k = ident:lower():match("^%s*(.-)%s*$") or ""
  k = PLUGIN_REF_ALIASES[k] or k
  return CTX._plugin_ref_cache[k] ~= nil
end

-- Return the stock fallback spec for a given type, or nil. Reads the
-- ```chains block in Plugin_Ref.md and derives the plugin_ref section key
-- via PLUGIN_REF_ALIASES so the popup knows which curated section to inject
-- when the user picks the stock option. Co-located with is_curated_plugin
-- because both rely on PLUGIN_REF_ALIASES being in lexical scope.
function Code.get_stock_fallback(type_key)
  if not type_key or type_key == "" then return nil end
  local chains = Code.get_fallback_chains()
  local entry = chains[type_key]
  if not entry or not entry.stock then return nil end
  local add   = entry.stock.add
  local alias = entry.stock.alias
  local k = add:lower():match("^%s*(.-)%s*$") or ""
  k = PLUGIN_REF_ALIASES[k] or k
  return {
    add   = add,
    label = alias or add,  -- display label for popup button
    ref   = k,              -- plugin_ref section key (lowercased)
  }
end

function CTX.plugin_ref(filter_names)
  if not filter_names or #filter_names == 0 then
    return "PLUGIN_REF: (error: no plugin specified -- "
      .. "use plugin_ref:ReaComp or plugin_ref:reverb, eq)"
  end

  local ok, err = CTX.ensure_plugin_ref_cache()
  if not ok then return nil, err end

  -- Look up each requested plugin. Resolve aliases first.
  local out = {}
  local matched_names = {}
  for _, name in ipairs(filter_names) do
    local k = name:lower():match("^%s*(.-)%s*$") or ""
    k = PLUGIN_REF_ALIASES[k] or k
    local section = CTX._plugin_ref_cache[k]
    if section then
      matched_names[#matched_names+1] = k
      out[#out+1] = section
      out[#out+1] = ""
    end
  end

  if #matched_names == 0 then
    return "PLUGIN_REF (no reference data for: "
      .. tbl_concat(filter_names, ", ")
      .. "). Use the parameter helpers (find_param, set_param_display) at runtime instead."
  end

  -- Title with the matched plugin names so weak models can string-scan for
  -- "is ReEQ here?" without parsing the body. Was previously just
  -- "PLUGIN PARAMETER REFERENCE:" which left models re-requesting the data
  -- via <context_needed>resolve:eq</context_needed> after preempt injection.
  return "PLUGIN PARAMETER REFERENCE (" .. tbl_concat(matched_names, ", ") .. "):\n"
    .. tbl_concat(out, "\n")
end

-- =============================================================================
-- CTX.installed_fx
-- =============================================================================
-- CTX.populate_installed_fx
-- =============================================================================
-- Idempotent helper that builds CTX._installed_fx_list by walking
-- reaper.EnumInstalledFX (REAPER 7.42+). Safe to call multiple times; the list
-- is only built once per session. Returns the list on success, or nil if the
-- REAPER build doesn't expose EnumInstalledFX.
--
-- Consolidated from previously-duplicated loops in: CTX.installed_fx,
-- pref_plugins_scan_start, the Preferred Plugins render, the per-row Rescan
-- handler, and the Plugin Resolve popup.
-- Dev-only filter: FabFilter product stems used when the
-- "dev_hide_fabfilter" ExtState flag is set (Debug Helper "Hide FabFilter"
-- toggle) to simulate "not installed" without touching REAPER state. Mirrors the
-- FabFilter section of PLUGIN_REF_ALIASES so short-form entries ("Pro-Q 4")
-- and vendor-suffixed entries ("VST3: Pro-Q 4 (FabFilter)") both match.
local FABFILTER_DEV_STEMS = {
  "fabfilter",
  "pro-q", "pro-c", "pro-l", "pro-mb", "pro-r", "pro-ds", "pro-g",
  "saturn", "timeless", "twin", "volcano", "simplon",
}

-- Returns true when the identifier (FX name as stored in preferred_types or
-- emitted by EnumInstalledFX) matches a FabFilter product stem. Used to gate
-- both the installed-FX enumeration AND the preferred_types read paths, so
-- the dev toggle hides FabFilter everywhere it could surface -- even if the
-- dev_signal refresh never reaches the main loop.
-- NOTE: declared with `function` (no `local`) so it assigns to the
-- forward-declared local near `Code = {}`, which is needed by
-- Code.ensure_preferred_from_chains earlier in the file.
function _is_fabfilter_ident(ident)
  if not ident or ident == "" then return false end
  local lc = ident:lower()
  for _, stem in ipairs(FABFILTER_DEV_STEMS) do
    if lc:find(stem, 1, true) then return true end
  end
  return false
end

function CTX.populate_installed_fx()
  -- ExtState is process-shared and always current, so consumers read
  -- the dev_hide_fabfilter flag directly here rather than mirroring it
  -- in a prefs field that could go stale if the dev_signal ever missed.
  local hide_ff = reaper.GetExtState(CFG.EXT_NS, "dev_hide_fabfilter") == "1"
  -- Invalidate the cached list when the flag flips so the next read rebuilds
  -- with (or without) the FabFilter filter applied. Without this, the cache
  -- stays fixed at whatever filter state was active when the list was first
  -- built, and a live toggle wouldn't affect the installed-FX view.
  if CTX._installed_fx_list_hide_ff ~= hide_ff then
    CTX._installed_fx_list         = nil
    CTX._installed_fx_list_deduped = nil
  end
  CTX._installed_fx_list_hide_ff = hide_ff
  if CTX._installed_fx_list then return CTX._installed_fx_list end
  if not reaper.EnumInstalledFX then return nil end
  CTX._installed_fx_list = {}
  local idx = 0
  -- Hard upper bound is defensive: a misbehaving REAPER build that
  -- returned truthy retval with an empty name forever would otherwise
  -- spin this loop indefinitely. 100k installed FX is far beyond any
  -- realistic library size; the falsy retval still terminates first
  -- on a sane build.
  while idx < 100000 do
    local retval, name = reaper.EnumInstalledFX(idx)
    if not retval or retval == 0 or retval == false then break end
    if name and name ~= "" then
      if not (hide_ff and _is_fabfilter_ident(name)) then
        CTX._installed_fx_list[#CTX._installed_fx_list+1] = name
      end
    end
    idx = idx + 1
  end
  -- Build the VST2/VST3-dedup variant in the same pass. Previously the
  -- UI populated this on first paint of the Preferred Plugins / resolve
  -- popup, which produced a noticeable stall on large FX libraries
  -- (thousands of plugins) the first time those screens opened. Doing
  -- it here folds it into the one-shot enumeration cost.
  do
    local has_vst3, has_vst3i = {}, {}
    for _, iname in ipairs(CTX._installed_fx_list) do
      local base3i = iname:match("^VST3i:%s*(.*)$")
      if base3i then
        base3i = base3i:gsub("%s*%(.-%)%s*$", "")
        has_vst3i[base3i:lower()] = true
      else
        local base3 = iname:match("^VST3:%s*(.*)$")
        if base3 then
          base3 = base3:gsub("%s*%(.-%)%s*$", "")
          has_vst3[base3:lower()] = true
        end
      end
    end
    local dedup = {}
    for _, iname in ipairs(CTX._installed_fx_list) do
      local hide = false
      local vst2i_base = iname:match("^VSTi:%s*(.*)$")
      if vst2i_base then
        vst2i_base = vst2i_base:gsub("%s*%(.-%)%s*$", "")
        if has_vst3i[vst2i_base:lower()] then hide = true end
      else
        local vst2_base = iname:match("^VST:%s*(.*)$")
        if vst2_base then
          vst2_base = vst2_base:gsub("%s*%(.-%)%s*$", "")
          if has_vst3[vst2_base:lower()] then hide = true end
        end
      end
      if not hide then dedup[#dedup+1] = iname end
    end
    CTX._installed_fx_list_deduped = dedup
  end
  return CTX._installed_fx_list
end

-- =============================================================================
-- Searches installed FX plugins by name and returns matching entries.
-- Uses reaper.EnumInstalledFX (REAPER 7.42+). The full list is cached
-- internally; only entries matching the search terms are returned.
-- search_terms is a list of strings to fuzzy-match (uses CTX.fx_name_matches).
-- Returns (formatted_string, match_count) on success, or (nil, error) on failure.
function CTX.installed_fx(search_terms)
  -- Build/cache the full list on first call.
  if not CTX.populate_installed_fx() then
    return nil, "Your REAPER version does not support listing installed plugins "
      .. "(requires REAPER 7.42+)."
  end
  -- Filter to matching entries.
  if not search_terms or #search_terms == 0 then
    return nil, "fx_list requires a plugin name to search for."
  end
  local matches = {}
  for _, name in ipairs(CTX._installed_fx_list) do
    if CTX.fx_name_matches(name, search_terms) then
      matches[#matches+1] = name
    end
  end
  if #matches == 0 then
    return "INSTALLED FX SEARCH (no matches for: "
      .. tbl_concat(search_terms, ", ") .. "):\n"
      .. "No installed plugins matched. The user may be using a nickname or "
      .. "abbreviation. Ask them for the exact name as it appears in their FX browser.",
      0
  end
  -- Format each match inside backticks with a leading dash. Makes it
  -- visually obvious to the model that each identifier is a verbatim
  -- string to copy. Preceded by a strict anti-hallucination header because
  -- C-tier models routinely merge vendor suffixes from CLAP entries onto
  -- VST3 entries (e.g. "VST3: Pro-Q 4" + CLAP's "(FabFilter)" ->
  -- hallucinated "VST3: Pro-Q 4 (FabFilter)" which doesn't exist).
  local quoted = {}
  for _, name in ipairs(matches) do
    quoted[#quoted+1] = "  - `" .. name .. "`"
  end
  return "INSTALLED FX MATCHING " .. tbl_concat(search_terms, ", ") .. ":\n"
    .. tbl_concat(quoted, "\n") .. "\n"
    .. "COPY the chosen identifier CHARACTER-BY-CHARACTER from the list "
    .. "above. Do NOT add vendor names like \"(FabFilter)\" to entries "
    .. "that don't already have them. Do NOT remove suffixes. Each entry "
    .. "above is an EXACT string from EnumInstalledFX; REAPER only "
    .. "accepts these exact strings.\n"
    .. "Pick the BEST match by format priority (VST3 > VSTi > VST > AU > "
    .. "CLAP) and newest version number.",
    #matches
end

-- =============================================================================
-- CTX.scan_fx_params  (unified param scanner)
-- =============================================================================
-- Reads all parameters from an FX instance on a track, applying junk filtering
-- (MIDI CC, host params, generic unnamed, repeating groups 3+) and enum
-- detection (21-probe sweep). Returns a structured table of param entries and
-- the max group number for truncation notes.
--
-- Returns: params_list, max_group, total_param_count
--   params_list: { {idx=N, name="...", default=0.5, display="...", enum={...}}, ... }
--   max_group:   highest numbered group found (0 if none)
--   total_param_count: raw TrackFX_GetNumParams value

function CTX.scan_fx_params(tr, fx_idx)
  local params = {}
  local param_count = R_TrackFX_GetNumParams(tr, fx_idx)
  -- A stale FX handle (plugin removed mid-scan, track deleted) can make
  -- REAPER return nil / -1 instead of a real count. Without this guard
  -- the `param_count - 1` upper bound below and the log concat above
  -- would throw before we get a chance to report a clean failure.
  if type(param_count) ~= "number" or param_count <= 0 then
    return params, 0, 0, false
  end
  Log.line("SCAN", "scan_fx_params start: param_count=" .. param_count)

  -- Readback-lag detection: some VST3 plugins (e.g. Soundtoys) process param
  -- writes on the next audio cycle, so same-tick GetParamNormalized returns the
  -- pre-write value. If detected, we skip enum/range probing (which produces
  -- garbage data under lag) and return needs_deep_scan=true so callers can
  -- trigger a defer-paced deep scan that captures accurate data.
  --
  -- Test design:
  --  * Probe up to 3 params, skipping Bypass / MIDI CC / host-injected names.
  --    Bypass is host-handled (REAPER intercepts it), so it always responds
  --    synchronously even on plugins whose DSP params lag -- probing it alone
  --    would miss real lag (false negative observed on Decapitator).
  --  * Lag means readback returned the OLD value despite the write. Test as:
  --    |orig - probe_val| > 0.5 (the write is meaningfully far from orig) AND
  --    |readback - orig|  < 0.05 (readback stayed at orig).
  --    The naive |readback - probe_val| > 0.1 test catches enum/binary
  --    quantization and produces false positives.
  local needs_deep_scan = false
  if param_count > 0 then
    local probes_done = 0
    for pi = 0, math.min(param_count - 1, 20) do
      if probes_done >= 3 then break end
      local _, pnm = R_TrackFX_GetParamName(tr, fx_idx, pi, "")
      local skip_name = pnm == "Bypass"
        or pnm:match("^CC %d") or pnm:match("^MIDI CC")
        or pnm == "Channel Pressure" or pnm == "Poly Pressure"
        or pnm == "Pitch Bend" or pnm == "Program Change"
      if not skip_name then
        local orig = reaper.TrackFX_GetParamNormalized(tr, fx_idx, pi)
        local probe_val = (orig < 0.5) and 0.9 or 0.1
        reaper.TrackFX_SetParamNormalized(tr, fx_idx, pi, probe_val)
        local readback = reaper.TrackFX_GetParamNormalized(tr, fx_idx, pi)
        reaper.TrackFX_SetParamNormalized(tr, fx_idx, pi, orig)
        probes_done = probes_done + 1
        if math.abs(orig - probe_val) > 0.5
           and math.abs(readback - orig) < 0.05 then
          needs_deep_scan = true
          Log.line("SCAN", "lag_detect: pi=" .. pi .. " name=" .. pnm
            .. " orig=" .. str_format("%.4f", orig)
            .. " probe=" .. str_format("%.4f", probe_val)
            .. " readback=" .. str_format("%.4f", readback)
            .. " -> needs_deep_scan=true")
          break
        end
      end
    end
    if not needs_deep_scan then
      Log.line("SCAN", "lag_detect: " .. probes_done
        .. " params probed, no lag detected")
    end
  end

  -- If we already know this plugin needs a deep scan, skip the main loop:
  -- callers will replace these entries via put_plugin(... deep_results) once
  -- the coroutine-paced deep scan completes. Building ~80 throwaway entries
  -- here just burns API calls on a first-scan that's about to be overwritten.
  if needs_deep_scan then
    return {}, 0, param_count, true
  end

  -- max_group is tracked inline as we visit each param (see the
  -- group_num extraction below). Previously a separate post-loop walk
  -- re-called R_TrackFX_GetParamName for every param just to compute
  -- this -- doubling the API calls per scan on dense plugins.
  local max_group = 0

  for pi = 0, param_count - 1 do
    local _, param_nm = R_TrackFX_GetParamName(tr, fx_idx, pi, "")
    -- Skip MIDI CC automation parameters.
    if param_nm:match("^CC %d") or param_nm:match("^MIDI CC") then
      goto continue_scan
    end
    -- Skip MIDI message params injected by the host.
    if param_nm == "Channel Pressure" or param_nm == "Poly Pressure"
       or param_nm == "Pitch Bend" or param_nm == "Program Change" then
      goto continue_scan
    end
    -- Skip VST3 host-appended params (Bypass/Wet/Delta/Internal at the tail).
    if _is_vst3_tail(param_nm, pi) then
      local _, disp_chk = R_TrackFX_GetFormattedParamValue(tr, fx_idx, pi, "")
      disp_chk = disp_chk or ""
      if disp_chk == "normal" or disp_chk == "-" or disp_chk:match("^%d+$") then
        goto continue_scan
      end
    end
    -- Skip generic "Param N" / "Parameter N" with no useful display value.
    local _, disp = R_TrackFX_GetFormattedParamValue(tr, fx_idx, pi, "")
    disp = disp or ""
    if (param_nm:match("^Param %d+$") or param_nm:match("^Parameter %d+$"))
       and (disp == "" or disp:match("^[%d%.%%]*$")) then
      goto continue_scan
    end
    -- Detect repeating numbered groups. Keep groups 1-2 as reference; skip 3+.
    local group_num = param_nm:match("^%d+")
      or param_nm:match("(%d+) %a")
      or param_nm:match("%(Band (%d+)")
      or param_nm:match("Mod (%d+)")
      or param_nm:match("%s(%d+)$")
    -- Track max_group inline so the trailing re-walk over all params
    -- isn't needed. Captured before the > 2 skip so groups 3+ that get
    -- filtered out still count toward the "highest group" used by the
    -- truncation-note in CTX.format_fx_params.
    if group_num then
      local gn_n = tonumber(group_num)
      if gn_n and gn_n > max_group then max_group = gn_n end
    end
    if group_num and tonumber(group_num) > 2 then
      goto continue_scan
    end
    local val, mn, mx = R_TrackFX_GetParam(tr, fx_idx, pi)
    local norm = 0
    if mx ~= mn then norm = (val - mn) / (mx - mn) end
    -- Probe 21 evenly-spaced normalised values: 2-20 distinct display
    -- strings -> record as enum; otherwise capture display@0 / display@1
    -- so the model knows the API display range. The earlier early-return
    -- at "if needs_deep_scan then return ..." above guarantees
    -- needs_deep_scan is false here, so no `if not needs_deep_scan`
    -- wrapper is needed.
    local enum_list = nil
    local disp_at_min, disp_at_max = nil, nil
    local probe_seen, probe_order = {}, {}
    local orig_norm = reaper.TrackFX_GetParamNormalized(tr, fx_idx, pi)
    for pn = 0, 20 do
      local pv = pn / 20
      reaper.TrackFX_SetParamNormalized(tr, fx_idx, pi, pv)
      local _, pd = R_TrackFX_GetFormattedParamValue(tr, fx_idx, pi, "")
      if pn == 0  then disp_at_min = pd end
      if pn == 20 then disp_at_max = pd end
      if not probe_seen[pd] then
        probe_seen[pd] = true
        probe_order[#probe_order+1] = pd
      end
    end
    reaper.TrackFX_SetParamNormalized(tr, fx_idx, pi, orig_norm)
    if #probe_order >= 2 and #probe_order <= 20 then
      enum_list = probe_order
    end
    local entry = {
      idx     = pi,
      name    = param_nm,
      default = tonumber(str_format("%.4f", norm)),
      display = disp,
    }
    if enum_list then entry.enum = enum_list end
    -- Store display range for continuous params so the model can detect
    -- API-vs-GUI display scale mismatches and compute normalized values.
    -- If min == max, the param is read-only / host-driven (e.g. Tempo
    -- reflecting project tempo) - the range would mislead the model.
    if not enum_list and disp_at_min and disp_at_max
       and disp_at_min ~= disp_at_max then
      entry.display_min = disp_at_min
      entry.display_max = disp_at_max
    end
    params[#params+1] = entry
    ::continue_scan::
  end

  -- max_group is now tracked inline within the main param loop above.

  -- Cap cached params to keep cache files and LLM context manageable.
  -- Main controls are at low indices; modulation/sequencer/slot params at
  -- higher indices are omitted. Use find_param at runtime for those.
  if #params > CFG.MAX_CACHED_PARAMS then
    local trimmed = {}
    for i = 1, CFG.MAX_CACHED_PARAMS do trimmed[i] = params[i] end
    params = trimmed
  end

  Log.line("SCAN", "scan_fx_params done: kept=" .. #params
    .. " max_group=" .. max_group
    .. " needs_deep_scan=" .. tostring(needs_deep_scan))
  return params, max_group, param_count, needs_deep_scan
end

-- =============================================================================
-- CTX.scan_fx_params_deep  (coroutine, defer-paced)
-- =============================================================================
-- Same filters + probe strategy as scan_fx_params, but yields one REAPER frame
-- between each param write and readback so VST3 plugins with one-cycle
-- readback lag (Soundtoys etc.) return accurate enum/range data. Intended to
-- run inside a coroutine resumed from loop().
--
-- Returns (via coroutine end): params_list, max_group, total_param_count

local function _fx_param_filter_skip(param_nm, disp)
  -- REAPER's TrackFX_GetFormattedParamValue can return nil for plugins
  -- that don't supply a formatted value (some VST3 host params, certain
  -- internal slots). Coerce so callers that pattern-match on disp aren't
  -- on the hook for the guard.
  disp = disp or ""
  if param_nm:match("^CC %d") or param_nm:match("^MIDI CC") then return true end
  if param_nm == "Channel Pressure" or param_nm == "Poly Pressure"
     or param_nm == "Pitch Bend" or param_nm == "Program Change" then
    return true
  end
  if (param_nm:match("^Param %d+$") or param_nm:match("^Parameter %d+$"))
     and (disp == "" or disp:match("^[%d%.%%]*$")) then
    return true
  end
  local group_num = param_nm:match("^%d+")
    or param_nm:match("(%d+) %a")
    or param_nm:match("%(Band (%d+)")
    or param_nm:match("Mod (%d+)")
    or param_nm:match("%s(%d+)$")
  if group_num and tonumber(group_num) > 2 then return true end
  return false
end

function CTX.scan_fx_params_deep_body(tr, fx_idx)
  local params = {}
  local max_group = 0
  local param_count = R_TrackFX_GetNumParams(tr, fx_idx)
  -- See CTX.scan_fx_params for the same guard's rationale; a stale FX
  -- handle here would crash on the log concat and the `0, param_count - 1`
  -- loop below.
  if type(param_count) ~= "number" or param_count <= 0 then
    return params, 0, 0
  end
  Log.line("DEEP_SCAN", "scan_fx_params_deep start: param_count=" .. param_count)

  -- Release the UI-refresh lock that fx_inspect_load held. Holding
  -- PreventUIRefresh(+1) across many defer cycles can put REAPER into
  -- a bad internal state and, combined with rapid VST3 param writes,
  -- has produced hard crashes. The cleanup callbacks will not call
  -- PreventUIRefresh(-1) again, since we released it here.
  reaper.PreventUIRefresh(-1)
  deep_scan._ui_refresh_released = true

  -- Helper: confirm the track pointer + plugin slot are still alive.
  -- REAPER invalidates MediaTrack pointers on project reloads, track
  -- deletions, and some undo actions. Touching a dead pointer with
  -- TrackFX_* is a segfault.
  local function _alive()
    if not reaper.ValidatePtr2(0, tr, "MediaTrack*") then return false end
    if R_TrackFX_GetNumParams(tr, fx_idx) <= 0 then return false end
    return true
  end

  for pi = 0, param_count - 1 do
    if deep_scan.cancel_req then return params, 0, param_count end
    if not _alive() then
      Log.line("DEEP_SCAN", "track/fx invalidated at pi=" .. pi .. " -- aborting")
      deep_scan.cancel_req = true
      return params, 0, param_count
    end
    -- Cap at probe time (not trim time) so giant plugins with 500+ params
    -- don't spend minutes probing entries we'd just drop on the floor.
    if #params >= CFG.MAX_CACHED_PARAMS then
      Log.line("DEEP_SCAN", "reached MAX_CACHED_PARAMS cap at pi=" .. pi .. ", stopping probe")
      break
    end

    -- Grab the name up front for filter checks + heavy-selector match.
    local _, _probe_nm = R_TrackFX_GetParamName(tr, fx_idx, pi, "")

    -- Track the highest group number seen, captured before the filter
    -- skip below so groups 3+ that get dropped still inform max_group
    -- (used by CTX.format_fx_params for the "shown groups 1-2 of N"
    -- truncation note). Replaces a trailing per-param re-walk.
    do
      local _gn = _probe_nm:match("^%d+")
        or _probe_nm:match("(%d+) %a")
        or _probe_nm:match("%(Band (%d+)")
        or _probe_nm:match("Mod (%d+)")
        or _probe_nm:match("%s(%d+)$")
      if _gn then
        local _gn_n = tonumber(_gn)
        if _gn_n and _gn_n > max_group then max_group = _gn_n end
      end
    end

    -- Apply the same name/group filter the shallow scan uses (and the deep-
    -- scan progress estimator already uses). Without this, repeating numbered
    -- groups (Pro-C 3's Side Chain EQ Bands 3-6, multi-mod plugins' Mod 3+)
    -- get fully probed even though shallow scan dropped them -- a 6-band
    -- plugin wastes ~4 bands x ~9 params x 21 probes = ~750 probes here.
    -- Saves ~50s of wall time on Pro-C 3-class plugins.
    local _, _probe_disp = R_TrackFX_GetFormattedParamValue(tr, fx_idx, pi, "")
    if _fx_param_filter_skip(_probe_nm, _probe_disp) then
      goto continue_deep
    end

    -- Fast-path: Bypass is always a binary Off/On enum, host-handled by
    -- REAPER. Synthesize the entry directly to skip ~21 yield cycles
    -- (~1.4s + plugin GUI flicker) of redundant sweeping.
    if _probe_nm == "Bypass" then
      local val, mn, mx = R_TrackFX_GetParam(tr, fx_idx, pi)
      local norm = 0
      if mx ~= mn then norm = (val - mn) / (mx - mn) end
      local _, d = R_TrackFX_GetFormattedParamValue(tr, fx_idx, pi, "")
      params[#params+1] = {
        idx     = pi,
        name    = _probe_nm,
        default = tonumber(str_format("%.4f", norm)),
        display = d,
        enum    = { "Off", "On" },
      }
      Log.line("DEEP_SCAN", "pi=" .. pi .. " name=Bypass -- fast-path synthesized")
      goto continue_deep
    end

    -- Heavy-selector candidate: params whose values *might* trigger expensive
    -- DSP reinit (impulse-response reload, sample-library swap, algorithm
    -- rewire). Name pattern is a hint, not a verdict -- some matches are
    -- lightweight (Decapitator's Style is just a saturation curve), others
    -- can hard-crash the plugin under rapid sweep (EchoBoy's Style swaps
    -- tape IRs). A single isolated write is safe on any plugin (the user
    -- changes Style manually all the time without crash); only RAPID writes
    -- queue faster than the asset loader can process and trip the race.
    --
    -- Strategy: do ONE calibration write, watch how long the plugin takes
    -- to settle (display changes from orig). Light -> fall through to full
    -- sweep. Heavy -> cooldown wait, restore orig with another wait, record
    -- bare entry. At most two writes spaced ~1s apart -- never a queue.
    local low_nm = _probe_nm:lower()
    local is_heavy_candidate =
         low_nm == "style"     or low_nm:match("^style$")
      or low_nm == "algorithm" or low_nm:match("algorithm")
      or low_nm == "engine"    or low_nm:match("^engine$")
      or low_nm == "character" or low_nm:match("^character$")
      or low_nm == "preset"    or low_nm:match("preset")
      or low_nm == "model"     or low_nm:match("^model$")
    if is_heavy_candidate then
      local CALIBRATION_MAX_YIELDS = 30  -- ~1s at 30fps
      local cal_orig = reaper.TrackFX_GetParamNormalized(tr, fx_idx, pi)
      local _, cal_orig_disp = R_TrackFX_GetFormattedParamValue(tr, fx_idx, pi, "")
      local cal_probe = (cal_orig < 0.5) and 1.0 or 0.0
      Log.line("DEEP_SCAN", "pi=" .. pi .. " name=" .. _probe_nm
        .. " -- calibrating (orig_disp=" .. tostring(cal_orig_disp)
        .. " probe=" .. cal_probe .. ")")
      reaper.TrackFX_SetParamNormalized(tr, fx_idx, pi, cal_probe)
      local settled = false
      for _try = 1, CALIBRATION_MAX_YIELDS do
        if deep_scan.cancel_req then
          if _alive() then
            reaper.TrackFX_SetParamNormalized(tr, fx_idx, pi, cal_orig)
          end
          return params, 0, param_count
        end
        coroutine.yield()
        if not _alive() then
          Log.line("DEEP_SCAN", "track/fx invalidated during calibration -- aborting")
          deep_scan.cancel_req = true
          return params, 0, param_count
        end
        local _, dnow = R_TrackFX_GetFormattedParamValue(tr, fx_idx, pi, "")
        if dnow ~= cal_orig_disp then settled = true; break end
      end

      if not settled then
        -- Heavy DSP detected. Cool down BEFORE restoring orig so the
        -- in-progress load can finish first (avoids stacking two heavy
        -- loads back-to-back). Then write orig and wait again. Bare entry.
        Log.line("DEEP_SCAN", "pi=" .. pi .. " name=" .. _probe_nm
          .. " -- HEAVY (no settle in " .. CALIBRATION_MAX_YIELDS
          .. " yields), cooling down + synthesizing bare entry")
        -- Estimator budgeted 21 probes for this param; the heavy path skips
        -- the standard sweep without incrementing probes_done, so retract
        -- the budget here to keep the progress bar denominator honest.
        deep_scan.total_probes = math_max(0, deep_scan.total_probes - 21)
        for _ = 1, CALIBRATION_MAX_YIELDS do
          if deep_scan.cancel_req or not _alive() then break end
          coroutine.yield()
        end
        if _alive() then
          reaper.TrackFX_SetParamNormalized(tr, fx_idx, pi, cal_orig)
          for _ = 1, CALIBRATION_MAX_YIELDS do
            if deep_scan.cancel_req or not _alive() then break end
            coroutine.yield()
          end
        end
        local val, mn, mx = R_TrackFX_GetParam(tr, fx_idx, pi)
        local norm = 0
        if mx ~= mn then norm = (val - mn) / (mx - mn) end
        params[#params+1] = {
          idx     = pi,
          name    = _probe_nm,
          default = tonumber(str_format("%.4f", norm)),
          display = cal_orig_disp,
          -- Intentionally no enum / display_min / display_max: LLM should
          -- find_param at runtime if it needs a specific value.
        }
        goto continue_deep
      end

      -- Light: restore orig, give one frame to settle, then fall through
      -- to the standard sweep below.
      reaper.TrackFX_SetParamNormalized(tr, fx_idx, pi, cal_orig)
      coroutine.yield()
      Log.line("DEEP_SCAN", "pi=" .. pi .. " name=" .. _probe_nm
        .. " -- calibration ok (light), proceeding with full sweep")
    end

    local _, param_nm = R_TrackFX_GetParamName(tr, fx_idx, pi, "")

    -- Deferred disp read: fetch current display before any filter so we can
    -- pass it to the generic-param filter. Peek without yielding.
    local _, disp = R_TrackFX_GetFormattedParamValue(tr, fx_idx, pi, "")
    disp = disp or ""

    -- VST3 host-appended tail params (Bypass/Wet/Delta/Internal).
    if _is_vst3_tail(param_nm, pi) then
      if disp == "normal" or disp == "-" or disp:match("^%d+$") then
        goto continue_deep
      end
    end

    if _fx_param_filter_skip(param_nm, disp) then goto continue_deep end

    -- Per-param log breadcrumb so a crash mid-probe tells us exactly
    -- which param index the plugin died on. Logged AFTER filters so the
    -- log only shows params that actually get swept.
    Log.line("DEEP_SCAN", "probing pi=" .. pi .. " name=" .. tostring(_probe_nm))

    -- Standard 21-probe sweep, yielding between write and readback so the
    -- plugin has a full frame to propagate the set before we read the
    -- formatted display. Orig norm is restored after probing.
    do
      local val, mn, mx = R_TrackFX_GetParam(tr, fx_idx, pi)
      local norm = 0
      if mx ~= mn then norm = (val - mn) / (mx - mn) end

      local orig_norm = reaper.TrackFX_GetParamNormalized(tr, fx_idx, pi)
      local probe_seen, probe_order = {}, {}
      local disp_at_min, disp_at_max = nil, nil

      -- Heavy-candidate pacing: instead of a fixed 2-frame gap between probes
      -- (which queues IR loads faster than the plugin's asset loader can
      -- process, crashing REAPER on e.g. EchoBoy Style at ~21 swaps), wait
      -- after each write until the display has been stable for
      -- STABLE_FRAMES_HEAVY consecutive frames or the hard cap is reached.
      -- Each IR/preset finishes loading before the next probe fires.
      -- If 3 probes in a row hit the cap (display never stabilizes), bail
      -- out for this param -- the plugin is misbehaving and no amount of
      -- extra probing will produce trustworthy enum data.
      local STABLE_FRAMES_HEAVY   = 3   -- must match N frames in a row to call "settled"
      local MAX_YIELDS_HEAVY      = 30  -- ~1 second cap per probe at 30fps
      local MAX_CONSEC_STUCK      = 3   -- abort-sweep threshold
      local heavy_sweep_aborted   = false
      local consec_stuck          = 0

      for pn = 0, 20 do
        if heavy_sweep_aborted then break end
        if deep_scan.cancel_req then
          if _alive() then
            reaper.TrackFX_SetParamNormalized(tr, fx_idx, pi, orig_norm)
          end
          return params, 0, param_count
        end
        if not _alive() then
          Log.line("DEEP_SCAN", "track/fx invalidated mid-probe -- aborting")
          deep_scan.cancel_req = true
          return params, 0, param_count
        end
        local pv = pn / 20
        reaper.TrackFX_SetParamNormalized(tr, fx_idx, pi, pv)
        if is_heavy_candidate then
          -- Settle-wait: loop yielding until display stabilizes.
          local last_disp, stable = nil, 0
          local settled = false
          for _y = 1, MAX_YIELDS_HEAVY do
            coroutine.yield()
            if deep_scan.cancel_req then
              if _alive() then
                reaper.TrackFX_SetParamNormalized(tr, fx_idx, pi, orig_norm)
              end
              return params, 0, param_count
            end
            if not _alive() then
              Log.line("DEEP_SCAN", "track/fx invalidated during settle-wait -- aborting")
              deep_scan.cancel_req = true
              return params, 0, param_count
            end
            local _, cur = R_TrackFX_GetFormattedParamValue(tr, fx_idx, pi, "")
            if cur == last_disp then
              stable = stable + 1
              if stable >= STABLE_FRAMES_HEAVY then
                settled = true
                break
              end
            else
              stable = 0
              last_disp = cur
            end
          end
          if settled then
            consec_stuck = 0
          else
            consec_stuck = consec_stuck + 1
            if consec_stuck >= MAX_CONSEC_STUCK then
              Log.line("DEEP_SCAN", "pi=" .. pi .. " name=" .. _probe_nm
                .. " -- " .. MAX_CONSEC_STUCK
                .. " consecutive probes never settled, aborting sweep (bare entry will be synthesized)")
              heavy_sweep_aborted = true
              -- Refund the remaining budget so the progress bar stays honest.
              -- pn is the probe that just failed (probes_done was NOT yet
              -- incremented for it), so `21 - pn` covers this probe plus the
              -- 20-pn still-untried iterations.
              local remaining = 21 - pn
              if remaining > 0 then
                deep_scan.total_probes = math_max(0, deep_scan.total_probes - remaining)
              end
              break
            end
          end
        else
          coroutine.yield()  -- wait 1 frame
          coroutine.yield()  -- extra frame: some VST3s crash under rapid-fire
                             -- writes; giving two frames between write+read
                             -- lets audio thread process at least one buffer.
        end
        if not _alive() then
          Log.line("DEEP_SCAN", "track/fx invalidated after yield -- aborting")
          deep_scan.cancel_req = true
          return params, 0, param_count
        end
        local _, pd = R_TrackFX_GetFormattedParamValue(tr, fx_idx, pi, "")
        if pn == 0  then disp_at_min = pd end
        if pn == 20 then disp_at_max = pd end
        if not probe_seen[pd] then
          probe_seen[pd] = true
          probe_order[#probe_order+1] = pd
        end
        deep_scan.probes_done = deep_scan.probes_done + 1
      end

      -- Aborted heavy sweep: restore orig and synthesize bare entry, then
      -- skip the rest of this iteration (endpoint check / extended pass /
      -- normal record).
      if heavy_sweep_aborted then
        if _alive() then
          reaper.TrackFX_SetParamNormalized(tr, fx_idx, pi, orig_norm)
          for _ = 1, MAX_YIELDS_HEAVY do
            if deep_scan.cancel_req or not _alive() then break end
            coroutine.yield()
          end
        end
        local bare_val, bare_mn, bare_mx = R_TrackFX_GetParam(tr, fx_idx, pi)
        local bare_norm = 0
        if bare_mx ~= bare_mn then bare_norm = (bare_val - bare_mn) / (bare_mx - bare_mn) end
        local _, bare_disp = R_TrackFX_GetFormattedParamValue(tr, fx_idx, pi, "")
        params[#params+1] = {
          idx     = pi,
          name    = _probe_nm,
          default = tonumber(str_format("%.4f", bare_norm)),
          display = bare_disp,
        }
        goto continue_deep
      end

      -- Determine whether endpoints look numeric (real range) or text
      -- (enum/preset list). Match requires the display to be a number with
      -- optional sign/decimal and an optional unit suffix composed of
      -- letters, spaces, slashes, or percent signs. This correctly rejects
      -- tokens like "1/64th" or "1/2 note" (digits embedded in unit) which
      -- are enum entries, not ranges.
      local function _looks_numeric(s)
        if not s or s == "" then return false end
        local clean = s:gsub(",", ""):match("^%s*(.-)%s*$")
        return clean:match("^[-+]?%d*%.?%d+[%a%s/%%]*$") ~= nil
      end
      local endpoints_numeric = _looks_numeric(disp_at_min) and _looks_numeric(disp_at_max)

      -- If endpoints are non-numeric, this is almost certainly an enum/preset
      -- list, possibly with more than 21 distinct values (e.g. EchoBoy Style
      -- has ~30 presets). Do a second interleaved pass at midpoints between
      -- the first-pass positions to capture more distinct values.
      --
      -- SAFETY GATE: heavy-named params (style/algorithm/engine/...) DO NOT
      -- get the extended pass. Calibration only measures display latency, not
      -- burst safety -- EchoBoy Style calibrates as "light" yet crashes at
      -- 41 IR-swaps. Cap heavy params at the empirically-safe 21 probes; the
      -- resulting enum is flagged `enum_partial` below so the model knows to
      -- use the paced runtime helper if the user's target is not in the cache.
      --
      -- RICHNESS GATE: also skip the extended pass for small enums. If the
      -- first 21 probes surfaced fewer than 15 distinct values, the enum is
      -- almost certainly small (Mode=4, HighSlope=2, PrimeNumbers=2, etc.)
      -- and the first pass already captured everything. The second pass
      -- would just re-observe the same handful of values at a cost of ~2s
      -- per param. Only extend when the first pass hit the "rich" threshold,
      -- suggesting there are more distinct values to discover.
      if not endpoints_numeric and not is_heavy_candidate
         and #probe_order >= 15 then
        -- Extended pass commits now -- grow the progress total so the bar
        -- tracks real work. Estimator only budgeted the first pass.
        deep_scan.total_probes = deep_scan.total_probes + 20
        for pn = 0, 19 do
          if deep_scan.cancel_req then
            if _alive() then
              reaper.TrackFX_SetParamNormalized(tr, fx_idx, pi, orig_norm)
            end
            return params, 0, param_count
          end
          if not _alive() then
            Log.line("DEEP_SCAN", "track/fx invalidated mid-probe2 -- aborting")
            deep_scan.cancel_req = true
            return params, 0, param_count
          end
          local pv = (2 * pn + 1) / 40  -- midpoint between pn/20 and (pn+1)/20
          reaper.TrackFX_SetParamNormalized(tr, fx_idx, pi, pv)
          coroutine.yield()
          coroutine.yield()
          if not _alive() then
            Log.line("DEEP_SCAN", "track/fx invalidated after yield2 -- aborting")
            deep_scan.cancel_req = true
            return params, 0, param_count
          end
          local _, pd = R_TrackFX_GetFormattedParamValue(tr, fx_idx, pi, "")
          if not probe_seen[pd] then
            probe_seen[pd] = true
            probe_order[#probe_order+1] = pd
          end
          deep_scan.probes_done = deep_scan.probes_done + 1
        end
      end

      reaper.TrackFX_SetParamNormalized(tr, fx_idx, pi, orig_norm)
      coroutine.yield()  -- one more frame so the restore doesn't bleed into the next read

      -- Post-restore display for the entry (after one-frame settle).
      local _, disp_after = R_TrackFX_GetFormattedParamValue(tr, fx_idx, pi, "")
      local entry = {
        idx     = pi,
        name    = param_nm,
        default = tonumber(str_format("%.4f", norm)),
        display = disp_after,
      }
      -- Classify by endpoint content, not just probe count:
      --   numeric endpoints           -> range (display_min/max)
      --   non-numeric, 2..64 distinct -> enum (full preset list)
      --   else if distinct endpoints  -> fallback string range (rare)
      --   else                        -> plain (no annotation; e.g. host-driven)
      if endpoints_numeric then
        if disp_at_min ~= disp_at_max then
          entry.display_min = disp_at_min
          entry.display_max = disp_at_max
        end
      elseif #probe_order >= 2 and #probe_order <= 64 then
        entry.enum = probe_order
        -- Heavy params capped at 21 probes may have more enum values than we
        -- captured. Mark partial so the model falls back to the paced runtime
        -- helper when the target isn't among the cached entries.
        if is_heavy_candidate then entry.enum_partial = true end
      elseif disp_at_min and disp_at_max and disp_at_min ~= disp_at_max then
        entry.display_min = disp_at_min
        entry.display_max = disp_at_max
      end
      params[#params+1] = entry
    end
    ::continue_deep::
  end

  -- max_group tracked inline within the param probe loop above.
  -- No post-loop trim needed: the loop body breaks at `#params >=
  -- MAX_CACHED_PARAMS` (probe-time cap, not trim-time), so by the time
  -- we get here #params is already <= the cap.

  Log.line("DEEP_SCAN", "scan_fx_params_deep done: kept=" .. #params
    .. " max_group=" .. max_group)
  return params, max_group, param_count
end

-- Estimate probe count for progress UI. Heavy-named params get 21 probes
-- (capped for burst-safety). Non-heavy params MAY get an extra 20-probe
-- interleaved pass if their endpoints are non-numeric; we can't tell in
-- advance, so we budget 41 for non-heavy to guarantee the progress bar
-- never goes over 100%. (Numeric non-heavy params finish faster than the
-- budget, so the bar simply completes early -- acceptable.)
local function _estimate_deep_probes(tr, fx_idx)
  local n = R_TrackFX_GetNumParams(tr, fx_idx)
  -- A stale FX handle could return nil / -1; the `0, n - 1` loop below
  -- would then crash on the comparison. Returning 0 makes the caller
  -- treat the budget as "no work to do", which is correct -- the scan
  -- body's matching guard will refuse to run anyway.
  if type(n) ~= "number" or n <= 0 then return 0 end
  local total = 0
  local kept = 0
  for pi = 0, n - 1 do
    local _, nm = R_TrackFX_GetParamName(tr, fx_idx, pi, "")
    local _, d  = R_TrackFX_GetFormattedParamValue(tr, fx_idx, pi, "")
    d = d or ""
    local skip = _fx_param_filter_skip(nm, d)
    -- Mirror the VST3-tail filter that's inlined in scan_fx_params so our
    -- progress total matches the probes actually performed.
    if not skip and _is_vst3_tail(nm, pi) then
      if d == "normal" or d == "-" or d:match("^%d+$") then skip = true end
    end
    if not skip then
      kept = kept + 1
      -- Bypass is fast-path synthesized in scan_fx_params_deep_body (0 probes).
      -- Exclude it from the budget so the progress bar doesn't overcount.
      if nm ~= "Bypass" then
        -- Base budget: the guaranteed first pass (21 probes at pn=0..20).
        -- The optional +20 extended pass is added dynamically inside the deep
        -- scan body at the moment it commits to running, so the total stays
        -- honest whether or not the extension triggers.
        total = total + 21
      end
      if kept >= CFG.MAX_CACHED_PARAMS then break end  -- matches the probe-time cap in scan_fx_params_deep_body
    end
  end
  return total
end

-- Start a deep scan. The temp track + plugin must already be loaded and
-- passed in; this function does NOT create the track. `on_complete` is called
-- with (params_list, max_group, total_param_count) when the coroutine
-- finishes. `on_cancel` is called with no args if the user cancels or an
-- error occurs (caller is responsible for cleaning up the temp track in both
-- success and cancel paths).
function CTX.start_deep_scan(opts)
  if deep_scan.active then
    Log.line("DEEP_SCAN", "start_deep_scan: already active, ignoring")
    return false
  end
  -- Validate inputs up front. Without these, the coroutine body would crash
  -- on first resume with cryptic nil-deref errors and the scan would still
  -- have been marked active, blocking future scans until manual reset.
  if not opts or not opts.tr or not opts.fx_idx then
    Log.line("DEEP_SCAN", "start_deep_scan: missing tr/fx_idx, ignoring")
    return false
  end
  -- Build everything as locals first; commit to the deep_scan table only
  -- after every step succeeds. Previously the function set deep_scan.active
  -- early then computed total_probes / built the coroutine -- if any of
  -- those threw, the scan was wedged at active=true with coro=nil, and
  -- pump_deep_scan would silently no-op forever.
  local ok_est, est = pcall(_estimate_deep_probes, opts.tr, opts.fx_idx)
  if not ok_est then
    Log.line("DEEP_SCAN", "estimate_deep_probes error: " .. tostring(est))
    return false
  end
  local co = coroutine.create(function()
    return CTX.scan_fx_params_deep_body(opts.tr, opts.fx_idx)
  end)
  -- Single commit point. Order: clear cancel flag, populate fields, then
  -- flip active=true LAST so pump_deep_scan can never observe a half-built
  -- state (active=true, coro=nil).
  deep_scan.cancel_req   = false
  deep_scan.tr           = opts.tr
  deep_scan.fx_idx       = opts.fx_idx
  deep_scan.identifier   = opts.identifier
  deep_scan.search_names = opts.search_names
  deep_scan.origin       = opts.origin or "chat"
  deep_scan.on_complete  = opts.on_complete
  deep_scan.on_cancel    = opts.on_cancel
  deep_scan.started_at   = time_precise()
  deep_scan.probes_done  = 0
  deep_scan.total_probes = est or 0
  deep_scan.coro         = co
  deep_scan.active       = true
  Log.line("DEEP_SCAN", "started: " .. (opts.identifier or "?")
    .. " est_probes=" .. deep_scan.total_probes
    .. " origin=" .. deep_scan.origin)
  -- Auto-scroll the chat: the explainer + progress block grows the status
  -- area by a few lines, which would otherwise push the new content below
  -- the visible area without moving the viewport.
  if deep_scan.origin == "chat" then S.scroll_to_bottom = true end
  return true
end

-- Ask the running deep scan to stop at its next yield point. The coroutine
-- body checks deep_scan.cancel_req and returns early.
function CTX.cancel_deep_scan()
  if not deep_scan.active then return end
  Log.line("DEEP_SCAN", "cancel requested")
  deep_scan.cancel_req = true
end

-- Resume the deep-scan coroutine one step. Called from loop() each frame.
function CTX.pump_deep_scan()
  if not deep_scan.active or not deep_scan.coro then return end
  local co = deep_scan.coro
  local ok, a, b, c = coroutine.resume(co)
  if not ok then
    Log.line("DEEP_SCAN", "coroutine error: " .. tostring(a))
    local cb = deep_scan.on_cancel
    deep_scan.active = false
    deep_scan.coro   = nil
    if cb then cb(tostring(a)) end
    return
  end
  if coroutine.status(co) == "dead" then
    -- a/b/c = params_list, max_group, total_param_count (from return)
    local cancelled = deep_scan.cancel_req
    local cb_complete = deep_scan.on_complete
    local cb_cancel   = deep_scan.on_cancel
    deep_scan.active = false
    deep_scan.coro   = nil
    if cancelled then
      if cb_cancel then cb_cancel("cancelled") end
    else
      if cb_complete then cb_complete(a or {}, b or 0, c or 0) end
    end
  end
end

-- Derive the GetByName-safe "display name" form of an EnumInstalledFX
-- identifier. REAPER reports two distinct name spaces for FX: the registry
-- identifier (what TrackFX_AddByName accepts -- e.g. "VST3: Manipulator
-- (Polyverse Music)") and the loaded-instance display name (what
-- TrackFX_GetByName matches against, what TrackFX_GetFXName returns --
-- e.g. just "Manipulator"). Using the long identifier with GetByName
-- silently fails -- the model previously hit this path repeatedly.
-- Strips the format prefix and the trailing vendor suffix.
local function _derive_display_name(identifier)
  if not identifier or identifier == "" then return identifier end
  local s = identifier:gsub("^[%w]+:%s*", "")     -- "VST3: " / "VST: " / "AU: " / "CLAP: " / "JS: "
  s = s:gsub("%s*%([^)]+%)%s*$", "")              -- " (Polyverse Music)"
  return s
end

-- Format scanned param data (table) into the text format the LLM expects.
-- Used by both fx_inspect and preferred_plugins context buckets.
function CTX.format_fx_params(identifier, params_list, max_group, search_names, is_inspect)
  local lines = {}
  local display_name = _derive_display_name(identifier)
  if is_inspect then
    lines[#lines+1] = "FX INSPECT (" .. tbl_concat(search_names or {}, ", ") .. "):"
    lines[#lines+1] = "AddByName identifier (use with TrackFX_AddByName): " .. identifier
    if display_name and display_name ~= identifier then
      lines[#lines+1] = "GetByName display name (use with TrackFX_GetByName / TrackFX_GetCount loops): "
        .. display_name
      lines[#lines+1] = "WARNING: TrackFX_GetByName matches against the display name, NOT the AddByName identifier. Passing the long identifier with the vendor suffix WILL return -1 even when the plugin is loaded."
    end
    lines[#lines+1] = "IMPORTANT: Use the EXACT parameter indices [N] below. Do NOT use find_param to re-discover them."
    lines[#lines+1] = "Apply the DECIDE FIRST flowchart in your instructions (prompt_bundle:plugin) per param. Include helper definitions (find_param, set_param_display, set_param_enum, set_param_enum_paced) ONLY if your script actually calls them."
  else
    lines[#lines+1] = "AddByName identifier: " .. identifier
    if display_name and display_name ~= identifier then
      lines[#lines+1] = "GetByName display name: " .. display_name
    end
  end
  lines[#lines+1] = ""
  for _, p in ipairs(params_list) do
    -- Display value first (human-readable), normalized in brackets.
    if p.enum then
      local partial_tag = p.enum_partial and "  [partial]" or ""
      lines[#lines+1] = str_format("  [%d] %s: %s  [norm: %.4f]  [enum: %s]%s",
        p.idx, p.name, p.display, p.default, tbl_concat(p.enum, ", "), partial_tag)
    elseif p.display_min and p.display_max then
      lines[#lines+1] = str_format("  [%d] %s: %s  [norm: %.4f]  [range: %s..%s]",
        p.idx, p.name, p.display, p.default, p.display_min, p.display_max)
    else
      lines[#lines+1] = str_format("  [%d] %s: %s  [norm: %.4f]",
        p.idx, p.name, p.display, p.default)
    end
  end
  if max_group and max_group > 2 then
    lines[#lines+1] = str_format(
      "(Bands/groups 3-%d follow the same parameter pattern as 1-2. "
      .. "Use the same param names with the group number replaced.)", max_group)
  end
  -- Note if the param list was capped during scanning.
  if #params_list >= 80 then
    lines[#lines+1] = "(Additional modulation/sequencer params exist beyond this list. "
      .. "Use find_param at runtime to access them.)"
  end
  return tbl_concat(lines, "\n")
end

-- =============================================================================
-- CTX.fx_inspect  (on-demand scoped bucket - two-phase, async)
-- =============================================================================
-- Temporarily loads a plugin to discover its parameter names, indices, and
-- default display values. Used when the model needs to configure a third-party
-- plugin it has no cached metadata for.
--
-- Phase 1 (fx_inspect_load): searches installed plugins, inserts a temp track
-- at the end of the track list, and adds the best-matching plugin. Phase 2
-- (params read + cleanup) is handled inline in finalize_context so the
-- shallow-vs-deep-scan branch can share state with the rest of the turn.

function CTX.fx_inspect_load(search_names)
  if not search_names or #search_names == 0 then
    return nil, nil, nil, "fx_inspect requires a plugin name to search for."
  end
  Log.line("FX_INSPECT", "fx_inspect_load: search=" .. tbl_concat(search_names, ", "))

  -- Reuse installed_fx to find matching identifiers.
  local fl_content, fl_result = CTX.installed_fx(search_names)
  if not fl_content or fl_result == 0 then
    return nil, nil, nil, "No installed plugins matched: "
      .. tbl_concat(search_names, ", ")
      .. ". Ask the user for the exact name as it appears in their FX browser."
  end

  -- Pick the best match: prefer VST3, then CLAP, then first overall.
  -- installed_fx wraps each entry as `  - `VST3: Name`` (markdown bullet +
  -- backticks) for anti-hallucination; strip that before format-priority
  -- matching so TrackFX_AddByName receives the bare identifier.
  local best_id, first_id = nil, nil
  for line in fl_content:gmatch("[^\n]+") do
    local id = line:match("^%s*%-%s*`(.-)`%s*$")
    if id then
      if not first_id then first_id = id end
      if not best_id and id:find("^VST3:") then best_id = id end
      if not best_id and id:find("^CLAP:") then best_id = id end
    end
  end
  best_id = best_id or first_id
  if not best_id then
    return nil, nil, nil, "Could not determine plugin identifier from search results."
  end

  -- Check the FX cache. If this plugin is already cached and the param count
  -- hasn't changed (proxy for version updates), return cached data directly.
  local cached = FXCache.get_plugin(best_id)
  if cached and cached.params then
    Log.line("FX_INSPECT", "cache HIT: " .. best_id
      .. " (" .. #cached.params .. " params"
      .. (cached.needs_deep_scan and ", needs_deep_scan" or "") .. ")")
    -- Return nil track (no temp track needed), nil fx, identifier, nil error, cached data.
    return nil, nil, best_id, nil, cached
  end
  Log.line("FX_INSPECT", "cache MISS: " .. best_id .. " -- scanning")

  -- Insert temp track at end, add plugin. Wrap in an explicit undo block so
  -- the flags=0 Undo_EndBlock in the read phase discards our own edits
  -- cleanly; without a matching Begin, the End would mismatch the stack.
  reaper.Undo_BeginBlock()
  reaper.PreventUIRefresh(1)
  local track_count = R_CountTracks(0)
  reaper.InsertTrackAtIndex(track_count, false)
  local tmp_tr = R_GetTrack(0, track_count)
  if not tmp_tr then
    reaper.PreventUIRefresh(-1)
    reaper.Undo_EndBlock("ReaAssist: fx_inspect (failed)", 0)
    return nil, nil, nil, "Failed to create temporary track for plugin inspection."
  end

  -- Hide from TCP and mixer so user doesn't see it flash.
  reaper.SetMediaTrackInfo_Value(tmp_tr, "B_SHOWINTCP", 0)
  reaper.SetMediaTrackInfo_Value(tmp_tr, "B_SHOWINMIXER", 0)

  local fx_idx = reaper.TrackFX_AddByName(tmp_tr, best_id, false, -1)
  if fx_idx < 0 then
    reaper.DeleteTrack(tmp_tr)
    reaper.PreventUIRefresh(-1)
    reaper.Undo_EndBlock("ReaAssist: fx_inspect (failed)", 0)
    return nil, nil, nil, "Failed to load plugin: " .. best_id
  end

  -- Hide the plugin UI (don't flash a window).
  reaper.TrackFX_Show(tmp_tr, fx_idx, 2)  -- 2 = hide floating window

  return tmp_tr, fx_idx, best_id, nil
end

-- =============================================================================
-- CTX.preferred_plugins  (on-demand scoped bucket)
-- =============================================================================
-- Reads the unified JSON cache and returns parameter data for the preferred
-- plugins matching the requested type keys (e.g. {"eq", "reverb"}).
-- Falls back to plugin_ref data when no preferred plugin is configured.
--
-- filter_types: list of type key strings (e.g. {"eq", "compressor"}).
--               If empty/nil, returns an error asking for specific types.

function CTX.preferred_plugins(filter_types)
  if not filter_types or #filter_types == 0 then
    return "PREFERRED PLUGINS: (error: no plugin type specified -- "
      .. "use preferred_plugins:eq or preferred_plugins:compressor, reverb)"
  end

  -- Read from the unified JSON cache.
  local cache = FXCache.load()
  local pref_types = cache.preferred_types or {}
  -- ExtState is process-shared and always current, so consumers read
  -- the dev_hide_fabfilter flag directly here rather than mirroring it
  -- in a prefs field that could go stale if the dev_signal ever missed.
  local hide_ff = reaper.GetExtState(CFG.EXT_NS, "dev_hide_fabfilter") == "1"

  -- Build output for only the requested types. Resolve aliases first.
  -- When a type has no preferred plugin set, do NOT silently fall back to
  -- curated data -- that bypasses the resolve popup and silently commits
  -- the user to a stock choice they never picked. Instead return a hint
  -- that tells the model to emit resolve:<type>, which fires the popup.
  local out = {}
  local matched = 0
  local no_pref_types = {}
  local pp_aliases = pref_plugins.alias_lookup()
  for _, type_key in ipairs(filter_types) do
    local k = type_key:lower():match("^%s*(.-)%s*$") or ""
    k = pp_aliases[k] or k
    local identifier = pref_types[k]
    -- Dev-only: treat FabFilter entries as "no pref set" when the hide
    -- flag is on, so the model emits resolve:<type> and fires the popup
    -- the dev wants to exercise.
    if hide_ff and _is_fabfilter_ident(identifier) then
      identifier = nil
    end
    if identifier and identifier ~= "" then
      local plugin_data = cache.plugins[identifier]
      matched = matched + 1
      out[#out+1] = k .. ": " .. identifier
      if plugin_data and plugin_data.params then
        if S._fx_cache_events then
          local t = S._fx_cache_events
          t.hit = t.hit or {}
          t.hit[#t.hit+1] = identifier
        end
        out[#out+1] = CTX.format_fx_params(
          identifier, plugin_data.params, plugin_data.max_group, nil, false)
      end
      out[#out+1] = ""
    else
      no_pref_types[#no_pref_types+1] = k
    end
  end

  -- Types with no preferred plugin: emit an explicit directive telling the
  -- model to re-request via resolve:<type>. DO NOT load plugins here.
  if #no_pref_types > 0 then
    local directives = {}
    for _, tk in ipairs(no_pref_types) do
      directives[#directives+1] =
        "  " .. tk .. ": NO PREFERRED PLUGIN SET. Emit "
        .. "<context_needed>resolve:" .. tk .. "</context_needed> so the "
        .. "user can pick one via the popup. Do NOT call TrackFX_AddByName "
        .. "with a generic type name."
    end
    if matched == 0 then
      return "PREFERRED PLUGINS:\n" .. tbl_concat(directives, "\n")
    end
    out[#out+1] = "Types with no preferred plugin set:"
    for _, d in ipairs(directives) do out[#out+1] = d end
  end

  return "PREFERRED PLUGINS:\n" .. tbl_concat(out, "\n")
end

-- =============================================================================
-- Preferred Plugins I/O (JSON cache)
-- =============================================================================

-- Merged alias lookup. Starts from PREF_PLUGIN_ALIASES (cross-type redirects
-- like expander->gate live here and stay code-owned), then layers in the
-- per-row user aliases from cache.preferred_aliases. User aliases can
-- override the code map for their own key; that's intentional.
-- Attached to pref_plugins (not file-scope) so callers declared above this
-- point resolve it via table lookup at call time, and so we don't burn new
-- file-scope local slots.
function pref_plugins.alias_lookup()
  -- Memoize on FXCache._mutation_count: the lookup table only depends on
  -- PREF_PLUGIN_ALIASES (constant) plus cache.preferred_aliases (mutates
  -- via the mutation-counted FXCache writers). Previously every caller
  -- did its own FXCache.load + pairs walk + gmatch; with multiple callers
  -- looping per-row over rows on a Save/Scan, that was 20+ JSON cache
  -- parses on a 20-row save.
  local mc = FXCache._mutation_count or 0
  if pref_plugins._alias_lookup_mc == mc and pref_plugins._alias_lookup then
    return pref_plugins._alias_lookup
  end
  local out = {}
  for k, v in pairs(PREF_PLUGIN_ALIASES) do out[k] = v end
  local cache = FXCache.load()
  local pa = cache.preferred_aliases
  if type(pa) == "table" then
    for key, aliases_str in pairs(pa) do
      for piece in tostring(aliases_str):gmatch("[^,]+") do
        local a = (piece:match("^%s*(.-)%s*$") or ""):lower()
        if a ~= "" then out[a] = key end
      end
    end
  end
  pref_plugins._alias_lookup    = out
  pref_plugins._alias_lookup_mc = mc
  return out
end

-- Reverse-index PREF_PLUGIN_ALIASES to seed per-row alias defaults. Returns
-- { eq = "equalizer, equaliser", compressor = "comp, compression", ... }.
-- Cross-type redirects (expander->gate, flanger->phaser) ARE included so the
-- user sees them as editable suggestions and can remove ones they dislike.
-- PREF_PLUGIN_ALIASES also carries entries whose alias is just the lowercased
-- canonical label ("pitch shift" -> "pitch_shift", "de-esser" -> "deesser",
-- "multiband compressor" -> ...); those exist for label_to_type_key
-- normalization, not as user-visible alternates, so we drop them.
function pref_plugins.default_aliases()
  local is_default_label = {}
  for _, lbl in ipairs(PREF_PLUGIN_DEFAULTS) do
    is_default_label[lbl:lower()] = true
  end
  local by_key = {}
  for alias, key in pairs(PREF_PLUGIN_ALIASES) do
    -- Drop identity hits (gate -> gate, synth -> synth) AND alias entries
    -- that are just the canonical label spelled out.
    if alias ~= key and not is_default_label[alias] then
      by_key[key] = by_key[key] or {}
      by_key[key][#by_key[key]+1] = alias
    end
  end
  -- Short-form seeds for long-label defaults: the canonical key (eq, synth)
  -- IS a natural alias when the row label is the long form (Equalizer,
  -- Synthesizer), but it doesn't live in PREF_PLUGIN_ALIASES (label_to_type_key
  -- falls through to the lowercase key for these; no alias entry required).
  -- Seed them explicitly so users see the short form in the alias column.
  local SHORT_FORMS = { eq = "eq", synth = "synth" }
  for key, short in pairs(SHORT_FORMS) do
    by_key[key] = by_key[key] or {}
    by_key[key][#by_key[key]+1] = short
  end
  local out = {}
  for key, list in pairs(by_key) do
    table.sort(list)
    out[key] = tbl_concat(list, ", ")
  end
  return out
end

-- Convert a user-facing label (e.g. "De-esser", "Pitch Correction") into its
-- canonical type key as used by pref_types, chain keys, and resolve:<type>
-- tokens. Applies the merged alias lookup so storage and lookup share one
-- vocabulary.
function label_to_type_key(label)
  local canonical = label:match("^([^,]+)") or label
  canonical = (canonical:match("^%s*(.-)%s*$") or ""):lower()
  if canonical == "" then return "" end
  local aliases = pref_plugins.alias_lookup()
  if aliases[canonical] then
    return aliases[canonical]
  end
  -- Fall back to space->underscore + strip-slash normalization. Matches the
  -- chain key form for types without a hyphen alias
  -- (e.g. "Multiband Compressor" -> "multiband_compressor").
  return (canonical:gsub("%s+", "_"):gsub("[/]+", ""))
end

-- Collect the current pref_plugins.rows aliases buffers into a
-- cache.preferred_aliases-shaped map. Rows with no type/aliases text
-- contribute nothing. Called from every save path so Save, scan_start
-- (zero-scan branch), and scan_read all persist alias edits.
function pref_plugins.collect_aliases()
  local out = {}
  for _, row in ipairs(pref_plugins.rows) do
    local lbl     = (row.label   or ""):match("^%s*(.-)%s*$") or ""
    local aliases = (row.aliases or ""):match("^%s*(.-)%s*$") or ""
    if lbl ~= "" and aliases ~= "" then
      local rkey = label_to_type_key(lbl)
      if rkey ~= "" then out[rkey] = aliases end
    end
  end
  return out
end

function CTX.load_pref_plugins()
  local cache = FXCache.load()
  local pref_types = cache.preferred_types or {}
  -- One-shot seed: if the cache has never carried preferred_aliases, populate
  -- it from the code defaults (reverse of PREF_PLUGIN_ALIASES). Absent field
  -- means "never seeded"; an empty table means "seeded then user cleared all".
  -- After seeding, we write back so subsequent loads skip this block.
  if cache.preferred_aliases == nil then
    cache.preferred_aliases = pref_plugins.default_aliases()
    FXCache.save(cache)
  end
  local pref_aliases = cache.preferred_aliases or {}
  -- ExtState is process-shared and always current, so consumers read
  -- the dev_hide_fabfilter flag directly here rather than mirroring it
  -- in a prefs field that could go stale if the dev_signal ever missed.
  local hide_ff = reaper.GetExtState(CFG.EXT_NS, "dev_hide_fabfilter") == "1"
  for ri, row in ipairs(pref_plugins.rows) do
    local rkey = label_to_type_key(row.label or "")
    if rkey ~= "" then
      local ident = pref_types[rkey]
      if ident and ident ~= "" then
        -- Dev-only filter: skip FabFilter entries when the hide flag is on
        -- so the row visibly reverts to empty (triggering the not-found /
        -- resolve popups the dev is trying to exercise). Cache stays
        -- untouched; real preferences come back the moment the flag is off.
        if not (hide_ff and _is_fabfilter_ident(ident)) then
          pref_plugins.rows[ri].name = ident
        end
      end
      local aliases_str = pref_aliases[rkey]
      if aliases_str and aliases_str ~= "" then
        pref_plugins.rows[ri].aliases = aliases_str
      end
    end
  end
end

-- Save preferences to the JSON cache.
-- Updates preferred_types (type -> ident mapping) AND preferred_aliases
-- (type -> user-alias string) from pref_plugins.rows.
function CTX.save_pref_plugins()
  local cache = FXCache.load()
  cache.preferred_types = {}
  for _, row in ipairs(pref_plugins.rows) do
    local lbl  = (row.label or ""):match("^%s*(.-)%s*$") or ""
    local name = (row.name  or ""):match("^%s*(.-)%s*$") or ""
    if lbl ~= "" and name ~= "" then
      local rkey = label_to_type_key(lbl)
      if rkey ~= "" then
        -- Canonicalize on save so the on-disk form is AddByName-ready
        -- (e.g., "Twin 3" -> "VST3i: Twin 3"). Logs the upgrade once
        -- per save when it actually changes the value.
        local canonical, upgraded = FXCache.canonicalize_identifier(rkey, name)
        if upgraded then
          Log.line("PREF", str_format(
            "preferred_types.%s = %s -> %s (canonicalized on UI save)",
            rkey, name, canonical))
        end
        cache.preferred_types[rkey] = canonical
      end
    end
  end
  cache.preferred_aliases = pref_plugins.collect_aliases()
  return FXCache.save(cache)
end

-- Tokenize a plugin-name-ish string into an ORDERED list of lowercased
-- tokens. Splits on any non-alphanumeric character AND across alpha/digit
-- boundaries so "Pro-Q 4" and "proq4" both yield ("pro","q","4"). Strips
-- the REAPER format prefix (VST3:, JS:, etc.) from the front. Vendor text
-- inside parentheses is included as tokens -- e.g. "VST3: Pro-Q 4 (FabFilter)"
-- yields ("pro","q","4","fabfilter"), so typing "Fabfilter" as a search term
-- matches through the vendor name without any special casing.
local function pref_plugins_tokenize(s)
  s = (s or ""):lower():gsub("^%w+:%s*", "")
  local tokens = {}
  local i, n = 1, #s
  while i <= n do
    local c = s:sub(i, i)
    if c:match("%a") then
      local j = i
      while j <= n and s:sub(j, j):match("%a") do j = j + 1 end
      tokens[#tokens+1] = s:sub(i, j-1)
      i = j
    elseif c:match("%d") then
      local j = i
      while j <= n and s:sub(j, j):match("%d") do j = j + 1 end
      tokens[#tokens+1] = s:sub(i, j-1)
      i = j
    else
      i = i + 1
    end
  end
  return tokens
end

-- Score a single FX candidate against a tokenized search. Returns 0 if no
-- meaningful match. Designed to be strict enough that "Pro-C" doesn't pull
-- in everything containing "proc" (processor, production, ...) while still
-- letting "filter" match "Fabfilter" and vendor-prefix searches resolve.
--
-- Tiers (highest first):
--   1. Exact blob match        (10000)       -- "proq4" == "proq4"
--   2. Blob prefix match        (~8000)      -- search is prefix of plugin
--                                              blob, catches "proq4" -> "Pro-Q 4"
--   3. Single-token search:
--        token equals search     (5000)
--        token has search prefix (3000)      -- "pro" -> "Pro-Q"
--        search is substring of
--           a token              ( 500)      -- "filter" -> "Fabfilter"
--   4. Multi-token search:
--        EVERY search token must equal or prefix some plugin token.
--        Substring-only matches rejected (too noisy once the user has
--        committed to multiple tokens -- e.g. "Pro-C" = {"pro","c"}
--        must NOT match "Video processor" just because "processor"
--        contains "proc"). Sum of per-token subscores (500 eq, 200 pfx).
-- A small "shorter name wins" bonus breaks ties in favor of more specific
-- matches ("Pro-Q 4" beats "Pro-Q Multiband").
local function pref_plugins_score(search_tokens, plugin_tokens, fx_name_len)
  if #search_tokens == 0 or #plugin_tokens == 0 then return 0 end

  local search_blob = table.concat(search_tokens)
  local plugin_blob = table.concat(plugin_tokens)
  if plugin_blob == search_blob then return 10000 end
  if #search_blob > 0 and plugin_blob:sub(1, #search_blob) == search_blob then
    return 8000 + math_max(0, 200 - fx_name_len)
  end

  -- Helper: is `s` acceptable as a prefix match against plugin token `p`?
  -- Single-character search tokens are too noisy as prefixes (e.g. "c"
  -- prefix-matches "cntrl", "cat's", "convolution"), so we require them to
  -- match a plugin token EXACTLY. Two+ character search tokens can match
  -- either exactly or as a prefix.
  local function _prefix_ok(s, p)
    if #s == 1 then return false end
    return #s <= #p and p:sub(1, #s) == s
  end

  if #search_tokens == 1 then
    local s = search_tokens[1]
    local best = 0
    for _, p in ipairs(plugin_tokens) do
      if p == s then
        if best < 5000 then best = 5000 end
      elseif _prefix_ok(s, p) then
        if best < 3000 then best = 3000 end
      elseif #s > 1 and p:find(s, 1, true) then
        if best < 500 then best = 500 end
      end
    end
    if best == 0 then return 0 end
    return best + math_max(0, 200 - fx_name_len)
  end

  -- Multi-token: every search token must equal OR prefix some plugin token.
  local total = 0
  for _, s in ipairs(search_tokens) do
    local best = 0
    for _, p in ipairs(plugin_tokens) do
      if p == s then
        if best < 500 then best = 500 end
      elseif _prefix_ok(s, p) then
        if best < 200 then best = 200 end
      end
    end
    if best == 0 then return 0 end
    total = total + best
  end
  return total + math_max(0, 200 - fx_name_len)
end

-- Split the normalized blob of a plugin name into (alpha_base, trailing_num).
-- "proq4" -> ("proq", 4); "reaeq" -> ("reaeq", -1). Used for the version
-- tie-break (Pro-Q 4 beats Pro-Q 2 when scores match).
local function pref_plugins_split_trailing_num(s)
  local base, num = s:match("^(.-)(%d+)$")
  if base and num then return base, tonumber(num) end
  return s, -1
end

-- Best-match for preferred plugin search. Returns (best_identifier, score)
-- from the installed FX list, or nil if nothing scores > 0.
function pref_plugins_best_match(search_name, fx_list)
  local search_tokens = pref_plugins_tokenize(search_name)
  if #search_tokens == 0 then return nil, 0 end

  local best_ident = nil
  local best_score = 0
  local best_blob  = nil  -- concatenated plugin blob of current best

  for _, fx_name in ipairs(fx_list) do
    local plugin_tokens = pref_plugins_tokenize(fx_name)
    local score = pref_plugins_score(search_tokens, plugin_tokens, #fx_name)

    if score > best_score then
      best_score = score
      best_ident = fx_name
      best_blob  = table.concat(plugin_tokens)
    elseif score > 0 and score == best_score and best_blob then
      -- Version tie-break: if blobs share the same alpha base and differ
      -- only by a trailing number, prefer the higher number (newer version).
      local cand_blob = table.concat(plugin_tokens)
      local b_base, b_num = pref_plugins_split_trailing_num(best_blob)
      local c_base, c_num = pref_plugins_split_trailing_num(cand_blob)
      if b_base == c_base and c_num > b_num then
        best_ident = fx_name
        best_blob  = cand_blob
      end
    end
  end

  return best_ident, best_score
end

-- Rank installed FX by match score and return the top `limit` canonical
-- names (scored > 0). Same scoring + tie-break as pref_plugins_best_match.
function pref_plugins_rank_matches(search_name, fx_list, limit)
  limit = limit or 8
  local search_tokens = pref_plugins_tokenize(search_name)
  if #search_tokens == 0 then return {} end

  local scored = {}
  for _, fx_name in ipairs(fx_list) do
    local plugin_tokens = pref_plugins_tokenize(fx_name)
    local score = pref_plugins_score(search_tokens, plugin_tokens, #fx_name)
    if score > 0 then
      local blob = table.concat(plugin_tokens)
      local base, num = pref_plugins_split_trailing_num(blob)
      scored[#scored+1] = {
        ident = fx_name, score = score, base = base, num = num,
      }
    end
  end

  -- Sort by score desc; tie-break by (base match -> higher num), then name.
  table.sort(scored, function(a, b)
    if a.score ~= b.score then return a.score > b.score end
    if a.base == b.base and a.num ~= b.num then return a.num > b.num end
    return a.ident < b.ident
  end)

  local out = {}
  for i = 1, math_min(limit, #scored) do out[i] = scored[i].ident end
  return out
end

-- Start an async parameter scan for all non-empty preferred plugins.
-- Phase 1 ("adding"): creates a temp track and adds each plugin.
-- Phase 2 ("reading"): runs on the next loop frame (FX are initialised by then),
-- reads all parameters using the unified scanner, caches to JSON, and cleans up.
-- force: if true, re-scan every resolved ident even if it's already cached.
-- Default (false/nil) skips idents already present in cache.plugins so that
-- Save acts as "save + scan only new plugins".
function CTX.pref_plugins_scan_start(force)
  local scan = pref_plugins.scan
  -- Defensive guard: also bail if a single-plugin rescan is in flight.
  -- (The buttons on the page already disable on this condition, but the
  --  guard protects against future callers.)
  if scan.active or fx_cache_ui.rescan.active then return end
  scan.force = force and true or false

  -- Ensure the installed FX cache is populated.
  CTX.populate_installed_fx()

  -- Build the list of plugins to scan using best-match scoring.
  scan.fx_map  = {}
  scan.results = {}
  -- Entries whose ident is already cached and we're not forcing: still need
  -- their preferred_types mapping updated but should not be re-inserted on
  -- the temp track. Collected separately and applied in scan_read.
  scan.skipped_cached = {}
  -- Load the cache ONCE here and pass it through scan state so scan_read
  -- reuses the same in-memory copy. Previously this was loaded 2-3 times
  -- per Save (here, in the zero-scan branch, and again in scan_read),
  -- which is wasteful for sessions with large param caches.
  scan.cache = FXCache.load()
  if CTX._installed_fx_list then
    for _, row in ipairs(pref_plugins.rows) do
      local lbl  = (row.label or ""):match("^%s*(.-)%s*$") or ""
      local name = (row.name  or ""):match("^%s*(.-)%s*$") or ""
      if lbl ~= "" and name ~= "" then
        local rkey = label_to_type_key(lbl)
        if rkey ~= "" then
          if Code.is_curated_plugin(name) then
            -- Curated plugins: commit the pref_types mapping but skip the
            -- live scan. Their param docs live in Plugin_Ref.md and preempt
            -- routes through plugin_ref:<Name>, never consulting the live
            -- scan cache -- scanning them is wasted work.
            scan.skipped_cached[#scan.skipped_cached+1] =
              { key = rkey, ident = name }
          else
            local ident = pref_plugins_best_match(name, CTX._installed_fx_list)
            if ident then
              local cached_entry = scan.cache.plugins
                and scan.cache.plugins[ident]
              local already_cached = cached_entry
                and cached_entry.params
                and #cached_entry.params > 0
              if (not scan.force) and already_cached then
                scan.skipped_cached[#scan.skipped_cached+1] =
                  { key = rkey, ident = ident }
              else
                scan.fx_map[#scan.fx_map+1] =
                  { key = rkey, name = name, ident = ident, fx_idx = -1 }
              end
            end
          end
        end
      end
    end
  end

  if #scan.fx_map == 0 then
    -- Nothing to actually scan, but we may still need to commit
    -- preferred_types mappings for already-cached entries. Reuse the
    -- cache we loaded above instead of re-reading from disk.
    if #scan.skipped_cached > 0 then
      -- Wipe-and-rebuild: skipped_cached reflects the CURRENT row set,
      -- so resetting preferred_types here is the only way a user-deleted
      -- row actually disappears from the saved mapping. Without this,
      -- deletions silently persisted.
      scan.cache.preferred_types = {}
      for _, entry in ipairs(scan.skipped_cached) do
        scan.cache.preferred_types[entry.key] = entry.ident
      end
      scan.cache.preferred_aliases = pref_plugins.collect_aliases()
      local err = FXCache.save(scan.cache)
      if err then
        scan.status = err
        UI.show_float_toast("Save failed", "err")
      else
        scan.status = ""
        UI.show_float_toast("Preferences saved", "ok")
        pref_plugins.pending_exit = true
      end
    else
      scan.status = ""
      -- Still save the preferences (without param data).
      local err = CTX.save_pref_plugins()
      if err then
        UI.show_float_toast("Save failed: " .. err, "err")
      else
        UI.show_float_toast("No matching plugins found", "err")
        pref_plugins.pending_exit = true
      end
    end
    scan.cache = nil
    return
  end

  -- Phase 1: create temp track and add all plugins.
  reaper.Undo_BeginBlock()
  reaper.PreventUIRefresh(1)
  reaper.InsertTrackAtIndex(reaper.CountTracks(0), false)
  local tr = reaper.GetTrack(0, reaper.CountTracks(0) - 1)
  if not tr then
    reaper.PreventUIRefresh(-1)
    scan.status = ""
    UI.show_float_toast("Scan failed: couldn't create temp track", "err")
    reaper.Undo_EndBlock("ReaAssist: scan (failed)", 0)
    scan.cache = nil
    return
  end
  -- Hide from TCP and mixer so user doesn't see it flash.
  reaper.SetMediaTrackInfo_Value(tr, "B_SHOWINTCP", 0)
  reaper.SetMediaTrackInfo_Value(tr, "B_SHOWINMIXER", 0)
  scan.track = tr

  for _, entry in ipairs(scan.fx_map) do
    local fx = reaper.TrackFX_AddByName(tr, entry.ident, false, -1)
    entry.fx_idx = fx
    -- Hide plugin UI.
    if fx >= 0 then reaper.TrackFX_Show(tr, fx, 2) end
  end

  scan.active = true
  scan.phase  = "reading"  -- will be processed on the next loop() frame
  scan.status = "Scanning parameters..."
end

-- Phase 2: read parameters from all added plugins using the unified scanner,
-- cache to JSON, then clean up.
-- Called from the main loop on the frame AFTER scan_start.
function CTX.pref_plugins_scan_read()
  local scan = pref_plugins.scan
  if not scan.active or scan.phase ~= "reading" then return end

  local tr = scan.track
  -- ValidatePtr2 guards against project switches or explicit deletions
  -- between the scan_start frame and this reader frame. A non-nil but
  -- stale userdata handle would crash TrackFX_GetNumParams below.
  if not tr or not reaper.ValidatePtr2(0, tr, "MediaTrack*") then
    scan.active = false
    scan.phase  = "done"
    scan.cache  = nil
    scan.track  = nil
    scan.status = ""
    UI.show_float_toast("Scan failed: temp track lost", "err")
    reaper.PreventUIRefresh(-1)
    reaper.Undo_EndBlock("ReaAssist: scan (failed)", 0)
    return
  end

  -- Read parameters for each successfully added plugin using unified scanner.
  -- Also update the preferred_types mapping in the cache. Reuse the cache
  -- that scan_start loaded and stashed on scan.cache so we don't re-parse
  -- the JSON file (fall back to a fresh load if the stash was cleared,
  -- which shouldn't happen during a normal active scan).
  local cache = scan.cache or FXCache.load()
  -- Per-entry xpcall: if scan_fx_params throws on one plugin (stale handle,
  -- REAPER returning nil mid-probe, etc.) we do NOT want to skip the cleanup
  -- at the end of this function -- that would leave an orphaned hidden temp
  -- track + a stuck PreventUIRefresh(-1) imbalance + an unclosed Undo block.
  -- The failed entry is logged and skipped so the remaining plugins still scan.
  local scan_failures = {}
  for _, entry in ipairs(scan.fx_map) do
    if entry.fx_idx >= 0 then
      local _ok, params_list, max_group, total_count, needs_deep_scan =
        xpcall(function()
          return CTX.scan_fx_params(tr, entry.fx_idx)
        end, debug.traceback)
      if not _ok then
        Log.line("PREF_PLUGINS_SCAN", string.format(
          "scan_fx_params threw for %s: %s",
          entry.ident or "?", tostring(params_list)))
        scan_failures[#scan_failures+1] = entry.ident or "?"
      else
        -- Store in unified cache keyed by identifier.
        cache.plugins[entry.ident] = {
          param_count      = total_count,
          max_group        = max_group,
          params           = params_list,
          needs_deep_scan  = needs_deep_scan or nil,
        }
        -- Collected scanned entries into fx_map; preferred_types is rebuilt
        -- below from fx_map + skipped_cached in a single wipe-then-populate
        -- pass so deleted rows are removed cleanly.
      end
    end
  end

  -- Wipe-and-rebuild preferred_types from scan.fx_map + scan.skipped_cached,
  -- which together represent the CURRENT row set after any Add/Modify/Delete
  -- edits. Additive-only updates (the earlier behavior) left deleted rows'
  -- mappings in the cache forever, so the UI appeared to discard deletions.
  --
  -- Skip entries whose plugin failed to load (entry.fx_idx < 0) or whose
  -- scan threw. Earlier code committed every entry unconditionally, baking
  -- in a saved preference that pointed at an identifier the user couldn't
  -- actually use; the next session would silently fail to load it with no
  -- breadcrumb in the UI. Track skipped names so the toast surfaces it.
  local _failed_idents = {}
  for _, ident in ipairs(scan_failures) do
    _failed_idents[ident] = true
  end
  local skipped_idents = {}
  cache.preferred_types = {}
  for _, entry in ipairs(scan.fx_map) do
    if entry.fx_idx >= 0 and not _failed_idents[entry.ident] then
      cache.preferred_types[entry.key] = entry.ident
    else
      skipped_idents[#skipped_idents+1] = entry.ident or entry.key or "?"
    end
  end
  if scan.skipped_cached then
    for _, entry in ipairs(scan.skipped_cached) do
      cache.preferred_types[entry.key] = entry.ident
    end
  end
  cache.preferred_aliases = pref_plugins.collect_aliases()
  -- Bump the mutation counter: scan_read mutates cache.preferred_types
  -- and cache.plugins directly (without going through put_plugin), so
  -- the FX-cache settings list cache wouldn't otherwise know to
  -- invalidate after a scan finishes.
  FXCache._mutation_count = (FXCache._mutation_count or 0) + 1

  -- Clean up: remove temp track.
  reaper.DeleteTrack(tr)
  reaper.PreventUIRefresh(-1)
  -- flags=0 (instead of -1) explicitly discards the block so the temp-track
  -- insert + probe writes + delete never enter the user's undo history.
  -- The earlier pattern relied on Undo_EndBlock(-1) + Undo_DoUndo2(0), which
  -- walks back one slot -- safe only when REAPER's heuristic actually
  -- registered this block. If it didn't (net-zero change detection), the
  -- DoUndo2 would walk into the user's previous action.
  reaper.Undo_EndBlock("ReaAssist: preferred plugins scan", 0)

  -- Save the unified JSON cache.
  local err = FXCache.save(cache)
  scan.active = false
  scan.phase  = "done"
  scan.cache  = nil  -- release stashed reference
  if err then
    scan.status = err
    UI.show_float_toast("Save failed", "err")
  else
    scan.status = ""
    if #skipped_idents > 0 then
      -- Partial success: some plugins couldn't load (or threw mid-scan), so
      -- the rest were saved but those rows have no preferred_types entry.
      -- Surface the count + first few names; full list goes to the debug
      -- log so the user has something to triage with.
      Log.line("PREF_PLUGINS_SCAN", "skipped " .. #skipped_idents
        .. " unloadable/failed: " .. tbl_concat(skipped_idents, ", "))
      local preview_n = (#skipped_idents < 2) and #skipped_idents or 2
      local preview = tbl_concat(skipped_idents, ", ", 1, preview_n)
      local more = #skipped_idents - preview_n
      local msg = "Saved (" .. #skipped_idents .. " skipped: " .. preview
      if more > 0 then msg = msg .. ", +" .. more .. " more" end
      msg = msg .. ")"
      UI.show_float_toast(msg, "err")
    else
      UI.show_float_toast("Preferences saved", "ok")
    end
    pref_plugins.pending_exit = true
  end
end

-- =============================================================================
-- CTX.build_snapshot
-- =============================================================================
-- Gathers all lightweight context buckets for the given project and returns
-- a formatted "SESSION CONTEXT:\n..." block. Called on every send so the data
-- is always fresh. The result is passed to Net.build_body() but never stored in
-- S.history, so older turns do not carry stale snapshot data.
--
-- Included buckets (all cheap, read-only REAPER API calls):
--   tempo/time sig   - project BPM and time signature (e.g. 6/8)
--   sample rate      - project sample rate in Hz
--   transport        - play/record/pause/stopped state
--   loop             - loop enable state and loop point range
--   markers/regions  - all markers and region start/end points (capped)
--   tracks           - track list with name, item count, mute/solo/arm flags
--   fx chains        - which FX are loaded on each track (names only; not params)
--   selected tracks  - which tracks are currently selected
--   time selection   - start/end of the current time selection (or "none")
--   edit cursor      - current cursor position in seconds
--   selected items   - position/length/track of selected media items (capped)
--
-- NOTE: FX parameter values are intentionally excluded here because they can
-- be very large on dense sessions (dozens of parameters per plugin across many
-- tracks). The assistant requests them on demand via
-- <context_needed>fx_params:PluginName</context_needed>, which scopes the
-- collection to only the named plugin(s).
-- Heavy-snapshot memoization. tracks() walks every track + FX chain and
-- markers() walks every marker/region; both can take hundreds of ms on
-- dense projects. Cache them keyed on reaper.GetProjectStateChangeCount(),
-- which increments on every undo-tracked mutation (track/FX/marker/loop
-- edits). The cheap + volatile bits (tempo, cursor, selection, transport,
-- selected items, time selection) are re-read every call -- they're each
-- under ~1ms, AND some of them (cursor, selection, transport) aren't
-- reflected in the state-count so we'd risk serving stale data if we
-- cached them. Invalidated automatically on project switch because proj
-- is part of the key.
CTX._snapshot_heavy_cache = nil

-- =============================================================================
-- CTX.preempt_buckets_for_prompt
-- =============================================================================
-- Scan the user's prompt for plugin-type keywords that match their saved
-- preferred_types. For each hit, load the corresponding preferred_plugins
-- content and drop it directly into S.sticky_context BEFORE the first API
-- send. That way the model sees the relevant plugin reference data in the
-- initial request and doesn't need to emit <context_needed>preferred_plugins:X
-- to ask for it -- saving a full API round trip.
--
-- This is a best-effort optimization. Word-boundary matching against the
-- user's preferred_types keys (whatever labels they typed on the Preferred
-- Plugins page, lowercased-with-underscores: "compressor", "eq", "de-esser",
-- etc.). Skipped when a type is already in sticky_context (user already has
-- that data from an earlier turn) or already marked sent for this turn.
--
-- Returns a list of preemption-reason strings for the debug log.
--
-- CHAIN_PHRASE_HINTS extends the trigger surface beyond single-keyword
-- matches: broad multi-FX phrases (e.g. "drum kit", "vocal chain", "mix
-- bus") strongly imply specific plugin types without naming them by type
-- word. When a phrase matches, the preempt loop treats each implied type
-- as if its own keyword had hit, pre-pinning that type's plugin_ref + pref
-- hint and saving the <context_needed>resolve:X</context_needed> round-trip
-- the model would otherwise emit. Each entry is {pattern, {implied_types}};
-- only types the user actually has a pref for get pinned (the main loop
-- iterates pref_types keys, so unconfigured types fall through naturally).
-- Saved per matched phrase: one full API round-trip (~2s + small request
-- cost) on the common drum-kit / vocal-chain / mix-bus creation requests.
local CHAIN_PHRASE_HINTS = {
  { "drum%s+kit",         {"eq", "compressor", "gate"} },
  { "drum%s+chain",       {"eq", "compressor", "gate"} },
  { "drum%s+bus",         {"eq", "compressor"} },
  -- Vocal-chain variants: the literal "vocal%s+chain" alone misses
  -- common phrasings like "chain of effects ... rock vocal" (observed
  -- in a turn-2 user prompt that paid a wasted resolve round-trip
  -- because reverb + compressor weren't preempted). Order matters
  -- for trigger-phrase attribution: more-specific patterns first so
  -- the debug log records the tightest match. All three entries imply
  -- the same type set, so type-pinning is unaffected by order.
  --
  -- All patterns require BOTH a vocal mention AND a chain/effects
  -- mention. "rock vocal" alone would over-preempt on add-only or
  -- record-only prompts ("add a rock vocal track", "record a rock
  -- vocal") that don't ask for a chain. Genre-prefixed phrasings
  -- like "rock vocal chain" already hit via vocal%s+chain anyway,
  -- since the substring "vocal chain" is present.
  { "chain%s+of%s+effects.-vocal", {"eq", "compressor", "deesser", "reverb"} },
  { "chain.-rock%s+vocal", {"gate", "eq", "compressor", "saturation", "limiter"} },
  { "chain.-vocal", {"eq", "compressor", "deesser", "reverb"} },
  { "vocal%s+chain",      {"eq", "compressor", "deesser", "reverb"} },
  { "vocal.-chain",       {"eq", "compressor", "deesser", "reverb"} },
  { "vocal%s+bus",        {"eq", "compressor"} },
  { "guitar%s+chain",     {"eq", "compressor", "saturation"} },
  { "bass%s+chain",       {"eq", "compressor"} },
  { "mix%s+bus",          {"eq", "compressor", "limiter"} },
  { "master%s+bus",       {"eq", "compressor", "limiter"} },
  { "mastering%s+chain",  {"eq", "compressor", "limiter"} },
  { "recording%s+chain",  {"eq", "compressor", "gate"} },
}

function CTX.prompt_indicates_chain_context(text)
  if type(text) ~= "string" or text == "" then return false end
  local t = text:lower()
  for _, hint in ipairs(CHAIN_PHRASE_HINTS) do
    if t:find(hint[1]) then return true end
  end
  if not t:find("%f[%w]chain%f[%W]") then return false end
  return t:find("%f[%w]drum%f[%W]") ~= nil
    or t:find("%f[%w]drums%f[%W]") ~= nil
    or t:find("%f[%w]snare%f[%W]") ~= nil
    or t:find("%f[%w]kick%f[%W]") ~= nil
    or t:find("%f[%w]tom%f[%W]") ~= nil
    or t:find("%f[%w]percussion%f[%W]") ~= nil
    or t:find("%f[%w]vocal%f[%W]") ~= nil
    or t:find("%f[%w]guitar%f[%W]") ~= nil
    or t:find("%f[%w]bass%f[%W]") ~= nil
    or t:find("%f[%w]mix%f[%W]") ~= nil
    or t:find("%f[%w]master%f[%W]") ~= nil
    or t:find("%f[%w]mastering%f[%W]") ~= nil
    or t:find("%f[%w]recording%f[%W]") ~= nil
    or t:find("%f[%w]effects%f[%W]") ~= nil
    or t:find("%f[%w]processing%f[%W]") ~= nil
end

function CTX.prompt_indicates_typed_action_plan(text)
  if type(text) ~= "string" or text == "" then return false end
  local t = text:lower()
  return t:find("typed action plan", 1, true) ~= nil
    or t:find("typed-action plan", 1, true) ~= nil
    or t:find("typed-action contract", 1, true) ~= nil
    or t:find("reaassist-actions", 1, true) ~= nil
end

-- DOCS_PHRASE_HINTS: keyword/phrase -> docs:<section> pre-pin map. When the
-- user prompt contains any of these, the matched section is loaded into
-- sticky_context BEFORE the first API call, saving the round-trip the
-- model would otherwise spend emitting <context_needed>docs:envelopes</context_needed>
-- (or whichever). Only fires for sections in DOCS_SECTION_NAMES; the
-- canonical key is what gets pinned.
--
-- Pattern style: multi-word phrases (e.g. "send to") use literal substring
-- match; common single words use the %f[%w]X%f[%W] frontier syntax for
-- whole-word boundaries (Lua has no \b). The frontier pattern requires the
-- bracket sets -- a bare %f without [...] errors out.
--
-- "automation" -> docs:envelopes intentionally. REAPER's "automation items"
-- are media-item-shaped objects layered onto envelopes, but the scripting
-- surface (Envelope_*, GetSetEnvelope*, InsertEnvelopePoint, etc.) lives
-- in the envelopes section. Users saying "automate the volume" or "add
-- automation" need envelope functions, not item functions.
local DOCS_PHRASE_HINTS = {
  -- envelopes
  { "envelope",              "envelopes" },
  { "automation",            "envelopes" },
  { "automate",              "envelopes" },
  -- routing (multi-word phrases avoid frontier-pattern needs)
  { "sidechain",             "routing"   },
  { "send to",               "routing"   },
  { "send from",             "routing"   },
  { "create a send",         "routing"   },
  { "create send",           "routing"   },
  { "add a send",            "routing"   },
  { "add send",              "routing"   },
  { "set up a send",         "routing"   },
  { "set up send",           "routing"   },
  { "receive from",          "routing"   },
  { "%f[%w]route%f[%W]",     "routing"   },
  { "%f[%w]routing%f[%W]",   "routing"   },
  { "%f[%w]bus%f[%W]",       "routing"   },
  { "%f[%w]aux%f[%W]",       "routing"   },
  { "return track",          "routing"   },
  { "hardware output",       "routing"   },
  -- take_fx. The phrase set covers both explicit "take FX" wording and
  -- the more common item-scoped FX targeting ("add an EQ to the selected
  -- item", "on this clip", "to the active take") -- when the user
  -- targets an item rather than a track, the model needs TakeFX_* not
  -- TrackFX_*, and reaching for core's TrackFX_* by default is the
  -- semantic mistake we want to prevent. Phrases are chosen to imply
  -- "applying FX TO X" (preposition + item/take noun) so plain item
  -- queries like "trim the selected item" or "count selected items"
  -- don't trigger an unnecessary take_fx pin.
  { "take fx",               "take_fx"   },
  { "take effect",           "take_fx"   },
  { "item fx",               "take_fx"   },
  { "per%-item fx",          "take_fx"   },
  { "to the selected item",  "take_fx"   },
  { "on the selected item",  "take_fx"   },
  { "to this item",          "take_fx"   },
  { "on this item",          "take_fx"   },
  { "to this clip",          "take_fx"   },
  { "on this clip",          "take_fx"   },
  { "to the active take",    "take_fx"   },
  { "on the active take",    "take_fx"   },
  { "to the take",           "take_fx"   },
  { "on the take",           "take_fx"   },
  -- items (markers/regions stay in core, so don't pin items on those words)
  { "razor edit",            "items"     },
  { "razor area",            "items"     },
  { "media item",            "items"     },
  { "midi item",             "items"     },
  { "midi items",            "items"     },
  -- tempo (markers/regions stay in core, so don't pin tempo on those words)
  { "%f[%w]tempo%f[%W]",     "tempo"     },
  { "time signature",        "tempo"     },
}

CTX = CTX or {}
CTX.DRUM_EDIT_PHRASE_HINTS = {
  "quantize drums",
  "quantize the drums",
  "drum quantize",
  "edit drums",
  "edit the drums",
  "editing drums",
  "tighten drums",
  "tighten the drums",
  "snap drums",
  "snap the drums",
  "drum transients",
  "drum hits",
  "drum editing",
}

function CTX.prompt_indicates_drum_edit(text)
  if type(text) ~= "string" or text == "" then return false end
  local t = text:lower()
  for _, phrase in ipairs(CTX.DRUM_EDIT_PHRASE_HINTS) do
    if t:find(phrase, 1, true) then return true end
  end
  local has_drum =
       t:find("%f[%w]drum%f[%W]") ~= nil
    or t:find("%f[%w]drums%f[%W]") ~= nil
  if not has_drum then return false end
  if t:find("%f[%w]quantiz") then return true end
  if t:find("%f[%w]tighten") then return true end
  if t:find("%f[%w]transient") then return true end
  if t:find("stretch marker", 1, true) then return true end
  if t:find("guide track", 1, true) then return true end
  return false
end

if REQUIRE_SWS_EXTENSION and not SupportExtFlag("optoutsws") then
  -- SWS docs are advertised only when the rollout flag is enabled. The
  -- loader accepts docs:sws either way, but normal releases should not
  -- nudge the model toward extension-only calls while SWS is still optional.
  local sws_hints = {
    { "%f[%w]sws%f[%W]",                  "sws" },
    { "s&m",                              "sws" },
    { "system clipboard",                 "sws" },
    { "%f[%w]clipboard%f[%W]",            "sws" },
    { "mouse cursor context",             "sws" },
    { "mouse cursor",                     "sws" },
    { "under my mouse",                   "sws" },
    { "under the mouse",                  "sws" },
    { "%f[%w]hovering%f[%W]",             "sws" },
    { "%f[%w]hovered%f[%W]",              "sws" },
    { "br_getmousecursorcontext",         "sws" },
    { "%f[%w]loudness%f[%W]",             "sws" },
    { "%f[%w]lufs%f[%W]",                 "sws" },
    { "sws notes",                        "sws" },
    { "marker region subtitle",           "sws" },
    { "region subtitle",                  "sws" },
  }
  for _, hint in ipairs(sws_hints) do
    DOCS_PHRASE_HINTS[#DOCS_PHRASE_HINTS + 1] = hint
  end
end

-- JSFX-intent detection: returns true when the user's prompt explicitly
-- asks for JSFX/EEL2/custom-DSP work. Intentionally narrow -- only fires on
-- the literal "jsfx" / "eel2" / "reajs" tokens, the "@init" / "@sample"
-- section markers (which only appear in JSFX code discussions), or the
-- common phrasing "write/build/make a (custom) plugin/effect/DSP". JSFX
-- family hints (shimmer, harmonizer, etc.) alone do NOT trigger -- those
-- words apply equally to plugin tasks, and a false positive here would
-- suppress plugin_ref / api_ref injection that the user actually needed.
--
-- Used by the send pipeline to:
--   - Skip plugin_ref / pref / docs co-pin in the keyword loop below
--     (saves ~25-30K input tokens per turn when user has a curated reverb
--     pref and types "reverb" alongside "JSFX").
--   - Trim the tracks list in the snapshot (no track is referenced when
--     generating an effect file).
local function _prompt_indicates_jsfx(text)
  if type(text) ~= "string" or text == "" then return false end
  local t = text:lower()
  -- Ignore negative/instructional mentions such as the typed-action
  -- contract's "Do not write Lua, ReaScript, JSFX..." line. Those are
  -- constraints, not JSFX authoring intent, and pre-pinning the JSFX bundle
  -- wastes tokens on otherwise compact local-action plans.
  t = t:gsub("do%s+not%s+write[^%.\n]*%f[%w]jsfx%f[%W][^%.\n]*", " ")
  t = t:gsub("don't%s+write[^%.\n]*%f[%w]jsfx%f[%W][^%.\n]*", " ")
  t = t:gsub("dont%s+write[^%.\n]*%f[%w]jsfx%f[%W][^%.\n]*", " ")
  t = t:gsub("without%s+%f[%w]jsfx%f[%W]", " ")
  t = t:gsub("no%s+%f[%w]jsfx%f[%W]", " ")
  t = t:gsub("not%s+%f[%w]jsfx%f[%W]", " ")
  if t:find("%f[%w]jsfx%f[%W]")  then return true end
  if t:find("%f[%w]eel2?%f[%W]") then return true end
  if t:find("%f[%w]reajs%f[%W]") then return true end
  if t:find("@init") or t:find("@sample") or t:find("@gfx")
     or t:find("@slider") or t:find("@block") then return true end
  return false
end

-- JSFX effect-family bundles. When the user prompt matches any phrase
-- below, the corresponding prompt_bundle:jsfx_<family> gets pinned on top
-- of the always-on prompt_bundle:jsfx core. Bundle content is in
-- Resources/Prompts.md (one SECTION per family). False-positive pins are
-- low-cost (one bundle, ~1.5K tokens) and don't change behavior beyond
-- giving the model more relevant DSP recipes; bias keywords toward
-- multi-word phrases when the single word is too generic to be safe.
local JSFX_FAMILY_HINTS = {
  -- jsfx_pitch: pitch shifters, shimmer reverbs, harmonizers, granular
  -- octave effects. Single-word `pitch` is too broad ("pitch the snare"
  -- in mixing context); require multi-word or context-specific phrasing.
  { "shimmer",                     "jsfx_pitch" },
  { "pitch shift",                 "jsfx_pitch" },
  { "pitch shifter",               "jsfx_pitch" },
  { "pitch%-shift",                "jsfx_pitch" },
  { "octave up",                   "jsfx_pitch" },
  { "octave down",                 "jsfx_pitch" },
  { "%f[%w]harmoniz",              "jsfx_pitch" },  -- harmonizer / harmoniser / harmonize
  { "%f[%w]transpose",             "jsfx_pitch" },
  { "%f[%w]grain%f[%W]",           "jsfx_pitch" },
  { "%f[%w]granular",              "jsfx_pitch" },
}

-- Exposed for callers outside this module (Net.send, the snapshot builder).
-- Keep the local in scope for in-module callers that already use it.
CTX.prompt_indicates_jsfx = _prompt_indicates_jsfx

function CTX.prompt_has_explicit_stock_fx_constraint(text)
  if type(text) ~= "string" or text == "" then return false end
  local t = text:lower()
  local stock_word = t:find("%f[%w]stock%f[%W]") ~= nil
    or t:find("%f[%w]cockos%f[%W]") ~= nil
  if not stock_word then return false end
  local names = { "reaeq", "reacomp", "reaxcomp", "reagate", "readelay",
    "realimit", "reapitch", "reatune", "reasynth", "reaverbate" }
  for _, name in ipairs(names) do
    if t:find(name, 1, true) then return true end
  end
  return t:find("%f[%w]only%f[%W]") ~= nil
    or t:find("stock only", 1, true) ~= nil
    or t:find("stock%-only", 1, false) ~= nil
    or t:find("no third%-party", 1, false) ~= nil
    or t:find("no third party", 1, true) ~= nil
end

function CTX.sticky_has_fx_params_for_ident(ident)
  if not ident or ident == "" or not S.sticky_context then return false end
  local target = _curated_for_ident(ident) or tostring(ident)
  target = target:gsub("^%w+:%s*", ""):lower()
  if target == "" then return false end
  for k in pairs(S.sticky_context) do
    local payload = k:match("^fx:(.+)$")
    if payload then
      for piece in payload:gmatch("[^/]+") do
        local name = piece:gsub("@%d+$", ""):lower()
        if name ~= "" and (name:find(target, 1, true)
            or target:find(name, 1, true)) then
          return true
        end
      end
    end
  end
  return false
end

function CTX.prompt_has_fx_param_read_intent(text)
  if type(text) ~= "string" or text == "" then return false end
  local t = text:lower()
  local names_params =
       t:find("%f[%w]parameters?%f[%W]") ~= nil
    or t:find("%f[%w]params?%f[%W]") ~= nil
  local names_settings =
       t:find("%f[%w]settings?%f[%W]") ~= nil
    or t:find("%f[%w]values?%f[%W]") ~= nil
    or t:find("set%s+to") ~= nil
  if not names_params and not names_settings then return false end
  return t:find("^%s*what%s+") ~= nil
    or t:find("^%s*which%s+") ~= nil
    or t:find("^%s*show%s+") ~= nil
    or t:find("^%s*list%s+") ~= nil
    or t:find("^%s*tell%s+") ~= nil
    or t:find("%f[%w]current%f[%W]") ~= nil
    or t:find("%f[%w]live%f[%W]") ~= nil
    or t:find("%f[%w]read%f[%W]") ~= nil
end

function CTX.live_fx_params_filter_for_ident(ident)
  if not ident or ident == "" then return nil end
  local proj = S.pending_project or reaper.EnumProjects(-1)
  if not proj then return nil end
  local target = _curated_for_ident(ident) or tostring(ident)
  target = target:gsub("^%w+:%s*", "")
  if target == "" then return nil end
  local queries = { target }
  if tostring(ident) ~= target then queries[#queries+1] = tostring(ident) end
  local track_count = R_CountTracks(proj)
  local tracks, seen = {}, {}
  for ti = 0, track_count - 1 do
    local tr = R_GetTrack(proj, ti)
    if tr then
      local fx_count = R_TrackFX_GetCount(tr) or 0
      for fi = 0, fx_count - 1 do
        local _, fx_nm = R_TrackFX_GetFXName(tr, fi, "")
        if CTX.fx_name_matches(fx_nm, queries) then
          local track_idx = ti + 1
          if not seen[track_idx] then
            tracks[#tracks+1] = track_idx
            seen[track_idx] = true
          end
        end
      end
    end
  end
  if #tracks == 1 then
    return { name = target, track = tracks[1] }
  end
  if #tracks > 1 and reaper.CountSelectedTracks and reaper.GetSelectedTrack then
    local selected_count = reaper.CountSelectedTracks(proj) or 0
    for si = 0, selected_count - 1 do
      local sel = reaper.GetSelectedTrack(proj, si)
      if sel then
        for ti = 0, track_count - 1 do
          if R_GetTrack(proj, ti) == sel and seen[ti + 1] then
            return { name = target, track = ti + 1 }
          end
        end
      end
    end
  end
  return nil
end

function CTX.preempt_live_fx_params_for_ident(ident, injected, reason, need_helpers)
  local filter = CTX.live_fx_params_filter_for_ident(ident)
  if not filter then return false end
  local fp_key = "fx:" .. CTX.fx_filter_key({ filter })
  if not S.sticky_context[fp_key] then
    local fx_str, matched = CTX.fx_params(S.pending_project or reaper.EnumProjects(-1),
      { filter })
    if not fx_str or not matched or matched < 1 then return false end
    Net.sticky_set(fp_key, fx_str, "preempt")
    injected[#injected+1] = fp_key
    Log.line("PREEMPT",
      "injected " .. fp_key .. " (live fx_params for " .. tostring(reason) .. ")")
  end
  if need_helpers then
    Net.copin_plugin_bundle(injected)
    Net.copin_docs_core(injected)
    Net.copin_plugin_helpers(injected, "preempt")
  end
  return true
end

function CTX.preempt_buckets_for_prompt(user_text)
  if not user_text or user_text == "" then return {} end
  local text = user_text:lower()
  if CTX.prompt_indicates_typed_action_plan(user_text) then
    Log.line("PREEMPT",
      "skipped context preempt (typed-action plan prompt)")
    return {}
  end
  local cache = FXCache.load()
  local pref_types = cache.preferred_types or {}
  -- JSFX-only intent suppresses the plugin_ref / pref / docs co-pin path
  -- in the type-keyword loop below. The JSFX_FAMILY_HINTS scan still runs
  -- (so prompt_bundle:jsfx_pitch etc. are pinned for "shimmer"-style
  -- prompts), and DOCS_PHRASE_HINTS still runs (envelopes/routing/etc.
  -- don't conflict with JSFX). What we skip is the `for tkey in keys` loop
  -- that pins plugin_ref:Pro-R 2 + pref:reverb + plugin bundle + docs core
  -- when the user has a curated pref for a type whose name appears in the
  -- prompt. Those payloads are useless for "create a JSFX <effect>" --
  -- the model writes EEL2, not reaper.* TrackFX_AddByName, and the docs
  -- gate is the safety net if it does choose to add a Lua companion.
  local jsfx_intent = _prompt_indicates_jsfx(user_text)
  local stock_fx_constraint = CTX.prompt_has_explicit_stock_fx_constraint(user_text)

  -- Scan chain-phrase hints first. Builds tkey -> matching_phrase so the
  -- main loop below can treat phrase hits identically to keyword hits and
  -- the log line can attribute the trigger.
  local phrase_implied = {}
  if not stock_fx_constraint then
    for _, hint in ipairs(CHAIN_PHRASE_HINTS) do
      if text:find(hint[1]) then
        for _, t in ipairs(hint[2]) do
          if not phrase_implied[t] then phrase_implied[t] = hint[1] end
        end
      end
    end
  end
  if phrase_implied.gate == "chain.-rock%s+vocal" then
    if phrase_implied.deesser == "chain.-vocal" then phrase_implied.deesser = nil end
    if phrase_implied.reverb == "chain.-vocal" then phrase_implied.reverb = nil end
  end
  local chain_phrase_hit = next(phrase_implied) ~= nil
  local preempt_needs_plugin_helpers =
    chain_phrase_hit or Code.prompt_has_param_write_intent(user_text)
  local preempt_live_fx_params =
    CTX.prompt_has_fx_param_read_intent(user_text)
    or Code.prompt_has_param_write_intent(user_text)

  -- injected: collected sticky_context keys we pre-pin this call. Hoisted
  -- above the docs-phrase scan so both the docs scan and the existing
  -- preferred-types loop below append to the same list. Returned at the end
  -- as the caller's "what we just preempted" log payload.
  local injected = {}

  do
    local recent_hit = false
    local recent_phrases = {
      "latest reaper", "current reaper", "new reaper", "recent reaper",
      "new in reaper", "what's new", "whats new",
      "reaper 7.65", "reaper 7.66", "reaper 7.67", "reaper 7.68",
      "reaper 7.69", "reaper 7.70", "reaper 7.71", "reaper 7.72",
      "sample edit", "sample editing", "sample edit envelope",
      "set sample values to zero", "render hidden marker",
      "render hidden region", "hidden marker", "hidden region",
      "wavpack", "render metadata", "embed project markers",
      "embed project regions", "font scaling", "font-size scaling",
      "theme font", "item label font", "ruler lane", "mouse modifier",
      "marker left drag", "region edge", "ruler lane header",
    }
    for _, phrase in ipairs(recent_phrases) do
      if text:find(phrase, 1, true) then
        recent_hit = phrase
        break
      end
    end
    if recent_hit and not S.sticky_context["recent_reaper_changes"] then
      local recent_content, recent_err = CTX.recent_reaper_changes()
      if recent_content then
        Net.sticky_set("recent_reaper_changes", recent_content, "preempt")
        injected[#injected+1] = "recent_reaper_changes"
        Log.line("PREEMPT",
          "injected recent_reaper_changes (recent phrase: '"
          .. tostring(recent_hit) .. "')")
      else
        Log.line("PREEMPT",
          "wanted to inject recent_reaper_changes but loader failed: "
          .. (recent_err or "?"))
      end
    end
  end

  -- Chain-build follow-up: pre-pin fx_chains so the model can honor the
  -- ADD-VS-REUSE rule. When the prompt is a chain phrase AND there's
  -- already prior conversation history, an earlier turn may have placed
  -- plugins on the target track(s) -- if the model can't see what's
  -- already there it defaults to AddByName for everything and silently
  -- duplicates the existing plugins. The bundle's CHAIN BUILD / UPSERT
  -- RULE describes the right behavior; this gives the model the data
  -- it needs to actually do it. First-turn chain prompts skip this
  -- (no prior plugins to reuse) so we don't pay for a snapshot that
  -- adds nothing.
  if chain_phrase_hit and #S.history > 0
     and not S.fx_chains_already_sent
     and not S.sticky_context["fx_chains"] then
    local proj = S.pending_project or 0
    local fx_snapshot = CTX.fx(proj)
    if fx_snapshot and fx_snapshot ~= "" then
      -- Prepend a short, high-salience upsert skeleton ahead of the
      -- chain data. The CHAIN BUILD / UPSERT RULE in prompt_bundle:plugin
      -- is correct but buried in a long bundle; small models often skip
      -- past it on first draft and the UPSERT-VALIDATOR catches them on
      -- retry. Putting the skeleton next to the data it applies to
      -- improves first-draft compliance for ~80 bytes.
      local upsert_header =
           "CHAIN BUILD = UPSERT (read this rule before writing code):\n"
        .. "  local fx = reaper.TrackFX_GetByName(tr, \"<bare name>\", false)\n"
        .. "  if fx < 0 then\n"
        .. "    fx = reaper.TrackFX_AddByName(tr, \"<format-prefixed id>\", false, -1)\n"
        .. "  end\n"
        .. "  if fx < 0 then ShowMessageBox + return end\n"
        .. "Apply to EVERY plugin in the chain. The static UPSERT-VALIDATOR "
        .. "rejects direct AddByName-only chains and forces a retry.\n"
        .. "HELPERS YOU CALL MUST BE PASTED: if your script calls "
        .. "set_param_display / set_param_enum / set_param_enum_paced / "
        .. "find_param, paste each helper's `local function NAME(...) end` "
        .. "source from prompt_bundle:plugin_helpers ABOVE main(). The "
        .. "static HELPER-VALIDATOR rejects called-but-undefined helpers "
        .. "and forces a retry.\n\n"
      Net.sticky_set("fx_chains", upsert_header .. fx_snapshot, "preempt")
      S.fx_chains_already_sent = true
      injected[#injected+1] = "fx_chains"
      Log.line("PREEMPT",
        "injected fx_chains (chain-phrase follow-up; lets the model "
        .. "honor ADD-VS-REUSE)")
    end
  end

  -- Scan docs-phrase hints. Each match pre-pins the docs:<section> bucket
  -- so the model doesn't need to emit <context_needed>docs:envelopes</context_needed>
  -- (etc.) on a follow-up. Idempotent via S.docs_section_sent + the sticky
  -- "already pinned" check. Errors are non-fatal (logged) -- a missing
  -- section file doesn't block the user's request.
  S.docs_section_sent = S.docs_section_sent or {}
  local sec_seen = {}
  for _, hint in ipairs(DOCS_PHRASE_HINTS) do
    if text:find(hint[1]) then
      local section = hint[2]
      if not sec_seen[section] then
        sec_seen[section] = true
        local sticky_key = "docs:" .. section
        if not S.sticky_context[sticky_key]
           and not S.docs_section_sent[section] then
          local sec_content, sec_err = CTX.docs_section(section)
          if sec_content then
            Net.sticky_set(sticky_key, sec_content)
            S.docs_section_sent[section] = true
            injected[#injected+1] = sticky_key
            Log.line("PREEMPT",
              "injected " .. sticky_key .. " (docs phrase: '" .. hint[1] .. "')")
          else
            Log.line("PREEMPT",
              "wanted to inject " .. sticky_key
              .. " but loader failed: " .. (sec_err or "?"))
          end
        end
      end
    end
  end
  if CTX.prompt_indicates_drum_edit(user_text) then
    local docs_already = S.api_ref_message ~= nil
    Net.copin_docs_core(injected)
    if not docs_already and S.api_ref_message then
      Log.line("PREEMPT",
        "injected docs (drum edit/quantize workflow)")
    end
    if not S.sticky_context["docs_extended"]
       and not S.docs_extended_already_sent then
      S.docs_extended_already_sent = true
      local ext_content, ext_err = CTX.docs_extended()
      if ext_content then
        Net.sticky_set("docs_extended", ext_content)
        injected[#injected+1] = "docs_extended"
        Log.line("PREEMPT",
          "injected docs_extended (drum edit/quantize workflow)")
      else
        Log.line("PREEMPT",
          "wanted to inject docs_extended for drum edit/quantize but "
          .. "loader failed: " .. (ext_err or "?"))
      end
    end
    for _, section in ipairs({ "items", "tempo" }) do
      local sticky_key = "docs:" .. section
      if not S.sticky_context[sticky_key]
         and not S.docs_section_sent[section] then
        local sec_content, sec_err = CTX.docs_section(section)
        if sec_content then
          Net.sticky_set(sticky_key, sec_content)
          S.docs_section_sent[section] = true
          injected[#injected+1] = sticky_key
          Log.line("PREEMPT",
            "injected " .. sticky_key
            .. " (drum edit/quantize workflow)")
        else
          Log.line("PREEMPT",
            "wanted to inject " .. sticky_key
            .. " for drum edit/quantize but loader failed: "
            .. (sec_err or "?"))
        end
      end
    end
  end
  -- JSFX effect-family bundles (jsfx_pitch, jsfx_reverb, ...). Each match
  -- pins the family bundle ON TOP OF the always-on prompt_bundle:jsfx
  -- core. Multiple families can fire in one turn (e.g. "shimmer chorus"
  -- would trigger jsfx_pitch + jsfx_modulation if both are registered).
  local fam_seen = {}
  for _, hint in ipairs(JSFX_FAMILY_HINTS) do
    if text:find(hint[1]) then
      local family = hint[2]
      if not fam_seen[family] then
        fam_seen[family] = true
        local pb_key = "prompt_bundle:" .. family
        local already_pinned = S.sticky_context[pb_key]
        Net.copin_jsfx_family(family, injected)
        if not already_pinned and S.sticky_context[pb_key] then
          Log.line("PREEMPT",
            "injected " .. pb_key .. " (jsfx phrase: '" .. hint[1] .. "')")
        end
      end
    end
  end

  -- Whenever JSFX intent is detected -- even for a generic request like
  -- "hall reverb" with no family-hint match -- pre-pin the base
  -- `prompt_bundle:jsfx` and `docs` (REAPER core API ref). The base bundle
  -- carries the safety mandates (feedback clamp, no output saturator,
  -- output-stage rules, srate / num_ch / play_state JSFX builtins) that
  -- weak models like GPT-5.4-mini-no-thinking won't request via
  -- <context_needed>; they just generate from training memory and produce
  -- typos like `samplespersec` (instead of `srate`) plus output sliders
  -- the bundle would have forbidden. Pre-pinning closes that hole.
  --
  -- Idempotent via the sticky_context already-pinned check inside
  -- Net.copin_jsfx_family / Net.copin_docs_core.
  if jsfx_intent then
    local base_key = "prompt_bundle:jsfx"
    local base_already = S.sticky_context[base_key]
    Net.copin_jsfx_family("jsfx", injected)
    if not base_already and S.sticky_context[base_key] then
      Log.line("PREEMPT",
        "injected " .. base_key .. " (JSFX intent: any JSFX request)")
    end
    local docs_already = S.api_ref_message ~= nil
    Net.copin_docs_core(injected)
    if not docs_already and S.api_ref_message then
      Log.line("PREEMPT",
        "injected docs (co-pin for JSFX Lua-companion path)")
    end
  end
  -- Dev-only: when the FabFilter-hide flag is on, treat matching entries
  -- in preferred_types as absent so the preempt path falls through to
  -- "no pref set" behavior (emits resolve:<type> and fires the popup we
  -- want to test). Read the flag fresh from ExtState rather than prefs
  -- so it stays current even if the dev_signal refresh didn't reach the
  -- main loop. Matches the same gate applied in CTX.preferred_plugins
  -- and CTX.load_pref_plugins.
  local hide_ff = reaper.GetExtState(CFG.EXT_NS, "dev_hide_fabfilter") == "1"
  -- Sorted key iteration for deterministic sticky_context ordering (keeps
  -- provider caches stable across turns when the same set of types hits).
  local keys = {}
  for k in pairs(pref_types) do keys[#keys+1] = k end
  table.sort(keys)
  -- Curated-pref dispatch shared with the resolve handler: when the user's
  -- saved preference for a type matches a CURATED_IDENT entry, both paths
  -- route through plugin_ref:<Name> instead of the live-scan
  -- preferred_plugins:<type>. The map lives at module scope (see
  -- CURATED_IDENT definition near PLUGIN_REF_ALIASES) so both the preempt
  -- and resolve paths stay in lockstep when the list is extended.
  --
  -- JSFX-intent skip: when the user explicitly asked for JSFX, do not pin
  -- any plugin_ref / pref / plugin bundle / docs core via this loop. The
  -- type-keyword match (e.g. "reverb" in "create a JSFX shimmer reverb")
  -- triggers all four pins on a Pro-R 2 user; the model never reads any of
  -- them while writing EEL2, and the docs co-pin alone is ~19K input
  -- tokens of waste. The docs-gate inside Net.try_finish_curl is
  -- still the safety net if the model does emit a Lua companion that
  -- needs reaper.* signatures.
  if jsfx_intent then
    if #keys > 0 then
      Log.line("PREEMPT",
        "skipped plugin_ref/pref keyword loop (JSFX intent)")
    end
    return injected
  end

  -- Direct curated-plugin-name preempt: when the user names a curated
  -- plugin in the prompt ("Add Pro-Q 4 to every track..."), pin
  -- plugin_ref:<Name> immediately even when no type-keyword ("eq")
  -- appears. Without this, the model has to emit
  -- <context_needed>fx_inspect:Pro-Q 4 + prompt_bundle:plugin</context_needed>
  -- on the first turn and then a SECOND retry once the docs gate fires --
  -- 3 calls instead of 1 for what's clearly a curated-plugin task. For
  -- each match, also pin pref:<tkey> if any saved pref maps to the same
  -- curated name (so the model gets the "this IS your saved pref" signal
  -- and skips a defensive resolve emission).
  local curated_unique = {}
  for _, name in pairs(CURATED_IDENT) do curated_unique[name] = true end
  for curated_name in pairs(curated_unique) do
    if text:find(curated_name:lower(), 1, true) then
      if preempt_live_fx_params
         and CTX.preempt_live_fx_params_for_ident(curated_name, injected,
           "direct curated name match", Code.prompt_has_param_write_intent(user_text)) then
        goto continue_curated_name
      end
      local pr_key = "plugin_ref:" .. curated_name
      if not S.sticky_context[pr_key]
         and not (S.plugin_ref_sent or {})[curated_name] then
        local rp_content, _ = CTX.plugin_ref({curated_name})
        if rp_content then
          CTX.populate_installed_fx()
          local exact_ident = nil
          if Code.resolve_chain_entry and CTX._installed_fx_list then
            exact_ident = Code.resolve_chain_entry(curated_name, CTX._installed_fx_list)
          end
          local prefix = ""
          if exact_ident and exact_ident ~= curated_name then
            prefix = "AddByName identifier on this system: `" .. exact_ident
              .. "` -- use this EXACT string with TrackFX_AddByName.\n\n"
          end
          Net.sticky_set(pr_key, prefix .. rp_content)
          if S.plugin_ref_sent then S.plugin_ref_sent[curated_name] = true end
          Net.copin_plugin_bundle(injected)
          Net.copin_docs_core(injected)
          if preempt_needs_plugin_helpers then
            Net.copin_plugin_helpers(injected, "preempt")
          end
          injected[#injected+1] = pr_key
          Log.line("PREEMPT",
            "injected " .. pr_key .. " (curated content, direct name match)"
            .. (exact_ident and (" exact=" .. exact_ident) or ""))
          -- Reverse-lookup pref:<tkey> if any saved pref maps to this curated.
          for tkey, ident in pairs(pref_types) do
            local mapped = ident and _curated_for_ident(ident) or nil
            if mapped == curated_name then
              if hide_ff and _is_fabfilter_ident(ident) then break end
              local pp_key = "pref:" .. tkey
              if not S.sticky_context[pp_key]
                 and not (S.pref_plugins_sent or {})[tkey] then
                local hint = "PREFERRED PLUGINS:\n"
                  .. "  " .. tkey .. " = " .. (exact_ident or ident or curated_name) .. "\n"
                  .. "(User's saved preference; full parameter reference above "
                  .. "in plugin_ref:" .. curated_name .. ". Use this plugin directly "
                  .. "and do NOT emit <context_needed>resolve:" .. tkey
                  .. "</context_needed>. For add-only/load-only tasks (no parameter "
                  .. "values set), use the AddByName identifier directly -- do NOT "
                  .. "emit <context_needed>fx_inspect:" .. (exact_ident or ident or curated_name)
                  .. "</context_needed> just to load the plugin. After every "
                  .. "TrackFX_AddByName, the next non-blank line MUST be `if "
                  .. "fx < 0 then ShowMessageBox(...) return end` before "
                  .. "using fx -- the static FX-CHECK-VALIDATOR rejects "
                  .. "unchecked AddByName results and forces a retry.)"
                Net.sticky_set(pp_key, hint)
                if S.pref_plugins_sent then S.pref_plugins_sent[tkey] = true end
                injected[#injected+1] = pp_key
                Log.line("PREEMPT",
                  "injected " .. pp_key .. " (pref hint for curated " .. curated_name .. ")")
              end
              break
            end
          end
        end
      end
    end
    ::continue_curated_name::
  end

  if stock_fx_constraint then
    if #keys > 0 then
      Log.line("PREEMPT",
        "skipped preferred-plugin keyword loop (explicit stock FX constraint)")
    end
    return injected
  end

  for _, tkey in ipairs(keys) do
    -- Word-boundary match so "eq" doesn't fire on "equal" / "sequence".
    -- %b pattern wouldn't help here; %f[%w] + %f[%W] brackets catch whole
    -- words including hyphenated ones like "de-esser".
    -- ALSO trigger when a CHAIN_PHRASE_HINTS entry implied this type (e.g.
    -- "drum kit" implies eq + compressor + gate). The phrase scan above
    -- populated phrase_implied[tkey] with the matching pattern so the log
    -- can attribute the trigger.
    local pat = "%f[%w]" .. tkey:gsub("(%W)", "%%%1") .. "%f[%W]"
    local kw_hit     = text:find(pat) ~= nil
    local phrase_hit = phrase_implied[tkey]
    if kw_hit or phrase_hit then
      local trigger = kw_hit
        and ("keyword match in user prompt")
        or  ("chain-phrase match: '" .. phrase_hit .. "'")
      local ident = pref_types[tkey]
      if hide_ff and _is_fabfilter_ident(ident) then
        ident = nil
      end
      -- When the filter (or a missing cache entry) leaves ident empty, skip
      -- the whole preempt for this type. Pinning a "no pref set" sticky
      -- here + marking pref_plugins_sent[tkey] would make the resolve
      -- dispatcher dedupe the model's <context_needed>resolve:<tkey></context_needed>
      -- request -- and the sticky itself tells the model to emit that
      -- tag -- so the two paths would chase each other forever. Letting
      -- the preempt fall through lets the resolve handler fire the popup.
      if not ident or ident == "" then
        goto continue_preempt
      end
      if preempt_live_fx_params
         and CTX.preempt_live_fx_params_for_ident(ident, injected,
           trigger, Code.prompt_has_param_write_intent(user_text)) then
        goto continue_preempt
      end
      if Code.prompt_has_param_write_intent(user_text)
         and CTX.sticky_has_fx_params_for_ident(ident) then
        Net.copin_plugin_bundle(injected)
        Net.copin_docs_core(injected)
        Net.copin_plugin_helpers(injected, "preempt")
        Log.line("PREEMPT",
          "skipped " .. tkey .. " plugin_ref (scoped live fx_params already pinned)")
        goto continue_preempt
      end
      -- Use the prefix/vendor-tolerant lookup so canonicalized prefs
      -- ("VST3: Pro-Q 4") still resolve to the curated section. A direct
      -- CURATED_IDENT[ident] would only match bare chain-entry form and
      -- would silently bypass curated plugin_ref content for every
      -- FabFilter pref after the preferred_types canonicalization.
      local curated = ident and _curated_for_ident(ident) or nil
      if curated then
        -- Curated plugin: inject plugin_ref:<Name> instead of
        -- preferred_plugins:<type>. Richer content, and doesn't depend
        -- on cache.plugins having scanned param data for the JSFX/stock.
        -- Also prepend the best enumerated identifier (e.g. "VST3: Pro-Q 4")
        -- so the model uses the exact format-prefixed string for
        -- TrackFX_AddByName -- prevents the bare-name fuzzy-match from
        -- loading a wrong version/format when multiple are installed.
        local pr_key = "plugin_ref:" .. curated
        if not S.sticky_context[pr_key]
           and not (S.plugin_ref_sent or {})[curated] then
          local rp_content, _ = CTX.plugin_ref({curated})
          if rp_content then
            -- Resolve the chain entry to the exact enumerated identifier
            -- (e.g. "Pro-Q 4" -> "VST3: Pro-Q 4") so the model uses the
            -- format-prefixed form. populate_installed_fx is cached -- the
            -- first preempt pays the one-time enumeration walk.
            CTX.populate_installed_fx()
            local exact_ident = nil
            if Code.resolve_chain_entry and CTX._installed_fx_list then
              exact_ident = Code.resolve_chain_entry(ident, CTX._installed_fx_list)
            end
            local prefix = ""
            if exact_ident and exact_ident ~= ident then
              prefix = "AddByName identifier on this system: `" .. exact_ident
                .. "` -- use this EXACT string with TrackFX_AddByName.\n\n"
            end
            Net.sticky_set(pr_key, prefix .. rp_content)
            if S.plugin_ref_sent then S.plugin_ref_sent[curated] = true end
            -- Piggyback prompt_bundle:plugin onto every plugin_ref pin: any
            -- plugin ADD/CONFIGURE task needs the plugin workflow rules, and
            -- co-pinning here saves the round-trip where the model would
            -- otherwise emit <context_needed>prompt_bundle:plugin</context_needed>.
            Net.copin_plugin_bundle(injected)
            -- Same rationale for docs core: every plugin add/configure task
            -- needs reaper.* signatures (TrackFX_*, defer, Undo_*). Without
            -- this, the rich plugin context biases the model into bypassing
            -- the API REF REQUIREMENT rule and the docs-gate has to retry.
            Net.copin_docs_core(injected)
            -- Co-pin plugin_helpers ON THE SAME TURN as plugin_bundle so
            -- helpers rides the stable rung's first emission instead of
            -- arriving mid-session via <context_needed>. Tagged "preempt"
            -- so Net.sticky_parts routes it to the stable rung (along with
            -- plugin_bundle) instead of growing -- the stable rung is
            -- being initialized this turn anyway, so adding helpers costs
            -- no extra cache miss but saves the helpers re-write that
            -- would otherwise happen on every subsequent growing-rung
            -- invalidation (each new plugin_ref / pref / fx_inspect).
            --
            -- Pre-pin helpers for explicit value writes and open-ended
            -- chain phrases. Add-only prompts ("add Pro-Q to track 1") still
            -- skip the ~17.8K-char helper bundle, but "build a vocal chain"
            -- / "chain suitable for a rock vocal" usually makes the model
            -- choose display-unit values and helper calls on its own. Pinning
            -- helpers here prevents the missing-helper retry for that family.
            if preempt_needs_plugin_helpers then
              Net.copin_plugin_helpers(injected, "preempt")
            end
            injected[#injected+1] = pr_key
            Log.line("PREEMPT",
              "injected " .. pr_key .. " (curated content, " .. trigger .. ")"
              .. (exact_ident and (" exact=" .. exact_ident) or ""))
            -- Co-pin a compact pref:<tkey> hint. Without it, the model
            -- sees plugin_ref:<Name> pinned but can't tell whether the name
            -- is the user's saved preference or just a curated default,
            -- and defensively emits <context_needed>resolve:<tkey></context_needed>
            -- to re-confirm -- a wasted round-trip (observed on the first
            -- plugin-type turn of every session). The pref:<tkey> entry
            -- gives the model an unambiguous "yes this IS the user's pref"
            -- signal, so it skips the resolve and writes code directly.
            -- Also marks pref_plugins_sent so the resolve dedup path fires
            -- if the model still emits resolve anyway.
            local pp_key = "pref:" .. tkey
            if not S.sticky_context[pp_key]
               and not (S.pref_plugins_sent or {})[tkey] then
              local hint = "PREFERRED PLUGINS:\n"
                .. "  " .. tkey .. " = " .. (exact_ident or ident or curated) .. "\n"
                .. "(User's saved preference; full parameter reference above "
                .. "in plugin_ref:" .. curated .. ". Use this plugin directly "
                .. "and do NOT emit <context_needed>resolve:" .. tkey
                .. "</context_needed>. For add-only/load-only tasks (no parameter "
                .. "values set), use the AddByName identifier directly -- do NOT "
                .. "emit <context_needed>fx_inspect:" .. (exact_ident or ident or curated)
                .. "</context_needed> just to load the plugin.)"
              Net.sticky_set(pp_key, hint)
              if S.pref_plugins_sent then S.pref_plugins_sent[tkey] = true end
              injected[#injected+1] = pp_key
              Log.line("PREEMPT",
                "injected " .. pp_key .. " (pref hint for curated " .. curated .. ")")
            end
          end
        end
      else
        -- Non-curated plugin: inject preferred_plugins:<type>.
        local pp_key = "pref:" .. tkey
        if not S.sticky_context[pp_key]
           and not (S.pref_plugins_sent or {})[tkey] then
          local pp_content, pp_err = CTX.preferred_plugins({tkey})
          if pp_content then
            -- Always-on directive (conditional in wording): tells the
            -- model that for add-only/load-only tasks the AddByName
            -- identifier in pp_content is sufficient, and fx_inspect
            -- isn't needed just to load the plugin. Without this, the
            -- model defensively emits <context_needed>fx_inspect:Name</context_needed>
            -- on add-only synth/instrument tasks even when pref already
            -- pins the AddByName string -- observed costing one extra
            -- API call on a "create a synth track + MIDI item" prompt
            -- where Twin 3 was already in pref:synth.
            local pp_directive = "\n\nDIRECTIVE: For add-only/load-only "
              .. "tasks (no parameter values set), use the AddByName "
              .. "identifier above directly with TrackFX_AddByName. Do "
              .. "NOT emit <context_needed>fx_inspect:Name</context_needed> "
              .. "just to load the plugin -- the parameter map is only "
              .. "needed when configuring values. After every "
              .. "TrackFX_AddByName, the next non-blank line MUST be `if "
              .. "fx < 0 then ShowMessageBox(...) return end` before using "
              .. "fx -- the static FX-CHECK-VALIDATOR rejects unchecked "
              .. "AddByName results and forces a retry."
            Net.sticky_set(pp_key, pp_content .. pp_directive)
            -- Mark sent so the model's <context_needed>preferred_plugins:tkey
            -- (if it emits one anyway) gets deduped by the bucket dispatcher.
            if S.pref_plugins_sent then S.pref_plugins_sent[tkey] = true end
            -- Co-pin plugin bundle + docs core (same rationale as the
            -- plugin_ref branch above: every pref-plugin pin drives a
            -- plugin task that needs both the workflow guide and the
            -- reaper.* signatures). Helpers rides the stable rung via
            -- the "preempt" source tag when this is an explicit value write
            -- or an open-ended chain phrase.
            Net.copin_plugin_bundle(injected)
            Net.copin_docs_core(injected)
            if preempt_needs_plugin_helpers then
              Net.copin_plugin_helpers(injected, "preempt")
            end
            injected[#injected+1] = pp_key
            Log.line("PREEMPT",
              "injected " .. pp_key .. " (" .. trigger .. ")")
          end
        end
      end
    end
    ::continue_preempt::
  end
  return injected
end

-- CTX.build_snapshot(proj, opts)
-- opts.minimal_tracks: emit a tracks-list trimmed to selected tracks +
-- count summary instead of the full per-track listing. Used by JSFX-only
-- prompts where the snapshot ships with a "create me an effect file"
-- request and the per-track names/item counts are dead weight.
-- The minimal listing bypasses the heavy-cache to keep the regular path
-- unaffected (the cache stores the full listing; reusing it across modes
-- would either return the wrong shape on a re-entry or require keying the
-- cache by mode).
function CTX.prompt_wants_routing_snapshot(user_text)
  local lt = tostring(user_text or ""):lower()
  if lt == "" then return false end
  if lt:find("send level", 1, true)
      or lt:find("send volume", 1, true)
      or lt:find("send gain", 1, true)
      or lt:find("level of the send", 1, true)
      or lt:find("volume of the send", 1, true)
      or lt:find("%f[%w]sends%f[%W]")
      or lt:find("%f[%w]receives%f[%W]")
      or lt:find("%f[%w]receive%s+from%f[%W]")
      or lt:find("%f[%w]send%s+to%f[%W]")
      or lt:find("%f[%w]send%s+into%f[%W]")
      or lt:find("%f[%w]route%s+to%f[%W]")
      or lt:find("%f[%w]routed%s+to%f[%W]")
      or lt:find("%f[%w]routing%f[%W]")
      or lt:find("%f[%w]sidechain%f[%W]")
      or lt:find("%f[%w]aux%f[%W]")
      or lt:find("%f[%w]bus%f[%W]")
      or lt:find("return track", 1, true) then
    return true
  end
  return false
end

CTX.build_snapshot = function(proj, opts)
  local minimal_tracks = opts and opts.minimal_tracks
  local drum_edit = (opts and opts.drum_edit) or S.pending_drum_edit_intent
  local state_count = reaper.GetProjectStateChangeCount(proj or 0)
  local c = CTX._snapshot_heavy_cache
  local tracks_txt, markers_txt
  if minimal_tracks then
    tracks_txt  = CTX.tracks(proj, { minimal = true })
    if c and c.proj == proj and c.state_count == state_count then
      markers_txt = c.markers
    else
      markers_txt = CTX.markers(proj)
    end
  elseif c and c.proj == proj and c.state_count == state_count then
    tracks_txt  = c.tracks
    markers_txt = c.markers
  else
    tracks_txt  = CTX.tracks(proj)
    markers_txt = CTX.markers(proj)
    CTX._snapshot_heavy_cache = {
      proj        = proj,
      state_count = state_count,
      tracks      = tracks_txt,
      markers     = markers_txt,
    }
  end
  local parts = {
    CTX.reaper_version(),
    CTX.tempo(proj),
    CTX.sample_rate(proj),
    CTX.play_state(proj),
    CTX.loop(proj),
    markers_txt,
    tracks_txt,
    CTX.selected(proj),
    CTX.time_selection(proj),
    CTX.cursor(proj),
    CTX.selected_items(proj),
  }
  if not minimal_tracks
      and CTX.prompt_wants_routing_snapshot(S.pending_orig_prompt) then
    parts[#parts + 1] = CTX.sends(proj, {})
  end
  if drum_edit then parts[#parts + 1] = CTX.dynamic_split_settings() end
  -- Multi-row sections (Tracks, FX chains, Track flags, Markers/regions,
  -- Selected items) use a compact pipe-delimited format with a header row
  -- declaring the columns. This shaves ~15-25% snapshot tokens on large
  -- sessions vs the previous prose form. Single-value lines remain
  -- human-readable. Pipe characters in track names are scrubbed to "_" to
  -- keep parsing trivial.
  local body = "SESSION CONTEXT (multi-row sections use pipe-delimited rows -- "
    .. "see each section's [col|col|...] header for column names):\n"
    .. tbl_concat(parts, "\n") .. "\n\n"
  local hint = CTX.target_hint(proj, S.pending_orig_prompt)
  if hint ~= "" then body = body .. hint .. "\n\n" end
  return body
end

-- =============================================================================
-- JSON helpers
-- =============================================================================
-- Sanitises a Lua byte string into valid UTF-8 by replacing any invalid byte
-- sequences with '?'. REAPER allows raw 8-bit bytes in track names, item
-- notes, and marker labels (often a result of dragged-in corrupt audio files
-- or weird VST presets), and the AI provider APIs reject any payload that
-- isn't strict UTF-8 with a 400 Bad Request.
--
-- Validates the four legal multi-byte forms (per RFC 3629):
--   1-byte: 0xxxxxxx
--   2-byte: 110xxxxx 10xxxxxx              (U+0080..U+07FF)
--   3-byte: 1110xxxx 10xxxxxx 10xxxxxx     (U+0800..U+FFFF, excluding surrogates)
--   4-byte: 11110xxx 10xxxxxx 10xxxxxx 10xxxxxx (U+10000..U+10FFFF)
-- Single-pass byte scan, no allocations on the happy path (string is returned
-- unchanged when it is already valid UTF-8).
local function sanitize_utf8(s)
  local len = #s
  local i = 1
  local out = nil  -- lazily allocated only if we hit invalid bytes
  while i <= len do
    local b1 = str_byte(s, i)
    local size, ok = 1, true
    if b1 < 0x80 then
      -- ASCII
      size = 1
    elseif b1 < 0xC2 then
      -- Continuation byte or overlong 2-byte form: invalid as a leading byte
      ok = false
    elseif b1 < 0xE0 then
      -- 2-byte sequence
      size = 2
      if i + 1 > len then ok = false
      else
        local b2 = str_byte(s, i + 1)
        if b2 < 0x80 or b2 > 0xBF then ok = false end
      end
    elseif b1 < 0xF0 then
      -- 3-byte sequence
      size = 3
      if i + 2 > len then ok = false
      else
        local b2 = str_byte(s, i + 1)
        local b3 = str_byte(s, i + 2)
        if b2 < 0x80 or b2 > 0xBF or b3 < 0x80 or b3 > 0xBF then
          ok = false
        elseif b1 == 0xE0 and b2 < 0xA0 then
          ok = false  -- overlong
        elseif b1 == 0xED and b2 > 0x9F then
          ok = false  -- UTF-16 surrogate half
        end
      end
    elseif b1 < 0xF5 then
      -- 4-byte sequence
      size = 4
      if i + 3 > len then ok = false
      else
        local b2 = str_byte(s, i + 1)
        local b3 = str_byte(s, i + 2)
        local b4 = str_byte(s, i + 3)
        if b2 < 0x80 or b2 > 0xBF
           or b3 < 0x80 or b3 > 0xBF
           or b4 < 0x80 or b4 > 0xBF then
          ok = false
        elseif b1 == 0xF0 and b2 < 0x90 then
          ok = false  -- overlong
        elseif b1 == 0xF4 and b2 > 0x8F then
          ok = false  -- > U+10FFFF
        end
      end
    else
      ok = false  -- 0xF5..0xFF: never valid
    end

    if ok then
      if out then out[#out+1] = str_sub(s, i, i + size - 1) end
      i = i + size
    else
      if not out then
        out = {}
        if i > 1 then out[1] = str_sub(s, 1, i - 1) end
      end
      out[#out+1] = "?"
      i = i + 1
    end
  end
  if out then return tbl_concat(out) end
  return s
end
JSON.sanitize_utf8 = sanitize_utf8

-- Escapes a Lua string for safe embedding inside a JSON string value.
-- Order matters: backslashes must be escaped first.
-- Also escapes control characters below 0x20 (backspace, form feed,
-- null bytes, etc.) that can appear in track names or user input and would
-- produce invalid JSON, causing silent API call failures. Invalid UTF-8 byte
-- sequences are replaced with '?' so the API never sees malformed payloads.
function JSON.escape(s)
  return sanitize_utf8(s)
           :gsub('\\', '\\\\')
           :gsub('"',  '\\"')
           :gsub('\n', '\\n')
           :gsub('\r', '\\r')
           :gsub('\t', '\\t')
           :gsub('[\x00-\x08\x0b\x0c\x0e-\x1f]', function(c)
             -- Encode remaining control chars as \u00XX JSON unicode escapes.
             return str_format('\\u%04x', str_byte(c))
           end)
end

-- =============================================================================
-- Minimal recursive-descent JSON decoder
-- =============================================================================
-- Proper parser that handles the full JSON spec: objects, arrays, strings
-- (with all escape sequences including \uXXXX), numbers, booleans, and null.
--
-- The decoder returns a native Lua table/value on success, or nil + error
-- string on malformed input. It never throws.
--
-- JSON null is represented by the sentinel table JSON.NULL rather than Lua nil.
-- This prevents silent key loss when a JSON object contains {"key": null},
-- since obj[key] = nil is a no-op in Lua. Callers should compare values
-- against JSON.NULL when null-awareness matters.
--
-- Performance: single-pass, no string copying for non-string values, avoids
-- gsub inside the hot path. Fast enough for the response sizes we handle
-- (typically 1-20 KB).
do
  -- Forward declarations for mutual recursion.
  local decode_value, decode_string, decode_number, decode_object, decode_array

  -- Skip whitespace and return the next non-whitespace position.
  local function skip_ws(s, pos)
    return str_match(s, "^%s*()", pos)
  end

  -- Decode a JSON string starting at the opening quote.
  -- Returns (lua_string, next_position) or (nil, error_string).
  decode_string = function(s, pos)
    -- pos points to the opening '"'
    pos = pos + 1  -- skip opening quote
    local len = #s
    local buf = {}
    while pos <= len do
      local ch = str_sub(s, pos, pos)
      if ch == '"' then
        return tbl_concat(buf), pos + 1
      elseif ch == '\\' then
        pos = pos + 1
        if pos > len then return nil, "unterminated string escape" end
        local esc = str_sub(s, pos, pos)
        if     esc == 'n'  then buf[#buf+1] = '\n'
        elseif esc == 't'  then buf[#buf+1] = '\t'
        elseif esc == 'r'  then buf[#buf+1] = '\r'
        elseif esc == '"'  then buf[#buf+1] = '"'
        elseif esc == '\\' then buf[#buf+1] = '\\'
        elseif esc == '/'  then buf[#buf+1] = '/'
        elseif esc == 'b'  then buf[#buf+1] = '\b'
        elseif esc == 'f'  then buf[#buf+1] = '\f'
        elseif esc == 'u'  then
          -- \uXXXX unicode escape. Decode to UTF-8 bytes.
          -- Handles surrogate pairs (\uD800-\uDFFF) for emoji/CJK.
          local hex = str_sub(s, pos + 1, pos + 4)
          local cp  = tonumber(hex, 16)
          if not cp then
            buf[#buf+1] = '\\u' .. hex
          else
            -- Surrogate pair: high surrogate followed by \uXXXX low surrogate.
            if cp >= 0xD800 and cp <= 0xDBFF then
              local lo_hex = str_sub(s, pos + 5, pos + 10)
              if str_sub(lo_hex, 1, 2) == "\\u" then
                local lo_cp = tonumber(str_sub(lo_hex, 3, 6), 16)
                if lo_cp and lo_cp >= 0xDC00 and lo_cp <= 0xDFFF then
                  cp = 0x10000 + (cp - 0xD800) * 0x400 + (lo_cp - 0xDC00)
                  pos = pos + 6  -- skip the low surrogate
                end
              end
            end
            -- Encode codepoint as UTF-8.
            if cp < 0x80 then
              buf[#buf+1] = str_char(cp)
            elseif cp < 0x800 then
              buf[#buf+1] = str_char(0xC0 + math_floor(cp / 64),
                                     0x80 + cp % 64)
            elseif cp < 0x10000 then
              buf[#buf+1] = str_char(0xE0 + math_floor(cp / 4096),
                                     0x80 + math_floor(cp / 64) % 64,
                                     0x80 + cp % 64)
            else
              buf[#buf+1] = str_char(0xF0 + math_floor(cp / 262144),
                                     0x80 + math_floor(cp / 4096) % 64,
                                     0x80 + math_floor(cp / 64) % 64,
                                     0x80 + cp % 64)
            end
          end
          pos = pos + 4
        else
          -- Unknown escape: preserve as-is for debugging.
          buf[#buf+1] = '\\' .. esc
        end
      else
        buf[#buf+1] = ch
      end
      pos = pos + 1
    end
    return nil, "unterminated string"
  end

  -- Decode a JSON number. Returns (number, next_position).
  decode_number = function(s, pos)
    local num_str = str_match(s, "^-?%d+%.?%d*[eE]?[+-]?%d*()", pos)
    if not num_str then return nil, "invalid number" end
    local val = tonumber(str_sub(s, pos, num_str - 1))
    if not val then return nil, "invalid number" end
    return val, num_str
  end

  -- Decode a JSON object. Returns (table, next_position).
  decode_object = function(s, pos)
    pos = pos + 1  -- skip '{'
    local obj = {}
    pos = skip_ws(s, pos)
    if str_sub(s, pos, pos) == '}' then return obj, pos + 1 end
    while true do
      pos = skip_ws(s, pos)
      if str_sub(s, pos, pos) ~= '"' then return nil, "expected string key" end
      local key, next_pos = decode_string(s, pos)
      if not key then return nil, next_pos end
      pos = skip_ws(s, next_pos)
      if str_sub(s, pos, pos) ~= ':' then return nil, "expected ':'" end
      pos = skip_ws(s, pos + 1)
      local val
      val, pos = decode_value(s, pos)
      if val == nil and type(pos) == "string" then return nil, pos end
      obj[key] = val
      pos = skip_ws(s, pos)
      local sep = str_sub(s, pos, pos)
      if sep == '}' then return obj, pos + 1 end
      if sep ~= ',' then return nil, "expected ',' or '}'" end
      pos = pos + 1
    end
  end

  -- Decode a JSON array. Returns (table, next_position).
  decode_array = function(s, pos)
    pos = pos + 1  -- skip '['
    local arr = {}
    pos = skip_ws(s, pos)
    if str_sub(s, pos, pos) == ']' then return arr, pos + 1 end
    while true do
      pos = skip_ws(s, pos)
      local val
      val, pos = decode_value(s, pos)
      if val == nil and type(pos) == "string" then return nil, pos end
      arr[#arr+1] = val
      pos = skip_ws(s, pos)
      local sep = str_sub(s, pos, pos)
      if sep == ']' then return arr, pos + 1 end
      if sep ~= ',' then return nil, "expected ',' or ']'" end
      pos = pos + 1
    end
  end

  -- Decode any JSON value. Top-level dispatch.
  decode_value = function(s, pos)
    pos = skip_ws(s, pos)
    local ch = str_sub(s, pos, pos)
    if ch == '"' then return decode_string(s, pos)
    elseif ch == '{' then return decode_object(s, pos)
    elseif ch == '[' then return decode_array(s, pos)
    elseif ch == 't' then
      if str_sub(s, pos, pos + 3) == "true" then return true, pos + 4 end
      return nil, "invalid value"
    elseif ch == 'f' then
      if str_sub(s, pos, pos + 4) == "false" then return false, pos + 5 end
      return nil, "invalid value"
    elseif ch == 'n' then
      if str_sub(s, pos, pos + 3) == "null" then return JSON.NULL, pos + 4 end
      return nil, "invalid value"
    elseif ch == '-' or (ch >= '0' and ch <= '9') then
      return decode_number(s, pos)
    else
      return nil, "unexpected character: " .. ch
    end
  end

  -- Public API: decode a JSON string into a Lua value.
  -- Returns (value, nil) on success, or (nil, error_string) on failure.
  -- Wrapped in pcall as a final safety net against any unforeseen edge case.
  JSON.decode = function(s)
    if type(s) ~= "string" or #s == 0 then
      return nil, "empty or non-string input"
    end
    local ok, result, next_pos = pcall(decode_value, s, 1)
    if not ok then return nil, tostring(result) end
    if result == nil and type(next_pos) == "string" then
      return nil, next_pos
    end
    return result, nil
  end
end

-- =============================================================================
-- Minimal recursive JSON encoder
-- =============================================================================
-- Encodes Lua values into compact or pretty-printed JSON strings.
-- Handles strings, numbers, booleans, nil, JSON.NULL, and tables
-- (auto-detects array vs object by checking sequential integer keys).
do
  local function is_array(t)
    local n = #t
    if n == 0 then
      -- Empty table: always encode as {} (object), never [].
      -- In this codebase empty tables are dictionaries, not empty arrays.
      return false
    end
    local count = 0
    for _ in pairs(t) do count = count + 1 end
    return count == n
  end

  local encode_value  -- forward declaration

  local function encode_string(s)
    return '"' .. JSON.escape(s) .. '"'
  end

  local function encode_number(n)
    if n ~= n then return '"NaN"' end             -- NaN safety
    if n == math.huge then return '"Infinity"' end
    if n == -math.huge then return '"-Infinity"' end
    if math.floor(n) == n and math.abs(n) < 2^53 then
      return str_format("%d", n)
    end
    return str_format("%.4f", n)
  end

  local function encode_array(t, indent, depth)
    if #t == 0 then return "[]" end
    local parts = {}
    for i = 1, #t do
      parts[i] = encode_value(t[i], indent, depth)
    end
    if indent then
      local pad = string.rep(indent, depth)
      local inner_pad = string.rep(indent, depth + 1)
      return "[\n" .. inner_pad .. tbl_concat(parts, ",\n" .. inner_pad) .. "\n" .. pad .. "]"
    end
    return "[" .. tbl_concat(parts, ",") .. "]"
  end

  local function encode_object(t, indent, depth)
    local parts = {}
    -- Collect and sort keys for deterministic output.
    local keys = {}
    for k in pairs(t) do keys[#keys+1] = k end
    table.sort(keys, function(a, b)
      local ta, tb = type(a), type(b)
      if ta ~= tb then return ta < tb end
      return a < b
    end)
    for _, k in ipairs(keys) do
      local ks = type(k) == "string" and encode_string(k) or ('"' .. tostring(k) .. '"')
      local vs = encode_value(t[k], indent, depth)
      if indent then
        parts[#parts+1] = ks .. ": " .. vs
      else
        parts[#parts+1] = ks .. ":" .. vs
      end
    end
    if #parts == 0 then return "{}" end
    if indent then
      local pad = string.rep(indent, depth)
      local inner_pad = string.rep(indent, depth + 1)
      return "{\n" .. inner_pad .. tbl_concat(parts, ",\n" .. inner_pad) .. "\n" .. pad .. "}"
    end
    return "{" .. tbl_concat(parts, ",") .. "}"
  end

  encode_value = function(v, indent, depth)
    depth = depth or 0
    if v == nil or v == JSON.NULL then return "null" end
    local tv = type(v)
    if tv == "string"  then return encode_string(v) end
    if tv == "number"  then return encode_number(v) end
    if tv == "boolean" then return v and "true" or "false" end
    if tv == "table"   then
      if is_array(v) then
        return encode_array(v, indent, depth + 1)
      else
        return encode_object(v, indent, depth + 1)
      end
    end
    return '"' .. tostring(v) .. '"'
  end

  -- Public API: encode a Lua value into a JSON string.
  -- Pass indent string (e.g. "  ") for pretty-printing, or nil for compact.
  JSON.encode = function(value, indent)
    local ok, result = pcall(encode_value, value, indent, 0)
    if not ok then return nil, tostring(result) end
    return result, nil
  end
end

-- Expose JSON to dofile'd sidecar modules (Resources/Diag.lua, future
-- v1.1 diagnostics modules). Required because JSON is `local` to this file
-- (forward-declared at line ~2366, populated above). Sidecar modules loaded
-- via dofile cannot see lexical locals from the parent file; they use RA.JSON
-- instead. Must come AFTER the do/end block above so RA.JSON points to the
-- fully populated table.
RA.JSON = JSON

-- =============================================================================
-- Auto-update module
-- =============================================================================
-- Non-blocking update checker. On startup (when prefs.update_check is on
-- and UPDATE_BASE_URL is configured) fires an async curl for manifest.json;
-- if a newer version exists the UI offers "Update Available". Each file
-- is fetched, SHA-256 verified against the manifest, and written to the
-- script directory (any hash mismatch rolls back the whole update). An
-- organic check failure stays silent (update.state = "idle"); only a
-- user-forced Repair surfaces errors via Updater._set_failure.
-- Manifest schema: see .tools/gen_manifest.py.

-- =============================================================================
-- SHA-256 (pure Lua, no external dependencies)
-- =============================================================================
-- Minimal implementation for update integrity verification. Operates on
-- 8-bit byte strings via string.byte. Lua 5.3+ bitwise operators; loaded
-- via load() so this whole block parses cleanly on older linters too.
--
-- Two interfaces:
--   sha256_hash(msg)              -- single-shot. Used by download_poll
--                                    where each file is small and gets
--                                    hashed once after a successful write.
--   _SHA.create(content)          -- chunked: returns state ready for step().
--   _SHA.step(state, max_blocks)  -- process up to N 64-byte blocks; returns
--                                    true when state is exhausted.
--   _SHA.finalize(state)          -- return hex digest of completed state.
--
-- Pure-Lua SHA-256 throughput on commodity hardware sits around ~1 MB/s
-- on Lua 5.4. The two largest manifest files (ReaAssist.lua and
-- UI.lua, ~700 KB each) take 600+ ms each in single-shot mode
-- which is a visible REAPER hitch. The chunked interface lets
-- Updater.tick_sha_diff process work for a per-frame time budget
-- (CFG.UPDATE_SHA_TIME_BUDGET), spreading the same total work across
-- many frames so each frame stays inside the budget regardless of CPU.
local sha256_hash
local _SHA = {}
do
  local band   = load("return function(a,b) return a & b end")()
  local bor    = load("return function(a,b) return a | b end")()
  local bxor   = load("return function(a,b) return a ~ b end")()
  local bnot   = load("return function(a) return ~a & 0xFFFFFFFF end")()
  local rshift = load("return function(a,n) return (a >> n) & 0xFFFFFFFF end")()
  local lshift = load("return function(a,n) return (a << n) & 0xFFFFFFFF end")()

  local function rrotate(x, n) return bor(rshift(x, n), lshift(x, 32 - n)) end

  local K = {
    0x428a2f98, 0x71374491, 0xb5c0fbcf, 0xe9b5dba5,
    0x3956c25b, 0x59f111f1, 0x923f82a4, 0xab1c5ed5,
    0xd807aa98, 0x12835b01, 0x243185be, 0x550c7dc3,
    0x72be5d74, 0x80deb1fe, 0x9bdc06a7, 0xc19bf174,
    0xe49b69c1, 0xefbe4786, 0x0fc19dc6, 0x240ca1cc,
    0x2de92c6f, 0x4a7484aa, 0x5cb0a9dc, 0x76f988da,
    0x983e5152, 0xa831c66d, 0xb00327c8, 0xbf597fc7,
    0xc6e00bf3, 0xd5a79147, 0x06ca6351, 0x14292967,
    0x27b70a85, 0x2e1b2138, 0x4d2c6dfc, 0x53380d13,
    0x650a7354, 0x766a0abb, 0x81c2c92e, 0x92722c85,
    0xa2bfe8a1, 0xa81a664b, 0xc24b8b70, 0xc76c51a3,
    0xd192e819, 0xd6990624, 0xf40e3585, 0x106aa070,
    0x19a4c116, 0x1e376c08, 0x2748774c, 0x34b0bcb5,
    0x391c0cb3, 0x4ed8aa4a, 0x5b9cca4f, 0x682e6ff3,
    0x748f82ee, 0x78a5636f, 0x84c87814, 0x8cc70208,
    0x90befffa, 0xa4506ceb, 0xbef9a3f7, 0xc67178f2,
  }

  -- Build incremental state from a plain content string. Pre-pads the
  -- message to a 64-byte boundary so subsequent step() calls only need
  -- to compress complete 64-byte blocks (no partial-block bookkeeping
  -- across calls). Pre-padding cost is O(n) memcpy, negligible vs the
  -- compression work that follows.
  function _SHA.create(content)
    local len = #content
    local extra = 64 - ((len + 9) % 64)
    if extra == 64 then extra = 0 end
    local msg = content .. "\128" .. ("\0"):rep(extra + 4)
       .. string.char(
            band(rshift(len * 8, 24), 0xFF),
            band(rshift(len * 8, 16), 0xFF),
            band(rshift(len * 8, 8), 0xFF),
            band(len * 8, 0xFF))
    return {
      msg = msg,
      pos = 1,                        -- next byte (1-indexed) to compress
      h0  = 0x6a09e667, h1 = 0xbb67ae85,
      h2  = 0x3c6ef372, h3 = 0xa54ff53a,
      h4  = 0x510e527f, h5 = 0x9b05688c,
      h6  = 0x1f83d9ab, h7 = 0x5be0cd19,
    }
  end

  -- Process up to max_blocks complete 64-byte chunks starting at
  -- state.pos. Updates state.h0..h7 and advances state.pos. Returns
  -- true when all blocks have been compressed (state ready for
  -- finalize), false when more remain. Pass math.huge to drain all
  -- remaining blocks in one call (single-shot mode).
  function _SHA.step(state, max_blocks)
    local msg = state.msg
    local total = #msg
    local h0, h1, h2, h3 = state.h0, state.h1, state.h2, state.h3
    local h4, h5, h6, h7 = state.h4, state.h5, state.h6, state.h7
    local pos = state.pos
    local processed = 0
    while pos <= total and processed < max_blocks do
      local W = {}
      for t = 1, 16 do
        local b = pos + (t - 1) * 4
        W[t] = lshift(string.byte(msg, b), 24)
             + lshift(string.byte(msg, b + 1), 16)
             + lshift(string.byte(msg, b + 2), 8)
             + string.byte(msg, b + 3)
      end
      for t = 17, 64 do
        local s0 = bxor(rrotate(W[t-15], 7),
                        bxor(rrotate(W[t-15], 18), rshift(W[t-15], 3)))
        local s1 = bxor(rrotate(W[t-2], 17),
                        bxor(rrotate(W[t-2], 19), rshift(W[t-2], 10)))
        W[t] = (W[t-16] + s0 + W[t-7] + s1) % 0x100000000
      end
      local a, b, c, d, e, f, g, h = h0, h1, h2, h3, h4, h5, h6, h7
      for t = 1, 64 do
        local S1 = bxor(rrotate(e, 6),
                        bxor(rrotate(e, 11), rrotate(e, 25)))
        local ch = bxor(band(e, f), band(bnot(e), g))
        local temp1 = (h + S1 + ch + K[t] + W[t]) % 0x100000000
        local S0 = bxor(rrotate(a, 2),
                        bxor(rrotate(a, 13), rrotate(a, 22)))
        local maj = bxor(band(a, b), bxor(band(a, c), band(b, c)))
        local temp2 = (S0 + maj) % 0x100000000
        h = g; g = f; f = e; e = (d + temp1) % 0x100000000
        d = c; c = b; b = a; a = (temp1 + temp2) % 0x100000000
      end
      h0 = (h0 + a) % 0x100000000; h1 = (h1 + b) % 0x100000000
      h2 = (h2 + c) % 0x100000000; h3 = (h3 + d) % 0x100000000
      h4 = (h4 + e) % 0x100000000; h5 = (h5 + f) % 0x100000000
      h6 = (h6 + g) % 0x100000000; h7 = (h7 + h) % 0x100000000
      pos = pos + 64
      processed = processed + 1
    end
    state.h0, state.h1, state.h2, state.h3 = h0, h1, h2, h3
    state.h4, state.h5, state.h6, state.h7 = h4, h5, h6, h7
    state.pos = pos
    return pos > total
  end

  function _SHA.finalize(state)
    return string.format("%08x%08x%08x%08x%08x%08x%08x%08x",
      state.h0, state.h1, state.h2, state.h3,
      state.h4, state.h5, state.h6, state.h7)
  end

  sha256_hash = function(msg)
    local s = _SHA.create(msg)
    _SHA.step(s, math.huge)
    return _SHA.finalize(s)
  end
end

-- Expose sha256_hash to dofile'd sidecar modules. Resources/Diag.lua
-- prefers RA.sha256_hex over its own pure-Lua fallback (this implementation
-- is the same algorithm but the existing instance is already loaded and
-- well-tested by the updater pipeline). Optional dependency; Diag.lua
-- checks for the function before using and falls back to its own SHA-256
-- if absent.
RA.sha256_hex = sha256_hash

-- =============================================================================
-- Local deterministic action modules
-- =============================================================================
-- These sidecars hold focused, non-LLM feature implementations that are too
-- substantial to keep in ReaAssist.lua. They are non-critical at startup:
-- a missing/corrupt module disables that local action but must not prevent the
-- chat UI, updater, or recovery flow from loading.
RA.Local = RA.Local or {}
do
  local path = RA.RESOURCES_DIR .. "Local" .. RA.SEP .. "Drum_Edit.lua"
  local ok, mod_or_err = pcall(dofile, path)
  if ok and type(mod_or_err) == "table" then
    RA.Local.Drum_Edit = mod_or_err
  else
    RA.Local.Drum_Edit = {
      name = "Drum_Edit",
      ready = false,
      unavailable_reason = tostring(mod_or_err),
    }
    if not ok and type(Log) == "table" and type(Log.line) == "function" then
      Log.line("LOCAL", "Drum_Edit.lua load failed: " .. tostring(mod_or_err))
    end
  end
end

-- Cross-chunk namespace. The UI file's Update-Available and File-
-- Integrity dialogs call Updater.download_start / Updater.force_reinstall,
-- so this table must be a plain global (chunk-local `local` would make
-- it invisible to the dofile'd UI chunk). The state table next to it is
-- lowercase `update`.
Updater = {}

-- Stamp a structured failure reason onto the update state so the
-- Bootstrap repair prompt can show the user *why* the last attempt
-- failed instead of silently re-rendering the Repair button. Also
-- emits a Log.line so Resources/Debug.log records the same
-- detail for post-mortem.
function Updater._set_failure(step, err)
  update.last_step  = step
  update.last_error = err
  Log.line("UPDATE", string.format("fail [%s]: %s",
                                   tostring(step), tostring(err)))
end

-- True when the updater is mid-flight on a fetch, verification, download,
-- or rename. Centralises the four-state predicate that gates re-entry on
-- force_reinstall, manual_check, the chat-piggyback check_start, and the
-- UI's ver_busy / busy disabled-button flags. A single helper means a
-- future state addition only needs to land in one place rather than five
-- separate condition lists.
function Updater.is_busy()
  return update.state == "checking"
      or update.state == "verifying"
      or update.state == "downloading"
      or update.state == "rename_retry"
end

-- Compare two semver strings numerically. Returns true if remote > local.
function Updater.is_newer(remote_ver, local_ver)
  local function parse(v)
    local parts = {}
    for n in v:gmatch("(%d+)") do parts[#parts+1] = tonumber(n) end
    return parts
  end
  local r, l = parse(remote_ver), parse(local_ver)
  for i = 1, math_max(#r, #l) do
    local rv, lv = r[i] or 0, l[i] or 0
    if rv > lv then return true end
    if rv < lv then return false end
  end
  return false
end

-- Fire an async curl GET. Writes response to out_path, exit code to exit_path.
-- Returns true if launched, false if URL is empty or launch fails.
function Updater.fire_get(url, out_path, exit_path)
  if not url or url == "" then return false end
  os.remove(out_path)
  os.remove(exit_path)
  -- Cache-busting: append a unix-time query parameter to the URL.
  -- GitHub's raw CDN keys on URL, so a unique timestamp guarantees a
  -- cache miss on every check. This eliminates the propagation race we
  -- have hit during rapid test-branch iteration where a new manifest
  -- and its updated file SHAs can be cached separately, leading to
  -- false repair popups on first launch after an update push.
  --
  -- We previously also sent Cache-Control / Pragma no-cache headers,
  -- but on Windows the literal double quotes around those header
  -- values broke the outer PowerShell -Command argument parse: the
  -- inner `"` terminated PowerShell's -Command string early, curl
  -- never ran, and the manual update check toasted "Could not reach
  -- update server" on every press. The timestamp query alone is
  -- sufficient (a CDN cannot serve a cached response for a URL it has
  -- never seen before), so the headers were dropped.
  local sep = url:find("?", 1, true) and "&" or "?"
  -- Cache-bust query: combine os.time() seconds with time_precise()
  -- millisecond fraction so two fetches inside the same second still
  -- produce distinct URLs. Pure os.time() collides on rapid Retry
  -- clicks (the v0.9.8.22 CDN-propagation fix encourages users to
  -- click Retry repeatedly), and a duplicate URL re-hits whatever
  -- the CDN has cached for that key, defeating the whole point.
  local ms = math.floor((time_precise() % 1) * 1000)
  url = url .. sep .. "_=" .. tostring(os.time())
                  .. string.format("%03d", ms)
  local timeout = CFG.UPDATE_CURL_TIMEOUT
  if RA.IS_WINDOWS then
    -- Defensive guard limited to characters that cannot legitimately
    -- appear in a valid Windows path OR a valid URL: " < > | are all
    -- reserved by Windows filenames and are also invalid in URLs (or,
    -- for ", a quote-terminator that would break the inner cmd arg
    -- parse). Other cmd-significant chars (& ^ ( ) %) ARE valid in
    -- Windows paths ("Program Files (x86)", user dirs like "R&D")
    -- and in URL query strings; the triple-quoted argument passing
    -- protects them, so we must NOT reject them or update / repair
    -- would silently fail for users on those paths.
    for _, c in ipairs({'"', '<', '>', '|'}) do
      if url:find(c, 1, true)
          or out_path:find(c, 1, true)
          or exit_path:find(c, 1, true) then
        Log.line("UPDATE", string.format(
          "fire_get: refusing to launch with cmd-unsafe character '%s' "
          .. "in URL or path", c))
        return false
      end
    end
    local cmd_line = str_format(
      'curl -s --connect-timeout 10 --max-time %d'
      .. ' "%s" -o """%s"""'
      .. ' & echo %%errorlevel%% > """%s"""',
      timeout, url, out_path, exit_path)
    local ps_cmd = str_format(
      'powershell -NoProfile -WindowStyle Hidden'
      .. ' -Command "Start-Process cmd -ArgumentList \'/c %s\''
      .. ' -WindowStyle Hidden"',
      Shell.ps_escape(cmd_line))
    reaper.ExecProcess(ps_cmd, 5000)
  else
    -- Single-quote the URL on POSIX shells. Double quotes still allow
    -- $(...) and `...` command substitution, so a malicious or malformed
    -- manifest filename baked into the URL could execute. is_safe_filename
    -- already blocks shell-sensitive characters, but quoting cleanly here
    -- closes the gap as defense-in-depth.
    local cmd = str_format(
      '(curl -s --connect-timeout 10 --max-time %d'
      .. ' %s -o %s ; echo $? > %s) &',
      timeout, Shell.sh_quote(url), Shell.sh_quote(out_path),
      Shell.sh_quote(exit_path))
    os.execute(cmd)
  end
  -- NOTE: Neither ExecProcess nor os.execute reliably indicate launch failure,
  -- so send_time is set unconditionally. If the process never started, the
  -- watchdog in Updater.poll() will time out after UPDATE_CURL_TIMEOUT + 10s.
  update.send_time = time_precise()
  return true
end

-- Poll for completion of the current async curl. Returns "done", "waiting", or "error".
function Updater.poll()
  if not update.send_time then return "error" end
  -- Watchdog: give up after timeout + generous slack.
  if (time_precise() - update.send_time) > (CFG.UPDATE_CURL_TIMEOUT + 10) then
    return "error"
  end
  -- io.open returns nil + err on failure; never throws. Direct call
  -- keeps the control flow flat.
  local ef = io.open(tmp.update_exit, "r")
  if not ef then return "waiting" end
  local exit_str = ef:read("*a"); ef:close()
  local exit_code = tonumber(exit_str:match("(%d+)"))
  if not exit_code then return "waiting" end
  if exit_code ~= 0 then return "error" end
  return "done"
end

-- Read and parse the response file. Returns parsed table or nil.
function Updater.read_response()
  local f = io.open(tmp.update_out, "r")
  if not f then return nil end
  local raw = f:read("*a"); f:close()
  if not raw or #raw < 2 then return nil end
  local data, err = JSON.decode(raw)
  if not data or type(data) ~= "table" then return nil end
  return data
end

-- Force a reinstall: bypass version check, daily cap, and snooze.
-- Re-entry guard: bail when a curl is already in flight. Without it, a
-- double-click on Bootstrap's Repair button (which stays rendered during
-- "checking" because Bootstrap's state dispatcher falls through to
-- render_prompt on unknown states) would double-fire the curl while the
-- first one is still writing to tmp.update_out / tmp.update_exit,
-- corrupting the read.
function Updater.force_reinstall()
  if CFG.UPDATE_BASE_URL == "" then return false end
  if Updater.is_busy() then return false end
  update.force = true
  update.popup_opened = false
  -- Clear stale failure metadata from a previous attempt. Without this,
  -- a Retry-after-failed click inherits the prior failure's last_step /
  -- last_error / repair_missing / repair_mismatched / action_was_repair
  -- values until the new check_poll result lands. The Update Failed
  -- dialog branches its copy on update.last_step (sha_verify gets the
  -- CDN-propagation message; everything else gets the generic copy), so
  -- a brief frame with a stale last_step could flash the wrong message.
  -- Mirror download_start's clean-slate pattern (download_queue,
  -- applied_files, skipped_count) for the failure-display fields too.
  update.last_step         = nil
  update.last_error        = nil
  update.repair_missing    = nil
  update.repair_mismatched = nil
  update.action_was_repair = nil
  local url = CFG.UPDATE_BASE_URL .. "/" .. CFG.UPDATE_MANIFEST
  if Updater.fire_get(url, tmp.update_out, tmp.update_exit) then
    update.state = "checking"
    return true
  end
  return false
end

-- Start the manifest check. Called from loop() on the first idle->waiting
-- chat-send edge in the session, so PowerShell is already warm from the
-- chat's curl and this check's ExecProcess cost is ~200ms instead of
-- 1-3s cold. No 24h throttle: the session flag
-- `update._session_check_fired` already prevents multiple fires per
-- session, and gating the fetch itself would prevent repair detection
-- too; we NEED a fresh manifest every session to compute the local-
-- vs-remote SHA diff. The update-nag snooze is honored lower in the
-- pipeline (check_poll's available branch) so it only suppresses the
-- "Update Available" popup, never the repair flow. Stamp
-- update_last_check here so any future consumer that wants a "time of
-- most recent successful fetch" reading has one.
function Updater.check_start()
  if CFG.UPDATE_BASE_URL == "" then return end
  if not prefs.update_check then return end
  -- Busy guard: the chat-piggyback fires on the first idle->waiting
  -- transition of the session, but a user could already have launched
  -- a manual Check / Repair in the same window. Without this guard the
  -- piggyback would fire a second curl that shares tmp.update_out /
  -- tmp.update_exit with the in-flight one, racing the manifest check
  -- against a download and corrupting the read.
  if Updater.is_busy() then return end
  reaper.SetExtState(CFG.EXT_NS, "update_last_check",
    tostring(os.time()), true)
  local url = CFG.UPDATE_BASE_URL .. "/" .. CFG.UPDATE_MANIFEST
  if Updater.fire_get(url, tmp.update_out, tmp.update_exit) then
    update.state = "checking"
  end
end

-- User-initiated check, wired to the "Check for Updates" button in
-- Settings. Bypasses the 24h throttle and the snooze (user is explicitly
-- asking), but unlike force_reinstall does NOT set update.force = true:
-- if the server is on the same version and SHAs match, we want to show
-- a friendly "You're up to date" toast instead of misleadingly offering
-- a reinstall. Bumps the throttle timestamp so the chat-piggyback does
-- not immediately re-fire the check on the user's next send.
function Updater.manual_check()
  if CFG.UPDATE_BASE_URL == "" then
    UI.show_float_toast("Update URL not configured", "err")
    return false
  end
  if Updater.is_busy() then return false end
  reaper.SetExtState(CFG.EXT_NS, "update_last_check",
    tostring(os.time()), true)
  update._manual = true
  -- Reset popup_opened so the "Update Available" dialog re-fires when
  -- this manual check finds an update. Without this, a sequence of
  -- (auto-fire piggyback shows popup -> Later -> manual check) would
  -- silently re-set state = "available" but the auto-show guard
  -- (`not update.popup_opened`) would suppress the popup the user
  -- explicitly asked to re-trigger. Same pattern as force_reinstall.
  update.popup_opened = false
  -- Sticky "Checking..." toast appears instantly so the user's click
  -- has immediate visual feedback during the PowerShell + curl round
  -- trip. check_poll replaces or clears this toast on every non-
  -- waiting result (up-to-date -> "up to date" toast; update or repair
  -- available -> cleared so the popup carries the feedback alone;
  -- error -> replaced with a specific error toast).
  UI.show_float_toast("Checking for updates...", "ok", true)
  local url = CFG.UPDATE_BASE_URL .. "/" .. CFG.UPDATE_MANIFEST
  if Updater.fire_get(url, tmp.update_out, tmp.update_exit) then
    update.state = "checking"
    return true
  end
  update._manual = false
  UI.show_float_toast("Update check failed to start", "err")
  return false
end

-- =============================================================================
-- SHA-256 verification pipeline (native subprocess + pure-Lua fallback)
-- =============================================================================
-- start_sha_diff preflights the manifest in pure Lua (classifying each entry
-- as missing / locked-skip / readable) and then prefers a native SHA-256
-- subprocess (PowerShell Get-FileHash on Windows; sha256sum / shasum -a 256
-- on POSIX) over the pure-Lua incremental hasher. Native is hundreds of MB/s
-- vs ~1 MB/s pure-Lua, so on a ~3.6 MB manifest the verify tail drops from
-- 5-12 s to well under 1 s.
--
-- The pure-Lua path remains as the reliability floor. It runs when:
--   * The native launcher couldn't start (PowerShell missing, AV block,
--     no sha256sum / shasum on POSIX, paths-file write error)
--   * tick_native_sha hits a non-zero exit, watchdog timeout, or
--     suspicious output (preflighted file readable but missing from
--     native output)
-- Each tick_sha_diff call compresses up to s.budget seconds of SHA work
-- (CFG.UPDATE_SHA_TIME_BUDGET for background piggyback,
-- CFG.UPDATE_SHA_TIME_BUDGET_MANUAL for manual / forced) at the 64-byte SHA
-- block level, so REAPER stays responsive even if every file has to be
-- hashed in-Lua. The main loop pumps either tick_native_sha or
-- tick_sha_diff once per frame while update.state == "verifying", same
-- shape as "checking" / "downloading" / "rename_retry".
--
-- download_start (the post-Update-Now path) keeps its own per-file
-- file_sha256_hex calls inline -- it's fired by an explicit user click
-- and only takes the same hash hit once, so a brief stall before the
-- download progress UI takes over is acceptable there.

-- Begin SHA verification. Caller passes the parsed manifest plus the
-- snapshotted manual / forced flags (so tick_*_sha -> _complete can branch
-- on the same intent that check_poll captured). Two-phase pipeline:
--
--   1) Preflight (in this function, in pure Lua): walk manifest, classify
--      each entry as missing / locked-skip / readable. Missing entries are
--      recorded directly in s.diff.missing; locked ones are logged and
--      skipped (preserving today's "AV / editor lock = treat as intact"
--      semantics so transient locks don't produce false Repair-Available
--      popups). Readable entries are collected into s.to_hash[].
--
--   2) Hash (deferred across frames): prefer native SHA-256 via PowerShell
--      Get-FileHash on Windows or sha256sum / shasum -a 256 on POSIX;
--      native is hundreds of MB/s vs ~1 MB/s pure-Lua, so on a ~3.6 MB
--      manifest the verify tail drops from 5-12 s to well under 1 s. Pure-
--      Lua remains the reliability floor: if the native subprocess fails
--      to launch, exits non-zero, watchdog-times-out, or produces output
--      that doesn't match preflight, _native_to_lua_fallback flips
--      s.mode = "lua_fallback" and tick_sha_diff walks s.to_hash from
--      idx 1 to recompute from a known-good code path.
--
-- Sets state = "verifying" so the main loop knows to pump the right tick
-- function each frame (tick_native_sha when s.mode == "native";
-- tick_sha_diff when s.mode == "lua" or "lua_fallback").
function Updater.start_sha_diff(manifest, manual, forced)
  local diff = { missing = {}, mismatched = {} }
  local to_hash = {}            -- list of { path, entry }
  local path_to_entry = {}      -- absolute path -> entry, for native parse

  for _, entry in ipairs(manifest.files or {}) do
    if type(entry) == "table" and type(entry.name) == "string"
        and type(entry.sha256) == "string"
        and Updater.is_safe_filename(entry.name) then
      local path = Updater.local_path_for(entry.name)
      local f, open_err = io.open(path, "rb")
      if not f then
        if reaper.file_exists and reaper.file_exists(path) then
          -- Locked: skip from diff entirely (treat as intact). See
          -- tick_sha_diff's note about Repair-Available false positives.
          Log.line("UPDATE", string.format(
            "start_sha_diff preflight: %s exists but open failed: %s "
            .. "(likely AV / editor lock; skipping from diff)",
            path, tostring(open_err)))
        else
          diff.missing[#diff.missing+1] = entry.name
        end
      else
        f:close()
        to_hash[#to_hash+1] = { path = path, entry = entry }
        path_to_entry[path] = entry
      end
    end
    -- Malformed manifest entry: skip silently (is_safe_filename gates the
    -- same way in download_start's inline diff).
  end

  update._sha_diff = {
    manifest      = manifest,
    files         = manifest.files,
    to_hash       = to_hash,
    path_to_entry = path_to_entry,
    lua_idx       = 1,             -- pure-Lua walker pointer into to_hash
    cur           = nil,           -- in-flight per-file SHA state (lua mode)
    diff          = diff,
    manual        = manual,
    forced        = forced,
    -- Higher per-frame budget when the user is actively waiting (manual
    -- check or forced repair). Background piggyback checks
    -- (manual = forced = nil/false) keep the conservative default because
    -- they run while the user reads the chat response and any visible
    -- stutter is undesirable. Only consulted by tick_sha_diff -- the
    -- native path runs out-of-process and has no per-frame budget concern.
    budget        = (manual or forced) and CFG.UPDATE_SHA_TIME_BUDGET_MANUAL
                                       or  CFG.UPDATE_SHA_TIME_BUDGET,
    started_at    = time_precise(),
    mode          = "lua",         -- overridden to "native" if subprocess launches
  }

  -- All entries were missing / locked / unsafe: nothing to hash, finalize.
  if #to_hash == 0 then
    Updater._sha_diff_complete()
    return
  end

  -- Try native first. If launch fails (no PowerShell, AV block, file write
  -- error, missing POSIX tool), stay in "lua" mode and the main loop's
  -- verifying branch will pump tick_sha_diff() from lua_idx 1.
  if Updater.fire_native_sha(to_hash) then
    update._sha_diff.mode             = "native"
    update._sha_diff.native_send_time = time_precise()
  end

  update.state = "verifying"
end

-- Launch a native SHA-256 hasher subprocess for every path in to_hash.
-- Writes one "<hex>\t<input path>" line per file to tmp.update_sha_out
-- and the inner-process exit code to tmp.update_sha_exit. Returns true if
-- the launch was attempted, false on prerequisite failure (paths-file
-- write error, defensive quote rejection, PS-script write error).
--
-- Detached via the same Start-Process cmd pattern as fire_get on Windows
-- and a backgrounded subshell on POSIX, so the main thread only pays
-- launcher startup (~200 ms warm PowerShell) -- not the hash duration --
-- and tick_native_sha polls tmp.update_sha_exit each frame for completion.
--
-- The Windows path emits the verbatim INPUT path (not Get-FileHash's
-- $_.Path) so tick_native_sha's exact-match lookup in path_to_entry can't
-- be defeated by provider-side casing or normalization. Output is written
-- via .NET StreamWriter with UTF-8(no-BOM) for predictable encoding
-- across PowerShell 5 / 7 / redirection differences.
function Updater.fire_native_sha(to_hash)
  os.remove(tmp.update_sha_in)
  os.remove(tmp.update_sha_out)
  os.remove(tmp.update_sha_exit)
  os.remove(tmp.update_sha_ps)

  -- Write absolute paths, one per line, UTF-8.
  local pf, pf_err = io.open(tmp.update_sha_in, "wb")
  if not pf then
    Log.line("UPDATE", "fire_native_sha: paths-file open failed: "
                       .. tostring(pf_err))
    return false
  end
  for _, item in ipairs(to_hash) do
    pf:write(item.path)
    pf:write("\n")
  end
  pf:close()

  if RA.IS_WINDOWS then
    -- Defensive guard limited to characters that cannot legitimately
    -- appear in a valid Windows path: " < > | are all reserved by
    -- Windows filenames. Other cmd-significant chars (& ^ ( ) %) ARE
    -- valid in Windows paths ("Program Files (x86)", "R&D", etc.) and
    -- the triple-quoted argument passing protects them; rejecting
    -- them would silently break update / repair for valid users. See
    -- fire_get for the same guard on the manifest-fetch path.
    for _, c in ipairs({'"', '<', '>', '|'}) do
      if tmp.update_sha_in:find(c, 1, true)
          or tmp.update_sha_out:find(c, 1, true)
          or tmp.update_sha_exit:find(c, 1, true)
          or tmp.update_sha_ps:find(c, 1, true) then
        Log.line("UPDATE", string.format(
          "fire_native_sha: refusing to launch with cmd-unsafe "
          .. "character '%s' in tmp paths", c))
        return false
      end
    end

    -- The PS script: read paths, hash each via Get-FileHash, write
    -- "<hex>\t<input path>" to the output file. Per-file try/catch so a
    -- single bad file (locked / deleted between preflight and hash)
    -- doesn't lose the rest -- tick_native_sha's missing-from-output
    -- triage handles those cases.
    local ps_script = string.format(
[[$ErrorActionPreference = 'Continue'
try {
  $paths = Get-Content -LiteralPath '%s' -Encoding UTF8
  $utf8 = New-Object System.Text.UTF8Encoding($false)
  $writer = New-Object System.IO.StreamWriter('%s', $false, $utf8)
  try {
    foreach ($p in $paths) {
      try {
        $h = Get-FileHash -Algorithm SHA256 -LiteralPath $p -ErrorAction Stop
        $writer.WriteLine($h.Hash.ToLowerInvariant() + "`t" + $p)
      } catch {
      }
    }
  } finally {
    $writer.Close()
  }
  exit 0
} catch {
  exit 1
}
]],
      Shell.ps_escape(tmp.update_sha_in), Shell.ps_escape(tmp.update_sha_out))

    -- Write the .ps1 with a UTF-8 BOM so PowerShell 5 reads it as UTF-8
    -- unambiguously (PS5 default file encoding is the system codepage;
    -- PS7 defaults to UTF-8). Matters when paths contain non-ASCII (e.g.
    -- a user dir with Unicode characters).
    local sf, sf_err = io.open(tmp.update_sha_ps, "wb")
    if not sf then
      Log.line("UPDATE", "fire_native_sha: PS-script open failed: "
                         .. tostring(sf_err))
      return false
    end
    sf:write("\239\187\191")
    sf:write(ps_script)
    sf:close()

    -- Inner cmd: run the PS script via -File (no script-content quoting
    -- needed -- avoids the inner-PS / cmd / outer-PS triple escape) and
    -- capture the inner PS's exit code via cmd's %errorlevel%.
    local cmd_line = string.format(
      'powershell -NoProfile -ExecutionPolicy Bypass'
      .. ' -File """%s""" & echo %%errorlevel%% > """%s"""',
      tmp.update_sha_ps, tmp.update_sha_exit)

    -- Outer PS: detach via Start-Process so ExecProcess's positive
    -- timeout only waits for PS to spawn cmd (~200 ms warm), not for
    -- the actual hashing. Same pattern as fire_get.
    local ps_cmd = string.format(
      'powershell -NoProfile -WindowStyle Hidden'
      .. ' -Command "Start-Process cmd -ArgumentList \'/c %s\''
      .. ' -WindowStyle Hidden"',
      Shell.ps_escape(cmd_line))
    reaper.ExecProcess(ps_cmd, 5000)
  else
    -- POSIX: prefer sha256sum (GNU; standard on Linux), fall back to
    -- shasum -a 256 (Perl; standard on macOS). exit 127 if neither is
    -- installed -- tick_native_sha falls back to pure-Lua. tr '\n' '\0'
    -- piped to xargs -0 so paths with spaces survive the shell split.
    local cmd = string.format(
      "(if command -v sha256sum >/dev/null 2>&1; then "
      .. "tr '\\n' '\\0' < %s | xargs -0 sha256sum > %s; rc=$?; "
      .. "elif command -v shasum >/dev/null 2>&1; then "
      .. "tr '\\n' '\\0' < %s | xargs -0 shasum -a 256 > %s; rc=$?; "
      .. "else rc=127; fi; echo $rc > %s) &",
      Shell.sh_quote(tmp.update_sha_in), Shell.sh_quote(tmp.update_sha_out),
      Shell.sh_quote(tmp.update_sha_in), Shell.sh_quote(tmp.update_sha_out),
      Shell.sh_quote(tmp.update_sha_exit))
    os.execute(cmd)
  end

  return true
end

-- One tick of the native-hash poll path. Called by the main loop each
-- frame while update.state == "verifying" and s.mode == "native". Reads
-- tmp.update_sha_exit; on completion (exit 0) parses tmp.update_sha_out,
-- triages each preflighted file against the parsed output, and either
-- commits results to s.diff or falls back to lua. On non-zero exit /
-- watchdog timeout / read failure / suspicious output (preflighted file
-- readable but missing from native output), transitions to lua_fallback
-- and lets tick_sha_diff take over from a known-good code path.
function Updater.tick_native_sha()
  local s = update._sha_diff
  if not s then return end

  -- Watchdog: native hashing of ~3.6 MB completes in well under a second;
  -- 15 s + 5 s slack covers cold spawn, slow disks, AV scanning. Beyond
  -- that, fall back rather than wait further.
  if s.native_send_time
      and (time_precise() - s.native_send_time)
          > (CFG.UPDATE_NATIVE_SHA_TIMEOUT + 5) then
    Log.line("UPDATE", "tick_native_sha: watchdog timeout, "
                       .. "falling back to pure-Lua verify")
    Updater._native_to_lua_fallback()
    return
  end

  -- Read exit file. While the inner process is still running, the file
  -- doesn't exist (cmd's `& echo %errorlevel% > exit` only runs after
  -- powershell returns). The race window where it exists but isn't
  -- fully written is small; tonumber(nil) -> nil makes us wait one more
  -- frame on partial reads.
  local ef = io.open(tmp.update_sha_exit, "r")
  if not ef then return end
  local exit_str = ef:read("*a"); ef:close()
  local exit_code = tonumber(exit_str:match("(%d+)"))
  if not exit_code then return end

  if exit_code ~= 0 then
    Log.line("UPDATE", string.format(
      "tick_native_sha: native hasher exited %d, "
      .. "falling back to pure-Lua verify", exit_code))
    Updater._native_to_lua_fallback()
    return
  end

  local of, of_err = io.open(tmp.update_sha_out, "rb")
  if not of then
    Log.line("UPDATE", "tick_native_sha: output read failed: "
                       .. tostring(of_err) .. ", falling back")
    Updater._native_to_lua_fallback()
    return
  end
  local raw = of:read("*a"); of:close()
  -- Defensive UTF-8 BOM strip. The PS script writes via UTF-8(no-BOM)
  -- StreamWriter so this should never trigger, but POSIX redirection
  -- behaves differently across platforms and stripping is harmless.
  if raw:sub(1, 3) == "\239\187\191" then raw = raw:sub(4) end

  -- Parse: "<64 hex>(whitespace)<path>". Both PS-pinned tab-separated
  -- output and POSIX two-space-separated output match this pattern.
  local hash_by_path = {}
  for line in raw:gmatch("[^\r\n]+") do
    local hex, rest = line:match("^([0-9a-fA-F]+)[ \t]+(.+)$")
    if hex and #hex == 64 and rest then
      hash_by_path[rest] = hex:lower()
    end
  end

  -- Triage each preflighted file. Hold mismatched / additional_missing
  -- in local tables so a fallback decision can discard them cleanly --
  -- the lua fallback redoes the comparison from scratch and we don't
  -- want partial native results leaking into its diff.
  local mismatched = {}
  local additional_missing = {}
  local suspicious = false
  for _, item in ipairs(s.to_hash) do
    local local_hash = hash_by_path[item.path]
    if local_hash then
      if local_hash ~= item.entry.sha256:lower() then
        mismatched[#mismatched+1] = item.entry.name
      end
    else
      -- Native produced no hash for this preflight-readable file. Triage:
      --   * file gone now: native saw a delete race -> record as missing
      --   * file present but locked now: AV / lock race -> log + skip
      --   * file present and readable now: native should have hashed it
      --     but didn't -- output is suspicious, fall back to lua so the
      --     whole result set gets recomputed from a known-good path.
      local exists = (reaper.file_exists and reaper.file_exists(item.path))
      if not exists then
        additional_missing[#additional_missing+1] = item.entry.name
      else
        local f = io.open(item.path, "rb")
        if not f then
          Log.line("UPDATE", string.format(
            "tick_native_sha: %s preflight readable but locked now "
            .. "(skipping from diff)", item.path))
        else
          f:close()
          Log.line("UPDATE", string.format(
            "tick_native_sha: %s readable but missing from native output "
            .. "(suspicious, falling back to pure-Lua verify)",
            item.path))
          suspicious = true
          break
        end
      end
    end
  end

  if suspicious then
    Updater._native_to_lua_fallback()
    return
  end

  -- Commit results to s.diff and finalize.
  for _, name in ipairs(mismatched) do
    s.diff.mismatched[#s.diff.mismatched+1] = name
  end
  for _, name in ipairs(additional_missing) do
    s.diff.missing[#s.diff.missing+1] = name
  end
  Updater._sha_diff_complete()
end

-- Switch from native mode to pure-Lua fallback. Reset the lua walker
-- pointer so tick_sha_diff re-walks s.to_hash from the start. Intentionally
-- does NOT clear s.diff -- preflight-derived missing entries remain valid
-- (they're filesystem facts, not native-tool output) and s.diff.mismatched
-- is empty at this point because tick_native_sha only mutates it after a
-- successful triage commit.
function Updater._native_to_lua_fallback()
  local s = update._sha_diff
  if not s then return end
  s.mode    = "lua_fallback"
  s.lua_idx = 1
  s.cur     = nil
end

-- One tick of incremental pure-Lua SHA verification. Called by the main
-- loop each frame while update.state == "verifying" and s.mode == "lua"
-- or "lua_fallback". Walks s.to_hash[] (preflighted readable files) so
-- classification work is not duplicated -- start_sha_diff already filed
-- missing / unsafe / locked entries.
--
-- State machine:
--   * No current file (s.cur == nil): pop the next entry from to_hash.
--     Race-handle the rare case where preflight saw the file readable
--     but it's locked now (log + skip, mirroring start_sha_diff's
--     locked-skip behavior) and the rare nil-read race (treat as locked).
--   * Current file in flight: compress one tick's worth of blocks. When
--     the state is exhausted, finalize, compare to manifest hash, append
--     to s.diff.mismatched on miss, advance lua_idx.
-- When lua_idx walks past #to_hash with no s.cur set, hand off to _complete.
function Updater.tick_sha_diff()
  local s = update._sha_diff
  if not s then return end
  local to_hash = s.to_hash

  if not s.cur then
    while s.lua_idx <= #to_hash do
      local item = to_hash[s.lua_idx]
      local f, open_err = io.open(item.path, "rb")
      if not f then
        Log.line("UPDATE", string.format(
          "tick_sha_diff: %s preflight readable but open failed: %s "
          .. "(likely AV / editor lock; skipping from diff)",
          item.path, tostring(open_err)))
        s.lua_idx = s.lua_idx + 1
      else
        local content = f:read("*a")
        f:close()
        if content then
          s.cur = { entry = item.entry, state = _SHA.create(content) }
          break
        else
          Log.line("UPDATE", string.format(
            "tick_sha_diff: %s opened but read returned nil "
            .. "(treating as locked; skipping from diff)", item.path))
          s.lua_idx = s.lua_idx + 1
        end
      end
    end
    if not s.cur then
      Updater._sha_diff_complete()
      return
    end
  end

  -- File in flight: compress as many 16-block chunks as fit inside the
  -- per-tick time budget. The chunk size is small enough that the budget
  -- check stays meaningful on slow hardware (one chunk ~= 1 ms on a
  -- commodity CPU; would-be 5+ ms on a very old CPU still stops after a
  -- single chunk, which is still better than the previous 192-block
  -- fixed budget would have been on the same hardware).
  local tick_start = time_precise()
  local budget = s.budget or CFG.UPDATE_SHA_TIME_BUDGET
  local done
  repeat
    done = _SHA.step(s.cur.state, 16)
    if done then break end
  until (time_precise() - tick_start) >= budget
  if done then
    local local_hash = _SHA.finalize(s.cur.state)
    if local_hash ~= s.cur.entry.sha256:lower() then
      s.diff.mismatched[#s.diff.mismatched+1] = s.cur.entry.name
    end
    s.cur     = nil
    s.lua_idx = s.lua_idx + 1
  end
end

-- Apply the result of a completed incremental SHA diff. Same branch logic as
-- the inline block that lived in check_poll before the refactor: a non-empty
-- diff transitions to "repair_available" with the popup, an empty diff
-- transitions to "idle" with the manual-check toast (or silence for the
-- piggyback). Clears update._sha_diff so a stale snapshot can never leak
-- into a later check.
function Updater._sha_diff_complete()
  local s = update._sha_diff
  if not s then return end
  local diff     = s.diff
  local manifest = s.manifest
  local manual   = s.manual
  local elapsed  = time_precise() - (s.started_at or time_precise())
  update._sha_diff = nil

  local repair_count = #diff.missing + #diff.mismatched
  if repair_count > 0 then
    update.state          = "repair_available"
    update.remote_version = manifest.version  -- same as CFG.VERSION; kept
                                              -- for consistent popup format
    update.manifest       = manifest
    update.repair_missing    = diff.missing
    update.repair_mismatched = diff.mismatched
    Log.line("UPDATE", string.format(
      "sha_diff complete in %.2fs: version matches (%s) but %d files "
      .. "need repair (%d missing, %d mismatched).",
      elapsed, manifest.version, repair_count,
      #diff.missing, #diff.mismatched))
    -- Match the "available" branch: clear the sticky "Checking..."
    -- toast so the repair popup is the sole visual feedback.
    if manual then S.float_toast = nil end
  else
    update.state = "idle"  -- already up to date and all files intact
    Log.line("UPDATE", string.format(
      "sha_diff complete in %.2fs: version matches (%s) and all files "
      .. "intact.", elapsed, manifest.version))
    -- Stamp the last-successful-check time so the footer's version-
    -- number tooltip can show "Up to date (checked X ago)" instead
    -- of the generic "Click to check for updates" copy. Applies to
    -- both manual checks (Settings button / footer link) and the
    -- auto-fired piggyback check after the first chat response.
    update._last_ok_at = os.time()
    -- Manual check (Settings button / version-number link) with no
    -- action needed -> give the user explicit feedback that their
    -- click did something. Auto-fired checks stay silent.
    if manual then
      UI.show_float_toast(
        "ReaAssist is up to date (v" .. CFG.VERSION .. ")", "ok")
    end
  end
end

function Updater.check_poll()
  local result = Updater.poll()
  if result == "waiting" then return end
  -- Snapshot-and-clear both one-shot flags before any return path so a
  -- single force_reinstall / manual_check call cannot leak into a
  -- later organic check. Without this, update.force stayed true after
  -- consumption, and subsequent startup checks were misclassified as
  -- "available" even when the user was already on the current version,
  -- feeding the wrong action_was_repair bool into download_start's
  -- completion copy. _manual follows the same snapshot pattern so the
  -- "You're up to date" toast only fires for the check the user just
  -- clicked, not any later one.
  local forced = update.force
  update.force = false
  local manual = update._manual
  update._manual = false
  if result == "error" then
    -- Network / curl failure. Only surface as a failure when the user
    -- explicitly forced this check (Repair button): organic startup
    -- checks fail silently so offline launches do not nag the user.
    if forced then
      Updater._set_failure("manifest_fetch",
        "Could not reach update server (network error or timeout).\n\n"
        .. "Please enable your network connection if it is disabled.")
    end
    -- Manual Settings button: replace the sticky "Checking..." toast
    -- with a transient error message so the user sees explicit failure
    -- feedback on their explicit action.
    if manual then
      UI.show_float_toast(
        "Could not reach update server\nCheck your network connection",
        "err")
    end
    update.state = "idle"
    return
  end
  -- Parse manifest.
  local manifest = Updater.read_response()
  if not manifest
    or type(manifest.version) ~= "string"
    or type(manifest.files) ~= "table" then
    -- Distinguish empty / near-empty response (connection dropped
    -- silently, typical of offline on Windows where DNS cache may let
    -- curl exit with status 0 even though no bytes were received) from
    -- a body that actually contained something but wasn't valid JSON.
    -- Empty body is surfaced as a connection error so the user's toast
    -- / Bootstrap error message points at the likely cause instead of
    -- blaming the server for "malformed" output.
    local body_size = 0
    local bf = io.open(tmp.update_out, "rb")
    if bf then
      bf:seek("end")
      body_size = bf:seek("cur")
      bf:close()
    end
    local empty = (body_size < 2)
    if forced then
      if empty then
        Updater._set_failure("manifest_fetch",
          "Could not reach update server (no response received).\n\n"
          .. "Please enable your network connection if it is disabled.")
      else
        Updater._set_failure("manifest_parse",
          "Update server returned a malformed manifest "
          .. "(missing version or files field).")
      end
    end
    if manual then
      if empty then
        UI.show_float_toast(
          "Could not reach update server\nCheck your network connection",
          "err")
      else
        UI.show_float_toast(
          "Update server returned a malformed response", "err")
      end
    end
    update.state = "idle"
    return
  end
  -- Three-way version compare so we never repair against an older manifest
  -- (which would effectively downgrade the install). Equality via the
  -- "neither newer" rule because is_newer parses numerically (so "1.0.0"
  -- and "1.0.0.0" compare equal even though string == would say false).
  local remote_newer = Updater.is_newer(manifest.version, CFG.VERSION)
  local remote_older = Updater.is_newer(CFG.VERSION, manifest.version)
  if remote_newer then
    -- A newer version is on the server. The update flow handles this case --
    -- the user sees "Update Available" and the download queue is built by
    -- comparing local SHA vs manifest SHA (Stage 3.1), so only files that
    -- actually changed between versions get downloaded.
    update.state = "available"
    update.remote_version = manifest.version
    update.manifest = manifest
    -- Manual check -> the popup carries the visual feedback from here.
    -- Clear the sticky "Checking..." toast so it doesn't overlap the
    -- dialog near the bottom of the window.
    if manual then S.float_toast = nil end
    -- Honor the "Later" snooze for auto-fire piggyback checks only.
    -- When active (user clicked Later within the last 7 days), we
    -- keep state = "available" so manual paths can still surface the
    -- update, but we pre-open popup_opened so the automatic popup
    -- trigger in Render.main_window treats it as "already shown" and
    -- leaves the user alone. Forced / manual paths bypass this so
    -- explicit user action always sees the popup.
    if not forced and not manual then
      local snooze = tonumber(
        reaper.GetExtState(CFG.EXT_NS, "update_snooze") or "")
      if snooze and os.time() < snooze then
        update.popup_opened = true
      end
    end
  elseif not remote_older then
    -- Versions match. But the local install may still have missing or
    -- corrupted files (user deleted something, disk error, partial copy).
    -- Normally we run the per-file SHA diff to find them, deferred across
    -- frames so REAPER stays responsive (synchronous diff would freeze
    -- the UI for ~100-500 ms hashing ~5-6 MB of fonts and large .lua
    -- files). See Updater.start_sha_diff / tick_sha_diff for the
    -- incremental machine.
    --
    -- Bootstrap fast-path: when this check fired from the Bootstrap
    -- repair button (`update._bootstrap_repair == true`), we already
    -- know which files are missing/broken from the critical-files probe
    -- at startup -- skip the SHA verify entirely and route directly to
    -- repair_available with the known list. The trade-off: SHA-level
    -- corruption in non-critical files won't be caught by THIS repair,
    -- but the next non-bootstrap launch's normal SHA verify will.
    if update._bootstrap_repair then
      update._bootstrap_repair = nil
      update.manifest          = manifest
      update.remote_version    = manifest.version
      -- S.bootstrap_missing entries can carry a " (load error)" suffix
      -- (added by the font-load probe) that is presentation-only and
      -- not part of the manifest filename; strip before queueing.
      local missing = {}
      for _, name in ipairs(S.bootstrap_missing or {}) do
        local clean = name:gsub("%s*%(load error%)$", "")
        missing[#missing + 1] = clean
      end
      update.repair_missing    = missing
      update.repair_mismatched = {}
      update.state             = "repair_available"
      Log.line("UPDATE", string.format(
        "check_poll: bootstrap fast-path armed; queueing %d known-broken "
        .. "file(s) without SHA verify.", #missing))
      if manual then S.float_toast = nil end
    else
      Updater.start_sha_diff(manifest, manual, forced)
    end
  elseif forced then
    -- Remote manifest is older than installed AND user explicitly asked to
    -- reinstall. Repairing against an older manifest would effectively
    -- downgrade the install; refuse with a specific failure so the
    -- "Update Failed" dialog can surface the cause.
    Updater._set_failure("manifest_version", string.format(
      "Update server returned manifest v%s, older than installed v%s. "
      .. "Refusing to repair against an older manifest.",
      tostring(manifest.version), tostring(CFG.VERSION)))
    update.state = "failed"
  else
    -- Remote manifest is older than installed and the user didn't force a
    -- reinstall. Most likely a CDN propagation race or a stale branch.
    -- Skip silently for auto-fire piggyback checks; surface a brief toast
    -- for explicit manual checks so the user knows the click was processed.
    update.state = "idle"
    Log.line("UPDATE", string.format(
      "Remote manifest is older (v%s) than installed (v%s); "
      .. "skipping repair check.",
      tostring(manifest.version), tostring(CFG.VERSION)))
    if manual then
      UI.show_float_toast(
        "Update server returned an older manifest; try again later.",
        "err", true)
    end
  end
end

-- Validate a manifest filename: no path traversal, no absolute paths, safe extension.
-- Forward-slash subpaths are allowed (e.g. "Resources/Help.md",
-- "Resources/ReEQ/Dependencies/svf_filter.jsfx-inc") so the manifest can mirror
-- the on-disk layout. Backslashes, leading slashes, drive letters, and any
-- ".." or hidden ("."-prefixed) path segments are rejected.
function Updater.is_safe_filename(name)
  if type(name) ~= "string" or name == "" then return false end
  -- Strict allowlist: only ASCII alphanumerics, underscore, hyphen, dot,
  -- and forward slash. Blocks shell-sensitive characters (spaces, $, `,
  -- &, ?, #, ;, parens, quotes, etc.) before they ever reach a curl
  -- command line or a local path. The remaining checks below run after
  -- the allowlist as defense-in-depth.
  if not name:match("^[A-Za-z0-9_./%-]+$") then return false end
  -- Reject backslashes, leading /, drive letters (absolute paths).
  if name:match("^/") or name:match("^%a:") then return false end
  if name:find("\\", 1, true) then return false end
  -- Validate each forward-slash-separated path segment.
  for segment in (name .. "/"):gmatch("([^/]*)/") do
    if segment == "" or segment == "." or segment == ".." then return false end
    if segment:sub(1, 1) == "." then return false end  -- hidden dotfiles/dirs
  end
  -- The final segment is the filename itself.
  local base_name = name:match("([^/]+)$") or name
  -- Reject Windows reserved device names (CON, PRN, AUX, NUL, COM1-9, LPT1-9).
  local base = base_name:match("^([^%.]+)") or ""
  local reserved = {
    CON=true, PRN=true, AUX=true, NUL=true,
    COM1=true, COM2=true, COM3=true, COM4=true, COM5=true,
    COM6=true, COM7=true, COM8=true, COM9=true,
    LPT1=true, LPT2=true, LPT3=true, LPT4=true, LPT5=true,
    LPT6=true, LPT7=true, LPT8=true, LPT9=true,
  }
  if reserved[base:upper()] then return false end
  -- Allow only known safe extensions.
  local ext = base_name:match("%.([^%.]+)$")
  if not ext then return false end
  local safe = {
    lua=true, md=true, txt=true, jsfx=true, ["jsfx-inc"]=true,
    json=true, png=true, csv=true, pdf=true,
    -- .ttf added in Stage 3.4: Resources/fonts/*.ttf are part of the
    -- distributable install (the bootstrap critical-files check verifies
    -- them at launch), so the download pipeline has to accept them.
    ttf=true,
  }
  if not safe[ext:lower()] then return false end
  return true
end

-- Read a local file and return its SHA-256 hex digest (lowercase). Used
-- by Updater.download_start() to skip files whose local content already
-- matches the manifest SHA, and the open path is mirrored inline by
-- Updater.tick_sha_diff() (incremental verify) to classify files as
-- missing, mismatched, or intact.
--
-- Returns (hex, nil) on success, or (nil, kind) on failure where kind is:
--   "missing" - genuinely not on disk
--   "locked"  - exists on disk but couldn't be opened (AV scanner mid-
--               scan, editor open handle, permission flicker). The caller
--               should treat this as "intact" rather than triggering a
--               repair: rolling a download in over a perfectly good file
--               just because the AV scanner caught it for 50ms produces
--               a confusing "repair available" prompt out of nowhere.
function Updater.file_sha256_hex(path)
  local f, open_err = io.open(path, "rb")
  if not f then
    -- reaper.file_exists handles Windows path separators and long-path
    -- weirdness better than a pcall around a second open. Its result
    -- tells us whether this is a true "missing" or a transient lock.
    if reaper.file_exists and reaper.file_exists(path) then
      Log.line("UPDATE", string.format(
        "file_sha256_hex: %s exists but open failed: %s "
        .. "(likely AV / editor lock; treating as intact for this run)",
        path, tostring(open_err)))
      return nil, "locked"
    end
    return nil, "missing"
  end
  local content = f:read("*a")
  f:close()
  if not content then return nil, "locked" end
  return sha256_hash(content)
end

-- Resolve a manifest filename ("Resources/X.md") to an absolute local path
-- using the host OS separator. Centralized so download_start (the local-SHA
-- check) and download_poll (the write target) agree on the layout.
function Updater.local_path_for(filename)
  local rel = filename
  if RA.SEP ~= "/" then rel = rel:gsub("/", RA.SEP) end
  return RA.script_path .. rel
end

-- Paths the orphan-cleanup pass must never delete, even if a manifest
-- listed them in removed_files. System_Prompt_Custom.md is the documented
-- power-user override -- the loader prefers it over the stock prompt and
-- it's intentionally untracked so updates don't touch it. Debug.log and
-- FX_Cache.json are runtime artifacts the script itself authors. None of
-- these are ever in our manifest's files list, so they could only end up
-- on a removed_files list via a malformed or malicious manifest; this set
-- is the runtime backstop for that case.
local PROTECTED_FROM_REMOVAL = {
  ["Resources/System_Prompt_Custom.md"] = true,
  ["Resources/Debug.log"]                = true,
  ["Resources/FX_Cache.json"]            = true,
}

-- Predicate gating per-path orphan deletes. All four checks must hold:
--   1. is_safe_filename: path-traversal, absolute paths, backslashes,
--      hidden segments, and non-allowlisted extensions all rejected here.
--   2. Inside ReaAssist's install zone: ReaAssist.lua, the three top-level
--      docs, or anything under Resources/. Anything else is out of scope
--      for the package and never something we shipped.
--   3. Not in PROTECTED_FROM_REMOVAL: user-override + runtime artifacts.
--   4. Not also in the current manifest's files list: defensive double-
--      lock against an inconsistent manifest where a path appears in both
--      `files` and `removed_files`. gen_manifest.py guards against this
--      at authoring time; this is belt-and-suspenders.
function Updater.should_remove_orphan(name, current_files)
  if type(name) ~= "string" then return false end
  if not Updater.is_safe_filename(name) then return false end
  if current_files and current_files[name] then return false end
  local owned =
       name == "ReaAssist.lua"
    or name == "CHANGELOG.md"
    or name == "LICENSE.txt"
    or name == "README.md"
    or name:sub(1, 10) == "Resources/"
  if not owned then return false end
  if PROTECTED_FROM_REMOVAL[name] then return false end
  return true
end

function Updater.download_start()
  -- Accept both triggers: "available" (new version on server) and
  -- "repair_available" (version matches but some files are missing or
  -- corrupted locally). The download pipeline and SHA-diff logic are
  -- identical for both; only the popup messaging differs.
  if (update.state ~= "available" and update.state ~= "repair_available")
      or not update.manifest then return end
  -- Remember which trigger started the session so the "done" view can
  -- say "Updated to vX" vs "Restored N files" accurately.
  update.action_was_repair = (update.state == "repair_available")
  update.download_queue = {}
  update.applied_files = {}  -- track successfully written files for rollback
  update.skipped_count  = 0  -- files whose local SHA already matches manifest
  -- When entering from repair_available, the SHA diff just finished and we
  -- already know which files are missing or mismatched. Reuse those lists
  -- instead of re-hashing the entire manifest synchronously, which freezes
  -- the UI for the full hash time on slower machines (~1 MB/s pure-Lua SHA
  -- means 5-6 MB of fonts plus two ~700 KB Lua files takes 5-7 seconds on
  -- a commodity CPU and longer on older hardware). Trade-off: a corruption
  -- introduced in the few seconds between the diff completing and the user
  -- clicking Repair Now wouldn't be caught here, but the next launch's SHA
  -- check would catch it.
  local repair_fileset = nil
  if update.action_was_repair
      and update.repair_missing
      and update.repair_mismatched then
    repair_fileset = {}
    for _, n in ipairs(update.repair_missing)    do repair_fileset[n] = true end
    for _, n in ipairs(update.repair_mismatched) do repair_fileset[n] = true end
  end
  for _, entry in ipairs(update.manifest.files) do
    local filename, expected_hash
    if type(entry) == "table" and entry.name and entry.sha256 then
      filename      = entry.name
      expected_hash = entry.sha256
    else
      -- Reject manifests without per-file SHA-256 hashes. All production
      -- manifests must use the {name, sha256} format for integrity
      -- verification. Route through _set_failure so the Update Failed
      -- dialog has a real reason to display instead of the generic
      -- "(unknown)" the empty fields would produce.
      Updater._set_failure("manifest_file",
        "Manifest entry missing required SHA-256 hash")
      update.state = "failed"
      return
    end
    if not Updater.is_safe_filename(filename) then
      Updater._set_failure("manifest_file",
        "Unsafe filename in manifest: " .. tostring(filename))
      update.state = "failed"
      return
    end
    if repair_fileset then
      -- Repair path: queue only files the SHA diff flagged. Everything else
      -- already matched per the diff and is safe to skip without re-hashing.
      if repair_fileset[filename] then
        update.download_queue[#update.download_queue+1] = {
          filename = filename,
          url      = CFG.UPDATE_BASE_URL .. "/" .. filename,
          sha256   = expected_hash,
        }
      else
        update.skipped_count = update.skipped_count + 1
      end
    else
      -- Version-bump path: hash each file synchronously to skip those whose
      -- local content already matches the manifest. This is unavoidable
      -- here -- we have no precomputed diff to lean on -- but it makes the
      -- download itself incremental (a point release that changes one
      -- markdown file only downloads that file, not the full manifest).
      local local_path = Updater.local_path_for(filename)
      local local_hash = Updater.file_sha256_hex(local_path)
      if local_hash and local_hash == expected_hash:lower() then
        update.skipped_count = update.skipped_count + 1
      else
        update.download_queue[#update.download_queue+1] = {
          filename = filename,
          url      = CFG.UPDATE_BASE_URL .. "/" .. filename,
          sha256   = expected_hash,
        }
      end
    end
  end
  -- If every file already matches (user manually swapped files, or re-invoked
  -- an update that already ran), close the popup and stay idle -- the
  -- manifest version stamp is handled by the next startup check. Surface a
  -- short toast so the click on "Update Now" doesn't silently appear to do
  -- nothing; without it the popup just disappears and the user has no
  -- confirmation that the action completed.
  if #update.download_queue == 0 then
    Log.line("UPDATE", string.format(
      "download_start: all %d manifest files already match local SHA; "
      .. "nothing to download.", update.skipped_count))
    update.show_dialog = false
    update.state       = "idle"
    UI.show_float_toast("Already up to date", "ok")
    return
  end
  Log.line("UPDATE", string.format(
    "download_start: %d files to download, %d already up to date.",
    #update.download_queue, update.skipped_count))
  update.download_idx = 1
  update.state = "downloading"
  local entry = update.download_queue[1]
  if not Updater.fire_get(entry.url, tmp.update_out, tmp.update_exit) then
    Updater._set_failure("download_start", string.format(
      "Could not start download for %s.", tostring(entry.filename)))
    update.state = "failed"
    return
  end
end

-- Rollback all successfully written files. For files that existed before
-- the update (bak_existed=true), restore the .bak. For fresh-install adds
-- (bak_existed=false), just delete the dest -- there is no prior version
-- to restore, and renaming a nonexistent .bak over dest silently deletes
-- it, leaving the user with neither a working file nor a recoverable
-- backup if the next update file fails.
function Updater.rollback()
  if not update.applied_files then return end
  -- Track restore failures so we can surface them via update.last_error.
  -- Rollback runs because some EARLIER step already failed, so last_step
  -- and last_error are typically already set at this point. We only
  -- overwrite them if a restore failure produces a worse situation than
  -- the original failure (i.e. a file the user had before the update is
  -- now gone with no .bak to recover from), which is the one rollback
  -- failure mode that genuinely requires manual attention.
  local restore_failures = {}
  for i = #update.applied_files, 1, -1 do
    local applied = update.applied_files[i]
    local dest = applied.path
    os.remove(dest)
    if applied.bak_existed then
      local bak_path = dest .. ".bak"
      local ok, err = os.rename(bak_path, dest)
      if not ok then
        Log.line("UPDATE", string.format(
          "rollback restore failed for %s: %s "
          .. "(.bak still on disk; manual recovery may be needed)",
          dest, tostring(err)))
        restore_failures[#restore_failures + 1] = dest
      end
    end
  end
  update.applied_files = {}
  if #restore_failures > 0 then
    -- Append a manual-attention note to the existing failure message so
    -- the Update Failed dialog surfaces both the original cause and the
    -- restore problem. Don't replace last_error/last_step -- the original
    -- failure step is the right pointer for the user; the restore note
    -- just adds urgency.
    local note = string.format(
      "\n\nNote: rollback could not restore %d previous file%s "
      .. "(.bak file%s left on disk for manual recovery): %s",
      #restore_failures,
      #restore_failures == 1 and "" or "s",
      #restore_failures == 1 and "" or "s",
      table.concat(restore_failures, ", "))
    update.last_error = (update.last_error or "(no prior error)") .. note
  end
end

-- Poll the current file download. Advances to next file or applies update.
function Updater.download_poll()
  local entry = update.download_queue[update.download_idx]
  local fname = entry and entry.filename or "?"
  local result = Updater.poll()
  if result == "waiting" then return end
  if result == "error" then
    Updater._set_failure("download",
      string.format("curl failed or timed out while fetching %s", fname))
    Updater.rollback()
    update.state = "failed"
    return
  end
  -- Read the downloaded file and save it.
  local f, f_err = io.open(tmp.update_out, "rb")
  if not f then
    Updater._set_failure("download_read",
      string.format("Could not open downloaded %s: %s",
                    fname, tostring(f_err)))
    Updater.rollback()
    update.state = "failed"
    return
  end
  local content = f:read("*a"); f:close()
  if not content or #content == 0 then
    Updater._set_failure("download_read",
      string.format("Downloaded %s is empty.", fname))
    Updater.rollback()
    update.state = "failed"
    return
  end
  -- Integrity checks.
  -- SHA-256 hash verification: if the manifest provided a hash, verify it.
  -- This is the primary integrity gate. A mismatch means the download was
  -- corrupted or tampered with; reject the entire update.
  if entry.sha256 then
    local actual_hash = sha256_hash(content)
    if actual_hash ~= entry.sha256:lower() then
      Updater._set_failure("sha_verify", string.format(
        "SHA-256 mismatch for %s: expected %s, got %s",
        fname, entry.sha256:lower(), actual_hash))
      Updater.rollback()
      update.state = "failed"
      return
    end
  end
  -- Secondary sanity check: every shipped .lua file contains a
  -- CFG.VERSION literal (the marker comment in Resources/Relaunch.lua
  -- and Resources/Diag.lua is required for exactly this reason). A
  -- download that passes SHA but doesn't contain the marker has either
  -- been intercepted (proxy injecting an HTML error page) or is some
  -- other file entirely. Distinct step name from sha_verify so the
  -- Update-Failed dialog can show a content-specific message instead
  -- of the CDN-propagation copy that fits sha_verify cases.
  if entry.filename:match("%.lua$") then
    if not content:find("CFG.VERSION", 1, true) then
      Updater._set_failure("content_verify", string.format(
        "Downloaded %s is missing the CFG.VERSION marker "
        .. "(rejected as likely-corrupt or non-ReaAssist content).",
        fname))
      Updater.rollback()
      update.state = "failed"
      return
    end
  end
  -- Write to a .tmp file first, then rename. Manifest entries may include
  -- forward-slash subpaths (e.g. "Resources/Help.md"); the path
  -- helper normalizes them to the platform separator. Ensure the parent
  -- directory exists so fresh installs can create the Resources/ tree on
  -- first update.
  local dest = Updater.local_path_for(entry.filename)
  local parent = dest:match("^(.*)[\\/][^\\/]+$")
  if parent and parent ~= "" then
    reaper.RecursiveCreateDirectory(parent, 0)
  end
  local tmp_path = dest .. ".tmp"
  local bak_path = dest .. ".bak"
  -- Write temp file. pcall-wrap the write/close so short writes, disk-
  -- full, and permission errors propagate as failure instead of silently
  -- shipping a truncated file.
  local wf, open_err = io.open(tmp_path, "wb")
  if not wf then
    Updater._set_failure("write_open", string.format(
      "Could not open temp file %s for write: %s",
      tmp_path, tostring(open_err)))
    Updater.rollback()
    update.state = "failed"
    return
  end
  local w_ok, w_err = pcall(function()
    local ok, perr = wf:write(content)
    if not ok then error(perr or "write returned nil", 0) end
  end)
  local c_ok, c_err = pcall(function()
    local ok, perr = wf:close()
    if not ok then error(perr or "close returned nil", 0) end
  end)
  if not w_ok or not c_ok then
    Updater._set_failure("write", string.format(
      "Write to %s failed: %s",
      tmp_path, tostring(w_err or c_err)))
    os.remove(tmp_path)
    Updater.rollback()
    update.state = "failed"
    return
  end
  -- Back up current file. We must distinguish "dest does not exist
  -- (fresh-install add)" from "dest exists but rename failed (lock,
  -- permissions, AV scan, cloud sync, editor handle)". `os.rename`
  -- returns nil for both, so probing existence first is the only way
  -- to disambiguate. Misclassifying an existing-but-locked file as
  -- fresh-install is dangerous: rollback's fresh-install branch deletes
  -- dest, which would destroy the only intact copy when no .bak was
  -- ever created. rename_bak_existed carries the truth into
  -- rename_retry_poll and rollback.
  os.remove(bak_path)
  local dest_existed = reaper.file_exists and reaper.file_exists(dest)
  if dest_existed then
    local ok_bak, bak_err = os.rename(dest, bak_path)
    if not ok_bak then
      os.remove(tmp_path)
      Updater._set_failure("backup", string.format(
        "Could not back up existing file %s: %s",
        dest, tostring(bak_err)))
      Updater.rollback()
      update.state = "failed"
      return
    end
    update.rename_bak_existed = true
  else
    update.rename_bak_existed = false
  end
  -- Move temp to final. On Windows, Defender / AV may hold a short-lived lock
  -- on the .tmp file immediately after close, causing rename to fail during
  -- the scan window (~20-50ms). Instead of busy-waiting, we attempt the rename
  -- once and defer to "rename_retry" state if it fails. The main loop will
  -- call Updater.rename_retry_poll() on subsequent frames (~30ms apart), which
  -- is a natural non-blocking delay that avoids stalling the UI thread.
  local ok_mv = os.rename(tmp_path, dest)
  if not ok_mv then
    -- Stash rename context and defer. The next frame will retry.
    update.rename_failures = 1
    update.rename_tmp      = tmp_path
    update.rename_dest     = dest
    update.rename_bak      = bak_path
    update.state           = "rename_retry"
    return
  end
  Updater.advance_after_rename(dest)
end

-- Fire auto-restart if the download pipeline is in "done" state, the
-- restart delay has elapsed, and we have not already fired. Called from
-- both the main loop and Bootstrap.loop so either flow auto-restarts
-- after a successful apply. Single-fire via update.restart_fired so we
-- only invoke Main_OnCommand once.
--
-- Fires the external relauncher action (registered at startup) and
-- closes ourselves. Firing Main_OnCommand on ReaAssist's own CMD_ID
-- from inside our still-running defer chain triggers REAPER's
-- re-entrance handling -- the action "is already running" -- and the
-- single-instance handshake interprets that as a toggle-off, exiting
-- the new instance immediately. The relauncher is a separate script
-- with its own action id, so invoking it from here does NOT hit that
-- re-entrance path. It waits for our "running" ExtState to clear,
-- re-registers ReaAssist via AddRemoveReaScript, and fires a fresh
-- Main_OnCommand on ReaAssist from its own context.
--
-- advance_after_rename only sets update.restart_after when the
-- relauncher file is present on disk, so by the time we reach this
-- function the on-demand AddRemoveReaScript call should succeed.
function Updater.try_auto_restart()
  if update.state ~= "done" then return end
  if not update.restart_after or update.restart_fired then return end
  if time_precise() < update.restart_after then return end
  update.restart_fired = true
  return Updater.fire_relauncher_now()
end

-- Shared helper: fires the relauncher script in its own Lua state, then
-- closes the current ReaAssist instance. Used by:
--   * try_auto_restart (post-update success)
--   * Render._factory_reset_execute (UI file -- relauncher path is
--     local to this file, so the UI can't fire it directly)
-- Returns true on success, false if the relauncher couldn't be
-- registered (caller can fall back to a "close and reopen" prompt).
function Updater.fire_relauncher_now()
  -- Lazy-register the relauncher action right before firing it. Keeps
  -- the Actions list uncluttered for sessions where no auto-restart
  -- ever happens. AddRemoveReaScript is synchronous and the returned
  -- cmd_id is immediately usable from Main_OnCommand. commit=false so
  -- the registration is session-only (vanishes when REAPER closes).
  local cmd_id = reaper.AddRemoveReaScript(true, 0, RELAUNCHER_PATH, false)
  if cmd_id and cmd_id ~= 0 then
    reaper.Main_OnCommand(cmd_id, 0)
    S.script_open = false
    return true
  end
  return false
end

-- Advance to the next file (or finish) after a successful rename.
function Updater.advance_after_rename(dest)
  -- Capture whether dest had a .bak before this apply. rollback uses the
  -- flag to skip restore for fresh-install adds (no prior .bak to restore;
  -- rolling back means simply deleting the newly-written dest, not renaming
  -- a nonexistent .bak over it which would silently delete the new file).
  update.applied_files[#update.applied_files+1] = {
    path = dest,
    bak_existed = (update.rename_bak_existed == true),
  }
  update.rename_failures = 0
  update.rename_tmp      = nil
  update.rename_dest     = nil
  update.rename_bak      = nil
  update.rename_bak_existed = false
  if update.download_idx < #update.download_queue then
    update.download_idx = update.download_idx + 1
    local next_entry = update.download_queue[update.download_idx]
    if not Updater.fire_get(next_entry.url, tmp.update_out, tmp.update_exit) then
      Updater._set_failure("download_start", string.format(
        "Could not start download for %s.", tostring(next_entry.filename)))
      Updater.rollback()
      update.state = "failed"
      return
    end
    update.state = "downloading"
  else
    for _, applied in ipairs(update.applied_files) do
      os.remove(applied.path .. ".bak")
    end
    -- Per-version stale-file cleanup. The new manifest's removed_files
    -- list (auto-populated by gen_manifest.py from the diff between this
    -- release and the prior, plus carry-forward of older deletions for
    -- users skipping versions) names files we previously shipped and no
    -- longer do. Without this step a renamed file's old name would
    -- linger on disk forever -- the rest of the updater only writes new
    -- files and overwrites existing ones, never deletes. Three layers
    -- of safety make removing user-facing files here safe:
    --   1. Authoring layer: gen_manifest.py only ever populates this
    --      list from prior manifests we ourselves shipped. A user-
    --      dropped file in the install dir cannot end up there.
    --   2. is_safe_filename: rejects path-traversal, absolute paths,
    --      backslashes, hidden segments, and unknown extensions.
    --   3. should_remove_orphan: enforces the "owned path" zone and the
    --      PROTECTED_FROM_REMOVAL set (custom system prompt override,
    --      runtime debug log, FX cache).
    -- os.remove failures are logged but do not fail the update; the
    -- new files are already in place, lingering orphans are cosmetic.
    do
      local removed = update.manifest and update.manifest.removed_files
      if type(removed) == "table" then
        local current_files = {}
        for _, entry in ipairs(update.manifest.files or {}) do
          if type(entry) == "table" and type(entry.name) == "string" then
            current_files[entry.name] = true
          end
        end
        for _, name in ipairs(removed) do
          if Updater.should_remove_orphan(name, current_files) then
            local path = Updater.local_path_for(name)
            if reaper.file_exists and reaper.file_exists(path) then
              local ok = os.remove(path)
              Log.line("UPDATE", string.format(
                "removed orphan %s: %s",
                name, ok and "ok" or "failed"))
            end
          elseif type(name) == "string" then
            -- Loud about rejected entries so a malformed manifest doesn't
            -- silently get past the predicate. Only log the first ~20
            -- chars of the name to keep the log line short on
            -- pathological inputs.
            Log.line("UPDATE", string.format(
              "removed_files: refused %s (outside owned zone or "
              .. "protected)", tostring(name):sub(1, 80)))
          end
        end
      end
    end
    update.state   = "done"
    update.applied = true
    -- Active stale-stock nudge for power-user prompt overrides. If this
    -- update modified the stock system prompt AND the user has a custom
    -- override file in place (which the loader prefers over the stock),
    -- set a persistent ExtState flag. The next-launch path reads it,
    -- clears it, and shows a one-time sticky toast inviting the user to
    -- diff the new stock prompt against their custom copy and merge any
    -- improvements worth keeping. Persistent (3rd arg true) so it
    -- survives the auto-restart that follows.
    do
      local stock_pp  = RA.RESOURCES_DIR .. "System_Prompt.md"
      local custom_pp = RA.RESOURCES_DIR .. "System_Prompt_Custom.md"
      local prompt_changed = false
      for _, applied in ipairs(update.applied_files) do
        if applied.path == stock_pp then prompt_changed = true; break end
      end
      if prompt_changed and reaper.file_exists(custom_pp) then
        reaper.SetExtState(CFG.EXT_NS, "prompt_review_pending", "1", true)
      end
    end
    -- Stage 3.4 auto-restart: schedule a short delay (so the user sees
    -- the "Applied" confirmation), then re-launch the script via the
    -- sidecar relauncher (Relaunch.lua). The relauncher re-
    -- registers ReaAssist via AddRemoveReaScript and fires it from its
    -- own script context, so auto-restart works regardless of how this
    -- instance was launched. File-existence check (cheap, no action-
    -- registry side effects) gates the restart scheduling so the done-
    -- view message stays honest: falls back to "Close and reopen" if
    -- the relauncher file is missing, which only happens on a broken
    -- install. try_auto_restart does the actual AddRemoveReaScript
    -- registration on-demand when it fires.
    if reaper.file_exists(RELAUNCHER_PATH) then
      update.restart_after = time_precise() + 1.5
      update.restart_fired = false
    else
      update.restart_after = nil
    end
  end
end

-- Called from the main loop when state == "rename_retry". Each call is one
-- frame (~30ms apart), providing a natural non-blocking delay between
-- attempts without busy-waiting. Ceiling is 15 attempts (~450ms): the
-- previous 5-attempt limit (~150ms total) tripped false-fails on cold
-- Windows Defender scans, which can hold a just-closed file exclusively
-- for 300-500ms. 15 covers the tail of that distribution without
-- noticeably delaying success cases (a single retry is the median).
function Updater.rename_retry_poll()
  if not update.rename_tmp or not update.rename_dest then
    Updater._set_failure("rename",
      "rename_retry_poll entered with no pending paths.")
    update.state = "failed"
    return
  end
  local ok_mv = os.rename(update.rename_tmp, update.rename_dest)
  if ok_mv then
    Updater.advance_after_rename(update.rename_dest)
    return
  end
  update.rename_failures = update.rename_failures + 1
  if update.rename_failures >= 15 then
    -- Give up. Restore the backup only if one was actually created --
    -- otherwise the destination is a fresh-install add and there is
    -- nothing to restore. Skipping the restore in that case prevents
    -- an empty-rename clobber that leaves neither dest nor bak.
    if update.rename_bak_existed then
      local ok_restore, restore_err = os.rename(update.rename_bak,
                                                update.rename_dest)
      if not ok_restore then
        Log.line("UPDATE", string.format(
          "rollback restore failed for %s: %s",
          update.rename_dest, tostring(restore_err)))
      end
    else
      -- Fresh-install add: no bak exists. Remove any leftover dest.
      os.remove(update.rename_dest)
    end
    os.remove(update.rename_tmp)
    Updater._set_failure("rename", string.format(
      "Could not rename downloaded file into place after %d attempts "
      .. "(%s -> %s). Antivirus or file lock?",
      update.rename_failures, update.rename_tmp, update.rename_dest))
    update.rename_tmp  = nil
    update.rename_dest = nil
    update.rename_bak  = nil
    update.rename_bak_existed = false
    Updater.rollback()
    update.state = "failed"
  end
  -- Otherwise stay in "rename_retry" state; next frame will try again.
end

Net = {}

-- =============================================================================
-- Custom-LLM connection test helpers
-- =============================================================================
-- Supports the Test Connection button on the custom_llm page. Fires a single
-- GET /v1/models request against the currently entered endpoint (without
-- requiring Save) and stores pass/fail in api_keys.custom_conn_test.result.
--
-- The test is model-agnostic -- /v1/models is a server directory listing, so
-- it only verifies the server is reachable + auth works. This is the most
-- information we can extract without running inference (which would invoke
-- reasoning on models like deepseek-r1 and block the test).
--
-- Implementation temporarily registers a minimal custom provider, fires
-- Net.fire_key_test (which dispatches custom providers to GET /v1/models),
-- then restores the originally-saved config on finish.
-- Placed after `local Net = {}` so the closures capture Net as an upvalue
-- instead of resolving it as a (nil) global.

-- Synthetic id used exclusively for the in-flight connection-test provider.
-- Double-underscore prefix makes it impossible to collide with any id that
-- Custom.gen_id() produces ("custom_" + 8 hex). Never persisted: the test
-- flow only touches in-memory PROVIDERS + S.api_key_map, never Key.save.
CUSTOM_CONN_TEST_ID = "__cllm_conn_test__"

-- Build a throwaway record from cfg_base, append it to PROVIDERS under the
-- conn-test sentinel id, and select it as the active provider. The model id
-- is a placeholder -- the GET /v1/models test doesn't reference it. Returns
-- the new provider index, or nil on failure. cfg_base carries the advanced
-- fields (connect_timeout, allow_insecure, extra_headers, model_prefix) so
-- the test exercises the same curl options the real request will use.
local function custom_conn_test_register(cfg_base)
  -- Default model id: a placeholder safe for the GET /v1/models path
  -- (which doesn't reference it). When the caller opts into the real-
  -- inference path, swap in the user's first model id from the form so
  -- the chat/completions POST hits the right model -- the placeholder
  -- would just earn an "unknown model" rejection from the server.
  local model_id_for_test = "conn-test"
  if cfg_base.use_inference_test and type(cfg_base.test_model_id) == "string"
     and cfg_base.test_model_id ~= "" then
    model_id_for_test = cfg_base.test_model_id
  end
  -- Provider-wide and per-model extra_body get plumbed through ONLY for
  -- the inference test path (GET /v1/models doesn't send a body, so the
  -- extras are irrelevant there). Net.merge_custom_extra_body reads
  -- p.extra_body and p.models[1].extra_body to assemble the merged
  -- vendor-toggle suffix that real chat would send.
  local record = {
    id                   = CUSTOM_CONN_TEST_ID,
    endpoint             = cfg_base.endpoint,
    timeout_secs         = cfg_base.timeout_secs,
    connect_timeout_secs = cfg_base.connect_timeout_secs,
    allow_insecure       = cfg_base.allow_insecure,
    model_prefix         = cfg_base.model_prefix,
    extra_headers        = cfg_base.extra_headers,
    label                = cfg_base.label,
    extra_body           = (cfg_base.use_inference_test
                              and cfg_base.extra_body) or "",
    models               = { {
      id             = model_id_for_test,
      price_in       = 0,
      price_out      = 0,
      context_window = CUSTOM_DEFAULT_CTX,
      extra_body     = (cfg_base.use_inference_test
                          and cfg_base.test_model_extra_body) or "",
    } },
  }
  -- Defensive: if a prior test left the sentinel registered, drop it first.
  Custom.unregister_id(CUSTOM_CONN_TEST_ID)
  local cust_idx = Custom.register_one(record)
  if cust_idx then
    -- Stamp the runtime-only flag on the registered provider entry so
    -- Net.fire_key_test / Net.handle_key_test can dispatch on it. Lives
    -- on the throwaway PROVIDERS slot only -- gets dropped with the
    -- sentinel in custom_conn_test_finish.
    if cfg_base.use_inference_test then
      PROVIDERS[cust_idx].use_inference_test = true
    end
    prefs.provider_idx = cust_idx
    MODELS.refresh()
  end
  return cust_idx
end

-- Validate current form values on the custom_llm edit screen and fire a
-- single connection test. Called by the "Test Connection" button. Writes
-- per-field errors on failure. Returns true if the test was fired, false
-- otherwise. Reads from api_keys.custom_edit, which is populated when the
-- user navigates into the edit screen (new record or existing record).
function CTX.custom_llm_start_conn_test()
  local edit = api_keys.custom_edit
  if not edit then return false end
  edit.errors = {}
  local has_format_error = false

  local endpoint_t  = (edit.endpoint        or ""):match("^%s*(.-)%s*$") or ""
  local timeout_t   = (edit.timeout         or ""):match("^%s*(.-)%s*$") or ""
  local ctimeout_t  = (edit.connect_timeout or ""):match("^%s*(.-)%s*$") or ""
  local label_t     = (edit.label           or ""):match("^%s*(.-)%s*$") or ""
  local key_t       = (edit.key             or ""):match("^%s*(.-)%s*$") or ""
  local prefix_t    = (edit.model_prefix    or ""):match("^%s*(.-)%s*$") or ""

  if label_t == "" then
    edit.errors.label = "Name is required."
    has_format_error = true
  end

  if not endpoint_t:match("^https?://") then
    edit.errors.endpoint = "Endpoint must start with http:// or https://."
    has_format_error = true
  elseif endpoint_t:find("[\"'`%c]") then
    -- Reject characters that would break (or escape out of) the
    -- powershell + cmd quoting in Net.fire_curl.
    edit.errors.endpoint = "Endpoint may not contain quotes, backticks, or control characters."
    has_format_error = true
  end

  local timeout_n = tonumber(timeout_t == "" and tostring(CUSTOM_DEFAULT_TIMEOUT) or timeout_t)
  if not timeout_n or timeout_n < CUSTOM_MIN_TIMEOUT then
    edit.errors.timeout = str_format(
      "Timeout must be a number >= %d seconds.", CUSTOM_MIN_TIMEOUT)
    has_format_error = true
  elseif timeout_n > CUSTOM_MAX_TIMEOUT then
    edit.errors.timeout = str_format(
      "Timeout must be <= %d seconds (1 hour).", CUSTOM_MAX_TIMEOUT)
    has_format_error = true
  end

  local ctimeout_n = tonumber(ctimeout_t == "" and tostring(Custom.DEFAULT_CONNECT) or ctimeout_t)
  if not ctimeout_n or ctimeout_n < Custom.MIN_CONNECT or ctimeout_n > Custom.MAX_CONNECT then
    edit.errors.connect_timeout = str_format(
      "Connect timeout must be a number between %d and %d seconds.",
      Custom.MIN_CONNECT, Custom.MAX_CONNECT)
    has_format_error = true
  end

  local headers_arr, headers_err = Custom.parse_headers_text(edit.headers_text or "")
  if headers_err then
    edit.errors.headers = headers_err
    has_format_error = true
  end

  if key_t ~= "" then
    local lk_valid, lk_reason = Key.validate_format(key_t,
      { is_custom = true, key_prefix = "", key_min_len = 0 })
    if not lk_valid then
      edit.errors.key = lk_reason
      has_format_error = true
    end
  end

  -- Opt-in real-inference test: only fires if the user ticked the
  -- checkbox AND filled in at least one model id. Without a model id we
  -- have nothing to send in the chat/completions body, so block the
  -- attempt with a clear per-field error rather than firing a malformed
  -- request and getting a confusing server-side error back.
  local use_inference = edit.test_with_inference and true or false
  local first_model_id = ""
  if type(edit.models) == "table" and edit.models[1] then
    first_model_id = (edit.models[1].id or ""):match("^%s*(.-)%s*$") or ""
  end
  if use_inference and first_model_id == "" then
    -- Surface via the test-result panel since edit.errors.models has no
    -- inline renderer. This puts the message right where the user is
    -- looking after they click Test Connection.
    if api_keys.custom_conn_test then
      api_keys.custom_conn_test.result = {
        ok    = false,
        error = "Add at least one model id before running an inference test.",
      }
    end
    return false
  end

  if has_format_error then return false end

  local cfg_base = {
    endpoint             = endpoint_t,
    timeout_secs         = timeout_n or CUSTOM_DEFAULT_TIMEOUT,
    connect_timeout_secs = ctimeout_n or Custom.DEFAULT_CONNECT,
    allow_insecure       = edit.allow_insecure and true or false,
    model_prefix         = prefix_t,
    extra_headers        = headers_arr,
    label                = label_t,
    use_inference_test   = use_inference,
    test_model_id        = first_model_id,
    -- Provider-wide and per-model extra_body. Only consumed by the
    -- inference test path; the GET /v1/models path sends no body so it
    -- ignores them. Pass the form values raw -- merge_custom_extra_body
    -- silently discards malformed JSON, so we don't need to re-run the
    -- save-time canonicalizer here.
    extra_body              = edit.extra_body or "",
    test_model_extra_body   = (edit.models and edit.models[1]
                                and edit.models[1].extra_body) or "",
  }
  CTX.custom_conn_test_start(cfg_base, key_t)
  return true
end

-- Start the connection test. cfg_base carries shared config (endpoint,
-- timeout, label); api_key is the auth key (or "" for none). The test
-- registers a throwaway provider under CUSTOM_CONN_TEST_ID and stashes
-- the active provider's index so finish() can restore it.
function CTX.custom_conn_test_start(cfg_base, api_key)
  local state = api_keys.custom_conn_test
  state.active            = true
  state.started           = reaper.time_precise()
  state.timeout           = CUSTOM_DEFAULT_TEST_TIMEOUT
  state.result            = nil   -- cleared; filled by advance()
  state.orig_provider_idx = prefs.provider_idx
  S.api_key_map[CUSTOM_CONN_TEST_ID] = (api_key ~= "" and api_key) or nil

  local cust_idx = custom_conn_test_register(cfg_base)
  local cust_prov = cust_idx and PROVIDERS[cust_idx] or nil
  if not cust_prov then
    CTX.custom_conn_test_advance(false, "Could not register custom provider.")
    return
  end
  S.api_key = S.api_key_map[CUSTOM_CONN_TEST_ID]
  api_keys.key_validating     = true
  api_keys.key_validating_idx = cust_idx
  -- Publish the test timeout for Net.fire_curl to pick up.
  S.key_test_custom_timeout = state.timeout
  Net.fire_key_test(cust_prov)
end

-- Record the test's pass/fail result and finish. Called by Net.handle_key_test
-- and by the various error paths in Net.fire_curl / Net.try_finish_curl.
function CTX.custom_conn_test_advance(ok, err_msg)
  local state = api_keys.custom_conn_test
  state.result = { ok = ok, error = err_msg }
  S.key_test_pending  = false
  S.key_test_provider = nil
  S.curl_pid          = nil
  CTX.custom_conn_test_finish()
end

-- Cancel an in-flight connection test. Kills any active curl request, marks
-- the result as cancelled, and restores the original custom config via finish().
function CTX.custom_conn_test_cancel()
  local state = api_keys.custom_conn_test
  if not state or not state.active then return end
  if Net.kill_curl then pcall(Net.kill_curl) end
  state.result        = { ok = false, error = "Test cancelled." }
  S.key_test_pending  = false
  S.key_test_provider = nil
  S.curl_pid          = nil
  CTX.custom_conn_test_finish()
end

-- Drop the throwaway conn-test provider, restore the previous active
-- provider, and clear transient state. Leaves state.result in place so
-- the UI can render the pass/fail message until the user clicks Test
-- Connection again or leaves the page. Persisted records are never
-- touched -- register_all was called at startup and stays in effect.
-- Idempotent: if the test was already finished (watchdog + advance racing,
-- or Cancel double-click), the second call is a no-op.
function CTX.custom_conn_test_finish()
  local state = api_keys.custom_conn_test
  if not state or not state.active then return end
  state.active                = false
  state.started               = nil
  -- Remove the throwaway provider and its in-memory key. The sentinel id is
  -- reserved, so wiping the key unconditionally is safe -- nothing else
  -- ever writes to S.api_key_map[CUSTOM_CONN_TEST_ID].
  Custom.unregister_id(CUSTOM_CONN_TEST_ID)
  S.api_key_map[CUSTOM_CONN_TEST_ID] = nil
  -- Restore active provider index (clamp if out of range).
  local orig_idx = state.orig_provider_idx or 1
  if orig_idx < 1 or orig_idx > #PROVIDERS then orig_idx = 1 end
  prefs.provider_idx = orig_idx
  MODELS.refresh()
  S.api_key = S.api_key_map[PROVIDERS.active().id]
  -- Clear transient flags.
  api_keys.key_validating     = false
  api_keys.key_validating_idx = nil
  S.status                    = "idle"
  S.key_test_custom_timeout   = nil
end

-- =============================================================================
-- Net.system_prompt_text
-- =============================================================================
-- Return the SYSTEM_PROMPT string, optionally with a per-TEST-SESSION stamp
-- appended as a hidden comment when prefs.test_force_cold_cache is on.
--
-- The stamp is minted ONCE when the toggle transitions off -> on (held in
-- S.cold_cache_stamp) and reused on every subsequent send until the toggle
-- flips off or is re-minted. That way the FIRST send after toggling on
-- misses cache across all three providers (fresh prefix the server has
-- never seen), but subsequent sends within the same test run hit cache
-- normally -- so you can still observe caching behavior turn-over-turn
-- while starting from a guaranteed cold state.
--
-- Starting a fresh cold test: toggle off, then toggle on again -- that
-- mints a new stamp.
function Net.system_prompt_text()
  local text = SYSTEM_PROMPT
  local lang = CFG.REPLY_LANGUAGE_CODES[prefs.reply_language_idx or 1]
  if lang and lang ~= "English" then
    text = text .. "\n\nVISIBLE REPLY LANGUAGE:\n"
      .. "- When visible natural-language prose is allowed, write it in "
      .. lang .. ".\n"
      .. "- Do not translate code, code fence labels, REAPER API names, "
      .. "plugin names/identifiers, JSON, XML-like tags such as "
      .. "<context_needed>, paths, filenames, model/provider names, "
      .. "diagnostic labels, or quoted project/user text.\n"
      .. "- If a contract requires raw code, JSON, or a bare "
      .. "<context_needed> tag only, obey that contract exactly."
  end
  if prefs.test_force_cold_cache and S.cold_cache_stamp then
    return text
      .. "\n\n<!-- test_force_cold_cache: "
      .. S.cold_cache_stamp
      .. " -->"
  end
  return text
end

-- =============================================================================
-- Net.bundled_static_refs
-- =============================================================================
-- Concatenates the long-lived static references (api_ref, midi_ref, theme_ref)
-- into one blob so each provider can emit them as ONE pinned exchange instead
-- of three. Saves the per-ref "Understood." ack overhead and reduces the
-- number of message turns the providers' caches have to align on (matters
-- most for Gemini's cachedContents structure). Returns nil when no refs
-- are present. Order is stable: api_ref first (largest, most stable), then
-- midi_ref, then theme_ref.
function Net.bundled_static_refs()
  local parts = {}
  if S.api_ref_message   then parts[#parts+1] = S.api_ref_message   end
  if S.midi_ref_message  then parts[#parts+1] = S.midi_ref_message  end
  if S.theme_ref_message then parts[#parts+1] = S.theme_ref_message end
  if #parts == 0 then return nil end
  return tbl_concat(parts, "\n\n")
end

-- =============================================================================
-- Net.sticky_text
-- =============================================================================
-- Net.sticky_set / Net.sticky_unset: wrappers that maintain both
-- S.sticky_context (the key -> content map) AND S.sticky_context_order (the
-- insertion-order key list). Use these instead of assigning to
-- S.sticky_context[k] directly -- the order list drives sticky_parts() emit
-- order, which is critical for prefix-cache stability.
--
-- Why insertion order matters: providers (Anthropic, OpenAI, Gemini) cache on
-- exact byte-prefix match. The earlier alphabetical sort shuffled new refs
-- into the middle of the sticky blob (e.g. adding Pro-C 3 pushed it before
-- Pro-Q 4), invalidating the entire cached prefix on every plugin addition.
-- Observed cost: ~15-20K tokens of cache_write on every ref-addition turn,
-- ~50% of total chat cost in a plugin-heavy session. Insertion order keeps
-- appends truly appended -- the prefix through existing refs stays
-- byte-identical and remains cached. See Net.sticky_parts() for the
-- two-block split that also preserves Anthropic block-level caching.
-- Dedup helper: for a fresh plugin_ref:/pref: write, check whether an
-- existing bundled key (same prefix, slash-joined names) already covers
-- this name. If yes, the standalone write is redundant -- skip it and let
-- the caller's "injected" log entry still fire at the bucket-dispatch site.
-- Returns true when the write should be skipped.
local function _sticky_would_duplicate(key)
  local prefix, name = key:match("^([%a_]+:)(.+)$")
  if not prefix or not name then return false end
  if prefix ~= "plugin_ref:" and prefix ~= "pref:" then return false end
  if name:find("/", 1, true) then return false end  -- the new key IS a bundle
  for existing_key in pairs(S.sticky_context or {}) do
    if existing_key ~= key then
      local ex_prefix, ex_names = existing_key:match("^([%a_]+:)(.+)$")
      if ex_prefix == prefix and ex_names and ex_names:find("/", 1, true) then
        for chunk in ex_names:gmatch("[^/]+") do
          if chunk == name then return true end
        end
      end
    end
  end
  return false
end

-- Symmetrical dedup: when a FRESH bundle is added, any standalone entries
-- with the same prefix that name a member of the bundle are now redundant
-- and should be removed. Returns the list of keys that were cleared (caller
-- uses this for logging if it cares).
local function _sticky_evict_standalones_for_bundle(bundle_key)
  local prefix, names = bundle_key:match("^([%a_]+:)(.+)$")
  if not prefix or not names then return {} end
  if prefix ~= "plugin_ref:" and prefix ~= "pref:" then return {} end
  if not names:find("/", 1, true) then return {} end
  local covered = {}
  for chunk in names:gmatch("[^/]+") do covered[chunk] = true end
  local to_evict = {}
  for existing_key in pairs(S.sticky_context or {}) do
    if existing_key ~= bundle_key then
      local ex_prefix, ex_name = existing_key:match("^([%a_]+:)(.+)$")
      if ex_prefix == prefix and ex_name
         and not ex_name:find("/", 1, true)
         and covered[ex_name] then
        to_evict[#to_evict+1] = existing_key
      end
    end
  end
  for _, k in ipairs(to_evict) do Net.sticky_unset(k) end
  return to_evict
end

function Net.sticky_set(key, content, source)
  if not S.sticky_context_order then S.sticky_context_order = {} end
  local is_fresh = S.sticky_context[key] == nil
  -- First-time add of a singleton that's already covered by an existing
  -- bundle: skip. Every turn before this was paying to send the same
  -- plugin_ref/pref content twice (once inside the bundle, once standalone),
  -- which bloated the sticky blob and invalidated prefix caching further
  -- downstream every time a new standalone landed.
  if is_fresh and _sticky_would_duplicate(key) then
    Log.line("STICKY", "skip redundant " .. key
      .. " (already covered by existing bundle)")
    return
  end
  if is_fresh then
    S.sticky_context_order[#S.sticky_context_order+1] = key
    -- First-time add of a bundle: evict any singletons it now subsumes.
    -- One-time cache-miss cost on the immediate next turn (the blob's
    -- suffix bytes shift), then permanent savings from not resending the
    -- singleton content on every subsequent turn.
    local evicted = _sticky_evict_standalones_for_bundle(key)
    if #evicted > 0 then
      Log.line("STICKY", "evicted " .. tbl_concat(evicted, ", ")
        .. " (subsumed by new bundle " .. key .. ")")
    end
    -- Record the source on first add only. Later same-key calls (idempotent
    -- re-pins) keep the original source -- a "copin" mid-session call
    -- shouldn't downgrade an already-"preempt" entry.
    S.sticky_pin_source = S.sticky_pin_source or {}
    S.sticky_pin_source[key] = source or "copin"
  end
  S.sticky_context[key] = content
end

function Net.sticky_unset(key)
  S.sticky_context[key] = nil
  if S.sticky_pin_source then S.sticky_pin_source[key] = nil end
  if not S.sticky_context_order then return end
  for i, k in ipairs(S.sticky_context_order) do
    if k == key then
      table.remove(S.sticky_context_order, i)
      return
    end
  end
end

-- Pin prompt_bundle:plugin into sticky if it's not already there. Called from
-- every site that pins a plugin_ref / pref_plugin / preferred_plugins entry,
-- so that any plugin ADD/CONFIGURE task arrives at the model already holding
-- the plugin workflow rules (find_param / set_param_display etc) -- saves
-- the first-plugin-turn round-trip where the model would otherwise emit
-- <context_needed>prompt_bundle:plugin</context_needed> and wait a full
-- turn before writing the script. The optional out_list parameter, when
-- provided, gets the pb_key appended so the caller can surface the bundle
-- in ctx_label / fetched_to_sticky logs.
function Net.copin_plugin_bundle(out_list)
  local pb_key = "prompt_bundle:plugin"
  if S.sticky_context[pb_key] then
    if S.prompt_bundle_sent then S.prompt_bundle_sent["plugin"] = true end
    return
  end
  local pb_content, _ = CTX.prompt_bundle("plugin")
  if not pb_content then return end
  Net.sticky_set(pb_key, pb_content)
  if S.prompt_bundle_sent then S.prompt_bundle_sent["plugin"] = true end
  if out_list then out_list[#out_list+1] = pb_key end
end

-- Pre-pin prompt_bundle:plugin_helpers (DECIDE FIRST flowchart, helper
-- function source, API DISPLAY RANGE MISMATCH guidance) into sticky_context.
-- Called when the dispatcher resolves a path that's about to write plugin
-- params with non-anchor values: fx_inspect (ADD + CONFIGURE), and fx_params
-- / preferred_plugins under a write-intent prompt. Most curated-plugin tasks
-- with verified-anchor values never need helpers and skip this co-pin.
--
-- No-op when:
--   - prompt_bundle:plugin_helpers is already in sticky_context (loaded
--     earlier this session; eviction is exempted same as docs sections).
--   - prompt_bundle_sent[plugin_helpers] is already true (defensive guard
--     against rapid double-co-pin within the same dispatch).
--   - The bundle file fails to load (logged via CTX.prompt_bundle error
--     path; the helper-definition validator is the safety net at gen time).
function Net.copin_plugin_helpers(out_list, source)
  local ph_key = "prompt_bundle:plugin_helpers"
  if S.sticky_context[ph_key] then
    if S.prompt_bundle_sent then S.prompt_bundle_sent["plugin_helpers"] = true end
    return
  end
  local ph_content, _ = CTX.prompt_bundle("plugin_helpers")
  if not ph_content then return end
  -- source defaults to "copin" inside Net.sticky_set. Pass "preempt"
  -- explicitly when called from CTX.preempt_buckets_for_prompt so the
  -- helpers bundle rides the same stable rung that's being initialized
  -- alongside prompt_bundle:plugin -- no extra rung-invalidation cost
  -- because the stable rung is being rebuilt this turn anyway.
  Net.sticky_set(ph_key, ph_content, source)
  if S.prompt_bundle_sent then S.prompt_bundle_sent["plugin_helpers"] = true end
  if out_list then out_list[#out_list+1] = ph_key end
end

-- Pre-pin a JSFX effect-family bundle (jsfx_pitch, jsfx_reverb, ...) into
-- sticky_context. Called from the preempt path when the user prompt matches
-- a family's keyword set. The bundle adds family-specific DSP topology +
-- recipe content on top of the always-available prompt_bundle:jsfx core.
-- No-op when the bundle is already pinned this session, when the bundle
-- file is missing, or when the family name isn't registered in
-- PROMPT_BUNDLE_NAMES.
function Net.copin_jsfx_family(family, out_list)
  if not family or family == "" then return end
  local pb_key = "prompt_bundle:" .. family
  if S.sticky_context[pb_key] then
    if S.prompt_bundle_sent then S.prompt_bundle_sent[family] = true end
    return
  end
  local pb_content, _ = CTX.prompt_bundle(family)
  if not pb_content then return end
  Net.sticky_set(pb_key, pb_content)
  if S.prompt_bundle_sent then S.prompt_bundle_sent[family] = true end
  if out_list then out_list[#out_list+1] = pb_key end
end

-- Pre-pin docs (core API ref) into S.api_ref_message. Called alongside
-- copin_plugin_bundle from every preempt / resolve site that signals plugin
-- work. Without this, the chain-phrase / resolve preempts pre-pin a rich
-- plugin context (plugin_ref + pref + bundle) but NO docs -- the model then
-- bypasses the API-REF-REQUIREMENT rule, writes reaper.* code anyway, and
-- the docs-gate inside Net.try_finish_curl silently force-fetches +
-- retries. Net: 2 round-trips instead of 1, +30K cache_write on the retry,
-- and the user-visible cost/time display only shows the FIRST request,
-- understating the true cost. Co-pinning docs alongside the plugin context
-- adds ~5K cache_write on the first turn but eliminates the retry's ~30K
-- and the wasted assistant turn. Net: smaller AND faster on every plugin
-- session that goes through preempt / resolve.
--
-- No-ops when:
--   - api_ref_message is already set (user has "Always include API ref" on,
--     or docs was force-fetched / requested earlier this session)
--   - docs file fails to load (logged via CTX.docs error path; docs-gate
--     still acts as the safety net on response)
--
-- Sets S.docs_already_sent so a same-turn <context_needed>docs</context_needed>
-- (e.g. from a model that's belt-and-suspenders) hits the dispatcher's
-- dedup branch instead of re-fetching. Also sets S.docs_fetched_session
-- so the docs-gate sees docs as available and doesn't trigger.
function Net.copin_docs_core(out_list)
  if S.api_ref_message then return end
  local content, _err = CTX.docs()
  if not content then return end
  S.api_ref_message      = content
  S.docs_already_sent    = true
  S.docs_fetched_session = true
  if out_list then out_list[#out_list+1] = "docs" end
end

-- Returns two text blobs, stable + growing, emitted in sticky_context_order.
--   stable : prompt_bundle:* payloads. Effectively never change once pinned
--            (a bundle is a chunk of system-prompt content for a task type,
--            not a per-plugin reference). Placed in a dedicated Anthropic
--            cache block so its cache rung stays hot across ref-addition
--            turns.
--   growing: everything else (plugin_ref, pref, preferred_plugins,
--            fx_params, fx_inspect, docs_extended). Grows as new plugins
--            are referenced; its cache rung invalidates when a new ref is
--            appended, but that only costs the new ref's tokens -- the
--            stable rung stays cached. A leading manifest line lists ALL
--            pinned keys (stable + growing) so weak models can string-scan
--            before emitting a redundant <context_needed>.
--
-- Both may be nil when their respective bucket set is empty. When only one
-- side has content, the other returns nil. sticky_text() concatenates both
-- for providers without multi-breakpoint caching.
function Net.sticky_parts()
  -- Static refs (docs / midi / theme) live in their own message slots, not in
  -- S.sticky_context, but they're equally "pinned above" from the model's POV.
  -- Include them in the manifest so the model's quick-scan sees them and
  -- doesn't emit a redundant <context_needed>docs</context_needed> (observed
  -- failure mode on weaker models).
  local static_keys = {}
  if S.api_ref_message   then static_keys[#static_keys+1] = "docs"  end
  if S.midi_ref_message  then static_keys[#static_keys+1] = "midi"  end
  if S.theme_ref_message then static_keys[#static_keys+1] = "theme" end

  local stable_keys, growing_keys = {}, {}
  if S.sticky_context_order then
    for _, k in ipairs(S.sticky_context_order) do
      if S.sticky_context[k] then
        -- Most prompt_bundle:* entries are stable (pinned once at the start
        -- of a plugin/jsfx/theme task and don't change). prompt_bundle:
        -- plugin_helpers is the exception: it can be pinned via three
        -- different paths and only one of them is safe to route to stable:
        --
        --   "preempt"        -- co-pinned in CTX.preempt_buckets_for_prompt
        --                       alongside prompt_bundle:plugin. The stable
        --                       rung is already being initialized this turn,
        --                       so adding helpers to it costs no extra
        --                       cache miss. Route to STABLE.
        --   "copin"          -- co-pinned mid-flow by a dispatcher write-
        --                       intent path (fx_params / fx_inspect /
        --                       preferred_plugins) or the helper-validator
        --                       retry. The stable rung was cached on an
        --                       earlier turn; adding helpers there would
        --                       invalidate it on a turn we didn't plan to.
        --                       Route to GROWING.
        --   "context_needed" -- pulled in response to a model
        --                       <context_needed>prompt_bundle:plugin_helpers
        --                       tag. Same reasoning as "copin". Route to
        --                       GROWING.
        --
        -- Default to "copin" (growing) for any helpers entry without a
        -- recorded source -- the safe choice that matches pre-source-tag
        -- behavior. Other prompt_bundle:* keys always go to stable; those
        -- bundles are session-defining and don't suffer the late-add
        -- problem helpers does.
        local is_helpers = (k == "prompt_bundle:plugin_helpers")
        local helpers_source = is_helpers and S.sticky_pin_source
          and S.sticky_pin_source[k] or nil
        if k:find("^prompt_bundle:") and not is_helpers then
          stable_keys[#stable_keys+1] = k
        elseif is_helpers and helpers_source == "preempt" then
          stable_keys[#stable_keys+1] = k
        else
          growing_keys[#growing_keys+1] = k
        end
      end
    end
  end

  -- Nothing pinned anywhere: no sticky output.
  if #static_keys == 0 and #stable_keys == 0 and #growing_keys == 0 then
    return nil, nil
  end

  local stable_text
  if #stable_keys > 0 then
    local parts = {}
    for _, k in ipairs(stable_keys) do parts[#parts+1] = S.sticky_context[k] end
    stable_text = tbl_concat(parts, "\n\n")
  end

  -- Always emit the manifest when any pinned bucket exists (static or sticky).
  -- The manifest lists every pinned key so the model can short-circuit
  -- re-requests. Order: static refs first (stable slot), then stable sticky
  -- (prompt_bundle:*), then growing sticky (plugin_ref/pref/fx_*).
  --
  -- LAYOUT WITHIN growing_text (cache-stability-driven):
  --   1. Byte-stable preamble (fixed text -- never changes).
  --   2. Plugin content in insertion order (sticky_context_order). This
  --      block's prefix bytes are stable across additions because content
  --      only ever appends to the end.
  --   3. Manifest at the END.
  -- Why manifest-at-end: the manifest line gains a key every time a plugin
  -- is added. Putting it at the TOP made byte 0 of growing_text differ on
  -- every addition, invalidating the entire growing cache rung. With the
  -- manifest at the end, the plugin-content prefix stays byte-identical
  -- across additions, so Anthropic's cache hits up through the previous
  -- turn's content -- only the new plugin's content + new manifest +
  -- last_asst need fresh cache_write. ~10-15K cache_write savings per
  -- ref-addition turn.
  local all_keys = {}
  for _, k in ipairs(static_keys)  do all_keys[#all_keys+1] = k end
  for _, k in ipairs(stable_keys)  do all_keys[#all_keys+1] = k end
  for _, k in ipairs(growing_keys) do all_keys[#all_keys+1] = k end
  local growing_parts = {}
  if #growing_keys > 0 then
    -- Byte-stable preamble (no key list -- fixed text). Cues the model that
    -- a manifest exists at the bottom of this section without changing the
    -- byte content turn-to-turn.
    growing_parts[#growing_parts+1] =
      "PINNED REFERENCES section follows. Full manifest at the END of this section."
    -- Plugin content in insertion order. Append-only is critical for cache
    -- stability -- see Net.sticky_set / sticky_context_order.
    for _, k in ipairs(growing_keys) do
      growing_parts[#growing_parts+1] = S.sticky_context[k]
    end
  end
  growing_parts[#growing_parts+1] =
    "PINNED REFERENCES (already provided above; do NOT re-request via "
    .. "<context_needed>): " .. tbl_concat(all_keys, ", ")
  local growing_text = tbl_concat(growing_parts, "\n\n")

  return stable_text, growing_text
end

-- Single-blob accessor for providers without Anthropic-style multi-breakpoint
-- caching (OpenAI / Gemini paths use this; Anthropic uses sticky_parts()
-- directly to keep the stable rung in its own cache breakpoint). Concatenates
-- stable + growing preserving insertion order. Returns nil when both sides
-- are empty.
function Net.sticky_text()
  local s, g = Net.sticky_parts()
  if not s and not g then return nil end
  if s and g then return s .. "\n\n" .. g end
  return s or g
end

-- =============================================================================
-- Net.sticky_evict
-- =============================================================================
-- Keeps S.sticky_context bounded over long sessions. Without this, every
-- plugin_ref / pref_plugins / fx_params bucket ever pinned in the session
-- stays in sticky forever, growing the prefix linearly and re-sending
-- 50-100K of irrelevant data on every turn for cinematic / 30+ turn sessions.
--
-- Strategy: each key has a "last touched" turn (sticky_context_age[k]).
--   - Unknown keys (just added) are treated as touched on the current turn.
--   - Keys whose payload identifier (the part after the colon) appears in
--     the current user prompt are refreshed to the current turn.
--   - Keys older than STICKY_MAX_AGE turns are evicted.
-- Conservative -- a re-mentioned plugin survives indefinitely; only truly
-- abandoned context gets pruned.
local STICKY_MAX_AGE = 10  -- turns

function Net.sticky_evict(user_text)
  if not S.sticky_context then return end
  S.turn_counter = (S.turn_counter or 0) + 1
  local now = S.turn_counter
  local age = S.sticky_context_age
  if not age then S.sticky_context_age = {}; age = S.sticky_context_age end
  local lower = (user_text or ""):lower()
  -- Initialize new keys, refresh keys whose identifier hits in the prompt.
  for k in pairs(S.sticky_context) do
    if not age[k] then age[k] = now end
    local ident = k:match("^[^:]+:(.+)$")
    if ident and lower ~= "" and lower:find(ident:lower(), 1, true) then
      age[k] = now
    end
  end
  -- Drop stale keys + clean up orphaned age entries.
  -- Exemption: docs:*, docs_extended, and recent_reaper_changes are stable
  -- session-wide reference material, not per-task context that should churn.
  -- The full set of doc payloads totals ~5K tokens; once loaded, cheaper to
  -- keep than to re-fetch on a follow-up keyword mention. Also makes the
  -- system prompt's "stays pinned for the rest of the conversation" promise
  -- truthful.
  -- Trade-off: a misfired pre-pin stays alive forever (bounded ~850-1800
  -- tokens × cache rolls; if this becomes a problem, a softer "evict at
  -- 25 turns of no-keyword-mention" rule could be added).
  local evicted
  for k, t in pairs(age) do
    if not S.sticky_context[k] then
      age[k] = nil
    elseif k == "docs_extended" or k == "recent_reaper_changes"
        or k:find("^docs:") then
      -- exempt; see comment above.
    elseif (now - t) > STICKY_MAX_AGE then
      Net.sticky_unset(k)   -- also removes k from sticky_context_order
      age[k] = nil
      evicted = (evicted or {})
      evicted[#evicted+1] = k
    end
  end
  if evicted then
    Log.line("STICKY", "evicted (age > " .. STICKY_MAX_AGE
      .. " turns): " .. tbl_concat(evicted, ", "))
  end
end

function Net.sticky_prune_after_plugin_success(user_text, code_text)
  if not (CTX and CTX.prompt_indicates_chain_context
      and CTX.prompt_indicates_chain_context(user_text)) then
    return
  end
  if not S.sticky_context then return end

  local code = tostring(code_text or "")
  local helper_used =
       code:find("%f[%w]find_param%s*%(") ~= nil
    or code:find("%f[%w]set_param_display%s*%(") ~= nil
    or code:find("%f[%w]set_param_enum%s*%(") ~= nil
    or code:find("%f[%w]set_param_enum_paced%s*%(") ~= nil
  local evict = {}
  for k in pairs(S.sticky_context) do
    if k == "fx_chains"
       or k:find("^plugin_ref:")
       or k:find("^pref:")
       or (k == "prompt_bundle:plugin_helpers" and not helper_used) then
      evict[#evict+1] = k
    end
  end
  table.sort(evict)
  for _, k in ipairs(evict) do
    if k == "fx_chains" then
      S.fx_chains_already_sent = false
    elseif k == "prompt_bundle:plugin_helpers" then
      if S.prompt_bundle_sent then S.prompt_bundle_sent["plugin_helpers"] = nil end
    else
      local refs = k:match("^plugin_ref:(.+)$")
      if refs and S.plugin_ref_sent then
        for name in refs:gmatch("[^/]+") do S.plugin_ref_sent[name] = nil end
      end
      local prefs = k:match("^pref:(.+)$")
      if prefs and S.pref_plugins_sent then
        for name in prefs:gmatch("[^/]+") do S.pref_plugins_sent[name] = nil end
      end
    end
    Net.sticky_unset(k)
    if S.sticky_context_age then S.sticky_context_age[k] = nil end
  end
  if #evict > 0 then
    Log.line("STICKY", "pruned after successful chain action: "
      .. tbl_concat(evict, ", "))
  end
end

-- =============================================================================
-- Net.build_body (provider dispatch)
-- =============================================================================
-- Constructs the complete API request JSON body. Dispatches to a provider-specific
-- builder based on the active provider. Each builder handles system prompt
-- packaging, message formatting, attachment encoding, and any provider-specific
-- features (e.g. Anthropic prompt caching).
function Net.build_body(msgs, snapshot, msg_attachments)
  -- Phase 1 instrumentation: time spent assembling the request body.
  -- Wraps the dispatcher rather than each provider variant so all
  -- callers (send_to_api initial build + retries / context-needed
  -- re-fires that call build_body inline) accumulate into the same
  -- turn's body_build phase total.
  Probe.mark_phase_start(S.probe_turn, "body_build")
  local p = PROVIDERS.active()
  local result
  if p.id == "anthropic" then
    result = Net.build_body_anthropic(msgs, snapshot, msg_attachments)
  elseif p.id == "openai" or p.id == "deepseek" or p.is_custom then
    -- Custom providers always speak the OpenAI Chat Completions schema (the
    -- de-facto standard for OSS servers like Ollama, LM Studio, vLLM).
    -- DeepSeek shares this branch -- it is OpenAI-compatible at the wire
    -- level, with thinking expressed via extra_body (see the
    -- deepseek_extra_body branch in build_body_openai itself).
    result = Net.build_body_openai(msgs, snapshot, msg_attachments)
  elseif p.id == "google" then
    result = Net.build_body_google(msgs, snapshot, msg_attachments)
  end
  Probe.mark_phase_end(S.probe_turn, "body_build")
  return result
end

-- =============================================================================
-- Net.build_body_anthropic
-- =============================================================================
-- Anthropic Messages API format. System prompt as top-level "system" field with
-- cache_control. Pinned API ref as first user message (stable cache position).
-- Snapshot injected as a separate content block in the last user message.
--
-- Cache breakpoints (max 4 allowed by Anthropic, we use up to 4):
--   1. System prompt                                 (always)
--   2. End of static_blob + sticky_stable rung       (when either present;
--      static_blob piggybacks on sticky_stable's mark when both are present)
--   3. sticky_growing rung                           (when present)
--   4. Last assistant message                        (moving breakpoint,
--      prefix grows one user/assistant pair per turn)
--
-- TTL strategy: every rung uses the 5-minute default (CACHE_5M). Two
-- constraints made anything fancier net-negative:
--
--   1. Anthropic forbids a 1h cache_control block from appearing AFTER any
--      5m block in the same request: "a ttl='1h' cache_control block must
--      not come after a ttl='5m' cache_control block" (invalid_request_error).
--      Since our breakpoints are positionally fixed (system first,
--      last_asst last), any per-rung mix of 5m+1h that puts 1h on
--      last_asst gets rejected.
--   2. Anthropic also treats the ttl field as part of the cache key, so
--      flipping a rung from 5m to 1h between turns busts that rung's
--      cached prefix. Earlier code stamped one TTL per request and
--      flipped 5m -> 1h on turn 2 to "warm" 1h coverage; the observed
--      effect was cache_read=0 on T2 (full prefix re-write) regardless
--      of whether the gap exceeded 5 min.
--
-- Plan A (this code): drop the 1h escalation entirely. Always 5m, on every
-- rung, every turn. Net effect: cache stays warm across normal read/run/
-- refine cadences (which are typically <5 min anyway), and the rare
-- >5-min idle gap costs one prefix re-write -- strictly cheaper than
-- the original "flip everyone to 1h on T2" approach which paid that cost
-- 100% of the time on multi-turn sessions.
local CACHE_5M = ',"cache_control":{"type":"ephemeral"}'

-- Cheap content fingerprint for cache-plan diagnostics. Not cryptographic --
-- just a stable 32-bit FNV-1a in hex so the debug log can show "did this
-- rung's bytes drift between turns" at a glance. Skipped when debug logging
-- is off (callers gate on prefs.debug_logging via Log.line).
local function _cache_plan_hash(s)
  local h = 2166136261
  for i = 1, #s do
    h = (h ~ s:byte(i)) * 16777619
    h = h & 0xFFFFFFFF
  end
  return string.format("%08x", h)
end

function Net.build_body_anthropic(msgs, snapshot, msg_attachments)
  -- Each rung emits CACHE_5M; the helpers below also record bytes/hash into
  -- cache_plan for the per-request CACHE-PLAN debug line. See the function
  -- header for the constraints that motivated the always-5m strategy.
  local cache_plan = {}
  local function rung_cache_mark(rung_name, content)
    cache_plan[#cache_plan+1] = {
      name = rung_name, ttl = "5m", bytes = content and #content or 0,
      hash = (content and prefs.debug_logging) and _cache_plan_hash(content) or "-",
    }
    return CACHE_5M
  end

  -- Diagnostic-only registration for content that lands ahead of an
  -- existing cache breakpoint without a marker of its own (e.g.,
  -- static_blob when sticky_stable absorbs it onto the same rung).
  -- Without this, the cache plan only hashes the rung-bearing block,
  -- so drift in the absorbed content (a new static ref appearing,
  -- reorder of api_ref / midi_ref / theme_ref) is invisible to the
  -- log even though it busts the rung's prefix in reality.
  local function rung_piggyback(rung_name, content)
    cache_plan[#cache_plan+1] = {
      name = rung_name .. "(piggyback)",
      ttl  = "-",
      bytes = content and #content or 0,
      hash = (content and prefs.debug_logging) and _cache_plan_hash(content) or "-",
    }
  end

  local system_text = Net.system_prompt_text()
  local system_json = str_format(
    '[{"type":"text","text":"%s"%s}]',
    JSON.escape(system_text), rung_cache_mark("system", system_text))

  local msg_parts = {}

  -- Bundle the long-lived static refs (api_ref + midi_ref + theme_ref) into
  -- ONE pinned user message with a single trailing ack, instead of three
  -- separate user/ack pairs. Saves ~16-24 tokens per turn in ack overhead
  -- and reduces alignment churn for downstream caches when refs come in.
  -- Anthropic 4-breakpoint allocation:
  --   slot 1: system                                   (always)
  --   slot 2: end of static_blob + sticky_stable       (when sticky_stable
  --                                                     present; static_blob
  --                                                     piggybacks on this rung)
  --           OR static_blob                           (when sticky_stable
  --                                                     absent but static_blob
  --                                                     present)
  --           OR sticky_stable                         (when static_blob absent)
  --   slot 3: sticky_growing                           (when present)
  --   slot 4: last_asst                                (moving, when history
  --                                                     has >= 1 complete turn)
  -- Why static_blob loses its dedicated cache mark when sticky_stable is
  -- present: a single-rung cache covering "system + static_blob + sticky_stable"
  -- is functionally identical to two separate rungs (any change to static_blob
  -- invalidates sticky_stable's prefix anyway), but it FREES a breakpoint slot
  -- so sticky_growing can have its own rung. The win: when sticky_growing
  -- changes (every fx_inspect / plugin_ref / pref addition), sticky_stable
  -- (~14K plugin bundle) keeps reading from cache instead of being rewritten
  -- alongside the growing block. Observed cost before this change: ~10-15K
  -- cache_write per ref-addition turn.
  local sticky_stable, sticky_growing = Net.sticky_parts()
  local static_blob = Net.bundled_static_refs()
  if static_blob then
    -- Drop static_blob's own cache_mark when sticky_stable will absorb it
    -- into the next rung. Keep it when sticky_stable is absent (otherwise
    -- static_blob would only cache via sticky_growing's rung, which gets
    -- invalidated frequently).
    local static_cache_mark
    if sticky_stable then
      -- Absorbed onto sticky_stable's rung. Register a piggyback entry
      -- in the cache plan so static-ref drift (a new midi_ref / theme_ref
      -- arriving, or api_ref reordering) shows up in the log even though
      -- this block carries no cache_control marker of its own.
      rung_piggyback("static", static_blob)
      static_cache_mark = ""
    else
      static_cache_mark = rung_cache_mark("static", static_blob)
    end
    msg_parts[#msg_parts+1] = str_format(
      '{"role":"user","content":[{"type":"text","text":"%s"%s}]}',
      JSON.escape(static_blob), static_cache_mark)
    msg_parts[#msg_parts+1] = '{"role":"assistant","content":[{"type":"text","text":"Understood."}]}'
  end
  -- Pinned sticky with up to TWO cache_control breakpoints:
  --   - sticky_stable  : prompt_bundle:* payloads (big, effectively frozen
  --                      for the rest of the session). Own cache rung so it
  --                      stays hot even when the growing block invalidates.
  --   - sticky_growing : plugin_ref / pref / fx_params / fx_inspect, plus
  --                      a manifest line listing all pinned keys. Its cache
  --                      rung re-writes on each ref addition but the stable
  --                      rung's ~15K tokens no longer get re-written with it.
  -- The 2-block split now fires whenever both halves are populated -- the
  -- breakpoint budget is free because static_blob piggybacks on sticky_stable.
  local has_sticky = sticky_stable or sticky_growing
  if has_sticky then
    local can_split = sticky_stable and sticky_growing
    if can_split then
      -- Two content blocks in ONE user message, each with its own
      -- cache_control. Anthropic caches each block as its own prefix rung:
      -- adding a new plugin_ref changes the growing block but NOT the
      -- stable block, so the stable rung keeps reading on subsequent
      -- turns. Saves ~15K tokens of cache_write per ref-addition turn.
      msg_parts[#msg_parts+1] = str_format(
        '{"role":"user","content":[{"type":"text","text":"%s"%s},{"type":"text","text":"%s"%s}]}',
        JSON.escape(sticky_stable), rung_cache_mark("sticky_stable", sticky_stable),
        JSON.escape(sticky_growing), rung_cache_mark("sticky_growing", sticky_growing))
    else
      -- Single-block fallback: only one of stable/growing is populated.
      -- Concatenate in stable-first order so byte-prefix caching still wins
      -- on OpenAI-style implicit cache if we're ever reused there.
      local blob = sticky_stable and sticky_growing
        and (sticky_stable .. "\n\n" .. sticky_growing)
        or  (sticky_stable or sticky_growing)
      -- Rung name reflects which half is present so per-rung TTL state
      -- doesn't conflate "sticky_stable alone" with "sticky_stable + growing
      -- collapsed into one rung". In practice only one of these branches
      -- exercises within a given session.
      local rung = sticky_stable and "sticky_stable" or "sticky_growing"
      msg_parts[#msg_parts+1] = str_format(
        '{"role":"user","content":[{"type":"text","text":"%s"%s}]}',
        JSON.escape(blob), rung_cache_mark(rung, blob))
    end
    msg_parts[#msg_parts+1] = '{"role":"assistant","content":[{"type":"text","text":"Understood."}]}'
  end

  for idx, m in ipairs(msgs) do
    local is_last_user = (m.role == "user" and idx == #msgs)

    if is_last_user then
      -- Build content blocks for the last user message: text + snapshot + attachments.
      local blocks = {}
      blocks[#blocks+1] = str_format('{"type":"text","text":"%s"}',
        JSON.escape(m.content))

      if snapshot then
        blocks[#blocks+1] = str_format('{"type":"text","text":"%s"}',
          JSON.escape(snapshot))
      end

      -- Append attachment content blocks (images, PDFs, text files).
      if msg_attachments then
        for _, att in ipairs(msg_attachments) do
          if att.kind == "image" then
            blocks[#blocks+1] = str_format(
              '{"type":"image","source":{"type":"base64","media_type":"%s","data":"%s"}}',
              att.media_type, att.b64)
          elseif att.kind == "pdf" then
            blocks[#blocks+1] = str_format(
              '{"type":"document","source":{"type":"base64","media_type":"application/pdf","data":"%s"}}',
              att.b64)
          elseif att.kind == "text" then
            blocks[#blocks+1] = str_format(
              '{"type":"text","text":"[Attached file: %s]\\n%s"}',
              JSON.escape(att.name), JSON.escape(att.data))
          end
        end
      end

      msg_parts[#msg_parts+1] = str_format(
        '{"role":"user","content":[%s]}', tbl_concat(blocks, ","))
    else
      -- Non-final messages: single block. Mark the last assistant message as a
      -- moving cache breakpoint so the conversation prefix is cached for
      -- cheaper follow-up turns.
      local is_last_asst = (m.role == "assistant" and idx == #msgs - 1)
      local cache = is_last_asst and rung_cache_mark("last_asst", m.content) or ""
      msg_parts[#msg_parts+1] = str_format(
        '{"role":"%s","content":[{"type":"text","text":"%s"%s}]}',
        m.role, JSON.escape(m.content), cache)
    end
  end

  -- Per-rung cache plan (debug only): rung=bytes/ttl/hash, comma-separated.
  -- Lets the user diff request-to-request: if a rung's hash changes, its
  -- prefix bytes drifted (manifest reorder, ref insertion); if its ttl
  -- string changes, the freeze logic regressed. Either way, expect a miss.
  if prefs.debug_logging and #cache_plan > 0 then
    local parts = {}
    for _, p in ipairs(cache_plan) do
      parts[#parts+1] = str_format("%s=%dB/%s/%s", p.name, p.bytes, p.ttl, p.hash)
    end
    Log.line("CACHE-PLAN", tbl_concat(parts, ", "))
  end

  -- Anthropic Messages API REQUIRES max_tokens (omitting returns 400). Send
  -- the active model's published output ceiling so the model can write up to
  -- the maximum it supports. Falls back to 64K if the model entry is missing
  -- max_output (older entries; defensive, all current entries have it).
  local active_m = MODELS[prefs.model_idx] or MODELS[1]
  local max_out  = (active_m and active_m.max_output) or 64000

  -- Extended thinking. Anthropic's API treats `thinking` as opt-in for
  -- every Claude model: when the field is absent, the model runs in
  -- non-thinking mode regardless of which 4.x variant is active. The
  -- "None" dropdown entry maps to that no-emit case. When a non-None
  -- level is picked, the wire shape depends on the active model's
  -- thinking_style: Haiku 4.5 takes manual budget_tokens; Opus 4.7
  -- requires adaptive + an effort knob (manual returns 400); Sonnet 4.6
  -- accepts either, adaptive preferred. S.thinking_override_idx (when
  -- set) wins over prefs.thinking_idx so the length-retry path can force
  -- "None" for one round-trip.
  local p_active = PROVIDERS.active()
  local effective_thinking_idx = S.thinking_override_idx or prefs.thinking_idx
  local thinking_field = ""
  if effective_thinking_idx and effective_thinking_idx > 0
     and p_active.thinking_levels then
    local tl = p_active.thinking_levels[effective_thinking_idx]
    local style = active_m and active_m.thinking_style
    if tl and tl.value ~= "none" then
      if style == "claude_adaptive" and tl.effort then
        thinking_field = str_format(
          ',"thinking":{"type":"adaptive"},"output_config":{"effort":"%s"}',
          tl.effort)
      elseif tl.budget_tokens then
        -- claude_manual (Haiku 4.5) -- and a defensive fallback if a
        -- model entry omits thinking_style entirely.
        thinking_field = str_format(
          ',"thinking":{"type":"enabled","budget_tokens":%d}',
          tl.budget_tokens)
      end
    end
  end

  return str_format(
    '{"model":"%s","max_tokens":%d%s,"system":%s,"messages":[%s]}',
    MODELS.active_id(), max_out, thinking_field, system_json,
    tbl_concat(msg_parts, ","))
end

-- =============================================================================
-- Net.merge_custom_extra_body
-- =============================================================================
-- Merge provider-wide extra_body (p.extra_body) with per-model extra_body
-- (active_m.extra_body) and return the result as a comma-prefixed JSON
-- body suffix ("," + inner-JSON without surrounding braces) ready to splice
-- into the outer chat/completions body. Returns "" when both are empty or
-- decode fails -- callers can append it unconditionally.
--
-- Per-model keys win over provider-wide keys (in-order decode/merge/re-
-- encode pass). Runs through JSON.decode / JSON.encode so we don't brace-
-- splice raw user input.
--
-- Shared by Net.build_body_openai (real chat) and Net.fire_key_test's
-- opt-in inference probe so the test exercises the same vendor-specific
-- toggles as the real chat path. active_m may be nil; result is the same
-- as if its extra_body were empty.
function Net.merge_custom_extra_body(p, active_m)
  if not p or not p.is_custom then return "" end
  local prov_body  = p.extra_body or ""
  local model_body = (active_m and active_m.extra_body) or ""
  if prov_body == "" and model_body == "" then return "" end
  local merged = {}
  if prov_body ~= "" then
    local pobj = JSON.decode(prov_body)
    if type(pobj) == "table" then
      for k, v in pairs(pobj) do merged[k] = v end
    end
  end
  if model_body ~= "" then
    local mobj = JSON.decode(model_body)
    if type(mobj) == "table" then
      for k, v in pairs(mobj) do merged[k] = v end
    end
  end
  local encoded = JSON.encode(merged)
  if not encoded or encoded == "{}"
     or encoded:sub(1, 1) ~= "{" or encoded:sub(-1) ~= "}" then
    return ""
  end
  local inner = encoded:sub(2, -2)
  if inner == "" then return "" end
  return "," .. inner
end

-- =============================================================================
-- Net.build_body_openai
-- =============================================================================
-- OpenAI Chat Completions API format. System prompt as a "system" role message.
-- All messages are simple {role, content} objects. Attachments: images as
-- image_url content parts, text files inline, PDFs as text note (unsupported).
function Net.build_body_openai(msgs, snapshot, msg_attachments)
  local msg_parts = {}

  -- System prompt as the first message.
  msg_parts[#msg_parts+1] = str_format(
    '{"role":"system","content":"%s"}', JSON.escape(Net.system_prompt_text()))

  -- Bundle the long-lived static refs (api_ref + midi_ref + theme_ref) into
  -- ONE pinned system message instead of three. OpenAI's implicit prefix
  -- caching aligns on byte-level prefix; fewer message boundaries mean a
  -- cleaner, more stable prefix. See Net.bundled_static_refs().
  local static_blob = Net.bundled_static_refs()
  if static_blob then
    msg_parts[#msg_parts+1] = str_format(
      '{"role":"system","content":"%s"}', JSON.escape(static_blob))
  end

  -- Prepend pinned sticky context (plugin_ref / pref_plugins / fx_params /
  -- fx_inspect) as a system message so OpenAI's implicit prefix caching can
  -- discover the stable common prefix across turns. See Net.sticky_text().
  local sticky_blob = Net.sticky_text()
  if sticky_blob then
    msg_parts[#msg_parts+1] = str_format(
      '{"role":"system","content":"%s"}', JSON.escape(sticky_blob))
  end

  for idx, m in ipairs(msgs) do
    local is_last_user = (m.role == "user" and idx == #msgs)

    if is_last_user then
      -- Last user message: may include snapshot and attachments as content array.
      local has_extras = snapshot or msg_attachments
      if has_extras then
        local blocks = {}
        blocks[#blocks+1] = str_format('{"type":"text","text":"%s"}',
          JSON.escape(m.content))
        if snapshot then
          blocks[#blocks+1] = str_format('{"type":"text","text":"%s"}',
            JSON.escape(snapshot))
        end
        local _is_deepseek = (PROVIDERS.active().id == "deepseek")
        if msg_attachments then
          for _, att in ipairs(msg_attachments) do
            if att.kind == "image" then
              if _is_deepseek then
                -- DeepSeek's Chat Completion API is text-only (their own
                -- Anthropic-compat table marks image content unsupported),
                -- so an image_url block would 400 the request. Surface
                -- the attachment by name as a text note so the model can
                -- acknowledge it and the user understands why it isn't
                -- visually inspected -- mirrors the PDF handling below.
                blocks[#blocks+1] = str_format(
                  '{"type":"text","text":"[Attached image: %s] (DeepSeek does not support image input; this attachment was not sent.)"}',
                  JSON.escape(att.name))
              else
                blocks[#blocks+1] = str_format(
                  '{"type":"image_url","image_url":{"url":"data:%s;base64,%s"}}',
                  att.media_type, att.b64)
              end
            elseif att.kind == "text" then
              blocks[#blocks+1] = str_format(
                '{"type":"text","text":"[Attached file: %s]\\n%s"}',
                JSON.escape(att.name), JSON.escape(att.data))
            elseif att.kind == "pdf" then
              blocks[#blocks+1] = str_format(
                '{"type":"text","text":"[Attached PDF: %s] (PDF content attached as document)"}',
                JSON.escape(att.name))
            end
          end
        end
        msg_parts[#msg_parts+1] = str_format(
          '{"role":"user","content":[%s]}', tbl_concat(blocks, ","))
      else
        msg_parts[#msg_parts+1] = str_format(
          '{"role":"user","content":"%s"}', JSON.escape(m.content))
      end
    else
      msg_parts[#msg_parts+1] = str_format(
        '{"role":"%s","content":"%s"}', m.role, JSON.escape(m.content))
    end
  end

  local p = PROVIDERS.active()
  -- reasoning_effort: top-level string on the Chat Completions API.
  -- Valid values: "minimal" | "low" | "medium" | "high". The dropdown's "none"
  -- entry means "do not send the field" -- omitting it disables reasoning.
  -- S.thinking_override_idx (when set) wins over prefs.thinking_idx -- the
  -- length auto-retry path uses this to force "none" for one round-trip
  -- when reasoning consumed the entire output budget on the first attempt.
  --
  -- DeepSeek (thinking_style == "deepseek_extra_body") expresses thinking
  -- via a top-level "thinking" object with type="disabled"|"enabled" instead
  -- of OpenAI's reasoning_effort scale. The "extra_body" name in DeepSeek's
  -- own docs is an OpenAI-SDK pass-through convention; on the wire the
  -- field sits at the top level next to where reasoning_effort would go.
  -- The field is MANDATORY for every DeepSeek request: omitting it falls
  -- through to DeepSeek's server-side default (currently enabled) which
  -- would silently ignore both the user's Non-Thinking selection and the
  -- length-retry fallback. Always emit an explicit "enabled"/"disabled";
  -- if the resolved idx is somehow out-of-range or carries an unexpected
  -- value, default to "disabled" (safer -- no surprise reasoning cost).
  local effective_thinking_idx = S.thinking_override_idx or prefs.thinking_idx
  local reasoning = ""
  if p.thinking_style == "deepseek_extra_body" then
    local tl = p.thinking_levels and p.thinking_levels[effective_thinking_idx]
    local val = (tl and tl.value) or "disabled"
    if val ~= "enabled" and val ~= "disabled" then val = "disabled" end
    reasoning = str_format(',"thinking":{"type":"%s"}', val)
  elseif effective_thinking_idx > 0
     and p.thinking_levels
     and p.thinking_levels[effective_thinking_idx] then
    local val = p.thinking_levels[effective_thinking_idx].value
    if val and val ~= "none" then
      reasoning = str_format(',"reasoning_effort":"%s"', val)
    end
  end
  -- prompt_cache_key: stable per script-session identifier. OpenAI's automatic
  -- prefix caching auto-routes requests sharing this key to the same backend
  -- worker, raising cache-hit rate on long sessions. The key is opaque to us.
  -- Custom-provider model prefix: OpenRouter/LiteLLM/Ollama routing gateways
  -- often require a prefix ("openrouter/anthropic/...", "ollama/...") on the
  -- model id. Stored per-provider so users don't have to type it into every
  -- model row. Empty string = no-op, matching hosted OpenAI's behaviour.
  local model_id = MODELS.active_id()
  if p.is_custom and p.model_prefix and p.model_prefix ~= "" then
    model_id = p.model_prefix .. model_id
  end
  local response_format = ""
  if p.id == "openai"
     and S.pending_typed_action_expected == true
     and S.pending_typed_action_response_format == true
     and type(Code.typed_actions_openai_response_format_field) == "function" then
    response_format =
      Code.typed_actions_openai_response_format_field(
        S.pending_orig_prompt or "") or ""
  end
  -- Custom-provider extra_body: merge provider-wide + per-model JSON objects
  -- into the outer request body. Net.merge_custom_extra_body is the shared
  -- helper -- used here for real chat AND from Net.fire_key_test's opt-in
  -- inference test path so the test exercises the same vendor toggles
  -- (Kimi thinking flag, Qwen enable_thinking, OpenRouter reasoning, etc.)
  -- that real chat sends.
  local extra_suffix = ""
  if p.is_custom then
    extra_suffix = Net.merge_custom_extra_body(p, MODELS[prefs.model_idx])
  end
  -- max_completion_tokens: optional on the OpenAI Chat Completions API. For
  -- normal cloud OpenAI chat, omit it so the server applies its own per-model
  -- ceiling -- avoids the GPT-5-thinking failure mode where a fixed cap got
  -- consumed by reasoning tokens and produced empty visible output. Typed-action
  -- response-format requests are different: the only valid answer is compact
  -- JSON, so cap them to prevent runaway structured-output completions. Keep
  -- enough room for GPT-5 mini Low thinking, which can spend several thousand
  -- hidden reasoning tokens before emitting the compact JSON object. Small
  -- typed-action profiles can opt into a lower cap; if they hit it, the
  -- validator fails closed and escalates instead of waiting on an 8K-token loop.
  -- For custom providers (Ollama / LM Studio / vLLM / OpenRouter etc.), keep
  -- the cap derived from the per-model context_window field on the API Keys
  -- page, since local servers commonly run with tight context windows that need
  -- a real bound on output.
  local max_tokens_field = ""
  if p.id == "openai" and response_format ~= "" then
    local typed_action_cap = 8192
    local active_model = MODELS[prefs.model_idx]
    local model_cap = active_model
      and tonumber(active_model.typed_action_max_completion)
    if model_cap and model_cap > 0 then
      typed_action_cap = math_floor(model_cap)
    end
    local tl = p.thinking_levels and p.thinking_levels[effective_thinking_idx]
    if S.typed_action_escalation_used == true
       and tl and tl.value == "none" then
      typed_action_cap = math_min(typed_action_cap, 2048)
    end
    max_tokens_field =
      str_format(',"max_completion_tokens":%d', typed_action_cap)
  elseif p.is_custom then
    local custom_active = MODELS[prefs.model_idx]
    local ctx_window    = (custom_active and tonumber(custom_active.context_window))
                          or CUSTOM_DEFAULT_CTX
    -- Reserve at most 10% of the local context for output, with a hard
    -- ceiling at 16K so a misconfigured huge context_window doesn't lead
    -- to absurd output budgets that don't match what local hardware can
    -- actually generate in a reasonable time.
    local custom_cap = math_min(16384, math_floor(ctx_window * 0.1))
    if custom_cap < 256 then custom_cap = 256 end
    max_tokens_field = str_format(',"max_completion_tokens":%d', custom_cap)
  end
  -- DeepSeek: skip prompt_cache_key (OpenAI-only routing hint; DeepSeek caches
  -- automatically on prefix and ignores the field, but emitting it makes the
  -- request log misleading) and skip max_completion_tokens (handled like
  -- cloud OpenAI -- let the server apply its own per-model ceiling).
  if p.id == "deepseek" then
    return str_format(
      '{"model":"%s","messages":[%s]%s%s}',
      model_id, tbl_concat(msg_parts, ","), reasoning, extra_suffix)
  end
  return str_format(
    '{"model":"%s"%s,"prompt_cache_key":"%s","messages":[%s]%s%s%s}',
    model_id, max_tokens_field, JSON.escape(S.INSTANCE_ID),
    tbl_concat(msg_parts, ","), reasoning, response_format, extra_suffix)
end

-- =============================================================================
-- Net.build_body_google
-- =============================================================================
-- Gemini generateContent API format. System prompt as systemInstruction.
-- Messages as contents[]. Role mapping: "assistant" -> "model".
-- Attachments: images and PDFs as inlineData parts, text files inline.
--
-- If a Gemini explicit context cache is active and valid for the current
-- model, the cached content (system_instruction + api_ref priming) is
-- referenced via cachedContent and omitted from the live request body.
function Net.build_body_google(msgs, snapshot, msg_attachments)
  local msg_parts = {}
  local use_cache = Net.gemini_cache_is_usable()
  S.gemini_cache_last_used = use_cache == true
  S.gemini_cache_last_state =
    Net.gemini_cache_debug_state("body_build", use_cache)

  -- Bundle the long-lived static refs (api_ref + midi_ref + theme_ref) into
  -- ONE pinned user+model exchange instead of three. Fewer turns inside
  -- contents[] is cleaner for Gemini's implicit prefix caching to align on.
  -- When the explicit context cache is active, it already covers api_ref +
  -- system_instruction, so we omit api_ref from the bundle in that case to
  -- avoid double-sending it.
  local static_parts = {}
  if S.api_ref_message and not use_cache then
    static_parts[#static_parts+1] = S.api_ref_message
  end
  if S.midi_ref_message  then static_parts[#static_parts+1] = S.midi_ref_message  end
  if S.theme_ref_message then static_parts[#static_parts+1] = S.theme_ref_message end
  if #static_parts > 0 then
    local static_blob = tbl_concat(static_parts, "\n\n")
    msg_parts[#msg_parts+1] = str_format(
      '{"role":"user","parts":[{"text":"%s"}]}', JSON.escape(static_blob))
    msg_parts[#msg_parts+1] = '{"role":"model","parts":[{"text":"Understood."}]}'
  end

  -- Prepend pinned sticky context (plugin_ref / pref_plugins / fx_params /
  -- fx_inspect) as a user+model exchange. Sits in a stable prefix position
  -- so Gemini's implicit caching (and explicit cache if it covers here) can
  -- match it across turns. See Net.sticky_text(). Deliberately NOT included
  -- in the Gemini explicit cache (that stays scoped to api_ref only), so
  -- sticky growth doesn't force cache recreation.
  local sticky_blob = Net.sticky_text()
  if sticky_blob then
    msg_parts[#msg_parts+1] = str_format(
      '{"role":"user","parts":[{"text":"%s"}]}', JSON.escape(sticky_blob))
    msg_parts[#msg_parts+1] = '{"role":"model","parts":[{"text":"Understood."}]}'
  end

  for idx, m in ipairs(msgs) do
    local is_last_user = (m.role == "user" and idx == #msgs)
    -- Gemini uses "model" instead of "assistant".
    local role = (m.role == "assistant") and "model" or m.role

    if is_last_user then
      local parts = {}
      parts[#parts+1] = str_format('{"text":"%s"}', JSON.escape(m.content))
      if snapshot then
        parts[#parts+1] = str_format('{"text":"%s"}', JSON.escape(snapshot))
      end
      if msg_attachments then
        for _, att in ipairs(msg_attachments) do
          if att.kind == "image" then
            parts[#parts+1] = str_format(
              '{"inlineData":{"mimeType":"%s","data":"%s"}}',
              att.media_type, att.b64)
          elseif att.kind == "pdf" then
            parts[#parts+1] = str_format(
              '{"inlineData":{"mimeType":"application/pdf","data":"%s"}}',
              att.b64)
          elseif att.kind == "text" then
            parts[#parts+1] = str_format(
              '{"text":"[Attached file: %s]\\n%s"}',
              JSON.escape(att.name), JSON.escape(att.data))
          end
        end
      end
      msg_parts[#msg_parts+1] = str_format(
        '{"role":"user","parts":[%s]}', tbl_concat(parts, ","))
    else
      msg_parts[#msg_parts+1] = str_format(
        '{"role":"%s","parts":[{"text":"%s"}]}', role, JSON.escape(m.content))
    end
  end

  local thinking = ""
  -- S.thinking_override_idx (when set) wins over prefs.thinking_idx -- the
  -- length auto-retry path uses this to force "none" for one round-trip
  -- when reasoning consumed the entire output budget on the first attempt.
  local effective_thinking_idx = S.thinking_override_idx or prefs.thinking_idx
  if effective_thinking_idx > 0 then
    local p = PROVIDERS.active()
    local m = MODELS[prefs.model_idx] or MODELS[1]
    if p.thinking_levels then
      -- If Pro model and MINIMAL selected, bump to LOW (MINIMAL is flash-only)
      local tidx = effective_thinking_idx
      local tl = p.thinking_levels[tidx]
      if tl and tl.flash_only and not m.is_flash then
        tidx = math_min(tidx + 1, #p.thinking_levels)  -- next level (LOW)
        tl = p.thinking_levels[tidx]
      end
      if tl then
        thinking = str_format(',"thinkingConfig":{"thinkingLevel":"%s","includeThoughts":false}', tl.value)
      end
    end
  end
  -- maxOutputTokens: optional in Gemini's generationConfig. Omit it so the
  -- server applies its own per-model ceiling (~64K on Gemini 3.x). Same
  -- rationale as the OpenAI path: a fixed cap can be entirely consumed by
  -- thinking tokens, leaving zero visible output. Letting the server cap
  -- naturally avoids that failure mode.
  if use_cache then
    -- system_instruction lives inside the cache; omit it from the live body.
    return str_format(
      '{"contents":[%s],"cachedContent":"%s","generationConfig":{%s}}',
      tbl_concat(msg_parts, ","), S.gemini_cache_name,
      thinking:gsub("^,", ""))
  end
  return str_format(
    '{"contents":[%s],"systemInstruction":{"parts":[{"text":"%s"}]},"generationConfig":{%s}}',
    tbl_concat(msg_parts, ","), JSON.escape(Net.system_prompt_text()),
    thinking:gsub("^,", ""))
end

-- =============================================================================
-- Net.trimmed_history
-- =============================================================================
-- Returns the last CFG.MAX_HISTORY_TURNS entries from S.history for the API call.
-- The full S.history table is preserved for display; only the slice is sent.
-- If the first entry in the slice is an assistant message (possible if an
-- odd number of entries were removed mid-conversation), it is dropped so
-- the API always receives a conversation starting with a user turn.
--
-- When the compact_history dev flag is on, T-2 and older successful
-- assistant turns are replaced with a fixed-format summary instead of
-- the full code body. T-1 always stays verbatim. See
-- Net.assistant_attach_compact_metadata + _maybe_compact_history below.
function Net.trimmed_history()
  local hist
  if #S.history <= CFG.MAX_HISTORY_TURNS then
    hist = S.history
  else
    hist = {}
    for i = #S.history - CFG.MAX_HISTORY_TURNS + 1, #S.history do
      hist[#hist+1] = S.history[i]
    end
    if #hist > 0 and hist[1].role == "assistant" then
      tbl_remove(hist, 1)
    end
    if #hist == 0 then
      -- Slice was a single assistant entry that we just dropped. Return
      -- just the most recent message rather than falling back to the
      -- FULL untrimmed S.history (latent overshoot of the trim budget;
      -- only triggerable at very low MAX_HISTORY_TURNS, but the previous
      -- behaviour silently sent every prior turn, defeating the trim).
      hist = { S.history[#S.history] }
    end
  end
  return Net._maybe_compact_history(hist)
end

-- Cheap fingerprint for compact_history summaries. Same FNV-1a 32-bit
-- as the cache-plan diagnostic; reused so a turn's history-summary
-- code-hash can be cross-referenced with cache-plan rung hashes.
-- Attached to Net (not a file-scope local) to stay under Lua 5.4's
-- 200-local-per-function limit on the top-level chunk.
function Net._compact_hash(s)
  if not s or s == "" then return "00000000" end
  local h = 2166136261
  for i = 1, #s do
    h = (h ~ s:byte(i)) * 16777619
    h = h & 0xFFFFFFFF
  end
  return string.format("%08x", h)
end

-- Build a fixed-format structured summary for an assistant turn. Local
-- construction (no model call); deterministic; ~200-300 bytes vs the
-- 3-7K of the original code body. Schema is intentionally rigid so
-- the model can quickly skim "what was that turn?" without parsing
-- prose. See Net.assistant_attach_compact_metadata for the per-turn
-- inputs.
function Net._build_compact_summary(info)
  local lines = { "[ASSISTANT TURN -- COMPACTED SUMMARY]" }
  local artifact = info.code_type or "none"
  if artifact == nil or artifact == "" then artifact = "none" end
  lines[#lines+1] = "artifact: " .. artifact
  lines[#lines+1] = "status: " .. (info.run_status or "unknown")
  if info.code_bytes and info.code_bytes > 0 then
    local nlines = info.code_lines or 0
    lines[#lines+1] = string.format(
      "code: %dB / %d lines / hash:%s",
      info.code_bytes, nlines, info.code_hash or "-")
  end
  if info.user_intent and info.user_intent ~= "" then
    -- Trim long prompts to ~120 chars so the summary stays compact even
    -- on verbose user requests. Newlines collapsed to spaces.
    local trimmed = info.user_intent:gsub("[\r\n]+", " ")
    if #trimmed > 120 then trimmed = trimmed:sub(1, 117) .. "..." end
    lines[#lines+1] = "intent: " .. trimmed
  end
  lines[#lines+1] = "(full code body elided; ask to "
                 .. "modify/fix the previous script to expand)"
  return tbl_concat(lines, "\n")
end

-- Attach compact-history metadata to S.history[hist_idx]. Called from
-- the canonical "turn completed successfully" site at the bottom of
-- Net.try_finish_curl. info.code is the extracted code body (lua or
-- jsfx); info.code_type is "lua" / "jsfx" / nil; info.auto_ran_ok and
-- info.was_truncated come from the response handler's locals;
-- info.user_intent is S.pending_orig_prompt (the user message that
-- triggered this turn).
--
-- compact_eligible only fires for the safe case: auto-ran-ok + a real
-- code body + not truncated + a summary that actually saves bytes.
-- Everything else (errored, manual_run, truncated, no_code,
-- gate-hit-without-retry, tiny scripts) stays verbatim so the model can
-- still see the original on a "fix that" follow-up.
Net._COMPACT_MIN_SAVINGS = 128
function Net.assistant_attach_compact_metadata(hist_idx, info)
  local row = S.history and S.history[hist_idx]
  if not row or row.role ~= "assistant" then return end
  -- run_status is mostly set already (Code.run path / risky-gate /
  -- truncation), but if no code was extracted at all, leave it at the
  -- "no_code" default written at append time. info.code being non-nil
  -- means the response had an extractable, parse-clean code block.
  local code = info.code
  local code_bytes, code_hash, code_lines = 0, nil, 0
  if code and code ~= "" then
    code_bytes = #code
    code_hash  = Net._compact_hash(code)
    -- Cheap line count -- newlines + 1 if last char isn't newline.
    local nl = 0
    for _ in code:gmatch("\n") do nl = nl + 1 end
    code_lines = nl + (code:sub(-1) == "\n" and 0 or 1)
  end
  -- Code exists but auto-run never ran (prefs.auto_run off, or one of
  -- the docs/validator/jsfx/defer/helper gates blocked the auto-run
  -- block in try_finish_curl). The row is still "no_code" because
  -- nothing wrote a real run_status. Upgrade to "manual_run" so the
  -- compact-history skip-reason diagnostic tells the truth -- the row
  -- is still ineligible for compaction either way (compact_eligible
  -- requires "ran_ok"), so behavior is unchanged, just less misleading.
  if code_bytes > 0 and row.run_status == "no_code" then
    row.run_status = "manual_run"
  end
  row.code_bytes = code_bytes
  row.code_hash  = code_hash
  row.code_lines = code_lines
  row.code_type  = info.code_type or row.code_type
  row.truncated  = info.was_truncated or row.truncated or false
  -- Build the summary content once, now, while the inputs are fresh.
  -- (Re-building on every send_to_api would be wasted work since the
  -- inputs don't change after the turn closes.)
  row.compact_summary = Net._build_compact_summary({
    code_type   = row.code_type,
    run_status  = row.run_status,
    code_bytes  = row.code_bytes,
    code_lines  = row.code_lines,
    code_hash   = row.code_hash,
    user_intent = info.user_intent,
  })
  row.compact_savings = #(row.content or "") - #(row.compact_summary or "")
  -- Eligibility gate. Conservative: only ran_ok turns with real code
  -- and no truncation are safe to compact, and only when the summary is
  -- meaningfully smaller than the original assistant content. Anything
  -- else stays verbatim with a recorded skip reason for the [HISTORY-COMPACT]
  -- diagnostic line.
  if row.run_status == "ran_ok"
     and code_bytes > 0
     and not row.truncated
     and row.compact_savings >= Net._COMPACT_MIN_SAVINGS then
    row.compact_eligible = true
    row.compact_skip_reason = nil
  else
    row.compact_eligible = false
    if row.run_status == "ran_ok" and code_bytes <= 0 then
      row.compact_skip_reason = "no_code"
    elseif row.run_status == "ran_ok" and row.truncated then
      row.compact_skip_reason = "truncated"
    elseif row.run_status == "ran_ok"
           and row.compact_savings < Net._COMPACT_MIN_SAVINGS then
      row.compact_skip_reason = "too_small"
    else
      row.compact_skip_reason = row.run_status or "unknown"
    end
  end
end

-- Conservative "modify the previous script" detector. Returns true when
-- the most recent user turn looks like a deictic reference to prior
-- code -- in which case _maybe_compact_history skips compaction
-- entirely so the model can see the full history. False positives just
-- disable savings for that turn (no correctness regression).
-- Constants attached to Net (not file-scope locals) to stay under Lua
-- 5.4's 200-local-per-function limit on the top-level chunk.
Net._MODIFY_PRIOR_VERBS =
  "modify|tweak|fix|change|adjust|update|revise|rework|redo|strip|remove"
  .. "|move|swap|replace|drop|delete"
Net._MODIFY_PRIOR_CODE_VERBS =
  "modify|tweak|fix|change|adjust|update|revise|rework|redo|strip|remove"
  .. "|move|swap|replace|drop|delete"
Net._MODIFY_PRIOR_REF_NOUNS =
  "that|it|this|previous|last|one|version|pass|result"
Net._MODIFY_PRIOR_CODE_NOUNS = "script|code"
Net._MODIFY_PRIOR_DIRECT_VERBS = "make|use"
Net._MODIFY_PRIOR_DIRECT_NOUNS = "it|that|this|one"
function Net._is_modify_prior_followup(hist)
  -- Last role=user turn (current turn's prompt -- already in hist as
  -- the trailing entry).
  local last_user
  for i = #hist, 1, -1 do
    if hist[i].role == "user" then last_user = hist[i].content; break end
  end
  if not last_user or last_user == "" then return false end
  local lo = last_user:lower()
  local function has_word(word)
    return lo:find("%f[%w]" .. word .. "%f[%W]") ~= nil
  end
  local function verb_near_noun(verbs, nouns)
    for verb in verbs:gmatch("[^|]+") do
      local pos = 1
      while true do
        local vstart, vend = lo:find("%f[%w]" .. verb .. "%f[%W]", pos)
        if not vstart then break end
        -- Look both directions within ~60 chars so "last script, change..."
        -- is treated the same as "change the last script".
        local window = lo:sub(math.max(1, vstart - 60), vend + 60)
        for noun in nouns:gmatch("[^|]+") do
          if window:find("%f[%w]" .. noun .. "%f[%W]") then
            return verb .. "-" .. noun
          end
        end
        pos = vend + 1
      end
    end
    return nil
  end
  local function direct_ref(verbs, nouns)
    for verb in verbs:gmatch("[^|]+") do
      local pos = 1
      while true do
        local _vstart, vend = lo:find("%f[%w]" .. verb .. "%f[%W]", pos)
        if not vend then break end
        -- Tight direct-reference window so "make it brighter" hits but
        -- "make a script that..." does not.
        local window = lo:sub(vend + 1, vend + 18)
        for noun in nouns:gmatch("[^|]+") do
          if window:find("^%W*%f[%w]" .. noun .. "%f[%W]") then
            return verb .. "-" .. noun
          end
        end
        pos = vend + 1
      end
    end
    return nil
  end

  local match = verb_near_noun(
    Net._MODIFY_PRIOR_VERBS, Net._MODIFY_PRIOR_REF_NOUNS)
  if match then return true, match end
  match = verb_near_noun(
    Net._MODIFY_PRIOR_CODE_VERBS, Net._MODIFY_PRIOR_CODE_NOUNS)
  if match then return true, match end
  match = direct_ref(
    Net._MODIFY_PRIOR_DIRECT_VERBS, Net._MODIFY_PRIOR_DIRECT_NOUNS)
  if match then return true, match end

  -- Common natural-language correction pattern with no explicit "that/it":
  -- "actually I want EQ before the comp", "instead, put delay after..."
  -- These false positives only skip savings for the current send.
  if (has_word("actually") or has_word("instead"))
     and (has_word("before") or has_word("after")
          or has_word("without") or has_word("instead")) then
    return true, has_word("actually") and "actually-edit" or "instead-edit"
  end
  return false
end

-- Apply compaction to the trimmed history slice. Default no-op (returns
-- hist unchanged); only fires when the compact_history ExtState flag
-- is on. T-1 (the last assistant row) is always preserved verbatim;
-- T-2 and older eligible rows are replaced with their compact_summary.
function Net._maybe_compact_history(hist)
  if reaper.GetExtState(CFG.EXT_NS, "compact_history") ~= "1" then
    return hist
  end
  -- modify-prior detector short-circuits compaction entirely. False
  -- positives only cost the savings for this one turn.
  local is_modify, mp_match = Net._is_modify_prior_followup(hist)
  if is_modify then
    if prefs.debug_logging then
      Log.line("HISTORY-COMPACT",
        "skipped (modify-prior follow-up: " .. tostring(mp_match) .. ")")
    end
    return hist
  end
  -- Find the last assistant index in hist -- it stays verbatim.
  local last_asst_idx = nil
  for i = #hist, 1, -1 do
    if hist[i].role == "assistant" then last_asst_idx = i; break end
  end
  local out = {}
  local compacted, kept_asst = 0, 0
  local skip_reasons = {}
  for i, row in ipairs(hist) do
    if row.role == "assistant"
       and i ~= last_asst_idx
       and row.compact_eligible
       and row.compact_summary
       and (#(row.content or "") - #(row.compact_summary or ""))
           >= Net._COMPACT_MIN_SAVINGS then
      out[#out+1] = { role = "assistant", content = row.compact_summary }
      compacted = compacted + 1
    else
      out[#out+1] = row
      if row.role == "assistant" then
        kept_asst = kept_asst + 1
        if i ~= last_asst_idx then
          local r = row.compact_skip_reason
          if row.compact_eligible
             and row.compact_summary
             and (#(row.content or "") - #(row.compact_summary or ""))
                 < Net._COMPACT_MIN_SAVINGS then
            r = "too_small"
          end
          r = r or "unknown"
          skip_reasons[r] = (skip_reasons[r] or 0) + 1
        end
      end
    end
  end
  if prefs.debug_logging then
    local before, after = 0, 0
    for _, r in ipairs(hist) do before = before + #(r.content or "") end
    for _, r in ipairs(out)  do after  = after  + #(r.content or "") end
    local skip_str = "none"
    if next(skip_reasons) then
      local parts = {}
      for r, c in pairs(skip_reasons) do parts[#parts+1] = r .. "(" .. c .. ")" end
      skip_str = tbl_concat(parts, ",")
    end
    local delta = after - before
    Log.line("HISTORY-COMPACT", string.format(
      "before=%dB after=%dB delta=%+dB compacted=%d kept=%d skipped=%s",
      before, after, delta, compacted, kept_asst, skip_str))
  end
  return out
end

-- =============================================================================
-- Net.fire_curl
-- =============================================================================
-- Writes the JSON body to a temp file and launches curl asynchronously.
-- Provider-aware: builds the endpoint URL, auth headers, and extra headers
-- dynamically from the active PROVIDERS entry.
--
-- Auth strategies:
--   header      (Claude, OpenAI, Gemini): key sent via -H @file so it never
--               appears on the command line. The auth file is cleaned up after
--               curl. Each provider specifies its own auth_header name.
--
-- Both platforms use an async pattern: curl runs in the background, writes
-- its response to tmp.out, stderr to tmp.err, and echoes its exit code to tmp.exit.
-- Net.try_finish_curl() polls both files each frame to detect completion.
--
-- Windows: the curl command is inlined directly into a PowerShell -Command
--   string launched via Start-Process -WindowStyle Hidden.
-- macOS/Linux: trailing "&" backgrounds the shell pipeline.
-- opts (optional table) lets the caller request a non-standard request shape:
--   opts.method            -- "GET" to send an empty GET instead of POST
--   opts.endpoint_override -- full URL to use instead of the provider's endpoint
-- Both are used by the custom-LLM connection test, which hits GET /v1/models
-- so no inference runs on the server. When method=="GET" we skip the body
-- write, the content-type header, and the -d flag; nil/POST behaves as before.
-- Restore the trailing user-history entry from S.pending_orig_prompt,
-- shedding any sticky-bucket / internal-retry-note content that was baked
-- in mid-turn. Mirrors the success-path cleanup in Net.process_response;
-- centralised so the per-turn-call-cap abort path can reuse the same
-- semantics without leaving an internal note as the user's last turn.
function Net._restore_pending_user_history()
  if S.pending_orig_prompt
     and #S.history > 0
     and S.history[#S.history].role == "user" then
    S.history[#S.history].content = "USER REQUEST:\n" .. S.pending_orig_prompt
  end
end

-- Retry prompts sometimes fire on terse follow-ups ("1", "yes", "use built
-- in", "snap them"), where S.pending_orig_prompt alone is not enough context.
-- Expand those into a compact task-context block so hidden validator retries
-- don't make the model reconstruct the user's real intent from luck.
function Net._retry_trim_text(text)
  return tostring(text or "")
    :gsub("\r\n", "\n")
    :gsub("^%s+", "")
    :gsub("%s+$", "")
end

function Net._retry_extract_user_request(content)
  local text = tostring(content or "")
  if text:find("INTERNAL NOTE TO THE MODEL", 1, true) then return "" end
  local marker, last = "USER REQUEST:", nil
  local pos = 1
  while true do
    local s, e = text:find(marker, pos, true)
    if not s then break end
    last = e + 1
    pos = e + 1
  end
  if last then text = text:sub(last) end
  return Net._retry_trim_text(text)
end

function Net._retry_prompt_needs_context(text)
  local t = Net._retry_trim_text(text)
  local lo = t:lower()
  if lo == "" then return false end
  if #lo <= 24 then return true end
  if lo:match("^%d+[%.)]?$") then return true end
  if lo:find("%f[%w]option%f[%W]") then return true end
  if lo:find("%f[%w]same%f[%W]") then return true end
  if lo:find("%f[%w]previous%f[%W]") then return true end
  if lo:find("%f[%w]last%f[%W]") then return true end
  if lo:find("%f[%w]that%f[%W]") then return true end
  if lo:find("%f[%w]this%f[%W]") then return true end
  if lo:find("%f[%w]them%f[%W]") then return true end
  if lo:find("%f[%w]those%f[%W]") then return true end
  if lo:find("built in", 1, true) or lo:find("built%-in") then return true end
  return false
end

function Net._retry_request_is_substantive(text, current)
  local t = Net._retry_trim_text(text)
  if t == "" or t == current then return false end
  if #t <= 12 then return false end
  if t:match("^[%d%p%s]+$") then return false end
  return true
end

function Net.retry_user_request_context()
  local current = Net._retry_trim_text(S.pending_orig_prompt or "")
  if not Net._retry_prompt_needs_context(current) then return current end
  local prior_rev = {}
  for i = #S.history, 1, -1 do
    local row = S.history[i]
    if row and row.role == "user" then
      local req = Net._retry_extract_user_request(row.content)
      if Net._retry_request_is_substantive(req, current) then
        prior_rev[#prior_rev + 1] = req
        if #prior_rev >= 2 then break end
      end
    end
  end
  if #prior_rev == 0 then return current end
  local prior = {}
  for i = #prior_rev, 1, -1 do
    local req = prior_rev[i]
    if #req > 700 then req = req:sub(1, 697) .. "..." end
    prior[#prior + 1] = req
  end
  return "Prior task context:\n" .. tbl_concat(prior, "\n\n")
    .. "\n\nLatest user reply / option selection:\n" .. current
end

-- Tier-aware copy for the per-turn-call-cap abort. Small / local models
-- loop the most, so the message nudges users toward the next tier up;
-- flagship models on the cap usually mean a genuinely confused turn,
-- so the suggestion is to start fresh and report it if it repeats.
function Net._call_cap_message()
  local p   = PROVIDERS.active() or {}
  local m   = MODELS[prefs.model_idx] or MODELS[1] or {}
  local mid = (m.id or m.name or ""):lower()
  local pid = p.id or ""
  -- Match a marker only at a word boundary so substrings inside larger
  -- names don't trigger -- e.g. "gemini-3.1-pro-preview" must NOT hit
  -- "mini", and "anthropic-flash-prototype" must hit "flash" cleanly.
  -- %f[%a] = position where prev char is non-letter and next is letter
  -- (start of a word); %f[%A] is the inverse (end of a word).
  local function tag(kw)
    return mid:find("%f[%a]" .. kw .. "%f[%A]") ~= nil
  end
  local hint
  if pid == "anthropic" and tag("haiku") then
    hint = "Try Sonnet 4.6 or Opus 4.7 for this request."
  elseif pid == "google" and (tag("flash") or tag("nano")) then
    hint = "Try Gemini 3.1 Pro for this request."
  elseif pid == "openai" and tag("mini") then
    hint = "Try a non-mini OpenAI model for this request."
  elseif p.is_custom
      or tag("haiku") or tag("flash") or tag("mini")
      or tag("nano")  or tag("gemma") or tag("llama")
      or tag("phi") then
    hint = "This often happens with smaller or local models -- try a "
        .. "higher-tier model."
  else
    hint = "Unusual on a flagship model. Try starting a new chat or "
        .. "rephrasing. If it repeats, please use Help -> Report an Issue."
  end
  return ("Stopped after %d API calls in one turn to avoid runaway cost. %s")
         :format(CFG.MAX_CALLS_PER_TURN, hint)
end

function Net._ensure_request_start_time()
  -- Hidden same-turn retries fire curl directly instead of re-entering
  -- Net.send_to_api(), so they must preserve the original wall-clock anchor
  -- for the visible "Elapsed" timer. If an older path already lost it, fall
  -- back to the current request clock rather than showing a frozen 0:00.
  if not S.request_start_time then
    S.request_start_time = S.send_time or time_precise()
  end
end

function Net.try_local_read_answer(user_text, attachments, probe_turn)
  if attachments then return false end
  if not CTX or not CTX.local_read_answer then return false end
  local answer = CTX.local_read_answer(user_text, S.pending_project)
  if not answer then return false end

  S.history[#S.history + 1] = {
    role = "user",
    content = "USER REQUEST:\n" .. tostring(user_text or ""),
  }
  S.history[#S.history + 1] = {
    role = "assistant",
    content = answer,
  }

  S.display_messages[#S.display_messages + 1] = {
    role = "user",
    content = tostring(user_text or ""),
    ctx_label = "local_read",
    model_label = "Local",
    provider_id = "local",
    from_card = S.from_card or nil,
  }
  S.display_messages[#S.display_messages + 1] = {
    role = "assistant",
    content = answer,
    provider_id = "local",
    model_label = "Local",
    local_answer = true,
  }
  S.from_card = false
  if #S.display_messages > CFG.MAX_DISPLAY_MSGS then
    if Diag.uploader_enabled and Diag.capture_current_chat then
      Diag.capture_current_chat()
    end
    while #S.display_messages > CFG.MAX_DISPLAY_MSGS do
      tbl_remove(S.display_messages, 1)
    end
    S.wrap_cache = {}
  end

  S.status = "idle"
  S.request_start_time = nil
  S.send_time = nil
  S.pending_code = nil
  S.pending_display_idx = nil
  S.pending_orig_prompt = nil
  S.pending_typed_action_expected = false
  S.pending_typed_action_response_format = false
  S.pending_typed_action_profile = nil
  S.pending_project = nil
  S.pending_snapshot = nil
  S.pending_attachments = nil
  S._fx_cache_events = nil
  S.scroll_to_bottom = true
  Probe.end_turn(probe_turn, "success")
  S.probe_turn = nil
  return true
end

function Net._try_escalate_typed_actions(reason_code, detail)
  local profile =
    Code.typed_actions_model_profile_by_key(S.pending_typed_action_profile)
  local fallback = type(profile) == "table" and profile.fallback or nil
  if type(fallback) ~= "table" then return false end
  if S.typed_action_escalation_used then return false end

  local original_p = PROVIDERS.active() or {}
  local original_m = MODELS[prefs.model_idx] or MODELS[1] or {}
  local original_thinking_override_idx = S.thinking_override_idx
  local ok, switch_reason =
    PROVIDERS.switch_to_model(fallback.provider_id, fallback.model_id)
  if not ok then
    Log.line("TYPED-ACTION-ESCALATION",
      "fallback model unavailable: " .. tostring(switch_reason or "unknown"))
    return false
  end

  local p = PROVIDERS.active() or {}
  local m = MODELS[prefs.model_idx] or MODELS[1] or {}
  local response_format = p.id == "openai"
  local fallback_profile = Code.typed_actions_model_profile(p.id, m.id)
  local fallback_model_id = m.id or fallback.model_id or "?"
  if fallback.thinking_value and p.thinking_levels then
    local found_thinking_idx
    for i, tl in ipairs(p.thinking_levels) do
      if tostring(tl.value or "") == tostring(fallback.thinking_value) then
        found_thinking_idx = i
        break
      end
    end
    if found_thinking_idx then
      S.thinking_override_idx = found_thinking_idx
    else
      Log.line("TYPED-ACTION-ESCALATION",
        "fallback thinking level unavailable: "
        .. tostring(fallback.thinking_value))
    end
  end
  S.pending_typed_action_response_format = response_format
  S.pending_typed_action_profile =
    type(fallback_profile) == "table" and fallback_profile.key or nil
  S.typed_action_retry_offset =
    (S.typed_action_retry_offset or 0)
    + (S.typed_action_format_validator_retries or 0)
    + (S.typed_action_schema_validator_retries or 0)
    + (S.typed_action_semantic_validator_retries or 0)
  S.typed_action_format_validator_retries = 0
  S.typed_action_schema_validator_retries = 0
  S.typed_action_semantic_validator_retries = 0
  S.typed_action_escalation_used = true
  S.typed_action_escalation_count =
    (S.typed_action_escalation_count or 0) + 1
  S.typed_action_escalation_model =
    tostring(p.id or fallback.provider_id or "") .. "/"
    .. tostring(fallback_model_id)
  S.typed_action_escalation_restore = {
    provider_id = original_p.id,
    model_id = original_m.id,
    fallback_provider_id = p.id or fallback.provider_id,
    fallback_model_id = fallback_model_id,
    thinking_override_idx = original_thinking_override_idx,
  }
  Probe.add_validator_retry(S.probe_turn, "typed_action_escalation")

  Log.line("TYPED-ACTION-ESCALATION",
    "escalating typed-action turn to "
    .. tostring(S.typed_action_escalation_model)
    .. " after " .. tostring(reason_code or "typed_action_failure")
    .. " (" .. tostring(detail or "") .. ")")

  local retry_contract =
    Code.typed_actions_prompt_contract(S.pending_orig_prompt or "",
      {
        force_enabled = true,
        response_format = response_format,
        profile = fallback_profile,
      }) or ""
  local reemit_hint = response_format
    and "the raw JSON object required by the active response schema"
    or "a single ```reaassist-actions fenced JSON object"
  local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
    .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: A weaker model could "
    .. "not produce a safe typed-action plan for this request. Reason: "
    .. tostring(reason_code or "typed_action_failure")
    .. ". Details: " .. tostring(detail or "") .. ". Re-solve the original "
    .. "request from scratch using the active typed-action contract. Emit "
    .. "the complete plan as " .. reemit_hint .. ". Do not copy any prior "
    .. "bad JSON. Do not write Lua, ReaScript, JSFX, prose, apologies, or "
    .. "omit any actions.)\n\n"
    .. (retry_contract ~= "" and (retry_contract .. "\n\n") or "")
    .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
  if #S.history > 0 and S.history[#S.history].role == "assistant" then
    S.history[#S.history] = nil
  end
  if #S.history > 0 and S.history[#S.history].role == "user" then
    S.history[#S.history] = nil
  end
  S.history[#S.history + 1] = { role = "user", content = history_content }

  if S.pending_display_idx
     and S.display_messages[S.pending_display_idx] then
    local dmsg = S.display_messages[S.pending_display_idx]
    local existing = dmsg.ctx_label or ""
    if not existing:find("typed_action_escalated", 1, true) then
      dmsg.ctx_label = existing ~= ""
        and (existing .. " + typed_action_escalated")
        or "typed_action_escalated"
    end
  end

  if prefs.include_snapshot then
    S.pending_project  = _resolve_pending_project()
    S.pending_snapshot = CTX.build_snapshot(S.pending_project,
      S.pending_jsfx_intent and { minimal_tracks = true } or nil)
  end
  S.status = "waiting"
  Net._ensure_request_start_time()
  Code.safe_write(tmp.out, "")
  local fired, fire_reason = Net.fire_curl(Net.build_body(Net.trimmed_history(),
    S.pending_snapshot, S.pending_attachments))
  if not fired then
    Net._restore_typed_action_escalation_model()
    if fire_reason ~= "call_cap_exceeded" then
      Log.add_error("Typed-action fallback model request did not go through. "
        .. "Please resend the last message.")
    end
  end
  S.scroll_to_bottom = true
  return true
end

function Net._restore_typed_action_escalation_model()
  local restore = S.typed_action_escalation_restore
  if type(restore) ~= "table" then return false end
  S.typed_action_escalation_restore = nil
  S.thinking_override_idx = restore.thinking_override_idx

  if not restore.provider_id or not restore.model_id then return false end

  local p = PROVIDERS.active() or {}
  local m = MODELS[prefs.model_idx] or MODELS[1] or {}
  if tostring(p.id or "") ~= tostring(restore.fallback_provider_id or "")
     or tostring(m.id or "") ~= tostring(restore.fallback_model_id or "") then
    Log.line("TYPED-ACTION-ESCALATION",
      "not restoring original model because active model changed from "
      .. tostring(restore.fallback_provider_id or "") .. "/"
      .. tostring(restore.fallback_model_id or "") .. " to "
      .. tostring(p.id or "") .. "/" .. tostring(m.id or ""))
    return false
  end

  local ok, reason = PROVIDERS.switch_to_model(restore.provider_id,
    restore.model_id)
  if not ok then
    Log.line("TYPED-ACTION-ESCALATION",
      "could not restore original model "
      .. tostring(restore.provider_id) .. "/" .. tostring(restore.model_id)
      .. ": " .. tostring(reason or "unknown"))
    return false
  end

  Log.line("TYPED-ACTION-ESCALATION",
    "restored original model after hidden fallback rescue: "
    .. tostring(restore.provider_id) .. "/" .. tostring(restore.model_id))
  return true
end

function Net._read_file_limited(path, cap)
  if not path or path == "" then return "", 0, false end
  local f = io.open(path, "rb")
  if not f then return "", 0, false end
  cap = cap or 4096
  local data = f:read(cap + 1) or ""
  local size = f:seek("end") or #data
  f:close()
  local truncated = #data > cap
  if truncated then data = data:sub(1, cap) end
  return data, size, truncated
end

function Net._debug_scrub(s)
  if not s or s == "" then return s end
  if type(Diag) == "table" and type(Diag.redact_log) == "function" then
    local ok, redacted = pcall(Diag.redact_log, s)
    if ok and type(redacted) == "string" then return redacted end
  end
  return Log.scrub_url_secrets(s)
end

function Net._debug_endpoint(p, endpoint)
  if not endpoint or endpoint == "" then return nil end
  if p and p.is_custom then return "(custom endpoint redacted)" end
  return Net._debug_scrub(endpoint)
end

function Net._curl_exit_meaning(code)
  local meanings = {
    [5]  = "could not resolve proxy",
    [6]  = "could not resolve host",
    [7]  = "failed to connect",
    [18] = "partial file / transfer closed early",
    [23] = "local write error",
    [28] = "operation timed out",
    [35] = "TLS/SSL connect error",
    [52] = "empty reply from server",
    [56] = "receive failure",
    [60] = "certificate verification failed",
    [77] = "certificate file problem",
    [92] = "HTTP/2 stream error",
  }
  return meanings[tonumber(code)] or "unmapped curl error"
end

function Net._curl_failure_debug(exit_code, detail, failure_kind)
  local dbg = {}
  if type(S.curl_debug) == "table" then
    for k, v in pairs(S.curl_debug) do dbg[k] = v end
  end
  dbg.failure_kind = failure_kind or "curl_exit"
  if exit_code ~= nil then
    dbg.exit_code = exit_code
    dbg.exit_meaning = Net._curl_exit_meaning(exit_code)
  end
  dbg.user_message = detail
  dbg.failed_at_utc = os.date("!%Y-%m-%dT%H:%M:%SZ")
  dbg.api_calls_this_turn = S.api_calls_this_turn
  dbg.retry_count = S.retry_count
  dbg.retry_max = S.retry_max
  dbg.gemini_tier_pending = S.gemini_tier_pending or nil
  dbg.key_test_pending = S.key_test_pending or nil
  if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
    local dmsg = S.display_messages[S.pending_display_idx]
    dbg.display_context = dmsg.ctx_label
    dbg.display_model = dmsg.model_label
    dbg.display_thinking = dmsg.thinking_label
  end

  local stderr, stderr_size, stderr_truncated =
    Net._read_file_limited(tmp.err, 4096)
  if stderr and stderr ~= "" then
    dbg.stderr = Net._debug_scrub(stderr)
    dbg.stderr_bytes = stderr_size
    dbg.stderr_truncated = stderr_truncated or nil
  else
    dbg.stderr_bytes = stderr_size or 0
  end

  local body_head, body_size, body_truncated =
    Net._read_file_limited(tmp.out, 2048)
  dbg.response_bytes = body_size or 0
  if body_head and body_head ~= "" then
    dbg.response_head = Net._debug_scrub(body_head)
    dbg.response_head_truncated = body_truncated or nil
  end
  return dbg
end

function Net.fire_curl(body, opts)
  -- TCP/TLS handshake timeout (seconds). Default 10 for cloud providers;
  -- per-record override for customs set below.
  local connect_timeout = 10
  -- Guard against double-send. Return a reason so callers can distinguish
  -- "another request in flight" (transient, deferrable) from genuine
  -- failures like disk/IO errors. Plain `if not fire_curl()` callers stay
  -- compatible -- the second return value is ignored unless inspected.
  if S.curl_pid then return false, "in_flight" end

  local method   = (opts and opts.method) or "POST"
  local is_get   = (method == "GET")

  -- A "turn POST" is a POST tied to the user's currently-pending display
  -- message: the initial send and every silent retry / context fetch /
  -- beta-fallback that fires before the turn settles. NOT a turn POST:
  -- GETs (auth probes, /v1/models scans), and the Settings-page POSTs
  -- from Net.fire_key_test / Net.fire_gemini_tier_test, which don't have
  -- a pending display message attached. The per-turn cap and per-message
  -- counter both gate on this same predicate so they stay in sync.
  local is_turn_post = not is_get
                       and S.pending_orig_prompt ~= nil
                       and S.pending_display_idx
                       and S.display_messages[S.pending_display_idx] ~= nil

  -- Per-turn call cap. Catches runaway loops (small / local model
  -- thrashing on context_needed or validator retries) before they rack
  -- up real cost. Aborts the turn cleanly: logs ONE user-visible error,
  -- restores the user's history entry from any internal retry note,
  -- ends the Probe turn, and returns a distinct reason so the 13 retry
  -- call sites can suppress their generic "did not go through" message.
  if is_turn_post
     and (S.api_calls_this_turn or 0) >= CFG.MAX_CALLS_PER_TURN then
    Log.add_error(Net._call_cap_message())
    Net._restore_pending_user_history()
    Net._restore_typed_action_escalation_model()
    S.status               = "idle"
    S.pending_display_idx  = nil
    S.pending_orig_prompt  = nil
    S.pending_typed_action_expected = false
    S.pending_typed_action_response_format = false
    S.pending_typed_action_profile = nil
    S.request_start_time   = nil
    S.retry_count          = 0
    S.retry_max            = CFG.MAX_RETRIES
    S.retry_scheduled      = false
    S.retry_saved_body     = nil
    if S.probe_turn then Probe.end_turn(S.probe_turn, "call_cap") end
    return false, "call_cap_exceeded"
  end

  -- Per-message API-call counter. Incremented for every POST that's tied
  -- to the user's pending display message: the initial send AND any
  -- silent retries (docs-gate auto-fetch, beta-header fallback, cache-
  -- expired refresh, fx-inspect intra-turn fetches). Surfaced in the
  -- Details box so the user can see when an "invisible" retry doubled
  -- the work -- the cost / time fields only reflect the LAST request,
  -- so without this counter the user has no indication that the visible
  -- numbers are missing one or more earlier round-trips. GET is a probe
  -- (auth check, /v1/models scan) and never a user-message API call, so
  -- it stays out of the count.
  if is_turn_post then
    local dmsg = S.display_messages[S.pending_display_idx]
    dmsg.api_calls = (dmsg.api_calls or 0) + 1
    S.api_calls_this_turn = (S.api_calls_this_turn or 0) + 1
    if S.probe_turn then
      S.probe_turn.posts_fired = (S.probe_turn.posts_fired or 0) + 1
    end
  end

  if not is_get then
    if not Code.safe_write(tmp.body, body) then return false, "io_error" end
  end

  local p = PROVIDERS.active()

  Log.request(p.label, is_get and ("[GET " .. (opts.endpoint_override or "?") .. "]") or body)

  -- Local LLMs (custom OpenAI-compatible endpoints) need a much longer timeout
  -- than cloud providers: prompt processing alone for a 15K-token context can
  -- take 1-2 minutes on consumer hardware before any tokens stream back. Cloud
  -- providers respond in seconds, so the snappy 30s ceiling stays for them.
  -- Custom providers expose a user-configurable per-provider timeout (set on
  -- the API Keys page); fall back to the 10-minute default if missing.
  local curl_timeout = (p.is_custom and (tonumber(p.request_timeout) or 600))
                       or CFG.CURL_TIMEOUT

  -- Custom-provider TCP/TLS handshake override. Cloud providers keep the
  -- fixed 10s default because every hosted endpoint is consistently reachable
  -- in under a second; customs can be behind slow CDNs or local servers that
  -- need more breathing room, so we expose a per-record knob.
  if p.is_custom and tonumber(p.connect_timeout) then
    connect_timeout = tonumber(p.connect_timeout)
  end

  -- Key-test override for custom providers. The curl --max-time is capped to
  -- the user-configured "Connection test timeout" (default 30s). Prevents a
  -- stalled/unresponsive model from blocking the row-test queue for the full
  -- request timeout (up to 1 hour). Also shortens the connect-timeout so a
  -- test against a dead port fails quickly instead of waiting the full
  -- per-provider handshake budget.
  if S.key_test_pending and p.is_custom then
    curl_timeout    = tonumber(S.key_test_custom_timeout)
                      or CUSTOM_DEFAULT_TEST_TIMEOUT
    connect_timeout = 3
  end

  -- --insecure: skip TLS verification when the custom provider has it set.
  -- Only ever applied to custom providers (cloud providers always validate).
  -- Emitted as a standalone flag in both Windows and POSIX branches below.
  local insecure_flag = (p.is_custom and p.allow_insecure) and " --insecure" or ""

  -- Build the endpoint URL.
  local endpoint
  if opts and opts.endpoint_override then
    endpoint = opts.endpoint_override
  elseif p.endpoint_tpl then
    endpoint = str_format(p.endpoint_tpl, MODELS.active_id())
  else
    endpoint = p.endpoint
  end
  local active_model = MODELS[prefs.model_idx] or MODELS[1] or {}
  S.curl_debug = {
    launched_at_utc = os.date("!%Y-%m-%dT%H:%M:%SZ"),
    method = method,
    provider_id = p.id,
    provider_label = p.label,
    model_id = active_model.id or MODELS.active_id(),
    model_label = active_model.label,
    endpoint = Net._debug_endpoint(p, endpoint),
    connect_timeout_s = connect_timeout,
    curl_timeout_s = curl_timeout,
    request_body_bytes = (not is_get and type(body) == "string") and #body or 0,
    is_turn_post = is_turn_post and true or false,
    provider_idx = prefs.provider_idx,
    model_idx = prefs.model_idx,
  }
  -- Write the auth header file (header-based auth only). Custom providers may
  -- have no key at all -- in that case skip the auth file so we don't send a
  -- bare "Authorization: Bearer " header that some servers reject.
  local use_auth_file = (p.auth_style == "header")
    and S.api_key ~= nil and S.api_key ~= ""
  if use_auth_file then
    local auth_value = (p.auth_prefix or "") .. S.api_key
    if not Code.safe_write(tmp.auth, p.auth_header .. ": " .. auth_value) then return false, "io_error" end
  end

  -- Clear any stale exit code / pid / response file from a previous request.
  -- The pid file is rewritten by the launched process; clearing first ensures
  -- Net.kill_curl never sees a stale PID from a finished request. tmp.out
  -- MUST also be cleared -- Net.try_finish_curl reads it every poll tick and
  -- only short-circuits on empty (<2 bytes); leaving the previous response's
  -- bytes in place makes the poller latch onto the prior response (which
  -- will even JSON-parse) before the new curl has had a chance to overwrite
  -- it, producing a stale instant "response".
  os.remove(tmp.exit)
  os.remove(tmp.err)
  os.remove(tmp.pid)
  Code.safe_write(tmp.out, "")
  Code.safe_write(tmp.err, "")

  -- Build the list of extra header flags. Skip the Anthropic extended-cache
  -- beta header if it has been rejected earlier this session -- paired with
  -- the 5-minute fallback in build_body_anthropic.
  local extra_h_parts = {}
  for _, h in ipairs(p.extra_headers) do
    if not (S.anthropic_beta_disabled
            and p.id == "anthropic"
            and h:find("extended%-cache%-ttl", 1, false)) then
      extra_h_parts[#extra_h_parts+1] = h
    end
  end

  if RA.IS_WINDOWS then
    -- Escape paths for embedding inside PowerShell single-quoted strings.
    local function ps_escape(path) return path:gsub("'", "''") end

    -- Build header flags for cmd.exe (triple-quoted for PowerShell).
    local h_flags = ""
    if use_auth_file then
      h_flags = h_flags .. ' -H @"""' .. tmp.auth .. '"""'
    end
    for _, h in ipairs(extra_h_parts) do
      h_flags = h_flags .. ' -H """' .. h .. '"""'
    end
    if not is_get then
      h_flags = h_flags .. ' -H """content-type: application/json"""'
    end

    -- Cleanup: delete auth file only if we wrote one.
    local cleanup = use_auth_file
      and (' & del """' .. tmp.auth .. '"""') or ""

    local body_flags = is_get and ""
      or (' -d @"""' .. tmp.body .. '"""')
    local cmd_line = str_format(
      'curl -sS%s --connect-timeout %d --max-time %d'
      .. ' -X %s """%s"""'
      .. '%s'
      .. '%s -o """%s""" 2> """%s"""'
      .. ' & call echo ^%%errorlevel^%% > """%s"""'
      .. '%s',
      insecure_flag,
      connect_timeout, curl_timeout,
      method, endpoint,
      h_flags,
      body_flags, tmp.out, tmp.err,
      tmp.exit,
      cleanup)

    -- Use Start-Process -PassThru so PowerShell hands us back the launched
    -- cmd.exe process object. We persist its PID to tmp.pid so Net.kill_curl
    -- can later run `taskkill /F /T /PID <pid>` to terminate the entire
    -- cmd+curl process tree on Cancel.
    local ps_cmd = str_format(
      'powershell -NoProfile -WindowStyle Hidden'
      .. ' -Command "$p = Start-Process cmd -ArgumentList \'/c %s\''
      .. ' -WindowStyle Hidden -PassThru;'
      .. ' $p.Id | Out-File -Encoding ASCII -FilePath \'%s\'"',
      ps_escape(cmd_line), ps_escape(tmp.pid))
    reaper.ExecProcess(ps_cmd, 5000)
  else
    -- macOS / Linux: launch curl in the background via shell.
    local function sq(path)
      return "'" .. path:gsub("'", "'\\''") .. "'"
    end

    -- Build header flags for shell. Each header is wrapped with sq() so
    -- $VAR, backticks, "\", and " in a custom provider header are treated
    -- as literal bytes by the shell rather than expanded or parsed. The
    -- header_is_safe() validator already rejects newlines and nulls; sq()
    -- handles every other shell-meaningful character.
    local h_flags = ""
    if use_auth_file then
      h_flags = h_flags .. ' -H @' .. sq(tmp.auth)
    end
    for _, h in ipairs(extra_h_parts) do
      h_flags = h_flags .. ' -H ' .. sq(h)
    end
    if not is_get then
      h_flags = h_flags .. ' -H ' .. sq("content-type: application/json")
    end

    local cleanup = use_auth_file
      and (' ; rm -f ' .. sq(tmp.auth)) or ""

    local body_flags = is_get and "" or (' -d @' .. sq(tmp.body))

    -- Wrap entire pipeline in a subshell so & backgrounds curl+echo together.
    -- Background curl inside the subshell so we can capture its PID via $!,
    -- write it to tmp.pid (so Net.kill_curl can `kill -9 <pid>` on Cancel),
    -- then `wait` for curl and record its real exit code in tmp.exit.
    local unix_curl = str_format(
      '(curl -sS%s --connect-timeout %d --max-time %d'
      .. ' -X %s %s'
      .. '%s'
      .. '%s -o %s 2> %s & CURL_PID=$! ; echo $CURL_PID > %s ; wait $CURL_PID ; echo $? > %s%s) &',
      insecure_flag,
      connect_timeout, curl_timeout,
      method, sq(endpoint),
      h_flags,
      body_flags, sq(tmp.out), sq(tmp.err),
      sq(tmp.pid),
      sq(tmp.exit),
      cleanup)
    os.execute(unix_curl)
  end

  S.curl_pid              = true
  S.curl_exited_clean     = false  -- reset partial-read guard for new request
  S.kill_pending          = false  -- a fresh request voids any stale Cancel watchdog
  S.send_time             = time_precise()
  S.timeout_extensions    = 0      -- watchdog clock just restarted; prior
                                   -- "Extend by Ns" clicks no longer apply
  S.retry_saved_body      = body  -- saved so a 529/overload retry can re-send
  S.pending_provider_idx  = prefs.provider_idx  -- snapshot for response parsing
  S.pending_model_idx     = prefs.model_idx
  -- Phase 1 instrumentation: curl_wait phase begins here. The curl
  -- process is now running; we are waiting for its response. The
  -- corresponding mark_phase_end fires inside Net.try_finish_curl
  -- just before JSON.decode parses the response body. This wraps
  -- every fire_curl success path, so multi-request turns
  -- (context-needed re-fires, validator retries) accumulate
  -- correctly via mark_phase_end's additive timing.
  Probe.mark_phase_start(S.probe_turn, "curl_wait")
  return true
end

-- =============================================================================
-- Net.kill_curl
-- =============================================================================
-- Forcibly terminates the in-flight curl request launched by Net.fire_curl.
-- Reads the OS PID written to tmp.pid by the launcher and runs the platform's
-- kill command. Without this, pressing Cancel only resets ReaAssist's state --
-- the underlying curl process keeps running, holding bandwidth and possibly
-- writing a stale response into tmp.out that contaminates the next request.
--
-- Windows: PowerShell wrote cmd.exe's PID; taskkill /T tears down the entire
-- cmd+curl process tree.
-- Unix: the shell wrapper wrote curl's PID directly; kill -9 ends it, which
-- causes the parent subshell's `wait` to return non-zero into tmp.exit.
function Net.kill_curl()
  -- Tier-test path doesn't capture a PID (no Start-Process -PassThru / $!),
  -- so there is no process to kill. The tier-test curl runs to completion
  -- under its own --connect-timeout 10 / --max-time 30 budget. Bail early
  -- and clear the tier flag so the post-Cancel state stays consistent.
  if S.gemini_tier_pending then
    Log.line("CANCEL", "tier test in flight; nothing to kill (no PID captured)")
    S.gemini_tier_pending = false
    return
  end
  local f = io.open(tmp.pid, "r")
  if not f then
    -- The launcher (PowerShell on Windows, sh on Unix) hasn't written the pid
    -- file yet -- there is a several-hundred-ms gap between Start-Process and
    -- Out-File on Windows in particular. Arm the deferred-kill watchdog so
    -- the main loop keeps retrying until either the pid file shows up or the
    -- deadline elapses; without this, a rapid Send -> Cancel leaves the
    -- background curl alive holding bandwidth and writing into tmp.out.
    S.kill_pending       = true
    S.kill_pending_until = reaper.time_precise() + 2.0
    return
  end
  local pid_text = f:read("*a") or ""
  f:close()
  local pid = pid_text:match("(%d+)")
  if not pid then
    -- File exists but is still mid-write (very rare but possible). Same fix.
    S.kill_pending       = true
    S.kill_pending_until = reaper.time_precise() + 2.0
    return
  end
  if RA.IS_WINDOWS then
    -- /F = force, /T = include child process tree.
    reaper.ExecProcess('cmd /c taskkill /F /T /PID ' .. pid, 2000)
  else
    reaper.ExecProcess('/bin/sh -c "kill -9 ' .. pid .. ' 2>/dev/null"', 2000)
  end
  -- Remove the pid file so a stray Cancel after this call doesn't try to kill
  -- a now-finished or PID-recycled process.
  os.remove(tmp.pid)
  S.kill_pending = false
end

-- =============================================================================
-- Net.try_finish_kill_pending
-- =============================================================================
-- Polled from the main loop while S.kill_pending is true. Re-attempts kill_curl
-- once the pid file lands (or until the deadline elapses, after which we give
-- up to avoid burning CPU forever on a request whose launcher silently failed).
function Net.try_finish_kill_pending()
  if not S.kill_pending then return end
  if reaper.time_precise() > S.kill_pending_until then
    S.kill_pending = false
    return
  end
  local f = io.open(tmp.pid, "r")
  if not f then return end
  f:close()
  -- pid file now exists -- re-enter kill_curl which will read and act on it.
  Net.kill_curl()
end

-- =============================================================================
-- Net.custom_models_url
-- =============================================================================
-- Derive an OpenAI-compatible `GET /v1/models` URL from a chat/completions
-- endpoint. Covers the common shapes emitted by LM Studio, Ollama, llama.cpp,
-- vLLM, and OpenRouter. Falls back to appending /v1/models to the host if the
-- input URL is unrecognized.
function Net.custom_models_url(endpoint)
  if type(endpoint) ~= "string" or endpoint == "" then return nil end
  -- Require an http(s):// scheme. The form validator catches this at user-
  -- input time, but defending here too means a saved-but-corrupt config
  -- can't accidentally produce a curl-wrong URL.
  if not endpoint:match("^https?://") then return nil end
  -- Strip trailing slash.
  local url = endpoint:gsub("/+$", "")
  -- Most common: ".../v1/chat/completions" -> ".../v1/models"
  local base = url:match("^(.-)/chat/completions$")
  if base then return base .. "/models" end
  -- Already a models URL.
  if url:match("/models$") then return url end
  -- URL ends at /v1 (no suffix): append /models.
  if url:match("/v1$") then return url .. "/models" end
  -- Bare-host fallback: append /v1/models ONLY when the input has no path.
  -- Strict anchor (^scheme://host$) so that a deliberately-typed-but-wrong
  -- path like ".../v3fffs" is NOT silently rewritten to ".../v1/models" --
  -- the test would otherwise report success against the canonical path
  -- the user didn't ask for. The earlier permissive prefix match was too
  -- eager. Returning nil here causes Net.fire_key_test to surface
  -- "Could not derive a /v1/models URL from the endpoint." so the user
  -- knows their endpoint shape isn't recognised.
  local host_only = url:match("^(https?://[^/]+)$")
  if host_only then return host_only .. "/v1/models" end
  return nil
end

-- =============================================================================
-- Net.fire_key_test
-- =============================================================================
-- Sends a minimal API request to validate the key. Cloud providers get a
-- 1-token chat/completions POST (cost negligible). Custom OpenAI-compatible
-- providers instead get a GET /v1/models request so no inference runs on the
-- server -- critical for reasoning models where `max_completion_tokens=1`
-- only caps output tokens, not the full thinking pass.
-- On completion, Net.try_finish_curl detects S.key_test_pending and routes to
-- Net.handle_key_test instead of the normal response flow.
-- provider_override: optional provider table to test (for multi-key intro screen).
function Net.fire_key_test(provider_override)
  local p = provider_override or PROVIDERS.active()
  -- Build a minimal test request. Cloud providers use a 1-token chat POST;
  -- custom providers use a GET /v1/models call (no inference -> no reasoning
  -- cost, no model load, instant response).
  local body
  local curl_opts = nil
  if p.is_custom then
    if p.use_inference_test then
      -- Opt-in real-inference test (Test Connection checkbox). Sends a
      -- 1-token chat/completions POST against the user's first model id
      -- (with model_prefix applied) -- exercises the same code path real
      -- chat will, at the cost of one short inference call. Default-off
      -- per the custom-LLM page UX since reasoning models would still
      -- run a full thinking pass on max_completion_tokens=1.
      --
      -- Mirrors Net.build_body_openai's custom path on two load-bearing
      -- points: (1) max_completion_tokens (the field newer OpenAI-
      -- compatibles expect; max_tokens diverges and could fail on a
      -- working provider); (2) the merged provider-wide + per-model
      -- extra_body via Net.merge_custom_extra_body so vendor toggles
      -- (Kimi thinking flag, Qwen enable_thinking, OpenRouter reasoning)
      -- get tested too -- without it, a provider that requires a toggle
      -- could pass the probe and fail under real chat. System prompt /
      -- prompt_cache_key / reasoning_effort are deliberately NOT included
      -- to keep the probe cheap (input-token cost stays minimal).
      local model_id = (p.models and p.models[1] and p.models[1].id) or ""
      if p.model_prefix and p.model_prefix ~= "" then
        model_id = p.model_prefix .. model_id
      end
      local extra_suffix = Net.merge_custom_extra_body(p,
        p.models and p.models[1] or nil)
      body = str_format(
        '{"model":"%s","max_completion_tokens":1,"messages":[{"role":"user","content":"hi"}]%s}',
        model_id, extra_suffix)
      -- curl_opts stays nil -> default POST to p.endpoint.
    else
      -- Default safe path: GET /v1/models. No inference, no cost,
      -- instant response.
      local url = Net.custom_models_url(p.endpoint)
      if not url then
        S.key_test_pending  = false
        S.key_test_provider = nil
        S.status            = "error"
        if api_keys.custom_conn_test and api_keys.custom_conn_test.active
           and api_keys.screen == "custom_llm" then
          CTX.custom_conn_test_advance(false,
            "Could not derive a /v1/models URL from the endpoint.")
          return
        end
        return
      end
      body      = nil
      curl_opts = { method = "GET", endpoint_override = url }
    end
  elseif p.id == "anthropic" then
    body = str_format(
      '{"model":"%s","max_tokens":1,"messages":[{"role":"user","content":"hi"}]}',
      p.models[1].id)
  elseif p.id == "openai" then
    body = str_format(
      '{"model":"%s","max_completion_tokens":1,"messages":[{"role":"user","content":"hi"}]}',
      p.models[1].id)
  elseif p.id == "deepseek" then
    -- DeepSeek speaks the OpenAI Chat Completions wire format but uses
    -- the older `max_tokens` cap field; their reference does not document
    -- `max_completion_tokens`, and an unknown-field cap is silently
    -- ignored (so the probe burns ~100+ output tokens of real generation
    -- on every key test instead of stopping at 1).
    body = str_format(
      '{"model":"%s","max_tokens":1,"messages":[{"role":"user","content":"hi"}]}',
      p.models[1].id)
  elseif p.id == "google" then
    body = '{"contents":[{"role":"user","parts":[{"text":"hi"}]}],"generationConfig":{"maxOutputTokens":1}}'
  end
  -- Defer if another curl is in flight (typically the auto-retest Gemini
  -- tier test that fires on startup). Without this guard, fire_curl's
  -- in_flight return would cascade through the queue, marking every
  -- provider as "Could not reach the X API. Check your internet connection"
  -- in seconds even though the actual problem is just timing. The loop
  -- handler below polls and re-fires once curl_pid clears, with a 30s
  -- ceiling so a stuck pending state doesn't trap the queue indefinitely.
  if S.curl_pid then
    S.key_test_armed = {
      provider = p,
      armed_at = time_precise(),
    }
    S.status = "waiting"
    return
  end
  S.key_test_pending  = true
  S.key_test_provider = p.id
  S.status            = "waiting"
  Code.safe_write(tmp.out, "")
  local fired, reason = Net.fire_curl(body, curl_opts)
  if not fired then
    S.key_test_pending  = false
    S.key_test_provider = nil
    S.status            = "error"
    local label = p.label
    -- "in_flight" should have been caught by the pre-check above; this
    -- branch covers the I/O-error reasons (disk full, AV lock on tmp.body
    -- / tmp.auth, etc.) and any future failure modes added to fire_curl.
    local in_flight = (reason == "in_flight")
    local short_msg, detail_msg, hint
    if in_flight then
      short_msg  = "Another request is in progress. Try again in a moment."
      detail_msg = "Couldn't start the " .. label .. " key test -- "
        .. "another request is already in flight."
      hint       = "Wait a few seconds and click Test API Keys again."
    else
      short_msg  = "Couldn't start the " .. label .. " key test (local "
        .. "error writing temp files)."
      detail_msg = "Couldn't start the " .. label .. " key test. "
        .. "ReaAssist failed to write its temporary request files."
      hint       = "Check that your REAPER Resources directory is writable "
        .. "and that no antivirus is locking files in it."
    end
    -- Custom-LLM row-test mode: record failure and advance the queue.
    if api_keys.custom_conn_test and api_keys.custom_conn_test.active
       and api_keys.screen == "custom_llm" and p.is_custom then
      CTX.custom_conn_test_advance(false, short_msg)
      return
    end
    -- Multi-key test mode: record failure and advance queue.
    if #api_keys.test_queue > 0 and (api_keys.screen == "first_run" or api_keys.screen == "settings") then
      Net.advance_key_test_queue(p.id, false, short_msg)
      return
    end
    if (api_keys.screen == "first_run" or api_keys.screen == "settings") then
      api_keys.key_validating = false
      api_keys.key_error      = short_msg
      -- Show error popup.
      api_keys.show_key_error_popup = true
      api_keys.key_error_provider   = label
      api_keys.key_error_detail     = detail_msg
      api_keys.key_error_hint       = hint
      api_keys.key_error_url        = nil
      api_keys.key_error_url_label  = nil
    else
      -- Append rather than clobber: if the user somehow triggered a key test
      -- while a conversation was on screen, wiping S.display_messages would
      -- destroy their chat. Log.add_error is the shared append path.
      Log.add_error(short_msg)
    end
  end
end

-- =============================================================================
-- Net.is_auth_error
-- =============================================================================
-- Returns true if the parsed response represents an authentication error
-- for the given provider. Each provider has a different error envelope
-- format. `prov` is the full provider table (from PROVIDERS) so we can
-- dispatch on id for hosted providers and on is_custom for any of the
-- user-configured OpenAI-compatible endpoints.
function Net.is_auth_error(resp, prov)
  if type(resp) ~= "table" then return false end
  if prov.id == "anthropic" then
    return resp.type == "error"
      and type(resp.error) == "table" and resp.error ~= JSON.NULL
      and resp.error.type == "authentication_error"
  elseif prov.id == "openai" or prov.id == "deepseek" or prov.is_custom then
    -- Custom OpenAI-compatible servers usually pass errors through unchanged.
    -- DeepSeek follows the same envelope conventions.
    return type(resp.error) == "table" and resp.error ~= JSON.NULL
      and (resp.error.code == "invalid_api_key"
        or resp.error.type == "invalid_request_error"
           and type(resp.error.message) == "string"
           and resp.error.message:lower():find("api key"))
  elseif prov.id == "google" then
    return type(resp.error) == "table" and resp.error ~= JSON.NULL
      and (resp.error.status == "UNAUTHENTICATED"
        or resp.error.code == 401)
  end
  return false
end

-- =============================================================================
-- Net.advance_key_test_queue
-- =============================================================================
-- Records a result for the just-tested provider and fires the next test in
-- api_keys.test_queue. When the queue is exhausted, sets the flag to open the
-- results popup. Returns true if a next test was started, false if done.
function Net.advance_key_test_queue(prov_id, ok, error_msg)
  -- Record result.
  local p = PROVIDERS.get(prov_id)
  api_keys.test_results[prov_id] = {
    ok    = ok,
    label = p and p.label or prov_id,
    error = error_msg,
  }
  -- Remove the completed entry from the front of the queue.
  if #api_keys.test_queue > 0 then
    table.remove(api_keys.test_queue, 1)
  end
  -- Fire next test if any remain.
  if #api_keys.test_queue > 0 then
    local nxt = api_keys.test_queue[1]
    api_keys.key_validating_idx = nxt.idx
    S.api_key = S.api_key_map[nxt.prov.id]
    prefs.provider_idx = nxt.idx
    MODELS.refresh()
    Code.safe_write(tmp.out, "")
    Net.fire_key_test(nxt.prov)
    return true
  end
  -- Queue exhausted: stop validating, restore active provider, show results.
  api_keys.key_validating     = false
  api_keys.key_validating_idx = nil
  api_keys.show_test_results  = true
  S.status = "idle"
  -- Restore the active-provider snapshot taken when the queue was kicked
  -- off (UI: Test API Keys click handler). Each queued provider had to
  -- temporarily own prefs.provider_idx so fire_key_test would target it;
  -- restoring here puts the user back on whichever provider they had
  -- selected before clicking Test, instead of leaving them parked on
  -- the last queue entry.
  if api_keys._test_orig_provider_idx then
    prefs.provider_idx = api_keys._test_orig_provider_idx
    api_keys._test_orig_provider_idx = nil
    MODELS.refresh()
  end
  -- Restore active provider key.
  S.api_key = S.api_key_map[PROVIDERS.active().id]
  Code.safe_write(tmp.out, "")

  -- If a Google key test succeeded in this queue, kick off tier detection so
  -- the free-tier warning fires via the Test API Keys button path too (the
  -- single-key Save path in fire_key_test already handles this; the queue
  -- path returns early before reaching it).
  local gres = api_keys.test_results and api_keys.test_results.google
  if gres and gres.ok and S.api_key_map.google then
    S.gemini_paid_tier = nil
    Net.fire_gemini_tier_test()
  end

  return false
end

-- =============================================================================
-- Net.handle_key_test
-- =============================================================================
-- Called by Net.try_finish_curl when S.key_test_pending is true. Checks whether the
-- validation request succeeded or returned an auth error, and shows the
-- appropriate message. Provider-aware: uses S.key_test_provider to identify
-- the provider being tested and its console URL.
function Net.handle_key_test(raw)
  S.key_test_pending = false
  local prov_id = S.key_test_provider or PROVIDERS.active().id
  local p       = PROVIDERS.get(prov_id) or PROVIDERS.active()
  S.key_test_provider = nil

  -- Parse the response using the JSON decoder.
  local resp = JSON.decode(raw)
  -- Custom (local LLM) test response check. Two shapes possible:
  --   * Default GET /v1/models path -- expect a `data` array.
  --   * Opt-in inference test (Test Connection checkbox) -- expect a
  --     chat/completions response with a `choices` array.
  -- Either way: must parse as JSON, must not carry a top-level error
  -- envelope. p.use_inference_test is set on the throwaway provider
  -- record by custom_conn_test_register when the user ticked the box.
  local custom_unreachable = false
  if p.is_custom then
    if type(resp) ~= "table" then
      custom_unreachable = true
    elseif type(resp.error) == "table" and resp.error ~= JSON.NULL then
      custom_unreachable = true
    elseif p.use_inference_test then
      if type(resp.choices) ~= "table" then
        custom_unreachable = true
      end
    elseif type(resp.data) ~= "table" then
      -- Server responded but the body isn't a /v1/models listing -> not
      -- OpenAI-compatible, or we hit the wrong route.
      custom_unreachable = true
    end
  end
  -- ---------- Custom-LLM connection test mode (Test Connection button) ------
  -- When the custom_conn_test is active, record pass/fail and finish.
  if api_keys.custom_conn_test and api_keys.custom_conn_test.active
     and api_keys.screen == "custom_llm" and p.is_custom then
    local err_msg = nil
    if custom_unreachable then
      local emsg = (type(resp) == "table" and type(resp.error) == "table"
                    and resp.error ~= JSON.NULL and type(resp.error.message) == "string")
                   and resp.error.message or nil
      local probe = p.use_inference_test and "/v1/chat/completions"
                                          or "/v1/models"
      err_msg = "Endpoint reachable but " .. probe
        .. " returned an unexpected response."
        .. (emsg and (" Server said: " .. emsg) or "")
    elseif Net.is_auth_error(resp, p) then
      err_msg = "Authentication failed."
    end
    CTX.custom_conn_test_advance(err_msg == nil, err_msg)
    Code.safe_write(tmp.out, "")
    return
  end

  -- ---------- Multi-key test mode (Test API Keys button) ----------
  -- When the test queue is active, record pass/fail and advance to the next
  -- provider instead of performing the normal single-key flow.
  if #api_keys.test_queue > 0 and (api_keys.screen == "first_run" or api_keys.screen == "settings") then
    local err_msg = nil
    if custom_unreachable then
      local emsg = (type(resp) == "table" and type(resp.error) == "table"
                    and resp.error ~= JSON.NULL and type(resp.error.message) == "string")
                   and resp.error.message or nil
      err_msg = "The endpoint responded but /v1/models returned an unexpected response."
        .. (emsg and (" Server said: " .. emsg) or "")
    elseif Net.is_auth_error(resp, p) then
      err_msg = "Authentication failed. The key may have expired or been revoked."
    end
    Net.advance_key_test_queue(p.id, err_msg == nil, err_msg)
    return
  end

  if custom_unreachable then
    S.status = "error"
    if (api_keys.screen == "first_run" or api_keys.screen == "settings") then
      api_keys.key_validating     = false
      api_keys.key_validating_idx = nil
      -- Same restore-on-failure pattern as the auth-error branch above.
      if api_keys._test_orig_provider_idx then
        local saved = api_keys._test_orig_provider_idx
        api_keys._test_orig_provider_idx = nil
        local saved_prov = PROVIDERS[saved]
        if saved_prov and S.api_key_map[saved_prov.id] then
          prefs.provider_idx = saved
          reaper.SetExtState(CFG.EXT_NS, "provider_idx", tostring(saved), true)
          MODELS.refresh()
          S.api_key = S.api_key_map[saved_prov.id]
        end
      end
      local emsg = (type(resp) == "table" and type(resp.error) == "table"
                    and resp.error ~= JSON.NULL and type(resp.error.message) == "string")
                   and resp.error.message or nil
      local detail = "The endpoint responded but the model test failed."
        .. (emsg and ("\n\nServer said: " .. emsg) or "")
      -- Show error popup.
      api_keys.show_key_error_popup = true
      api_keys.key_error_provider   = p.label or "Custom LLM"
      api_keys.key_error_detail     = detail
      api_keys.key_error_hint       = "Check that the server is running, the URL and port "
        .. "are correct, and the model identifier matches what the server expects."
      api_keys.key_error_url        = nil
      api_keys.key_error_url_label  = nil
    end
    Code.safe_write(tmp.out, "")
    return
  end

  if Net.is_auth_error(resp, p) then
    -- Key is invalid: clear it and prompt again.
    S.api_key = nil
    S.api_key_map[p.id] = nil
    if p.key_extstate then Key.clear(p.key_extstate) end
    -- Restore the active-provider snapshot taken when the Save handler
    -- flipped to test this key. If the original provider still has a
    -- working key, put the user back there so a failed OpenAI key test
    -- doesn't strand them on a broken OpenAI configuration when they
    -- were happily on Claude before. If the snapshotted provider lost
    -- its key (e.g. user wiped Claude before pasting OpenAI), leave
    -- prefs.provider_idx alone -- restoring would also break.
    if api_keys._test_orig_provider_idx then
      local saved = api_keys._test_orig_provider_idx
      api_keys._test_orig_provider_idx = nil
      local saved_prov = PROVIDERS[saved]
      if saved_prov and S.api_key_map[saved_prov.id] then
        prefs.provider_idx = saved
        reaper.SetExtState(CFG.EXT_NS, "provider_idx", tostring(saved), true)
        MODELS.refresh()
        S.api_key = S.api_key_map[saved_prov.id]
      end
    end
    S.status = "error"
    if (api_keys.screen == "first_run" or api_keys.screen == "settings") then
      api_keys.key_validating = false
      local idx = PROVIDERS._by_id[p.id]
      if idx and api_keys.key_errors then
        api_keys.key_errors[idx] = "That key didn't work. It may have expired "
          .. "or been entered incorrectly."
      end
      -- Clear the failed key out of the input buffer so the user can
      -- either paste a fresh key or just click Save and exit. Without
      -- this, the bad key stays in the field as password bullets and
      -- a no-edit Save would re-test (and re-fail) it.
      if idx and api_keys.key_bufs then
        api_keys.key_bufs[idx] = ""
      end
      api_keys.key_error = "That " .. p.label .. " key didn't work. It may have "
        .. "expired or been entered incorrectly. Please paste a valid key and try again."
      -- Show error popup.
      api_keys.show_key_error_popup = true
      api_keys.key_error_provider   = p.label
      api_keys.key_error_detail     = "The " .. p.label .. " API key failed authentication. "
        .. "The key may have expired, been revoked, or was entered incorrectly."
      api_keys.key_error_hint       = "Double-check the key for typos, or generate a new one at your provider's console."
      api_keys.key_error_url        = p.console_url
      api_keys.key_error_url_label  = p.console_label
    else
      -- Append rather than clobber: preserves any conversation state that
      -- happens to be on screen when a key test triggers.
      Log.add_error(
        "That " .. p.label .. " key didn't work. It may have expired or been "
          .. "entered incorrectly.\n\n"
          .. "Click the Settings button to try again.\n\n"
          .. "You can find or create a key here:",
        p.console_url, p.console_label)
    end
    return
  end

  -- If we got here, the key works (even a rate-limit means auth succeeded).
  -- Persist the tested key now that validation has confirmed it works. Custom
  -- providers may have no key at all -- skip the save in that case.
  if S.api_key and p.key_extstate then
    Key.save(S.api_key, p.key_extstate)
    S.api_key_map[p.id] = S.api_key
  end
  S.status = "idle"
  if (api_keys.screen == "first_run" or api_keys.screen == "settings") then
    -- Also persist any other newly entered keys that passed format validation
    -- (they were stored in S.api_key_map during submit but not yet saved to ExtState).
    for i, prov in ipairs(PROVIDERS) do
      if prov.id ~= p.id then
        local buf = api_keys.key_bufs[i] or ""
        local trimmed = buf:match("^%s*(.-)%s*$") or ""
        if trimmed ~= "" and S.api_key_map[prov.id] == trimmed then
          Key.save(trimmed, prov.key_extstate)
        end
      end
    end
    local was_reentry = api_keys.is_reentry
    -- Leave the key screen and enter the main UI.
    api_keys.screen         = nil
    api_keys.is_reentry     = false
    api_keys.key_validating = false
    api_keys.key_error      = nil
    api_keys.key_bufs       = {}
    api_keys.key_errors     = {}
    api_keys.key_focused    = false
    api_keys.custom_edit = nil
    UI.show_float_toast(was_reentry and "Settings saved" or "API key validated", "ok")
    if not was_reentry then
      -- First-run: set the active provider to the one just validated.
      -- Drop any test-snapshot since first-run is intentionally choosing
      -- the new provider as active; restoring would defeat the purpose.
      api_keys._test_orig_provider_idx = nil
      local prov_idx = PROVIDERS._by_id[p.id]
      if prov_idx then
        prefs.provider_idx = prov_idx
        reaper.SetExtState(CFG.EXT_NS, "provider_idx", tostring(prov_idx), true)
        MODELS.refresh()
      end
    elseif api_keys._test_orig_provider_idx then
      -- Settings re-entry: restore the active-provider snapshot taken
      -- when the Save handler flipped to test the new key, so testing
      -- e.g. a fresh OpenAI key while currently on Claude doesn't
      -- silently switch the active provider as a side effect of Save.
      -- If the snapshotted provider lost its key during this Save (user
      -- wiped it in the same submission), leave provider_idx pointing
      -- at the just-validated provider so the user retains a working
      -- configuration -- restoring would land them on a no-key slot.
      local saved = api_keys._test_orig_provider_idx
      api_keys._test_orig_provider_idx = nil
      local saved_prov = PROVIDERS[saved]
      if saved_prov and S.api_key_map[saved_prov.id] then
        prefs.provider_idx = saved
        reaper.SetExtState(CFG.EXT_NS, "provider_idx", tostring(saved), true)
        MODELS.refresh()
      end
    end
    S.api_key = S.api_key_map[PROVIDERS.active().id]
    S.refocus_prompt   = true
    if Diag.uploader_enabled and Diag.capture_current_chat then
      Diag.capture_current_chat()
    end
    S.display_messages = {}
    S.history          = {}
    S.scroll_to_bottom = true
    -- Settings provider-switch implicitly starts a new chat. Rotate chat_id
    -- to match what Net.clear_conversation does at the canonical "+ New Chat"
    -- entry point.
    if Diag.uploader_enabled then
      Diag.rotate_chat_id()
    end
  end

  -- Clear the response file so the next Net.send_to_api call doesn't pick up
  -- the stale key-test response before the new curl has written its output.
  Code.safe_write(tmp.out, "")

  -- Detect Gemini free vs paid tier by testing the Pro model. Fires whenever
  -- a Google key ended up persisted by this key-test flow -- not just when
  -- Google was the tested provider. On first-run / Settings, Save & Continue
  -- tests only the FIRST valid key and side-saves the rest (see the loop
  -- above). Without this broader trigger, a Gemini key pasted alongside
  -- another provider never gets its tier detected and the free-tier popup
  -- never fires. fire_gemini_tier_test guards against double-firing via
  -- the S.curl_pid check at its top.
  if S.api_key_map.google then
    S.gemini_paid_tier = nil
    Net.fire_gemini_tier_test()
  end
end

-- =============================================================================
-- Net.fire_gemini_tier_test
-- =============================================================================
-- Fires a 1-token request using the Pro model to detect free vs paid tier.
-- Free tier: response body contains "free_tier" in quota metrics (429, limit=0).
-- Paid tier: request succeeds (Pro accessible).
function Net.fire_gemini_tier_test()
  -- Don't fire while another request is in-flight.
  if S.curl_pid then return end
  local google_key = S.api_key_map.google
  if not google_key then return end

  -- Find the Pro model ID from the provider's full model list.
  local google_prov = PROVIDERS.get("google")
  if not google_prov then return end
  local pro_id
  for _, m in ipairs(google_prov.models) do
    if m.paid_only then pro_id = m.id; break end
  end
  if not pro_id then return end

  -- Pin thinkingLevel=LOW (the lowest setting Gemini Pro allows -- there is
  -- no "off" for Pro models) so the tier-test request doesn't burn 20-60s on
  -- internal reasoning before hitting the 1-token output cap. Without this,
  -- Pro defaults to MEDIUM thinking and the tier test routinely exceeds
  -- curl --max-time 30, leaving us at the mercy of the 180s watchdog and
  -- producing the "ambiguous (timeout)" classification on slow connections.
  -- The tier test only needs to know whether Pro is *callable*, not whether
  -- it produces a useful response, so cheap thinking is fine.
  local body = '{"contents":[{"role":"user","parts":[{"text":"hi"}]}],'
    .. '"generationConfig":{"maxOutputTokens":1,'
    .. '"thinkingConfig":{"thinkingLevel":"LOW","includeThoughts":false}}}'
  if not Code.safe_write(tmp.body, body) then return end

  -- Write the Gemini auth header to a temp file so it stays off the command
  -- line (not visible in ps/Task Manager). Uses tmp.gemini_auth to avoid
  -- trampling the main request's tmp.auth.
  if not Code.safe_write(tmp.gemini_auth, "x-goog-api-key: " .. google_key) then return end

  local endpoint = str_format(google_prov.endpoint_tpl, pro_id)
  local CONNECT_TIMEOUT_SECS = 10

  os.remove(tmp.exit)
  os.remove(tmp.err)
  -- Clear any stale tmp.pid from a previous real curl. This path does not
  -- launch curl with PID capture (no Start-Process -PassThru / $! plumbing),
  -- so leaving an old PID on disk would let Net.kill_curl `taskkill` an
  -- unrelated process if the user clicks Cancel during the tier test (or
  -- worse, a recycled PID owned by some other application).
  os.remove(tmp.pid)
  Code.safe_write(tmp.out, "")
  Code.safe_write(tmp.err, "")
  S.curl_debug = {
    launched_at_utc = os.date("!%Y-%m-%dT%H:%M:%SZ"),
    method = "POST",
    provider_id = "google",
    provider_label = google_prov.label,
    model_id = pro_id,
    model_label = "Gemini tier probe",
    endpoint = Net._debug_endpoint(google_prov, endpoint),
    connect_timeout_s = CONNECT_TIMEOUT_SECS,
    curl_timeout_s = 30,
    request_body_bytes = #body,
    is_turn_post = false,
    probe_kind = "gemini_tier_test",
  }

  if RA.IS_WINDOWS then
    local function ps_escape(path) return path:gsub("'", "''") end
    local cmd_line = str_format(
      'curl -sS --connect-timeout %d --max-time 30'
      .. ' -X POST %s'
      .. ' -H """content-type: application/json"""'
      .. ' -H @"""%s"""'
      .. ' -d @"""%s""" -o """%s""" 2> """%s"""'
      .. ' & call echo ^%%errorlevel^%% > """%s""" & del """%s"""',
      CONNECT_TIMEOUT_SECS, endpoint, tmp.gemini_auth, tmp.body, tmp.out,
      tmp.err, tmp.exit, tmp.gemini_auth)
    local ps_cmd = str_format(
      'powershell -NoProfile -WindowStyle Hidden'
      .. ' -Command "Start-Process cmd -ArgumentList \'/c %s\''
      .. ' -WindowStyle Hidden"',
      ps_escape(cmd_line))
    reaper.ExecProcess(ps_cmd, 5000)
  else
    local function sq(path) return "'" .. path:gsub("'", "'\\''") .. "'" end
    -- Wrap entire pipeline in a subshell so & backgrounds curl+echo together.
    local unix_curl = str_format(
      '(curl -sS --connect-timeout %d --max-time 30'
      .. ' -X POST %s'
      .. ' -H "content-type: application/json"'
      .. ' -H @%s'
      .. ' -d @%s -o %s 2> %s ; rc=$? ; rm -f %s ; echo $rc > %s) &',
      CONNECT_TIMEOUT_SECS, endpoint,
      sq(tmp.gemini_auth),
      sq(tmp.body), sq(tmp.out), sq(tmp.err),
      sq(tmp.gemini_auth), sq(tmp.exit))
    os.execute(unix_curl)
  end

  S.gemini_tier_pending = true
  S.curl_pid            = true
  S.send_time           = time_precise()
  -- Sticky floating toast so the user sees something is happening. Replaced
  -- by handle_gemini_tier_test (and the timeout / curl-exit branches) once
  -- the test resolves, with a result-specific message.
  if UI and UI.show_float_toast then
    UI.show_float_toast("Verifying Gemini tier...", "ok", true)
  end
end

-- =============================================================================
-- Net.handle_gemini_tier_test
-- =============================================================================
-- Parses the Pro model test response. Paid is set only on a positive signal
-- (successful generation); free is set on an explicit 429/403 error or the
-- legacy "free_tier" substring. Ambiguous responses leave S.gemini_paid_tier
-- unchanged (and do NOT persist) so the next session or Test-API-Keys click
-- retries instead of inheriting a bad classification. The Pro filter stays
-- engaged in the meantime (it gates on `~= true`), so users on the free tier
-- still don't see Pro -- they just don't get the "(Free)" label or the
-- explanatory popup until detection succeeds.
function Net.handle_gemini_tier_test(raw)
  S.gemini_tier_pending = false
  local is_paid, is_free
  if raw and #raw > 0 then
    local ok, resp = pcall(JSON.decode, raw)
    if ok and type(resp) == "table" and resp ~= JSON.NULL then
      if type(resp.error) == "table" and resp.error ~= JSON.NULL then
        local code   = tonumber(resp.error.code)
        local status = type(resp.error.status) == "string" and resp.error.status or ""
        if code == 429 or code == 403
           or status == "RESOURCE_EXHAUSTED" or status == "PERMISSION_DENIED" then
          is_free = true
        end
      elseif type(resp.candidates) == "table" and #resp.candidates > 0 then
        is_paid = true
      end
    end
  end
  local interpretation
  if is_paid then
    S.gemini_paid_tier = true
    reaper.SetExtState(CFG.EXT_NS, "gemini_paid_tier", "true", true)
    interpretation = "paid"
    if UI and UI.show_float_toast then
      UI.show_float_toast("Gemini Pro available", "ok")
    end
  elseif is_free then
    S.gemini_paid_tier = false
    reaper.SetExtState(CFG.EXT_NS, "gemini_paid_tier", "false", true)
    S.show_gemini_free_warn = true
    interpretation = "free"
    -- Free-tier popup handles the user-facing notice; just clear the
    -- in-flight sticky toast so it doesn't sit there indefinitely.
    S.float_toast = nil
  else
    -- Ambiguous: leave S.gemini_paid_tier and the persisted ExtState entry
    -- untouched so the next opportunity (app restart, Test API Keys click)
    -- can retry. Persisting `false` here would bake in a wrong answer that
    -- only manual ExtState surgery could undo.
    interpretation = "ambiguous"
    if UI and UI.show_float_toast then
      UI.show_float_toast(
        "Couldn't verify Gemini tier - will retry on next start", "err")
    end
  end
  Log.line("TIER-TEST", string.format("interpreted as: %s (raw bytes=%d)",
    interpretation, raw and #raw or 0))
  if PROVIDERS.active().id == "google" then MODELS.refresh() end
  Code.safe_write(tmp.out, "")  -- clear stale tier test response
end

-- =============================================================================
-- Gemini explicit context caching
-- =============================================================================
-- Explicit caching lets us pay a discounted rate on the tokens that make up
-- the system prompt + pinned API reference, instead of billing them as fresh
-- input tokens on every turn. The cache has a TTL (1h) and is bound to a
-- specific model id, so it must be recreated on model switch.
--
-- Lifecycle:
--   ensure()     - called at send time; fires an async create if eligible and
--                  we don't already have a live cache. Never blocks the send.
--   invalidate() - clears local state and fires a fire-and-forget DELETE so
--                  the cache stops accruing storage charges server-side.
--   is_usable()  - checked in build_body_google to decide whether to emit
--                  cachedContent and skip the inline api_ref + systemInstruction.
--
-- The first send after (re)creation goes out WITHOUT cache because creation
-- is async and completes in parallel. Subsequent sends benefit.
-- =============================================================================

-- Minimum input tokens to qualify for explicit caching on Gemini. Flash
-- family is 1024; Pro family is 4096. The API ref alone clears both, but
-- we include system_instruction in the cache too for a bigger discount.
local GEMINI_CACHE_TTL_SECS  = 3600  -- 1 hour
local GEMINI_CACHE_SAFETY    = 60    -- treat as expired if within 60s of TTL

-- =============================================================================
-- Net.gemini_cache_is_usable
-- =============================================================================
-- True when we have a live, non-expired cache that matches the current model.
function Net.gemini_cache_source_signature(api_ref)
  local sys = tostring((Net.system_prompt_text and Net.system_prompt_text())
    or SYSTEM_PROMPT or "")
  local ref = tostring(api_ref or "")
  local h = 5381
  local function fold(s)
    for i = 1, #s do
      h = (h * 33 + s:byte(i)) % 4294967296
    end
  end
  fold(sys)
  h = (h * 33 + 10) % 4294967296
  fold(ref)
  return tostring(#sys) .. ":" .. tostring(#ref)
    .. ":" .. str_format("%08x", h)
end

function Net.gemini_cache_is_usable()
  if not S.gemini_cache_name then return false end
  if S.gemini_paid_tier ~= true then return false end
  if not S.api_ref_message or S.api_ref_message == "" then return false end
  local p = PROVIDERS.active()
  if p.id ~= "google" then return false end
  if S.gemini_cache_model ~= MODELS.active_id() then return false end
  if S.gemini_cache_signature
      ~= Net.gemini_cache_source_signature(S.api_ref_message) then
    return false
  end
  if os.time() >= (S.gemini_cache_expires - GEMINI_CACHE_SAFETY) then
    return false
  end
  return true
end

function Net.gemini_cache_debug_state(stage, used_cache, reported_read_tokens)
  local p = PROVIDERS.active()
  local provider_id = p and p.id or ""
  local active_model = MODELS.active_id and MODELS.active_id() or ""
  local has_name = type(S.gemini_cache_name) == "string"
    and S.gemini_cache_name ~= ""
  local has_api_ref = type(S.api_ref_message) == "string"
    and S.api_ref_message ~= ""
  local current_signature = has_api_ref
    and Net.gemini_cache_source_signature(S.api_ref_message)
    or ""
  local expires_in = (tonumber(S.gemini_cache_expires) or 0) - os.time()
  local status, reason
  if provider_id ~= "google" then
    status, reason = "disabled", "provider_not_google"
  elseif S.gemini_paid_tier ~= true then
    status = "disabled"
    reason = (S.gemini_paid_tier == false)
      and "paid_tier_false"
      or "paid_tier_unknown"
  elseif not has_api_ref then
    status, reason = "disabled", "api_ref_missing"
  elseif used_cache == true then
    local reported = tonumber(reported_read_tokens)
    if reported and reported <= 0 then
      status, reason = "used_unreported", "cached_content_sent_no_token_report"
    elseif reported and reported > 0 then
      status, reason = "used", "cached_content_sent_reported"
    else
      status, reason = "used", "cached_content_sent"
    end
  elseif S.gemini_cache_creating then
    status, reason = "pending", "create_in_flight"
  elseif not has_name then
    status, reason = "miss", "not_created"
  elseif S.gemini_cache_model ~= active_model then
    status, reason = "miss", "model_mismatch"
  elseif S.gemini_cache_signature ~= current_signature then
    status, reason = "miss", "source_mismatch"
  elseif expires_in <= GEMINI_CACHE_SAFETY then
    status, reason = "miss", "expired_or_near_expiry"
  else
    status, reason = "ready", "usable"
  end
  return {
    stage = stage or "",
    provider = provider_id,
    status = status,
    reason = reason,
    used = used_cache == true,
    paid_tier = S.gemini_paid_tier == true and "true"
      or S.gemini_paid_tier == false and "false"
      or "unknown",
    cache_name_present = has_name,
    cache_signature_present = type(S.gemini_cache_signature) == "string"
      and S.gemini_cache_signature ~= "",
    creating = S.gemini_cache_creating == true,
    api_ref_present = has_api_ref,
    active_model = active_model,
    cache_model = S.gemini_cache_model or "",
    expires_in_s = expires_in > 0 and math_floor(expires_in) or 0,
    reported_read_tokens = tonumber(reported_read_tokens) or 0,
    create_reason = S.gemini_cache_last_create_reason or "",
  }
end

-- =============================================================================
-- Net.gemini_cache_should_create
-- =============================================================================
-- True when the conditions for caching are met but no live cache exists yet.
local function gemini_cache_should_create()
  if S.gemini_cache_creating then return false end
  if S.gemini_paid_tier ~= true then return false end
  -- Treat empty string the same as nil. CTX.docs() normally returns nil on
  -- failure, but a partial-load failure path that produces "" would
  -- otherwise queue a Gemini cache create with a zero-token body, which
  -- the API rejects under its min-tokens limit -- wasted curl cycle.
  if not S.api_ref_message or S.api_ref_message == "" then return false end
  local p = PROVIDERS.active()
  if p.id ~= "google" then return false end
  if Net.gemini_cache_is_usable() then return false end
  return true
end

-- =============================================================================
-- Net.fire_gemini_cache_delete
-- =============================================================================
-- Fire-and-forget DELETE against cachedContents/NAME. We don't poll for
-- completion -- if it fails the cache will expire on its own via TTL.
function Net.fire_gemini_cache_delete(cache_name)
  if not cache_name or cache_name == "" then return end
  local google_key = S.api_key_map and S.api_key_map.google
  if not google_key then return end
  -- Write key to temp file so it stays off the command line.
  if not Code.safe_write(tmp.gemini_auth, "x-goog-api-key: " .. google_key) then return end
  local url = str_format(
    "https://generativelanguage.googleapis.com/v1beta/%s",
    cache_name)
  if RA.IS_WINDOWS then
    local cmd_line = str_format(
      'curl -s -X DELETE -H @"""%s""" %s & del """%s"""',
      tmp.gemini_auth, url, tmp.gemini_auth)
    local ps_cmd = str_format(
      'powershell -NoProfile -WindowStyle Hidden'
      .. ' -Command "Start-Process cmd -ArgumentList \'/c %s\''
      .. ' -WindowStyle Hidden"',
      cmd_line:gsub("'", "''"))
    reaper.ExecProcess(ps_cmd, 2000)
  else
    local function sq(path) return "'" .. path:gsub("'", "'\\''") .. "'" end
    os.execute(str_format(
      '(curl -s -X DELETE -H @%s %s > /dev/null 2>&1 ; rm -f %s) &',
      sq(tmp.gemini_auth), url, sq(tmp.gemini_auth)))
  end
end

-- atexit: persist the active Gemini context cache reference so the next
-- launch can reuse it instead of paying to recreate. Server-side TTL
-- (1h) cleans up orphans if the user never reopens.
reaper.atexit(function()
  if S.gemini_cache_name then
    local ok, err = pcall(Net.gemini_cache_persist)
    if not ok then
      Log.line("GEMINI", "cache_persist (atexit) failed: " .. tostring(err))
    end
  end
end)

-- =============================================================================
-- Net.gemini_cache_invalidate
-- =============================================================================
-- Clears local cache state and issues a server-side DELETE so the old cache
-- stops accruing storage charges. Safe to call when no cache exists.
function Net.gemini_cache_invalidate()
  local old_name = S.gemini_cache_name
  S.gemini_cache_name    = nil
  S.gemini_cache_model   = nil
  S.gemini_cache_signature = nil
  S.gemini_cache_expires = 0
  -- A create in-flight will land with a name we no longer want; mark the
  -- flight as aborted so the poll path discards the response.
  if S.gemini_cache_creating then
    S.gemini_cache_creating = false
  end
  Net.gemini_cache_clear_persisted()
  if old_name then
    Net.fire_gemini_cache_delete(old_name)
  end
end

-- =============================================================================
-- Net.gemini_cache_persist / restore / clear_persisted
-- =============================================================================
-- Survives the cache reference (name/model/expires) across script restarts via
-- ExtState. Without this, every restart re-creates a fresh cache while the
-- prior one continues billing storage server-side until its TTL expires --
-- typically ~$0.01 per restart on Gemini Pro and a 1-3s extra cold-start.
function Net.gemini_cache_persist()
  if not S.gemini_cache_name or S.gemini_cache_name == "" then return end
  reaper.SetExtState(CFG.EXT_NS, "gemini_cache_name",
    S.gemini_cache_name, true)
  reaper.SetExtState(CFG.EXT_NS, "gemini_cache_model",
    S.gemini_cache_model or "", true)
  reaper.SetExtState(CFG.EXT_NS, "gemini_cache_signature",
    S.gemini_cache_signature or "", true)
  reaper.SetExtState(CFG.EXT_NS, "gemini_cache_expires",
    tostring(S.gemini_cache_expires or 0), true)
end

function Net.gemini_cache_clear_persisted()
  reaper.DeleteExtState(CFG.EXT_NS, "gemini_cache_name",    true)
  reaper.DeleteExtState(CFG.EXT_NS, "gemini_cache_model",   true)
  reaper.DeleteExtState(CFG.EXT_NS, "gemini_cache_signature", true)
  reaper.DeleteExtState(CFG.EXT_NS, "gemini_cache_expires", true)
end

function Net.gemini_cache_restore()
  local name = reaper.GetExtState(CFG.EXT_NS, "gemini_cache_name")
  if not name or name == "" then return end
  local model = reaper.GetExtState(CFG.EXT_NS, "gemini_cache_model")
  local signature = reaper.GetExtState(CFG.EXT_NS, "gemini_cache_signature")
  local expires_str = reaper.GetExtState(CFG.EXT_NS, "gemini_cache_expires")
  local expires = tonumber(expires_str) or 0
  -- Discard expired caches (or those within the safety window). Server-side
  -- TTL has already collected them.
  if os.time() >= (expires - GEMINI_CACHE_SAFETY) then
    Net.gemini_cache_clear_persisted()
    return
  end
  S.gemini_cache_name    = name
  S.gemini_cache_model   = (model ~= "") and model or nil
  S.gemini_cache_signature = (signature ~= "") and signature or nil
  S.gemini_cache_expires = expires
  Log.line("GEMINI_CACHE", "restored " .. name
    .. " (model=" .. tostring(S.gemini_cache_model)
    .. ", signature=" .. tostring(S.gemini_cache_signature)
    .. ", expires_in=" .. tostring(expires - os.time()) .. "s)")
end

-- =============================================================================
-- Net.fire_gemini_cache_create
-- =============================================================================
-- Async POST /v1beta/cachedContents. Writes the body to tmp.cache_body and
-- launches curl in the background, with output going to tmp.cache_out and
-- exit code to tmp.cache_exit. The main loop polls completion via
-- Net.try_finish_gemini_cache_create.
--
-- Body contains: model id, systemInstruction, contents (the api_ref priming
-- exchange), and a TTL. Minimum token counts are naturally met since the api
-- ref alone is ~8k tokens.
function Net.fire_gemini_cache_create()
  if S.gemini_cache_creating then
    S.gemini_cache_last_create_reason = "already_creating"
    return
  end
  if not gemini_cache_should_create() then
    S.gemini_cache_last_create_reason = "not_eligible"
    return
  end

  local google_key = S.api_key_map and S.api_key_map.google
  if not google_key or google_key == "" then
    S.gemini_cache_last_create_reason = "api_key_map_missing"
    return
  end

  local model_id = MODELS.active_id()
  if not model_id then
    S.gemini_cache_last_create_reason = "model_missing"
    return
  end
  local source_signature = Net.gemini_cache_source_signature(S.api_ref_message)

  -- Build the create body: system_instruction + the same user/model priming
  -- exchange we'd otherwise inline into every request.
  local body = str_format(
    '{"model":"models/%s",'
    .. '"systemInstruction":{"parts":[{"text":"%s"}]},'
    .. '"contents":[{"role":"user","parts":[{"text":"%s"}]},'
    .. '{"role":"model","parts":[{"text":"Understood."}]}],'
    .. '"ttl":"%ds"}',
    model_id,
    JSON.escape(Net.system_prompt_text()),
    JSON.escape(S.api_ref_message),
    GEMINI_CACHE_TTL_SECS)

  if not Code.safe_write(tmp.cache_body, body) then
    S.gemini_cache_last_create_reason = "cache_body_write_failed"
    return
  end

  -- Write auth header to temp file (keeps key off command line).
  if not Code.safe_write(tmp.gemini_auth, "x-goog-api-key: " .. google_key) then
    S.gemini_cache_last_create_reason = "auth_write_failed"
    return
  end

  local url = "https://generativelanguage.googleapis.com/v1beta/cachedContents"

  os.remove(tmp.cache_exit)
  Code.safe_write(tmp.cache_out, "")

  if RA.IS_WINDOWS then
    local cmd_line = str_format(
      'curl -s --connect-timeout 10 --max-time 30'
      .. ' -X POST %s'
      .. ' -H """content-type: application/json"""'
      .. ' -H @"""%s"""'
      .. ' -d @"""%s""" -o """%s"""'
      .. ' & del """%s""" & echo %%errorlevel%% > """%s"""',
      url, tmp.gemini_auth, tmp.cache_body, tmp.cache_out,
      tmp.gemini_auth, tmp.cache_exit)
    local ps_cmd = str_format(
      'powershell -NoProfile -WindowStyle Hidden'
      .. ' -Command "Start-Process cmd -ArgumentList \'/c %s\''
      .. ' -WindowStyle Hidden"',
      cmd_line:gsub("'", "''"))
    reaper.ExecProcess(ps_cmd, 5000)
  else
    local function sq(path) return "'" .. path:gsub("'", "'\\''") .. "'" end
    local unix_curl = str_format(
      '(curl -s --connect-timeout 10 --max-time 30'
      .. ' -X POST %s'
      .. ' -H "content-type: application/json"'
      .. ' -H @%s'
      .. ' -d @%s -o %s ; rm -f %s ; echo $? > %s) &',
      url, sq(tmp.gemini_auth),
      sq(tmp.cache_body), sq(tmp.cache_out),
      sq(tmp.gemini_auth), sq(tmp.cache_exit))
    os.execute(unix_curl)
  end

  S.gemini_cache_creating   = true
  S.gemini_cache_started_at = reaper.time_precise()
  S.gemini_cache_model      = model_id  -- remember intended model for poll
  S.gemini_cache_signature  = source_signature
  S.gemini_cache_last_create_reason = "launched"
end

-- =============================================================================
-- Net.gemini_cache_ensure
-- =============================================================================
-- Called before building a Gemini request body. If we should have a cache but
-- don't (yet), fire an async create. Never blocks; the current send proceeds
-- with whatever state exists right now.
function Net.gemini_cache_ensure()
  if S.gemini_cache_creating then
    Net.try_finish_gemini_cache_create()
  end
  if S.gemini_cache_name
      and S.gemini_paid_tier == true
      and S.api_ref_message and S.api_ref_message ~= ""
      and not Net.gemini_cache_is_usable() then
    Net.gemini_cache_invalidate()
  end
  if gemini_cache_should_create() then
    Net.fire_gemini_cache_create()
  elseif Net.gemini_cache_should_renew() then
    Net.fire_gemini_cache_renew()
  elseif not Net.gemini_cache_is_usable() then
    local gc = Net.gemini_cache_debug_state("ensure", false)
    S.gemini_cache_last_create_reason = gc and gc.reason or "not_eligible"
  end
end

-- =============================================================================
-- Net.gemini_cache_should_renew / fire_gemini_cache_renew
-- =============================================================================
-- Bumps the server-side TTL of the active cache before it expires, instead of
-- waiting for expiry and paying to recreate. Without this, mid-session caches
-- silently expire after 1h and the next send rebuilds from scratch.
--
-- Renew threshold: remaining TTL < 15 min, no renew already in flight.
-- Fire-and-forget PATCH, optimistic local bump. If the server-side renew
-- fails for any reason, the next send will hit a 404 cache_miss and the
-- existing invalidate -> recreate path picks up cleanly.
local GEMINI_CACHE_RENEW_THRESHOLD = 15 * 60  -- 15 minutes
local GEMINI_CACHE_RENEW_DEDUPE    = 5 * 60   -- don't re-fire renew within 5 min

function Net.gemini_cache_should_renew()
  if not S.gemini_cache_name then return false end
  if S.gemini_cache_creating then return false end
  if not Net.gemini_cache_is_usable() then return false end
  -- Throttle: at most one renew attempt per dedupe window so a burst of sends
  -- doesn't fire 10 PATCHes back-to-back.
  local now = os.time()
  if (S.gemini_cache_last_renew or 0) > now - GEMINI_CACHE_RENEW_DEDUPE then
    return false
  end
  local remaining = (S.gemini_cache_expires or 0) - now
  return remaining > 0 and remaining < GEMINI_CACHE_RENEW_THRESHOLD
end

function Net.fire_gemini_cache_renew()
  local cache_name = S.gemini_cache_name
  if not cache_name or cache_name == "" then return end
  local google_key = S.api_key_map and S.api_key_map.google
  if not google_key then return end
  if not Code.safe_write(tmp.gemini_auth, "x-goog-api-key: " .. google_key) then return end
  local body = str_format('{"ttl":"%ds"}', GEMINI_CACHE_TTL_SECS)
  if not Code.safe_write(tmp.cache_body, body) then return end
  local url = str_format(
    "https://generativelanguage.googleapis.com/v1beta/%s",
    cache_name)
  if RA.IS_WINDOWS then
    local cmd_line = str_format(
      'curl -s -X PATCH %s'
      .. ' -H """content-type: application/json"""'
      .. ' -H @"""%s"""'
      .. ' -d @"""%s""" -o NUL'
      .. ' & del """%s""" & del """%s"""',
      url, tmp.gemini_auth, tmp.cache_body,
      tmp.gemini_auth, tmp.cache_body)
    local ps_cmd = str_format(
      'powershell -NoProfile -WindowStyle Hidden'
      .. ' -Command "Start-Process cmd -ArgumentList \'/c %s\''
      .. ' -WindowStyle Hidden"',
      cmd_line:gsub("'", "''"))
    reaper.ExecProcess(ps_cmd, 2000)
  else
    local function sq(path) return "'" .. path:gsub("'", "'\\''") .. "'" end
    os.execute(str_format(
      '(curl -s -X PATCH -H "content-type: application/json"'
      .. ' -H @%s -d @%s %s > /dev/null 2>&1 ; rm -f %s %s) &',
      sq(tmp.gemini_auth), sq(tmp.cache_body), url,
      sq(tmp.gemini_auth), sq(tmp.cache_body)))
  end
  -- Optimistically bump local expiry. If the PATCH fails server-side, the
  -- next send hits 404 and Net.gemini_cache_invalidate clears state cleanly.
  S.gemini_cache_expires    = os.time() + GEMINI_CACHE_TTL_SECS
  S.gemini_cache_last_renew = os.time()
  Net.gemini_cache_persist()
  Log.line("GEMINI_CACHE", "renew fired for " .. cache_name
    .. " (new TTL " .. GEMINI_CACHE_TTL_SECS .. "s, optimistic)")
end

-- =============================================================================
-- Net.try_finish_gemini_cache_create
-- =============================================================================
-- Polled from the main loop while S.gemini_cache_creating is true. Reads the
-- response file, parses the cache name and expireTime, and stores them for
-- subsequent send_to_api calls to pick up via gemini_cache_is_usable.
function Net.try_finish_gemini_cache_create()
  if not S.gemini_cache_creating then return end

  -- Watchdog: if the cache-create curl hasn't resolved within 45 seconds
  -- (curl's own --max-time is 30s; we allow 15s of slack for PowerShell
  -- launch delay and fs lag), give up and unstick state so caching stays
  -- functional for the rest of the session.
  local started = S.gemini_cache_started_at or 0
  if started > 0 and (reaper.time_precise() - started) > 45 then
    S.gemini_cache_creating = false
    S.gemini_cache_model    = nil
    S.gemini_cache_signature = nil
    S.gemini_cache_last_create_reason = "watchdog_timeout"
    os.remove(tmp.cache_exit)
    Code.safe_write(tmp.cache_out, "")
    return
  end

  -- Exit code first (network error path). A nonzero code means curl failed
  -- outright; an exit code 0 means curl completed, so we must parse the
  -- response body even if it isn't JSON -- otherwise a proxy HTML page
  -- would silently pin us in the "creating" state forever.
  local curl_done = false
  do
    local ok_ef, ef = pcall(io.open, tmp.cache_exit, "r")
    if ok_ef and ef then
      local exit_str = ef:read("*a"); ef:close()
      local exit_code = tonumber(exit_str:match("(%d+)"))
      if exit_code and exit_code ~= 0 then
        S.gemini_cache_creating = false
        S.gemini_cache_model    = nil
        S.gemini_cache_signature = nil
        S.gemini_cache_last_create_reason = "curl_exit_" .. tostring(exit_code)
        os.remove(tmp.cache_exit)
        return
      elseif exit_code == 0 then
        curl_done = true
        os.remove(tmp.cache_exit)
      end
    end
  end

  -- Response body. If curl hasn't exited yet, bail out partial -- we only
  -- commit to parsing once we know the write is complete.
  local ok_f, f = pcall(io.open, tmp.cache_out, "r")
  if not ok_f or not f then return end
  local raw = f:read("*a"); f:close()
  if not curl_done then
    if #raw < 10 then return end
    local last_char = raw:match("(%S)%s*$")
    if last_char ~= "}" then return end
  end

  S.gemini_cache_creating = false
  Code.safe_write(tmp.cache_out, "")

  local resp = JSON.decode(raw)
  if type(resp) ~= "table" then
    -- Non-JSON response (e.g. proxy HTML); caching stays unusable this turn
    -- but the "creating" flag is already cleared so future sends can retry.
    S.gemini_cache_model = nil
    S.gemini_cache_signature = nil
    S.gemini_cache_last_create_reason = "non_json_response"
    return
  end

  -- Error envelope: {"error":{"code":N,"message":"...","status":"..."}}
  if type(resp.error) == "table" and resp.error ~= JSON.NULL then
    S.gemini_cache_model = nil
    S.gemini_cache_signature = nil
    local err = resp.error
    S.gemini_cache_last_create_reason =
      "api_error_" .. tostring(err.status or err.code or "unknown")
    return
  end

  -- Success: {"name":"cachedContents/abc","model":"models/...","expireTime":"..."}
  if type(resp.name) == "string" and resp.name ~= "" then
    S.gemini_cache_name = resp.name
    S.gemini_cache_signature = S.gemini_cache_signature
      or Net.gemini_cache_source_signature(S.api_ref_message)
    -- We set ttl=3600s in the create request, so expires = now + TTL is
    -- accurate. The server also returns expireTime (RFC3339 UTC) but parsing
    -- it via os.time() applies local-timezone offset and skews the result.
    S.gemini_cache_expires = os.time() + GEMINI_CACHE_TTL_SECS
    Net.gemini_cache_persist()  -- survive script restart
    S.gemini_cache_last_create_reason = "success"
  else
    S.gemini_cache_model = nil
    S.gemini_cache_signature = nil
    S.gemini_cache_last_create_reason = "missing_cache_name"
  end
end

-- =============================================================================
-- Net.send_to_api
-- =============================================================================
-- Entry point for every user-initiated send.
--
-- Flow:
--   1. Capture the active project tab (EnumProjects(-1)).
--   2. Build a fresh session snapshot if "Send snapshot" is on.
--   3. Load the API reference into the pinned message slot on first send of the
--      session if "Always include REAPER API reference" is on. The pinned message is prepended to every
--      API call by Net.build_body() outside the sliding window, keeping its cache
--      position stable.
--   4. Push the user text to S.history (snapshot and API ref are NOT stored here).
--   5. Preflight token estimation: abort with a friendly error if the request
--      would exceed the model's 200K context window (rough chars/4 heuristic).
--   6. Fire curl. The snapshot is injected by Net.build_body(), not stored in S.history.
function Net.send_to_api(user_text)
  -- Phase 1 instrumentation: open a Probe turn at the outermost
  -- boundary. Probe is currently an in-line no-op compatibility surface
  -- so older instrumentation call sites stay harmless while the local
  -- probe module is retired. If a previous turn somehow didn't reach an
  -- end_turn site (re-entrance, missed exit path), close it as "aborted"
  -- before clobbering S.probe_turn with the new handle.
  if S.probe_turn then
    Probe.end_turn(S.probe_turn, "aborted")
    S.probe_turn = nil
  end
  local probe_turn = Probe.start_turn(user_text)
  S.probe_turn = probe_turn
  -- Phase 1 instrumentation: preempt phase covers all per-turn setup
  -- before the first body build (state resets, snapshot capture,
  -- ref/midi/theme auto-injection, sticky eviction, preempt bucket
  -- injection). Ends just before Net.build_body is first called.
  Probe.mark_phase_start(probe_turn, "preempt")

  S.status                = "waiting"
  S.request_start_time    = reaper.time_precise()
  S.pending_code          = nil
  S.docs_already_sent     = false
  S.docs_extended_already_sent = false
  S.docs_section_sent     = {}
  S.session_already_sent  = false
  S.fx_params_already_sent = false
  S.plugin_ref_sent        = {}
  S.pending_resolves       = {}
  S.pending_plugin_ref_names = {}
  S.pending_pref_plugin_types = {}
  S.context_loop_retries   = 0
  S.api_validator_retries  = 0
  S.action_validator_retries = 0
  S.transient_validator_retries = 0
  S.drum_quantize_validator_retries = 0
  S.drum_marker_sync_validator_retries = 0
  S.arity_validator_retries = 0
  S.sendidx_validator_retries = 0
  S.stockfx_validator_retries = 0
  S.fxident_validator_retries = 0
  S.typed_action_format_validator_retries = 0
  S.typed_action_schema_validator_retries = 0
  S.typed_action_semantic_validator_retries = 0
  S.typed_action_retry_offset = 0
  S.typed_action_escalation_used = false
  S.typed_action_escalation_count = 0
  S.typed_action_escalation_model = nil
  S.typed_action_escalation_restore = nil
  S.fxcheck_validator_retries = 0
  S.upsert_validator_retries = 0
  S.helper_int_validator_retries = 0
  S.defer_validator_retries = 0
  S.fx_param_scope_validator_retries = 0
  S.helper_validator_retries = 0
  S.void_return_validator_retries = 0
  S.void_return_retry_used = false
  S.track_creation_validator_retries = 0
  S.track_creation_retry_used = false
  S.track_creation_index_retry_used = false
  S.folder_boundary_retry_used = false
  S.track_index_validator_retries = 0
  S.track_index_retry_used = false
  S.track_selection_validator_retries = 0
  S.track_selection_retry_used = false
  S.track_pan_validator_retries = 0
  S.track_pan_retry_used = false
  S.master_send_validator_retries = 0
  S.master_send_retry_used = false
  S.midi_item_validator_retries = 0
  S.midi_item_retry_used = false
  S.bare_lua_retry_used = false
  S.unclosed_fence_retry_used = false
  S.parse_retry_used       = false
  S.jsfx_validator_retries = 0
  S.length_retry_used      = false
  S.empty_retry_used       = false
  S.api_calls_this_turn    = 0   -- aggregate cap counter (see CFG.MAX_CALLS_PER_TURN)
  S.thinking_override_idx  = nil
  S._context_reuse_hint    = nil
  S._mixed_output_hint     = nil
  S._fx_inspect_dropped    = nil
  S.fx_list_already_sent   = false
  S.fx_chains_already_sent = false
  S.track_flags_already_sent = false
  S.midi_already_sent      = false
  S.pref_plugins_sent      = {}
  S.theme_already_sent     = false
  S.fx_inspect_already_sent = false
  -- Defensive: clear any leftover deferred-assemble or silent-inspect flag
  -- from a cancelled prior turn so this turn isn't poisoned.
  S._fx_params_pending_assemble  = nil
  S._fx_inspect_silent_for_fx_params = nil
  S.pending_orig_prompt   = user_text
  Code.maybe_update_latest_from_user(user_text)
  Code.maybe_mark_latest_candidate_working(user_text)
  S.pending_typed_action_expected = false
  S.pending_typed_action_response_format = false
  S.pending_typed_action_profile = nil
  S.retry_count           = 0          -- reset retry counter for each new user send
  S.retry_max             = CFG.MAX_RETRIES
  S.retry_scheduled       = false

  -- Capture current attachments and clear the queue before any early returns.
  local msg_attachments = #S.attachments > 0 and S.attachments or nil
  S.attachments = {}

  -- Warn if PDFs are attached to a provider that doesn't support them.
  if msg_attachments and PROVIDERS.active().id == "openai" then
    for _, att in ipairs(msg_attachments) do
      if att.kind == "pdf" then
        Log.add_error("ChatGPT does not support PDF attachments. "
          .. "The file name will be sent but its content cannot be read. "
          .. "Try Claude or Gemini for PDF support.")
        break
      end
    end
  end

  -- 1. Reset FX cache event tracking for this exchange.
  S._fx_cache_events = {}  -- keyed by type: { hit = {name, ...}, cached = {...}, annotated = {...} }

  -- 1b. Capture the active project.
  S.pending_project = reaper.EnumProjects(-1)
  if Net.try_local_read_answer(user_text, msg_attachments, probe_turn) then
    return true
  end

  -- 1c. JSFX intent detection. Used by the snapshot tracks-trim and the
  -- plugin_ref / pref / docs preempt skip. Mirrored to S.pending_jsfx_intent
  -- so the JSFX validator-retry path, which rebuilds the snapshot from
  -- outside Net.send_to_api, can keep the same minimal-tracks trim.
  -- The detector is conservative (literal "jsfx" / "eel2" / "reajs" /
  -- "@init"-style markers only) so non-JSFX prompts that happen to
  -- contain DSP words like "shimmer" or "harmonizer" still get full
  -- plugin treatment.
  local jsfx_intent = CTX.prompt_indicates_jsfx(user_text)
  S.pending_jsfx_intent = jsfx_intent or nil
  local drum_edit_intent = CTX.prompt_indicates_drum_edit(user_text)
  S.pending_drum_edit_intent = drum_edit_intent or nil

  -- 2. Build a fresh session snapshot if enabled.
  local snapshot_opts = nil
  if jsfx_intent or drum_edit_intent then
    snapshot_opts = {
      minimal_tracks = jsfx_intent or nil,
      drum_edit = drum_edit_intent or nil,
    }
  end
  local snapshot = prefs.include_snapshot
    and CTX.build_snapshot(S.pending_project, snapshot_opts)
    or nil
  S.pending_snapshot    = snapshot        -- saved for potential docs follow-up
  S.pending_attachments = msg_attachments -- saved for beta-header fallback rebuild

  -- 3. Load the API reference into the pinned slot on first send of the session.
  local ref_injected = false
  if prefs.include_api_ref and not S.api_ref_message then
    local ref_content, ref_err = CTX.docs()
    if ref_content then
      S.api_ref_message = ref_content
      ref_injected    = true
    else
      Log.add_error(ref_err)
    end
  end
  if S.api_ref_message then ref_injected = true end

  -- 3a. MIDI auto-inject: if the user prompt contains the word "midi" as a
  -- standalone token (case-insensitive), pre-load the MIDI reference into the
  -- pinned slot. This avoids a context_needed round-trip when the prompt is
  -- clearly MIDI-related. The model can also request it explicitly via
  -- <context_needed>midi</context_needed> for prompts that imply MIDI without
  -- saying it (e.g. "transpose those notes"). Once loaded, it stays loaded
  -- for the rest of the session and is cached at the top of the prefix.
  local midi_injected = false
  if not S.midi_ref_message then
    -- Match "midi" with non-letter boundaries on both sides (Lua has no \b).
    local lower_text = user_text:lower()
    local has_midi = false
    if lower_text == "midi" or lower_text:match("^midi[^%a]")
       or lower_text:match("[^%a]midi$") or lower_text:match("[^%a]midi[^%a]") then
      has_midi = true
    end
    if has_midi then
      local mref_content, mref_err = CTX.midi()
      if mref_content then
        S.midi_ref_message = mref_content
        midi_injected = true
      else
        Log.add_error(mref_err)
      end
    end
  end
  if S.midi_ref_message then midi_injected = true end

  -- 3b. Gemini: kick off an async context cache create if eligible and no
  -- live cache exists yet. Non-blocking -- this send proceeds without the
  -- cache if it's not ready, and subsequent sends pick it up when it lands.
  if PROVIDERS.active().id == "google" then
    Net.gemini_cache_ensure()
  end

  -- 3c. Theme auto-inject: detect requests to change REAPER's UI appearance.
  -- Two paths:
  --   A) Prompt contains "theme" + any color/appearance word.
  --   B) Prompt contains a REAPER UI element name + a color/appearance action.
  -- This avoids a context_needed round-trip. The model can also request the
  -- bucket explicitly via <context_needed>theme</context_needed>.
  local theme_injected = false
  if not S.theme_already_sent then
    local lt = user_text:lower()
    -- Appearance action words.
    local has_appearance = lt:find("color") or lt:find("colour")
      or lt:find("background") or lt:find("darker") or lt:find("lighter")
      or lt:find("bright") or lt:find("appearance")
    -- Path A: "theme" as a standalone token + appearance word.
    local has_theme_word = lt:match("[^%a]theme[^%a]") or lt:match("^theme[^%a]")
      or lt:match("[^%a]theme$") or lt == "theme"
    -- Path B: REAPER UI element name + appearance action (covers "make the
    -- arrange darker", "change waveform color", "mixer background", etc.).
    local has_ui_element = lt:find("arrange") or lt:find("mixer")
      or lt:find("track panel") or lt:find("tcp") or lt:find("mcp")
      or lt:find("waveform") or lt:find("peaks") or lt:find("cursor")
      or lt:find("grid") or lt:find("meter") or lt:find("timeline")
      or lt:find("ruler") or lt:find("transport") or lt:find("marker")
      or lt:find("region") or lt:find("envelope") or lt:find("midi editor")
    if has_appearance and (has_theme_word or has_ui_element) then
      local th_content, th_err = CTX.theme()
      if th_content then
        S.theme_ref_message = th_content
          .. "\n\n(Theme reference is loaded above. Do NOT request "
          .. "<context_needed>theme</context_needed> or "
          .. "<context_needed>session</context_needed> -- you have "
          .. "everything needed. Proceed directly with the color change code.)"
        theme_injected = true
        S.theme_already_sent = true
      end
    end
  end
  if S.theme_ref_message then theme_injected = true end

  -- Preemptive bucket injection. If the user's prompt mentions a plugin
  -- type they have a saved preferred plugin for ("add a compressor",
  -- "change the eq band 2 freq"), inject the preferred_plugins content
  -- into sticky_context right here so the model sees it on the FIRST
  -- API call. Saves one <context_needed> round trip in the common case.
  -- No-op when the user has no preferred_types configured or when their
  -- prompt mentions no matching keyword. See CTX.preempt_buckets_for_prompt.
  --
  -- Bump the turn counter and prune stale sticky_context entries first, so
  -- preempt's relevance-driven re-touches happen against a fresh state and
  -- this turn's adds don't get accidentally evicted by their own arrival.
  local typed_action_backup_ready = true
  if prefs.auto_backup then
    local _, typed_action_proj_path = reaper.EnumProjects(-1)
    typed_action_backup_ready = type(typed_action_proj_path) == "string"
      and typed_action_proj_path:match("%.[rR][pP][pP]$") ~= nil
  end
  local active_provider = PROVIDERS.active()
  local active_model = MODELS[prefs.model_idx] or MODELS[1]
  local typed_action_profile =
    Code.typed_actions_model_profile(active_provider.id,
      active_model and active_model.id or nil)
  local typed_action_response_format =
    active_provider.id == "openai"
  local typed_action_contract =
    (prefs.auto_run and typed_action_backup_ready)
    and Code.typed_actions_prompt_contract(user_text, {
      response_format = typed_action_response_format,
      profile = typed_action_profile,
    }) or nil
  local typed_action_plan_prompt =
    CTX.prompt_indicates_typed_action_plan(user_text)
  local reascript_prompt = false
  do
    local lt = user_text:lower()
    local edit_verb =
         lt:find("%f[%w]create%f[%W]") ~= nil
      or lt:find("%f[%w]add%f[%W]") ~= nil
      or lt:find("%f[%w]make%f[%W]") ~= nil
      or lt:find("%f[%w]insert%f[%W]") ~= nil
      or lt:find("%f[%w]rename%f[%W]") ~= nil
      or lt:find("%f[%w]delete%f[%W]") ~= nil
      or lt:find("%f[%w]remove%f[%W]") ~= nil
      or lt:find("%f[%w]route%f[%W]") ~= nil
      or lt:find("%f[%w]send%f[%W]") ~= nil
      or lt:find("%f[%w]split%f[%W]") ~= nil
      or lt:find("%f[%w]select%f[%W]") ~= nil
    local edit_noun =
         lt:find("%f[%w]track%f[%W]") ~= nil
      or lt:find("%f[%w]tracks%f[%W]") ~= nil
      or lt:find("%f[%w]item%f[%W]") ~= nil
      or lt:find("%f[%w]items%f[%W]") ~= nil
      or lt:find("%f[%w]marker%f[%W]") ~= nil
      or lt:find("%f[%w]region%f[%W]") ~= nil
      or lt:find("%f[%w]midi%f[%W]") ~= nil
      or lt:find("%f[%w]fx%f[%W]") ~= nil
      or lt:find("%f[%w]effect%f[%W]") ~= nil
      or lt:find("%f[%w]plugin%f[%W]") ~= nil
      or lt:find("%f[%w]send%f[%W]") ~= nil
      or lt:find("%f[%w]bus%f[%W]") ~= nil
      or lt:find("%f[%w]folder%f[%W]") ~= nil
      or lt:find("%f[%w]envelope%f[%W]") ~= nil
      or lt:find("%f[%w]automation%f[%W]") ~= nil
    local qna_prompt =
         lt:find("^%s*how%s+") ~= nil
      or lt:find("^%s*what%s+") ~= nil
      or lt:find("^%s*why%s+") ~= nil
      or lt:find("^%s*where%s+") ~= nil
      or lt:find("^%s*when%s+") ~= nil
      or lt:find("^%s*is%s+") ~= nil
      or lt:find("^%s*are%s+") ~= nil
    reascript_prompt =
         lt:find("reaper lua script", 1, true) ~= nil
      or lt:find("reascript", 1, true) ~= nil
      or lt:find("lua script", 1, true) ~= nil
      or (lt:find("write", 1, true) ~= nil
          and lt:find("script", 1, true) ~= nil
          and lt:find("reaper", 1, true) ~= nil)
      or (edit_verb and edit_noun and not qna_prompt)
  end
  local preempted_context = nil
  Net.sticky_evict(user_text)
  if not typed_action_contract and not typed_action_plan_prompt then
    preempted_context = CTX.preempt_buckets_for_prompt(user_text)
  elseif typed_action_plan_prompt then
    Log.line("PREEMPT",
      "skipped context preempt (typed-action plan prompt)")
  end
  if preempted_context and #preempted_context > 0 then
    for _, key in ipairs(preempted_context) do
      if key == "recent_reaper_changes" then
        user_text = "(INTERNAL CONTEXT NOTE -- DO NOT MENTION THIS: "
          .. "Recent REAPER changes are pinned above. Use that bucket "
          .. "for recent or version-specific REAPER feature facts; it "
          .. "overrides stale training data.)\n\n" .. user_text
        break
      end
    end
  end
  if not typed_action_contract
     and not typed_action_plan_prompt
     and reascript_prompt then
    local docs_already = S.api_ref_message ~= nil
    Net.copin_docs_core(preempted_context)
    if not docs_already and S.api_ref_message then
      Log.line("PREEMPT",
        "injected docs (explicit ReaScript/Lua-script prompt)")
    end
  end
  -- Re-evaluate ref-injected flags: preempt's copin_docs_core (and the
  -- chain-phrase preempt path generally) can set S.api_ref_message AFTER
  -- the initial ref_injected probe ran above. Without this, the ctx_label
  -- assembled below misses the "api_ref" tag for any session where docs
  -- was co-pinned only via the preempt path -- the request ships docs
  -- correctly but the Details / Context display omits it. Mirror midi /
  -- theme for symmetry (no preempt path sets them today, but future
  -- co-pin helpers should not need a second touch-up here).
  if S.api_ref_message   then ref_injected   = true end
  if S.midi_ref_message  then midi_injected  = true end
  if S.theme_ref_message then theme_injected = true end

  -- 4. Build the history content: just "USER REQUEST:\n" + prompt.
  -- The API ref is no longer stored in history -- it lives in S.api_ref_message
  -- and is prepended by Net.build_body() on every call. Theme ref likewise
  -- lives in S.theme_ref_message.
  --
  -- Sticky context (plugin_ref, preferred_plugins, fx_params) is emitted by
  -- Net.build_body_* as a pinned user/assistant pair after the api_ref pin,
  -- rather than baked into each user message here. That way the content sits
  -- in a stable prefix position and the providers' caches treat it as part
  -- of the cached prefix, rather than re-writing it into every new turn's
  -- cache breakpoint.
  -- If the previous generated-code execution failed, prepend the error so
  -- the model can self-correct when the user types a follow-up like
  -- "fix that". Cleared after this send -- carrying it indefinitely would
  -- pollute unrelated subsequent prompts.
  -- Snapshot last_run_error before clearing so the two rollback blocks
  -- below can restore it. Without this, a token-budget overflow or
  -- fire_curl failure permanently loses the prior-run error context, so
  -- the next "fix that" retry would send the prompt with no error to fix.
  local _saved_last_run_error = S.last_run_error
  local history_text
  if S.last_run_error and S.last_run_error ~= "" then
    history_text = "PREVIOUS_RUN_ERROR (the code you generated last turn "
      .. "failed when executed):\n" .. S.last_run_error
      .. "\n\nUSER REQUEST:\n" .. user_text
    S.last_run_error = nil
  else
    history_text = "USER REQUEST:\n" .. user_text
  end

  do
    local latest_note = Code.latest_code_followup_note(user_text)
    if latest_note then
      history_text = latest_note .. "\n\n" .. history_text
    end
  end

  if not typed_action_contract and reascript_prompt then
    local ref_note = S.api_ref_message
      and (" Core REAPER API docs are already pinned above, so do NOT "
        .. "emit <context_needed>docs</context_needed>.")
      or ""
    history_text = "(INTERNAL OUTPUT NOTE -- DO NOT MENTION THIS: "
      .. "If you generate Lua/ReaScript for this request, return the "
      .. "entire runnable script inside one complete ```lua ... ``` "
      .. "code fence. Do not return bare Lua." .. ref_note .. ")\n\n"
      .. history_text
  end

  if not typed_action_contract
     and type(preempted_context) == "table"
     and #preempted_context > 0 then
    local seen_resolve, resolved_tags = {}, {}
    for _, key in ipairs(preempted_context) do
      if type(key) == "string" then
        local tkey = key:match("^pref:(.+)$")
        if tkey and not seen_resolve[tkey] then
          seen_resolve[tkey] = true
          resolved_tags[#resolved_tags + 1] = "resolve:" .. tkey
        end
      end
    end
    if #resolved_tags > 0 then
      table.sort(resolved_tags)
      history_text = "(INTERNAL CONTEXT NOTE -- DO NOT MENTION THIS: "
        .. "The generic plugin type(s) for this request are already "
        .. "resolved and pinned above: " .. tbl_concat(resolved_tags, ", ")
        .. ". Do NOT emit <context_needed> for these resolve tags. "
        .. "Use the pinned plugin_ref / preferred-plugin content now.)\n\n"
        .. history_text
    end
  end

  if typed_action_contract then
    history_text = history_text .. "\n\n" .. typed_action_contract
    S.pending_typed_action_expected = true
    S.pending_typed_action_response_format = typed_action_response_format
    S.pending_typed_action_profile =
      typed_action_profile and typed_action_profile.key or nil
  end

  -- Collect sticky labels for the Show Details display (the content itself
  -- is emitted downstream by build_body_*).
  local sticky_labels = {}
  for key, _ in pairs(S.sticky_context) do
    sticky_labels[#sticky_labels+1] = key
  end

  -- Context label for Show Details display.
  local ctx_parts = {}
  if prefs.include_snapshot then ctx_parts[#ctx_parts+1] = "snapshot" end
  if ref_injected   then ctx_parts[#ctx_parts+1] = "api_ref" end
  if midi_injected  then ctx_parts[#ctx_parts+1] = "midi"    end
  if theme_injected then ctx_parts[#ctx_parts+1] = "theme"   end
  if typed_action_contract then ctx_parts[#ctx_parts+1] = "typed_actions" end
  if msg_attachments then
    for _, a in ipairs(msg_attachments) do ctx_parts[#ctx_parts+1] = a.name end
  end
  -- Append sticky context labels so Show Details reflects what was re-injected.
  table.sort(sticky_labels)
  for _, lbl in ipairs(sticky_labels) do ctx_parts[#ctx_parts+1] = lbl end
  local ctx_label = #ctx_parts > 0 and tbl_concat(ctx_parts, " + ") or "none"

  -- Push to history (without snapshot) and display (bare prompt).
  S.history[#S.history+1] = { role = "user", content = history_text }
  local disp_idx = #S.display_messages + 1
  -- Build a summary of attachments for display in the chat bubble.
  local attach_summary = nil
  if msg_attachments then
    local parts = {}
    for _, a in ipairs(msg_attachments) do
      parts[#parts+1] = a.name
    end
    attach_summary = parts
  end
  S.display_messages[disp_idx] = {
    role           = "user",
    content        = user_text,
    ctx_label      = ctx_label,
    model_label    = PROVIDERS.active().label .. " " .. (function()
      -- Fall back to MODELS[1] (or "?") when MODELS[prefs.model_idx] is
      -- nil. Indexing nil here used to throw on a custom provider whose
      -- models array was cleared mid-session, or briefly after a
      -- provider switch where prefs.model_idx temporarily points past
      -- the new provider's list before MODELS.refresh re-clamps it.
      local _m = MODELS[prefs.model_idx] or MODELS[1]
      return _m and _m.label or "?"
    end)(),
    provider_id    = PROVIDERS.active().id,
    thinking_label = (function()
      local p = PROVIDERS.active()
      if p.thinking_levels and prefs.thinking_idx > 0 then
        local tl = p.thinking_levels[prefs.thinking_idx]
        if tl then return tl.label end
      end
    end)(),
    attach_names   = attach_summary,
    from_card      = S.from_card or nil,
  }
  S.from_card = false
  S.pending_display_idx = disp_idx

  -- 5. Preflight token estimation: abort before sending if the request would
  -- exceed the model's context window. Uses a ~4 chars/token heuristic; false
  -- positives are acceptable -- better to warn than waste API time. For
  -- attachments, add their estimated token counts directly.
  --
  -- Per-model context_window on the active model wins. Built-in providers
  -- now carry context_window on each model entry where it differs from the
  -- 200K default (Sonnet/Opus 1M, GPT-5.4 nano/mini 400K, GPT-5.4 1.05M,
  -- Gemini 3.x 1,048,576, DeepSeek V4 Flash 1M); a provider-level
  -- field is honored as a fallback if a model row omits it. Custom
  -- providers always carry context_window per-model (set by the user on
  -- the API Keys page from each loaded model's actual server-side limit;
  -- exceeding it on a local llama.cpp server either truncates the prompt
  -- or starts evicting tokens from the front of the cache). Final fallback
  -- is 200K, the floor every cloud provider we ship still honors. A model
  -- without context_window AND a provider with no fallback (e.g. Claude
  -- Haiku 4.5) lands on the 200K default.
  local active_provider     = PROVIDERS.active()
  local active_model        = MODELS[prefs.model_idx] or MODELS[1]
  local MODEL_CONTEXT_LIMIT = (active_model and tonumber(active_model.context_window))
                              or tonumber(active_provider.context_window)
                              or 200000
  local CHARS_PER_TOKEN     = 4       -- ~4 for prose, ~3 for code, ~5 for JSON keys; 4 is a safe middle
  -- Phase 1 instrumentation: preempt phase ends here. body_build is
  -- timed inside Net.build_body itself (entry/exit wrap), so the
  -- gap between mark_phase_end("preempt") and Net.build_body's
  -- internal mark_phase_start("body_build") is negligible.
  Probe.mark_phase_end(probe_turn, "preempt")
  -- Gemini explicit cache eligibility can appear late in preempt: the
  -- ReaScript prompt path may co-pin API docs after the early ensure above.
  -- Re-check here, once all static refs for this request are settled.
  if PROVIDERS.active().id == "google" then
    Net.gemini_cache_ensure()
  end
  local body = Net.build_body(Net.trimmed_history(), snapshot, msg_attachments)
  -- Phase 1 instrumentation: byte accounting for the request body.
  -- Pre-escape source bytes (raw strings before JSON encoding inflates
  -- them) for each known source bucket, plus the final assembled
  -- JSON body bytes. Captures only the initial request -- multi-request
  -- turns (context_needed re-fires, retries) re-build the body with
  -- inline build_body calls and are NOT accumulated here. body_build
  -- phase latency does accumulate across all such calls (instrumented
  -- inside Net.build_body itself).
  do
    local sys = Net.system_prompt_text()
    if sys then Probe.add_bytes(probe_turn, "system_prompt", #sys) end
    local static_total = 0
    if S.api_ref_message   then static_total = static_total + #S.api_ref_message   end
    if S.midi_ref_message  then static_total = static_total + #S.midi_ref_message  end
    if S.theme_ref_message then static_total = static_total + #S.theme_ref_message end
    if static_total > 0 then Probe.add_bytes(probe_turn, "static_refs", static_total) end
    local sticky_total = 0
    for _, content in pairs(S.sticky_context or {}) do
      if type(content) == "string" then
        sticky_total = sticky_total + #content
      end
    end
    if sticky_total > 0 then Probe.add_bytes(probe_turn, "sticky_refs", sticky_total) end
    if snapshot then Probe.add_bytes(probe_turn, "snapshot", #snapshot) end
    if msg_attachments then
      local att_total = 0
      for _, a in ipairs(msg_attachments) do
        if a.b64       then att_total = att_total + #a.b64
        elseif a.data  then att_total = att_total + #a.data
        end
      end
      if att_total > 0 then Probe.add_bytes(probe_turn, "attachments", att_total) end
    end
    Probe.set_body_total(probe_turn, #body)
  end
  local estimated_tokens = math_floor(#body / CHARS_PER_TOKEN)
  -- Base64 inflates size ~33%, so compensate: attachment tokens are more accurate
  -- than the chars/4 heuristic on the inflated base64. Subtract the base64 size
  -- contribution and add the pre-computed token estimates instead.
  --
  -- Text attachments are inlined into the body as raw UTF-8 (not base64), so
  -- they are ALREADY counted by the #body/4 heuristic above. Re-adding a.tokens
  -- for text attachments would double-count them and trigger false-positive
  -- context overflows for large pasted logs. Skip them here.
  --
  -- Read the contribution from a.b64 (the encoded string actually inlined into
  -- the body), NOT a.data: Attach.pump_encoding nils out a.data once encoding
  -- is complete to avoid carrying two copies of large attachments in memory.
  if msg_attachments then
    for _, a in ipairs(msg_attachments) do
      if a.kind ~= "text" and a.b64 then
        local b64_chars_est = math_floor(#a.b64 / CHARS_PER_TOKEN)
        estimated_tokens = estimated_tokens - b64_chars_est + a.tokens
      end
    end
  end
  -- Reserve output space inside the context window. Each cloud model has
  -- its own published output ceiling (max_output, 64K-128K); reserve that
  -- so a maxed-out reply doesn't blow the model's context window. Custom
  -- local LLMs often have tight context windows (16K-32K) where reserving
  -- the full output cap would leave almost no room for the API ref + prompt
  -- -- cap the reserve at 10% of context. The custom server enforces its
  -- own real limit (finish_reason=length if output overflows), so the reserve
  -- only needs to guarantee a short reply has room.
  local cloud_output_cap = (active_model and tonumber(active_model.max_output)) or 16384
  local output_reserve = active_provider.is_custom
    and math_min(cloud_output_cap, math_floor(MODEL_CONTEXT_LIMIT * 0.1))
    or cloud_output_cap
  local token_budget   = MODEL_CONTEXT_LIMIT - output_reserve

  if estimated_tokens > token_budget then
    -- Roll back the history and display entries we just pushed, AND restore the
    -- user's typed prompt + attachments to the input area so they don't lose
    -- their work. The user can trim attachments or clear and retry without
    -- re-typing.
    S.history[#S.history]          = nil
    S.display_messages[disp_idx] = nil
    S.pending_display_idx        = nil
    S.status    = "error"
    S.send_time = nil
    S.input_buf = user_text
    if msg_attachments then S.attachments = msg_attachments end
    -- Clear the pending_* / event-tracking state populated earlier in this
    -- function (lines ~16555-16585) so a context-needed handler firing later
    -- doesn't pick up stale snapshot/project/prompt from a turn that never
    -- actually sent. The _already_sent resets at ~16549-16580 are
    -- intentionally left applied; the next attempt should re-run those
    -- buckets fresh.
    S.pending_orig_prompt  = nil
    S.pending_typed_action_expected = false
    S.pending_typed_action_response_format = false
    S.pending_typed_action_profile = nil
    S.pending_project      = nil
    S.pending_snapshot     = nil
    S.pending_attachments  = nil
    S._fx_cache_events     = nil
    -- Restore last_run_error so a "fix that" retry still has the prior-run
    -- error context.
    S.last_run_error       = _saved_last_run_error
    Log.add_error(str_format(
      "Your message is too large to send (about %dk tokens, limit is ~%dk)."
      .. "\n\nYour message and attachments have been restored to the input box. "
      .. "To make it fit:\n"
      .. "- Remove large attachments\n"
      .. "- Turn off \"Always include REAPER API reference\" or Send snapshot to reduce size\n"
      .. "- Or click + new chat to start fresh",
      math_floor(estimated_tokens / 1000),
      math_floor(token_budget / 1000)))
    S.scroll_to_bottom = true
    -- Phase 1 instrumentation: turn aborted before any HTTP traffic.
    Probe.end_turn(probe_turn, "aborted")
    S.probe_turn = nil
    return
  end

  -- 6. Fire the API call (reuse the body already built by the preflight check).
  if not Net.fire_curl(body) then
    -- Roll back on failure and restore the user's input so they can retry.
    S.history[#S.history]          = nil
    S.display_messages[disp_idx] = nil
    S.pending_display_idx        = nil
    S.status    = "error"
    S.send_time = nil
    S.input_buf = user_text
    if msg_attachments then S.attachments = msg_attachments end
    -- Clear pending_* / event-tracking state and restore last_run_error;
    -- mirrors the token-budget rollback above.
    S.pending_orig_prompt  = nil
    S.pending_typed_action_expected = false
    S.pending_typed_action_response_format = false
    S.pending_typed_action_profile = nil
    S.pending_project      = nil
    S.pending_snapshot     = nil
    S.pending_attachments  = nil
    S._fx_cache_events     = nil
    S.last_run_error       = _saved_last_run_error
    Log.add_error(
      "Couldn't send. Another request may still be in progress. "
      .. "Wait a moment and try again.")
    -- Phase 1 instrumentation: turn ended at fire_curl failure. No
    -- early-return here -- the original code falls through to the
    -- shared scroll_to_bottom assignment, so we let it. The natural-
    -- end Probe.end_turn below is idempotent and a no-op after this.
    Probe.end_turn(probe_turn, "error")
    S.probe_turn = nil
  end

  S.scroll_to_bottom = true
  -- Phase 1 instrumentation: NOTE that on the success path of
  -- send_to_api, the turn is NOT ended here. The request was just
  -- handed off to curl; the response is still pending. The turn
  -- handle stays alive on S.probe_turn and is ended at the canonical
  -- "turn completed successfully" site inside Net.try_finish_curl.
  -- Step 9 audits and adds remaining error/cancel exit paths.
end

function Net.resend_saved_prompt(user_text, attachments)
  user_text = tostring(user_text or ""):match("^%s*(.-)%s*$")
  if user_text == "" then return false, "No saved message to resend." end
  local queued = S.attachments or {}
  S.attachments = type(attachments) == "table" and attachments or {}
  local ok, err = pcall(Net.send_to_api, user_text)
  S.attachments = queued
  if not ok then
    return false, tostring(err or "Could not resend the message.")
  end
  return true
end

-- =============================================================================
-- Net.clear_conversation
-- =============================================================================
-- Resets all conversation, token, cost, and pending state. The API reference
-- file content cache is preserved (file doesn't change). S.api_ref_message is
-- cleared so it is re-pinned on the next send; the Gemini explicit cache is
-- app-scoped static reference state and remains usable when its source
-- signature still matches.
function Net.clear_conversation(opts)
  local clear_gemini_cache =
    type(opts) == "table" and opts.clear_gemini_cache == true
  -- =========================================================================
  -- CLEAR CONVERSATION -- reset every conversation-scoped piece of S.* state.
  -- =========================================================================
  -- IMPORTANT: When you add a new conversation-scoped field to S (anything
  -- that grows with messages, tracks per-turn flags, holds pending follow-up
  -- data, or accumulates session totals like token/cost counters), add it
  -- below. Do NOT add app-scoped state here (UI prefs, model picks, cache
  -- warmth, network in-flight tracking) -- those should survive a chat clear.
  -- =========================================================================
  -- Conversation history + display
  if Diag.uploader_enabled and Diag.capture_current_chat then
    Diag.capture_current_chat()
  end
  S.history              = {}
  S.display_messages     = {}
  S.sticky_context       = {}
  S.sticky_context_age   = {}
  S.sticky_context_order = {}
  -- Per-key source tag: "preempt" (pinned by CTX.preempt_buckets_for_prompt
  -- in the same pre-request batch as other stable bundles), "copin" (pinned
  -- by a deterministic mid-flow path like the dispatcher write-intent paths
  -- or the helper-validator retry), or "context_needed" (pulled in response
  -- to a model <context_needed> tag). Drives the prompt_bundle:plugin_helpers
  -- routing in Net.sticky_parts: only "preempt" promotes helpers to the
  -- stable rung; the others keep helpers in the growing rung where mid-
  -- session pins don't invalidate the bigger stable bundle.
  S.sticky_pin_source    = {}
  S.turn_counter         = 0
  S.last_run_error       = nil
  -- Pending follow-up state (mid-flight when clear is hit)
  Net._restore_typed_action_escalation_model()
  S.pending_code         = nil
  S.pending_orig_prompt  = nil
  S.pending_typed_action_expected = false
  S.pending_typed_action_response_format = false
  S.pending_typed_action_profile = nil
  S.pending_snapshot     = nil
  S.pending_project      = nil
  S.pending_display_idx  = nil
  S.pending_resolves          = {}
  S.pending_plugin_ref_names  = {}
  S.pending_pref_plugin_types = {}
  S.pending_attachments       = nil
  S.pending_provider_idx      = nil
  S.pending_model_idx         = nil
  S.pending_jsfx_intent       = nil
  S.pending_drum_edit_intent  = nil
  -- Per-turn one-shot guards
  S.docs_already_sent          = false
  S.docs_extended_already_sent = false
  S.docs_section_sent          = {}
  S.session_already_sent       = false
  S.fx_params_already_sent     = false
  S.fx_list_already_sent       = false
  S.fx_chains_already_sent     = false
  S.track_flags_already_sent   = false
  S.midi_already_sent          = false
  S.theme_already_sent         = false
  S.fx_inspect_already_sent    = false
  S.plugin_ref_sent            = {}
  S.pref_plugins_sent          = {}
  S.context_loop_retries       = 0
  S.api_validator_retries      = 0
  S.action_validator_retries   = 0
  S.transient_validator_retries = 0
  S.drum_quantize_validator_retries = 0
  S.drum_marker_sync_validator_retries = 0
  S.arity_validator_retries    = 0
  S.sendidx_validator_retries  = 0
  S.stockfx_validator_retries  = 0
  S.fxident_validator_retries  = 0
  S.typed_action_format_validator_retries = 0
  S.typed_action_schema_validator_retries = 0
  S.typed_action_semantic_validator_retries = 0
  S.typed_action_retry_offset = 0
  S.typed_action_escalation_used = false
  S.typed_action_escalation_count = 0
  S.typed_action_escalation_model = nil
  S.typed_action_escalation_restore = nil
  S.fxcheck_validator_retries  = 0
  S.upsert_validator_retries   = 0
  S.helper_int_validator_retries = 0
  S.defer_validator_retries    = 0
  S.fx_param_scope_validator_retries = 0
  S.helper_validator_retries   = 0
  S.void_return_validator_retries = 0
  S.void_return_retry_used     = false
  S.track_creation_validator_retries = 0
  S.track_creation_retry_used   = false
  S.track_creation_index_retry_used = false
  S.folder_boundary_retry_used = false
  S.track_index_validator_retries = 0
  S.track_index_retry_used = false
  S.track_selection_validator_retries = 0
  S.track_selection_retry_used = false
  S.track_pan_validator_retries = 0
  S.track_pan_retry_used = false
  S.master_send_validator_retries = 0
  S.master_send_retry_used = false
  S.midi_item_validator_retries = 0
  S.midi_item_retry_used       = false
  S.bare_lua_retry_used        = false
  S.unclosed_fence_retry_used  = false
  S.parse_retry_used           = false
  S.jsfx_validator_retries     = 0
  S.length_retry_used          = false
  S.empty_retry_used           = false
  S.api_calls_this_turn        = 0
  S.thinking_override_idx      = nil
  S._context_reuse_hint        = nil
  S._mixed_output_hint         = nil
  S._fx_inspect_dropped        = nil
  -- Defensive clear of fx_inspect -> fx_params handoff state (also reset per
  -- send_to_api; mirroring here keeps mid-flow clears from poisoning the
  -- next conversation).
  S._fx_params_pending_assemble       = nil
  S._fx_inspect_silent_for_fx_params  = nil
  S._resolve_deep_scan_attempted      = nil
  -- Pinned ref slots -- force reload on next send if relevant prefs are on
  S.api_ref_message      = nil
  S.midi_ref_message     = nil
  S.theme_ref_message    = nil
  -- Session-level docs flag: cleared with the chat since history (where the
  -- inlined docs content lived) is about to be wiped. Next send will either
  -- re-pin via the pref or wait for the model to re-request docs.
  S.docs_fetched_session = false
  -- Resolve popup state (could be open mid-clear; close it cleanly)
  S.resolve_popup             = nil
  S.open_resolve_popup        = false
  S.resolve_popup_text        = ""
  S.resolve_popup_error       = nil
  S.resolve_popup_matches     = {}
  S.resolve_popup_sel         = 0
  S.resolve_popup_last_filter = nil
  S.resolve_popup_refocus     = false
  -- Keep app-scoped Gemini static-reference caches across chat clears. They
  -- contain only the system prompt + API reference, not user conversation
  -- content, and Net.gemini_cache_is_usable verifies the source signature
  -- before reuse. Explicit test/reset paths can still force invalidation.
  if clear_gemini_cache then
    Net.gemini_cache_invalidate()
  end
  -- Session totals
  S.session_tok_in       = 0
  S.session_tok_out      = 0
  S.session_cost         = 0
  -- Retry / attachment state
  S.retry_count          = 0
  S.retry_max            = CFG.MAX_RETRIES
  S.retry_scheduled      = false
  S.retry_saved_body     = nil
  S.attachments          = {}
  S.attach_error         = nil
  S.attach_error_time    = 0
  -- UI / status
  S.status               = "idle"
  S.scroll_to_bottom     = true
  S.wrap_cache           = {}  -- invalidate per-bubble text-wrap cache
  Code.safe_write(tmp.out, "")
  -- Diag uploader: rotate chat_id so subsequent feedback events from this
  -- new conversation group correctly. Guarded by the same uploader_enabled
  -- gate the main-loop Diag.tick() call uses (module may be disabled / not
  -- loaded if RA.JSON wasn't available at dofile time).
  if Diag.uploader_enabled then
    Diag.rotate_chat_id()
  end
end

