function Code.typed_actions_model_profile(provider_id, model_id)
  local by_provider = _TYPED_ACTION_MODEL_PROFILES[tostring(provider_id or "")]
  if not by_provider then return nil end
  return by_provider[tostring(model_id or "")]
end

function Code.typed_actions_model_profile_by_key(key)
  return _TYPED_ACTION_PROFILES_BY_KEY[tostring(key or "")]
end

local function _typed_action_contract_for_profile(contract, profile)
  if not contract or contract == "" then return contract end
  if type(profile) ~= "table" then return contract end
  local extra = profile.extra_prompt
  if type(extra) ~= "string" or extra == "" then return contract end
  return contract .. extra
end

function Code.typed_action_request_specific_help(user_text)
  if not Code.typed_action_user_forbids_track_creation(user_text) then
    return ""
  end
  return [[

REQUEST-SPECIFIC TYPED ACTION RULE:
- The user explicitly forbids creating tracks. Do not emit `track.ensure`.
  Resolve existing target tracks with `track.resolve`, then apply the requested
  `track.set`, `fx.add_stock`, or `send.create` action.
]]
end

local _TYPED_ACTION_SCHEMA_PARAM_KEYS = {
  "band",
  "frequency_hz",
  "gain_db",
  "threshold_db",
  "ceiling_db",
  "attack_ms",
  "release_ms",
  "wet_db",
  "dry_db",
  "rms_ms",
  "feedback_pct",
  "feedback_db",
  "room_size",
  "dampening",
  "hysteresis_db",
  "hold_ms",
}

local function _typed_action_json_type(...)
  local out = {}
  for i = 1, select("#", ...) do out[#out+1] = select(i, ...) end
  return { type = out }
end

local function _typed_action_string_enum(value)
  return { type = "string", enum = { value } }
end

local function _typed_action_required_from_properties(properties)
  local required = {}
  for key in pairs(properties or {}) do required[#required+1] = key end
  table.sort(required)
  return required
end

local function _typed_action_schema_object(properties, required)
  return {
    type = "object",
    properties = properties,
    required = required or _typed_action_required_from_properties(properties),
    additionalProperties = false,
  }
end

local function _typed_action_schema_action(properties, required)
  return _typed_action_schema_object(properties, required)
end

local function _typed_action_schema_params_object()
  local props = {}
  for _, name in ipairs(_TYPED_ACTION_SCHEMA_PARAM_KEYS) do
    props[name] = _typed_action_json_type("number", "null")
  end
  return _typed_action_schema_object(props, _TYPED_ACTION_SCHEMA_PARAM_KEYS)
end

function Code.typed_actions_openai_response_format_field(user_text)
  user_text = tostring(user_text
    or (type(S) == "table" and S.pending_orig_prompt) or "")
  local selected_indexes, selected_index_required =
    Code._typed_action_selected_indexes_from_user_text(user_text)
  local include_track_resolve = true
  local include_track_ensure = true
  local include_absolute_index_resolve =
    not Code._typed_action_forbids_absolute_track_index(user_text)
  if Code.typed_action_user_requests_track_creation(user_text)
     and not Code.typed_action_user_requests_selected_target(user_text) then
    include_track_resolve = false
  elseif Code.typed_action_user_forbids_track_creation(user_text) then
    include_track_ensure = false
  end
  local selected_index_schema = { type = "number" }
  if #selected_indexes > 0 then
    selected_index_schema = { type = "number", enum = selected_indexes }
  end

  local action_variants = {}
  local function add_action(schema)
    action_variants[#action_variants + 1] = schema
  end

  if include_track_ensure then
    add_action(_typed_action_schema_action({
      op = _typed_action_string_enum("track.ensure"),
      id = { type = "string" },
      name = { type = "string" },
      position = _typed_action_json_type("string", "null"),
      select = _typed_action_json_type("boolean", "null"),
    }))
  end

  -- For blank-project/create-track requests, the model has no existing target
  -- to resolve. Do not offer track.resolve in the structured-output schema:
  -- weak models were legally choosing that branch as a fake FX/send placeholder
  -- and then failing semantic validation before any safe mutation could run.
  if include_track_resolve then
    add_action(_typed_action_schema_action({
      op = _typed_action_string_enum("track.resolve"),
      id = { type = "string" },
      name = { type = "string" },
      selected = _typed_action_json_type("null"),
      selected_index = _typed_action_json_type("null"),
      index = _typed_action_json_type("null"),
    }))
    if not selected_index_required then
      add_action(_typed_action_schema_action({
        op = _typed_action_string_enum("track.resolve"),
        id = { type = "string" },
        name = _typed_action_json_type("null"),
        selected = { type = "boolean", enum = { true } },
        selected_index = _typed_action_json_type("null"),
        index = _typed_action_json_type("null"),
      }))
    end
    add_action(_typed_action_schema_action({
      op = _typed_action_string_enum("track.resolve"),
      id = { type = "string" },
      name = _typed_action_json_type("null"),
      selected = _typed_action_json_type("null"),
      selected_index = selected_index_schema,
      index = _typed_action_json_type("null"),
    }))
    if include_absolute_index_resolve then
      add_action(_typed_action_schema_action({
        op = _typed_action_string_enum("track.resolve"),
        id = { type = "string" },
        name = _typed_action_json_type("null"),
        selected = _typed_action_json_type("null"),
        selected_index = _typed_action_json_type("null"),
        index = { type = "number" },
      }))
      add_action(_typed_action_schema_action({
        op = _typed_action_string_enum("track.resolve"),
        id = { type = "string" },
        name = { type = "string" },
        selected = _typed_action_json_type("null"),
        selected_index = _typed_action_json_type("null"),
        index = { type = "number" },
      }))
    end
  end

  add_action(_typed_action_schema_action({
    op = _typed_action_string_enum("track.set"),
    track = { type = "string" },
    name = _typed_action_json_type("string", "null"),
    volume_db = _typed_action_json_type("number", "null"),
    pan_pct = _typed_action_json_type("number", "null"),
    mute = _typed_action_json_type("boolean", "null"),
    solo = _typed_action_json_type("boolean", "null"),
    master_send = _typed_action_json_type("boolean", "null"),
  }))
  add_action(_typed_action_schema_action({
    op = _typed_action_string_enum("track.folder"),
    parent = { type = "string" },
    children = {
      type = "array",
      items = { type = "string" },
    },
  }))
  add_action(_typed_action_schema_action({
    op = _typed_action_string_enum("fx.add_stock"),
    track = { type = "string" },
    id = { type = "string" },
    fx = {
      type = "string",
      enum = { "ReaEQ", "ReaComp", "ReaDelay", "ReaVerbate", "ReaGate", "ReaLimit" },
    },
  }))
  add_action(_typed_action_schema_action({
    op = _typed_action_string_enum("fx.set_param"),
    fx = { type = "string" },
    params = _typed_action_schema_params_object(),
  }))
  add_action(_typed_action_schema_action({
    op = _typed_action_string_enum("send.create"),
    id = _typed_action_json_type("string", "null"),
    ["from"] = { type = "string" },
    to = { type = "string" },
    volume_db = _typed_action_json_type("number", "null"),
    pan = _typed_action_json_type("number", "null"),
    mode = _typed_action_json_type("string", "number", "null"),
    muted = _typed_action_json_type("boolean", "null"),
  }))

  local action_schema = { anyOf = action_variants }
  local schema = _typed_action_schema_object({
    version = { type = "integer", enum = { 1 } },
    actions = {
      type = "array",
      items = action_schema,
      maxItems = 64,
    },
  }, { "version", "actions" })
  local encoded = JSON.encode({
    type = "json_schema",
    json_schema = {
      name = "reaassist_actions_v1",
      strict = true,
      schema = schema,
    },
  })
  if not encoded then return "" end
  return ',"response_format":' .. encoded
end

local function _typed_action_text_has_any(lt, terms)
  for _, term in ipairs(terms) do
    if lt:find(term, 1, true) then return true end
  end
  return false
end

function Code.typed_actions_prompt_contract(user_text, opts)
  opts = type(opts) == "table" and opts or {}
  if not opts.force_enabled and not Code.typed_actions_executor_enabled() then
    return nil, "executor_disabled"
  end
  if type(user_text) ~= "string" or user_text == "" then
    return nil, "empty_prompt"
  end

  local lt = user_text:lower()
  local trimmed_lt = lt:gsub("^%s+", "")
  local words = " " .. lt:gsub("[^%w]+", " "):gsub("%s+", " ") .. " "
  local function has_word_phrase(term)
    return words:find(" " .. term .. " ", 1, true) ~= nil
  end
  local fx_presence_question =
       trimmed_lt:find("^does%s+.+%s+have%s+") ~= nil
    or trimmed_lt:find("^do%s+.+%s+have%s+") ~= nil
    or trimmed_lt:find("^does%s+.+%s+use%s+") ~= nil
    or trimmed_lt:find("^do%s+.+%s+use%s+") ~= nil
  local question_or_readonly =
       trimmed_lt:find("^how%s+") ~= nil
    or trimmed_lt:find("^what%s+") ~= nil
    or trimmed_lt:find("^why%s+") ~= nil
    or trimmed_lt:find("^where%s+") ~= nil
    or trimmed_lt:find("^when%s+") ~= nil
    or trimmed_lt:find("^is%s+") ~= nil
    or trimmed_lt:find("^are%s+") ~= nil
    or trimmed_lt:find("^explain%s+") ~= nil
    or trimmed_lt:find("^tell%s+me%s+") ~= nil
    or trimmed_lt:find("^show%s+me%s+how%s+") ~= nil
    or trimmed_lt:find("^list%s+") ~= nil
    or trimmed_lt:find("^show%s+") ~= nil
    or trimmed_lt:find("^inspect%s+") ~= nil
    or trimmed_lt:find("^analyze%s+") ~= nil
    or trimmed_lt:find("^review%s+") ~= nil
    or trimmed_lt:find("^diagnose%s+") ~= nil
    or trimmed_lt:find("^summarize%s+") ~= nil
    or fx_presence_question
  if question_or_readonly then
    return nil, "question_or_readonly"
  end

  local explicit_lua_request =
       lt:find("reaper lua", 1, true) ~= nil
    or lt:find("lua script", 1, true) ~= nil
    or lt:find("lua code", 1, true) ~= nil
    or lt:find("reascript", 1, true) ~= nil
    or lt:find("return only lua", 1, true) ~= nil
    or lt:find("return only the lua", 1, true) ~= nil
    or (has_word_phrase("write") and has_word_phrase("script")
      and (has_word_phrase("reaper") or has_word_phrase("lua")))
    or (has_word_phrase("generate") and has_word_phrase("script")
      and (has_word_phrase("reaper") or has_word_phrase("lua")))
  if explicit_lua_request then
    return nil, "explicit_lua_request"
  end

  local blocked_terms = {
    "midi", "jsfx", "eel2", "reajs", "theme", "marker", "region",
    "item", "take", "envelope", "automation", "tempo", "time signature",
    "render", "export", "install", "download", "color", "colors",
    "colour", "colours", "third-party", "third party",
    "vst3", "fabfilter", "pro-q", "pro q", "waves", "uad", "kontakt",
    "serum", "vital", "omnisphere", "ozone", "soothe",
  }
  if _typed_action_text_has_any(lt, blocked_terms) then
    return nil, "unsupported_scope"
  end

  local has_stock_fx = _typed_action_text_has_any(lt, {
    "reaeq", "reacomp", "readelay", "reaverbate", "reagate", "realimit",
  })
  if not has_stock_fx then
    local generic_fx_lt = lt
    for _, phrase in ipairs({
      "do not add any effects",
      "do not add effects",
      "do not add any effect",
      "do not add effect",
      "do not add any fx",
      "do not add fx",
      "add no effects",
      "add no effect",
      "add no fx",
      "no effects",
      "no effect",
      "no fx",
    }) do
      generic_fx_lt = generic_fx_lt:gsub(phrase, "")
    end
    local generic_fx_words = " "
      .. generic_fx_lt:gsub("[^%w]+", " "):gsub("%s+", " ") .. " "
    local function has_generic_fx_word_phrase(term)
      return generic_fx_words:find(" " .. term .. " ", 1, true) ~= nil
    end
    local generic_fx_terms = {
      "chain", "fx", "effect", "effects", "plugin", "plugins",
      "compressor", "eq", "equalizer", "reverb", "delay", "gate",
      "limiter", "deesser", "saturation", "saturator", "chorus",
      "phaser", "pitch correction", "pitch shift", "vocal chain",
      "rock vocal", "suitable", "suitable for", "processing",
      "processor", "rack", "strip", "channel strip", "mix ready",
      "mixready", "sound good", "sound better", "amp", "amp sim",
      "distortion", "drive", "auto tune", "autotune",
    }
    for _, term in ipairs(generic_fx_terms) do
      if has_generic_fx_word_phrase(term) then
        return nil, "generic_fx_chain"
      end
    end
  end
  local has_routing = _typed_action_text_has_any(lt, {
    "route", "routing", "send", "sends", "bus", "buss", "aux",
  })
  local has_track_setup =
    _typed_action_text_has_any(lt, { "create", "add", "make", "set up", "setup", "build" })
    and _typed_action_text_has_any(lt, { "track", "tracks", "bus", "aux" })
  local track_property_lt =
    Code._typed_action_track_property_intent_text(user_text)
  local has_track_property =
    _typed_action_text_has_any(track_property_lt, {
      "track", "tracks", "bus", "aux", "selected", "current", "existing",
    })
    and _typed_action_text_has_any(track_property_lt, {
      "volume", "vol ", "fader", "pan", "panned", "mute", "muted", "unmute",
      "solo", "soloed", "unsolo",
      "master send", "main send", "master/parent", "master parent",
      "parent send", "master output", "rename", "renamed", "call ", "called",
    })
  local has_folder = Code.typed_action_user_requests_folder(user_text)

  if not (has_stock_fx or has_routing or has_track_setup
      or has_track_property or has_folder) then
    return nil, "no_typed_action_intent"
  end

  if opts.response_format then
    local contract = _typed_action_contract_for_profile(
      _TYPED_ACTION_RESPONSE_FORMAT_PROMPT_CONTRACT, opts.profile)
    return contract .. Code.typed_action_request_specific_help(user_text),
      "eligible"
  end
  local contract = _typed_action_contract_for_profile(
    _TYPED_ACTION_PROMPT_CONTRACT, opts.profile)
  return contract .. Code.typed_action_request_specific_help(user_text),
    "eligible"
end

function Code.typed_actions_plan_from_text(text, opts)
  opts = type(opts) == "table" and opts or {}
  if opts.allow_raw_json then
    local raw_json = _typed_action_trim(text)
    if raw_json:sub(1, 1) == "{" then
      local plan, errors = Code.parse_typed_actions_block(raw_json)
      if plan then Code.repair_typed_actions_plan(plan, opts) end
      return plan, errors
    end
  end
  local raw, extract_errors = Code.extract_typed_actions(text)
  if not raw then return nil, extract_errors end
  local plan, errors = Code.parse_typed_actions_block(raw)
  if plan then Code.repair_typed_actions_plan(plan, opts) end
  return plan, errors
end

function Code.validate_typed_actions_semantics(plan, opts)
  opts = type(opts) == "table" and opts or {}
  local profile = opts.profile
  if type(profile) == "string" then
    profile = Code.typed_actions_model_profile_by_key(profile)
  end
  if type(profile) ~= "table"
     and tostring(opts.user_text or "") ~= "" then
    profile = _TYPED_ACTION_PROFILE_MINIMAL_PLAN_HELP
  end
  if type(profile) ~= "table" or profile.semantic_retry ~= true then
    return true, nil
  end

  local tracks, track_order, fx_seen_by_track, fx_by_track, op_counts, errors =
    {}, {}, {}, {}, {}, {}
  local fx_type_by_id = {}
  local folder_children_by_parent = {}
  local function lower(s) return tostring(s or ""):lower() end
  local function trim(s) return tostring(s or ""):match("^%s*(.-)%s*$") end
  local function normalized_name(s)
    return lower(trim(s)):gsub("%s+", " ")
  end
  local function name_has(name, needle)
    return lower(name):find(tostring(needle or ""), 1, true) ~= nil
  end
  local function is_bus_name(name)
    local n = lower(name)
    return n:find("bus", 1, true) ~= nil or n:find("buss", 1, true) ~= nil
  end
  local function is_return_name(name)
    local n = lower(name)
    return n:find("verb", 1, true) ~= nil
      or n:find("reverb", 1, true) ~= nil
      or n:find("delay", 1, true) ~= nil
      or n:find("return", 1, true) ~= nil
      or n:find("aux", 1, true) ~= nil
  end
  local function is_aux_like_name(name)
    local n = lower(name)
    return is_return_name(name)
      or n:find("crush", 1, true) ~= nil
      or n:find("parallel", 1, true) ~= nil
  end
  local function word_text(s)
    return normalized_name(tostring(s or ""):gsub("[^%w]+", " "))
  end
  local u = lower(opts.user_text)
  local u_words = word_text(opts.user_text)
  local exact_send_graph_requested =
    u:find("keep the graph exact", 1, true) ~= nil
    or u:find("do not add any other", 1, true) ~= nil
    or u:find("do not add extra", 1, true) ~= nil
    or u:find("no other sends", 1, true) ~= nil
  local function explicit_send_requested(src_name, dst_name)
    local src = word_text(src_name)
    local dst = word_text(dst_name)
    if src == "" or dst == "" then return false end
    local phrases = {
      src .. " to " .. dst,
      src .. " into " .. dst,
      src .. " feed " .. dst,
      src .. " feeds " .. dst,
      src .. " feeding " .. dst,
      "route " .. src .. " to " .. dst,
      "route " .. src .. " into " .. dst,
      "send " .. src .. " to " .. dst,
      "send " .. src .. " into " .. dst,
    }
    for _, phrase in ipairs(phrases) do
      if u_words:find(phrase, 1, true) then return true end
    end
    return false
  end
  local function user_mentions_db_value(db)
    local want = tonumber(db)
    if not want then return false end
    for raw in tostring(opts.user_text or ""):gmatch("([%+%-]?%d+%.?%d*)%s*[dD][bB]") do
      local got = tonumber(raw)
      if got and math.abs(got - want) <= 0.25 then return true end
    end
    return false
  end
  local required_selected_indexes, selected_index_required =
    Code._typed_action_selected_indexes_from_user_text(opts.user_text)
  local positional_selector_forbidden =
    Code._typed_action_forbids_positional_track_selector(opts.user_text)
  local seen_selected_indexes, any_selected_index_resolve = {}, false
  local allow_duplicate_fx =
    u:find("duplicate", 1, true) ~= nil
    or u:find("another", 1, true) ~= nil
    or u:find("two ", 1, true) ~= nil
    or u:find("multiple", 1, true) ~= nil
  local function user_mentions_name(name)
    local n = word_text(name)
    return n ~= "" and u_words:find(n, 1, true) ~= nil
  end
  local function requested_supported_stock_fx()
    for fx_name in pairs(_TYPED_ACTION_STOCK_FX) do
      if u:find(lower(fx_name), 1, true) ~= nil then return true end
    end
    return u:find("stock fx", 1, true) ~= nil
      or u:find("stock effect", 1, true) ~= nil
      or u:find("stock plugin", 1, true) ~= nil
  end
  local requests_stock_fx = requested_supported_stock_fx()
  local requests_params =
    requests_stock_fx
    and (u:find("threshold", 1, true) ~= nil
      or u:find("frequency", 1, true) ~= nil
      or u:find("gain", 1, true) ~= nil
      or u:find("ratio", 1, true) ~= nil
      or u:find("attack", 1, true) ~= nil
      or u:find("release", 1, true) ~= nil
      or u:find("feedback", 1, true) ~= nil
      or u:find("wet", 1, true) ~= nil
      or u:find("dry", 1, true) ~= nil
      or u:find("ceiling", 1, true) ~= nil)
  local function user_mentions_param(param, value, params)
    param = tostring(param or "")
    if param == "band" then
      return (params.frequency_hz ~= nil
          and user_mentions_param("frequency_hz", params.frequency_hz, params))
        or (params.gain_db ~= nil
          and user_mentions_param("gain_db", params.gain_db, params))
    elseif param == "frequency_hz" then
      return u:find("frequency", 1, true) ~= nil
        or u:find("freq", 1, true) ~= nil
        or u:find(" hz", 1, true) ~= nil
        or u:find("khz", 1, true) ~= nil
    elseif param == "gain_db" then
      return u:find("gain", 1, true) ~= nil
        or u:find("boost", 1, true) ~= nil
        or u:find("cut", 1, true) ~= nil
        or (u:find("band", 1, true) ~= nil
          and user_mentions_db_value(value))
    elseif param == "threshold_db" then
      return u:find("threshold", 1, true) ~= nil
    elseif param == "ratio" then
      return u:find("ratio", 1, true) ~= nil
    elseif param == "attack_ms" then
      return u:find("attack", 1, true) ~= nil
    elseif param == "release_ms" then
      return u:find("release", 1, true) ~= nil
    elseif param == "wet_db" then
      return u:find("wet", 1, true) ~= nil
    elseif param == "dry_db" then
      return u:find("dry", 1, true) ~= nil
    elseif param == "rms_ms" then
      return u:find("rms", 1, true) ~= nil
    elseif param == "feedback_pct" or param == "feedback_db" then
      return u:find("feedback", 1, true) ~= nil
    elseif param == "room_size" then
      return u:find("room size", 1, true) ~= nil
        or u:find("room", 1, true) ~= nil
    elseif param == "dampening" then
      return u:find("dampening", 1, true) ~= nil
        or u:find("damping", 1, true) ~= nil
    elseif param == "hysteresis_db" then
      return u:find("hysteresis", 1, true) ~= nil
    elseif param == "hold_ms" then
      return u:find("hold", 1, true) ~= nil
    elseif param == "ceiling_db" then
      return u:find("ceiling", 1, true) ~= nil
    end
    return false
  end
  local send_intent_text =
    Code._typed_action_send_intent_text(opts.user_text)
  local send_intent_words = " " .. word_text(send_intent_text) .. " "
  local requests_sends =
    (send_intent_words:find(" send ", 1, true) ~= nil
      or send_intent_words:find(" sends ", 1, true) ~= nil
      or send_intent_words:find(" route ", 1, true) ~= nil
      or send_intent_words:find(" routes ", 1, true) ~= nil
      or send_intent_words:find(" routed ", 1, true) ~= nil
      or send_intent_words:find(" routing ", 1, true) ~= nil
      or send_intent_words:find(" feed ", 1, true) ~= nil
      or send_intent_words:find(" feeds ", 1, true) ~= nil
      or send_intent_words:find(" feeding ", 1, true) ~= nil)
  local track_property_text =
    Code._typed_action_track_property_intent_text(opts.user_text)
  local requests_master_send_state =
    Code._typed_action_user_requests_master_send_state(opts.user_text)
  local requests_track_properties =
    (track_property_text:find("volume", 1, true) ~= nil
      or track_property_text:find("fader", 1, true) ~= nil
      or track_property_text:find("pan", 1, true) ~= nil
      or track_property_text:find("panned", 1, true) ~= nil
      or track_property_text:find("mute", 1, true) ~= nil
      or track_property_text:find("muted", 1, true) ~= nil
      or track_property_text:find("unmute", 1, true) ~= nil
      or track_property_text:find("solo", 1, true) ~= nil
      or track_property_text:find("soloed", 1, true) ~= nil
      or track_property_text:find("unsolo", 1, true) ~= nil
      or requests_master_send_state
      or track_property_text:find("rename", 1, true) ~= nil
      or track_property_text:find("renamed", 1, true) ~= nil
      or track_property_text:find("call ", 1, true) ~= nil
      or track_property_text:find("called", 1, true) ~= nil)
    and (track_property_text:find("track", 1, true) ~= nil
      or track_property_text:find("bus", 1, true) ~= nil
      or track_property_text:find("aux", 1, true) ~= nil)
  local requests_track_creation =
    Code.typed_action_user_requests_track_creation(opts.user_text)
  local user_text_lower = lower(opts.user_text)
  local existing_target_only =
    not requests_track_creation
    and (user_text_lower:find("existing track", 1, true) ~= nil
      or user_text_lower:find("existing tracks", 1, true) ~= nil
      or user_text_lower:find("resolve the existing", 1, true) ~= nil
      or user_text_lower:find("do not create", 1, true) ~= nil
      or user_text_lower:find("don't create", 1, true) ~= nil)
  local selected_target_requested =
    Code.typed_action_user_requests_selected_target(opts.user_text)
  local requests_folders =
    Code.typed_action_user_requests_folder(opts.user_text)
  local function is_fx_like_track_name(name)
    local n = " " .. word_text(name) .. " "
    return n:find(" eq ", 1, true) ~= nil
      or n:find(" comp ", 1, true) ~= nil
      or n:find(" compressor ", 1, true) ~= nil
      or n:find(" reverb ", 1, true) ~= nil
      or n:find(" delay ", 1, true) ~= nil
      or n:find(" gate ", 1, true) ~= nil
      or n:find(" limiter ", 1, true) ~= nil
  end
  local function requested_exact_track_order(text)
    text = tostring(text or "")
    local lt = lower(text)
    local function parse_order_fragment(fragment)
      fragment = tostring(fragment or "")
      fragment = fragment:gsub("^%s*.-:%s*", "")
      fragment = fragment:gsub("%f[%a][Tt]hen%f[%A]", ",")
      fragment = fragment:gsub("%f[%a][Aa]nd%f[%A]", ",")
      local out = {}
      for part in fragment:gmatch("[^,]+") do
        local name = trim(part)
          :gsub("^then%s+", "")
          :gsub("^and%s+", "")
          :gsub("^create%s+", "")
          :gsub("^make%s+", "")
          :gsub("^set%s+up%s+", "")
          :gsub("^build%s+", "")
          :gsub("^exactly%s+[%w]+%s+tracks?%s+named%s+", "")
          :gsub("^[%w]+%s+tracks?%s+named%s+", "")
          :gsub("^tracks?%s+named%s+", "")
          :gsub("^named%s+", "")
          :gsub("^the%s+", "")
          :gsub("^a%s+", "")
        name = trim(name)
        if name ~= "" then out[#out + 1] = normalized_name(name) end
      end
      return #out >= 2 and out or nil
    end
    local explicit_fragment =
      text:match("[Tt]rack%s+order%s+must%s+be%s+([^%.\n]+)")
      or text:match("[Oo]rder%s+must%s+be%s+([^%.\n]+)")
    if explicit_fragment then
      local explicit_order = parse_order_fragment(explicit_fragment)
      if explicit_order then return explicit_order end
    end
    local marker = lt:find(" in that exact order", 1, true)
      or lt:find(" in exact order", 1, true)
      or lt:find(" in that order", 1, true)
    if not marker then return nil end
    local before = text:sub(1, marker - 1)
    local cut = 0
    for i = 1, #before do
      local ch = before:sub(i, i)
      if ch == "." or ch == "\n" then cut = i end
    end
    if cut > 0 then before = before:sub(cut + 1) end
    before = before:gsub("^.*[Cc]reate%s+exactly%s+[%w%-]+%s+tracks?%s+named%s+", "")
    before = before:gsub("^.*[Cc]reate%s+[%w%-]+%s+tracks?%s+named%s+", "")
    before = before:gsub("^.*[Mm]ake%s+exactly%s+[%w%-]+%s+tracks?%s+named%s+", "")
    before = before:gsub("^.*[Ss]et%s+up%s+exactly%s+[%w%-]+%s+tracks?%s+named%s+", "")
    before = before:gsub("^.*%f[%a]with%s+", "")
    return parse_order_fragment(before)
  end

  local function requested_folder_memberships(text)
    text = tostring(text or "")
    local wanted = {}
    local function mentioned_names(fragment)
      local f_words = " " .. word_text(fragment) .. " "
      local out, seen = {}, {}
      for _, name in ipairs(track_order) do
        local key = word_text(name)
        if key ~= "" and f_words:find(" " .. key .. " ", 1, true)
            and not seen[key] then
          out[#out + 1] = normalized_name(name)
          seen[key] = true
        end
      end
      return out
    end
    for sentence in text:gmatch("[^%.\n]+") do
      local start_pos, end_pos = lower(sentence):find("folder%s+containing")
      if start_pos then
        local parents = mentioned_names(sentence:sub(1, start_pos - 1))
        local children = mentioned_names(sentence:sub(end_pos + 1))
        local parent = parents[#parents]
        if parent and #children > 0 then
          local filtered_children = {}
          for _, child in ipairs(children) do
            if child ~= parent then
              filtered_children[#filtered_children + 1] = child
            end
          end
          if #filtered_children > 0 then
            wanted[#wanted + 1] = {
              parent = parent,
              children = filtered_children,
            }
          end
        end
      end
    end
    return wanted
  end

  for i, action in ipairs((type(plan) == "table" and plan.actions) or {}) do
    local path = "$.actions[" .. tostring(i) .. "]"
    local op = tostring(action.op or "")
    op_counts[op] = (op_counts[op] or 0) + 1
    if action.op == "track.ensure" and action.id then
      tracks[action.id] = action.name
      track_order[#track_order + 1] = action.name
      if requests_stock_fx
         and is_fx_like_track_name(action.name)
         and not user_mentions_name(action.name) then
        errors[#errors + 1] = _typed_action_error(
          "fx_as_track", path .. ".name",
          tostring(action.name) .. " looks like an effect track, but the user "
            .. "asked for stock FX; use fx.add_stock on the intended track")
      end
    elseif action.op == "track.resolve" and action.id then
      if positional_selector_forbidden
         and type(action.selected_index) == "number" then
        errors[#errors + 1] = _typed_action_error(
          "forbidden_selected_index", path .. ".selected_index",
          "User explicitly said not to use selected_index; use the requested "
            .. "non-positional selector instead")
      end
      if positional_selector_forbidden
         and type(action.index) == "number" then
        errors[#errors + 1] = _typed_action_error(
          "forbidden_track_index", path .. ".index",
          "User explicitly said not to use absolute track indexes; use the "
            .. "requested non-positional selector instead")
      end
      if requests_track_creation
         and not selected_target_requested
         and (action.selected == true
           or type(action.selected_index) == "number"
           or type(action.index) == "number") then
        errors[#errors + 1] = _typed_action_error(
          "unexpected_track_resolve_target", path,
          "User requested creating tracks in a blank/project template; do not "
            .. "target selected or indexed existing tracks")
      end
      if requests_stock_fx
         and is_fx_like_track_name(action.id)
         and not _typed_action_is_nonempty_string(action.name) then
        errors[#errors + 1] = _typed_action_error(
          "track_resolve_used_for_fx", path,
          "Do not create FX ids with track.resolve. Use fx.add_stock with this "
            .. "id on the intended track, then use fx.set_param if needed")
      end
      if _typed_action_is_nonempty_string(action.name) then
        tracks[action.id] = action.name
      elseif type(action.index) == "number" then
        tracks[action.id] = "track " .. tostring(action.index)
      elseif type(action.selected_index) == "number" then
        any_selected_index_resolve = true
        seen_selected_indexes[action.selected_index] = true
        tracks[action.id] = "selected track " .. tostring(action.selected_index)
      elseif action.selected == true then
        tracks[action.id] = "selected track"
      else
        tracks[action.id] = action.id
      end
    elseif action.op == "track.set" then
      if action.master_send ~= nil and not requests_master_send_state then
        local track_name = tracks[action.track] or action.track
        errors[#errors + 1] = _typed_action_error(
          "unrequested_master_send_action", path .. ".master_send",
          "User did not explicitly request master/parent send state for "
            .. tostring(track_name)
            .. "; leave master_send null and use send.create for routing")
      end
    elseif action.op == "fx.add_stock" then
      local track_id = action.track
      local track_name = tracks[track_id] or track_id
      local fx = tostring(action.fx or "")
      if _typed_action_is_nonempty_string(action.id) then
        fx_type_by_id[action.id] = fx
      end
      local track_key = tostring(track_id or "")
      fx_seen_by_track[track_key] = fx_seen_by_track[track_key] or {}
      fx_by_track[track_key] = fx_by_track[track_key] or {}
      fx_by_track[track_key][fx] = true
      if fx_seen_by_track[track_key][fx] and not allow_duplicate_fx then
        errors[#errors + 1] = _typed_action_error(
          "duplicate_track_fx", path .. ".fx",
          "Duplicate " .. fx .. " on " .. tostring(track_name)
            .. "; add each requested source-chain FX once per track")
      end
      fx_seen_by_track[track_key][fx] = true

      if name_has(track_name, "verb") and fx ~= "ReaVerbate" then
        errors[#errors + 1] = _typed_action_error(
          "return_fx_mismatch", path .. ".fx",
          tostring(track_name) .. " is a reverb return; use ReaVerbate only "
            .. "unless the user asks for more")
      elseif name_has(track_name, "delay") and fx ~= "ReaDelay" then
        errors[#errors + 1] = _typed_action_error(
          "return_fx_mismatch", path .. ".fx",
          tostring(track_name) .. " is a delay return; use ReaDelay only "
            .. "unless the user asks for more")
      end
    elseif action.op == "send.create" then
      local src_name = tracks[action["from"]] or action["from"]
      local dst_name = tracks[action.to] or action.to
      local volume_db = tonumber(action.volume_db)
      if exact_send_graph_requested
         and is_aux_like_name(src_name)
         and is_bus_name(dst_name)
         and not explicit_send_requested(src_name, dst_name) then
        errors[#errors + 1] = _typed_action_error(
          "extra_inferred_return_bus_send", path,
          tostring(src_name) .. " -> " .. tostring(dst_name)
            .. " was not explicitly requested; exact routing graphs must not "
            .. "invent return/parallel-track sends")
      end
      if is_bus_name(dst_name)
         and not is_return_name(src_name)
         and volume_db ~= nil
         and math.abs(volume_db) > 0.7
         and not user_mentions_db_value(volume_db) then
        errors[#errors + 1] = _typed_action_error(
          "bus_send_not_unity", path .. ".volume_db",
          tostring(src_name) .. " -> " .. tostring(dst_name)
            .. " is bus routing and should use volume_db 0 unless the user "
            .. "asks for a different bus level")
      end
    elseif action.op == "fx.set_param" and type(action.params) == "table" then
      for param, value in pairs(action.params) do
        if value ~= nil and not user_mentions_param(param, value, action.params) then
          errors[#errors + 1] = _typed_action_error(
            "unrequested_param_action", path .. ".params." .. tostring(param),
            "User did not request " .. tostring(fx_type_by_id[action.fx] or "FX")
              .. "." .. tostring(param) .. "; do not emit extra parameter writes")
        end
      end
    elseif action.op == "track.folder" then
      local children = {}
      if type(action.children) == "table" then
        for _, child in ipairs(action.children) do
          children[#children + 1] = child
        end
      end
      folder_children_by_parent[action.parent] = children
    end
  end

  if selected_index_required then
    if #required_selected_indexes == 0 then
      if not any_selected_index_resolve then
        errors[#errors + 1] = _typed_action_error(
          "missing_selected_index", "$.actions",
          "User explicitly requested selected_index targeting; use "
            .. "track.resolve with selected_index and do not substitute name, "
            .. "index, or selected:true")
      end
    else
      for _, selected_index in ipairs(required_selected_indexes) do
        if not seen_selected_indexes[selected_index] then
          errors[#errors + 1] = _typed_action_error(
            "missing_selected_index", "$.actions",
            "User requested selected track " .. tostring(selected_index)
              .. "; use track.resolve with selected_index="
              .. tostring(selected_index)
              .. " and do not substitute name, index, or selected:true")
        end
      end
    end
  end

  if requests_track_creation and (op_counts["track.ensure"] or 0) == 0 then
    errors[#errors + 1] = _typed_action_error(
      "missing_track_ensure_actions", "$.actions",
      "User requested creating tracks or a blank-project template; use "
        .. "track.ensure for the requested tracks, not track.resolve")
  end
  if existing_target_only and (op_counts["track.ensure"] or 0) > 0 then
    errors[#errors + 1] = _typed_action_error(
      "unexpected_track_ensure_existing_target", "$.actions",
      "User requested existing-track targets; use track.resolve for those "
        .. "tracks and do not create replacement tracks")
  end
  if requests_stock_fx and (op_counts["fx.add_stock"] or 0) == 0 then
    errors[#errors + 1] = _typed_action_error(
      "missing_fx_actions", "$.actions",
      "User requested supported stock FX; the typed-action plan must include "
        .. "fx.add_stock actions, not only track.ensure")
  end
  if requests_params and (op_counts["fx.set_param"] or 0) == 0 then
    errors[#errors + 1] = _typed_action_error(
      "missing_param_actions", "$.actions",
      "User requested FX parameter settings; the typed-action plan must include "
        .. "fx.set_param actions")
  end
  if requests_sends and (op_counts["send.create"] or 0) == 0 then
    errors[#errors + 1] = _typed_action_error(
      "missing_send_actions", "$.actions",
      "User requested routing/sends; the typed-action plan must include "
        .. "send.create actions")
  end
  if requests_track_properties and (op_counts["track.set"] or 0) == 0 then
    errors[#errors + 1] = _typed_action_error(
      "missing_track_set_actions", "$.actions",
      "User requested track rename/name, volume, pan, mute, unmute, solo, unsolo, or "
        .. "master/parent send state; the typed-action plan must include "
        .. "track.set actions")
  end
  if requests_folders and (op_counts["track.folder"] or 0) == 0 then
    errors[#errors + 1] = _typed_action_error(
      "missing_folder_actions", "$.actions",
      "User requested a track folder; the typed-action plan must include "
        .. "track.folder actions")
  end
  if not requests_folders and (op_counts["track.folder"] or 0) > 0 then
    errors[#errors + 1] = _typed_action_error(
      "unexpected_folder_actions", "$.actions",
      "User did not request a track folder; do not emit track.folder actions")
  end
  if not requests_track_properties and (op_counts["track.set"] or 0) > 0 then
    errors[#errors + 1] = _typed_action_error(
      "unexpected_track_set_actions", "$.actions",
      "User did not request track rename/name, volume, pan, mute, unmute, solo, unsolo, or "
        .. "master/parent send state; do not emit track.set actions")
  end

  local requested_order = requested_exact_track_order(opts.user_text)
  if requested_order then
    if exact_send_graph_requested and #track_order > #requested_order then
      errors[#errors + 1] = _typed_action_error(
        "unexpected_track_ensure_actions", "$.actions",
        "User requested an exact track order with "
          .. tostring(#requested_order)
          .. " tracks, but the plan creates "
          .. tostring(#track_order)
          .. "; do not create extra tracks for FX, folders, or helper ids")
    end
    for i, want in ipairs(requested_order) do
      local got = normalized_name(track_order[i])
      if got ~= want then
        errors[#errors + 1] = _typed_action_error(
          "track_order_mismatch", "$.actions",
          "User requested exact track order; expected track "
            .. tostring(i) .. " to be " .. tostring(want)
            .. ", got " .. tostring(track_order[i] or "missing"))
        break
      end
    end
  end

  if requests_folders then
    local child_names_by_parent = {}
    for parent_id, child_ids in pairs(folder_children_by_parent) do
      local parent_name = normalized_name(tracks[parent_id] or parent_id)
      child_names_by_parent[parent_name] = child_names_by_parent[parent_name] or {}
      for _, child_id in ipairs(child_ids) do
        child_names_by_parent[parent_name][normalized_name(tracks[child_id] or child_id)] = true
      end
    end
    for _, want in ipairs(requested_folder_memberships(opts.user_text)) do
      local got = child_names_by_parent[want.parent] or {}
      for _, child_name in ipairs(want.children) do
        if not got[child_name] then
          errors[#errors + 1] = _typed_action_error(
            "missing_folder_child", "$.actions",
            "User requested " .. tostring(want.parent)
              .. " to contain " .. tostring(child_name)
              .. "; include that id in the parent track.folder children list")
        end
      end
    end
  end

  local repeated_source_chain_requested =
    (u_words:find("reaeq first and reacomp second", 1, true) ~= nil)
    or (u_words:find("reaeq first", 1, true) ~= nil
      and u_words:find("reacomp second", 1, true) ~= nil)
    or (u_words:find("reacomp first and reaeq second", 1, true) ~= nil)
    or (u_words:find("reacomp first", 1, true) ~= nil
      and u_words:find("reaeq second", 1, true) ~= nil)
    or (u_words:find("reaeq followed by reacomp", 1, true) ~= nil)
    or (u_words:find("reacomp followed by reaeq", 1, true) ~= nil)
    or (u_words:find("reaeq then reacomp", 1, true) ~= nil)
    or (u_words:find("reacomp then reaeq", 1, true) ~= nil)
    or (u_words:find("reaeq and reacomp to", 1, true) ~= nil)
    or (u_words:find("reaeq and reacomp on", 1, true) ~= nil)
    or (u_words:find("reacomp and reaeq to", 1, true) ~= nil)
    or (u_words:find("reacomp and reaeq on", 1, true) ~= nil)
  if repeated_source_chain_requested then
    for track_id, name in pairs(tracks) do
      if not is_bus_name(name)
         and not is_return_name(name)
         and not is_aux_like_name(name) then
        local fx = fx_by_track[tostring(track_id)] or {}
        if fx.ReaComp and not fx.ReaEQ then
          errors[#errors + 1] = _typed_action_error(
            "incomplete_source_fx_chain", "$.actions",
            tostring(name) .. " has ReaComp but is missing ReaEQ; source "
              .. "tracks in this repeated chain need both requested FX")
        end
      end
    end
  end

  if exact_send_graph_requested and requests_stock_fx then
    local requested_fx_by_track = {}
    for sentence in tostring(opts.user_text or ""):gmatch("[^%.%!%?]+") do
      local sw = word_text(sentence)
      if sw ~= "" then
        local sentence_fx = {}
        for fx_name in pairs(_TYPED_ACTION_STOCK_FX) do
          if sw:find(word_text(fx_name), 1, true) then
            sentence_fx[fx_name] = true
          end
        end
        if next(sentence_fx) then
          local broad =
            sw:find("all tracks", 1, true) ~= nil
            or sw:find("every track", 1, true) ~= nil
            or sw:find("each track", 1, true) ~= nil
          for track_id, name in pairs(tracks) do
            if broad or sw:find(word_text(name), 1, true) then
              requested_fx_by_track[track_id] =
                requested_fx_by_track[track_id] or {}
              for fx_name in pairs(sentence_fx) do
                requested_fx_by_track[track_id][fx_name] = true
              end
            end
          end
        end
      end
    end
    for track_id, fx_set in pairs(fx_by_track) do
      local requested = requested_fx_by_track[track_id]
      if requested then
        local track_name = tracks[track_id] or track_id
        for fx_name in pairs(fx_set) do
          if not requested[fx_name] then
            errors[#errors + 1] = _typed_action_error(
              "unexpected_track_fx", "$.actions",
              tostring(track_name) .. " has " .. tostring(fx_name)
                .. ", but the user did not request that stock FX for this "
                .. "track; keep exact graph FX assignments separate")
          end
        end
      end
    end
  end

  return #errors == 0, (#errors > 0 and errors or nil)
end

function Code.format_typed_action_semantic_errors(errors, limit)
  if type(errors) ~= "table" or #errors == 0 then return "semantic_mismatch" end
  limit = tonumber(limit) or 3
  local parts = {}
  for i = 1, math.min(#errors, limit) do
    local e = errors[i]
    parts[#parts + 1] = tostring(e.code or "semantic_mismatch")
      .. " at " .. tostring(e.path or "$")
      .. ": " .. tostring(e.message or "")
  end
  if #errors > limit then
    parts[#parts + 1] = tostring(#errors - limit) .. " more"
  end
  return table.concat(parts, "; ")
end

function Code.typed_action_semantic_detail_missing_action_family(detail)
  detail = tostring(detail or "")
  return detail:find("missing_fx_actions", 1, true) ~= nil
    or detail:find("missing_param_actions", 1, true) ~= nil
    or detail:find("missing_send_actions", 1, true) ~= nil
end

function Code.typed_action_semantic_retry_from_scratch(profile, detail)
  detail = tostring(detail or "")
  if type(profile) == "table"
     and profile.semantic_retry_from_scratch == true then
    return true
  end
  if detail:find("unexpected_track_ensure_existing_target", 1, true) then
    return true
  end
  if Code.typed_action_semantic_detail_missing_action_family(detail)
     and type(S) == "table"
     and (S.typed_action_escalation_used == true
       or (tonumber(S.typed_action_escalation_count or 0) or 0) > 0) then
    return true
  end
  return false
end

function Code._typed_action_schema_retry_detail(text, opts)
  opts = type(opts) == "table" and opts or {}
  local plan, plan_errors = Code.typed_actions_plan_from_text(text, {
    allow_raw_json = opts.allow_raw_json == true,
  })
  local detail = nil
  if plan then
    local valid, validate_errors = Code.validate_typed_actions_plan(plan)
    if not valid then
      detail = Code.format_typed_action_semantic_errors(validate_errors, 4)
    end
  else
    detail = Code.format_typed_action_semantic_errors(plan_errors, 4)
  end

  local u = tostring(opts.user_text or ""):lower()
  local track_property_text = u
    :gsub("post%-fader", "")
    :gsub("post fader", "")
    :gsub("pre%-fader", "")
    :gsub("pre fader", "")
    :gsub("do not rename", "")
    :gsub("don't rename", "")
    :gsub("without renaming", "")
    :gsub("rename any tracks", "")
    :gsub("rename any track", "")
    :gsub("no rename", "")
    :gsub("not rename", "")
  local requests_track_properties =
    (track_property_text:find("volume", 1, true) ~= nil
      or track_property_text:find("fader", 1, true) ~= nil
      or track_property_text:find("pan", 1, true) ~= nil
      or track_property_text:find("panned", 1, true) ~= nil
      or track_property_text:find("mute", 1, true) ~= nil
      or track_property_text:find("muted", 1, true) ~= nil
      or track_property_text:find("unmute", 1, true) ~= nil
      or track_property_text:find("solo", 1, true) ~= nil
      or track_property_text:find("soloed", 1, true) ~= nil
      or track_property_text:find("unsolo", 1, true) ~= nil
      or track_property_text:find("master send", 1, true) ~= nil
      or track_property_text:find("main send", 1, true) ~= nil
      or track_property_text:find("master/parent", 1, true) ~= nil
      or track_property_text:find("master parent", 1, true) ~= nil
      or track_property_text:find("parent send", 1, true) ~= nil
      or track_property_text:find("master output", 1, true) ~= nil
      or track_property_text:find("rename", 1, true) ~= nil
      or track_property_text:find("renamed", 1, true) ~= nil
      or track_property_text:find("call ", 1, true) ~= nil
      or track_property_text:find("called", 1, true) ~= nil)
  if plan and requests_track_properties then
    local counts = _typed_action_count_ops(plan)
    if (counts["track.resolve"] or 0) > 0
       and (counts["track.set"] or 0) == 0 then
      local hint = "User requested track property changes; keep one valid "
        .. "track.resolve for the target, then add one track.set using that "
        .. "same id"
      detail = detail and detail ~= "" and (detail .. "; " .. hint) or hint
    end
  end
  return detail and detail ~= "" and detail or "invalid_plan"
end

local function _typed_action_executor_validate(plan)
  local valid, errors = Code.validate_typed_actions_plan(plan)
  if not valid then return false, errors end

  local fx_type_by_id, exec_errors = {}, {}
  for i, action in ipairs(plan.actions or {}) do
    local path = "$.actions[" .. tostring(i) .. "]"
    if action.op == "track.ensure" then
      if action.color ~= nil
         and not tostring(action.color):match("^#%x%x%x%x%x%x$") then
        exec_errors[#exec_errors+1] = _typed_action_error(
          "unsupported_color", path .. ".color",
          "Typed-action executor supports only #RRGGBB colors")
      end
    elseif action.op == "fx.add_stock" and action.id and action.fx then
      fx_type_by_id[action.id] = action.fx
    elseif action.op == "fx.set_param" then
      local fx_name = fx_type_by_id[action.fx]
      local setters, perr = _typed_action_param_setters(
        fx_name, action.params, path)
      if not setters then
        for _, e in ipairs(perr or {}) do exec_errors[#exec_errors+1] = e end
      end
    elseif action.op == "send.create" and action.mode ~= nil
       and type(action.mode) == "string" then
      local m = tostring(action.mode):lower():gsub("%s+", "_"):gsub("%-", "_")
      local ok_mode = m == "post_fader"
        or m == "post_fader_post_pan"
        or m == "pre_fx"
        or m == "pre_fader"
        or m == "post_fx"
      if not ok_mode then
        exec_errors[#exec_errors+1] = _typed_action_error(
          "unsupported_send_mode", path .. ".mode",
          "Unsupported send mode: " .. tostring(action.mode))
      end
    end
  end
  return #exec_errors == 0, exec_errors
end

local function _typed_action_find_existing_track(api, name)
  local found = {}
  local n = api.CountTracks(0)
  for i = 0, n - 1 do
    local tr = api.GetTrack(0, i)
    local _, tname = api.GetTrackName(tr, "")
    if tname == name then found[#found+1] = tr end
  end
  return found
end

function Code._typed_action_resolve_existing_track(api, action)
  if action.selected_index ~= nil then
    if type(api.CountSelectedTracks) ~= "function"
       or type(api.GetSelectedTrack) ~= "function" then
      return nil, "selected_track_unavailable",
        "REAPER selected-track APIs are unavailable"
    end
    local idx = tonumber(action.selected_index)
    local count = api.CountSelectedTracks(0)
    if not idx or idx % 1 ~= 0 or idx < 1 or idx > count then
      return nil, "missing_selected_track",
        "No selected track at 1-based selected index "
          .. tostring(action.selected_index) .. "; found "
          .. tostring(count or 0)
    end
    local tr = api.GetSelectedTrack(0, idx - 1)
    if not tr then
      return nil, "missing_selected_track",
        "Could not resolve selected track index "
          .. tostring(action.selected_index)
    end
    return tr
  end

  if action.selected == true then
    if type(api.CountSelectedTracks) ~= "function"
       or type(api.GetSelectedTrack) ~= "function" then
      return nil, "selected_track_unavailable",
        "REAPER selected-track APIs are unavailable"
    end
    local count = api.CountSelectedTracks(0)
    if count ~= 1 then
      return nil, "ambiguous_selected_track",
        "track.resolve selected requires exactly one selected track; found "
          .. tostring(count or 0)
    end
    local tr = api.GetSelectedTrack(0, 0)
    if not tr then
      return nil, "missing_selected_track",
        "Could not resolve the selected track"
    end
    return tr
  end

  if action.index ~= nil then
    local idx = tonumber(action.index)
    local count = api.CountTracks(0)
    if not idx or idx % 1 ~= 0 or idx < 1 or idx > count then
      return nil, "missing_track",
        "No existing track at 1-based index " .. tostring(action.index)
    end
    local tr = api.GetTrack(0, idx - 1)
    if not tr then
      return nil, "missing_track",
        "Could not resolve track index " .. tostring(action.index)
    end
    if action.name ~= nil then
      local _, tname = api.GetTrackName(tr, "")
      if tname ~= action.name then
        return nil, "track_name_mismatch",
          "Track index " .. tostring(action.index) .. " is named "
            .. tostring(tname) .. ", not " .. tostring(action.name)
      end
    end
    return tr
  end

  if action.name ~= nil then
    local found = _typed_action_find_existing_track(api, action.name)
    if #found == 0 then
      return nil, "missing_track",
        "No existing track is named " .. tostring(action.name)
    end
    if #found > 1 then
      return nil, "ambiguous_track",
        "Multiple existing tracks are named " .. tostring(action.name)
    end
    return found[1]
  end

  return nil, "invalid_target_selector",
    "track.resolve needs name, selected, selected_index, or index"
end

local function _typed_action_track_insert_index(api, action, tracks)
  local count = api.CountTracks(0)
  local pos = action.position
  if not pos or pos == "" or pos == "end" then return count end
  local dir, ref = pos:match("^(after):(.-)$")
  if not dir then dir, ref = pos:match("^(before):(.-)$") end
  local ref_tr = ref and tracks[ref] or nil
  if not ref_tr then return nil, "Unknown position reference: " .. tostring(pos) end
  local ref_num = api.GetMediaTrackInfo_Value(ref_tr, "IP_TRACKNUMBER")
  if not ref_num or ref_num < 1 then
    return nil, "Could not resolve position reference: " .. tostring(pos)
  end
  if dir == "before" then return math.max(0, ref_num - 1) end
  return math.min(count, ref_num)
end

local function _typed_action_apply_track_color(api, tr, color)
  if not color then return true end
  local r, g, b = tostring(color):match("^#(%x%x)(%x%x)(%x%x)$")
  if not r then
    return false, "Only #RRGGBB track colors are supported"
  end
  local native = api.ColorToNative(tonumber(r, 16), tonumber(g, 16),
    tonumber(b, 16)) | 0x1000000
  api.SetTrackColor(tr, native)
  return true
end

local function _typed_action_send_mode(mode)
  if mode == nil then return nil, nil end
  if type(mode) == "number" then return mode, nil end
  local m = tostring(mode):lower():gsub("%s+", "_"):gsub("%-", "_")
  local map = {
    post_fader = 0,
    post_fader_post_pan = 0,
    pre_fx = 1,
    pre_fader = 3,
    post_fx = 3,
  }
  if map[m] == nil then return nil, "Unsupported send mode: " .. tostring(mode) end
  return map[m], nil
end

local function _typed_action_error_result(code, path, message, result)
  return false, {
    code = code or "execution_error",
    path = path or "$",
    message = message or "Structured edit failed",
    result = result,
  }
end

function Code.typed_actions_user_failure_message(exec_result)
  local code = exec_result and exec_result.code or "execution_failed"
  local detail = exec_result and exec_result.message or nil
  local result = exec_result and exec_result.result or nil
  local changed = type(result) == "table"
    and type(result.action_results) == "table"
    and #result.action_results > 0
  if code == "executor_disabled" then
    return Code.typed_actions_executor_disabled_message()
  end
  if code == "invalid_json" or code == "missing_action_block"
     or code == "invalid_plan" or code == "semantic_mismatch" then
    local msg = "I blocked this structured edit before it changed the project because the plan did not match the request safely. No changes were made."
    if detail and detail ~= "" then msg = msg .. " Details: " .. tostring(detail) end
    return msg
  end
  if changed then
    local msg = "Structured edit failed after making part of the change. ReaAssist stopped immediately; use REAPER Undo if the project is not in the state you want."
    if detail and detail ~= "" then msg = msg .. " Details: " .. tostring(detail) end
    return msg
  end
  local msg = "Structured edit failed before it changed the project. No changes were made."
  if detail and detail ~= "" then msg = msg .. " Details: " .. tostring(detail) end
  return msg
end

function Code.execute_typed_actions_plan(plan, opts)
  opts = opts or {}
  local api = opts.reaper or reaper
  local result = {
    executed = false,
    completed = false,
    deferred = false,
    op_counts = _typed_action_count_ops(plan),
    action_results = {},
  }

  if not opts.allow_dev_executor and not Code.typed_actions_executor_enabled() then
    return _typed_action_error_result("executor_disabled", "$",
      Code.typed_actions_executor_disabled_message(), result)
  end

  if type(api) ~= "table" then
    return _typed_action_error_result("executor_unavailable", "$",
      "REAPER API table is unavailable", result)
  end

  local valid, validation_errors = _typed_action_executor_validate(plan)
  if not valid then
    result.validation_errors = validation_errors
    return _typed_action_error_result("invalid_plan", "$",
      "Typed action plan failed executor validation", result)
  end
  local folder_depth_plan, folder_depth_errors =
    Code._typed_action_folder_depth_plan(plan)
  if folder_depth_errors and #folder_depth_errors > 0 then
    result.validation_errors = folder_depth_errors
    return _typed_action_error_result("invalid_plan", "$",
      "Typed action folder plan failed executor validation", result)
  end

  local tracks, fx_by_id, param_actions = {}, {}, {}
  local undo_open, refresh_open = false, false

  local function close_block(label, flags)
    if refresh_open then
      pcall(api.PreventUIRefresh, -1)
      refresh_open = false
    end
    if type(api.TrackList_AdjustWindows) == "function" then
      pcall(api.TrackList_AdjustWindows, false)
    end
    if type(api.UpdateArrange) == "function" then pcall(api.UpdateArrange) end
    if undo_open then
      pcall(api.Undo_EndBlock, label or "ReaAssist: typed actions", flags or -1)
      undo_open = false
    end
  end

  local function fail(code, path, message)
    close_block("ReaAssist: typed actions failed", -1)
    local msg = "Structured edit failed: " .. tostring(message)
    if type(Log) == "table" and type(Log.add_error) == "function" then
      Log.add_error(msg)
    end
    if type(api.ShowMessageBox) == "function" then
      pcall(api.ShowMessageBox, msg, "ReaAssist", 0)
    end
    return _typed_action_error_result(code, path, message, result)
  end

  local function complete(ok, done_result)
    result.completed = true
    result.executed = ok == true
    if type(opts.on_done) == "function" then
      local cb_ok, cb_err = pcall(opts.on_done, ok == true,
        done_result or { result = result })
      if not cb_ok and type(Log) == "table"
         and type(Log.add_error) == "function" then
        Log.add_error("Structured edit completion callback failed: "
          .. tostring(cb_err))
      end
    end
  end

  api.Undo_BeginBlock()
  undo_open = true
  api.PreventUIRefresh(1)
  refresh_open = true

  for i, action in ipairs(plan.actions or {}) do
    local path = "$.actions[" .. tostring(i) .. "]"
    local op = action.op
    if op == "track.ensure" then
      local existing = _typed_action_find_existing_track(api, action.name)
      local tr
      if #existing > 1 then
        return fail("ambiguous_track", path .. ".name",
          "Multiple existing tracks are named " .. tostring(action.name))
      elseif #existing == 1 then
        tr = existing[1]
      else
        local idx, pos_err = _typed_action_track_insert_index(api, action, tracks)
        if not idx then return fail("unknown_ref", path .. ".position", pos_err) end
        api.InsertTrackAtIndex(idx, true)
        tr = api.GetTrack(0, idx)
        if not tr then
          return fail("track_create_failed", path,
            "Could not create track " .. tostring(action.name))
        end
      end
      api.GetSetMediaTrackInfo_String(tr, "P_NAME", action.name, true)
      local color_ok, color_err = _typed_action_apply_track_color(api, tr, action.color)
      if not color_ok then return fail("unsupported_color", path .. ".color", color_err) end
      if action.select == true then
        api.SetTrackSelected(tr, true)
      end
      tracks[action.id] = tr
      result.action_results[#result.action_results+1] = {
        op = op, id = action.id, status = "ok"
      }

    elseif op == "track.resolve" then
      local tr, code, err = Code._typed_action_resolve_existing_track(api, action)
      if not tr then
        return fail(code or "track_resolve_failed", path,
          err or ("Could not resolve track " .. tostring(action.id)))
      end
      tracks[action.id] = tr
      result.action_results[#result.action_results+1] = {
        op = op, id = action.id, status = "ok"
      }

    elseif op == "track.set" then
      local tr = tracks[action.track]
      if not tr then
        return fail("unknown_ref", path .. ".track",
          "Unknown track id " .. tostring(action.track))
      end
      if action.name ~= nil then
        api.GetSetMediaTrackInfo_String(tr, "P_NAME", action.name, true)
      end
      if action.volume_db ~= nil then
        api.SetMediaTrackInfo_Value(tr, "D_VOL",
          _typed_action_db_to_amp(action.volume_db))
      end
      if action.pan_pct ~= nil then
        api.SetMediaTrackInfo_Value(tr, "D_PAN", action.pan_pct / 100)
      end
      if action.mute ~= nil then
        api.SetMediaTrackInfo_Value(tr, "B_MUTE", action.mute and 1 or 0)
      end
      if action.solo ~= nil then
        api.SetMediaTrackInfo_Value(tr, "I_SOLO", action.solo and 1 or 0)
      end
      if action.master_send ~= nil then
        api.SetMediaTrackInfo_Value(tr, "B_MAINSEND",
          action.master_send and 1 or 0)
      end
      result.action_results[#result.action_results+1] = {
        op = op, id = action.track, status = "ok"
      }

    elseif op == "track.folder" then
      result.action_results[#result.action_results+1] = {
        op = op, id = action.parent, status = "ok"
      }

    elseif op == "fx.add_stock" then
      local tr = tracks[action.track]
      if not tr then
        return fail("unknown_ref", path .. ".track",
          "Unknown track id " .. tostring(action.track))
      end
      local fx = api.TrackFX_AddByName(tr, action.fx, false, -1)
      if not fx or fx < 0 then
        return fail("fx_add_failed", path .. ".fx",
          "Could not add " .. tostring(action.fx))
      end
      fx_by_id[action.id] = { track = tr, fx = fx, fx_name = action.fx }
      result.action_results[#result.action_results+1] = {
        op = op, id = action.id, status = "ok"
      }

    elseif op == "fx.set_param" then
      param_actions[#param_actions+1] = { action = action, path = path }

    elseif op == "send.create" then
      local src, dst = tracks[action["from"]], tracks[action.to]
      if not src then
        return fail("unknown_ref", path .. ".from",
          "Unknown source track id " .. tostring(action["from"]))
      end
      if not dst then
        return fail("unknown_ref", path .. ".to",
          "Unknown destination track id " .. tostring(action.to))
      end
      local sidx = api.CreateTrackSend(src, dst)
      if not sidx or sidx < 0 then
        return fail("send_create_failed", path,
          "Could not create send " .. tostring(action.id))
      end
      if action.volume_db ~= nil then
        api.SetTrackSendInfo_Value(src, 0, sidx, "D_VOL",
          _typed_action_db_to_amp(action.volume_db))
      end
      if action.pan ~= nil then
        api.SetTrackSendInfo_Value(src, 0, sidx, "D_PAN", action.pan)
      end
      if action.muted ~= nil then
        api.SetTrackSendInfo_Value(src, 0, sidx, "B_MUTE",
          action.muted and 1 or 0)
      end
      if action.mode ~= nil then
        local mode, mode_err = _typed_action_send_mode(action.mode)
        if mode == nil then return fail("unsupported_send_mode", path .. ".mode", mode_err) end
        api.SetTrackSendInfo_Value(src, 0, sidx, "I_SENDMODE", mode)
      end
      result.action_results[#result.action_results+1] = {
        op = op, id = action.id, status = "ok"
      }
    end
  end

  for _, track_id in ipairs((folder_depth_plan and folder_depth_plan.order) or {}) do
    local tr = tracks[track_id]
    if not tr then
      return fail("unknown_ref", "$.actions",
        "Unknown folder track id " .. tostring(track_id))
    end
    api.SetMediaTrackInfo_Value(tr, "I_FOLDERDEPTH",
      folder_depth_plan.depths[track_id] or 0)
  end

  local function apply_params_and_close()
    local ok, err = xpcall(function()
      for _, item in ipairs(param_actions) do
        local action, path = item.action, item.path
        local fx_ref = fx_by_id[action.fx]
        if not fx_ref then error(path .. ": unknown FX id " .. tostring(action.fx)) end
        local setters = assert(_typed_action_param_setters(
          fx_ref.fx_name, action.params, path))
        for _, setter in ipairs(setters) do
          if setter.method == "raw" then
            api.TrackFX_SetParam(fx_ref.track, fx_ref.fx, setter.index, setter.value)
          else
            api.TrackFX_SetParamNormalized(fx_ref.track, fx_ref.fx,
              setter.index, setter.value)
          end
        end
        result.action_results[#result.action_results+1] = {
          op = action.op, id = action.fx, status = "ok"
        }
      end
    end, debug and debug.traceback or tostring)
    if not ok then
      close_block("ReaAssist: typed actions failed", -1)
      local msg = "Structured edit parameter write failed: " .. tostring(err)
      if type(Log) == "table" and type(Log.add_error) == "function" then
        Log.add_error(msg)
      end
      if type(api.ShowMessageBox) == "function" then
        pcall(api.ShowMessageBox, msg, "ReaAssist", 0)
      end
      local _, err_result = _typed_action_error_result(
        "param_write_failed", "$.actions", tostring(err), result)
      complete(false, err_result)
      return
    end
    close_block("ReaAssist: typed actions", -1)
    complete(true, { result = result })
  end

  if #param_actions > 0 then
    result.deferred = true
    if type(api.defer) ~= "function" then
      return fail("defer_unavailable", "$.actions",
        "REAPER defer API is unavailable")
    end
    local defer_ok, defer_err = pcall(api.defer, apply_params_and_close)
    if not defer_ok then
      return fail("defer_failed", "$.actions", tostring(defer_err))
    end
  else
    close_block("ReaAssist: typed actions", -1)
    complete(true, { result = result })
  end

  return true, result
end

function Code.execute_typed_actions_from_text(text, opts)
  opts = type(opts) == "table" and opts or {}
  local plan, errors = Code.typed_actions_plan_from_text(text, opts)
  if not plan then
    local code = _typed_action_first_error_code(errors)
    local result_code = (code == "invalid_json" or code == "invalid_json_shape")
      and "invalid_json" or "missing_action_block"
    return _typed_action_error_result(result_code, "$",
      code or "No reaassist-actions block found", nil)
  end
  local semantic_ok, semantic_errors = Code.validate_typed_actions_semantics(
    plan, {
      profile = opts.profile,
      user_text = opts.user_text or "",
    })
  if not semantic_ok then
    return _typed_action_error_result("semantic_mismatch", "$.actions",
      Code.format_typed_action_semantic_errors(semantic_errors, 4), nil)
  end
  return Code.execute_typed_actions_plan(plan, opts)
end

function Code.inspect_typed_actions(text, opts)
  opts = type(opts) == "table" and opts or {}
  local metrics = {
    present = false,
    valid = false,
    executed = false,
    fallback_to_lua = false,
    raw_json = false,
    retry_count = 0,
    error = nil,
    op_counts = _typed_action_blank_op_counts(),
  }

  if opts.allow_raw_json then
    local raw_json = _typed_action_trim(text)
    if raw_json:sub(1, 1) == "{" then
      metrics.present = true
      metrics.raw_json = true
      local plan, parse_errors = Code.parse_typed_actions_block(raw_json)
      if not plan then
        metrics.error = _typed_action_first_error_code(parse_errors) or "invalid_json"
        return metrics
      end
      Code.repair_typed_actions_plan(plan, opts)
      metrics.op_counts = _typed_action_count_ops(plan)
      local valid, validate_errors = Code.validate_typed_actions_plan(plan)
      if not valid then
        metrics.error = _typed_action_first_error_code(validate_errors) or "invalid_plan"
        return metrics
      end
      metrics.valid = true
      return metrics
    end
  end

  local raw, extract_errors = Code.extract_typed_actions(text)
  if not raw then
    if extract_errors and #extract_errors > 0 then
      metrics.present = true
      metrics.error = _typed_action_first_error_code(extract_errors)
    end
    return metrics
  end

  metrics.present = true
  local plan, parse_errors = Code.parse_typed_actions_block(raw)
  if not plan then
    metrics.error = _typed_action_first_error_code(parse_errors) or "invalid_json"
    return metrics
  end

  Code.repair_typed_actions_plan(plan, opts)
  metrics.op_counts = _typed_action_count_ops(plan)
  local valid, validate_errors = Code.validate_typed_actions_plan(plan)
  if not valid then
    metrics.error = _typed_action_first_error_code(validate_errors) or "invalid_plan"
    return metrics
  end

  metrics.valid = true
  return metrics
end
end -- close typed action validator scope

-- =============================================================================
-- Code safety: risky-call scanner + execution gate
-- =============================================================================
-- Code.find_unknown_reaper_calls(lua_code) -> list of bad names, or nil
-- =============================================================================
-- Pre-flight validator that catches model-emitted reaper.X calls where X
-- isn't a real function on this user's machine. Complements the docs-gate
-- (which auto-fetches docs when the model wrote reaper.* without docs in
-- context); this fires AFTER the docs-gate, on the case where docs IS
-- pinned but the model still hallucinated a function name.
--
-- Source of truth is the live `reaper` table (introspected once per session
-- via _valid_reaper_fns), not the curated docs file -- the curated docs is
-- a small subset (~150 functions) of REAPER's full ~3000-function API plus
-- whatever extensions the user has installed (SWS, JS_ReaScriptAPI, BR_,
-- CF_, etc.). Validating against docs would flag tons of legitimate calls.
-- Validating against the live table flags exactly the calls that would
-- fail at runtime on this machine.
--
-- Common failure mode caught: weaker models (Gemini Flash 3, Kimi k2.6,
-- smaller Claude variants) sometimes emit plausible-sounding but
-- non-existent names like "GetProjectMarkerByIndex" (real function is
-- "EnumProjectMarkers") even when docs is pinned. The runtime sandbox
-- catches these as "attempt to call a nil value" but the user sees a
-- crash instead of a corrected reply.
local _valid_reaper_fns_cache = nil
local function _valid_reaper_fns()
  if _valid_reaper_fns_cache then return _valid_reaper_fns_cache end
  local t, count = {}, 0
  for k, v in pairs(reaper) do
    if type(v) == "function" then
      t[k] = true
      count = count + 1
    end
  end
  _valid_reaper_fns_cache = t
  -- One-shot proof-of-life log: confirms the validator was loaded and
  -- shows how many functions REAPER + installed extensions exposed on
  -- this user's machine. Only fires once per session (subsequent calls
  -- hit the cache and return immediately above).
  Log.line("API-VALIDATOR",
    "cache built: " .. count .. " reaper.* functions available")
  return t
end

function Code.find_unknown_reaper_calls(lua_code)
  if not lua_code or lua_code == "" then return nil, 0 end
  -- Strip line comments first so "-- reaper.Foo described below" can't
  -- false-positive. Block comments (--[[...]]) are rare in generated code
  -- and not worth the complexity to handle.
  local stripped = lua_code:gsub("%-%-[^\n]*", "")
  local valid = _valid_reaper_fns()
  local seen, unknown = {}, {}
  local total = 0
  for name in stripped:gmatch("reaper%.([%w_]+)") do
    total = total + 1
    if not valid[name] and not seen[name] then
      seen[name] = true
      unknown[#unknown+1] = name
    end
  end
  if #unknown == 0 then return nil, total end
  table.sort(unknown)
  return unknown, total
end

-- =============================================================================
-- Code.find_unverified_main_oncommand_ids
-- =============================================================================
-- Main_OnCommand(command_id, 0) is a sharp edge: any integer is syntactically
-- valid, so the API validator cannot tell whether the model picked the right
-- REAPER action. We only allow literal numeric IDs from the small documented
-- common-action list, or IDs the user explicitly typed in the request. Other
-- native actions should be implemented with direct API calls where possible,
-- or the model should ask the user to confirm the exact Action List ID.

function Code.find_unverified_main_oncommand_ids(lua_code, user_text)
  if not lua_code or lua_code == "" then return nil end
  local common = {
    [1007] = true, [1008] = true, [1013] = true, [1016] = true,
    [40044] = true, [40073] = true,

    [40029] = true, [40030] = true, [40026] = true, [40012] = true,
    [40061] = true, [40362] = true, [40548] = true, [40006] = true,
    [40057] = true, [40058] = true, [40698] = true, [40434] = true,
    [40033] = true, [40123] = true, [40719] = true,

    [40001] = true, [40005] = true, [40062] = true, [40297] = true,
    [40296] = true,

    [40020] = true, [40635] = true, [40626] = true, [40364] = true,
    [40769] = true,
  }
  local function user_text_mentions_action_id(id)
    local text = tostring(user_text or "")
    id = tostring(id or "")
    if id == "" then return false end
    local pos = 1
    while true do
      local s, e = text:find(id, pos, true)
      if not s then return false end
      local before = s > 1 and text:sub(s - 1, s - 1) or ""
      local after = e < #text and text:sub(e + 1, e + 1) or ""
      if not before:match("%d") and not after:match("%d") then
        return true
      end
      pos = e + 1
    end
  end
  local seen, bad = {}, {}
  local line_no = 0
  for raw_line in (lua_code .. "\n"):gmatch("([^\n]*)\n") do
    line_no = line_no + 1
    local line = raw_line:gsub("%-%-[^\n]*", "")
    for _, fn in ipairs({ "Main_OnCommand", "Main_OnCommandEx" }) do
      local pattern = "reaper%." .. fn .. "%s*%(%s*([+-]?%d+)"
      for id_text in line:gmatch(pattern) do
        local id = tonumber(id_text)
        if id and not common[id]
           and not user_text_mentions_action_id(id) then
          local key = fn .. ":" .. tostring(id)
          if not seen[key] then
            seen[key] = true
            bad[#bad + 1] = { fn = fn, id = id, line = line_no }
          end
        end
      end
    end
  end
  if #bad == 0 then return nil end
  table.sort(bad, function(a, b)
    if a.id ~= b.id then return a.id < b.id end
    return a.fn < b.fn
  end)
  return bad
end

-- =============================================================================
-- Code.find_audio_accessor_transient_marker_scripts
-- =============================================================================
-- A simple Lua peak/energy detector is much worse than REAPER's Dynamic Split
-- for "every hit" drum/transient stretch-marker work: it tends to mark decays
-- and bleed as hits. For that intent, block scripts that combine audio-accessor
-- scanning with direct stretch-marker insertion unless the user explicitly
-- asked for a custom/approximate threshold detector.
function Code.find_audio_accessor_transient_marker_scripts(lua_code, user_text)
  if not lua_code or lua_code == "" then return nil end
  local prompt = tostring(user_text or ""):lower()
  local prompt_names_drum_source =
       prompt:find("%f[%w]drum%f[%W]")
    or prompt:find("%f[%w]drums%f[%W]")
    or prompt:find("%f[%w]kick%f[%W]")
    or prompt:find("%f[%w]snare%f[%W]")
    or prompt:find("guide track", 1, true)
  local prompt_names_drum_edit =
       prompt:find("%f[%w]quantiz")
    or prompt:find("%f[%w]edit")
    or prompt:find("%f[%w]tighten")
    or prompt:find("%f[%w]sync")
    or prompt:find("%f[%w]transient")
    or prompt:find("%f[%w]hit%f[%W]")
    or prompt:find("%f[%w]hits%f[%W]")
    or prompt:find("stretch marker", 1, true)
  local drum_edit_intent =
       CTX
   and CTX.prompt_indicates_drum_edit
   and CTX.prompt_indicates_drum_edit(prompt)
    or (prompt_names_drum_source and prompt_names_drum_edit)
  local wants_markers =
       prompt:find("stretch marker", 1, true)
    or prompt:find("stretch%-marker")
    or drum_edit_intent
  if not wants_markers then return nil end
  local wants_hits =
       prompt:find("%f[%w]hit%f[%W]")
    or prompt:find("%f[%w]hits%f[%W]")
    or prompt:find("%f[%w]transient%f[%W]")
    or prompt:find("%f[%w]transients%f[%W]")
    or prompt:find("%f[%w]drum%f[%W]")
    or prompt:find("%f[%w]drums%f[%W]")
    or prompt:find("%f[%w]kick%f[%W]")
    or prompt:find("%f[%w]snare%f[%W]")
    or drum_edit_intent
  if not wants_hits then return nil end
  local explicitly_custom =
       prompt:find("%f[%w]custom%f[%W]")
    or prompt:find("%f[%w]approximate%f[%W]")
    or prompt:find("%f[%w]approximation%f[%W]")
    or prompt:find("%f[%w]threshold%f[%W]")
    or prompt:find("%f[%w]energy%f[%W]")
  if explicitly_custom then return nil end

  local stripped = lua_code:gsub("%-%-[^\n]*", "")
  if not stripped:find("reaper%.GetAudioAccessorSamples", 1, false) then
    return nil
  end
  if not stripped:find("reaper%.SetTakeStretchMarker", 1, false) then
    return nil
  end
  local findings = {}
  local line_no = 0
  for raw_line in (lua_code .. "\n"):gmatch("([^\n]*)\n") do
    line_no = line_no + 1
    local line = raw_line:gsub("%-%-[^\n]*", "")
    if line:find("reaper%.GetAudioAccessorSamples", 1, false)
       or line:find("reaper%.SetTakeStretchMarker", 1, false) then
      findings[#findings + 1] = { line = line_no }
    end
  end
  return #findings > 0 and findings or { { line = 1 } }
end

-- =============================================================================
-- Code.find_drum_whole_item_quantize_scripts
-- =============================================================================
-- Drum quantize should move hit timing inside the drum items (normally shared
-- stretch markers from explicit guide tracks), not treat media-item starts as
-- drum hits. A whole-item D_POSITION script can pass validation, report "moved"
-- counts, and still do nothing audible if the item starts are already on-grid.
function Code.find_drum_whole_item_quantize_scripts(lua_code, user_text)
  if not lua_code or lua_code == "" then return nil end
  local prompt = tostring(user_text or ""):lower()
  local has_drum =
       prompt:find("%f[%w]drum%f[%W]")
    or prompt:find("%f[%w]drums%f[%W]")
  if not has_drum then return nil end
  local timing_intent =
       prompt:find("%f[%w]quantiz")
    or prompt:find("%f[%w]tighten")
    or prompt:find("%f[%w]transient")
    or prompt:find("%f[%w]snap%f[%W]")
    or prompt:find("stretch marker", 1, true)
    or prompt:find("guide track", 1, true)
    or prompt:find("edit drums", 1, true)
    or prompt:find("editing drums", 1, true)
  if not timing_intent then return nil end
  local explicitly_whole_item =
       prompt:find("move whole item", 1, true)
    or prompt:find("move whole media item", 1, true)
    or prompt:find("move the items", 1, true)
    or prompt:find("move item starts", 1, true)
  if explicitly_whole_item then return nil end

  local stripped = lua_code:gsub("%-%-[^\n]*", "")
  if not stripped:find("reaper%.SetMediaItemInfo_Value", 1, false)
     or not stripped:find("[\"']D_POSITION[\"']") then
    return nil
  end
  if stripped:find("reaper%.SetTakeStretchMarker", 1, false) then
    return nil
  end

  local findings = {}
  local line_no = 0
  for raw_line in (lua_code .. "\n"):gmatch("([^\n]*)\n") do
    line_no = line_no + 1
    local line = raw_line:gsub("%-%-[^\n]*", "")
    if line:find("reaper%.SetMediaItemInfo_Value", 1, false)
       and line:find("[\"']D_POSITION[\"']") then
      findings[#findings + 1] = { line = line_no }
    end
  end
  return #findings > 0 and findings or { { line = 1 } }
end

-- Drum stretch-marker quantize must normalize every affected item to the same
-- marker set. If a script adds/moves stretch markers without deleting/replacing
-- the range first, guide tracks can keep Dynamic Split-only markers while the
-- rest of the kit gets a different map.
function Code.find_unsynced_drum_stretch_marker_scripts(lua_code, user_text)
  if not lua_code or lua_code == "" then return nil end
  local prompt = tostring(user_text or ""):lower()
  local has_drum =
       prompt:find("%f[%w]drum%f[%W]")
    or prompt:find("%f[%w]drums%f[%W]")
  if not has_drum then return nil end
  local timing_intent =
       prompt:find("%f[%w]quantiz")
    or prompt:find("%f[%w]tighten")
    or prompt:find("%f[%w]transient")
    or prompt:find("%f[%w]snap%f[%W]")
    or prompt:find("stretch marker", 1, true)
    or prompt:find("guide track", 1, true)
    or prompt:find("edit drums", 1, true)
    or prompt:find("editing drums", 1, true)
  if not timing_intent then return nil end
  local explicit_existing =
       prompt:find("existing stretch marker", 1, true)
    or prompt:find("existing markers", 1, true)
    or prompt:find("already has stretch marker", 1, true)
    or prompt:find("already have stretch marker", 1, true)
  if explicit_existing then return nil end

  local stripped = lua_code:gsub("%-%-[^\n]*", "")
  if not stripped:find("reaper%.SetTakeStretchMarker", 1, false) then
    return nil
  end
  if stripped:find("reaper%.DeleteTakeStretchMarkers", 1, false) then
    return nil
  end

  local findings = {}
  local line_no = 0
  for raw_line in (lua_code .. "\n"):gmatch("([^\n]*)\n") do
    line_no = line_no + 1
    local line = raw_line:gsub("%-%-[^\n]*", "")
    if line:find("reaper%.SetTakeStretchMarker", 1, false) then
      findings[#findings + 1] = { line = line_no }
    end
  end
  return #findings > 0 and findings or { { line = 1 } }
end

-- =============================================================================
-- Code.find_reaper_arity_mismatches
-- =============================================================================
-- Conservative fixed-arity check for high-confidence param-write calls. The
-- API validator above only checks that NAMES exist; a bug like
-- `reaper.TrackFX_SetParamNormalized(tr, fx, best_v)` (3 args, missing pidx)
-- passes the name check but crashes at runtime inside reaper.defer with
-- "bad argument #3 ... (number has no integer representation)" because
-- best_v (a float) lands in the integer pidx slot. Caught in a Gemini
-- session where the model pasted set_param_display but corrupted the
-- final setter call.
--
-- Scope is intentionally narrow -- only fixed-arity functions where every
-- documented signature has the same arg count, and where the args are
-- always positional (no optional trailing varargs that would produce false
-- positives). Adding a name here is opting it into the strict check; do
-- not add unless every real call site uses the same fixed count.
local _REAPER_FIXED_ARITY = {
  TrackFX_SetParamNormalized      = 4,
  TakeFX_SetParamNormalized       = 4,
  TrackFX_SetParam                = 4,
  TakeFX_SetParam                 = 4,
  TrackFX_GetParamNormalized      = 3,
  TakeFX_GetParamNormalized       = 3,
  TrackFX_GetFormattedParamValue  = 4,
  TakeFX_GetFormattedParamValue   = 4,
  GetTrackSendInfo_Value          = 4,
  SetTrackSendInfo_Value          = 5,
  TrackList_AdjustWindows         = 1,
}

function Code.find_reaper_arity_mismatches(lua_code)
  if not lua_code or lua_code == "" then return nil end
  local stripped = lua_code:gsub("%-%-[^\n]*", "")
  local seen, mismatches = {}, {}
  local pos = 1
  while true do
    local _ms, me, name = stripped:find("reaper%.([%w_]+)%s*%(", pos)
    if not me then break end
    local expected = _REAPER_FIXED_ARITY[name]
    if expected then
      -- Walk forward from me (the open paren) tracking bracket depth +
      -- string state. Comma at depth==1 separates top-level args.
      -- (), {}, [] all increment/decrement depth so a nested table
      -- literal `{1, 2, 3}` doesn't add false top-level commas.
      local depth, args = 1, 0
      local i = me + 1
      local in_str = nil  -- nil, '"', or "'"
      local saw_content = false
      while i <= #stripped do
        local c = stripped:sub(i, i)
        if in_str then
          if c == "\\" then
            i = i + 2  -- skip escape sequence
          else
            if c == in_str then in_str = nil end
            i = i + 1
          end
        else
          if c == '"' or c == "'" then
            in_str = c; saw_content = true
          elseif c == "(" or c == "[" or c == "{" then
            depth = depth + 1; saw_content = true
          elseif c == ")" or c == "]" or c == "}" then
            depth = depth - 1
            if depth == 0 then break end
          elseif c == "," and depth == 1 then
            args = args + 1
          elseif not c:match("%s") then
            saw_content = true
          end
          i = i + 1
        end
      end
      if depth == 0 then
        local got = saw_content and (args + 1) or 0
        if got ~= expected then
          local key = name .. ":" .. got
          if not seen[key] then
            seen[key] = true
            mismatches[#mismatches+1] =
              { name = name, expected = expected, got = got }
          end
        end
      end
    end
    pos = me + 1
  end
  if #mismatches == 0 then return nil end
  table.sort(mismatches, function(a, b)
    if a.name ~= b.name then return a.name < b.name end
    return a.got < b.got
  end)
  return mismatches
end

-- =============================================================================
-- Code.find_untracked_createtracksend_results
-- =============================================================================
-- CreateTrackSend returns the new send index. When a script creates multiple
-- sends from the same source track and then sets send properties using literal
-- indices (0/1/2), it can silently set the wrong send if REAPER orders sends
-- differently than the model assumed. Keep this intentionally narrow: only
-- flag standalone CreateTrackSend calls whose return value is ignored, paired
-- with later SetTrackSendInfo_Value calls on the same source track that use
-- hard-coded numeric send indices.
function Code.find_untracked_createtracksend_results(lua_code)
  if not lua_code or lua_code == "" then return nil end
  local stripped = lua_code:gsub("%-%-[^\n]*", "")

  local function line_for_pos(pos)
    local line = 1
    for _ in stripped:sub(1, pos):gmatch("\n") do line = line + 1 end
    return line
  end

  local function normalize_arg(v)
    return tostring(v or ""):gsub("%s+", "")
  end

  local function parse_args(open_pos)
    local args, field = {}, {}
    local depth = 1
    local i = open_pos + 1
    local in_str = nil
    while i <= #stripped do
      local c = stripped:sub(i, i)
      if in_str then
        field[#field + 1] = c
        if c == "\\" then
          i = i + 1
          if i <= #stripped then field[#field + 1] = stripped:sub(i, i) end
        elseif c == in_str then
          in_str = nil
        end
      else
        if c == '"' or c == "'" then
          in_str = c
          field[#field + 1] = c
        elseif c == "(" or c == "[" or c == "{" then
          depth = depth + 1
          field[#field + 1] = c
        elseif c == ")" or c == "]" or c == "}" then
          depth = depth - 1
          if depth == 0 then
            args[#args + 1] = table.concat(field):match("^%s*(.-)%s*$") or ""
            return args
          end
          field[#field + 1] = c
        elseif c == "," and depth == 1 then
          args[#args + 1] = table.concat(field):match("^%s*(.-)%s*$") or ""
          field = {}
        else
          field[#field + 1] = c
        end
      end
      i = i + 1
    end
    return nil
  end

  local violations, seen = {}, {}
  local ignored_by_source = {}
  local assigned_sendidx = {}
  local pos = 1
  while true do
    local s, open_pos = stripped:find("reaper%.CreateTrackSend%s*%(", pos)
    if not s then break end
    local line_start = stripped:sub(1, s):match(".*()\n")
    line_start = line_start and (line_start + 1) or 1
    local prefix = stripped:sub(line_start, s - 1)
    local args = parse_args(open_pos)
    local lhs = prefix:match("^%s*local%s+(.+)%s*=%s*$")
      or prefix:match("^%s*(.-)%s*=%s*$")
    if lhs and lhs:find(",", 1, true) then
      local key = "multi_assign:" .. tostring(line_for_pos(s))
      if not seen[key] then
        seen[key] = true
        violations[#violations + 1] = {
          kind = "multi_assign",
          source = args and args[1] or "",
          sendidx = lhs,
          create_line = line_for_pos(s),
          set_line = line_for_pos(s),
        }
      end
    elseif prefix:match("^%s*$") then
      if args and args[1] and args[1] ~= "" then
        local src = normalize_arg(args[1])
        ignored_by_source[src] = ignored_by_source[src] or {}
        ignored_by_source[src][#ignored_by_source[src] + 1] = {
          pos = s,
          line = line_for_pos(s),
        }
      end
    elseif lhs then
      local var = lhs:match("^%s*([%a_][%w_]*)%s*$")
      if var and args and args[1] and args[1] ~= "" then
        assigned_sendidx[var] = {
          source = args[1],
          create_line = line_for_pos(s),
        }
      end
    end
    pos = open_pos + 1
  end

  for var, create in pairs(assigned_sendidx) do
    local esc = var:gsub("([^%w_])", "%%%1")
    local bad_s, bad_e = stripped:find("%f[%w_]if%s+[^%n]-" .. esc
      .. "%s*~=%s*0%f[^%w_]")
    if not bad_s then
      bad_s, bad_e = stripped:find("%f[%w_]if%s+[^%n]-" .. esc
        .. "%s*>%s*0%f[^%w_]")
    end
    if bad_s and create.create_line and line_for_pos(bad_s) >= create.create_line then
      local key = "zero_check:" .. tostring(var) .. ":" .. tostring(line_for_pos(bad_s))
      if not seen[key] then
        seen[key] = true
        violations[#violations + 1] = {
          kind = "zero_check",
          source = create.source,
          sendidx = var,
          create_line = create.create_line,
          set_line = line_for_pos(bad_s),
        }
      end
    end
  end

  pos = 1
  while true do
    local s, open_pos = stripped:find("reaper%.SetTrackSendInfo_Value%s*%(", pos)
    if not s then break end
    local args = parse_args(open_pos)
    if args and args[1] and args[3] then
      local src = normalize_arg(args[1])
      local creates = ignored_by_source[src]
      local sendidx = tostring(args[3]):match("^%s*(.-)%s*$") or ""
      if creates and sendidx:match("^%d+$") then
        local risky = tonumber(sendidx) ~= 0 or #creates > 1
        local follows_create = false
        local create_line = nil
        for _, c in ipairs(creates) do
          if c.pos < s then
            follows_create = true
            create_line = create_line or c.line
          end
        end
        if risky and follows_create then
          local key = src .. ":" .. sendidx
          if not seen[key] then
            seen[key] = true
            violations[#violations + 1] = {
              source = args[1],
              sendidx = sendidx,
              create_line = create_line,
              set_line = line_for_pos(s),
            }
          end
        end
      end
    end
    pos = open_pos + 1
  end

  if #violations == 0 then return nil end
  table.sort(violations, function(a, b)
    if a.set_line ~= b.set_line then return a.set_line < b.set_line end
    return tostring(a.source) < tostring(b.source)
  end)
  return violations
end

-- =============================================================================
-- Code.find_master_send_remove_misuse
-- =============================================================================
-- Master/parent send is not a normal send slot. Removing category 1 sends removes
-- hardware outputs; the master/parent send lives on B_MAINSEND.
function Code.prompt_requests_master_send_change(user_text)
  if Code._typed_action_user_requests_master_send_state
     and Code._typed_action_user_requests_master_send_state(user_text) then
    return true
  end
  local lt = tostring(user_text or ""):lower():gsub("%s+", " ")
  if lt == "" then return false end
  return lt:find("master send", 1, true) ~= nil
    or lt:find("master sends", 1, true) ~= nil
    or lt:find("main send", 1, true) ~= nil
    or lt:find("main sends", 1, true) ~= nil
    or lt:find("master/parent", 1, true) ~= nil
    or lt:find("master parent", 1, true) ~= nil
    or lt:find("parent send", 1, true) ~= nil
    or lt:find("parent sends", 1, true) ~= nil
    or lt:find("master output", 1, true) ~= nil
    or lt:find("master_send", 1, true) ~= nil
    or lt:find("going only to the master", 1, true) ~= nil
    or lt:find("only goes to master", 1, true) ~= nil
    or lt:find("only to the master", 1, true) ~= nil
end

function Code.find_master_send_remove_misuse(lua_code)
  if not lua_code or lua_code == "" then return nil end
  local stripped = lua_code
    :gsub("%-%-%[%[.-%]%]", "")
    :gsub("%-%-[^\n]*", "")

  local function line_for_pos(pos)
    local line = 1
    for _ in stripped:sub(1, pos):gmatch("\n") do line = line + 1 end
    return line
  end

  local one_vars = {}
  for name in stripped:gmatch("%f[%w_]local%s+([%a_][%w_]*)%s*=%s*1%f[^%w_]") do
    local ln = name:lower()
    if ln:find("master", 1, true)
        or ln:find("send", 1, true)
        or ln:find("cat", 1, true)
        or ln:find("category", 1, true) then
      one_vars[name] = true
    end
  end

  local violations, seen = {}, {}
  local pos = 1
  while true do
    local s, open_pos = stripped:find("reaper%.RemoveTrackSend%s*%(", pos)
    if not s then break end
    local depth, i = 1, open_pos + 1
    local field, args, in_str = {}, {}, nil
    while i <= #stripped do
      local c = stripped:sub(i, i)
      if in_str then
        field[#field + 1] = c
        if c == "\\" then
          i = i + 1
          if i <= #stripped then field[#field + 1] = stripped:sub(i, i) end
        elseif c == in_str then
          in_str = nil
        end
      else
        if c == '"' or c == "'" then
          in_str = c
          field[#field + 1] = c
        elseif c == "(" or c == "[" or c == "{" then
          depth = depth + 1
          field[#field + 1] = c
        elseif c == ")" or c == "]" or c == "}" then
          depth = depth - 1
          if depth == 0 then
            args[#args + 1] = table.concat(field):match("^%s*(.-)%s*$") or ""
            break
          end
          field[#field + 1] = c
        elseif c == "," and depth == 1 then
          args[#args + 1] = table.concat(field):match("^%s*(.-)%s*$") or ""
          field = {}
        else
          field[#field + 1] = c
        end
      end
      i = i + 1
    end
    local category = args[2] and args[2]:match("^%s*(.-)%s*$") or ""
    if category == "1" or one_vars[category] then
      local key = tostring(line_for_pos(s)) .. ":" .. category
      if not seen[key] then
        seen[key] = true
        violations[#violations + 1] = {
          line = line_for_pos(s),
          category = category,
        }
      end
    end
    pos = open_pos + 1
  end
  if #violations == 0 then return nil end
  return violations
end

function Code.prompt_requests_track_pan(user_text)
  local lt = tostring(user_text or ""):lower():gsub("%s+", " ")
  if lt == "" then return false end
  if lt:find("send pan", 1, true)
      or lt:find("pan the send", 1, true)
      or lt:find("pan send", 1, true) then
    return false
  end
  return lt:find("%f[%w]pan%f[%W]") ~= nil
    or lt:find("percent left", 1, true) ~= nil
    or lt:find("percent right", 1, true) ~= nil
end

function Code.find_track_pan_sent_as_send_pan(lua_code, user_text)
  if not lua_code or lua_code == "" then return nil end
  if not Code.prompt_requests_track_pan(user_text) then return nil end
  local stripped = lua_code
    :gsub("%-%-%[%[.-%]%]", "")
    :gsub("%-%-[^\n]*", "")
  if stripped:find("reaper%.SetMediaTrackInfo_Value%s*%([^%)]-[\"']D_PAN[\"']") then
    return nil
  end
  local violations = {}
  local function line_for_pos(pos)
    local line = 1
    for _ in stripped:sub(1, pos):gmatch("\n") do line = line + 1 end
    return line
  end
  local pos = 1
  while true do
    local s = stripped:find("reaper%.SetTrackSendInfo_Value%s*%([^%)]-[\"']D_PAN[\"']", pos)
    if not s then break end
    violations[#violations + 1] = { line = line_for_pos(s) }
    pos = s + 1
  end
  if #violations == 0 then return nil end
  return violations
end

-- =============================================================================
-- Code.prompt_requests_track_creation / Code.lua_creates_tracks
-- =============================================================================
-- Guard against syntactically valid but inert scripts where the user asked to
-- create tracks and the model merely renames existing track handles.
function Code.prompt_requests_track_creation(user_text)
  local lt = tostring(user_text or ""):lower()
  if lt == "" then return false end
  lt = lt:gsub("%s+", " ")
  local patterns = {
    "%f[%w]create%s+exactly%s+.-%f[%w]track%f[%W]",
    "%f[%w]create%s+exactly%s+.-%f[%w]tracks%f[%W]",
    "%f[%w]creates%s+exactly%s+.-%f[%w]track%f[%W]",
    "%f[%w]creates%s+exactly%s+.-%f[%w]tracks%f[%W]",
    "%f[%w]create%s+one%s+track%f[%W]",
    "%f[%w]creates%s+one%s+track%f[%W]",
    "%f[%w]create%s+a%s+track%f[%W]",
    "%f[%w]creates%s+a%s+track%f[%W]",
    "%f[%w]create%s+track%s+named%f[%W]",
    "%f[%w]creates%s+track%s+named%f[%W]",
    "%f[%w]create%s+tracks%s+named%f[%W]",
    "%f[%w]creates%s+tracks%s+named%f[%W]",
    "%f[%w]insert%s+a%s+track%f[%W]",
    "%f[%w]insert%s+tracks%s+named%f[%W]",
    "%f[%w]add%s+a%s+track%f[%W]",
    "%f[%w]add%s+tracks%s+named%f[%W]",
  }
  for _, pat in ipairs(patterns) do
    if lt:find(pat) then return true end
  end
  return false
end

function Code.lua_creates_tracks(lua_code)
  if not lua_code or lua_code == "" then return false end
  local stripped = lua_code
    :gsub("%-%-%[%[.-%]%]", "")
    :gsub("%-%-[^\n]*", "")
  if stripped:find("reaper%.InsertTrackAtIndex%s*%(") then return true end
  if stripped:find("reaper%.Main_OnCommand%s*%(%s*40001%s*,") then return true end
  return false
end

function Code.find_literal_gettrack_index_mismatches(lua_code, snapshot)
  if type(lua_code) ~= "string" or lua_code == "" then return nil end
  if type(snapshot) ~= "string" or snapshot == "" then return nil end
  local tracks = {}
  local track_count
  track_count = tonumber(snapshot:match("Tracks%s*%(%s*N%s*=%s*(%d+)%s*%)"))
  for line in snapshot:gmatch("[^\r\n]+") do
    local idx, name = line:match("^(%d+)|([^|]*)|")
    idx = tonumber(idx)
    if idx and name then
      tracks[#tracks + 1] = {
        display_idx = idx,
        api_idx = idx - 1,
        name = name,
        name_l = tostring(name):lower(),
      }
    end
  end
  if #tracks == 0 and not track_count then return nil end

  local violations = {}
  local line_no = 0
  for line in lua_code:gmatch("[^\r\n]+") do
    line_no = line_no + 1
    local line_l = line:lower()
    for idx_text in line:gmatch("reaper%.GetTrack%s*%(%s*0%s*,%s*(%d+)%s*%)") do
      local api_idx = tonumber(idx_text)
      local expected
      local reason
      if track_count and api_idx and api_idx >= track_count then
        expected = track_count > 0 and (track_count - 1) or 0
        reason = "out_of_range"
      end
      for _, tr in ipairs(tracks) do
        local mentions_track_number =
          line_l:find("%f[%w]track%s*" .. tostring(tr.display_idx) .. "%f[%W]") ~= nil
        local mentions_name = tr.name_l ~= "" and line_l:find(tr.name_l, 1, true) ~= nil
        if (mentions_track_number or mentions_name)
            and api_idx and api_idx ~= tr.api_idx then
          expected = tr.api_idx
          reason = mentions_name and "name_comment_mismatch"
            or "track_number_comment_mismatch"
          break
        end
      end
      if expected then
        violations[#violations + 1] = {
          line = line_no,
          api_idx = api_idx,
          expected_api_idx = expected,
          reason = reason,
          source = line:match("^%s*(.-)%s*$"),
        }
      end
    end
  end
  if #violations == 0 then return nil end
  return violations
end

function Code.find_track_creation_index_misuse(lua_code, user_text, snapshot)
  if type(lua_code) ~= "string" or lua_code == "" then return nil end
  if not Code.prompt_requests_track_creation(user_text) then return nil end
  local lt = tostring(user_text or ""):lower():gsub("%s+", " ")
  if lt:find("%f[%w]before%f[%W]")
      or lt:find("%f[%w]after%f[%W]")
      or lt:find("at position", 1, true)
      or lt:find("at track", 1, true)
      or lt:find("insert position", 1, true) then
    return nil
  end
  local track_count = nil
  if type(snapshot) == "string" then
    track_count = tonumber(snapshot:match("Tracks%s*%(%s*N%s*=%s*(%d+)%s*%)"))
  end
  if not track_count then track_count = 0 end

  local table_lengths = {}
  for var, body in lua_code:gmatch(
      "local%s+([%a_][%w_]*)%s*=%s*{%s*(.-)%s*}") do
    local count = 0
    for _ in body:gmatch("[\"'][^\"']+[\"']") do
      count = count + 1
    end
    if count > 0 then table_lengths[var] = count end
  end

  local violations = {}
  local line_no = 0
  local active_loop = nil
  local active_ensure_count = nil
  local ensure_counted = false
  for line in lua_code:gmatch("[^\r\n]+") do
    line_no = line_no + 1
    local ensure_count = line:match(
      "^%s*while%s+reaper%.CountTracks%s*%(%s*0%s*%)%s*<%s*(%d+)%s*do%s*$")
    if ensure_count then
      active_ensure_count = tonumber(ensure_count)
      ensure_counted = false
    end
    local loop_var, loop_first, loop_last = line:match(
      "^%s*for%s+([%a_][%w_]*)%s*=%s*(%d+)%s*,%s*(%d+)%s*do%s*$")
    if not loop_var then
      local len_var
      loop_var, loop_first, len_var = line:match(
        "^%s*for%s+([%a_][%w_]*)%s*=%s*(%d+)%s*,%s*#([%a_][%w_]*)%s*do%s*$")
      loop_last = len_var and table_lengths[len_var] or nil
    end
    if loop_var then
      active_loop = {
        var = loop_var,
        first = tonumber(loop_first),
        last = tonumber(loop_last),
        counted_insert = false,
      }
    end
    local insert_idx =
      tonumber(line:match("reaper%.InsertTrackAtIndex%s*%(%s*(%d+)%s*,"))
    if insert_idx then
      track_count = track_count + 1
    elseif active_loop and not active_loop.counted_insert
        and active_loop.first and active_loop.last
        and (line:find("reaper%.InsertTrackAtIndex%s*%(%s*"
          .. active_loop.var .. "%s*,")
          or line:find("reaper%.InsertTrackAtIndex%s*%(%s*"
            .. active_loop.var .. "%s*[%+%-]%s*%d+%s*,")) then
      track_count = track_count + math.abs(active_loop.last - active_loop.first) + 1
      active_loop.counted_insert = true
    elseif active_ensure_count and not ensure_counted
        and line:find("reaper%.InsertTrackAtIndex%s*%(%s*reaper%.CountTracks%s*%(%s*0%s*%)%s*,") then
      if active_ensure_count > track_count then
        track_count = active_ensure_count
      end
      ensure_counted = true
    end
    for idx_text in line:gmatch("reaper%.GetTrack%s*%(%s*0%s*,%s*(%d+)%s*%)") do
      local api_idx = tonumber(idx_text)
      if api_idx and api_idx >= track_count then
        violations[#violations + 1] = {
          line = line_no,
          api_idx = api_idx,
          expected_api_idx = track_count > 0 and (track_count - 1) or 0,
          reason = "created_track_out_of_range",
          source = line:match("^%s*(.-)%s*$"),
        }
      end
    end
    if active_loop and line:match("^%s*end%s*$") then
      active_loop = nil
    end
    if active_ensure_count and line:match("^%s*end%s*$") then
      active_ensure_count = nil
      ensure_counted = false
    end
  end
  if #violations == 0 then return nil end
  return violations
end

function Code.find_folder_child_boundary_misuse(lua_code, user_text)
  if type(lua_code) ~= "string" or lua_code == "" then return nil end
  local lt = tostring(user_text or ""):lower():gsub("%s+", " ")
  local child_text, parent_text =
    lt:match("make%s+(.+)%s+children%s+of%s+([^%.]+)")
  if not child_text or not parent_text then return nil end
  if not lua_code:find("I_FOLDERDEPTH", 1, true) then return nil end

  local function norm(s)
    s = tostring(s or ""):lower()
    s = s:gsub("^%s+", ""):gsub("%s+$", "")
    s = s:gsub("^the%s+", ""):gsub("%s+tracks?$", "")
    return s:gsub("%s+", " ")
  end

  child_text = child_text:gsub(",%s*and%s+", ",")
    :gsub("%s+and%s+", ",")
  local children, child_set = {}, {}
  for part in child_text:gmatch("[^,]+") do
    local child = norm(part)
    if child ~= "" then
      children[#children + 1] = child
      child_set[child] = true
    end
  end
  if #children == 0 then return nil end
  local last_child = children[#children]

  local ref_to_name = {}
  local name_to_ref = {}
  for ref, name in lua_code:gmatch(
      "reaper%.GetSetMediaTrackInfo_String%s*%(%s*([%w_%.%[%]]+)%s*,%s*[\"']P_NAME[\"']%s*,%s*[\"']([^\"']+)[\"']") do
    local normalized_name = norm(name)
    ref_to_name[ref] = normalized_name
    name_to_ref[normalized_name] = ref
  end
  local names_var = lua_code:match("local%s+([%a_][%w_]*)%s*=%s*{%s*[\"']")
  if names_var then
    local names_body = lua_code:match(
      "local%s+" .. names_var .. "%s*=%s*{%s*(.-)%s*}")
    local indexed_names = {}
    if names_body then
      for name in names_body:gmatch("[\"']([^\"']+)[\"']") do
        indexed_names[#indexed_names + 1] = norm(name)
      end
    end
    if #indexed_names > 0 then
      local active_loop = nil
      for line in lua_code:gmatch("[^\r\n]+") do
        local loop_var, first, last = line:match(
          "^%s*for%s+([%a_][%w_]*)%s*=%s*(%d+)%s*,%s*(%d+)%s*do%s*$")
        if loop_var then
          active_loop = {
            var = loop_var,
            first = tonumber(first),
            last = tonumber(last),
          }
        end
        if active_loop and active_loop.first and active_loop.last then
          local track_table, track_idx_var, name_idx_var = line:match(
            "reaper%.GetSetMediaTrackInfo_String%s*%(%s*([%a_][%w_]*)%[%s*([%a_][%w_]*)%s*%]%s*,%s*[\"']P_NAME[\"']%s*,%s*"
              .. names_var .. "%[%s*([%a_][%w_]*)%s*%+%s*1%s*%]")
          if track_table
              and track_idx_var == active_loop.var
              and name_idx_var == active_loop.var then
            local step = active_loop.first <= active_loop.last and 1 or -1
            local i = active_loop.first
            while true do
              local name = indexed_names[i - active_loop.first + 1]
              if name then
                local ref = track_table .. "[" .. tostring(i) .. "]"
                ref_to_name[ref] = name
                name_to_ref[name] = ref
              end
              if i == active_loop.last then break end
              i = i + step
            end
          end
        end
        if active_loop and line:match("^%s*end%s*$") then
          active_loop = nil
        end
      end
    end
  end
  if not next(ref_to_name) then return nil end

  local negative_by_name = {}
  local line_no = 0
  for line in lua_code:gmatch("[^\r\n]+") do
    line_no = line_no + 1
    local ref, depth = line:match(
      "reaper%.SetMediaTrackInfo_Value%s*%(%s*([%w_%.%[%]]+)%s*,%s*[\"']I_FOLDERDEPTH[\"']%s*,%s*(-?%d+)")
    depth = tonumber(depth)
    if ref and depth and depth < 0 then
      local name = ref_to_name[ref]
      if name then
        negative_by_name[name] = { line = line_no, depth = depth, ref = ref }
      end
    end
  end
  local last_child_close = negative_by_name[last_child]
  local violations = {}
  for name, info in pairs(negative_by_name) do
    if not child_set[name] then
      violations[#violations + 1] = {
        line = info.line,
        name = name,
        ref = info.ref,
        expected_name = last_child,
        expected_ref = name_to_ref[last_child],
        parent = norm(parent_text),
        reason = last_child_close and "outside_track_closes_folder"
          or "last_child_not_closed",
      }
    end
  end
  if #violations == 0 then return nil end
  return violations
end

function Code.repair_folder_child_boundary_misuse(lua_code, user_text)
  local findings = Code.find_folder_child_boundary_misuse(lua_code, user_text)
  if not findings or #findings == 0 then return lua_code, false, nil end
  local f = findings[1]
  if not f.ref or not f.expected_ref then return lua_code, false, findings end
  local function patt(s)
    return tostring(s or ""):gsub("([%(%)%.%%%+%-%*%?%[%]%^%$])", "%%%1")
  end
  local call_pat = "reaper%.SetMediaTrackInfo_Value%s*%(%s*"
    .. patt(f.ref)
    .. "%s*,%s*[\"']I_FOLDERDEPTH[\"']%s*,%s*-?%d+%s*%)"
  local replacement = "reaper.SetMediaTrackInfo_Value("
    .. tostring(f.expected_ref) .. ", \"I_FOLDERDEPTH\", -1)\n"
    .. "reaper.SetMediaTrackInfo_Value("
    .. tostring(f.ref) .. ", \"I_FOLDERDEPTH\", 0)"
  local repaired, n = lua_code:gsub(call_pat, function()
    return replacement
  end, 1)
  if n == 0 then return lua_code, false, findings end
  return repaired, true, findings
end

-- =============================================================================
-- Code.find_nil_prone_settrackselected_args
-- =============================================================================
-- SetTrackSelected requires a real boolean. Lower-tier models sometimes pass an
-- and/or expression that can evaluate to nil, which crashes at runtime.
function Code.find_nil_prone_settrackselected_args(lua_code)
  if not lua_code or lua_code == "" then return nil end
  local stripped = lua_code:gsub("%-%-[^\n]*", "")

  local function trim(v)
    return tostring(v or ""):match("^%s*(.-)%s*$") or ""
  end

  local function line_for_pos(pos)
    local line = 1
    for _ in stripped:sub(1, pos):gmatch("\n") do line = line + 1 end
    return line
  end

  local assignments = {}
  for line in stripped:gmatch("[^\r\n]+") do
    local var, expr = line:match("^%s*local%s+([%a_][%w_]*)%s*=%s*(.-)%s*$")
    if not var then
      var, expr = line:match("^%s*([%a_][%w_]*)%s*=%s*(.-)%s*$")
    end
    if var and expr and expr:sub(1, 1) ~= "=" then
      assignments[var] = trim(expr)
    end
  end

  local function parse_args(open_pos)
    local args, field = {}, {}
    local depth = 1
    local i = open_pos + 1
    local in_str = nil
    while i <= #stripped do
      local c = stripped:sub(i, i)
      if in_str then
        field[#field + 1] = c
        if c == "\\" then
          i = i + 1
          if i <= #stripped then field[#field + 1] = stripped:sub(i, i) end
        elseif c == in_str then
          in_str = nil
        end
      else
        if c == '"' or c == "'" then
          in_str = c
          field[#field + 1] = c
        elseif c == "(" or c == "[" or c == "{" then
          depth = depth + 1
          field[#field + 1] = c
        elseif c == ")" or c == "]" or c == "}" then
          depth = depth - 1
          if depth == 0 then
            args[#args + 1] = trim(table.concat(field))
            return args
          end
          field[#field + 1] = c
        elseif c == "," and depth == 1 then
          args[#args + 1] = trim(table.concat(field))
          field = {}
        else
          field[#field + 1] = c
        end
      end
      i = i + 1
    end
    return nil
  end

  local function may_return_nil_boolean(expr)
    expr = trim(expr)
    if expr == "" or expr == "true" or expr == "false" then return false end
    if expr:find("%f[%w_]and%s+true%s+or%s+false%f[^%w_]")
       or expr:find("%f[%w_]and%s+false%s+or%s+true%f[^%w_]")
       or expr:find("%f[%w_]or%s+false%s*$")
       or expr:find("%f[%w_]or%s+true%s*$") then
      return false
    end
    return expr:find("%f[%w_]and%f[^%w_]") ~= nil
  end

  local findings = {}
  local pos = 1
  while true do
    local s, open_pos = stripped:find("reaper%.SetTrackSelected%s*%(", pos)
    if not s then break end
    local args = parse_args(open_pos)
    local arg = args and args[2] or nil
    local expr = nil
    if arg and may_return_nil_boolean(arg) then
      expr = arg
    else
      local var = arg and arg:match("^([%a_][%w_]*)$") or nil
      if var and assignments[var] and may_return_nil_boolean(assignments[var]) then
        expr = assignments[var]
      end
    end
    if expr then
      findings[#findings + 1] = {
        line = line_for_pos(s),
        arg = arg,
        expr = expr,
      }
    end
    pos = open_pos + 1
  end

  if #findings == 0 then return nil end
  return findings
end

-- =============================================================================
-- Code.find_stock_fx_substitutions
-- =============================================================================
-- If the user explicitly names a stock Cockos plugin, do not let the generated
-- script silently substitute a third-party or JSFX alternative from the same
-- plugin family. This is intentionally narrow and only checks Track/Take
-- FX_AddByName string literals: explicit exact plugin requests are user intent,
-- not preference-hint suggestions.
function Code.find_stock_fx_substitutions(lua_code, user_prompt)
  if not lua_code or lua_code == "" then return nil end
  local prompt = tostring(user_prompt or ""):lower()
  if prompt == "" then return nil end

  local specs = {
    {
      requested = "ReaEQ",
      prompt_token = "reaeq",
      substitutes = {
        { pattern = "pro%-q", label = "FabFilter Pro-Q" },
        { pattern = "reeq",  label = "ReEQ" },
      },
    },
    {
      requested = "ReaComp",
      prompt_token = "reacomp",
      substitutes = {
        { pattern = "pro%-c", label = "FabFilter Pro-C" },
      },
    },
  }

  local requested = {}
  for _, spec in ipairs(specs) do
    if prompt:find(spec.prompt_token, 1, true) then
      requested[spec.requested] = true
    end
  end
  if next(requested) == nil then return nil end

  local stripped = lua_code:gsub("%-%-[^\n]*", "")

  local function line_for_pos(pos)
    local line = 1
    for _ in stripped:sub(1, pos):gmatch("\n") do line = line + 1 end
    return line
  end

  local function parse_args(open_pos)
    local args, field = {}, {}
    local depth = 1
    local i = open_pos + 1
    local in_str = nil
    while i <= #stripped do
      local c = stripped:sub(i, i)
      if in_str then
        field[#field + 1] = c
        if c == "\\" then
          i = i + 1
          if i <= #stripped then field[#field + 1] = stripped:sub(i, i) end
        elseif c == in_str then
          in_str = nil
        end
      else
        if c == '"' or c == "'" then
          in_str = c
          field[#field + 1] = c
        elseif c == "(" or c == "[" or c == "{" then
          depth = depth + 1
          field[#field + 1] = c
        elseif c == ")" or c == "]" or c == "}" then
          depth = depth - 1
          if depth == 0 then
            args[#args + 1] = table.concat(field):match("^%s*(.-)%s*$") or ""
            return args
          end
          field[#field + 1] = c
        elseif c == "," and depth == 1 then
          args[#args + 1] = table.concat(field):match("^%s*(.-)%s*$") or ""
          field = {}
        else
          field[#field + 1] = c
        end
      end
      i = i + 1
    end
    return nil
  end

  local function string_literal_value(v)
    v = tostring(v or ""):match("^%s*(.-)%s*$") or ""
    local q = v:sub(1, 1)
    if q ~= '"' and q ~= "'" then return nil end
    local out = {}
    local i = 2
    while i <= #v do
      local c = v:sub(i, i)
      if c == "\\" then
        i = i + 1
        if i <= #v then out[#out + 1] = v:sub(i, i) end
      elseif c == q then
        return table.concat(out)
      else
        out[#out + 1] = c
      end
      i = i + 1
    end
    return nil
  end

  local calls = {}
  for _, fn in ipairs({ "TrackFX_AddByName", "TakeFX_AddByName" }) do
    local pos = 1
    while true do
      local s, open_pos = stripped:find("reaper%." .. fn .. "%s*%(", pos)
      if not s then break end
      local args = parse_args(open_pos)
      local plugin = args and string_literal_value(args[2])
      if plugin and plugin ~= "" then
        calls[#calls + 1] = {
          fn = fn,
          plugin = plugin,
          plugin_lower = plugin:lower(),
          line = line_for_pos(s),
        }
      end
      pos = open_pos + 1
    end
  end
  if #calls == 0 then return nil end

  local function code_adds_requested(spec)
    local token = spec.requested:lower()
    for _, call in ipairs(calls) do
      if call.plugin_lower:find(token, 1, true) then return true end
    end
    return false
  end

  local violations, seen = {}, {}
  for _, spec in ipairs(specs) do
    if requested[spec.requested] and not code_adds_requested(spec) then
      for _, call in ipairs(calls) do
        for _, sub in ipairs(spec.substitutes) do
          if call.plugin_lower:find(sub.pattern)
             and not prompt:find(sub.pattern) then
            local key = spec.requested .. ":" .. call.plugin_lower .. ":"
              .. tostring(call.line)
            if not seen[key] then
              seen[key] = true
              violations[#violations + 1] = {
                requested = spec.requested,
                substitute = call.plugin,
                substitute_label = sub.label,
                fn = call.fn,
                line = call.line,
              }
            end
          end
        end
      end
    end
  end

  if #violations == 0 then return nil end
  table.sort(violations, function(a, b)
    if a.line ~= b.line then return a.line < b.line end
    if a.requested ~= b.requested then return a.requested < b.requested end
    return tostring(a.substitute) < tostring(b.substitute)
  end)
  return violations
end

-- =============================================================================
-- Code.find_preferred_fx_identifier_drift
-- =============================================================================
-- Preferred-plugin context gives the model exact AddByName identifiers such as
-- "VST3: Pro-G". After hidden repair retries, weaker models sometimes strip the
-- prefix/vendor and fall back to bare names like "Pro-G", which can fail on
-- installs where REAPER requires the exact identifier. Catch those before
-- auto-run and ask for a focused identifier-only repair.
function Code.find_preferred_fx_identifier_drift(lua_code)
  if not lua_code or lua_code == "" then return nil end
  if not FXCache or not FXCache.get_preferred_types then return nil end

  local prefs_map = FXCache.get_preferred_types() or {}
  local preferred = {}
  local function strip_prefix(s)
    return tostring(s or ""):gsub("^[A-Za-z][A-Za-z0-9]*:%s*", "")
  end
  local function strip_vendor(s)
    return tostring(s or ""):gsub("%s+%b()", "")
  end
  local function has_prefix(s)
    return tostring(s or ""):find("^[A-Za-z][A-Za-z0-9]*:%s*") ~= nil
  end
  for type_key, ident in pairs(prefs_map) do
    ident = tostring(ident or "")
    if ident ~= "" and has_prefix(ident) then
      local bare = strip_vendor(strip_prefix(ident)):lower()
      if bare ~= "" then
        preferred[#preferred + 1] = {
          type_key = tostring(type_key or ""),
          exact = ident,
          bare = bare,
        }
      end
    end
  end
  if #preferred == 0 then return nil end

  local stripped = lua_code:gsub("%-%-[^\n]*", "")
  local function line_for_pos(pos)
    local line = 1
    for _ in stripped:sub(1, pos):gmatch("\n") do line = line + 1 end
    return line
  end

  local function parse_args(open_pos)
    local args, field = {}, {}
    local depth = 1
    local i = open_pos + 1
    local in_str = nil
    while i <= #stripped do
      local c = stripped:sub(i, i)
      if in_str then
        field[#field + 1] = c
        if c == "\\" then
          i = i + 1
          if i <= #stripped then field[#field + 1] = stripped:sub(i, i) end
        elseif c == in_str then
          in_str = nil
        end
      else
        if c == '"' or c == "'" then
          in_str = c
          field[#field + 1] = c
        elseif c == "(" or c == "[" or c == "{" then
          depth = depth + 1
          field[#field + 1] = c
        elseif c == ")" or c == "]" or c == "}" then
          depth = depth - 1
          if depth == 0 then
            args[#args + 1] = table.concat(field):match("^%s*(.-)%s*$") or ""
            return args
          end
          field[#field + 1] = c
        elseif c == "," and depth == 1 then
          args[#args + 1] = table.concat(field):match("^%s*(.-)%s*$") or ""
          field = {}
        else
          field[#field + 1] = c
        end
      end
      i = i + 1
    end
    return nil
  end

  local function string_literal_value(v)
    v = tostring(v or ""):match("^%s*(.-)%s*$") or ""
    local q = v:sub(1, 1)
    if q ~= '"' and q ~= "'" then return nil end
    local out = {}
    local i = 2
    while i <= #v do
      local c = v:sub(i, i)
      if c == "\\" then
        i = i + 1
        if i <= #v then out[#out + 1] = v:sub(i, i) end
      elseif c == q then
        return table.concat(out)
      else
        out[#out + 1] = c
      end
      i = i + 1
    end
    return nil
  end

  local violations, seen = {}, {}
  for _, fn in ipairs({ "TrackFX_AddByName", "TakeFX_AddByName" }) do
    local pos = 1
    while true do
      local s, open_pos = stripped:find("reaper%." .. fn .. "%s*%(", pos)
      if not s then break end
      local args = parse_args(open_pos)
      local plugin = args and string_literal_value(args[2])
      if plugin and plugin ~= "" and not has_prefix(plugin) then
        local normalized = strip_vendor(plugin):lower()
        for _, pref in ipairs(preferred) do
          if normalized == pref.bare
             or normalized:find(pref.bare, 1, true)
             or pref.bare:find(normalized, 1, true) then
            local key = fn .. ":" .. normalized .. ":" .. pref.exact .. ":"
              .. tostring(line_for_pos(s))
            if not seen[key] then
              seen[key] = true
              violations[#violations + 1] = {
                fn = fn,
                plugin = plugin,
                exact = pref.exact,
                type_key = pref.type_key,
                line = line_for_pos(s),
              }
            end
          end
        end
      end
      pos = open_pos + 1
    end
  end
  if #violations == 0 then return nil end
  table.sort(violations, function(a, b)
    if a.line ~= b.line then return a.line < b.line end
    return tostring(a.plugin) < tostring(b.plugin)
  end)
  return violations
end

-- =============================================================================
-- Code.find_unchecked_addbyname_results
-- =============================================================================
-- Static check for unchecked TrackFX_AddByName / TakeFX_AddByName results.
-- A common silent-failure pattern from less-careful models:
--
--   local fx = reaper.TrackFX_AddByName(tr, "VST3i: Twin 3", false, -1)
--   -- ... never checks fx < 0; downstream code assumes fx is valid
--
-- or the silent-skip variant:
--
--   local fx_comp = reaper.TrackFX_AddByName(tr, ..., false, -1)
--   if fx_comp >= 0 then
--     ... configure ...
--   end                            -- no else, no error, no return
--
-- Both forms claim the script "ran OK" while in reality a required plugin
-- failed to load and the user gets no diagnostic. The script is dependent
-- on the AddByName succeeding; if it doesn't, that's a broken chain the
-- user should be told about.
--
-- Detection: for each `NAME = reaper.(Track|Take)FX_AddByName(...)`, check
-- that NAME appears in a failure-direction comparison somewhere in the
-- script. Acceptable patterns: `NAME < 0`, `NAME == -1`, `NAME <= -1`.
-- If only the success-direction (`NAME >= 0`, `NAME > -1`) appears, that's
-- the silent-skip pattern -- still flagged. Bare unassigned AddByName calls
-- are also flagged because the script cannot observe or report load failure.
-- GetByName is intentionally NOT covered: returning -1 from GetByName is a
-- legitimate "not present" signal in upsert patterns and forcing an
-- early-error would break them.
--
-- Returns a sorted list of `{name, line}` entries (line is approximate),
-- or nil if every AddByName result is properly checked.
function Code.find_unchecked_addbyname_results(lua_code)
  if not lua_code or lua_code == "" then return nil end
  local stripped = lua_code:gsub("%-%-[^\n]*", "")
  local violations, seen = {}, {}
  local function _line_for_pos(pos)
    local line = 1
    for _ in stripped:sub(1, pos):gmatch("\n") do line = line + 1 end
    return line
  end
  local function _assignment_name(call_start)
    local prefix = stripped:sub(math.max(1, call_start - 160), call_start - 1)
    return prefix:match("([%w_]+)%s*=%s*$")
  end
  local function _scan(fn)
    local pos = 1
    while true do
      local s, e = stripped:find("reaper%." .. fn .. "%s*%(", pos)
      if not s then break end
      local name = _assignment_name(s)
      local seen_key = name or ("@unassigned:" .. tostring(s))
      if not seen[seen_key] then
        seen[seen_key] = true
        if not name then
          violations[#violations+1] = {
            name = "(unassigned result)",
            line = _line_for_pos(s),
            unassigned = true,
          }
        else
          -- Append a sentinel newline so end-of-string patterns behave
          -- the same as mid-string ones (the trailing [^%w_%.] needs a
          -- non-identifier byte to consume).
          local hay = stripped .. "\n"
          local nid = "[^%w_]"
          local end_  = "[^%w_%.]"  -- excludes "." so "< 0.5" doesn't match "< 0"
          local checked =
               hay:find(nid .. name .. "%s*<%s*0"   .. end_)   -- NAME < 0
            or hay:find(nid .. name .. "%s*==%s*%-%s*1" .. end_)  -- NAME == -1
            or hay:find(nid .. name .. "%s*<=%s*%-%s*1" .. end_)  -- NAME <= -1
            or hay:find(nid .. name .. "%s*<%s*%-%s*1"  .. end_)  -- NAME < -1
          if not checked then
            violations[#violations+1] = { name = name, line = _line_for_pos(s) }
          end
        end
      end
      pos = e + 1
    end
  end
  _scan("TrackFX_AddByName")
  _scan("TakeFX_AddByName")
  if #violations == 0 then return nil end
  table.sort(violations, function(a, b)
    if a.line ~= b.line then return a.line < b.line end
    return a.name < b.name
  end)
  return violations
end

-- =============================================================================
-- Code.find_chain_upsert_violations
-- =============================================================================
-- Strict-pairing check for chain-build follow-up turns: every plugin name
-- referenced via TrackFX_GetByName MUST also appear in a TrackFX_AddByName
-- call (and vice-versa). Catches two opposite anti-patterns observed
-- across providers when fx_chains is pinned and the user said "build a
-- vocal chain" / "set up a chain":
--
--   GET-ONLY (ChatGPT pattern): GetByName for all required plugins,
--   then if any returns < 0, ShowMessageBox "missing one or more chain
--   plugins" and return. Misses the "add the missing ones" half of the
--   upsert -- the script bails when the chain is incomplete instead of
--   completing it.
--
--   ADD-ONLY (Claude pattern): AddByName for every plugin without
--   checking whether the plugin is already on the track. Silently
--   duplicates plugins that an earlier turn already placed.
--
-- The canonical pattern requires BOTH calls for the same plugin:
--   local fx = reaper.TrackFX_GetByName(tr, "Pro-Q 4", false)
--   if fx < 0 then
--     fx = reaper.TrackFX_AddByName(tr, "VST3: Pro-Q 4", false, -1)
--   end
--   if fx < 0 then -- report failure end
--
-- Caller is responsible for gating: only run when the prompt is a chain-
-- build (CHAIN_PHRASE_HINTS matched) AND fx_chains was preempted/pinned
-- this turn. In other contexts both patterns can be legitimate
-- (modifying an existing instance, adding a new plugin to a fresh track,
-- etc.) and this validator would false-positive.
--
-- Returns a list of `{kind, bare, id}` entries (kind is "get_only" or
-- "add_only", bare is the lowercased name without format prefix or
-- vendor suffix, id is the original string from the call) or nil if
-- every plugin name appears in both call types.
function Code.find_chain_upsert_violations(lua_code)
  if not lua_code or lua_code == "" then return nil end
  local stripped = lua_code:gsub("%-%-[^\n]*", "")
  local function _bare(id)
    if not id then return nil end
    local n = id:match("^[A-Za-z][A-Za-z0-9]*:%s*(.+)$") or id
    n = n:gsub("%s*%(.-%)%s*$", "")
    return n:lower()
  end
  -- Resolve simple `local NAME = "literal"` constants so AddByName /
  -- GetByName calls that pass a variable instead of a literal still
  -- match. Observed in a Gemini session that hoisted the identifier
  -- into local id_eq = "VST3: Pro-Q 4"; reaper.TrackFX_AddByName(tr,
  -- id_eq, ...) and slipped past the literal-only scan. Only resolves
  -- single-line `local X = "..."` -- not concatenations, function
  -- calls, table indexing, or reassignment.
  local string_consts = {}
  for ident, val in stripped:gmatch("local%s+([%w_]+)%s*=%s*\"([^\"]+)\"") do
    string_consts[ident] = val
  end
  for ident, val in stripped:gmatch("local%s+([%w_]+)%s*=%s*'([^']+)'") do
    string_consts[ident] = val
  end
  local function _resolve_arg(captured)
    -- captured may be a quoted string content (already resolved by the
    -- gmatch pattern that captured between quotes) or a bare identifier
    -- (when the pattern matched the variable form). Caller passes both
    -- shapes through this helper -- if it looks like an identifier and
    -- we have a constant for it, return the constant; otherwise return
    -- the captured value as-is.
    if not captured then return nil end
    if captured:match("^[%w_]+$") and string_consts[captured] then
      return string_consts[captured]
    end
    return captured
  end
  local get_names, add_names = {}, {}
  -- Match: TrackFX_GetByName(track_arg, "name"|'name'|IDENT, ...)
  for cap in stripped:gmatch("TrackFX_GetByName%s*%([^,]+,%s*\"([^\"]+)\"") do
    local b = _bare(cap); if b then get_names[b] = cap end
  end
  for cap in stripped:gmatch("TrackFX_GetByName%s*%([^,]+,%s*'([^']+)'") do
    local b = _bare(cap); if b then get_names[b] = cap end
  end
  for cap in stripped:gmatch("TrackFX_GetByName%s*%([^,]+,%s*([%w_]+)%s*,") do
    local resolved = _resolve_arg(cap)
    if resolved and resolved ~= cap then  -- only count if we resolved a const
      local b = _bare(resolved); if b then get_names[b] = resolved end
    end
  end
  for cap in stripped:gmatch("TrackFX_AddByName%s*%([^,]+,%s*\"([^\"]+)\"") do
    local b = _bare(cap); if b then add_names[b] = cap end
  end
  for cap in stripped:gmatch("TrackFX_AddByName%s*%([^,]+,%s*'([^']+)'") do
    local b = _bare(cap); if b then add_names[b] = cap end
  end
  for cap in stripped:gmatch("TrackFX_AddByName%s*%([^,]+,%s*([%w_]+)%s*,") do
    local resolved = _resolve_arg(cap)
    if resolved and resolved ~= cap then
      local b = _bare(resolved); if b then add_names[b] = resolved end
    end
  end
  local violations = {}
  for bare, id in pairs(get_names) do
    if not add_names[bare] then
      violations[#violations+1] = { kind = "get_only", bare = bare, id = id }
    end
  end
  for bare, id in pairs(add_names) do
    if not get_names[bare] then
      violations[#violations+1] = { kind = "add_only", bare = bare, id = id }
    end
  end
  if #violations == 0 then return nil end
  table.sort(violations, function(a, b)
    if a.bare ~= b.bare then return a.bare < b.bare end
    return a.kind < b.kind
  end)
  return violations
end

-- =============================================================================
-- Code.find_helper_integrity_violations
-- =============================================================================
-- Narrow check for known-corrupted bundled helper bodies. The plugin_helpers
-- bundle's source is the canonical form; helpers are meant to be pasted
-- verbatim. Models occasionally rewrite or simplify the body in ways that
-- break safety -- the observed case from a ChatGPT 5.4 Mini session was the
-- range-guard on set_param_display:
--
--   GOOD: vmin and vmax and vmin < vmax and (target < vmin or target > vmax)
--   BAD:  vmin and vmax and target < vmin or target > vmax
--
-- Lua's and/or precedence makes the bad form parse as
-- `(vmin and vmax and target < vmin) or (target > vmax)`, so the second
-- disjunct evaluates `target > vmax` even when vmax is nil, producing
-- "attempt to compare nil with number" inside reaper.defer (after Code.run
-- has already logged "Script completed OK").
--
-- Detection is whitespace-insensitive substring matching against the
-- canonical fragment(s). False-positive risk is low because the helper
-- bodies are not meant to be creatively rewritten -- a model that paraphrases
-- them is producing a different program from the bundle's tested source.
--
-- Returns a list of `{name, missing}` entries (missing is the canonical
-- fragment the helper body lacks), or nil if every defined helper looks
-- intact.
function Code.find_helper_integrity_violations(lua_code)
  if not lua_code or lua_code == "" then return nil end
  -- Inlined to avoid a file-scope local slot (we're at the 200-local
  -- limit). Trivial reconstruction cost; this validator runs at most
  -- once per turn.
  local required_fragments = {
    set_param_display = {
      -- The parenthesized range-guard. The unparenthesized form bites on
      -- nil vmax; the parenthesized form short-circuits cleanly.
      "vmin and vmax and vmin < vmax and (target < vmin or target > vmax)",
      -- Nil-safe parse helper. The bare `s:gsub(...)` form crashes when
      -- TrackFX_GetFormattedParamValue returns nil (some VST3 plugins
      -- return that during the binary-search probe phase). The `(s or "")`
      -- guard turns a nil into a no-op match.
      "(s or \"\"):gsub",
    },
  }
  local stripped = lua_code:gsub("%-%-[^\n]*", "")
  -- Strip ALL whitespace from haystack and required fragments before
  -- substring search. This makes the check insensitive to formatting
  -- choices (line breaks across the expression, no spaces around
  -- operators, etc.). False-positive collision risk is low because the
  -- fragments are long, syntactically specific strings that don't appear
  -- elsewhere in plausible REAPER scripts.
  local function _normws(s) return (s:gsub("%s+", "")) end
  local hay = _normws(stripped)
  local violations = {}
  for name, fragments in pairs(required_fragments) do
    -- Only check helpers that are BOTH defined AND called. A pasted-
    -- but-uncalled helper is dead code -- its corruption never executes,
    -- so forcing a retry is wasted cost. Mirrors the dead-code exemption
    -- the defer-validator already has. Call-site detection: NAME(
    -- preceded by a non-identifier, non-`.` byte (so `obj.NAME(` doesn't
    -- count and we don't false-positive on field access).
    local defined =
         stripped:find("local%s+function%s+" .. name .. "%s*%(", 1)
      or stripped:find("[^%w_]function%s+" .. name .. "%s*%(", 1)
      or stripped:find("^function%s+" .. name .. "%s*%(", 1)
    if defined then
      -- Scan for a call site OUTSIDE the def header. The call pattern
      -- `[^%w_%.]NAME%s*%(` would match the space before NAME in
      -- `function NAME(`; that match's start position is between the
      -- definition keyword and NAME, so we accept any call-pattern hit
      -- whose start is AFTER the matched def's end position.
      local def_end = stripped:find(name .. "%s*%(", defined)
      def_end = def_end and (def_end + #name) or defined
      local call_pat = "[^%w_%.]" .. name .. "%s*%("
      local called = false
      local p = 1
      while true do
        local cs = stripped:find(call_pat, p)
        if not cs then break end
        if cs > def_end then called = true; break end
        p = cs + 1
      end
      if called then
        for _, frag in ipairs(fragments) do
          if not hay:find(_normws(frag), 1, true) then
            violations[#violations+1] = { name = name, missing = frag }
            break  -- one violation per helper is enough to trigger retry
          end
        end
      end
    end
  end
  if #violations == 0 then return nil end
  table.sort(violations, function(a, b) return a.name < b.name end)
  return violations
end

-- For a hallucinated reaper.X name, return up to N real function names that
-- look similar (share a substring of >=4 chars, case-insensitive). Sorted
-- so the suggestions are stable across calls. Used by the API-validator
-- retry hint to give the model concrete candidates instead of just "you
-- got it wrong, try again."
function Code.suggest_reaper_alternatives(bad_name, max_results)
  max_results = max_results or 8
  local bad_lo = bad_name:lower()
  local needle = bad_lo:sub(1, math.min(8, #bad_lo))
  local valid = _valid_reaper_fns()
  local matches = {}
  for real in pairs(valid) do
    local real_lo = real:lower()
    -- Two-way prefix match: bad starts with real's prefix, or real starts
    -- with bad's prefix. Catches "GetProjectMarkerByIndex" -> "GetProjectMarker"
    -- (real shorter) and "GetTrack" -> "GetTrackInfo_Value" (real longer).
    if real_lo:find(needle, 1, true)
       or bad_lo:find(real_lo:sub(1, math.min(8, #real_lo)), 1, true) then
      matches[#matches+1] = real
    end
  end
  table.sort(matches)
  while #matches > max_results do matches[#matches] = nil end
  return matches
end

-- =============================================================================
-- Code.find_param_calls_outside_defer
-- =============================================================================
-- Behavioral validator for the MANDATORY DEFER RULE in
-- prompt_bundle:plugin. Generated scripts that call TrackFX/TakeFX
-- param Get/Set helpers OUTSIDE a `reaper.defer(function() ... end)`
-- block can silently fail on some VST3 plugins -- the script appears
-- to succeed (even logs "Script completed OK") but the parameters
-- never actually change. The existing API validator only checks that
-- function NAMES exist, not WHERE they're called, so this check fills
-- the gap.
--
-- Returns a sorted, deduplicated list of violating function names, or
-- nil if every param call is inside a defer scope (or the script has
-- no param calls at all).
--
-- Algorithm:
--   1. Replace line comments with same-length spaces so byte offsets
--      stay aligned with the original source while comments don't
--      pollute pattern matches. Block comments / strings containing
--      reaper.* calls are rare in generated code; accepted as a
--      pragmatic limitation rather than building a full Lua tokenizer.
--   2. Walk the cleaned text. For each `reaper.defer(function()`
--      opening, find the matching `end)` by tracking Lua block depth
--      (function/if/repeat increment; for/while + do also increment;
--      end and until decrement). Record each defer body as a [start,
--      end] byte range.
--   3. Scan for every `reaper.<NAME>` call. If NAME is in the
--      param-touching set AND the byte position is not inside any
--      recorded defer range, flag it.
--
-- False-positive risk: low. The model would have to either pass a
-- named function to defer (e.g. `reaper.defer(my_callback)`) or wrap
-- params in a helper called from outside defer. Both are anti-patterns
-- per the plugin bundle and worth flagging anyway.
local _DEFER_OPEN_PAT = "reaper%.defer%s*%(%s*function%s*%(%s*%)"
local _PARAM_CALL_NAMES = {
  TrackFX_GetParam              = true,
  TrackFX_GetParamNormalized    = true,
  TrackFX_SetParam              = true,
  TrackFX_SetParamNormalized    = true,
  TrackFX_GetParamName          = true,
  TrackFX_GetNumParams          = true,
  TrackFX_GetFormattedParamValue= true,
  TakeFX_GetParam               = true,
  TakeFX_GetParamNormalized     = true,
  TakeFX_SetParam               = true,
  TakeFX_SetParamNormalized     = true,
  TakeFX_GetParamName           = true,
  TakeFX_GetNumParams           = true,
  TakeFX_GetFormattedParamValue = true,
}

local function _strip_line_comments_preserving_offsets(code)
  -- Replace each line-comment span with same-length spaces so positions
  -- discovered in the cleaned text map 1:1 to the original source.
  return (code:gsub("%-%-[^\n]*", function(s) return string.rep(" ", #s) end))
end

-- Walk forward from `start_i` tracking Lua block depth (function/if/for/
-- while/repeat/do as opens, end/until as closes). Returns the byte index
-- one past the matching close, or nil if no matching close was found.
-- Shared by both the defer-region scan and the local-function-body scan.
local function _walk_to_matching_end(stripped, start_i, initial_depth)
  local depth = initial_depth
  local saw_loop_header = false
  local i = start_i
  while i <= #stripped and depth > 0 do
    local prev = i > 1 and stripped:sub(i-1, i-1) or ""
    local is_word_start = not prev:match("[%w_]")
    if is_word_start then
      local word = stripped:sub(i):match("^([%w_]+)")
      if word == "function" or word == "if" or word == "repeat" then
        depth = depth + 1
        saw_loop_header = false
        i = i + #word
      elseif word == "for" or word == "while" then
        saw_loop_header = true
        i = i + #word
      elseif word == "do" then
        depth = depth + 1
        saw_loop_header = false
        i = i + #word
      elseif word == "end" or word == "until" then
        depth = depth - 1
        saw_loop_header = false
        i = i + #word
      elseif word then
        i = i + #word
      else
        i = i + 1
      end
    else
      i = i + 1
    end
  end
  if depth == 0 then return i end
  return nil
end

local function _find_defer_regions(stripped)
  local regions = {}
  local pos = 1
  while true do
    local s, e = stripped:find(_DEFER_OPEN_PAT, pos)
    if not s then break end
    local body_start = e + 1
    local body_end_plus1 = _walk_to_matching_end(stripped, body_start, 1)
    if body_end_plus1 then
      regions[#regions+1] = { body_start, body_end_plus1 - 1 }
      pos = body_end_plus1
    else
      pos = e + 1
    end
  end
  return regions
end

-- Returns list of { name, body_start, body_end } for each `local function
-- NAME(...) ... end` definition in the script. Used by the defer validator
-- to recognize that helper-function bodies whose NAME is called inside a
-- defer block are transitively "deferred" -- the helper's reaper.* calls
-- only execute when the helper is invoked, and that invocation happens
-- inside defer.
local function _find_local_function_regions(stripped)
  local fns = {}
  local pos = 1
  while true do
    local s, e, name = stripped:find("local%s+function%s+([%w_]+)%s*%(", pos)
    if not s then break end
    -- Skip past the parameter list to find the body start.
    local i = e
    while i <= #stripped and stripped:sub(i, i) ~= ")" do i = i + 1 end
    if i > #stripped then break end
    i = i + 1  -- past `)`
    local body_start = i
    local body_end_plus1 = _walk_to_matching_end(stripped, body_start, 1)
    if body_end_plus1 then
      fns[#fns+1] = { name = name, def_start = s, body_start = body_start, body_end = body_end_plus1 - 1 }
      -- Advance INTO the body, not past its end. The model commonly wraps
      -- the whole script in `local function main() ... end main()` and
      -- defines helpers (set_param_display, find_param, etc.) as nested
      -- local functions inside main. Skipping past main's end would
      -- therefore miss every helper, leaving the defer validator unable
      -- to recognize their bodies as transitively in-defer when called
      -- from within reaper.defer().
      pos = body_start
    else
      pos = e + 1
    end
  end
  return fns
end

function Code.find_param_calls_outside_defer(lua_code)
  if not lua_code or lua_code == "" then return nil end
  local stripped = _strip_line_comments_preserving_offsets(lua_code)
  local regions  = _find_defer_regions(stripped)

  -- Expand regions to include local-function bodies whose name is called
  -- inside any current "in-defer" region. The conventional script shape
  -- defines helpers (set_param_display, find_param, custom nil-safe
  -- wrappers like setp) at the script top OR inside main()'s body BEFORE
  -- the reaper.defer block, then CALLS them from inside defer. The
  -- reaper.* calls inside the helper's source body don't execute when
  -- the helper is defined; they only execute when the helper is invoked
  -- (which is inside defer). Without this expansion, the validator
  -- false-positive-flags every helper-internal SetParamNormalized call
  -- and blocks auto-run on perfectly-correct scripts. Iterative pass
  -- handles transitivity (helper A calls helper B, A is called from
  -- defer -> B is also "in defer").
  local fns = _find_local_function_regions(stripped)
  local function _local_call_positions(fn_name)
    local positions = {}
    local ps = 1
    while true do
      local cs, ce = stripped:find(fn_name .. "%s*%(", ps)
      if not cs then break end
      local prev = cs > 1 and stripped:sub(cs - 1, cs - 1) or ""
      if not prev:match("[%w_%.:]") then
        positions[#positions + 1] = cs
      end
      ps = ce + 1
    end
    return positions
  end

  local function _local_token_positions(fn_name)
    local positions = {}
    local ps = 1
    while true do
      local cs, ce = stripped:find(fn_name, ps, true)
      if not cs then break end
      local prev = cs > 1 and stripped:sub(cs - 1, cs - 1) or ""
      local next_ch = ce < #stripped and stripped:sub(ce + 1, ce + 1) or ""
      if not prev:match("[%w_%.:]") and not next_ch:match("[%w_]") then
        positions[#positions + 1] = cs
      end
      ps = ce + 1
    end
    return positions
  end

  local function _name_called_in_regions(fn_name, regs)
    for _, cs in ipairs(_local_call_positions(fn_name)) do
      for _, r in ipairs(regs) do
        if cs >= r[1] and cs <= r[2] then return true end
      end
    end
    return false
  end
  local known_in_defer = {}
  local added = true
  while added do
    added = false
    for _, fn in ipairs(fns) do
      if not known_in_defer[fn]
         and _name_called_in_regions(fn.name, regions) then
        regions[#regions+1] = { fn.body_start, fn.body_end }
        known_in_defer[fn] = true
        added = true
      end
    end
  end

  -- Dead-code exemption: a local function whose name has no call sites
  -- OUTSIDE its own def header + body is unreachable -- its reaper.* calls
  -- never execute, so don't flag them. This catches the common case of
  -- the model pasting a helper (e.g. set_param_display) "just in case"
  -- without actually invoking it. Limited to one-level reachability:
  -- helpers called only by other dead helpers are still flagged. Acceptable
  -- because that pattern is rare and erring on the side of flagging keeps
  -- the validator's primary purpose intact (catch real defer violations
  -- like `local function apply() ... end; apply()` outside defer).
  for _, fn in ipairs(fns) do
    if not known_in_defer[fn] then
      local has_external = false
      for _, cs in ipairs(_local_call_positions(fn.name)) do
        if cs < fn.def_start or cs > fn.body_end then
          has_external = true
          break
        end
      end
      if not has_external then
        -- `pcall(main)`, `xpcall(main, ...)`, or assigning/passing a local
        -- function as a callback still makes that function reachable even
        -- though it is not written as `main(...)`. Treat any out-of-body
        -- token reference as reachable so wrapper mains don't mask nested
        -- helper-param calls from the defer validator.
        for _, cs in ipairs(_local_token_positions(fn.name)) do
          if cs < fn.def_start or cs > fn.body_end then
            has_external = true
            break
          end
        end
      end
      if not has_external then
        regions[#regions+1] = { fn.body_start, fn.body_end }
      end
    end
  end

  local violations = {}
  local seen = {}
  local s = 1
  while true do
    local hs, he, name = stripped:find("reaper%.([%w_]+)", s)
    if not hs then break end
    if _PARAM_CALL_NAMES[name] then
      local in_defer = false
      for _, r in ipairs(regions) do
        if hs >= r[1] and hs <= r[2] then in_defer = true; break end
      end
      if not in_defer and not seen[name] then
        seen[name] = true
        violations[#violations+1] = name
      end
    end
    s = he + 1
  end
  if #violations == 0 then return nil end
  table.sort(violations)
  return violations
end

-- =============================================================================
-- Code.find_helper_calls_without_definition
-- =============================================================================
-- Behavioral validator for the prompt_bundle:plugin_helpers contract.
-- Helpers (find_param, set_param_display, set_param_enum, set_param_enum_paced)
-- are LOCAL FUNCTIONS, not REAPER built-ins. The model has seen them in
-- training data and CAN write the calls from memory without including the
-- function source -- which produces a runtime `attempt to call a nil value`
-- crash on the deferred tick. The plugin_helpers bundle exists so the model
-- has the source available; this validator catches the case where the call
-- is emitted without the source.
--
-- Returns a sorted, deduplicated list of helper names that are CALLED but
-- not DEFINED in the same script, or nil if every called helper has a
-- matching `local function NAME(` definition.
local _HELPER_NAMES = {
  find_param           = true,
  set_param_display    = true,
  set_param_enum       = true,
  set_param_enum_paced = true,
}

function Code.find_helper_calls_without_definition(lua_code)
  if not lua_code or lua_code == "" then return nil end
  -- Strip line comments preserving offsets so positions remain consistent
  -- with the rest of the validator pass (block comments rare in generated
  -- code; accept the false-positive risk).
  local stripped = (lua_code:gsub("%-%-[^\n]*",
    function(s) return string.rep(" ", #s) end))
  -- For each helper name, find the earliest definition position and the
  -- earliest call position. Two failure modes both produce the same
  -- runtime crash ("attempt to call a nil value"); both treated as
  -- violations so the retry hint covers them uniformly:
  --
  --   1. NO definition anywhere -- model called the helper without
  --      including its source.
  --   2. Definition exists but is LEXICALLY AFTER the first call site.
  --      Common when the model writes main() first and helper functions
  --      below: when Lua compiles main()'s body, the helper's `local`
  --      slot doesn't exist yet at that source position, so the call
  --      compiles as a global (_ENV) lookup and crashes at runtime
  --      inside the deferred callback. Confirmed reproducible against
  --      Lua 5.4 with the exact pattern observed in a debug log.
  --
  -- Definition forms accepted:
  --   `local function NAME(`        -- standard form the bundle uses
  --   `function NAME(`              -- bare (no local; less safe but valid)
  --   `local NAME = function`       -- assignment form
  --   `NAME = function` (mid-line)  -- bare assignment (creates global)
  --
  -- The definition-before-call check uses START position of the def
  -- match. For a `local function NAME(` site, that's the 'l' of "local",
  -- which is always BEFORE the call-pattern's match (the space inside
  -- "function NAME(" that satisfies [^%w_%.]). So def-site false-call-
  -- matches don't trigger out-of-order -- they compare def_pos < their
  -- own call_pos.
  local violations, seen = {}, {}
  for name in pairs(_HELPER_NAMES) do
    local def_pos = nil
    local function _take_min(pat)
      local sp = stripped:find(pat)
      if sp and (not def_pos or sp < def_pos) then def_pos = sp end
    end
    _take_min("local%s+function%s+" .. name .. "%s*%(")
    _take_min("[^%w_]function%s+" .. name .. "%s*%(")
    _take_min("^function%s+" .. name .. "%s*%(")
    _take_min("local%s+" .. name .. "%s*=%s*function")
    _take_min("[^%w_]" .. name .. "%s*=%s*function")
    -- Earliest call site (NAME followed by `(`, not preceded by an
    -- identifier or a `.` which would make it a method/field access).
    -- Deliberately scan for "called but not defined" only -- a defined-
    -- but-uncalled helper is fine (the bundle's "only include helpers
    -- you call" guidance is about size, not correctness).
    local call_pos = stripped:find("[^%w_%.]" .. name .. "%s*%(")
    if not call_pos and stripped:find("^" .. name .. "%s*%(") then
      call_pos = 1
    end
    if call_pos and not seen[name] then
      if not def_pos or def_pos > call_pos then
        seen[name] = true
        violations[#violations+1] = name
      end
    end
  end
  if #violations == 0 then return nil end
  table.sort(violations)
  return violations
end

-- =============================================================================
-- Code.prompt_has_param_write_intent
-- =============================================================================
-- Returns true if the user's prompt looks like a request to WRITE plugin
-- parameter values (vs. a pure-read query like "what is X set to?").
-- Used by the dispatcher to gate the plugin_helpers co-pin on fx_params
-- and preferred_plugins paths -- pure reads don't need helpers; writes do.
--
-- Two-signal detection: a write verb AND a value-shape pattern. Either
-- signal alone is too weak (a mention of "set" without a value, or a
-- value pattern without a write verb, are both weak signals). Conjunction
-- catches the high-signal cases without spamming co-pin on weak prompts.
local _WRITE_VERBS = {
  "set", "change", "configure", "adjust", "make", "turn",
  "boost", "cut", "raise", "lower", "lift", "drop", "tune",
  "tweak", "dial", "increase", "decrease", "shift", "move",
  "bump", "nudge", "trim",
}
-- Value-shape patterns: number followed by a unit, or a colon-separated
-- ratio. Lua patterns; %d is digit, %s is whitespace.
local _VALUE_PATTERNS = {
  "%d+%s*[dD][bB]",         -- 6 dB, 6dB, 6 DB
  "%d+%s*[hH][zZ]",         -- 100 Hz, 100hz
  "%d+%s*[kK][hH][zZ]",     -- 5 kHz
  "%d+%s*ms",               -- 50 ms
  "%d+%s*sec",              -- 2 sec
  "%d+%s*%%",               -- 65%
  "%d+%s*[cC][eE][nN][tT]", -- 50 cents, 50 cent
  "%d+%s*[sS][eE][mM][iI]", -- 12 semitones
  "%d+:%d+",                -- 4:1, 10:1
  "%d+%.%d+",               -- 0.75, 1.5 (bare decimal -- looks intentional)
  "[Qq]%s*=%s*%d",          -- Q=2, Q = 1.5
  "[Qq]%s+of%s+%d",         -- Q of 2
}

function Code.prompt_has_param_write_intent(text)
  if type(text) ~= "string" or text == "" then return false end
  local lo = text:lower()
  -- Verb scan with word-boundary frontier so "settle" doesn't match "set".
  local has_verb = false
  for _, v in ipairs(_WRITE_VERBS) do
    if lo:find("%f[%w]" .. v .. "%f[%W]") then has_verb = true; break end
  end
  if not has_verb then return false end
  -- Value-shape scan.
  for _, pat in ipairs(_VALUE_PATTERNS) do
    if lo:find(pat) then return true end
  end
  return false
end

function Code.prompt_has_chain_or_recipe_intent(text)
  if type(text) ~= "string" or text == "" then return false end
  local lo = text:lower()
  return lo:find("%f[%w]chain%f[%W]") ~= nil
    or lo:find("%f[%w]recipe%f[%W]") ~= nil
    or lo:find("%f[%w]preset%f[%W]") ~= nil
    or lo:find("%f[%w]tone%f[%W]") ~= nil
    or lo:find("%f[%w]sound%s+like%f[%W]") ~= nil
    or lo:find("%f[%w]vibe%f[%W]") ~= nil
end

function Code.prompt_is_fx_add_only(text)
  if type(text) ~= "string" or text == "" then return false end
  if Code.prompt_has_param_write_intent(text)
     or Code.prompt_has_chain_or_recipe_intent(text) then
    return false
  end
  local lo = text:lower()
  local add_verb =
    lo:find("%f[%w]add%f[%W]") ~= nil
    or lo:find("%f[%w]insert%f[%W]") ~= nil
    or lo:find("%f[%w]load%f[%W]") ~= nil
    or lo:find("%f[%w]put%f[%W]") ~= nil
  if not add_verb then return false end
  return lo:find("%f[%w]fx%f[%W]") ~= nil
    or lo:find("%f[%w]plugin%f[%W]") ~= nil
    or lo:find("%f[%w]effect%f[%W]") ~= nil
    or lo:find("reaeq", 1, true) ~= nil
    or lo:find("reacomp", 1, true) ~= nil
    or lo:find("readelay", 1, true) ~= nil
    or lo:find("reaverbate", 1, true) ~= nil
    or lo:find("reagate", 1, true) ~= nil
    or lo:find("realimit", 1, true) ~= nil
    or lo:find("%f[%w]compressor%f[%W]") ~= nil
    or lo:find("%f[%w]eq%f[%W]") ~= nil
    or lo:find("%f[%w]delay%f[%W]") ~= nil
    or lo:find("%f[%w]reverb%f[%W]") ~= nil
    or lo:find("%f[%w]gate%f[%W]") ~= nil
    or lo:find("%f[%w]limiter%f[%W]") ~= nil
end

function Code.lua_has_fx_param_writes(lua_code)
  if type(lua_code) ~= "string" or lua_code == "" then return false end
  local stripped = lua_code
    :gsub("%-%-%[%[.-%]%]", "")
    :gsub("%-%-[^\n]*", "")
  return stripped:find("reaper%.TrackFX_SetParam%s*%(") ~= nil
    or stripped:find("reaper%.TrackFX_SetParamNormalized%s*%(") ~= nil
    or stripped:find("reaper%.TakeFX_SetParam%s*%(") ~= nil
    or stripped:find("reaper%.TakeFX_SetParamNormalized%s*%(") ~= nil
    or stripped:find("%f[%w]set_param_display%s*%(") ~= nil
    or stripped:find("%f[%w]set_param_enum%s*%(") ~= nil
    or stripped:find("%f[%w]set_param_enum_paced%s*%(") ~= nil
end

function Code.prompt_requests_full_param_readout(text)
  if type(text) ~= "string" or text == "" then return false end
  local lo = text:lower()
  return lo:find("%f[%w]all%f[%W]") ~= nil
    or lo:find("%f[%w]full%f[%W]") ~= nil
    or lo:find("%f[%w]every%f[%W]") ~= nil
    or lo:find("%f[%w]complete%f[%W]") ~= nil
    or lo:find("%f[%w]raw%f[%W]") ~= nil
  end

function Code.filter_broad_fx_param_readout(user_text, response_text)
  if type(response_text) ~= "string" or response_text == "" then
    return response_text, 0
  end
  if response_text:find("```", 1, true) then return response_text, 0 end
  if not (CTX and CTX.prompt_has_fx_param_read_intent
      and CTX.prompt_has_fx_param_read_intent(user_text)) then
    return response_text, 0
  end
  if Code.prompt_requests_full_param_readout(user_text) then
    return response_text, 0
  end

  local prompt = tostring(user_text or ""):lower()
  local function clean_name(name)
    return tostring(name or "")
      :gsub("[`*_]", "")
      :gsub("^%s*(.-)%s*$", "%1")
      :lower()
  end
  local function clean_display(display)
    return tostring(display or "")
      :gsub("[`*_]", "")
      :gsub("^%s*(.-)%s*$", "%1")
      :lower()
  end
  local function prompt_mentions_name(name)
    local n = clean_name(name):gsub("[^%w]+", " "):gsub("^%s*(.-)%s*$", "%1")
    if n == "" then return false end
    return prompt:find(n, 1, true) ~= nil
  end
  local function defaultish_display(name, display)
    local n, d = clean_name(name), clean_display(display)
    if d == "" then return true end
    if n:find("pan", 1, true) then
      return d == "0" or d == "0.0" or d == "0.00" or d == "0.000"
        or d == "center" or d == "centre" or d == "c"
    end
    if n:find("level", 1, true) or n:find("trim", 1, true) then
      return d == "0 db" or d == "0.0 db" or d == "0.00 db"
        or d == "+0 db" or d == "+0.0 db" or d == "+0.00 db"
        or d == "-inf db" or d == "-inf" or d == "-infinity db"
    end
    if n:find("mix", 1, true) then
      return d == "0" or d == "0.0" or d == "0.00" or d == "0.000"
    end
    if n:find("bypass", 1, true) then
      return d:find("not bypass", 1, true) ~= nil
        or d == "off" or d == "disabled"
    end
    if n == "midi state" then return d == "enabled" end
    if n == "oversampling" or n == "expert mode"
       or n == "audition side chain" then
      return d == "off" or d == "disabled"
    end
    if n == "channel mode" then
      return d == "left/right" or d == "stereo"
    end
    if n == "side chain input signal" then
      return d == "normal input" or d == "normal"
    end
    if n == "interface" or n == "ex style" then return true end
    return false
  end
  local function should_drop(name, display)
    if prompt_mentions_name(name) then return false end
    local n = clean_name(name)
    local secondary =
         n:find("side chain level", 1, true)
      or n:find("side chain mix", 1, true)
      or n == "side chain input signal"
      or n == "wet level" or n == "wet pan"
      or n == "dry level" or n == "dry pan"
      or n == "input level" or n == "input pan"
      or n == "output level" or n == "output pan"
      or n == "midi state"
      or n == "oversampling"
      or n == "expert mode"
      or n == "audition side chain"
      or n == "channel mode"
      or n == "interface"
      or n == "ex style"
      or n:find("bypass", 1, true)
    return secondary and defaultish_display(n, display)
  end

  local out, removed = {}, 0
  for line in (response_text .. "\n"):gmatch("(.-)\n") do
    local name, display = line:match("^%s*[-*]%s+([^:]+):%s*(.-)%s*$")
    if name and should_drop(name, display) then
      removed = removed + 1
    else
      out[#out+1] = line
    end
  end
  if removed == 0 then return response_text, 0 end
  return tbl_concat(out, "\n"):gsub("%s+$", ""), removed
end

-- =============================================================================
-- Code.scan_risky(code) -> warning_string or nil
-- Scans a Lua code string for calls that could have side effects beyond the
-- REAPER project (file deletion, arbitrary shell commands, loading external
-- code, etc.). Returns a human-readable warning string listing what was found,
-- or nil if no risky patterns were detected.
--
-- This scanner GATES code execution: when it returns a non-nil warning, the
-- UI blocks the Run button behind a confirmation modal ("Review Before
-- Running") that the user must explicitly accept. Auto-run is also blocked.
-- This is a hard gate, not an advisory label.
--
-- Patterns are intentionally broad (matching "os.remove" anywhere in the
-- string, including inside comments or strings) to minimize false negatives.
-- A few false positives are acceptable for a safety feature.
-- RISKY_PATTERNS is hoisted out of Code.scan_risky into this do-block so it
-- isn't reallocated on every call. scan_risky runs from the render hot path
-- (once per visible Lua code block per frame), so the table allocation +
-- field assignments were measurable on long conversations.
--
-- Each entry is a list of patterns that all flag the same risk label.
-- Patterns cover both dot-notation (os.remove) and string-indexed access
-- (os["remove"], os['remove'], _G.os.remove) so the model cannot bypass the
-- warning by simply switching syntax. Catches the obvious bypass attempts;
-- determined obfuscation (loadstring with hex-encoded strings, etc.) is
-- still possible but at that point the model is actively trying to evade
-- the user's safety check, which is well outside our threat model -- the
-- user is opting in to running generated code in the first place.
do
  local RISKY_PATTERNS = {
    { label = "os.remove (deletes files)", patterns = {
      "os%.remove",
      'os%s*%[%s*["\']remove["\']%s*%]',
      "_G%.os%.remove",
      '_G%s*%[%s*["\']os["\']%s*%]',
    }},
    { label = "os.rename (moves/renames files)", patterns = {
      "os%.rename",
      'os%s*%[%s*["\']rename["\']%s*%]',
    }},
    { label = "os.execute (runs shell commands)", patterns = {
      "os%.execute",
      'os%s*%[%s*["\']execute["\']%s*%]',
      "_G%.os%.execute",
    }},
    { label = "io.popen (runs shell commands)", patterns = {
      "io%.popen",
      'io%s*%[%s*["\']popen["\']%s*%]',
    }},
    { label = "io.open in write/append mode", patterns = {
      -- Anchor the mode arg to the second positional ([^,]+ prevents the
      -- lazy match from walking across the path arg into a later string
      -- like print("welcome") that happens to start with "w" or "a"). The
      -- old lazy pattern flagged read-mode opens whenever any later quoted
      -- string in the snippet started with w or a (false-positive risky
      -- popup on perfectly safe read scripts).
      'io%.open%s*%([^,]+,%s*["\']w',
      'io%.open%s*%([^,]+,%s*["\']a',
      'io%s*%[%s*["\']open["\']%s*%]',
    }},
    { label = "shell/process launch via REAPER or SWS", patterns = {
      -- REAPER's built-in process launcher and the SWS / js_ReaScriptAPI
      -- shell helpers. Generated code can shell out via these APIs without
      -- touching os.execute or io.popen, so they need explicit coverage in
      -- the scanner -- otherwise a malicious or careless plugin call could
      -- run arbitrary commands while the auto-run gate stays silent.
      "reaper%.ExecProcess",
      "reaper%.CF_ShellExecute",
      "reaper%.BR_Win32_ShellExecute",
      'reaper%s*%[%s*["\']ExecProcess["\']%s*%]',
      'reaper%s*%[%s*["\']CF_ShellExecute["\']%s*%]',
      'reaper%s*%[%s*["\']BR_Win32_ShellExecute["\']%s*%]',
    }},
    { label = "require (loads external modules)", patterns = {
      "require%s*%(",
      "require%s*['\"]",
    }},
    { label = "dofile (executes external files)", patterns = {
      "dofile%s*%(",
      "dofile%s*['\"]",
    }},
    { label = "loadfile (loads external files)", patterns = {
      "loadfile%s*%(",
      "loadfile%s*['\"]",
    }},
    { label = "loadstring/load (executes runtime strings)", patterns = {
      "loadstring%s*%(",
      "[^%w_]load%s*%(",  -- bare load() but not e.g. fileloader(
    }},
    { label = "debug library access", patterns = {
      "debug%.",
      'debug%s*%[%s*["\']',
    }},
  }
  function Code.scan_risky(code)
    local found = {}
    for _, entry in ipairs(RISKY_PATTERNS) do
      for _, pat in ipairs(entry.patterns) do
        if code:find(pat) then
          found[#found+1] = entry.label
          break  -- one match per label is enough
        end
      end
    end
    if #found == 0 then return nil end
    return "Warning: " .. tbl_concat(found, ", ")
  end
end

function Code._lua_artifact_trim(s)
  s = tostring(s or "")
  return (s:gsub("^%s+", ""):gsub("%s+$", ""))
end

function Code._lua_artifact_line_count(s)
  s = tostring(s or "")
  if s == "" then return 0 end
  local n = 1
  for _ in s:gmatch("\n") do n = n + 1 end
  return n
end

function Code._lua_artifact_strip_comments(s)
  return tostring(s or "")
    :gsub("%-%-%[%[.-%]%]", "")
    :gsub("%-%-[^\n]*", "")
end

function Code._lua_artifact_context_says_fragment(text)
  local lt = tostring(text or ""):lower()
  if lt == "" then return false end
  if lt:find("complete script", 1, true)
     or lt:find("full script", 1, true)
     or lt:find("entire script", 1, true)
     or lt:find("runnable script", 1, true) then
    return false
  end
  return lt:find("snippet", 1, true) ~= nil
    or lt:find("fragment", 1, true) ~= nil
    or lt:find("patch", 1, true) ~= nil
    or lt:find("diff", 1, true) ~= nil
    or lt:find("replace this", 1, true) ~= nil
    or lt:find("replace the line", 1, true) ~= nil
    or lt:find("change this line", 1, true) ~= nil
    or lt:find("one-line", 1, true) ~= nil
    or lt:find("one line", 1, true) ~= nil
    or lt:find("single line", 1, true) ~= nil
    or lt:find("only showed", 1, true) ~= nil
    or lt:find("just reduce", 1, true) ~= nil
end

function Code.classify_lua_artifact(code, opts)
  opts = opts or {}
  local raw = tostring(code or "")
  local trimmed = Code._lua_artifact_trim(raw)
  local info = {
    kind = "complete_script",
    parse_ok = true,
    runnable = true,
    reason = nil,
    line_count = Code._lua_artifact_line_count(trimmed),
    byte_count = #raw,
  }
  if trimmed == "" then
    info.kind = "empty"
    info.runnable = false
    info.reason = "empty Lua block"
    return info
  end

  local _chunk, parse_err = load(trimmed, "lua_artifact_preflight", "t", {})
  if not _chunk then
    info.kind = "syntax_error"
    info.parse_ok = false
    info.runnable = false
    info.parse_err = parse_err
    info.reason = "Lua syntax check failed"
    return info
  end

  local stripped = Code._lua_artifact_strip_comments(trimmed)
  local lower = stripped:lower()
  local first_line = stripped:match("^%s*([^\r\n]+)") or stripped
  local short = info.line_count <= 4 and #trimmed <= 360
  local has_reaper_or_gfx = stripped:find("reaper%.") ~= nil
    or stripped:find("gfx%.") ~= nil
  local has_complete_shape = lower:find("undo_beginblock", 1, true) ~= nil
    or lower:find("undo_endblock", 1, true) ~= nil
    or stripped:find("local%s+function%s+[%w_]+") ~= nil
    or stripped:find("function%s+[%w_]+%s*%(") ~= nil
    or stripped:find("reaper%.defer%s*%(") ~= nil
  local starts_control =
       first_line:match("^%s*if%s") ~= nil
    or first_line:match("^%s*if%s*%(") ~= nil
    or first_line:match("^%s*for%s") ~= nil
    or first_line:match("^%s*while%s") ~= nil
    or first_line:match("^%s*repeat%s*$") ~= nil
    or first_line:match("^%s*elseif%s") ~= nil
    or first_line:match("^%s*else%s*$") ~= nil
    or first_line:match("^%s*return%s") ~= nil
    or first_line:match("^%s*break%s*$") ~= nil

  if trimmed:find("^%s*@@")
     or trimmed:find("^%s*%-%-%-")
     or trimmed:find("^%s*%+%+%+") then
    info.kind = "patch"
    info.runnable = false
    info.reason = "diff or patch text"
    return info
  end

  if short and starts_control and not has_reaper_or_gfx
     and not has_complete_shape then
    info.kind = "fragment"
    info.runnable = false
    info.reason = "short control-flow snippet without REAPER actions"
    return info
  end

  if info.line_count <= 8
     and Code._lua_artifact_context_says_fragment(opts.context_text)
     and not has_complete_shape then
    info.kind = "fragment"
    info.runnable = false
    info.reason = "surrounding text presents this as a snippet or patch"
    return info
  end

  return info
end

function Code.lua_artifact_block_message(info)
  info = info or {}
  local kind = info.kind or "fragment"
  local reason = info.reason or "it does not look self-contained"
  if kind == "syntax_error" then
    return "This Lua block failed syntax validation and was not run: "
      .. tostring(info.parse_err or reason)
  end
  return "This Lua block looks like a " .. kind
    .. ", not a complete runnable script (" .. tostring(reason) .. "). "
    .. "ReaAssist did not run it. Ask for the complete script or edit "
    .. "the block until it is self-contained before running."
end

function Code.record_latest_code_candidate(code, source, opts)
  opts = opts or {}
  if type(code) ~= "string" or code == "" then return nil end
  local artifact = opts.artifact
    or Code.classify_lua_artifact(code, { context_text = opts.context_text })
  if not artifact or not artifact.parse_ok or not artifact.runnable then
    return nil
  end
  local prev = S.latest_code_candidate
  local keep_working = prev and prev.code == code and prev.working == true
  S.latest_code_candidate = {
    code = code,
    source = source or "unknown",
    code_type = "lua",
    artifact_kind = artifact.kind,
    runnable = true,
    working = keep_working or opts.working == true,
    working_note = keep_working and prev.working_note or opts.working_note,
    captured_at = os.time and os.time() or nil,
  }
  return S.latest_code_candidate
end

function Code.extract_user_lua_candidate(user_text)
  local text = tostring(user_text or "")
  local parts = {}
  for block in text:gmatch("```lua%s*\n(.-)\n%s*```") do
    parts[#parts+1] = block
  end
  if #parts == 0 then
    for block in text:gmatch("```reascript%s*\n(.-)\n%s*```") do
      parts[#parts+1] = block
    end
  end
  if #parts > 0 then
    local code = tbl_concat(parts, "\n\n")
    return code, Code.classify_lua_artifact(code, { context_text = text })
  end

  local trimmed = Code._lua_artifact_trim(text)
  if trimmed == "" then return nil end
  if not (trimmed:find("reaper%.") or trimmed:find("gfx%.")
          or trimmed:find("local%s+function")
          or trimmed:find("function%s+[%w_]+%s*%(")) then
    return nil
  end
  local artifact = Code.classify_lua_artifact(trimmed, { context_text = text })
  if artifact.parse_ok then return trimmed, artifact end
  return nil
end

function Code.maybe_update_latest_from_user(user_text)
  local code, artifact = Code.extract_user_lua_candidate(user_text)
  if code and artifact then
    return Code.record_latest_code_candidate(code, "user", {
      artifact = artifact,
      context_text = user_text,
    })
  end
  return nil
end

function Code.maybe_mark_latest_candidate_working(user_text)
  local cand = S.latest_code_candidate
  if not cand then return false end
  local lt = tostring(user_text or ""):lower()
  if lt == "" then return false end
  if lt:find("doesn't work", 1, true)
     or lt:find("doesnt work", 1, true)
     or lt:find("does not work", 1, true)
     or lt:find("not working", 1, true)
     or lt:find("won't work", 1, true)
     or lt:find("wont work", 1, true)
     or lt:find("runtime error", 1, true) then
    return false
  end
  local positive = lt:find("%f[%w]works%f[%W]") ~= nil
    or lt:find("%f[%w]worked%f[%W]") ~= nil
    or lt:find("%f[%w]good%f[%W]") ~= nil
    or lt:find("%f[%w]perfect%f[%W]") ~= nil
    or lt:find("looks good", 1, true) ~= nil
    or lt:find("that's it", 1, true) ~= nil
    or lt:find("that is it", 1, true) ~= nil
  if not positive then return false end
  cand.working = true
  cand.working_note = user_text
  cand.working_at = os.time and os.time() or nil
  return true
end

function Code.latest_code_followup_note(user_text)
  local cand = S.latest_code_candidate
  if not cand or type(cand.code) ~= "string" or cand.code == "" then
    return nil
  end
  local lt = tostring(user_text or ""):lower()
  local refers =
       lt:find("latest script", 1, true) ~= nil
    or lt:find("last script", 1, true) ~= nil
    or lt:find("previous script", 1, true) ~= nil
    or lt:find("complete script", 1, true) ~= nil
    or lt:find("complete latest", 1, true) ~= nil
    or lt:find("full script", 1, true) ~= nil
    or lt:find("working script", 1, true) ~= nil
    or lt:find("this script", 1, true) ~= nil
    or lt:find("that script", 1, true) ~= nil
    or lt:find("same script", 1, true) ~= nil
    or lt:find("fix it", 1, true) ~= nil
    or lt:find("change it", 1, true) ~= nil
    or lt:find("make it", 1, true) ~= nil
    or lt:find("add to it", 1, true) ~= nil
    or lt:find("before you do", 1, true) ~= nil
  if not refers then return nil end
  local code = cand.code
  local truncated = false
  if #code > 40000 then
    code = code:sub(1, 40000)
      .. "\n-- [latest code candidate truncated for context]"
    truncated = true
  end
  return "(INTERNAL CODE CONTEXT -- DO NOT MENTION THIS: The user appears "
    .. "to be referring to the latest runnable Lua script candidate. Use "
    .. "this as the current code base unless the user explicitly provides "
    .. "a newer script. source=" .. tostring(cand.source)
    .. ", working_base=" .. tostring(cand.working == true)
    .. ", truncated=" .. tostring(truncated) .. ".)\n```lua\n"
    .. code .. "\n```"
end

-- =============================================================================
-- Code.run
-- =============================================================================
-- Compiles and executes a Lua string inside REAPER. Shows a message box on
-- compile or runtime error. Returns true on success, false on error.
--
-- Wraps execution in a plugin-level undo block as a safety net. The assistant
-- is instructed to include Undo_BeginBlock/EndBlock in its code, but if it
-- forgets, this outer wrapper ensures the user still gets undo protection.
-- Nested undo blocks are harmless in REAPER (inner ones are simply absorbed).

-- =============================================================================
-- Code.safety_backup
-- =============================================================================
-- Copies the current project file to a timestamped .rpp-bak file in the same
-- directory. Returns true on success, or false plus an error key on failure:
--   "unsaved"    - project has never been saved (no file on disk)
--   "read_error" - could not open the source file
--   "write_error"- could not write the backup file
function Code.safety_backup()
  local BACKUP_MAX = 10  -- maximum safety backups to keep per project
  local _, proj_path = reaper.EnumProjects(-1)
  if not proj_path or proj_path == "" then
    return false, "unsaved"
  end

  -- Extract directory and project name (without .rpp extension). Match the
  -- extension case-insensitively so projects saved as .RPP / .Rpp / etc. are
  -- not treated as unsaved.
  local dir  = proj_path:match("(.+)[/\\]")
  local name = proj_path:match("([^/\\]+)%.[rR][pP][pP]$")
  if not dir or not name then
    return false, "unsaved"
  end

  -- Diff-aware: skip if the project state hasn't changed since our last backup.
  -- GetProjectStateChangeCount increments on every change (fader moves, edits,
  -- FX adds, etc.) regardless of whether the user has saved.
  local cur_state = reaper.GetProjectStateChangeCount(0)
  if S.last_backup_path and S.last_backup_state == cur_state then
    return false, "unchanged"
  end

  local timestamp   = os.date("%Y%m%d-%H%M%S")
  local backup_path = dir .. RA.SEP .. name .. "-SafetyBackup-" .. timestamp .. ".rpp-bak"

  -- Save current project state (including unsaved changes) directly to the
  -- backup path without touching the main .rpp. Options=0 means no template
  -- flags and no project-path reassignment.
  reaper.Main_SaveProjectEx(0, backup_path, 0)

  -- Main_SaveProjectEx returns nothing, so verify the backup landed on disk
  -- before claiming success. Without this, a permission error or full-disk
  -- failure would silently let generated code run while the UI insists a
  -- safety backup exists.
  if not reaper.file_exists(backup_path) then
    return false, "write_error"
  end
  local probe = io.open(backup_path, "rb")
  if not probe then return false, "write_error" end
  local first = probe:read(1)
  probe:close()
  if not first then return false, "write_error" end

  -- Track last backup state for diff-aware skipping.
  S.last_backup_path  = backup_path
  S.last_backup_state = cur_state

  -- Enforce backup cap: collect all SafetyBackup files, delete oldest if over limit.
  -- Escape Lua magic characters in the project name so names like "Mix-v1.2"
  -- don't break the pattern and bypass the cap (causing infinite disk bloat).
  local safe_name = name:gsub("[%^%$%(%)%%%.%[%]%*%+%-%?]", "%%%1")
  local pattern = "^" .. safe_name .. "%-SafetyBackup%-%d+%-%d+%.rpp%-bak$"
  local backups = {}
  local idx = 0
  while true do
    local fn = reaper.EnumerateFiles(dir, idx)
    if not fn then break end
    if fn:match(pattern) then
      backups[#backups + 1] = fn
    end
    idx = idx + 1
  end
  if #backups > BACKUP_MAX then
    table.sort(backups)  -- alphabetical = chronological (timestamp format)
    for k = 1, #backups - BACKUP_MAX do
      local victim = dir .. RA.SEP .. backups[k]
      local ok_rm, err_rm = os.remove(victim)
      if not ok_rm then
        Log.line("BACKUP", "Failed to prune old safety backup "
          .. backups[k] .. ": " .. tostring(err_rm))
      end
    end
  end

  return true
end

-- Redirects print() to reaper.ShowConsoleMsg so output from assistant-generated
-- code is visible in REAPER's console window rather than going to stdout
-- (which REAPER hides).
--
-- Sandboxed environment: generated code only sees a curated whitelist of Lua
-- builtins plus the reaper/gfx APIs. Dangerous modules (os, io, debug,
-- package) and meta-level primitives (load, loadfile, dofile, require,
-- rawset, rawget, getmetatable, setmetatable, _G) are excluded. This is a
-- defence-in-depth layer on top of the risky-code scanner and the system
-- prompt rules -- any one of the three may stop a bad generation, but all
-- three together make accidental damage extremely unlikely.
--
-- The sandbox is a flat table (no __index fallback to _G) so generated code
-- cannot reach anything not explicitly listed. Writes go into the sandbox
-- table itself and do not leak to script globals.

-- Build the sandbox once at load time. Rebuilding per-call would be wasteful
-- since the whitelist is static; only the `print` redirect needs the closure.

-- Shallow-copy a table's fields into a new table. Used to isolate sandbox
-- copies of `string`, `math`, and `table` from the host environment so that
-- generated code cannot corrupt the host's standard libraries by mutating
-- shared references (e.g. `string.format = function() return "pwned" end`).
local function sandbox_lib_copy(t)
  local c = {}
  for k, v in pairs(t) do c[k] = v end
  return c
end

local CODE_SANDBOX_BASE = {
  -- Lua core builtins (safe subset)
  assert     = assert,
  error      = error,
  ipairs     = ipairs,
  next       = next,
  pairs      = pairs,
  pcall      = pcall,
  select     = select,
  tonumber   = tonumber,
  tostring   = tostring,
  type       = type,
  unpack     = table.unpack or unpack,
  xpcall     = xpcall,
  -- Safe standard libraries (isolated copies -- mutations by generated code
  -- stay inside the sandbox and cannot corrupt host-side string/math/table).
  math       = sandbox_lib_copy(math),
  string     = sandbox_lib_copy(string),
  table      = sandbox_lib_copy(table),
  -- REAPER APIs (the whole point of running generated code)
  reaper     = reaper,
  gfx        = gfx,
}

function Code.run(code)
  local artifact = Code.classify_lua_artifact(code)
  if not artifact.runnable then
    local msg = Code.lua_artifact_block_message(artifact)
    Log.line("SCRIPT", "Blocked non-runnable Lua artifact: "
      .. tostring(artifact.kind) .. " / " .. tostring(artifact.reason))
    Log.add_error(msg)
    S.last_run_error = "blocked non-runnable lua artifact: "
      .. tostring(artifact.kind) .. " / " .. tostring(artifact.reason)
    return false
  end

  -- Per-call sandbox: shallow copy the static base and add the print redirect.
  -- Built BEFORE load() so we can pass the env directly via the 4th argument,
  -- which is cleaner and stricter than retrofitting _ENV via debug.setupvalue.
  local code_env = {}
  for k, v in pairs(CODE_SANDBOX_BASE) do code_env[k] = v end
  code_env.print = function(...)
    -- Use select("#", ...) + select(i, ...) rather than {...}/#args: a table
    -- built with `{...}` has an undefined length when the varargs contain nil
    -- (e.g. print(1, nil, 3)), which silently drops trailing arguments.
    local n = select("#", ...)
    local buf = {}
    for i = 1, n do
      local v = tostring((select(i, ...)))
      if i > 1 then reaper.ShowConsoleMsg("\t"); buf[#buf+1] = "\t" end
      reaper.ShowConsoleMsg(v)
      buf[#buf+1] = v
    end
    reaper.ShowConsoleMsg("\n")
    Log.line("SCRIPT", "print: " .. table.concat(buf))
  end

  -- Undo capture state. The outer wrapper (below) is the ONLY real Begin/End
  -- pair against REAPER's undo stack; the shim intercepts the generated
  -- code's own Begin/End calls so a throw between them cannot unbalance the
  -- stack. We still capture the descriptive label the code passed to
  -- Undo_EndBlock and forward it to the outer End, so REAPER's undo history
  -- reads "ReaAssist: Create 10 tracks" rather than a generic "ReaAssist".
  -- Later captures overwrite earlier ones; generated code that issues
  -- multiple Begin/End pairs collapses into one outer entry with the last
  -- non-empty label (typical generations are one logical operation).
  local inner_undo_label = nil
  local inner_undo_flags = -1

  -- Wrap `reaper` so user-facing calls (dialogs, console output) are logged
  -- when debug logging is enabled. Every other reaper.* call falls through to
  -- the real API via __index with zero overhead when logging is off.
  local reaper_shim = setmetatable({
    ShowMessageBox = function(msg, title, btn_type)
      Log.line("SCRIPT", "ShowMessageBox [" .. tostring(title) .. "]: "
        .. tostring(msg):gsub("\n", " \\n "))
      return reaper.ShowMessageBox(msg, title, btn_type)
    end,
    ShowConsoleMsg = function(msg)
      Log.line("SCRIPT", "ShowConsoleMsg: " .. tostring(msg):gsub("\n$", ""):gsub("\n", " \\n "))
      return reaper.ShowConsoleMsg(msg)
    end,
    -- Undo shim: no-op on REAPER's side, capture the label on End so the
    -- outer wrapper can apply it. Return 0 from EndBlock to match REAPER's
    -- real signature (it returns 0 when there was nothing to undo, non-zero
    -- otherwise); generated code rarely checks this, and returning 0 is the
    -- safe default given we didn't actually open a real block here.
    Undo_BeginBlock  = function() end,
    Undo_BeginBlock2 = function(_proj) end,
    Undo_EndBlock = function(label, flags)
      if label and label ~= "" then
        inner_undo_label = label
        inner_undo_flags = flags or -1
      end
      return 0
    end,
    Undo_EndBlock2 = function(_proj, label, flags)
      if label and label ~= "" then
        inner_undo_label = label
        inner_undo_flags = flags or -1
      end
      return 0
    end,
  }, { __index = reaper })
  code_env.reaper = reaper_shim

  if Log.enabled() then
    Log.line("SCRIPT", "Running generated code (" .. #code .. " bytes)")
  end

  -- "t" enforces text-only chunks (no bytecode), and the 4th arg sets _ENV
  -- directly at compile time without needing debug.setupvalue.
  local fn, compile_err = load(code, "ReaAssist", "t", code_env)
  if not fn then
    local err_str = tostring(compile_err)
    Log.line("SCRIPT", "Compile error: " .. err_str)
    Diag.add_error(err_str, nil, code)
    -- Surface the failure as a chat-visible message instead of (only) a modal
    -- popup: the popup interrupts flow and hides the error the moment the
    -- user clicks OK, so they have nothing to reference when they type a
    -- follow-up. Inline lets them read the trace, copy parts, and keep going.
    Log.add_error("Lua compile error in generated code:\n\n" .. err_str)
    -- Stash so the next user prompt's send_to_api can include the error as
    -- model context -- when the user types "fix that" they expect the model
    -- to know what broke. Cleared after the next send.
    S.last_run_error = "compile error: " .. err_str
    return false
  end

  -- Plugin-level undo wrapper. The generated code's own Undo_Begin/EndBlock
  -- calls are intercepted by reaper_shim above (no-op + label capture), so
  -- this pair is the ONLY real interaction with REAPER's undo stack and a
  -- throw anywhere inside fn() cannot leave the stack unbalanced. The label
  -- the inner code passed to Undo_EndBlock ("ReaAssist: Create 10 tracks"
  -- etc.) is surfaced in REAPER's undo history via inner_undo_label.
  reaper.Undo_BeginBlock()
  local ok, run_err = xpcall(fn, debug and debug.traceback or tostring)
  reaper.Undo_EndBlock(inner_undo_label or "ReaAssist", inner_undo_flags)
  if not ok then
    local err_str = tostring(run_err)
    Log.line("SCRIPT", "Runtime error: " .. err_str:gsub("\n", " \\n "))
    Diag.add_error(err_str, nil, code)
    -- Trim the traceback to the first 6 lines so the chat bubble stays
    -- compact. The full trace is still in the debug log + Diag report.
    local short = err_str
    do
      local lines, n = {}, 0
      for line in err_str:gmatch("[^\n]+") do
        n = n + 1
        if n > 6 then lines[#lines+1] = "  ..."; break end
        lines[#lines+1] = line
      end
      short = tbl_concat(lines, "\n")
    end
    Log.add_error("Runtime error in generated code:\n\n" .. short)
    S.last_run_error = "runtime error: " .. err_str
    return false
  end
  Log.line("SCRIPT", "Script completed OK")
  reaper.UpdateArrange()
  return true
end

-- =============================================================================
-- Code.tokenize_lua  /  Code.tokenize_jsfx
-- =============================================================================
-- Lightweight syntax highlighter for the chat code blocks. Used by default
-- for every code block until the user clicks the per-block Edit button to
-- switch that block to a plain editable widget. The tokenizer walks the source
-- character by character (no PCRE/lpeg) and emits a flat list of {type, text} tokens that
-- the renderer then paints with TextColored + SameLine. Token text may span
-- newlines (long strings, block comments) -- the renderer slices on \n.
--
-- Token types: "kw" (keyword), "str" (string), "num", "com" (comment),
--              "api" (known library: reaper, ImGui, math, ...), "id", "ws",
--              "other" (operators / punctuation -- rendered in default color).
--
-- Limitations on purpose (keep the tokenizer ~120 lines):
--   * No nested long brackets [==[ ... ]==] -- only [[ ... ]] is recognised.
--   * No multi-character escape parsing inside strings; we just walk past \X.
--   * JSFX/EEL gets a separate, simpler tokenizer (//, /* */, # for hex).
local LUA_KEYWORDS = {
  ["and"]=1, ["break"]=1, ["do"]=1, ["else"]=1, ["elseif"]=1, ["end"]=1,
  ["false"]=1, ["for"]=1, ["function"]=1, ["goto"]=1, ["if"]=1, ["in"]=1,
  ["local"]=1, ["nil"]=1, ["not"]=1, ["or"]=1, ["repeat"]=1, ["return"]=1,
  ["then"]=1, ["true"]=1, ["until"]=1, ["while"]=1,
}
local LUA_API_NAMES = {
  reaper=1, ImGui=1, gfx=1, math=1, string=1, table=1, io=1, os=1,
  bit=1, debug=1, coroutine=1, package=1, _G=1, _ENV=1,
  ipairs=1, pairs=1, next=1, select=1, type=1, tostring=1, tonumber=1,
  pcall=1, xpcall=1, error=1, assert=1, print=1, require=1, setmetatable=1,
  getmetatable=1, rawget=1, rawset=1, rawequal=1, rawlen=1, unpack=1,
  load=1, loadstring=1, loadfile=1, dofile=1,
}

-- Detects a Lua long-bracket open at position i. Returns the level (number of
-- "=" between the brackets) if `[`, optional `=...`, `[` is present, else nil.
-- Used by the tokenizer to handle [[...]], [=[...]=], [==[...]==], etc.
local function _long_bracket_open_level(src, i)
  if src:sub(i, i) ~= "[" then return nil end
  local j = i + 1
  while src:sub(j, j) == "=" do j = j + 1 end
  if src:sub(j, j) ~= "[" then return nil end
  return j - i - 1
end

function Code.tokenize_lua(src)
  local tokens = {}
  local i, n = 1, #src
  while i <= n do
    local c = src:sub(i, i)
    -- Whitespace run (preserve verbatim so indentation lines up).
    if c == " " or c == "\t" or c == "\n" or c == "\r" then
      local j = i + 1
      while j <= n do
        local cj = src:sub(j, j)
        if cj ~= " " and cj ~= "\t" and cj ~= "\n" and cj ~= "\r" then break end
        j = j + 1
      end
      tokens[#tokens+1] = { type = "ws", text = src:sub(i, j - 1) }
      i = j
    -- Block comment --[[ ... ]] (or --[=[ ... ]=], --[==[ ... ]==], etc.)
    elseif c == "-" and src:sub(i + 1, i + 1) == "-"
       and _long_bracket_open_level(src, i + 2) then
      local lvl   = _long_bracket_open_level(src, i + 2)
      local close = src:find("]" .. ("="):rep(lvl) .. "]",
        i + 2 + lvl + 1, true)
      local stop  = close and (close + lvl + 1) or n
      tokens[#tokens+1] = { type = "com", text = src:sub(i, stop) }
      i = stop + 1
    -- Line comment --
    elseif c == "-" and src:sub(i + 1, i + 1) == "-" then
      local nl   = src:find("\n", i, true)
      local stop = nl and (nl - 1) or n
      tokens[#tokens+1] = { type = "com", text = src:sub(i, stop) }
      i = stop + 1
    -- Long-bracket string [[ ... ]] (or [=[ ... ]=], [==[ ... ]==], etc.)
    elseif c == "[" and _long_bracket_open_level(src, i) then
      local lvl   = _long_bracket_open_level(src, i)
      local close = src:find("]" .. ("="):rep(lvl) .. "]",
        i + lvl + 2, true)
      local stop  = close and (close + lvl + 1) or n
      tokens[#tokens+1] = { type = "str", text = src:sub(i, stop) }
      i = stop + 1
    -- Quoted string ('...' or "...")
    elseif c == '"' or c == "'" then
      local quote = c
      local j = i + 1
      while j <= n do
        local cj = src:sub(j, j)
        if cj == "\\" then
          j = j + 2
        elseif cj == quote then
          j = j + 1
          break
        elseif cj == "\n" then
          break  -- unterminated; stop at newline
        else
          j = j + 1
        end
      end
      tokens[#tokens+1] = { type = "str", text = src:sub(i, j - 1) }
      i = j
    -- Number (hex, decimal, optional fractional and exponent parts).
    elseif c:match("%d") then
      local rest = src:sub(i)
      local num  = rest:match("^0[xX][%dA-Fa-f]+") or
                   rest:match("^%d+%.?%d*[eE][%+%-]?%d+") or
                   rest:match("^%d+%.?%d*")
      if num and #num > 0 then
        tokens[#tokens+1] = { type = "num", text = num }
        i = i + #num
      else
        tokens[#tokens+1] = { type = "other", text = c }
        i = i + 1
      end
    -- Identifier or keyword.
    elseif c:match("[_%a]") then
      local rest  = src:sub(i)
      local ident = rest:match("^[_%a][_%w]*") or c
      local ttype
      if LUA_KEYWORDS[ident] then
        ttype = "kw"
      elseif LUA_API_NAMES[ident] then
        ttype = "api"
      else
        ttype = "id"
      end
      tokens[#tokens+1] = { type = ttype, text = ident }
      i = i + #ident
      -- Chain api highlight through dotted accesses so
      -- "reaper.InsertTrackAtIndex" renders the whole path in fn_amber,
      -- not just the module prefix. Tags the ".method" tail as api too.
      if ttype == "api" then
        while i <= n and src:sub(i, i) == "." do
          local next_ident = src:sub(i + 1):match("^[_%a][_%w]*")
          if not next_ident then break end
          tokens[#tokens+1] = { type = "api", text = "." }
          tokens[#tokens+1] = { type = "api", text = next_ident }
          i = i + 1 + #next_ident
        end
      end
    -- Anything else: single-char "other" token (operators, punctuation).
    else
      tokens[#tokens+1] = { type = "other", text = c }
      i = i + 1
    end
  end
  return tokens
end

local JSFX_KEYWORDS = {
  ["if"]=1, ["else"]=1, ["while"]=1, ["loop"]=1, ["function"]=1,
  ["local"]=1, ["global"]=1, ["instance"]=1, ["this"]=1,
}

function Code.tokenize_jsfx(src)
  -- Each token: { type, text, pos, line, col }. Line/col track the original
  -- source so static-validator rules report findings at user-readable
  -- positions. Types: ws, com, str, num, kw (JSFX_KEYWORDS + @sections),
  -- id, other.
  local tokens = {}
  local i, n = 1, #src
  local line, col = 1, 1
  local function advance(len)
    for k = i, i + len - 1 do
      if src:sub(k, k) == "\n" then line = line + 1; col = 1
      else col = col + 1 end
    end
    i = i + len
  end
  while i <= n do
    local sl, sc, sp = line, col, i
    local c = src:sub(i, i)
    local tok
    if c == " " or c == "\t" or c == "\n" or c == "\r" then
      local j = i
      while j <= n and src:sub(j, j):match("[ \t\n\r]") do j = j + 1 end
      tok = { type = "ws", text = src:sub(i, j - 1) }; advance(j - i)
    elseif c == "/" and src:sub(i + 1, i + 1) == "*" then
      local close = src:find("*/", i + 2, true)
      local stop = close and (close + 1) or n
      tok = { type = "com", text = src:sub(i, stop) }; advance(stop - i + 1)
    elseif c == "/" and src:sub(i + 1, i + 1) == "/" then
      local nl = src:find("\n", i, true)
      local stop = nl and (nl - 1) or n
      tok = { type = "com", text = src:sub(i, stop) }; advance(stop - i + 1)
    elseif c == "@" then
      local sect = src:sub(i):match("^@%w+") or "@"
      tok = { type = "kw", text = sect }; advance(#sect)
    elseif c == '"' or c == "'" then
      local q = c
      local j = i + 1
      while j <= n do
        local cj = src:sub(j, j)
        if cj == "\\" then j = j + 2
        elseif cj == q then j = j + 1; break
        elseif cj == "\n" then break
        else j = j + 1 end
      end
      tok = { type = "str", text = src:sub(i, j - 1) }; advance(j - i)
    elseif c:match("%d") then
      local rest = src:sub(i)
      local num = rest:match("^0[xX][%dA-Fa-f]+")
               or rest:match("^%d+%.?%d*[eE][%+%-]?%d+")
               or rest:match("^%d+%.?%d*")
      if num and #num > 0 then
        tok = { type = "num", text = num }; advance(#num)
      else
        tok = { type = "other", text = c }; advance(1)
      end
    elseif c:match("[_%a]") then
      local ident = src:sub(i):match("^[_%a][_%w]*") or c
      tok = {
        type = JSFX_KEYWORDS[ident] and "kw" or "id",
        text = ident,
      }; advance(#ident)
    else
      tok = { type = "other", text = c }; advance(1)
    end
    tok.line, tok.col, tok.pos = sl, sc, sp
    tokens[#tokens + 1] = tok
  end
  return tokens
end

-- =============================================================================
-- Code.validate_jsfx
-- =============================================================================
-- Static analysis for generated JSFX before auto-save / auto-run. Returns a
-- list of findings; each: { severity, code, line, message }. Severity is
-- "fatal" (would gate auto-run + qualify for one retry) or "warn" (advisory).
-- Calibrated against C:\REAPER\Effects (264 standalone stock + community JSFX)
-- to keep per-rule false-positive rates at or below ~3.5%. The audit harness
-- lives in Dev/Tests/corpus_audit.lua (gitignored); regression tests live
-- alongside it in Dev/Tests/test_*.lua.
--
-- Rules:
--  fatal  missing_desc          first non-comment content not `desc:`
--  fatal  reaper_api            `reaper.X` reference (JSFX has no reaper API)
--  fatal  banned_braces         `{` or `}` outside header lines / strings / comments
--  fatal  banned_else           bare `else` keyword (no else in EEL2)
--  fatal  banned_math_prefix    `math.X` (EEL2 uses bare `sin`, `cos`, ...)
--  fatal  banned_for_loop       C-style `for(...)` (use `loop()` or `while()`)
--  fatal  feedback_unclamped    feedback-named slider can exceed 0.85 with no
--                               `0.85` clamp visible (Prompts.md mandate)
--  fatal  memory_no_init        `id[...]` or `mem[id+...]` indexed but `id`
--                               is never assigned a base value (skipped when
--                               file uses `import`)
--  fatal  buffer_overlap        two declared buffers (`X = base; X_len = len;`
--                               where X is used as a memory base) have spans
--                               that intersect -- two filters writing to the
--                               same memory addresses
--  fatal  parallel_comb_doubled in @sample, 2+ buffer writes share the same
--                               additive feedback RHS (`bufN[wN] = input +
--                               <term>*<id>`). Identical content written to
--                               parallel buffers makes their summed reads
--                               loop-gain N*fb; runs away even with fb<=0.85
--  fatal  hard_clip_unrequested `min(max(audio, -T), T)` with T<=1.5 on a
--                               sample-touching expr, when user_text doesn't
--                               request clip/limit/distort
--  fatal  arg_count_mismatch    `id(...)` call to a built-in EEL2/JSFX
--                               function with fixed arity uses the wrong
--                               number of arguments (e.g. `memset(0, len)`
--                               instead of `memset(0, 0, len)`). Catches
--                               REAPER's `'%s' needs N prms` compile error
--                               class. Conservative arity table -- only
--                               functions with unambiguous fixed signatures.
--  warn   unknown_function      `id(...)` call where id is neither in the
--                               EEL2/JSFX whitelist nor user-defined; logged
--                               but not gated
do

local function add(findings, sev, code, line, message)
  findings[#findings + 1] = { severity = sev, code = code, line = line, message = message }
end

local function next_significant(tokens, from)
  for i = from, #tokens do
    local t = tokens[i]
    if t.type ~= "ws" and t.type ~= "com" then return i, t end
  end
end

local function skip_ws(tokens, i)
  while tokens[i] and (tokens[i].type == "ws" or tokens[i].type == "com") do
    i = i + 1
  end
  return tokens[i] and i or nil
end

local function read_signed_num(tokens, i)
  i = skip_ws(tokens, i); if not i then return nil end
  local sign = 1
  if tokens[i].type == "other" and tokens[i].text == "-" then
    sign = -1
    i = skip_ws(tokens, i + 1); if not i then return nil end
  end
  if tokens[i].type ~= "num" then return nil end
  return sign * tonumber(tokens[i].text), i + 1
end

local function match_seq(tokens, start, pat)
  local i = start
  for _, p in ipairs(pat) do
    while tokens[i] and (tokens[i].type == "ws" or tokens[i].type == "com") do
      i = i + 1
    end
    local t = tokens[i]
    if not t then return false end
    if p.type and t.type ~= p.type then return false end
    if p.text and t.text ~= p.text then return false end
    i = i + 1
  end
  return true
end

local function find_seq_lines(tokens, pat)
  -- Only start matches at significant tokens. match_seq's leading-ws skip
  -- means starting from a ws/com token would otherwise produce a duplicate
  -- hit at the preceding line.
  local lines = {}
  for i = 1, #tokens do
    local t = tokens[i]
    if t.type ~= "ws" and t.type ~= "com" and match_seq(tokens, i, pat) then
      lines[#lines + 1] = t.line
    end
  end
  return lines
end

-- `sliderN:default<min,max,step>Name` (range optional).
local function parse_sliders(src)
  local out = {}
  local cur = 0
  for line_text in src:gmatch("([^\n]*)\n?") do
    cur = cur + 1
    local idx, def, rest = line_text:match("^%s*slider(%d+):([^<\n]*)(.*)$")
    if idx then
      local mn, mx, step, name
      local range, after = rest:match("^<([^>]*)>(.*)$")
      if range then
        mn, mx, step = range:match("^([^,]*),([^,]*),([^,]*)$")
        if not mn then mn, mx = range:match("^([^,]*),([^,]*)$") end
        name = after
      else
        name = rest
      end
      out[#out + 1] = {
        index = tonumber(idx),
        default = (def or ""):gsub("^%s+", ""):gsub("%s+$", ""),
        min  = tonumber(((mn   or ""):gsub("%s", ""))),
        max  = tonumber(((mx   or ""):gsub("%s", ""))),
        step = tonumber(((step or ""):gsub("%s", ""))),
        name = (name or ""):gsub("^%s+", ""):gsub("%s+$", ""),
        line = cur,
      }
    end
  end
  return out
end

-- Header lines (slider, desc, tags, ...) are NOT EEL2 code: `{enum}` and
-- `[TAG]` text inside descriptions are legal there and must be skipped.
local function build_header_lines(src)
  local set = {}
  local n = 0
  for line_text in src:gmatch("([^\n]*)\n?") do
    n = n + 1
    if line_text:match("^%s*slider%d")
       or line_text:match("^%s*desc:")
       or line_text:match("^%s*filename:")
       or line_text:match("^%s*tags:")
       or line_text:match("^%s*author:")
       or line_text:match("^%s*in_pin:")
       or line_text:match("^%s*out_pin:")
       or line_text:match("^%s*options:")
       or line_text:match("^%s*import%s") then
      set[n] = true
    end
  end
  return set
end

local function check_desc(tokens, findings)
  local _, t = next_significant(tokens, 1)
  if not t then
    add(findings, "fatal", "missing_desc", 1, "Empty source; no `desc:` line found.")
    return
  end
  if not (t.type == "id" and t.text == "desc") then
    add(findings, "fatal", "missing_desc", t.line,
        "First non-comment content must be `desc:` line.")
  end
end

local function check_reaper_api(tokens, findings)
  for _, line in ipairs(find_seq_lines(tokens, {
    { type = "id", text = "reaper" }, { type = "other", text = "." },
  })) do
    add(findings, "fatal", "reaper_api", line,
        "JSFX has no access to `reaper.*` API.")
  end
end

-- `end`, `then`, `return` are NOT reserved in EEL2 and stock JSFX uses them
-- as identifiers (e.g. `end = 18 * (2*$pi/16)`); banning them false-positives
-- on legit code. Only `else` is rare-enough as an identifier to keep.
local BANNED_BARE = {
  ["else"] = "EEL2 has no `else` keyword. Use ternary `cond ? a : b`.",
}

local function check_banned_syntax(tokens, header_lines, findings)
  for _, t in ipairs(tokens) do
    if t.type == "other" and (t.text == "{" or t.text == "}") then
      if not header_lines[t.line] then
        add(findings, "fatal", "banned_braces", t.line,
            "EEL2 has no `{}` blocks. Group statements with `(...)`.")
      end
    elseif (t.type == "id" or t.type == "kw") and BANNED_BARE[t.text] then
      add(findings, "fatal", "banned_" .. t.text, t.line, BANNED_BARE[t.text])
    end
  end
  for _, line in ipairs(find_seq_lines(tokens, {
    { type = "id", text = "math" }, { type = "other", text = "." },
  })) do
    add(findings, "fatal", "banned_math_prefix", line,
        "EEL2 uses bare math functions (sin, cos, sqrt, ...). No `math.` prefix.")
  end
  for _, line in ipairs(find_seq_lines(tokens, {
    { type = "id", text = "for" }, { type = "other", text = "(" },
  })) do
    add(findings, "fatal", "banned_for_loop", line,
        "EEL2 has no C-style `for(...)`. Use `loop(N, ...)` or `while(cond) (...)`.")
  end
end

-- Map slider max into a worst-case feedback coefficient under common
-- conventions: raw 0..1, percent 0..100. Anything else is treated as risky.
local function slider_max_coef(s)
  if not s.max then return nil end
  local mx = s.max
  if mx <= 1.001 then return mx end
  if mx <= 100.001 then return mx / 100 end
  return 1.5
end

local FEEDBACK_NAMES = { "feedback", "regen", "regeneration", "resonance" }
local function name_is_feedback(name)
  local low = name:lower()
  if low:match("%f[%w]fb%f[^%w]") then return true end
  for _, p in ipairs(FEEDBACK_NAMES) do
    if low:find(p, 1, true) then return true end
  end
  return false
end

local function check_feedback_clamp(src, sliders, findings)
  local risky = {}
  for _, s in ipairs(sliders) do
    if name_is_feedback(s.name) then
      local coef = slider_max_coef(s)
      if coef and coef > 0.85 then risky[#risky + 1] = s end
    end
  end
  if #risky == 0 then return end
  -- Loose clamp detection: literal 0.85 or .85 anywhere in source.
  if src:find("0?%.85") then return end
  for _, s in ipairs(risky) do
    add(findings, "fatal", "feedback_unclamped", s.line,
        ("Feedback-style slider `%s` reaches >0.85 effective coefficient with no `0.85` clamp visible. Per ReaAssist's JSFX safety rule, hard-clamp the feedback coefficient to <= 0.85.")
          :format(s.name))
  end
end

local MEM_BUILTINS = { mem = 1, gmem = 1, spl0 = 1, spl1 = 1, spl2 = 1,
  spl3 = 1, spl4 = 1, spl5 = 1, spl6 = 1, spl7 = 1, this = 1 }

-- Has any token-level base assignment to id (`id =`, `id += ...`, etc.)?
-- An assignment to a slot (`id[expr] =`) does NOT count.
local function id_has_base_assignment(tokens, id_text)
  for i = 1, #tokens do
    local t = tokens[i]
    if t.type == "id" and t.text == id_text then
      local j = skip_ws(tokens, i + 1)
      if j and tokens[j].type == "other" then
        local jt = tokens[j].text
        if jt == "+" or jt == "-" or jt == "*" or jt == "/" then
          j = skip_ws(tokens, j + 1)
        end
        if j and tokens[j].type == "other" and tokens[j].text == "=" then
          local k = tokens[j + 1]
          if not (k and k.type == "other" and k.text == "=") then
            return true
          end
        end
      end
    end
  end
  return false
end

local function check_memory_init(tokens, header_lines, has_imports, findings)
  if has_imports then return end
  local seen = {}

  local function maybe_fire(id_text, line)
    if MEM_BUILTINS[id_text] then return end
    if id_text:match("^slider%d+$") then return end
    if seen[id_text] then return end
    seen[id_text] = true
    if not id_has_base_assignment(tokens, id_text) then
      add(findings, "fatal", "memory_no_init", line,
          ("Indexed access on `%s[...]` but `%s` is never assigned a base value (no `%s = ...` anywhere). Initialize the buffer base in @init.")
            :format(id_text, id_text, id_text))
    end
  end

  for i = 1, #tokens - 1 do
    local a = tokens[i]
    if a.type == "id" and not header_lines[a.line] then
      if a.text == "mem" or a.text == "gmem" then
        -- Pattern: `mem [ id` -- the id is the buffer base.
        local j = skip_ws(tokens, i + 1)
        if j and tokens[j].type == "other" and tokens[j].text == "[" then
          local k = skip_ws(tokens, j + 1)
          if k and tokens[k].type == "id" and not header_lines[tokens[k].line] then
            maybe_fire(tokens[k].text, tokens[k].line)
          end
        end
      else
        -- Pattern: `id [ ...` -- direct array indexing.
        local _, b = next_significant(tokens, i + 1)
        if b and b.type == "other" and b.text == "["
           and not header_lines[b.line] then
          maybe_fire(a.text, a.line)
        end
      end
    end
  end
end

-- buffer_overlap: detect pairs of declared buffer regions whose memory
-- spans overlap. A buffer is recognized when an id has BOTH a literal-int
-- base assignment AND a matching `<id>_len` (or `_length` / `_size`)
-- literal assignment, AND is used somewhere as a memory base (`id[...]` or
-- `mem[id + ...]`). Each overlapping pair fires its own fatal finding so
-- the model can fix the layout holistically on retry.
local LENGTH_SUFFIXES = { "_len", "_length", "_size" }

local function check_buffer_overlap(tokens, findings)
  -- Step 1: collect all `id = <integer literal>` assignments.
  local assigns = {}
  for i = 1, #tokens do
    local t = tokens[i]
    if t.type == "id" then
      local j = skip_ws(tokens, i + 1)
      if j and tokens[j].type == "other" and tokens[j].text == "=" then
        local nxt = tokens[j + 1]
        if not (nxt and nxt.type == "other" and nxt.text == "=") then
          local v = read_signed_num(tokens, j + 1)
          if v and v == math.floor(v) and v >= 0 then
            assigns[t.text] = { value = v, line = t.line }
          end
        end
      end
    end
  end

  -- Step 2: pair bases with length companions.
  local candidates = {}
  for id, info in pairs(assigns) do
    local is_len = false
    for _, suf in ipairs(LENGTH_SUFFIXES) do
      if id:sub(-#suf) == suf then is_len = true; break end
    end
    if not is_len then
      for _, suf in ipairs(LENGTH_SUFFIXES) do
        local len_info = assigns[id .. suf]
        if len_info and len_info.value > 0 then
          candidates[#candidates + 1] = {
            id = id, base = info.value,
            length = len_info.value, line = info.line,
          }
          break
        end
      end
    end
  end

  -- Step 3: confirm each candidate is actually used as a memory base.
  local used_as_base = {}
  for i = 1, #tokens - 1 do
    local t = tokens[i]
    if t.type == "id" then
      if t.text == "mem" or t.text == "gmem" then
        local j = skip_ws(tokens, i + 1)
        if j and tokens[j].type == "other" and tokens[j].text == "[" then
          local k = skip_ws(tokens, j + 1)
          if k and tokens[k].type == "id" then
            used_as_base[tokens[k].text] = true
          end
        end
      else
        local j = skip_ws(tokens, i + 1)
        if j and tokens[j].type == "other" and tokens[j].text == "[" then
          used_as_base[t.text] = true
        end
      end
    end
  end

  local buffers = {}
  for _, c in ipairs(candidates) do
    if used_as_base[c.id] then buffers[#buffers + 1] = c end
  end

  -- Step 4: pairwise overlap check. Each overlap fires a separate finding.
  for i = 1, #buffers do
    for j = i + 1, #buffers do
      local b1, b2 = buffers[i], buffers[j]
      local lo1, hi1 = b1.base, b1.base + b1.length - 1
      local lo2, hi2 = b2.base, b2.base + b2.length - 1
      if lo1 <= hi2 and lo2 <= hi1 then
        local first, second = b1, b2
        if first.base > second.base then first, second = second, first end
        local overlap = math.min(hi1, hi2) - math.max(lo1, lo2) + 1
        add(findings, "fatal", "buffer_overlap",
            math.max(b1.line, b2.line),
            ("Buffer `%s` (base=%d, len=%d -> owns %d..%d) overlaps buffer `%s` (base=%d, len=%d -> owns %d..%d) by %d samples. Each filter must own a non-overlapping memory region.")
              :format(
                first.id, first.base, first.length,
                first.base, first.base + first.length - 1,
                second.id, second.base, second.length,
                second.base, second.base + second.length - 1,
                overlap))
      end
    end
  end
end

local function find_hard_clip_clamps(tokens)
  local out = {}
  for i = 1, #tokens do
    local t = tokens[i]
    if t.type == "id" and t.text == "min" then
      local j = skip_ws(tokens, i + 1)
      if j and tokens[j].type == "other" and tokens[j].text == "(" then
        local k = skip_ws(tokens, j + 1)
        if k and tokens[k].type == "id" and tokens[k].text == "max" then
          local m = skip_ws(tokens, k + 1)
          if m and tokens[m].type == "other" and tokens[m].text == "(" then
            local depth = 1
            local expr_start, expr_end = m + 1, nil
            local q = m + 1
            while tokens[q] do
              local x = tokens[q]
              if x.type == "other" then
                if x.text == "(" then depth = depth + 1
                elseif x.text == ")" then depth = depth - 1; if depth == 0 then break end
                elseif x.text == "," and depth == 1 then expr_end = q - 1; break end
              end
              q = q + 1
            end
            if expr_end then
              local lo, lo_after = read_signed_num(tokens, q + 1)
              if lo then
                local close_max = skip_ws(tokens, lo_after)
                if close_max and tokens[close_max].type == "other"
                   and tokens[close_max].text == ")" then
                  local comma2 = skip_ws(tokens, close_max + 1)
                  if comma2 and tokens[comma2].type == "other"
                     and tokens[comma2].text == "," then
                    local hi, _ = read_signed_num(tokens, comma2 + 1)
                    if hi then
                      local pieces = {}
                      for r = expr_start, expr_end do
                        if tokens[r].type ~= "ws" and tokens[r].type ~= "com" then
                          pieces[#pieces + 1] = tokens[r].text
                        end
                      end
                      out[#out + 1] = {
                        line = t.line,
                        threshold = math.max(math.abs(lo), math.abs(hi)),
                        expr_text = table.concat(pieces, " "),
                      }
                    end
                  end
                end
              end
            end
          end
        end
      end
    end
  end
  return out
end

local function expr_touches_audio(expr_text)
  return expr_text:match("%f[%w]spl%d+%f[^%w]") ~= nil
end

local CLIP_INTENT = { "clip", "limit", "limiter", "brick", "wall", "fuzz",
  "crush", "distort", "saturate", "drive", "hard" }

local function user_requested_clip(user_text)
  if not user_text or user_text == "" then return false end
  local low = user_text:lower()
  for _, w in ipairs(CLIP_INTENT) do
    if low:find(w, 1, true) then return true end
  end
  return false
end

local function check_hard_clip(tokens, user_text, findings)
  if user_requested_clip(user_text) then return end
  for _, c in ipairs(find_hard_clip_clamps(tokens)) do
    if c.threshold <= 1.5 and expr_touches_audio(c.expr_text) then
      add(findings, "fatal", "hard_clip_unrequested", c.line,
          ("Hard-clip pattern min(max(audio, -%g), %g) on a sample-touching expression without explicit user request for clip/limit/distort. Use soft saturation `x/(1+abs(x))` instead (tanh is NOT a JSFX built-in -- define it inline if needed).")
            :format(math.abs(c.threshold), c.threshold))
      return
    end
  end
end

-- parallel_comb_doubled: in @sample, multiple buffer writes share the same
-- feedback-style RHS expression. Pattern signature: 2+ writes of the form
-- `bufN[idx] = <RHS> ;` where the RHS is textually identical AND contains
-- both a `+` operator (additive feedback structure: `input + feedback_term`)
-- and a `<term> * <id>` subsequence (the feedback-coefficient multiplication).
--
-- Why this catches the runaway-feedback pattern: a Schroeder-style comb bank
-- requires each comb's write to feed back from its OWN read (cN[wN] =
-- input + fN * fb). When the model instead computes one shared feedback
-- signal and writes it into N parallel combs, all N buffers hold identical
-- content; their summed reads form a feedback path with loop gain N*fb,
-- well above unity even when fb=0.85. From any seed the signal grows
-- exponentially until the soft-saturator (if any) clamps -- the user hears
-- silence -> ramp -> pinned at full scale, often loud enough to damage
-- speakers/ears.
--
-- The `+` AND `*<id>` requirement filters out benign shared-write patterns
-- (`bufL[wL] = mono; bufR[wR] = mono;`) and pure gain applications
-- (`bufL[wL] = spl0 * gain;`). Calibrated against C:\REAPER\Effects: zero
-- false positives on stock JSFX; fires only on ReaAssist-generated reverbs
-- that produced the exact runaway-feedback bug.
local function check_parallel_comb_doubled(tokens, header_lines, has_imports, findings)
  if has_imports then return end

  -- Find @sample section bounds. JSFX_KEYWORDS doesn't mark @sections as kw,
  -- so the production tokenizer assigns them type "kw" with text "@sample"
  -- (see Code.tokenize_jsfx; @-prefixed sections get the kw type explicitly).
  local sample_start, sample_end
  for i = 1, #tokens do
    local t = tokens[i]
    if t.type == "kw" and t.text:sub(1, 1) == "@" then
      if t.text == "@sample" and not sample_start then
        sample_start = i + 1
      elseif sample_start and t.text ~= "@sample" then
        sample_end = i - 1
        break
      end
    end
  end
  if not sample_start then return end
  if not sample_end then sample_end = #tokens end

  -- Inner helper: walk RHS [rhs_start, rhs_end_excl) and return
  --   pieces            -- joined text, used as fingerprint
  --   has_plus          -- top-level `+` operator seen
  --   has_mult_by_id    -- explicit `<term> * <id>` in this RHS
  --   ref_ids           -- set of bare ids referenced in this RHS
  local function scan_rhs(rhs_start, rhs_end_excl)
    local pieces, has_plus, has_mult_by_id, ref_ids = {}, false, false, {}
    local prev_was_star, depth3 = false, 0
    for r = rhs_start, rhs_end_excl - 1 do
      local tr = tokens[r]
      if tr.type ~= "ws" and tr.type ~= "com" then
        pieces[#pieces + 1] = tr.text
        if tr.type == "other" then
          if tr.text == "(" or tr.text == "[" then depth3 = depth3 + 1
          elseif tr.text == ")" or tr.text == "]" then depth3 = depth3 - 1 end
          if tr.text == "+" and depth3 == 0 then has_plus = true end
        end
        if prev_was_star and tr.type == "id" then has_mult_by_id = true end
        if tr.type == "id" then ref_ids[tr.text] = true end
        prev_was_star = (tr.type == "other" and tr.text == "*")
      end
    end
    return table.concat(pieces, " "), has_plus, has_mult_by_id, ref_ids
  end

  -- Pass 1: collect feedback-flavored temp identifiers. The model can evade
  -- a "RHS contains <term> * <id>" check by hoisting the multiplication into
  -- a temp earlier in @sample (Opus 4.7 retry pattern: `combfb_L = fbL *
  -- fb_smooth; buf_cL0[wL0] = inL + combfb_L; buf_cL1[wL1] = inL + combfb_L;
  -- ...`). We track `id = <expr containing <id>*<id>> ;` assignments and
  -- treat any later RHS that references one of those temps as if it had a
  -- direct `* <id>`.
  local feedback_temps = {}
  do
    local i2 = sample_start
    while i2 <= sample_end do
      local t = tokens[i2]
      if t.type == "id" and not header_lines[t.line] then
        local j = skip_ws(tokens, i2 + 1)
        -- Look for `id = ...;` (NOT `id [ ... ] = ...;` which is a buffer
        -- write handled in pass 2, NOT `==` which is comparison).
        if j and tokens[j].type == "other" and tokens[j].text == "="
           and not (tokens[j+1] and tokens[j+1].type == "other"
                    and tokens[j+1].text == "=") then
          local rhs_start = j + 1
          local depth_p1, m = 0, rhs_start
          while m <= sample_end do
            local tm = tokens[m]
            if tm.type == "other" then
              if tm.text == "(" or tm.text == "[" then depth_p1 = depth_p1 + 1
              elseif tm.text == ")" or tm.text == "]" then depth_p1 = depth_p1 - 1
              elseif tm.text == ";" and depth_p1 == 0 then break end
            end
            m = m + 1
          end
          if m <= sample_end then
            local _, _, has_mult = scan_rhs(rhs_start, m)
            if has_mult then feedback_temps[t.text] = true end
            i2 = m
          end
        end
      end
      i2 = i2 + 1
    end
  end

  -- Pass 2: walk @sample, collect buffer-write signatures.
  local writes = {}
  local i = sample_start
  while i <= sample_end do
    local t = tokens[i]
    if t.type == "id" and not header_lines[t.line] then
      local j = skip_ws(tokens, i + 1)
      if j and tokens[j].type == "other" and tokens[j].text == "[" then
        local idx_start = j + 1
        local depth = 1
        local k = j + 1
        while k <= sample_end and depth > 0 do
          local tk = tokens[k]
          if tk.type == "other" then
            if tk.text == "[" then depth = depth + 1
            elseif tk.text == "]" then depth = depth - 1 end
          end
          k = k + 1
        end
        if depth == 0 then
          -- Capture the index expression text so two writes to the SAME
          -- buffer at different offsets count as distinct LHS slots
          -- (Gemini's flat-buffer-with-tap-offsets evasion).
          local idx_pieces = {}
          for r = idx_start, k - 2 do
            local tr = tokens[r]
            if tr.type ~= "ws" and tr.type ~= "com" then
              idx_pieces[#idx_pieces + 1] = tr.text
            end
          end
          local lhs_idx = table.concat(idx_pieces, " ")
          local eq = skip_ws(tokens, k)
          if eq and tokens[eq].type == "other" and tokens[eq].text == "=" then
            local nxt = tokens[eq + 1]
            if not (nxt and nxt.type == "other" and nxt.text == "=") then
              local rhs_start = eq + 1
              local depth2 = 0
              local m = rhs_start
              while m <= sample_end do
                local tm = tokens[m]
                if tm.type == "other" then
                  if tm.text == "(" or tm.text == "[" then depth2 = depth2 + 1
                  elseif tm.text == ")" or tm.text == "]" then depth2 = depth2 - 1
                  elseif tm.text == ";" and depth2 == 0 then break end
                end
                m = m + 1
              end
              if m <= sample_end then
                local fp, has_plus, has_mult_by_id, ref_ids =
                  scan_rhs(rhs_start, m)
                local has_mult_via_temp = false
                for id_name in pairs(ref_ids) do
                  if feedback_temps[id_name] then
                    has_mult_via_temp = true
                    break
                  end
                end
                writes[#writes + 1] = {
                  lhs_buf            = t.text,
                  lhs_idx            = lhs_idx,
                  fingerprint        = fp,
                  line               = t.line,
                  has_plus           = has_plus,
                  has_mult_by_id     = has_mult_by_id,
                  has_mult_via_temp  = has_mult_via_temp,
                }
                i = m
              end
            end
          end
        end
      end
    end
    i = i + 1
  end

  -- Group qualifying writes by RHS fingerprint; fire when 2+ distinct
  -- (buffer, index) write slots share the same feedback expression. The
  -- (buffer, index) tuple catches both topologies that produce identical
  -- content in N parallel taps:
  --   - N distinct buffers, same RHS  (classic Schroeder error)
  --   - 1 buffer, N distinct offsets, same RHS  (flat-buffer/tap-offset
  --     workaround; same loop-gain explosion since each region gets the
  --     same input-plus-shared-feedback every sample)
  local groups = {}
  for _, w in ipairs(writes) do
    if w.has_plus and (w.has_mult_by_id or w.has_mult_via_temp) then
      local g = groups[w.fingerprint]
      if not g then g = { members = {} }; groups[w.fingerprint] = g end
      g.members[#g.members + 1] = w
    end
  end
  local reported = {}
  for fp, g in pairs(groups) do
    local distinct = {}
    local distinct_bufs = {}
    for _, mem in ipairs(g.members) do
      distinct[mem.lhs_buf .. "[" .. mem.lhs_idx .. "]"] = true
      distinct_bufs[mem.lhs_buf] = true
    end
    local slots = {}
    for n in pairs(distinct) do slots[#slots + 1] = n end
    local bufs = {}
    for n in pairs(distinct_bufs) do bufs[#bufs + 1] = n end
    if #slots >= 2 and not reported[fp] then
      reported[fp] = true
      table.sort(slots)
      table.sort(bufs)
      local first = g.members[1]
      -- Tailor the message body to which evasion path was hit so the retry
      -- hint sent back to the model is specific (different buffers vs same
      -- buffer at different offsets).
      local target_phrase
      if #bufs >= 2 then
        target_phrase = ("%d different buffers (%s)")
          :format(#bufs, table.concat(bufs, ", "))
      else
        target_phrase = ("the same buffer `%s` at %d different offsets")
          :format(bufs[1], #slots)
      end
      add(findings, "fatal", "parallel_comb_doubled", first.line,
          ("Same feedback expression `%s` written to %s inside @sample. Each parallel comb must take its feedback from its OWN read (`cN[wN] = input + fN * fb`); writing one shared feedback signal to N parallel slots makes all N hold identical content, and the summed read path then has loop gain N*fb (well above unity for any N>=2 with fb=0.85), producing exponential runaway feedback that can damage speakers.")
            :format(fp, target_phrase))
    end
  end
end

-- unknown_function: flag function calls whose name is neither in the EEL2/
-- JSFX built-in whitelist nor user-defined in this file. Severity is `warn`
-- (advisory only -- not gated for retry) since the whitelist may need
-- expansion as new EEL2 functions are added by Cockos.
local KNOWN_FUNCTIONS = {
  -- Math
  ["sin"]=1, ["cos"]=1, ["tan"]=1, ["asin"]=1, ["acos"]=1,
  ["atan"]=1, ["atan2"]=1, ["sinh"]=1, ["cosh"]=1,
  -- NOTE: `tanh` is NOT a JSFX/EEL2 built-in. REAPER's compiler reports
  -- `'tanh' undefined`. Stock JSFX (Tukan, cookdsp) defines tanh as a
  -- user function. Do NOT add tanh here unless Cockos adds it natively.
  ["sqrt"]=1, ["sqr"]=1, ["pow"]=1, ["exp"]=1,
  ["log"]=1, ["log10"]=1, ["log2"]=1,
  ["abs"]=1, ["floor"]=1, ["ceil"]=1, ["min"]=1, ["max"]=1,
  ["sign"]=1, ["mod"]=1, ["invsqrt"]=1, ["rand"]=1, ["sleep"]=1,
  -- Bit (functional form)
  ["xor"]=1, ["shl"]=1, ["shr"]=1, ["bitor"]=1, ["bitand"]=1,
  -- Memory
  ["memcpy"]=1, ["memset"]=1, ["__memtop"]=1, ["freembuf"]=1,
  ["mem_set_values"]=1, ["mem_get_values"]=1, ["mem_insert_shuffle"]=1,
  -- Stack
  ["stack_push"]=1, ["stack_pop"]=1, ["stack_peek"]=1, ["stack_exch"]=1,
  -- String
  ["strlen"]=1, ["strcpy"]=1, ["strcmp"]=1, ["stricmp"]=1,
  ["strncmp"]=1, ["strnicmp"]=1, ["strncpy"]=1, ["strcat"]=1, ["strncat"]=1,
  ["strcpy_from"]=1, ["strcpy_substr"]=1, ["strcpy_fromslider"]=1,
  ["str_getchar"]=1, ["str_setchar"]=1, ["str_setlen"]=1,
  ["str_insert"]=1, ["str_delete_sub"]=1,
  ["match"]=1, ["matchi"]=1, ["sprintf"]=1, ["printf"]=1,
  ["atof"]=1, ["atoi"]=1,
  -- File
  ["file_open"]=1, ["file_close"]=1, ["file_avail"]=1, ["file_var"]=1,
  ["file_mem"]=1, ["file_riff"]=1, ["file_string"]=1, ["file_text"]=1,
  ["file_rewind"]=1,
  -- FFT / MDCT
  ["fft"]=1, ["ifft"]=1, ["fft_real"]=1, ["ifft_real"]=1,
  ["fft_permute"]=1, ["fft_ipermute"]=1, ["convolve_c"]=1,
  ["mdct"]=1, ["imdct"]=1, ["mdct_real"]=1, ["imdct_real"]=1,
  -- MIDI
  ["midisend"]=1, ["midirecv"]=1, ["midisend_buf"]=1, ["midirecv_buf"]=1,
  ["midisyx"]=1, ["midisend_str"]=1, ["midirecv_str"]=1,
  -- JSFX-specific
  ["slider"]=1, ["slider_automate"]=1, ["slider_next_chg"]=1,
  ["sliderchange"]=1, ["slider_show"]=1, ["spl"]=1,
  ["get_pin_mapping"]=1, ["set_pin_mapping"]=1,
  ["get_pinmapper_flags"]=1, ["set_pinmapper_flags"]=1,
  ["get_host_numchan"]=1, ["set_host_numchan"]=1,
  ["export_buffer_to_project"]=1,
  -- Atomics (newer EEL2)
  ["atomic_set"]=1, ["atomic_add"]=1, ["atomic_exch"]=1,
  ["atomic_or"]=1, ["atomic_and"]=1, ["atomic_xor"]=1,
  ["atomic_setifequal"]=1, ["atomic_get"]=1,
  -- GFX
  ["gfx_setpixel"]=1, ["gfx_getpixel"]=1, ["gfx_set"]=1, ["gfx_setcursor"]=1,
  ["gfx_setfont"]=1, ["gfx_getfont"]=1,
  ["gfx_line"]=1, ["gfx_lineto"]=1, ["gfx_rect"]=1, ["gfx_rectto"]=1,
  ["gfx_circle"]=1, ["gfx_arc"]=1, ["gfx_triangle"]=1,
  ["gfx_roundrect"]=1, ["gfx_gradrect"]=1, ["gfx_muladdrect"]=1,
  ["gfx_deltablit"]=1, ["gfx_blit"]=1, ["gfx_blitext"]=1,
  ["gfx_blit_ext"]=1, ["gfx_blit2"]=1, ["gfx_blitext2"]=1,
  ["gfx_loadimg"]=1, ["gfx_setimgdim"]=1, ["gfx_getimgdim"]=1,
  ["gfx_imgresize"]=1,
  ["gfx_drawchar"]=1, ["gfx_drawnumber"]=1, ["gfx_drawstr"]=1,
  ["gfx_measurestr"]=1, ["gfx_printf"]=1, ["gfx_setdest"]=1, ["gfx_clear"]=1,
  ["gfx_showmenu"]=1, ["gfx_getchar"]=1, ["gfx_getdropfile"]=1,
  ["gfx_blurto"]=1, ["gfx_getsyscol"]=1,
  -- EEL2 control flow / structural (callable-form: `loop(N, ...)`)
  ["loop"]=1, ["while"]=1, ["function"]=1, ["if"]=1,
  ["local"]=1, ["global"]=1, ["globals"]=1, ["instance"]=1, ["this"]=1,
  -- Time / misc
  ["time_precise"]=1, ["time"]=1,
  ["__denormal_likely_zero"]=1,
}

-- Built-in EEL2/JSFX functions with a strictly-fixed argument count. An
-- arity mismatch is a compile-time error in REAPER ("'memset' needs 3 prms").
-- Conservative list -- only functions where the signature is unambiguous in
-- the EEL2 / JSFX docs. Variadic builtins (mem_set_values, gfx_*, midisend
-- with optional ext bytes, etc.), default-arg builtins (rand which is 0-or-1
-- arg), and anything I'm not 100% sure about are intentionally absent --
-- false-fire on a legitimate call costs more than missing one or two
-- additional bug classes.
local FIXED_ARITY = {
  -- Memory ops: most-frequently-misused class (LLMs often forget the
  -- `value` arg on memset, the `count` arg on memcpy).
  memset = 3,    -- memset(dest, value, count)
  memcpy = 3,    -- memcpy(dest, src,   count)
  -- Math two-arg
  pow   = 2,     -- pow(base, exp)
  atan2 = 2,     -- atan2(y, x)
  -- Slider control
  sliderchange = 1,  -- sliderchange(slider_idx)
  -- Memory single-arg
  freembuf = 1,  -- freembuf(start_idx)
  -- Misc
  sleep = 1,     -- sleep(ms)
}

-- Returns the arg count of a function call starting at the `(` token at
-- index `paren_open`. Counts top-level commas; returns the close-paren
-- index too (or nil if unbalanced).
local function count_call_args(tokens, paren_open, sample_end)
  local depth, arg_count, has_content = 1, 0, false
  local k = paren_open + 1
  local end_idx = sample_end or #tokens
  while k <= end_idx and depth > 0 do
    local tk = tokens[k]
    if tk.type == "other" then
      if tk.text == "(" or tk.text == "[" then depth = depth + 1
      elseif tk.text == ")" or tk.text == "]" then depth = depth - 1
      elseif tk.text == "," and depth == 1 then arg_count = arg_count + 1 end
    end
    if depth >= 1 and tk.type ~= "ws" and tk.type ~= "com" then
      has_content = true
    end
    if depth == 0 then return arg_count + (has_content and 1 or 0), k end
    k = k + 1
  end
  return nil, nil  -- unbalanced
end

local function check_arg_count(tokens, has_imports, findings)
  if has_imports then return end

  -- Build set of user-defined function names so we don't false-fire on
  -- a JSFX that defined its own `function memset(...)` etc. (rare, but
  -- legal -- the user-defined function shadows the builtin).
  local user_defined = {}
  for i = 1, #tokens - 1 do
    local t = tokens[i]
    if (t.type == "id" or t.type == "kw") and t.text == "function" then
      local j = skip_ws(tokens, i + 1)
      if j and tokens[j].type == "id" then
        user_defined[tokens[j].text] = true
      end
    end
  end

  for i = 1, #tokens do
    local t = tokens[i]
    if t.type == "id" and FIXED_ARITY[t.text] and not user_defined[t.text] then
      local j = skip_ws(tokens, i + 1)
      if j and tokens[j].type == "other" and tokens[j].text == "(" then
        -- Skip method-call form (preceded by `.`): `obj.memset(...)` is
        -- a different function on a struct, not the global builtin.
        local p = i - 1
        while p >= 1 and (tokens[p].type == "ws" or tokens[p].type == "com") do
          p = p - 1
        end
        local is_method = p >= 1 and tokens[p].type == "other"
                       and tokens[p].text == "."
        if not is_method then
          local got = count_call_args(tokens, j)
          local expected = FIXED_ARITY[t.text]
          if got and got ~= expected then
            add(findings, "fatal", "arg_count_mismatch", t.line,
              ("`%s(...)` requires %d argument(s); call site has %d. EEL2 will reject this with a `'%s' needs %d prms` compile error."):format(
                t.text, expected, got, t.text, expected))
          end
        end
      end
    end
  end
end

local function check_unknown_function(tokens, header_lines, has_imports, findings)
  if has_imports then return end

  -- Step 1: collect user-defined function names from `function NAME(...)`.
  local user_defined = {}
  for i = 1, #tokens - 1 do
    local t = tokens[i]
    if (t.type == "id" or t.type == "kw") and t.text == "function" then
      local j = skip_ws(tokens, i + 1)
      if j and tokens[j].type == "id" then
        user_defined[tokens[j].text] = true
      end
    end
  end

  -- Step 2: scan for `id ( ` patterns. Skip header lines (slider display
  -- names look like calls -- `Mix (%)`), method calls (preceded by `.`),
  -- slider variables, and `@`-prefixed section markers (those are kw-typed
  -- by the tokenizer and `skip_ws` after them will cross the newline and
  -- land on the first `(` of the section body, falsely flagging
  -- `@sample(...)` / `@block(...)` etc. as unknown function calls).
  local seen = {}
  for i = 1, #tokens do
    local t = tokens[i]
    if (t.type == "id" or t.type == "kw") and not seen[t.text]
       and not KNOWN_FUNCTIONS[t.text] and not user_defined[t.text]
       and not t.text:match("^slider%d+$")
       and not t.text:match("^@")
       and not header_lines[t.line] then
      local j = skip_ws(tokens, i + 1)
      if j and tokens[j].type == "other" and tokens[j].text == "(" then
        local p = i - 1
        while p >= 1 and (tokens[p].type == "ws" or tokens[p].type == "com") do
          p = p - 1
        end
        local is_method = p >= 1 and tokens[p].type == "other"
                       and tokens[p].text == "."
        if not is_method then
          seen[t.text] = true
          add(findings, "warn", "unknown_function", t.line,
              ("Function `%s(...)` is not a documented EEL2/JSFX built-in and is not defined in this file. Verify it exists in your REAPER version, or define the function explicitly with `function %s(...) ( ... );`.")
                :format(t.text, t.text))
        end
      end
    end
  end
end

function Code.validate_jsfx(src, user_text)
  if not src or src == "" then return {} end
  local findings = {}
  local tokens = Code.tokenize_jsfx(src)
  local sliders = parse_sliders(src)
  local header_lines = build_header_lines(src)
  local has_imports = src:match("\n%s*import%s+%S") ~= nil
                   or src:match("^%s*import%s+%S") ~= nil
  check_desc(tokens, findings)
  check_reaper_api(tokens, findings)
  check_banned_syntax(tokens, header_lines, findings)
  check_feedback_clamp(src, sliders, findings)
  check_memory_init(tokens, header_lines, has_imports, findings)
  check_buffer_overlap(tokens, findings)
  check_parallel_comb_doubled(tokens, header_lines, has_imports, findings)
  check_hard_clip(tokens, user_text or "", findings)
  check_arg_count(tokens, has_imports, findings)
  check_unknown_function(tokens, header_lines, has_imports, findings)
  return findings
end

-- True if any finding has fatal severity (would gate auto-run).
function Code.jsfx_findings_have_gate(findings)
  if not findings then return false end
  for _, f in ipairs(findings) do
    if f.severity == "fatal" then return true end
  end
  return false
end

end  -- close JSFX validator scope

-- =============================================================================
-- Net.process_response_buckets: handle <context_needed> on-demand buckets
-- =============================================================================
-- Parses any <context_needed>...</context_needed> tag in the model response and,
-- if fresh bucket data is needed, assembles the enriched history and fires a
-- follow-up curl request. Returns true when the follow-up was fired (caller
-- should bail); false when the normal final-response path should continue.
function Net.process_response_buckets(text)
  -- Handle <context_needed> on-demand buckets: session, docs, plugin_ref,
  -- fx_params:Name[, Name2]. Buckets can be combined in one tag (comma-separated).
  -- Each is guarded by a one-shot flag so the same bucket is never injected twice
  -- in one turn, preventing infinite follow-up loops.
  --
  -- Strip inline code spans and fenced code blocks BEFORE looking for
  -- <context_needed> tags. Models often quote the tag syntax in
  -- explanations ("your reply must be `<context_needed>docs</context_needed>`
  -- with no other content"), and those quoted tags are demonstrations,
  -- not real requests. Parsing them fires a wasted bucket-fetch round
  -- trip, which the loop detector then flags as duplicate context and
  -- aborts the turn with a user-facing error. A compliant model's real
  -- request emits the bare tag per the system-prompt rule "AND NOTHING
  -- ELSE," so the bare form will still match after scrubbing; only the
  -- demonstration-quoted form gets filtered out.
  local scrubbed = text
    :gsub("```.-```", "")     -- fenced code blocks (non-greedy)
    :gsub("`[^`]*`", "")      -- inline code spans
  -- Models occasionally emit two separate <context_needed> tags in one
  -- response instead of one comma-joined tag. Collect all of them and merge
  -- their payloads with a comma so the existing token parser handles them
  -- uniformly. Without this, only the first tag was processed and the rest
  -- vanished silently, leaving the model stuck waiting for context.
  local merged = {}
  -- Tolerate stray whitespace inside the tag delimiters (e.g. "< context_needed>"):
  -- some quantized models tokenize "<context_needed>" as separate pieces and
  -- decode with a space, which would otherwise fall through as visible chat.
  for cap in scrubbed:gmatch("<%s*context_needed%s*>%s*(.-)%s*<%s*/%s*context_needed%s*>") do
    if cap ~= "" then merged[#merged+1] = cap end
  end
  local bucket_str = (#merged > 0) and tbl_concat(merged, ", ") or nil
  if not (bucket_str and S.pending_orig_prompt) then return false end

  -- Mixed-output detection. The system prompt requires a bare <context_needed>
  -- tag with no prose. Models violate this routinely with polite hedges like
  -- "I need to see which tracks have FX before I can act." + tag. Old behavior
  -- surfaced the prose and dropped the tag, forcing the user to nag the model
  -- two or three times before it complied with a bare tag. New behavior: fire
  -- the bucket fetch anyway (the prose is hidden because intermediate bucket-
  -- fetch turns aren't displayed) and append a reminder to the follow-up so
  -- the model self-corrects on subsequent turns. The CONTEXT_LOOP detector
  -- below catches the pathological case (model keeps re-requesting already-
  -- pinned data). Threshold: 40 non-whitespace characters of non-tag,
  -- non-code content -- short tags like "Fetching..." don't need the hint.
  local non_tag = scrubbed:gsub("<%s*context_needed%s*>.-<%s*/%s*context_needed%s*>", "")
  local non_ws_count = 0
  for _ in non_tag:gmatch("%S") do
    non_ws_count = non_ws_count + 1
    if non_ws_count > 40 then break end
  end
  local raw_non_tag = text:gsub("<%s*context_needed%s*>.-<%s*/%s*context_needed%s*>", "")
  local has_final_payload =
       raw_non_tag:find("```%s*[%w_-]*%s*\n") ~= nil
    or raw_non_tag:find("reaper%.") ~= nil
    or raw_non_tag:find('"actions"%s*:') ~= nil
  if non_ws_count > 40 then
    Log.line("CONTEXT_NEEDED",
      "tag emitted alongside prose; firing fetch with reminder (\""
      .. bucket_str .. "\")")
    S._mixed_output_hint = true
  end

  local wants_docs        = false
  local wants_docs_extended = false
  local wants_docs_section = false
  local docs_section_names  = {}  -- canonical section names to fetch this turn
  local bogus_docs_sections = {}  -- raw payloads that failed allowlist; for nudge
  local wants_session     = false
  local wants_fx_params   = false
  local wants_plugin_ref  = false
  local plugin_ref_names  = {}  -- plugin names for plugin_ref scoped bucket
  local curated_pref_hints = {} -- {tkey, ident, curated} tuples accumulated by
                                -- the resolve handler when a user-pref ident
                                -- matches CURATED_IDENT; finalize emits a
                                -- slim pref:<tkey> hint for each so the model
                                -- knows the curated content IS the user's pref
  local wants_fx_list     = false
  local wants_fx_chains   = false
  local wants_track_flags = false
  local wants_midi        = false
  local wants_recent_reaper_changes = false
  local wants_pref_plugins = false
  local wants_theme       = false
  local wants_fx_inspect  = false
  -- Sentinel: set when the model emits a <context_needed> for data already
  -- in sticky_context (typically from preempt injection or an earlier
  -- turn's fetch). We still need to fire a follow-up turn -- the model's
  -- response so far is just the context_needed tag, not code -- but we
  -- don't fetch anything new. The reinforcement hint tells the model the
  -- data is already available and nudges it to write code. Weak models
  -- (GPT-5 mini, Flash 3) hit this path routinely after preempt injection.
  local wants_preempt_hint = false
  local wants_prompt_bundle = false
  local pref_plugin_types = {}  -- type keys for preferred_plugins scoped bucket
  local fx_filter_names   = {}  -- plugin names to match; populated from the colon payload
  local fx_list_search    = {}  -- search terms for fx_list bucket
  local fx_inspect_names  = {}  -- search terms for fx_inspect bucket
  local prompt_bundle_names = {}  -- bundle names for prompt_bundle scoped bucket

  -- Parse comma-separated bucket tokens. Plain keywords ("session", "docs") are
  -- handled directly. Scoped keywords ("fx_params:VintageVerb") split on ":".
  -- Two-pass approach: pass 1 finds fx_params and its inline payload; pass 2
  -- collects subsequent non-keyword tokens as additional plugin name filters,
  -- so "fx_params:Plugin1, Plugin2" correctly builds filter = {Plugin1, Plugin2}.
  local recognised_keywords = { session=true, docs=true, docs_extended=true, recent_reaper_changes=true, fx_params=true, plugin_ref=true, fx_list=true, fx_chains=true, track_flags=true, midi=true, preferred_plugins=true, theme=true, fx_inspect=true, resolve=true, prompt_bundle=true }
  -- Hoisted out of the resolve branch so the pre-pass (just below) and the
  -- popup-bail scan-ahead can both reference it.
  local VALID_RESOLVE_TYPES = {
    eq=true, compressor=true, multiband_compressor=true, reverb=true,
    delay=true, saturation=true, limiter=true, gate=true, chorus=true,
    phaser=true, deesser=true, pitch_correction=true,
    pitch_shift=true, synth=true, custom=true,
  }
  local raw_tokens = {}
  for tok in bucket_str:gmatch("[^,]+") do
    raw_tokens[#raw_tokens+1] = tok:match("^%s*(.-)%s*$")
  end

  -- Expand resolve scoped-continuation. The system prompt teaches scoped
  -- continuation for plugin_ref/fx_list/preferred_plugins (e.g.
  -- "preferred_plugins:eq, compressor"), and the model occasionally applies
  -- the same shorthand to resolve ("resolve:compressor, eq"). The main
  -- parser's last_scoped path can't cover resolve because the resolve branch
  -- bails the loop on popup -- continuation tokens after that would be lost.
  -- Easiest fix: pre-rewrite "resolve:X, Y" into ["resolve:X", "resolve:Y"]
  -- here, so the rest of the parser sees explicit resolve tokens.
  local prev_was_resolve = false
  for i, tok in ipairs(raw_tokens) do
    local has_colon = tok:find(":", 1, true) ~= nil
    if has_colon then
      local hkw = (tok:match("^([^:]+)") or ""):match("^%s*(.-)%s*$"):lower()
      prev_was_resolve = (hkw == "resolve")
    elseif prev_was_resolve and VALID_RESOLVE_TYPES[tok:lower()] then
      raw_tokens[i] = "resolve:" .. tok
      -- prev_was_resolve stays true so a chain "resolve:a, b, c" all expand.
    else
      prev_was_resolve = false
    end
  end

  -- Pre-pass: drop tokens whose data is already in pinned context. The
  -- model occasionally re-requests data already listed in the PINNED
  -- REFERENCES manifest (observed: a turn 2 tag that named session +
  -- 3 already-pinned bundles alongside a legitimate resolve, costing a
  -- wasted inner round-trip). Per-bucket gates inside the main loop
  -- already drop most of these silently, but coverage is uneven (some
  -- gates set wants_preempt_hint, others fall through; `session` checks
  -- session_already_sent but not whether the snapshot is on this very
  -- turn). The pre-pass unifies the de-dup, logs the dropped list so
  -- the redundancy is visible at a glance, and sets the reuse hint so
  -- an all-redundant tag still fires a "use the data you have"
  -- follow-up instead of leaking the model's tag-only response.
  --
  -- Scope: only static buckets that map 1:1 to pinned slots (sticky
  -- bundles, static refs, or the snapshot attached to this turn).
  -- Most dynamic buckets (fx_list, fx_chains, fx_inspect, track_flags,
  -- resolve:*) are NOT pre-deduped -- their data is live and the model is
  -- allowed to re-emit them to get a fresh read. Scoped fx_params is the
  -- exception: preempt may have already pinned the exact live instance for
  -- this turn, and re-requesting it just burns a follow-up round-trip.
  local dropped_pinned = {}
  do
    local function token_already_pinned(kw, payload)
      if kw == "session" then
        -- Snapshot is attached to the current user message already
        -- (S.pending_snapshot is set whenever build_snapshot ran for
        -- this turn). A re-fetch would just rebuild the same snapshot
        -- the model is about to read.
        return S.pending_snapshot ~= nil
      elseif kw == "docs" and payload == "" then
        return S.api_ref_message ~= nil or S.docs_already_sent
      elseif kw == "docs" and payload ~= "" then
        local canonical = _docs_section_canonical(payload)
        return canonical
          and S.docs_section_sent
          and S.docs_section_sent[canonical] == true
      elseif kw == "docs_extended" then
        return S.docs_extended_already_sent == true
      elseif kw == "recent_reaper_changes" then
        return S.sticky_context
          and S.sticky_context["recent_reaper_changes"] ~= nil
      elseif kw == "midi" then
        return S.midi_ref_message ~= nil or S.midi_already_sent
      elseif kw == "theme" then
        return S.theme_ref_message ~= nil or S.theme_already_sent
      elseif kw == "prompt_bundle" and payload ~= "" then
        local pkey = payload:lower()
        return S.sticky_context
          and S.sticky_context["prompt_bundle:" .. pkey] ~= nil
      elseif kw == "plugin_ref" and payload ~= "" then
        return (S.plugin_ref_sent and S.plugin_ref_sent[payload] == true)
          or (S.sticky_context and S.sticky_context["plugin_ref:" .. payload] ~= nil)
      elseif kw == "preferred_plugins" and payload ~= "" then
        return (S.pref_plugins_sent and S.pref_plugins_sent[payload] == true)
          or (S.sticky_context and S.sticky_context["pref:" .. payload] ~= nil)
      elseif kw == "fx_chains" then
        return S.fx_chains_already_sent == true
      elseif kw == "track_flags" then
        return S.track_flags_already_sent == true
      elseif kw == "fx_params" and payload ~= "" then
        local fp_key = "fx:" .. CTX.fx_filter_key({ CTX.fx_filter_parse(payload) })
        return S.sticky_context
          and (S.sticky_context[fp_key] ~= nil
            or CTX.sticky_has_fx_params_for_ident(payload))
      elseif kw == "fx_params" and payload == "" then
        return S.fx_params_already_sent == true
      elseif kw == "fx_list" and payload == "" then
        return S.fx_list_already_sent == true
      elseif kw == "fx_inspect" and payload == "" then
        return S.fx_inspect_already_sent == true
      end
      return false
    end
    local kept = {}
    for _, tok in ipairs(raw_tokens) do
      local kw, payload = tok:match("^([^:]+):?(.*)$")
      kw = kw and kw:match("^%s*(.-)%s*$"):lower() or ""
      payload = payload and payload:match("^%s*(.-)%s*$") or ""
      if token_already_pinned(kw, payload) then
        dropped_pinned[#dropped_pinned+1] = tok
      else
        kept[#kept+1] = tok
      end
    end
    if #dropped_pinned > 0 then
      if #kept == 0 then
        Log.line("CONTEXT_ALREADY_PINNED",
          "all requested tags already present: "
          .. tbl_concat(dropped_pinned, ", "))
      else
        Log.line("DISPATCH",
          "dropped already-pinned tokens (" .. #dropped_pinned .. "/"
          .. (#dropped_pinned + #kept) .. "): "
          .. tbl_concat(dropped_pinned, ", "))
      end
      S._context_reuse_hint = S._context_reuse_hint or {}
      for _, t in ipairs(dropped_pinned) do
        S._context_reuse_hint[#S._context_reuse_hint+1] = t
      end
      -- All tokens dropped -> no real fetch will fire below. If the model
      -- also emitted a runnable/structured final payload, ignore the stale
      -- tag and let the normal final-response path strip it, validate code,
      -- and continue. Plain prose is not enough: models often narrate
      -- "let me check..." while still failing to produce a usable answer.
      -- In that case, fire a follow-up turn carrying the reuse hint instead
      -- of falling through to display the non-answer.
      if #kept == 0 then
        if has_final_payload then
          S._context_reuse_hint = nil
          S._mixed_output_hint = nil
          Log.line("CONTEXT_ALREADY_PINNED",
            "all requested tags already present; ignoring stale tag and continuing final response")
          return false
        end
        wants_preempt_hint = true
      end
    end
    raw_tokens = kept
  end

  local last_scoped = nil  -- tracks which scoped keyword ("fx_params"/"fx_list") was last seen

  for tok_idx, tok in ipairs(raw_tokens) do
    local kw, payload = tok:match("^([^:]+):?(.*)$")
    kw = kw and kw:match("^%s*(.-)%s*$"):lower() or ""
    payload = payload and payload:match("^%s*(.-)%s*$") or ""

    if kw == "session" and not S.session_already_sent then
      wants_session = true
      last_scoped = nil
    elseif kw == "docs" and payload ~= "" then
      -- docs:<section> -- on-demand API ref section. MUST come before the
      -- bare-docs branch below: that branch matches kw=="docs" regardless
      -- of payload and would silently drop the section name. Validate via
      -- the allowlist; unknown names land in bogus_docs_sections so the
      -- handler can emit a recoverable nudge instead of a silent drop.
      local canonical = _docs_section_canonical(payload)
      if canonical then
        S.docs_section_sent = S.docs_section_sent or {}
        if not S.docs_section_sent[canonical] then
          wants_docs_section = true
          docs_section_names[#docs_section_names+1] = canonical
        end
      else
        bogus_docs_sections[#bogus_docs_sections+1] = payload
      end
      last_scoped = "docs"  -- enables "docs:items, envelopes" continuation
    elseif kw == "docs" and not S.docs_already_sent then
      wants_docs = true
      last_scoped = nil
    elseif kw == "docs_extended" and not S.docs_extended_already_sent then
      wants_docs_extended = true
      last_scoped = nil
    elseif kw == "recent_reaper_changes" then
      if not (S.sticky_context and S.sticky_context["recent_reaper_changes"]) then
        wants_recent_reaper_changes = true
      else
        wants_preempt_hint = true
        S._context_reuse_hint = S._context_reuse_hint or {}
        S._context_reuse_hint[#S._context_reuse_hint+1] =
          "recent_reaper_changes"
      end
      last_scoped = nil
    elseif kw == "plugin_ref" then
      last_scoped = "plugin_ref"
      if payload ~= "" and not S.plugin_ref_sent[payload] then
        wants_plugin_ref = true
        plugin_ref_names[#plugin_ref_names+1] = payload
      end
    elseif kw == "fx_list" and not S.fx_list_already_sent then
      wants_fx_list = true
      last_scoped = "fx_list"
      if payload ~= "" then
        fx_list_search[#fx_list_search+1] = payload
      end
    elseif kw == "fx_chains" and not S.fx_chains_already_sent then
      wants_fx_chains = true
      last_scoped = nil
    elseif kw == "track_flags" and not S.track_flags_already_sent then
      wants_track_flags = true
      last_scoped = nil
    elseif kw == "fx_params" and not S.fx_params_already_sent then
      wants_fx_params = true
      last_scoped = "fx_params"
      if payload ~= "" then
        fx_filter_names[#fx_filter_names+1] = CTX.fx_filter_parse(payload)
      end
    elseif kw == "midi" and not S.midi_already_sent then
      wants_midi = true
      last_scoped = nil
    elseif kw == "preferred_plugins" then
      last_scoped = "preferred_plugins"
      if payload ~= "" and not S.pref_plugins_sent[payload] then
        wants_pref_plugins = true
        pref_plugin_types[#pref_plugin_types+1] = payload
      end
    elseif kw == "theme" and not S.theme_already_sent then
      wants_theme = true
      last_scoped = nil
    elseif kw == "fx_inspect" and not S.fx_inspect_already_sent then
      wants_fx_inspect = true
      last_scoped = "fx_inspect"
      if payload ~= "" then
        fx_inspect_names[#fx_inspect_names+1] = payload
      end
    elseif kw == "prompt_bundle" then
      last_scoped = "prompt_bundle"
      if payload ~= "" then
        local pb_name = payload:lower()
        local pb_key = "prompt_bundle:" .. pb_name
        if not (S.sticky_context and S.sticky_context[pb_key]) then
          wants_prompt_bundle = true
          prompt_bundle_names[#prompt_bundle_names+1] = pb_name
        else
          -- Already pinned (typically via JSFX-family co-pin: when
          -- prompt_bundle:jsfx_pitch was pre-pinned alongside jsfx_pitch,
          -- the base bundle and the family bundle are both in sticky_context).
          -- Without this branch the request
          -- silently drops -- fine for the dedupe but the model is still
          -- waiting for permission to write code, so the turn stalls. Fire
          -- a follow-up with the reuse hint so the model proceeds without
          -- a second round-trip.
          wants_preempt_hint     = true
          S._context_reuse_hint  = S._context_reuse_hint or {}
          S._context_reuse_hint[#S._context_reuse_hint+1] = pb_key
        end
      end
    elseif kw == "resolve" then
      -- resolve:<type> -- chokepoint for "give me a plugin of TYPE without
      -- specifying which". Translates the request into an underlying bucket
      -- based on what the user has installed/configured:
      --
      --   pref set for type     -> route through preferred_plugins:<type>
      --   eq + ReEQ installed   -> route through plugin_ref:ReEQ (EQ only)
      --   otherwise             -> block the round and raise the resolve
      --                            popup so the user can pick a plugin.
      --                            Returns immediately -- no follow-up curl
      --                            fires until the user clicks.
      --
      -- Supported types must match the set the system prompt is allowed to
      -- emit (see System_Prompt.md "resolve:Type bucket").
      last_scoped = nil
      local rtype = payload:lower()
      if not VALID_RESOLVE_TYPES[rtype] then
        Log.line("RESOLVE", "unsupported type: " .. tostring(rtype))
      else
        -- Dedupe: if the data this resolve would fetch is already in
        -- sticky_context (from preempt injection or an earlier turn),
        -- skip the fetch and set a reinforcement hint. Covers the common
        -- case where preempt injected plugin_ref:ReEQ for "eq" but the
        -- model still emits <context_needed>resolve:eq</context_needed>
        -- anyway -- weak models (mini, flash) ignore pinned sticky data
        -- and re-request. Firing the follow-up with just the hint ("you
        -- already have this data above, use it now") nudges the model
        -- into writing code without another full bucket-fetch round trip.
        local already_covered = false
        if rtype == "eq" and S.plugin_ref_sent and S.plugin_ref_sent["ReEQ"] then
          already_covered = true
        elseif S.pref_plugins_sent and S.pref_plugins_sent[rtype] then
          already_covered = true
        end
        if already_covered then
          Log.line("RESOLVE", rtype
            .. " -> already covered by sticky (dedupe; no fetch)")
          wants_preempt_hint = true
          S._context_reuse_hint = S._context_reuse_hint or {}
          S._context_reuse_hint[#S._context_reuse_hint+1] = "resolve:" .. rtype
        else
        local pref = FXCache.get_preferred_types()
        local pref_ident = pref and pref[rtype]
        -- Dev-only FabFilter hide: treat a matching pref as absent so the
        -- resolve path falls through to the popup branch below (same gate
        -- applied in CTX.preferred_plugins / load_pref_plugins / preempt).
        -- Without this, the resolve handler would still load the real
        -- pref content + mark pref_plugins_sent, and a second resolve
        -- request from the model would hit the dedupe branch and loop.
        if reaper.GetExtState(CFG.EXT_NS, "dev_hide_fabfilter") == "1"
           and _is_fabfilter_ident(pref_ident) then
          pref_ident = nil
        end
        if pref_ident and pref_ident ~= "" then
          Log.line("RESOLVE", rtype .. " -> user_pref ("
            .. tostring(pref_ident) .. ")")
          -- If the user's preferred plugin matches a curated section in
          -- Plugin_Ref.md, route through plugin_ref:<Name>
          -- instead of the live-scan preferred_plugins:<type> bucket.
          -- The curated ref carries verified indices, scale formulas, and
          -- per-recipe normalized values that the live param scan lacks.
          -- Mirrors the preempt path's curated handling so both routes
          -- deliver the same content for the same pref identifier. Uses
          -- the prefix/vendor-tolerant lookup (preferred_types may store
          -- canonicalized "VST3: Pro-Q 4" instead of bare "Pro-Q 4").
          local curated = _curated_for_ident(pref_ident)
          if curated then
            if not S.plugin_ref_sent[curated] then
              wants_plugin_ref = true
              plugin_ref_names[#plugin_ref_names+1] = curated
              curated_pref_hints[#curated_pref_hints+1] = {
                tkey = rtype, ident = pref_ident, curated = curated,
              }
            end
            -- Mark pref_plugins_sent so a same-turn re-emission of
            -- resolve:<rtype> hits the already_covered branch above (the
            -- model already has the user's pref data, just under a
            -- plugin_ref: key instead of a pref: key).
            S.pref_plugins_sent[rtype] = true
          elseif not S.pref_plugins_sent[rtype] then
            wants_pref_plugins = true
            pref_plugin_types[#pref_plugin_types+1] = rtype
          end
        elseif rtype == "eq" and Code.is_reeq_installed() then
          -- Mid-session ReEQ catch. If the user just installed ReEQ via
          -- ReaPack while the script was already running, CTX._installed_fx_list
          -- is stale and Code.ensure_preferred_from_chains (which walks that
          -- cached list) won't find it. Code.is_reeq_installed() bypasses
          -- the cache via a direct filesystem check, so we catch it here.
          -- ReEQ is the only bundled/special-case plugin -- other types
          -- hit the resolve popup below if their chain came up empty.
          Log.line("RESOLVE", "eq -> reeq (mid-session filesystem check)")
          if not S.plugin_ref_sent["ReEQ"] then
            wants_plugin_ref = true
            plugin_ref_names[#plugin_ref_names+1] = "ReEQ"
          end
          -- Invalidate the cached FX list then rerun chains so pref_types.eq
          -- commits for future turns (no re-route through this branch).
          CTX._installed_fx_list = nil
          Code.ensure_preferred_from_chains()
        else
          -- Block the round: raise the modal and bail out without firing
          -- a follow-up. pending_orig_prompt / pending_snapshot stay intact
          -- so the popup's action buttons can resume the turn.
          -- Drop chat status to idle so the UI isn't stuck on "waiting";
          -- the popup itself is modal so the user can't send anything else.
          --
          -- Before bailing, scan the rest of raw_tokens for any OTHER
          -- resolve:Type tokens and stash their types in S.pending_resolves.
          -- After the popup resumes, resolve_popup_resume will append
          -- "resolve:<type>" for each queued type to its synthesized tag,
          -- so the model gets all originally-requested data in one round-trip
          -- instead of having to re-emit the dropped tokens itself.
          Log.line("RESOLVE", rtype .. " -> popup")
          S.pending_resolves = {}
          for ahead = tok_idx + 1, #raw_tokens do
            local at = raw_tokens[ahead]
            local akw, apayload = at:match("^([^:]+):?(.*)$")
            akw = akw and akw:match("^%s*(.-)%s*$"):lower() or ""
            apayload = apayload and apayload:match("^%s*(.-)%s*$"):lower() or ""
            if akw == "resolve" and apayload ~= "" and VALID_RESOLVE_TYPES[apayload] then
              S.pending_resolves[#S.pending_resolves+1] = apayload
            end
          end
          -- Stash any wants_* state already accumulated in this parse round
          -- (from tokens BEFORE this popup-triggering one). Without this, a
          -- plugin_ref:Name or preferred_plugins:type processed earlier in
          -- the same loop is silently lost when the function returns -- the
          -- locals plugin_ref_names / pref_plugin_types are discarded with
          -- the call frame. resolve_popup_resume re-emits these as buckets
          -- in its synthesized tag so the data is restored on the next pass.
          S.pending_plugin_ref_names = {}
          for _, n in ipairs(plugin_ref_names) do
            S.pending_plugin_ref_names[#S.pending_plugin_ref_names+1] = n
          end
          S.pending_pref_plugin_types = {}
          for _, t in ipairs(pref_plugin_types) do
            S.pending_pref_plugin_types[#S.pending_pref_plugin_types+1] = t
          end
          S.resolve_popup      = { type = rtype }
          S.open_resolve_popup = true
          S.status             = "idle"
          return true
        end
        end  -- if already_covered (dedupe)
      end
    elseif last_scoped and not recognised_keywords[kw] then
      -- Non-keyword token after a scoped keyword: additional name filter.
      -- e.g. "fx_list:Pro-Q, Valhalla" -> fx_list_search = {Pro-Q, Valhalla}
      local name = tok:match("^%s*(.-)%s*$")
      if last_scoped == "fx_params" then
        fx_filter_names[#fx_filter_names+1] = CTX.fx_filter_parse(name)
      elseif last_scoped == "fx_list" then
        fx_list_search[#fx_list_search+1] = name
      elseif last_scoped == "preferred_plugins" then
        if not S.pref_plugins_sent[name] then
          wants_pref_plugins = true
          pref_plugin_types[#pref_plugin_types+1] = name
        end
      elseif last_scoped == "plugin_ref" then
        if not S.plugin_ref_sent[name] then
          wants_plugin_ref = true
          plugin_ref_names[#plugin_ref_names+1] = name
        end
      elseif last_scoped == "fx_inspect" then
        fx_inspect_names[#fx_inspect_names+1] = name
      elseif last_scoped == "prompt_bundle" then
        local nlo = name:lower()
        if not S.prompt_bundle_sent[nlo] then
          wants_prompt_bundle = true
          prompt_bundle_names[#prompt_bundle_names+1] = nlo
        else
          -- Continuation-token form ("prompt_bundle:jsfx_pitch, jsfx") --
          -- same dedupe-with-hint behaviour as the explicit colon form
          -- above.
          wants_preempt_hint     = true
          S._context_reuse_hint  = S._context_reuse_hint or {}
          S._context_reuse_hint[#S._context_reuse_hint+1] =
            "prompt_bundle:" .. nlo
        end
      elseif last_scoped == "docs" then
        -- Continuation of a "docs:items, envelopes" tag. Each subsequent
        -- bare token is another section name (with the same allowlist gate).
        local canonical = _docs_section_canonical(name)
        if canonical then
          S.docs_section_sent = S.docs_section_sent or {}
          if not S.docs_section_sent[canonical] then
            wants_docs_section = true
            docs_section_names[#docs_section_names+1] = canonical
          end
        else
          bogus_docs_sections[#bogus_docs_sections+1] = name
        end
      end
    end
  end

  -- If fx_list was requested (now or earlier this turn), skip fx_params -
  -- the plugin likely isn't loaded yet, so fx_params will fail. The AI
  -- should use runtime helpers (find_param, set_param_display) instead.
  if wants_fx_params and (wants_fx_list or S.fx_list_already_sent) then
    wants_fx_params = false
    fx_filter_names = {}
  end
  -- fx_inspect supersedes fx_list (it includes the identifier in its output).
  if wants_fx_inspect and wants_fx_list then
    wants_fx_list = false
    fx_list_search = {}
  end

  if wants_docs or wants_docs_extended or wants_docs_section or wants_session or wants_fx_params or wants_plugin_ref or wants_fx_list or wants_fx_chains or wants_track_flags or wants_midi or wants_recent_reaper_changes or wants_pref_plugins or wants_theme or wants_fx_inspect or wants_preempt_hint or wants_prompt_bundle or #bogus_docs_sections > 0 then
    -- Build a fresh session snapshot if requested and not already present.
    if wants_session then
      S.session_already_sent = true
      S.pending_project  = _resolve_pending_project()
      -- Carry JSFX intent across the rebuild so the trimmed track-listing
      -- (selected only) used on the original turn stays trimmed on this
      -- retry/follow-up. Otherwise the rebuild would inject the full
      -- ~80-track listing on top of the cached prefix, busting the cache
      -- rung and re-sending tracks the JSFX writer never reads.
      S.pending_snapshot = CTX.build_snapshot(S.pending_project,
        S.pending_jsfx_intent and { minimal_tracks = true } or nil)
    end

    -- Build the fx_params block for the requested plugins.
    -- Assembly is deferred into finalize_context so that any auto-inspect
    -- triggered below (to populate the cache for enum/range annotations)
    -- completes first.
    if wants_fx_params then
      S.fx_params_already_sent = true
      S.pending_project = _resolve_pending_project()
      -- Co-pin plugin helpers when the prompt looks like a write intent
      -- ("set X to Y", "change A to B", numeric-with-unit patterns). fx_params
      -- on a pure read ("what is X set to?") doesn't need helpers; on a
      -- read-then-write request, the model gets back live values AND will
      -- need set_param_display etc. to write the new ones. Co-pinning
      -- here means the helpers ride the same follow-up build instead of
      -- requiring an extra <context_needed>prompt_bundle:plugin_helpers
      -- round-trip after the model sees fx_params.
      if Code.prompt_has_param_write_intent(S.pending_orig_prompt) then
        Net.copin_plugin_helpers(fetched_to_sticky)
      end

      -- Auto-cache: if any matched FX has no cached param data, route the
      -- first uncached plugin through fx_inspect (silent: result populates
      -- the cache but is not appended to history_content, since fx_params
      -- already covers it with live values). Skip when the user explicitly
      -- requested fx_inspect this turn -- their inspect handles caching.
      -- The hidden temp track avoids touching the user's live FX, which
      -- would visibly cycle params and glitch audio.
      --
      -- INVARIANT: this `not wants_fx_inspect` guard is load-bearing for
      -- the silent-flag contract. If the auto-inspect ran alongside an
      -- explicit fx_inspect:X, S._fx_inspect_silent_for_fx_params (a
      -- single boolean) would silence both -- the user's explicit Foo
      -- inspection would never pin to sticky and the model would get no
      -- inspect data for it. If you ever remove this guard, you must
      -- replace the boolean with a per-name silent set (S._fx_inspect_
      -- silent_names = {name=true}) and gate every silent-flag read on
      -- per-name membership; the bool no longer captures the right
      -- granularity once mixed lists are possible.
      if not wants_fx_inspect then
        local _proj = S.pending_project
        local _tc = R_CountTracks(_proj)
        -- Auto-inspect ignores any per-filter @track scope: caching one
        -- instance's params for a plugin populates the FX cache used by
        -- every other instance, and inspecting the wrong instance is fine
        -- here because we only use the result to backfill enum/range
        -- annotations, not to answer the user's track-specific question.
        local _names_only = CTX.fx_filter_names_only(fx_filter_names)
        local found_search = nil
        for _ti = 0, _tc - 1 do
          if found_search then break end
          local _tr = R_GetTrack(_proj, _ti)
          if _tr then
            local _fc = R_TrackFX_GetCount(_tr)
            for _fi = 0, _fc - 1 do
              local _, _fxnm = R_TrackFX_GetFXName(_tr, _fi, "")
              if CTX.fx_name_matches(_fxnm, _names_only) then
                local _ck, _cp = FXCache.find_plugin(_fxnm)
                if not _cp then
                  -- Use the user's filter term that matched as the search
                  -- input for fx_inspect_load (cleaner than full bracketed
                  -- VST3 identifier).
                  for _, fn in ipairs(_names_only) do
                    if _fxnm:lower():find(fn:lower(), 1, true) then
                      found_search = fn; break
                    end
                  end
                  found_search = found_search or _fxnm
                  break
                end
              end
            end
          end
        end
        if found_search then
          Log.line("FX_PARAMS",
            "uncached match -- auto-inspecting (silent): " .. found_search)
          fx_inspect_names[#fx_inspect_names+1] = found_search
          wants_fx_inspect = true
          S._fx_inspect_silent_for_fx_params = true
        end
      end

      -- Defer assembly into finalize_context (after any auto-inspect
      -- populates the cache).
      S._fx_params_pending_assemble = {
        proj   = S.pending_project,
        names  = fx_filter_names,
        fp_key = #fx_filter_names > 0
          and ("fx:" .. CTX.fx_filter_key(fx_filter_names)) or "fx_params",
      }
    end

    -- Assemble enriched history content: small inline-only buckets + USER
    -- REQUEST. Big sticky-backed buckets (plugin_ref / pref_plugins /
    -- fx_inspect / fx_params / docs_extended) write to S.sticky_context ONLY
    -- -- no inline duplication in history_content. On the follow-up build,
    -- Net.sticky_text() emits them as the pinned message, so the model sees
    -- each bucket exactly once per turn (in the well-cached pinned slot),
    -- not twice. Saves the bucket's size in input tokens per follow-up turn
    -- -- on a ~3K-token fx_inspect that's ~$0.02 of cache-write cost on
    -- Sonnet. See fetched_to_sticky below for the model-facing ack.
    -- CTX.docs/CTX.plugin_ref return nil + error on failure; show the error
    -- and proceed without the missing bucket rather than blocking the follow-up.
    local history_content = ""
    -- Collects bucket keys that were fetched-and-stickied this turn. Used to
    -- emit a brief model-facing pointer ("<context_needed> satisfied; data
    -- is in PINNED REFERENCES above") so the model doesn't re-request.
    local fetched_to_sticky = {}
    if wants_docs then
      S.docs_already_sent = true
      local ref_content, ref_err = CTX.docs()
      if ref_content then
        -- Pin docs to the persistent api_ref slot rather than inlining into
        -- this turn's history_content. Inlining was load-bearing on the
        -- bare /docs follow-up but fragile across multi-step turns: any
        -- subsequent <context_needed> in the same turn (e.g. session,
        -- fx_chains) rebuilds history_content from scratch and the docs
        -- inline disappears, forcing the model to re-emit
        -- <context_needed>docs</context_needed>. Since docs is already
        -- flagged sent, the second request loops and the turn aborts.
        -- Promoting to S.api_ref_message routes docs through the static
        -- pinned slot (same path as midi/theme refs and the docs-gate
        -- auto-retry), so it survives every follow-up build in this turn
        -- and stays pinned for the rest of the session.
        S.api_ref_message      = ref_content
        S.docs_fetched_session = true
        fetched_to_sticky[#fetched_to_sticky+1] = "docs"
      else
        Log.add_error(ref_err)
        wants_docs = false  -- clear flag so ctx_label is not updated below
      end
    end
    if wants_docs_extended then
      S.docs_extended_already_sent = true
      local ext_content, ext_err = CTX.docs_extended()
      if ext_content then
        -- Sticky only. Emitted by Net.sticky_text() on the follow-up build
        -- in the pinned slot; no duplicate inline copy in history_content.
        Net.sticky_set("docs_extended", ext_content)
        fetched_to_sticky[#fetched_to_sticky+1] = "docs_extended"
      else
        Log.add_error(ext_err)
        wants_docs_extended = false
      end
    end
    if wants_docs_section then
      -- Each section is loaded + sticky_set under its own "docs:<name>" key
      -- so it lands in sticky_growing alongside docs_extended (see
      -- Net.sticky_parts). Per-name sent-flag dedups intra-turn re-emits;
      -- the eviction exemption keeps the section alive session-wide.
      S.docs_section_sent = S.docs_section_sent or {}
      for _, name in ipairs(docs_section_names) do
        local sec_content, sec_err = CTX.docs_section(name)
        if sec_content then
          Net.sticky_set("docs:" .. name, sec_content)
          S.docs_section_sent[name] = true
          fetched_to_sticky[#fetched_to_sticky+1] = "docs:" .. name
        else
          Log.add_error(sec_err or ("Failed to load docs:" .. name))
        end
      end
    end
    if wants_recent_reaper_changes then
      local recent_content, recent_err = CTX.recent_reaper_changes()
      if recent_content then
        Net.sticky_set("recent_reaper_changes", recent_content, "context_needed")
        fetched_to_sticky[#fetched_to_sticky+1] = "recent_reaper_changes"
      else
        Log.add_error(recent_err or "Failed to load recent_reaper_changes")
        wants_recent_reaper_changes = false
      end
    end
    if #bogus_docs_sections > 0 then
      -- Recoverable nudge for unknown section names. Without this, the
      -- model sees no acknowledgment of its <context_needed>docs:<bogus>
      -- and may keep re-emitting the same invalid tag. Inject a brief
      -- ack listing the valid section names so the model can correct.
      local valid = _docs_section_list()
      for _, raw in ipairs(bogus_docs_sections) do
        Log.line("DOCS-SECTION", "unknown name '" .. tostring(raw)
          .. "'; valid: " .. valid)
        fetched_to_sticky[#fetched_to_sticky+1] =
          "(docs:" .. raw .. " is not a valid section; valid: " .. valid
          .. ". Use plain `docs` for the core reference.)"
      end
    end
    if wants_plugin_ref then
      local rp_content, rp_err = CTX.plugin_ref(plugin_ref_names)
      if rp_content then
        -- Mark each injected plugin name as sent this turn so later round-
        -- trips within the same user turn don't re-inject the same content,
        -- while still allowing plugin_ref for OTHER plugin names to fire.
        -- (Was a coarse boolean flag that blocked plugin_ref for ANY
        -- subsequent name once the first was sent -- caused resolve:eq ->
        -- ReEQ to silently drop when Pro-C 3 had been injected earlier in
        -- the same turn.) Marked only on fetch success: a disk error here
        -- used to lock the name out for the rest of the turn, so the next
        -- intra-turn retry would re-emit <context_needed>plugin_ref:Foo
        -- and get nothing back.
        for _, nm in ipairs(plugin_ref_names) do S.plugin_ref_sent[nm] = true end
        -- Sticky only -- emitted by Net.sticky_text() as the pinned message
        -- on the follow-up build.
        local rp_key = #plugin_ref_names > 0
          and ("plugin_ref:" .. tbl_concat(plugin_ref_names, "/")) or "plugin_ref"
        Net.sticky_set(rp_key, rp_content)
        fetched_to_sticky[#fetched_to_sticky+1] = rp_key
        -- Co-pin plugin bundle + docs core (same rationale as the preempt
        -- path). docs core matters here too: plugin_ref payload is rich
        -- enough that the model often skips emitting <context_needed>docs
        -- </context_needed> and the docs-gate has to retry.
        Net.copin_plugin_bundle(fetched_to_sticky)
        Net.copin_docs_core(fetched_to_sticky)
        -- Co-pin plugin helpers when the prompt has write intent. Curated
        -- plugin_ref data carries verified anchors but NOT a per-arbitrary-
        -- value mapping (Pro-C 3 Release is non-linear; the ref shows
        -- 100ms/200ms/500ms/1sec/2sec anchors but interpolating between
        -- them gives wrong values). Without helpers in the same follow-up
        -- build, the model sees a non-anchor target ("247ms"), notices it
        -- doesn't match any anchor, and either makes a second round-trip
        -- for plugin_helpers OR (observed live) skips the round-trip and
        -- linearly interpolates -- which crashes the displayed value on
        -- non-linear curves. Co-pinning here makes set_param_display the
        -- easy path for non-anchor curated targets, no extra round-trip.
        if Code.prompt_has_param_write_intent(S.pending_orig_prompt) then
          Net.copin_plugin_helpers(fetched_to_sticky)
        end
      else
        Log.add_error(rp_err)
        wants_plugin_ref = false  -- clear flag so ctx_label is not updated below
      end
    end
    -- Curated user-pref slim hints: when the resolve handler routed a
    -- preferred plugin through plugin_ref:<Name> (because pref_ident
    -- matched CURATED_IDENT), pin a small pref:<tkey> entry pointing at
    -- the curated bundle just emitted above. Without this, the model sees
    -- plugin_ref:Pro-G in sticky but can't tell whether Pro-G is the
    -- user's saved preference or curated default content -- weak models
    -- defensively re-emit <context_needed>resolve:gate</context_needed>.
    -- Format mirrors the preempt path's hint byte-for-byte so byte-prefix
    -- caching stays stable when the same hint comes from either route.
    if wants_plugin_ref and #curated_pref_hints > 0 then
      CTX.populate_installed_fx()
      for _, h in ipairs(curated_pref_hints) do
        local pp_key = "pref:" .. h.tkey
        if not S.sticky_context[pp_key] then
          local exact_ident = nil
          if Code.resolve_chain_entry and CTX._installed_fx_list then
            exact_ident = Code.resolve_chain_entry(h.ident, CTX._installed_fx_list)
          end
          local hint = "PREFERRED PLUGINS:\n"
            .. "  " .. h.tkey .. " = " .. (exact_ident or h.ident or h.curated) .. "\n"
            .. "(User's saved preference; full parameter reference above "
            .. "in plugin_ref:" .. h.curated .. ". Use this plugin directly "
            .. "and do NOT emit <context_needed>resolve:" .. h.tkey
            .. "</context_needed>.)"
          Net.sticky_set(pp_key, hint)
          fetched_to_sticky[#fetched_to_sticky+1] = pp_key
        end
      end
    end
    if wants_prompt_bundle then
      -- Per-name dedup like plugin_ref. Fetched content goes into
      -- sticky_context so it stays pinned for the rest of the conversation
      -- (subsequent turns see the bundle without re-fetching). Any bundles
      -- that fail to load are dropped with a user-visible error; successful
      -- ones still pin so the turn can proceed with partial coverage.
      local ok = 0
      for _, nm in ipairs(prompt_bundle_names) do
        local pb_content, pb_err = CTX.prompt_bundle(nm)
        if pb_content then
          S.prompt_bundle_sent[nm] = true
          local pb_key = "prompt_bundle:" .. nm
          -- Tag as "context_needed": the model asked for this bundle
          -- mid-flow, so it's a reactive pin. Affects plugin_helpers
          -- routing in Net.sticky_parts -- helpers pulled this way
          -- stays in the growing rung instead of invalidating the
          -- larger stable bundle on a turn we didn't plan to.
          Net.sticky_set(pb_key, pb_content, "context_needed")
          fetched_to_sticky[#fetched_to_sticky+1] = pb_key
          ok = ok + 1
        else
          Log.add_error(pb_err)
        end
      end
      if ok == 0 then wants_prompt_bundle = false end
    end
    if wants_fx_list then
      S.fx_list_already_sent = true
      local fl_content, fl_result = CTX.installed_fx(fx_list_search)
      if fl_content then
        history_content = history_content .. fl_content .. "\n"
          .. "Use the identifiers above with TrackFX_AddByName. Set parameters using find_param and set_param_display at runtime. Do NOT request fx_params.\n\n"
        -- Zero-match notice is embedded in fl_content so the assistant
        -- sees it and can self-correct. No user-facing error needed.
      else
        Log.add_error(fl_result)
        wants_fx_list = false
      end
    end
    if wants_fx_chains then
      S.fx_chains_already_sent = true
      local proj = _resolve_pending_project()
      history_content = history_content .. CTX.fx(proj) .. "\n\n"
    end
    if wants_track_flags then
      S.track_flags_already_sent = true
      local proj = _resolve_pending_project()
      history_content = history_content .. CTX.track_flags(proj) .. "\n\n"
    end
    -- MIDI ref is loaded into the persistent slot (S.midi_ref_message)
    -- rather than injected into history_content. The follow-up call's
    -- build_body_* will pick it up and prepend it as a synthetic
    -- user/assistant pair, just like the api_ref. From this turn forward
    -- it lives in the static cache prefix slot.
    if wants_midi then
      S.midi_already_sent = true
      local mref_content, mref_err = CTX.midi()
      if mref_content then
        S.midi_ref_message = mref_content
      else
        Log.add_error(mref_err)
        wants_midi = false  -- clear flag so ctx_label is not updated below
      end
    end
    -- Theme color reference: loaded into the persistent slot
    -- (S.theme_ref_message) rather than into history_content, matching the
    -- MIDI pattern. build_body_* will prepend it on every subsequent call.
    if wants_theme then
      S.theme_already_sent = true
      local th_content, th_err = CTX.theme()
      if th_content then
        S.theme_ref_message = th_content
          .. "\n\n(Theme reference is loaded above. Do NOT request "
          .. "<context_needed>theme</context_needed> or "
          .. "<context_needed>session</context_needed> -- you have "
          .. "everything needed. Proceed directly with the color change code.)"
      else
        Log.add_error(th_err)
        wants_theme = false
      end
    end
    -- Preferred plugins: load only the requested type sections.
    if wants_pref_plugins then
      local pp_content, pp_err = CTX.preferred_plugins(pref_plugin_types)
      if pp_content then
        -- Mark each injected type as sent this turn (per-type dedup, mirrors
        -- the plugin_ref_sent pattern). Was a coarse boolean that blocked
        -- preferred_plugins for ANY type once one had been sent in the turn
        -- -- caused the resolve:compressor follow-up to silently no-op
        -- after preferred_plugins:eq had fired in the same turn. Marked
        -- only on fetch success so an intra-turn retry can re-fetch a type
        -- that failed the first time.
        for _, t in ipairs(pref_plugin_types) do S.pref_plugins_sent[t] = true end
        -- Sticky only -- pinned-slot emission on follow-up build.
        local pp_key = #pref_plugin_types > 0
          and ("pref:" .. tbl_concat(pref_plugin_types, "/")) or "pref_plugins"
        Net.sticky_set(pp_key, pp_content)
        fetched_to_sticky[#fetched_to_sticky+1] = pp_key
        -- Co-pin plugin bundle + docs core (every pref-plugin pin drives a
        -- plugin task that needs both the workflow guide and reaper.*
        -- signatures).
        Net.copin_plugin_bundle(fetched_to_sticky)
        Net.copin_docs_core(fetched_to_sticky)
        -- Co-pin plugin helpers when the prompt looks like a write intent.
        -- preferred_plugins for non-curated types returns live-scan param
        -- data without verified anchors; if the user asked for a specific
        -- value that doesn't match a cached point, the model needs
        -- set_param_display to probe at runtime. Pure "what plugin is my
        -- preferred X?" or generic "add a compressor" requests skip this.
        if Code.prompt_has_param_write_intent(S.pending_orig_prompt) then
          Net.copin_plugin_helpers(fetched_to_sticky)
        end
      else
        Log.add_error(pp_err)
        wants_pref_plugins = false
      end
    end
    -- (fx_params content is assembled in finalize_context, after any
    -- auto-inspect populates the cache.)

    -- fx_inspect: temporarily load a plugin to discover its parameters.
    -- Phase 1 runs here (add temp track + plugin); phase 2 (read params +
    -- cleanup) runs inside finalize_context after a one-frame defer.
    if wants_fx_inspect then
      S.fx_inspect_already_sent = true
      -- Multi-plugin fx_inspect is NOT supported. fx_inspect_load picks the
      -- single best_id from installed_fx's combined output, silently
      -- dropping the rest. That bug let the model use one plugin's data
      -- (e.g. Pro-C 3 Side Chain EQ "Band 1 Slope") for a different plugin
      -- (e.g. Pro-Q 4's main "Band 1 Slope") with disastrously wrong norms.
      -- Truncate to the first name, log the drop, and inject a warning into
      -- history_content so the model re-requests the missing plugins.
      if #fx_inspect_names > 1 then
        local dropped = {}
        for i = 2, #fx_inspect_names do
          dropped[#dropped+1] = fx_inspect_names[i]
        end
        Log.line("FX_INSPECT", str_format(
          "multi-plugin request: keeping '%s'; dropped %s. "
          .. "Re-request hint will be injected into the follow-up turn.",
          fx_inspect_names[1], tbl_concat(dropped, ", ")))
        while #fx_inspect_names > 1 do
          table.remove(fx_inspect_names)
        end
        S._fx_inspect_dropped = dropped  -- one-shot, consumed below
      end
      -- fx_inspect IS the "ADD + CONFIGURE with values" signal -- the model
      -- requested it specifically because the user asked to set specific
      -- param values that need runtime probing. Always co-pin plugin_helpers
      -- here so the follow-up build contains both fx_inspect data AND helper
      -- definitions in one round-trip (no second context_needed for helpers
      -- after the model sees the param map).
      Net.copin_plugin_helpers(fetched_to_sticky)
      local tmp_tr, fx_idx, identifier, err, cached = CTX.fx_inspect_load(fx_inspect_names)
      if err then
        if S._fx_inspect_silent_for_fx_params then
          -- Silent auto-cache trigger from fx_params: don't surface the
          -- inspect error to the model. fx_params still emits live values
          -- (just without enum/range annotations).
          Log.line("FX_PARAMS",
            "silent auto-inspect failed (continuing): " .. err)
        else
          history_content = history_content .. "FX INSPECT ERROR: " .. err .. "\n\n"
        end
      elseif cached then
        -- Cache hit: format cached data directly, no temp track needed.
        if S._fx_cache_events then
          local t = S._fx_cache_events
          t.hit = t.hit or {}
          t.hit[#t.hit+1] = identifier
        end
        if not S._fx_inspect_silent_for_fx_params then
          local inspect_data = CTX.format_fx_params(
            identifier, cached.params, cached.max_group, fx_inspect_names, true)
          -- Sticky only -- pinned-slot emission on follow-up build.
          local fi_key = "fx_inspect:" .. tbl_concat(fx_inspect_names, "/")
          Net.sticky_set(fi_key, inspect_data)
          fetched_to_sticky[#fetched_to_sticky+1] = fi_key
        end
      else
        S._fx_inspect_tmp = {
          tr = tmp_tr, fx = fx_idx,
          id = identifier, names = fx_inspect_names,
        }
      end
    end

    -- Finalize: assemble remaining context, update labels, fire API.
    -- Wrapped in a function so it can be deferred one frame when fx_inspect
    -- needs REAPER to finish initialising the plugin before reading params.
    local finalize_context
    finalize_context = function()
      -- fx_inspect phase 2: read params from temp plugin, remove temp track.
      -- If the shallow scan detects readback lag (e.g. Soundtoys VST3),
      -- kick off a coroutine-paced deep scan and defer the rest of
      -- finalize_context until it completes (or is cancelled).
      if S._fx_inspect_tmp then
        local fi = S._fx_inspect_tmp
        -- ValidatePtr2: try_inspect_read already checks, but finalize_context
        -- can also be entered directly (np>0 path) with no validation gap, or
        -- after a deep scan where on_complete may have already deleted fi.tr.
        -- A stale handle here would crash scan_fx_params on the first
        -- TrackFX_* call.
        if not reaper.ValidatePtr2(0, fi.tr, "MediaTrack*") then
          reaper.PreventUIRefresh(-1)
          reaper.Undo_EndBlock("ReaAssist: fx_inspect (invalid track)", 0)
          S._fx_inspect_tmp = nil
          if not S._fx_inspect_silent_for_fx_params then
            history_content = history_content
              .. "FX INSPECT ERROR: temporary track was invalidated before params could be read.\n\n"
          end
        else
        -- Wrap the shallow scan in xpcall so a thrown error (stale FX
        -- handle, REAPER returning nil from a probe, etc.) does not skip
        -- the cleanup at the end of this block, which would leave an
        -- orphaned hidden temp track + a stuck PreventUIRefresh(-1)
        -- imbalance + an unclosed Undo block.
        local _scan_ok, params_list, max_group, total_count, needs_deep =
          xpcall(function()
            return CTX.scan_fx_params(fi.tr, fi.fx)
          end, debug.traceback)
        if not _scan_ok then
          -- params_list holds the error+traceback string in the failure case.
          local err_msg = tostring(params_list or "scan threw")
          Log.line("FX_INSPECT", "shallow scan threw: " .. err_msg)
          if reaper.ValidatePtr2(0, fi.tr, "MediaTrack*") then
            reaper.DeleteTrack(fi.tr)
          end
          reaper.PreventUIRefresh(-1)
          reaper.Undo_EndBlock("ReaAssist: fx_inspect (scan error)", 0)
          S._fx_inspect_tmp = nil
          if not S._fx_inspect_silent_for_fx_params then
            history_content = history_content
              .. "FX INSPECT ERROR: shallow scan failed unexpectedly.\n\n"
          end
          -- Fall through to fx_params assemble + rest of finalize. Use a
          -- dummy nil set so subsequent statements that read these locals
          -- don't reference the error string.
          params_list, max_group, total_count, needs_deep = nil, nil, nil, nil
          goto fx_inspect_done
        end

        if needs_deep and not S._deep_scan_started then
          S._deep_scan_started = true
          S._deep_scan_label   = fi.id
          Log.line("DEEP_SCAN", "chat: auto-triggering deep scan for " .. fi.id)
          local _started_ok = CTX.start_deep_scan({
            tr           = fi.tr,
            fx_idx       = fi.fx,
            identifier   = fi.id,
            search_names = fi.names,
            origin       = "chat",
            on_complete  = function(dparams, dmax, dcount)
              FXCache.put_plugin(fi.id, dparams, dcount, dmax, false)
              if S._fx_cache_events then
                local t = S._fx_cache_events
                t.cached = t.cached or {}
                t.cached[#t.cached+1] = fi.id
              end
              if not S._fx_inspect_silent_for_fx_params then
                local inspect_data = CTX.format_fx_params(
                  fi.id, dparams, dmax, fi.names, true)
                -- Sticky only -- pinned-slot emission on follow-up build.
                local fi_key = "fx_inspect:" .. tbl_concat(fi.names, "/")
                Net.sticky_set(fi_key, inspect_data)
                fetched_to_sticky[#fetched_to_sticky+1] = fi_key
              end
              if reaper.ValidatePtr2(0, fi.tr, "MediaTrack*") then
                reaper.DeleteTrack(fi.tr)
              end
              -- PreventUIRefresh(-1) already done by scan_fx_params_deep_body;
              -- see comment there about avoiding double-release crashes.
              -- flags=0: discard the whole temp-track block rather than
              -- relying on Undo_DoUndo2 to walk it back (see preferred
              -- plugins scan for the rationale).
              reaper.Undo_EndBlock("ReaAssist: fx_inspect deep", 0)
              S._fx_inspect_tmp   = nil
              S._deep_scan_started = false
              S._deep_scan_label   = nil
              finalize_context()
            end,
            on_cancel    = function(reason)
              if reaper.ValidatePtr2(0, fi.tr, "MediaTrack*") then
                reaper.DeleteTrack(fi.tr)
              end
              -- PreventUIRefresh(-1) already done by scan_fx_params_deep_body.
              reaper.Undo_EndBlock("ReaAssist: fx_inspect (cancelled)", 0)
              S._fx_inspect_tmp   = nil
              S._deep_scan_started = false
              S._deep_scan_label   = nil
              if reason == "cancelled" then
                -- User cancelled: abort the whole turn. The chat Cancel
                -- button already resets status/display; just bail.
                -- Clear leftover deferred-assemble + silent flag so they
                -- don't poison the next turn.
                S._fx_params_pending_assemble  = nil
                S._fx_inspect_silent_for_fx_params = nil
                return
              end
              if S._fx_inspect_silent_for_fx_params then
                Log.line("FX_PARAMS",
                  "silent auto-inspect deep scan failed (continuing): "
                  .. tostring(reason))
              else
                history_content = history_content
                  .. "FX INSPECT ERROR: Deep scan failed ("
                  .. tostring(reason) .. ").\n\n"
              end
              finalize_context()
            end,
          })
          if not _started_ok then
            -- start_deep_scan rejected the request (already active, missing
            -- opts, or _estimate_deep_probes threw). Neither on_complete nor
            -- on_cancel will fire, so unwind the resources fx_inspect_load
            -- set up: hidden temp track, PreventUIRefresh(+1), open Undo
            -- block. Without this the UI stops repainting and a stale undo
            -- block pairs with the next unrelated Undo_EndBlock in the
            -- session.
            Log.line("DEEP_SCAN", "chat: start_deep_scan returned false for "
              .. fi.id .. "; unwinding fx_inspect resources")
            if reaper.ValidatePtr2(0, fi.tr, "MediaTrack*") then
              reaper.DeleteTrack(fi.tr)
            end
            reaper.PreventUIRefresh(-1)
            reaper.Undo_EndBlock("ReaAssist: fx_inspect (start_deep_scan failed)", 0)
            S._fx_inspect_tmp    = nil
            S._deep_scan_started = false
            S._deep_scan_label   = nil
            if not S._fx_inspect_silent_for_fx_params then
              history_content = history_content
                .. "FX INSPECT ERROR: deep scan could not start (see debug log).\n\n"
            end
            -- Bypass shallow-success path; continue with the rest of
            -- finalize_context (fx_params assemble, sticky build, etc.).
            params_list, max_group, total_count, needs_deep = nil, nil, nil, nil
            goto fx_inspect_done
          end
          return  -- coroutine runs; on_complete will re-call finalize_context
        end

        -- Shallow scan succeeded: cache, format, append inline.
        FXCache.put_plugin(fi.id, params_list, total_count, max_group, false)
        if S._fx_cache_events then
          local t = S._fx_cache_events
          t.cached = t.cached or {}
          t.cached[#t.cached+1] = fi.id
        end
        reaper.DeleteTrack(fi.tr)
        reaper.PreventUIRefresh(-1)
        reaper.Undo_EndBlock("ReaAssist: fx_inspect", 0)
        if not S._fx_inspect_silent_for_fx_params then
          local inspect_data = CTX.format_fx_params(
            fi.id, params_list, max_group, fi.names, true)
          -- Sticky only -- pinned-slot emission on follow-up build.
          local fi_key = "fx_inspect:" .. tbl_concat(fi.names, "/")
          Net.sticky_set(fi_key, inspect_data)
          fetched_to_sticky[#fetched_to_sticky+1] = fi_key
        end
        S._fx_inspect_tmp = nil
        ::fx_inspect_done::
        end  -- end of ValidatePtr2 else
      end

      -- Assemble fx_params content now (any auto-inspect above has populated
      -- the cache, so enum/range annotations are picked up by CTX.fx_params).
      if S._fx_params_pending_assemble then
        local a = S._fx_params_pending_assemble
        local fx_str = CTX.fx_params(a.proj, a.names)
        -- Sticky only -- pinned-slot emission on follow-up build.
        Net.sticky_set(a.fp_key, fx_str)
        fetched_to_sticky[#fetched_to_sticky+1] = a.fp_key
        S._fx_params_pending_assemble = nil
      end

      -- Sticky context (plugin_ref, preferred_plugins, fx_params, fx_inspect)
      -- is emitted by Net.build_body_* as a pinned user/assistant pair after
      -- the api_ref pin -- no longer re-injected into per-turn history content.
      -- This keeps the moving cache breakpoint from having to re-write sticky
      -- bytes on every turn. See Net.sticky_text().
      -- Loop-recovery hint: prepended when the previous response from the
      -- model was a duplicate <context_needed> for already-provided data.
      -- See LOOP DETECTION in process_response_buckets. Carries the actual
      -- re-requested tags so the message names them rather than relying on
      -- generic "plugin parameter / preferred plugins" copy that doesn't
      -- match docs:* / midi / api_ref shapes.
      local reuse_hint_fired = false
      if S._context_reuse_hint and #S._context_reuse_hint > 0 then
        local tags_str = tbl_concat(S._context_reuse_hint, ", ")
        history_content = history_content
          .. "(NOTE: The reference/context data you requested ("
          .. tags_str
          .. ") is already present in PINNED REFERENCES above. "
          .. "USE IT NOW to generate the code. Do NOT emit another "
          .. "<context_needed> tag for these tags.)\n\n"
        S._context_reuse_hint = nil  -- one-shot
        reuse_hint_fired = true
      end
      if S._mixed_output_hint then
        history_content = history_content
          .. "(NOTE: Your previous reply emitted prose alongside the "
          .. "<context_needed> tag. The fetch was honored anyway, but the "
          .. "prose was hidden from the user. Per the system prompt, when "
          .. "you need data your entire reply must be the bare tag -- no "
          .. "prose before or after. On future turns, emit ONLY the tag.)\n\n"
        S._mixed_output_hint = nil  -- one-shot
      end
      if S._fx_inspect_dropped then
        history_content = history_content
          .. "(NOTE: fx_inspect can only load ONE plugin per call. Loaded data "
          .. "for the first name above; NOT loaded: "
          .. tbl_concat(S._fx_inspect_dropped, ", ")
          .. ". To get parameters for the missing plugin(s), emit a separate "
          .. "<context_needed>fx_inspect:Name</context_needed> for each one in "
          .. "your follow-up turn -- or <context_needed>plugin_ref:Name"
          .. "</context_needed> if it's a curated plugin (Pro-Q 4, Pro-C 3, "
          .. "Pro-G, Pro-L 2, ReaEQ, ReaComp, etc.). DO NOT infer the missing "
          .. "plugin's parameters, indices, or enum mappings from the loaded "
          .. "plugin's data; they are unrelated.)\n\n"
        S._fx_inspect_dropped = nil  -- one-shot
      end
      -- Pointer to the pinned sticky slot. Each fetched bucket (plugin_ref /
      -- pref_plugins / fx_inspect / fx_params / docs_extended) lives ONLY
      -- in Net.sticky_text() now -- no inline duplication in this message.
      -- The pointer tells the model its <context_needed> was satisfied and
      -- to read the data above so it doesn't re-emit another context_needed.
      if #fetched_to_sticky > 0 then
        Log.line("DISPATCH",
          "fetched_to_sticky=[" .. tbl_concat(fetched_to_sticky, ", ") .. "]")
        -- Suppress when the loop-recovery hint above already fired -- it
        -- carries stronger imperative wording naming the same tags.
        if not reuse_hint_fired then
          history_content = history_content
            .. "(The data for <context_needed> tag(s) "
            .. tbl_concat(fetched_to_sticky, ", ")
            .. " is now present in PINNED REFERENCES above. USE IT NOW to "
            .. "generate the code. Do NOT emit another <context_needed> tag "
            .. "for these tags.)\n\n"
        end
      end
      history_content = history_content .. "USER REQUEST:\n" .. S.pending_orig_prompt

      -- Update the Show Details context label to reflect all injected buckets.
      if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
        local dmsg = S.display_messages[S.pending_display_idx]
        -- Build updated label: start from existing, append newly injected buckets.
        local parts = {}
        local existing = dmsg.ctx_label or ""
        if existing ~= "" then parts[#parts+1] = existing end
        if wants_session and not existing:find("snapshot") then
          parts[#parts+1] = "snapshot"
        end
        -- "docs" and "api_ref" alias the same content; skip if either is
        -- already in the chip label so we don't render both.
        if wants_docs and not existing:find("api_ref", 1, true)
                      and not existing:find("docs",    1, true) then
          parts[#parts+1] = "docs"
        end
        if wants_docs_extended then parts[#parts+1] = "docs_extended" end
        if wants_plugin_ref then
          parts[#parts+1] = #plugin_ref_names > 0
            and ("plugin_ref:" .. tbl_concat(plugin_ref_names, "/")) or "plugin_ref"
        end
        if wants_fx_list then
          parts[#parts+1] = #fx_list_search > 0
            and ("fx_list:" .. tbl_concat(fx_list_search, "/")) or "fx_list"
        end
        if wants_fx_chains   then parts[#parts+1] = "fx_chains" end
        if wants_track_flags then parts[#parts+1] = "track_flags" end
        if wants_fx_params then
          parts[#parts+1] = #fx_filter_names > 0
            and ("fx:" .. CTX.fx_filter_key(fx_filter_names)) or "fx_params"
        end
        if wants_midi  then parts[#parts+1] = "midi" end
        if wants_theme then parts[#parts+1] = "theme" end
        if wants_recent_reaper_changes then
          parts[#parts+1] = "recent_reaper_changes"
        end
        if wants_pref_plugins then
          parts[#parts+1] = #pref_plugin_types > 0
            and ("pref:" .. tbl_concat(pref_plugin_types, "/")) or "pref_plugins"
        end
        if wants_fx_inspect and not S._fx_inspect_silent_for_fx_params then
          parts[#parts+1] = #fx_inspect_names > 0
            and ("fx_inspect:" .. tbl_concat(fx_inspect_names, "/")) or "fx_inspect"
        end
        -- Append sticky context labels not already covered by fresh buckets.
        local existing_joined = tbl_concat(parts, " + ")
        local sticky_keys = {}
        for skey in pairs(S.sticky_context) do sticky_keys[#sticky_keys+1] = skey end
        table.sort(sticky_keys)
        for _, skey in ipairs(sticky_keys) do
          if not existing_joined:find(skey, 1, true) then
            parts[#parts+1] = skey
          end
        end
        dmsg.ctx_label = #parts > 0 and tbl_concat(parts, " + ") or ""
      end

      -- Clear the silent-inspect flag now that all gating consumers
      -- (history append, sticky context, ctx_label) have read it.
      S._fx_inspect_silent_for_fx_params = nil

      -- Replace the last user history entry with the enriched content
      -- (snapshot is passed to Net.build_body(), never stored in history).
      if #S.history > 0 and S.history[#S.history].role == "user" then
        S.history[#S.history] = nil
      end
      S.history[#S.history+1] = {
        role    = "user",
        content = history_content,
      }
      -- Refresh the snapshot right before firing. finalize_context can run
      -- many seconds after the original send -- if fx_inspect triggered a
      -- deep scan, the user's cursor/selection/play state could have moved
      -- on. The snapshot rebuild is cheap next to the curl round trip, so
      -- always re-capture (when snapshots are enabled) rather than sending
      -- stale "at the cursor" / "to the selected item" context.
      if prefs.include_snapshot then
        S.pending_project  = _resolve_pending_project()
        -- See JSFX-intent comment on the analogous retry sites above:
        -- carry pending_jsfx_intent across snapshot rebuilds so the trim
        -- survives every retry path, not just the JSFX-validator's.
        S.pending_snapshot = CTX.build_snapshot(S.pending_project,
          S.pending_jsfx_intent and { minimal_tracks = true } or nil)
      end
      S.status = "waiting"
      Code.safe_write(tmp.out, "")
      local ok, reason = Net.fire_curl(Net.build_body(Net.trimmed_history(),
        S.pending_snapshot, S.pending_attachments))
      if not ok and reason ~= "call_cap_exceeded" then
        Log.add_error("Tried to load additional project info but the "
          .. "follow-up request didn't go through. Please try again.")
      end
      S.scroll_to_bottom = true
    end  -- finalize_context

    -- If fx_inspect loaded a plugin, poll until it's initialised (params
    -- readable) before finalizing. Heavy plugins (large sample libs, complex
    -- synths) may need more than one frame. Max ~1 second (30 retries).
    if S._fx_inspect_tmp then
      local inspect_retries = 0
      local function try_inspect_read()
        local fi = S._fx_inspect_tmp
        -- Guard: S._fx_inspect_tmp could have been cleared between defer
        -- cycles by another path (dev_signal cancel, project switch handler,
        -- etc.). Without this, the timeout branch's fi.tr / fi.names derefs
        -- below would crash 30 frames later.
        if not fi then
          S._fx_inspect_tmp = nil
          return
        end
        -- ValidatePtr2 before touching fi.tr: across up to 30 defer cycles
        -- (~1s) the user could switch projects or delete the track, leaving
        -- a dangling pointer that would crash TrackFX_GetNumParams.
        if not reaper.ValidatePtr2(0, fi.tr, "MediaTrack*") then
          reaper.PreventUIRefresh(-1)
          reaper.Undo_EndBlock("ReaAssist: fx_inspect (invalid track)", 0)
          S._fx_inspect_tmp = nil
          -- Honor the silent-inspect contract: when this inspect was an
          -- auto-trigger from fx_params (not user-requested), do not leak
          -- "FX INSPECT ERROR" prose into history_content (which becomes
          -- the model prompt). Mirrors the timeout branch below.
          if not S._fx_inspect_silent_for_fx_params then
            history_content = history_content
              .. "FX INSPECT ERROR: temporary track was invalidated before params could be read.\n\n"
          end
          finalize_context()
          return
        end
        local np = R_TrackFX_GetNumParams(fi.tr, fi.fx) or 0
        if np > 0 then
          finalize_context()
        elseif inspect_retries < 30 then
          inspect_retries = inspect_retries + 1
          reaper.defer(try_inspect_read)
        else
          -- Timed out - clean up and report.
          if reaper.ValidatePtr2(0, fi.tr, "MediaTrack*") then
            reaper.DeleteTrack(fi.tr)
          end
          reaper.PreventUIRefresh(-1)
          reaper.Undo_EndBlock("ReaAssist: fx_inspect (timeout)", 0)
          S._fx_inspect_tmp = nil
          if S._fx_inspect_silent_for_fx_params then
            Log.line("FX_PARAMS",
              "silent auto-inspect timed out (continuing): "
              .. tbl_concat(fi.names, ", "))
          else
            history_content = history_content
              .. "FX INSPECT ERROR: Plugin did not initialise in time ("
              .. tbl_concat(fi.names, ", ") .. "). "
              .. "Try adding the plugin manually first, then use fx_params.\n\n"
          end
          finalize_context()
        end
      end
      reaper.defer(try_inspect_read)
    else
      finalize_context()
    end
    return true
  end

  -- LOOP DETECTION: tag was non-empty (#raw_tokens > 0) but produced no
  -- wants_* -- meaning every requested bucket was either gated by a *_sent
  -- flag or is an unknown name. The model is re-asking for context it
  -- already has (or inventing bucket names). One recovery attempt if a
  -- sticky sent-set was the blocker (clear it + retry with a "use it" hint);
  -- otherwise surface a clean error with recovery buttons instead of
  -- dumping the raw tag as the assistant reply.
  if #raw_tokens > 0 then
    -- "had_sticky" -> the previous turn or earlier in this turn injected
    -- some piece of pinned data, so the model's re-request is plausibly
    -- about that already-pinned data and worth one retry with a hint.
    -- Detection has to cover both the per-name dedup tables and the
    -- one-shot booleans -- the model could be re-asking for a single
    -- bucket (docs, session, midi, theme, fx_*) just as easily as a
    -- named one (plugin_ref:X, prompt_bundle:X, preferred_plugins:X).
    local had_sticky =
         next(S.plugin_ref_sent)
      or next(S.pref_plugins_sent)
      or next(S.prompt_bundle_sent)
      or S.docs_already_sent
      or S.docs_extended_already_sent
      or next(S.docs_section_sent)
      or S.session_already_sent
      or S.fx_params_already_sent
      or S.fx_list_already_sent
      or S.fx_chains_already_sent
      or S.track_flags_already_sent
      or S.midi_already_sent
      or S.theme_already_sent
      or S.fx_inspect_already_sent
    if had_sticky and (S.context_loop_retries or 0) < 1 then
      S.context_loop_retries = (S.context_loop_retries or 0) + 1
      Log.line("CONTEXT_LOOP",
        "model re-requested already-provided context; clearing all sent flags + adding hint")
      -- Clear every gating flag that the per-token elseif chain checks,
      -- so whatever bucket the model re-emitted falls through ungated on
      -- the recursive pass and triggers a fresh fetch + follow-up call
      -- with the "use it" hint. Earlier versions only cleared the per-
      -- name dedup tables (plugin_ref_sent, pref_plugins_sent, eventually
      -- prompt_bundle_sent), which fixed plugin-shaped loops but missed
      -- the simpler one-shot booleans (docs / session / midi / theme /
      -- fx_*). Sonnet 4.6 has been observed re-emitting any of these
      -- under the right conditions, so we now clear the full set.
      S.plugin_ref_sent              = {}
      S.pref_plugins_sent            = {}
      S.prompt_bundle_sent           = {}
      S.docs_already_sent            = false
      S.docs_extended_already_sent   = false
      S.docs_section_sent            = {}
      S.session_already_sent         = false
      S.fx_params_already_sent       = false
      S.fx_list_already_sent         = false
      S.fx_chains_already_sent       = false
      S.track_flags_already_sent     = false
      S.midi_already_sent            = false
      S.theme_already_sent           = false
      S.fx_inspect_already_sent      = false
      S._context_reuse_hint = S._context_reuse_hint or {}
      for _, t in ipairs(raw_tokens) do
        S._context_reuse_hint[#S._context_reuse_hint+1] = t
      end
      return Net.process_response_buckets(text)
    else
      Log.line("CONTEXT_LOOP",
        "unresolvable context loop; aborting turn with user error")
      Log.add_error("The model re-requested context that was already provided. "
        .. "Try rephrasing your request, or switch to a different model.")
      S.status = "idle"
      return true  -- treat as handled so caller doesn't display the raw tag
    end
  end
  return false
end

-- =============================================================================
-- Net.resolve_popup_resume: resume a turn blocked by the resolve-type popup
-- =============================================================================
-- Called by the popup's action buttons once the user picks a plugin. Synthesizes
-- a <context_needed>plugin_ref:<identifier>> tag and re-enters the dispatcher so
-- the follow-up API call fires with the correct plugin reference injected.
--
-- The caller is responsible for persisting the user's choice to preferred_types
-- if they want the next turn to resolve without a popup (see popup "Use this"
-- button handler).
-- Returns true iff `name` matches a section in the curated plugin_ref cache
-- (after alias resolution). Used by resolve_popup_resume to decide whether
-- to inject the picked plugin via plugin_ref:<identifier> (curated -- has
-- recipes/golden-ratios) or preferred_plugins:<type> (third-party -- live
-- params from the just-saved preference + FX cache scan).
local function _is_in_plugin_ref(name)
  if not name or name == "" then return false end
  -- Trigger lazy-load of the cache if not yet built. CTX.plugin_ref builds
  -- it on first call; the probe arg returns a no-match string but populates
  -- CTX._plugin_ref_cache as a side effect.
  if not CTX._plugin_ref_cache then
    local ok_probe, probe_err = pcall(CTX.plugin_ref, {"__probe__"})
    if not ok_probe then
      Log.line("PLUGIN_REF",
        "plugin_ref probe failed: " .. tostring(probe_err))
    end
  end
  if not CTX._plugin_ref_cache then return false end
  local k = name:lower():match("^%s*(.-)%s*$") or ""
  k = PLUGIN_REF_ALIASES[k] or k
  return CTX._plugin_ref_cache[k] ~= nil
end

function Net.resolve_popup_resume(identifier)
  -- Capture popup type, pending resolves, and any wants_* state stashed by a
  -- popup-bailed parse loop BEFORE clearing state. The popup may already
  -- have been cleared by the typed-pick handler (which clears it early so
  -- the chat status doesn't keep saying "Waiting for selection..." through
  -- a slow scan); in that case we read the type from S.resolve_pending_type
  -- which the typed-pick handler stashed for exactly this purpose.
  local resolve_type    = (S.resolve_popup and S.resolve_popup.type)
                       or S.resolve_pending_type
                       or nil
  S.resolve_pending_type = nil
  local pending         = S.pending_resolves or {}
  local pending_pr      = S.pending_plugin_ref_names or {}
  local pending_pp      = S.pending_pref_plugin_types or {}
  S.pending_resolves          = {}
  S.pending_plugin_ref_names  = {}
  S.pending_pref_plugin_types = {}

  -- Clear popup state. pending_orig_prompt / pending_snapshot / pending_display_idx
  -- stay intact -- the dispatcher re-enters finalize_context which uses them.
  S.resolve_popup        = nil
  S.resolve_popup_text   = ""
  S.resolve_popup_error  = nil
  S.resolve_popup_matches     = {}
  S.resolve_popup_sel         = 0
  S.resolve_popup_last_filter = nil
  S.resolve_popup_refocus     = false
  S.status               = "waiting"
  -- Clear the per-name sent set so the synthesized plugin_ref actually injects
  -- (a previous turn in this session may have sent plugin_ref for other names).
  S.plugin_ref_sent = {}

  -- Build the synthesized tag. For the picked plugin:
  --   * Curated (in plugin_ref.md, e.g. ReaEQ/ReaComp/ReEQ) -> plugin_ref:<id>
  --     gives the model recipes + verified normalized values.
  --   * Third-party (e.g. VST3: Pro-C 3) -> preferred_plugins:<type>
  --     surfaces live params from the just-completed FX cache scan. Falling
  --     back to plugin_ref here would inject "no reference data for: <id>" --
  --     a useless placeholder that wastes a round-trip.
  -- Then append any resolve:<type> tokens that were dropped when this popup
  -- bailed the parser loop, so the model gets all originally-requested data
  -- without having to re-emit them itself.
  local synth = {}
  -- 1) Any wants_* state that was lost when an earlier popup bailed the loop.
  -- Re-emit as explicit buckets so the data the user already picked is
  -- restored without another popup.
  for _, n in ipairs(pending_pr) do
    synth[#synth+1] = "plugin_ref:" .. n
  end
  for _, t in ipairs(pending_pp) do
    synth[#synth+1] = "preferred_plugins:" .. t
  end
  -- 2) The bucket for the plugin the user just picked in THIS popup.
  if resolve_type and not _is_in_plugin_ref(identifier) then
    synth[#synth+1] = "preferred_plugins:" .. resolve_type
  else
    synth[#synth+1] = "plugin_ref:" .. identifier
  end
  -- 3) Any resolve:Type tokens that were dropped when this popup bailed the
  -- loop. They go LAST so any popup they trigger re-stashes (1) and (2)'s
  -- buckets correctly via the bail-stash code in the resolve branch.
  for _, ptype in ipairs(pending) do
    synth[#synth+1] = "resolve:" .. ptype
  end

  local fake_text = "<context_needed>" .. tbl_concat(synth, ", ") .. "</context_needed>"
  local fired = Net.process_response_buckets(fake_text)
  if not fired then
    -- Dispatcher didn't fire the follow-up. Safety net: drop back to idle
    -- so the user isn't stuck watching "waiting" forever.
    Log.line("RESOLVE", "resume: dispatcher didn't fire for " .. identifier
      .. " -- aborting turn")
    S.status = "idle"
    Log.add_error("Couldn't resume the request after your selection. "
      .. "Please try sending the message again.")
  end
end

-- =============================================================================
-- Called by the main loop (throttled to CFG.POLL_THROTTLE) while waiting for
-- a curl response. Handles in order:
--   1. Watchdog timeout: fires an error if the per-provider timeout is exceeded.
--   2. Exit code file: detects curl network errors and captures diagnostics.
--   3. Partial-read guard: waits for closing brace before parsing.
--   4. JSON decode and API error envelope detection (auth, rate-limit, overload).
--   5. Auto-retry on 529 (overloaded_error) with exponential backoff (2s, 4s, 8s).
--   6. <context_needed> detection: injects requested buckets and fires a follow-up.
--   7. Normal final response: updates display, S.history, token counters, and cost.
-- Watchdog timeout check. Returns true if the request has exceeded the
-- per-provider poll timeout and the timeout has been surfaced to the user
-- (via tier-test abort, key-test abort, or chat error). Caller should
-- return immediately on true.
--
-- Must stay above the curl --max-time set in Net.fire_curl so curl gets the
-- chance to write its exit code before the watchdog fires. Custom providers
-- use their user-configured request_timeout + 15s slack.
function Net._handle_watchdog_timeout()
  local p_active = PROVIDERS.active()
  local poll_timeout = (p_active.is_custom
    and ((tonumber(p_active.request_timeout) or 600) + 15))
    or (prefs.cloud_request_timeout or CFG.CLOUD_TIMEOUT_DEFAULT)
  local elapsed = S.send_time and (time_precise() - S.send_time) or 0
  if not S.send_time or elapsed <= poll_timeout then
    return false
  end
  local timeout_msg =
    "The request timed out. The server may be busy, or your internet "
    .. "connection may have dropped.\n\n"
    .. "Try sending your message again."
  local debug = Net._curl_failure_debug(nil, timeout_msg, "watchdog_timeout")
  debug.elapsed_s = elapsed
  debug.poll_timeout_s = poll_timeout
  S.curl_pid  = nil
  S.send_time = nil
  if S.gemini_tier_pending then
    -- Tier test timed out: ambiguous result. Don't persist `false` -- a
    -- transient timeout shouldn't bake in a wrong tier classification.
    -- Pro filter still treats `nil` as "not paid" (gates on `~= true`),
    -- so the user doesn't gain Pro access; they just get a retest on
    -- next opportunity instead of being stuck.
    S.gemini_tier_pending = false
    Log.line("TIER-TEST", "interpreted as: ambiguous (timeout; not persisted)")
    if UI and UI.show_float_toast then
      UI.show_float_toast(
        "Couldn't verify Gemini tier - will retry on next start", "err")
    end
    if PROVIDERS.active().id == "google" then MODELS.refresh() end
    return true
  end
  if S.key_test_pending then
    local test_prov_id = S.key_test_provider
    S.key_test_pending  = false
    S.key_test_provider = nil
    S.status = "error"
    if api_keys.custom_conn_test and api_keys.custom_conn_test.active
       and api_keys.screen == "custom_llm" then
      CTX.custom_conn_test_advance(false, "Timed out waiting for response.")
      return true
    end
    if #api_keys.test_queue > 0 and (api_keys.screen == "first_run" or api_keys.screen == "settings") and test_prov_id then
      Net.advance_key_test_queue(test_prov_id, false,
        "The server took too long to respond.")
      return true
    end
    -- Append rather than clobber: preserves chat history if the key test
    -- somehow fires while a conversation is on screen.
    Log.add_error(
      "The server took too long to respond while checking your key. "
        .. "Your key is stored for this session but has not been permanently "
        .. "saved yet. Try sending a message to test it. Once verified, "
        .. "it will be saved automatically."
        .. "\n\nIf that doesn't work, click the Settings button to re-enter your key.")
    return true
  end
  if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
    S.display_messages[S.pending_display_idx].ctx_label = "timeout"
  end
  Log.add_error(timeout_msg, nil, nil, nil,
    { error_kind = "watchdog_timeout", error_debug = debug })
  return true
end

-- Check curl's exit-code tmp file. Returns true if curl exited with a
-- non-zero code and the network error has been surfaced (tier abort, key-test
-- abort, or chat error). Caller should return on true. Exit code 0 sets
-- S.curl_exited_clean so the partial-read brace guard is bypassed, and
-- returns false so the caller continues parsing.
function Net._handle_curl_exit_failure()
  local ok_ef, ef = pcall(io.open, tmp.exit, "r")
  if not (ok_ef and ef) then return false end
  local exit_str = ef:read("*a"); ef:close()
  local exit_code = tonumber(exit_str:match("(%d+)"))
  if not exit_code then return false end
  if exit_code == 0 then
    -- curl finished cleanly. Bypass the partial-read brace guard so non-JSON
    -- responses (captive portals, proxy HTML) surface as a clear error
    -- instead of looping until the watchdog fires.
    S.curl_exited_clean = true
    os.remove(tmp.exit)
    os.remove(tmp.err)
    return false
  end
  S.curl_pid  = nil
  S.send_time = nil
  os.remove(tmp.exit)
  local prov_label = PROVIDERS.active().label
  local curl_errors = {
    [5]  = "Can't reach the proxy configured for " .. prov_label .. ". "
           .. "Check your network or proxy settings and try again.",
    [6]  = "Can't reach the " .. prov_label .. " servers. Please check your "
           .. "internet connection and try again.",
    [7]  = "The server refused the connection. It may be temporarily "
           .. "down. Try again in a few minutes.",
    [18] = "The connection closed before the full response arrived. "
           .. "Try sending your message again.",
    [23] = "ReaAssist could not write the server response to its temporary "
           .. "file. Check that your REAPER resource folder is writable.",
    [28] = "The connection timed out. Please check your internet "
           .. "connection and try again.",
    [35] = "Couldn't establish a secure connection. A firewall or "
           .. "network setting may be blocking it.",
    [52] = "The server closed the connection without sending a response. "
           .. "Try again in a moment.",
    [56] = "The connection dropped while ReaAssist was receiving the "
           .. "response. Try again in a moment.",
    [60] = "There's an issue with the server's security certificate. "
           .. "Please check that your computer's date and time are correct.",
    [77] = "curl could not read its certificate bundle. Check your curl "
           .. "or system certificate installation.",
    [92] = "The HTTP/2 connection failed while talking to the server. "
           .. "Try again; if it repeats, switch networks or disable VPN/proxy.",
  }
  local detail = curl_errors[exit_code]
    or "A network error occurred. Please check your internet "
       .. "connection and try again."
  local debug = Net._curl_failure_debug(exit_code, detail)
  Log.line("CURL", string.format("exit=%s (%s), provider=%s, model=%s",
    tostring(exit_code), tostring(debug.exit_meaning),
    tostring(debug.provider_id or "?"), tostring(debug.model_id or "?")))
  if S.gemini_tier_pending then
    -- Tier test curl errored: ambiguous result. Same rationale as the
    -- watchdog branch above -- don't persist a wrong classification on
    -- a transient network failure. Retest fires on next opportunity.
    S.gemini_tier_pending = false
    Log.line("TIER-TEST", string.format(
      "interpreted as: ambiguous (curl exit=%d; not persisted)", exit_code))
    if UI and UI.show_float_toast then
      UI.show_float_toast(
        "Couldn't verify Gemini tier - will retry on next start", "err")
    end
    if PROVIDERS.active().id == "google" then MODELS.refresh() end
    return true
  end
  if S.key_test_pending then
    local test_prov_id = S.key_test_provider
    local test_prov    = test_prov_id and PROVIDERS.get(test_prov_id) or nil
    local was_custom   = test_prov and test_prov.is_custom or false
    S.key_test_pending  = false
    S.key_test_provider = nil
    S.status = "error"
    if api_keys.custom_conn_test and api_keys.custom_conn_test.active
       and api_keys.screen == "custom_llm" then
      CTX.custom_conn_test_advance(false, detail)
      return true
    end
    if #api_keys.test_queue > 0 and (api_keys.screen == "first_run" or api_keys.screen == "settings") and test_prov_id then
      Net.advance_key_test_queue(test_prov_id, false, detail)
      return true
    end
    -- On the API key entry screen, surface the error inline (popup) instead
    -- of dumping it into the chat -- the user hasn't left the screen so a
    -- chat message would be invisible. Custom LLM path almost always lands
    -- here when a port is mistyped, so this is the common case.
    if (api_keys.screen == "first_run" or api_keys.screen == "settings") then
      api_keys.key_validating     = false
      api_keys.key_validating_idx = nil
      local key_prov_label = (test_prov and test_prov.label)
        or (was_custom and "Custom LLM")
        or "the provider"
      if not was_custom then
        api_keys.key_error = detail
      end
      api_keys.show_key_error_popup = true
      api_keys.key_error_provider   = key_prov_label
      api_keys.key_error_detail     = detail
      api_keys.key_error_hint       = was_custom
        and "Check that the server is running and the URL/port is correct."
        or "Check your internet connection and try again."
      api_keys.key_error_url        = nil
      api_keys.key_error_url_label  = nil
      return true
    end
    -- Append rather than clobber (see timeout branch above).
    Log.add_error(detail .. "\n\n"
      .. "Once you're back online, click the Settings button to try again.",
      nil, nil, nil, { error_kind = "curl_exit", error_debug = debug })
    return true
  end
  if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
    S.display_messages[S.pending_display_idx].ctx_label = "network error"
  end
  Log.add_error(detail, nil, nil, nil,
    { error_kind = "curl_exit", error_debug = debug })
  return true
end

-- JSON decode failed. Log raw body, tag the display entry, and show an
-- error. If the response looks like HTML, surface the proxy/captive-portal
-- explanation instead of a generic "unreadable JSON" message.
function Net._handle_json_decode_error(raw, decode_err)
  Code.safe_write(tmp.log, raw)
  if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
    S.display_messages[S.pending_display_idx].ctx_label = "error"
  end
  local raw_head = raw:sub(1, 256):lower()
  local looks_html = raw_head:find("<!doctype", 1, true)
                  or raw_head:find("<html",     1, true)
                  or raw_head:find("<head",     1, true)
                  or raw_head:find("502 bad",   1, true)
                  or raw_head:find("503 ",      1, true)
                  or raw_head:find("504 ",      1, true)
  if looks_html then
    Log.add_error(
      "The server returned an HTML page instead of a JSON response. This "
      .. "usually means a proxy, firewall, or captive portal (hotel/coffee "
      .. "shop Wi-Fi) is intercepting the request, or the API endpoint is "
      .. "temporarily down behind a 5xx gateway error.\n\n"
      .. "Try a different network, disable any VPN/proxy, or wait a few "
      .. "minutes and retry.")
  else
    Log.add_error(
      "Got an unreadable response from the server. This is usually "
      .. "a temporary glitch."
      .. (decode_err and ("\n\nTechnical detail: " .. decode_err) or "")
      .. "\n\nPlease try again.")
  end
end

-- Unified API error handler used by all providers. Maps error types to
-- user-facing messages; provider-specific billing/console links are pulled
-- from the `p` provider record so the same handler works for all three.
--
-- inner_type: provider-specific error code string (e.g. "rate_limit_error",
--   "insufficient_quota", "RESOURCE_EXHAUSTED"). is_overloaded triggers the
--   exponential-backoff auto-retry (up to CFG.MAX_RETRIES). is_auth wipes
--   the stored key and prompts re-entry.
function Net._recoverable_openai_throttle(p, inner_type, api_err)
  if not p or p.id ~= "openai" then return false end
  local code = tostring(inner_type or "")
  if code ~= "rate_limit_exceeded" and code ~= "rate_limit_error" then return false end
  local lmsg = tostring(api_err or ""):lower()
  if lmsg:find("billing", 1, true)
      or lmsg:find("credit", 1, true)
      or lmsg:find("insufficient_quota", 1, true)
      or lmsg:find("exceeded your current quota", 1, true) then
    return false
  end
  return true
end

function Net._retry_after_hint_seconds(api_err)
  local lmsg = tostring(api_err or ""):lower()
  local n = tonumber(lmsg:match("try again in%s+([%d%.]+)%s*ms"))
  if n then return n / 1000 end
  n = tonumber(lmsg:match("try again in%s+([%d%.]+)%s*s"))
  if n then return n end
  n = tonumber(lmsg:match("try again in%s+([%d%.]+)%s*sec"))
  if n then return n end
  return nil
end

function Net._recoverable_anthropic_server_error(inner_type, api_err)
  if tostring(inner_type or "") ~= "api_error" then return false end
  local lmsg = tostring(api_err or ""):lower()
  return lmsg:find("internal server error", 1, true) ~= nil
end

function Net._overload_retry_policy(p, inner_type, api_err)
  local max_retries = CFG.MAX_RETRIES
  local jitter = 0
  local min_delay = nil
  if p and p.id == "google"
     and (tostring(inner_type) == "UNAVAILABLE" or tostring(inner_type) == "503") then
    max_retries = CFG.GEMINI_OVERLOAD_MAX_RETRIES or max_retries
    jitter = CFG.RETRY_JITTER_SECS or 0
  elseif p and p.id == "anthropic"
     and Net._recoverable_anthropic_server_error(inner_type, api_err) then
    jitter = CFG.RETRY_JITTER_SECS or 0
  elseif Net._recoverable_openai_throttle(p, inner_type, api_err) then
    max_retries = CFG.OPENAI_THROTTLE_MAX_RETRIES or max_retries
    jitter = CFG.RETRY_JITTER_SECS or 0
    min_delay = Net._retry_after_hint_seconds(api_err)
  end
  return max_retries, CFG.RETRY_DELAY_BASE, jitter, min_delay
end

function Net._google_capacity_recovery(p)
  if not p or p.id ~= "google" or not S.pending_orig_prompt then return nil end
  local current_model = p.models and p.models[S.pending_model_idx or prefs.model_idx] or nil
  if current_model and current_model.id == "gemini-3-flash-preview" then return nil end
  local fallback
  for _, m in ipairs(p.models or {}) do
    if m.id == "gemini-3-flash-preview" then fallback = m; break end
  end
  if not fallback then return nil end
  return {
    provider_id = "google",
    model_id = current_model and current_model.id or nil,
    fallback_provider_id = "google",
    fallback_model_id = fallback.id,
    fallback_label = fallback.label or "Flash 3",
    recovery_prompt = S.pending_orig_prompt,
    recovery_attachments = S.pending_attachments,
  }
end

function Net._handle_api_error(p, inner_type, api_err, is_overloaded, is_auth)
  -- Auto-retry on overload (Anthropic 529, or provider-specific equivalents).
  local max_retries, retry_base, retry_jitter, retry_min_delay =
    Net._overload_retry_policy(p, inner_type, api_err)
  if is_overloaded and S.retry_count < max_retries then
    S.retry_count = S.retry_count + 1
    S.retry_max = max_retries
    local delay = retry_base * (2 ^ (S.retry_count - 1))
    if retry_min_delay and retry_min_delay > delay then delay = retry_min_delay end
    if retry_jitter > 0 then delay = delay + (math.random() * retry_jitter) end
    S.retry_scheduled = true
    S.retry_fire_time = time_precise() + delay
    S.status = "waiting"
    if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
      S.display_messages[S.pending_display_idx].ctx_label =
        str_format("retrying in %.1fs (%d/%d)", delay, S.retry_count, max_retries)
    end
    return
  end

  if Net._recoverable_openai_throttle(p, inner_type, api_err) then
    if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
      S.display_messages[S.pending_display_idx].ctx_label = "provider throttle"
    end
    Log.add_error(
      "OpenAI is throttling this request because the account/model "
      .. "token-per-minute limit is temporarily saturated. This is a "
      .. "provider-side throughput limit, not a Lua or prompt failure.\n\n"
      .. "ReaAssist retried with exponential backoff and OpenAI still returned "
      .. "a rate-limit error. Wait a minute and retry, or switch to a smaller "
      .. "model for this request.")
    return
  end

  if p and p.id == "google" and is_overloaded then
    if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
      S.display_messages[S.pending_display_idx].ctx_label = "provider capacity"
    end
    local recovery = Net._google_capacity_recovery(p)
    local msg = "Google's Gemini service says this model is currently at capacity. "
      .. "This is a provider-side availability issue, not a problem with your "
      .. "prompt, API key, or ReaAssist.\n\n"
      .. "ReaAssist retried with exponential backoff and Google still returned "
      .. "503 UNAVAILABLE. You can wait and retry later"
    if recovery then
      msg = msg .. ", or switch to Flash 3 and resend the same message."
    else
      msg = msg .. "."
    end
    Log.add_error(msg, nil, nil, recovery and "google_model_capacity" or nil, recovery)
    return
  end

  if is_auth then
    S.api_key = nil
    S.api_key_map[p.id] = nil
    Key.clear(p.key_extstate)
    S.status = "error"
    if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
      S.display_messages[S.pending_display_idx].ctx_label = "auth error"
    end
    S.display_messages[#S.display_messages+1] = {
      role    = "assistant",
      content = "Your " .. p.label .. " API key isn't working. It may have expired or been "
        .. "entered incorrectly.\n\n"
        .. "Click the Settings button below to enter a new one.\n\n"
        .. "You can find or create a key here:",
      link_url   = p.console_url,
      link_label = p.console_label,
      storage_note = "Your key is obfuscated and locked to this REAPER install "
        .. "path. It will not work if copied to another machine.",
    }
    S.scroll_to_bottom = true
    return
  end

  -- Error map. Messages that reference provider name or billing URL are
  -- rebuilt with p fields; others are constant but kept together here so
  -- the table stays a single source of truth.
  local error_info = {
    -- Anthropic
    rate_limit_error      = { label = "rate limited",
      msg = "Slow down! You're sending messages too quickly. "
        .. "Wait about 30 seconds and try again.\n\n"
        .. "If this keeps happening, try switching models in the dropdown." },
    credit_balance_error  = { label = "out of credits",
      msg = "Your " .. p.label .. " account has run out of credits."
        .. "\n\nTo continue using ReaAssist, add funds to your account:",
      link_url = p.billing_url, link_label = p.billing_label },
    overloaded_error      = { label = "overloaded",
      msg = "The servers are busy right now. "
        .. "Wait a moment and try again; this usually clears up quickly." },
    api_error             = { label = "provider service error",
      msg = "The provider service returned a temporary internal server error. "
        .. "This is a provider-side service issue, not a problem with your "
        .. "prompt, API key, or ReaAssist.\n\n"
        .. "ReaAssist retried with exponential backoff and the provider still "
        .. "failed. Wait a moment and try again, or switch models for this request." },
    invalid_request_error = { label = "invalid request",
      msg = "This conversation has gotten too long for the model to handle."
        .. "\n\nTo fix this:\n- Click + new chat to start fresh\n"
        .. "- Try a shorter message\n"
        .. "- Turn off \"Always include REAPER API reference\" or Send snapshot to reduce size" },
    not_found_error       = { label = "model not found",
      msg = "That model doesn't seem to exist anymore. It may have been "
        .. "renamed or retired.\n\nTry picking a different one from the dropdown below." },
    permission_error      = { label = "permission denied",
      msg = "Your API key doesn't have access to this model. This usually "
        .. "means it requires a higher account tier.\n\nTry a different model, "
        .. "or check your plan here:",
      link_url = p.billing_url, link_label = p.billing_label },
    -- OpenAI
    rate_limit_exceeded   = { label = "provider throttle",
      msg = "OpenAI is throttling this request because the account/model "
        .. "token-per-minute limit is temporarily saturated. This is a "
        .. "provider-side throughput limit, not a Lua or prompt failure.\n\n"
        .. "Wait a minute and try again, or switch to a smaller model for this request." },
    server_error          = { label = "provider service error",
      msg = "The provider service returned a temporary server error. "
        .. "This is a provider-side service issue, not a problem with your "
        .. "prompt, API key, or ReaAssist.\n\n"
        .. "ReaAssist retried with exponential backoff and the provider still "
        .. "failed. Wait a moment and try again, or switch models for this request." },
    overloaded            = { label = "provider busy",
      msg = "The provider service is busy right now. This is a provider-side "
        .. "capacity issue, not a problem with your prompt, API key, or ReaAssist.\n\n"
        .. "ReaAssist retried with exponential backoff and the provider still "
        .. "failed. Wait a moment and try again, or switch models for this request." },
    insufficient_quota    = { label = "out of credits",
      msg = "Your " .. p.label .. " account has run out of credits."
        .. "\n\nTo continue using ReaAssist, add funds to your account:",
      link_url = p.billing_url, link_label = p.billing_label },
    model_not_found       = { label = "model not found",
      msg = "That model doesn't seem to exist anymore. It may have been "
        .. "renamed or retired.\n\nTry picking a different one from the dropdown below." },
    -- Google
    RESOURCE_EXHAUSTED    = { label = "rate limited",
      msg = "You've hit a rate limit. Wait a moment and try again." },
    RESOURCE_EXHAUSTED_BILLING = { label = "out of quota",
      msg = "Your Google account has exhausted its Gemini quota."
        .. "\n\nIf you're on the free tier, you may need to enable billing. "
        .. "If you're on a paid plan, add funds or check your usage limits:",
      link_url = p.billing_url, link_label = p.billing_label },
    NOT_FOUND             = { label = "model not found",
      msg = "That model doesn't seem to exist anymore. Try picking a different one." },
    PERMISSION_DENIED     = { label = "permission denied",
      msg = "Your API key doesn't have access to this model.",
      link_url = p.billing_url, link_label = p.billing_label },
  }

  -- Reclassify generic error types into funding errors when the message
  -- mentions credits/quota/billing -- gives the user actionable billing links
  -- instead of a misleading "try again later" or "conversation too long".
  -- Anthropic in particular returns invalid_request_error for both context-
  -- window overflow AND "Your credit balance is too low..."; without this
  -- the credits case shows the context-overflow copy.
  local effective_type = inner_type
  if api_err then
    local lmsg = api_err:lower()
    if inner_type == "rate_limit_error" and lmsg:find("credit") then
      effective_type = "credit_balance_error"
    elseif inner_type == "invalid_request_error"
       and (lmsg:find("credit") or lmsg:find("balance") or lmsg:find("billing")) then
      effective_type = "credit_balance_error"
    elseif inner_type == "rate_limit_exceeded"
       and (lmsg:find("quota") or lmsg:find("billing") or lmsg:find("exceeded your current")) then
      effective_type = "insufficient_quota"
    elseif inner_type == "RESOURCE_EXHAUSTED"
       and (lmsg:find("quota") or lmsg:find("billing") or lmsg:find("limit.*exceed")) then
      effective_type = "RESOURCE_EXHAUSTED_BILLING"
    end
  end

  local info  = error_info[effective_type]
  local label = info and info.label or "api error"
  local msg   = info and info.msg
    or ("Something went wrong. Please try again."
      .. (api_err and ("\n\nDetails: " .. api_err) or ""))
  if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
    S.display_messages[S.pending_display_idx].ctx_label = label
  end
  if api_err and not info then
    msg = msg .. "\n\nDetails: " .. api_err
  end
  Log.add_error(msg, info and info.link_url, info and info.link_label)
end

function Net.try_finish_curl()
  if not S.curl_pid then return end

  if Net._handle_watchdog_timeout() then return end

  if Net._handle_curl_exit_failure() then return end

  -- Read the response file (pcall handles transient AV scanner file locks).
  local ok_f, f = pcall(io.open, tmp.out, "r")
  if not ok_f or not f then return end
  local raw = f:read("*a"); f:close()
  if #raw < 2 then return end  -- truly empty response: wait for content
  -- Partial-read guard: while curl is still running, the body file may be
  -- mid-write. Wait for the closing brace before parsing. Once curl has exited
  -- (curl_exited_clean), the body is complete and we go straight to JSON.decode
  -- so non-JSON responses surface as a clear error instead of looping.
  if not S.curl_exited_clean then
    local last_char = raw:match("(%S)%s*$")
    if last_char ~= "}" then return end
  end

  local elapsed = S.send_time and (time_precise() - S.send_time) or nil
  S.curl_pid  = nil
  S.send_time = nil

  Log.response(raw, elapsed)

  if S.gemini_tier_pending then
    Net.handle_gemini_tier_test(raw)
    return
  end

  if S.key_test_pending then
    Net.handle_key_test(raw)
    return
  end

  -- Phase 1 instrumentation: end of curl_wait, start of response_parse.
  -- Placed after the early-return paths above (gemini tier test, key
  -- test) so those don't attribute curl_wait time to a regular turn.
  Probe.mark_phase_end(S.probe_turn, "curl_wait")
  Probe.mark_phase_start(S.probe_turn, "response_parse")
  local resp, decode_err = JSON.decode(raw)
  Probe.mark_phase_end(S.probe_turn, "response_parse")
  if not resp or type(resp) ~= "table" then
    Net._handle_json_decode_error(raw, decode_err)
    return
  end

  -- ==========================================================================
  -- Provider-specific error handling and response extraction.
  -- Each provider has different error envelope formats and response structures.
  -- The dispatch calls a provider-specific handler that either:
  --   (a) handles the error (shows UI feedback) and returns, or
  --   (b) extracts text and tokens and falls through to the common post-parse flow.
  -- Uses the provider/model snapshot from send time, not current UI state,
  -- so a mid-request provider switch doesn't corrupt parsing.
  -- ==========================================================================
  local p = PROVIDERS[S.pending_provider_idx] or PROVIDERS.active()


  -- ---------------------------------------------------------------------------
  -- Provider-specific error detection and response extraction.
  -- Each block either calls Net._handle_api_error + return, or sets text/tokens and
  -- falls through to the common post-parse flow below.
  -- ---------------------------------------------------------------------------
  -- empty_reason carries provider-specific context for the empty-text path so
  -- the post-parse error message can name the actual cause (length cap hit on
  -- reasoning tokens, content filter, refusal) instead of the generic fallback.
  local text, raw_tok_in, raw_tok_out, tok_in_read, tok_in_create
  local empty_reason, refusal_text, reasoning_only_tokens

  if p.id == "anthropic" then
    -- Anthropic error envelope: {"type":"error","error":{"type":"...","message":"..."}}
    if resp.type == "error" and type(resp.error) == "table" and resp.error ~= JSON.NULL then
      local it = resp.error.type
      local em = type(resp.error.message) == "string" and resp.error.message or ""
      -- Beta-header rejection guard. When Anthropic deprecates the
      -- extended-cache-ttl-2025-04-11 beta header, the API starts returning
      -- 400 invalid_request_error referencing the header name or "beta"
      -- + "ttl"/"cache". Strip the header session-wide, fall back to 5-min
      -- ephemeral caching, rebuild the body, and silently retry the same
      -- request so the user never sees the deprecation. Only attempt this
      -- once per session (anthropic_beta_disabled flag) so a genuinely bad
      -- request doesn't loop forever.
      if not S.anthropic_beta_disabled and it == "invalid_request_error" then
        local lm = em:lower()
        local mentions_beta = lm:find("extended-cache-ttl", 1, true)
                           or lm:find("anthropic-beta",     1, true)
                           or (lm:find("beta", 1, true)
                               and (lm:find("ttl", 1, true)
                                    or lm:find("cache_control", 1, true)
                                    or lm:find('"1h"', 1, true)))
        if mentions_beta then
          S.anthropic_beta_disabled = true
          -- Rebuild the body without 1h cache markers and re-fire on the
          -- normal retry timer (no backoff -- this isn't an overload).
          local rebuilt = Net.build_body(
            Net.trimmed_history(),
            S.pending_snapshot,
            S.pending_attachments)
          S.retry_saved_body = rebuilt
          S.retry_scheduled  = true
          S.retry_fire_time  = time_precise()  -- fire next loop tick
          S.status           = "waiting"
          if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
            S.display_messages[S.pending_display_idx].ctx_label = "retrying (5m cache)"
          end
          return
        end
      end
      Net._handle_api_error(p, it, em,
        it == "overloaded_error"
          or Net._recoverable_anthropic_server_error(it, em),
        it == "authentication_error")
      return
    end
    -- Validate structure.
    if resp.type ~= "message" or type(resp.content) ~= "table" then
      Code.safe_write(tmp.log, raw)
      if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
        S.display_messages[S.pending_display_idx].ctx_label = "error"
      end
      Log.add_error("Got an unexpected response from the server. This is likely a "
        .. "temporary issue.\n\nPlease try again.")
      return
    end
    -- Extract text. Also count thinking / redacted_thinking blocks so they
    -- aren't silently dropped if a future build enables extended thinking on
    -- Claude (today thinking_levels=nil for the Claude provider, so this path
    -- only activates if/when that changes -- but the count goes into the log
    -- so we'll know the moment it does, and tool-use turns won't break by
    -- surprise from missing-thinking-block 400s).
    local text_parts = {}
    local thinking_blocks = 0
    for _, block in ipairs(resp.content) do
      if type(block) == "table" then
        if block.type == "text" and type(block.text) == "string" then
          text_parts[#text_parts+1] = block.text
        elseif block.type == "thinking" or block.type == "redacted_thinking" then
          thinking_blocks = thinking_blocks + 1
        end
      end
    end
    if thinking_blocks > 0 then
      Log.line("ANTHROPIC", "received " .. thinking_blocks
        .. " thinking block(s) (not preserved in history; enable a thinking-aware "
        .. "history adapter before using extended thinking with tool use)")
    end
    -- "\n\n" between content blocks rather than a single "\n": a code
    -- fence at the end of one block plus prose at the start of the next
    -- would otherwise concatenate to "```\nLine of prose" and break the
    -- fence. Anthropic almost always returns a single text block today,
    -- but the join cost is identical and the multi-block case is safer.
    text = #text_parts > 0 and tbl_concat(text_parts, "\n\n") or nil
    -- Diagnostic fields for the empty-text branch. Anthropic uses
    --   stop_reason="max_tokens" -> output cap hit
    --   stop_reason="refusal"    -> model declined the request
    if resp.stop_reason == "max_tokens" then
      empty_reason = "length"
    elseif resp.stop_reason == "refusal" then
      empty_reason = "refusal"
    end
    -- Tokens: Anthropic includes cache breakdown.
    local usage     = type(resp.usage) == "table" and resp.usage or {}
    local base      = tonumber(usage.input_tokens)                or 0
    tok_in_create   = tonumber(usage.cache_creation_input_tokens) or 0
    tok_in_read     = tonumber(usage.cache_read_input_tokens)     or 0
    raw_tok_in      = base + tok_in_create + tok_in_read
    raw_tok_out     = tonumber(usage.output_tokens) or 0

  elseif p.id == "openai" or p.id == "deepseek" or p.is_custom then
    -- OpenAI error envelope: {"error":{"type":"...","message":"...","code":"..."}}
    -- Custom OpenAI-compatible endpoints (Ollama, LM Studio, vLLM, OpenRouter,
    -- etc.) and DeepSeek follow the same wire format, so they share this branch.
    if type(resp.error) == "table" and resp.error ~= JSON.NULL then
      local code = resp.error.code or resp.error.type or ""
      local em = type(resp.error.message) == "string" and resp.error.message or ""
      local is_auth = (code == "invalid_api_key")
        or (em:lower():find("api key", 1, true) ~= nil)
      local is_overloaded = (code == "server_error" or code == "overloaded")
        or Net._recoverable_openai_throttle(p, code, em)
      Net._handle_api_error(p, code, em, is_overloaded, is_auth)
      return
    end
    -- Validate structure: {"choices":[{"message":{"content":"..."}}]}
    if type(resp.choices) ~= "table" or #resp.choices == 0
       or type(resp.choices[1].message) ~= "table" then
      Code.safe_write(tmp.log, raw)
      if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
        S.display_messages[S.pending_display_idx].ctx_label = "error"
      end
      Log.add_error("Got an unexpected response from the server. This is likely a "
        .. "temporary issue.\n\nPlease try again.")
      return
    end
    local choice  = resp.choices[1]
    local message = choice.message
    text = message.content
    -- Capture diagnostic fields so the empty-text branch can name the cause:
    --   finish_reason="length"  -> reasoning/output budget exhausted
    --   finish_reason="content_filter" -> safety filter blocked output
    --   message.refusal (string) -> model declined the request
    if type(message.refusal) == "string" and message.refusal ~= "" then
      refusal_text = message.refusal
      empty_reason = "refusal"
    elseif choice.finish_reason == "length" then
      empty_reason = "length"
    elseif choice.finish_reason == "content_filter" then
      empty_reason = "content_filter"
    end
    -- Tokens: OpenAI usage. prompt_tokens is the TOTAL input (including cached),
    -- and prompt_tokens_details.cached_tokens is the portion served from the
    -- automatic prefix cache (billed at 10% of regular input). OpenAI's caching
    -- has no separate cache-write fee, so tok_in_create stays 0.
    --
    -- DeepSeek reports cache hits at the top level of usage as
    -- prompt_cache_hit_tokens / prompt_cache_miss_tokens (not nested under
    -- prompt_tokens_details). Caching is automatic on prefix and there is no
    -- separate cache-write fee, so tok_in_create also stays 0.
    local usage   = type(resp.usage) == "table" and resp.usage or {}
    raw_tok_in    = tonumber(usage.prompt_tokens)     or 0
    raw_tok_out   = tonumber(usage.completion_tokens) or 0
    if p.id == "deepseek" then
      tok_in_read = tonumber(usage.prompt_cache_hit_tokens) or 0
    else
      local details = type(usage.prompt_tokens_details) == "table"
                      and usage.prompt_tokens_details or {}
      tok_in_read   = tonumber(details.cached_tokens) or 0
    end
    tok_in_create = 0
    -- Reasoning-token count for the length-cap error path. Lets the user see
    -- exactly how much of the cap went to internal reasoning vs visible output.
    local cdet    = type(usage.completion_tokens_details) == "table"
                    and usage.completion_tokens_details or {}
    reasoning_only_tokens = tonumber(cdet.reasoning_tokens) or 0

  elseif p.id == "google" then
    -- Gemini error envelope: {"error":{"code":N,"message":"...","status":"..."}}
    if type(resp.error) == "table" and resp.error ~= JSON.NULL then
      local status = resp.error.status or ""
      local code   = resp.error.code or 0
      local msg    = resp.error.message or ""
      local is_auth = (status == "UNAUTHENTICATED" or code == 401)
      local is_overloaded = (code == 503 or status == "UNAVAILABLE")
      -- Cache miss: the cachedContent we referenced no longer exists server-
      -- side (TTL expired, or deleted out-of-band). Drop local cache state
      -- so the next send rebuilds without the stale reference. We don't
      -- auto-retry here because reconstructing the body would require
      -- re-plumbing attachments; a manual resend costs one click and is rare.
      local cache_miss = S.gemini_cache_name
        and (code == 404 or status == "NOT_FOUND"
             or (msg:find("[Cc]ached") and msg:find("[Nn]ot found")))
      if cache_miss then
        Net.gemini_cache_invalidate()
        if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
          S.display_messages[S.pending_display_idx].ctx_label = "cache expired"
        end
        Log.add_error(
          "The Gemini context cache expired between sends. "
          .. "Please send your message again; a fresh cache will be "
          .. "created automatically.")
        S.status = "error"
        return
      end
      -- Fallback free tier detection: 403/429 on a paid_only model.
      local cur_model = p.models[prefs.model_idx] or MODELS[prefs.model_idx]
      if (code == 403 or code == 429 or status == "PERMISSION_DENIED"
          or status == "RESOURCE_EXHAUSTED") and cur_model and cur_model.paid_only then
        S.gemini_paid_tier = false
        reaper.SetExtState(CFG.EXT_NS, "gemini_paid_tier", "false", true)
        MODELS.refresh()
        if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
          S.display_messages[S.pending_display_idx].ctx_label = "api error"
        end
        Log.add_error("Gemini Pro requires a paid Google account. "
          .. "Your account appears to be on the free tier.\n\n"
          .. "The model has been switched to Flash Lite. "
          .. "To use Pro, enable billing at aistudio.google.com/apikey.")
        return
      end
      Net._handle_api_error(p, status, resp.error.message, is_overloaded, is_auth)
      return
    end
    -- Validate structure: {"candidates":[{"content":{"parts":[{"text":"..."}]}}]}
    -- Note: when finishReason is MAX_TOKENS/SAFETY/RECITATION, the candidate
    -- may be present without a `content` block, so we treat that as the
    -- empty-text case (with an explanatory empty_reason) rather than as a
    -- malformed response.
    if type(resp.candidates) ~= "table" or #resp.candidates == 0 then
      Code.safe_write(tmp.log, raw)
      if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
        S.display_messages[S.pending_display_idx].ctx_label = "error"
      end
      Log.add_error("Got an unexpected response from the server. This is likely a "
        .. "temporary issue.\n\nPlease try again.")
      return
    end
    local cand    = resp.candidates[1]
    local content = type(cand.content) == "table" and cand.content or nil
    -- Extract text from all parts (if a content block exists at all).
    if content and type(content.parts) == "table" then
      local text_parts = {}
      for _, part in ipairs(content.parts) do
        if type(part) == "table" and type(part.text) == "string" then
          text_parts[#text_parts+1] = part.text
        end
      end
      text = #text_parts > 0 and tbl_concat(text_parts, "\n") or nil
    end
    -- Diagnostic fields for the empty-text branch.
    if cand.finishReason == "MAX_TOKENS" then
      empty_reason = "length"
    elseif cand.finishReason == "SAFETY" or cand.finishReason == "RECITATION" then
      empty_reason = "content_filter"
    end
    -- Tokens: Gemini usageMetadata. promptTokenCount is the TOTAL input
    -- (including cached), and cachedContentTokenCount is the portion served
    -- from an explicit context cache (billed at a discounted rate).
    local usage   = type(resp.usageMetadata) == "table" and resp.usageMetadata or {}
    raw_tok_in    = tonumber(usage.promptTokenCount)     or 0
    raw_tok_out   = tonumber(usage.candidatesTokenCount) or 0
    tok_in_read   = tonumber(usage.cachedContentTokenCount) or 0
    tok_in_create = 0  -- Gemini has no per-turn cache-create token cost
    -- Gemini reports thinking tokens separately in thoughtsTokenCount.
    reasoning_only_tokens = tonumber(usage.thoughtsTokenCount) or 0
  end

  -- Phase 1 instrumentation: capture per-request metadata and usage.
  -- Fires after each successful response extraction by any provider
  -- branch. Multi-request turns (context-needed re-fires, validator
  -- retries) accumulate one entry per HTTP round-trip in the turn's
  -- requests array. Provider-internal early-return retry paths
  -- (e.g., beta-header rejection -> retry) bypass this site by
  -- design; step 9 audit covers those paths.
  do
    local model_entry = MODELS[S.pending_model_idx or prefs.model_idx]
                     or MODELS[1]
    local thinking_lvl
    if p.thinking_levels and prefs.thinking_idx and prefs.thinking_idx > 0 then
      local tl = p.thinking_levels[prefs.thinking_idx]
      if tl then thinking_lvl = tl.id or tl.label end
    end
    Probe.add_request(S.probe_turn, {
      provider       = p.id,
      model          = model_entry and (model_entry.id or model_entry.label),
      thinking_level = thinking_lvl,
    })
    local total_in     = tonumber(raw_tok_in)    or 0
    local cache_read   = tonumber(tok_in_read)   or 0
    local cache_create = tonumber(tok_in_create) or 0
    local uncached_in  = total_in - cache_read - cache_create
    if uncached_in < 0 then uncached_in = 0 end
    Probe.add_request_usage(S.probe_turn, nil, {
      cache_read   = cache_read,
      cache_create = cache_create,
      uncached_in  = uncached_in,
      output       = tonumber(raw_tok_out) or 0,
    })
  end

  -- Common post-parse: clean up text.
  if text then
    text = text:gsub("\n\n\n+", "\n\n")
    -- Collapse double-newlines between consecutive list items to single newlines.
    text = text:gsub("(\n[%*%-][^\n]*)\n\n([%*%-])", "%1\n%2")
    text = text:match("^(.-)%s*$") or ""
  end

  if not text or text == "" then
    Code.safe_write(tmp.log, raw)

    -- Credit the failed call's tokens to the session totals. The user paid
    -- real money for the reasoning that produced no output, and hiding it
    -- from the running cost display would be misleading. We mirror the
    -- success path's accounting so the dollar figure matches the bill.
    -- Compute cost once; used for both session total and per-message stamp.
    local fail_cost = nil
    if (raw_tok_in or 0) > 0 or (raw_tok_out or 0) > 0 then
      S.session_tok_in  = S.session_tok_in  + (raw_tok_in  or 0)
      S.session_tok_out = S.session_tok_out + (raw_tok_out or 0)
      local mi = S.pending_model_idx or prefs.model_idx
      local mentry = MODELS[mi] or MODELS[1]
      if mentry then
        local base = (raw_tok_in or 0) - (tok_in_read or 0) - (tok_in_create or 0)
        fail_cost = MODELS.calc_cost(mentry, base, tok_in_read or 0, tok_in_create or 0, raw_tok_out or 0)
        S.session_cost = S.session_cost + fail_cost
      end
    end

    -- Empty-text-from-length auto-retry. When the model burned the full
    -- output budget on internal reasoning and emitted no visible reply
    -- (observed on gpt-5.4-mini with reasoning_effort=medium and a 16K
    -- cap; mostly defanged by the no-cap-sent change for cloud, but the
    -- failure can still happen at the model's real 128K ceiling on long
    -- complex prompts), silently re-fire the same user prompt with
    -- thinking forced to "none" and a terse "code-only" repair nudge.
    -- Single retry per user prompt -- if even thinking-off doesn't fit,
    -- fall through to the visible error so the user can intervene.
    -- Skipped when the active provider doesn't expose thinking levels
    -- (Anthropic today): nothing to retry-with-different-thinking.
    local _retry_prov = PROVIDERS.active()
    -- "Thinking off" is provider-specific. For OpenAI/Gemini, override_idx=0
    -- omits the reasoning_effort field which is effectively off. For
    -- DeepSeek, omitting the "thinking" field falls through to its
    -- server-side default (enabled), so a 0 override would NOT actually
    -- disable reasoning -- it would re-fire with thinking still on and
    -- usually fail the length cap again. Find the "off" entry by value
    -- ("none" for OpenAI, "disabled" for DeepSeek) and use its idx;
    -- providers without an explicit off entry (Gemini's Minimal/Low/Med/
    -- High) fall back to 0 = omit, matching the existing behavior.
    local _retry_off_idx = 0
    if _retry_prov.thinking_levels then
      for _i, _tl in ipairs(_retry_prov.thinking_levels) do
        if _tl.value == "none" or _tl.value == "disabled" then
          _retry_off_idx = _i; break
        end
      end
    end
    -- Don't fire the retry if we are already at the provider's off entry
    -- (the prior request already had thinking off and still hit the cap;
    -- another retry with the same setting won't change anything).
    local _cur_idx = S.thinking_override_idx or prefs.thinking_idx
    local _cur_tl  = _retry_prov.thinking_levels
                     and _retry_prov.thinking_levels[_cur_idx]
    local _cur_is_off = _cur_tl
                        and (_cur_tl.value == "none"
                             or _cur_tl.value == "disabled")
    if empty_reason == "length"
       and not S.length_retry_used
       and _retry_prov.thinking_levels
       and not _cur_is_off
       and _cur_idx > 0 then
      S.length_retry_used     = true
      Probe.add_validator_retry(S.probe_turn, "length")
      S.thinking_override_idx = _retry_off_idx  -- provider-aware "off"
      local detail = ""
      if reasoning_only_tokens and reasoning_only_tokens > 0 then
        detail = " (" .. reasoning_only_tokens
          .. " reasoning tokens, " .. (raw_tok_out or 0) .. " visible)"
      end
      Log.line("LENGTH-RETRY",
        "empty response from length cap" .. detail
        .. "; retrying with thinking=none (user-invisible)")
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT MENTION "
        .. "ANY OF THIS IN YOUR VISIBLE REPLY: Your previous reply consumed "
        .. "the entire output token budget on internal reasoning and "
        .. "produced zero visible output. This retry is firing with "
        .. "reasoning disabled. Deliver the answer concisely: a short "
        .. "lead sentence, the code block, and the standard tip line. "
        .. "Skip recap tables, explanations of decision steps, and any "
        .. "prose beyond what the user actually needs. Respond as if this "
        .. "is your FIRST reply -- do NOT apologize, do NOT say 'let me "
        .. "try again', do NOT mention the retry.)\n\n"
        .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
      if #S.history > 0 and S.history[#S.history].role == "assistant" then
        S.history[#S.history] = nil
      end
      if #S.history > 0 and S.history[#S.history].role == "user" then
        S.history[#S.history] = nil
      end
      S.history[#S.history+1] = { role = "user", content = history_content }
      if S.pending_display_idx
         and S.display_messages[S.pending_display_idx] then
        local dmsg = S.display_messages[S.pending_display_idx]
        local existing = dmsg.ctx_label or ""
        if not existing:find("length_retry", 1, true) then
          dmsg.ctx_label = existing ~= ""
            and (existing .. " + length_retry") or "length_retry"
        end
      end
      if prefs.include_snapshot then
        S.pending_project  = _resolve_pending_project()
        -- See JSFX-intent comment on the analogous retry sites above:
        -- carry pending_jsfx_intent across snapshot rebuilds so the trim
        -- survives every retry path, not just the JSFX-validator's.
        S.pending_snapshot = CTX.build_snapshot(S.pending_project,
          S.pending_jsfx_intent and { minimal_tracks = true } or nil)
      end
      S.status = "waiting"
      Net._ensure_request_start_time()
      Code.safe_write(tmp.out, "")
      local ok, reason = Net.fire_curl(Net.build_body(Net.trimmed_history(),
        S.pending_snapshot, S.pending_attachments))
      if not ok and reason ~= "call_cap_exceeded" then
        Log.add_error("Auto-retry after empty length-capped reply did not "
          .. "go through. Please resend the last message.")
      end
      S.scroll_to_bottom = true
      return
    end

    -- Pick a precise label and message based on what the parser captured.
    -- recovery_kind = "token_limit" tells Log.add_error to render the inline
    -- Lower-Thinking + Retry recovery row. (Bump-Max-Tokens was retired
    -- alongside the Max Tokens dropdown -- max_tokens is now per-model
    -- metadata, already at the model's published ceiling for cloud.)
    local label, msg, recovery_kind
    if empty_reason == "length" then
      label = "out of tokens"
      recovery_kind = "token_limit"
      local detail = ""
      if reasoning_only_tokens and reasoning_only_tokens > 0 then
        detail = str_format(
          " (%d of %d output tokens went to internal reasoning)",
          reasoning_only_tokens, raw_tok_out or 0)
      end
      local has_thinking = PROVIDERS.active().thinking_levels and prefs.thinking_idx > 0
      msg = "The model hit its output token limit before producing any "
        .. "visible response" .. detail .. ".\n"
        .. (has_thinking
          and "Try lowering the Thinking level, or rephrase your message to require less reasoning."
          or  "Try rephrasing your message to require a shorter response, or switch to a different model.")
    elseif empty_reason == "content_filter" then
      label = "filtered"
      msg = "The provider's safety filter blocked the response.\n\n"
        .. "Try rephrasing your message."
    elseif empty_reason == "refusal" then
      label = "refused"
      msg = "The model declined to answer this request."
        .. (refusal_text and ("\n\nDetails: " .. refusal_text) or "")
    else
      -- Generic empty response with finish_reason=stop -- the provider
      -- said "done" but produced no visible content. Observed as
      -- transient flakiness on ChatGPT (completion=3, body empty). Fire
      -- one hidden auto-retry before surfacing the user-facing error;
      -- if the retry also comes back empty, fall through to the error
      -- and the user gets the recovery row. Same scrub-and-rebuild
      -- pattern as the length-cap retry above.
      if not S.empty_retry_used then
        S.empty_retry_used = true
        Log.line("EMPTY-RETRY",
          "empty response from provider; retrying once (user-invisible)")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
          .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: Your previous "
          .. "reply was empty -- finish_reason=stop with no content. "
          .. "Generate the response now. Respond as if this is your "
          .. "FIRST reply -- do NOT apologize, do NOT mention a retry.)\n\n"
          .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
        if #S.history > 0 and S.history[#S.history].role == "assistant" then
          S.history[#S.history] = nil
        end
        if #S.history > 0 and S.history[#S.history].role == "user" then
          S.history[#S.history] = nil
        end
        S.history[#S.history+1] = { role = "user", content = history_content }
        if S.pending_display_idx
           and S.display_messages[S.pending_display_idx] then
          local dmsg = S.display_messages[S.pending_display_idx]
          local existing = dmsg.ctx_label or ""
          if not existing:find("empty_retry", 1, true) then
            dmsg.ctx_label = existing ~= ""
              and (existing .. " + empty_retry") or "empty_retry"
          end
        end
        if prefs.include_snapshot then
          S.pending_project  = _resolve_pending_project()
          S.pending_snapshot = CTX.build_snapshot(S.pending_project,
            S.pending_jsfx_intent and { minimal_tracks = true } or nil)
        end
        S.status = "waiting"
        Net._ensure_request_start_time()
        Code.safe_write(tmp.out, "")
        local ok, reason = Net.fire_curl(Net.build_body(Net.trimmed_history(),
          S.pending_snapshot, S.pending_attachments))
        if not ok and reason ~= "call_cap_exceeded" then
          Log.add_error("Auto-retry after empty response did not go "
            .. "through. Please resend the last message.")
        end
        S.scroll_to_bottom = true
        return
      end
      label = "error"
      recovery_kind = "token_limit"
      local has_thinking2 = PROVIDERS.active().thinking_levels and prefs.thinking_idx > 0
      msg = "The model's response was empty after processing, even after a "
        .. "retry. This can happen when the model uses all its output for "
        .. "internal reasoning.\n"
        .. (has_thinking2
          and "Try lowering the Thinking level, or rephrase your message to require less reasoning."
          or  "Try rephrasing your message, or switch to a different model.")
    end

    if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
      local dmsg = S.display_messages[S.pending_display_idx]
      dmsg.ctx_label = label
      -- Write token info so the user can see what they were billed for.
      if (raw_tok_in or 0) > 0 or (raw_tok_out or 0) > 0 then
        dmsg.tok_in           = raw_tok_in  or 0
        dmsg.tok_out          = raw_tok_out or 0
        dmsg.tok_cache_read   = tok_in_read or 0
        dmsg.tok_cache_create = tok_in_create or 0
        dmsg.cost             = fail_cost
      end
      if p.id == "google" then
        local gc = Net.gemini_cache_debug_state(
          "response_empty", S.gemini_cache_last_used == true, tok_in_read)
        local req_gc = S.gemini_cache_last_state
        if type(req_gc) == "table" then
          gc.request_status = req_gc.status
          gc.request_reason = req_gc.reason
          gc.request_used   = req_gc.used == true
          gc.request_create_reason = req_gc.create_reason
        end
        dmsg.gemini_cache = gc
      end
      if S.request_start_time then
        dmsg.response_time = reaper.time_precise() - S.request_start_time
      end
    end
    -- This branch ends the turn with a visible error after recording
    -- response_time above, so clear the live elapsed timer before surfacing it.
    S.request_start_time = nil
    -- Pop the orphan user message that fired this empty turn. Without
    -- this, the user's manual retry (via the recovery row or by
    -- resending) appends a fresh user entry on top of the orphan and
    -- the next request's history shows the same user prompt twice
    -- (observed: msg [8] bare + msg [9] with snapshot). Auto-retry
    -- paths above (length-cap retry) already do their own pop, so
    -- this only fires when we're returning to idle without an internal
    -- retry. Defensive role check so we never pop an assistant entry.
    if #S.history > 0 and S.history[#S.history].role == "user" then
      S.history[#S.history] = nil
    end
    Log.add_error(msg, nil, nil, recovery_kind)
    return
  end

  -- Dispatch any <context_needed> request to the bucket handler. Returns true
  -- if a follow-up was fired (we bail and wait for the next poll tick).
  if Net.process_response_buckets(text) then return end

  -- Strip any leftover <context_needed> tag. Reaches here only when the
  -- bucket handler returned false (no follow-up fired), which now also
  -- includes the mixed-output case where the model emitted both the tag and
  -- substantive prose. The tag is then noise in the visible reply -- pull it
  -- out (and any trailing whitespace it leaves behind) so the user sees the
  -- prose cleanly.
  text = text:gsub("<%s*context_needed%s*>.-<%s*/%s*context_needed%s*>%s*", "")
  text = text:match("^%s*(.-)%s*$") or ""

  -- Normal final response: update token counters, build display entry, extract code.

  -- Ensure ctx_label is set on the user display entry.
  if S.pending_display_idx and S.display_messages[S.pending_display_idx] then
    local dmsg = S.display_messages[S.pending_display_idx]
    if not dmsg.ctx_label then dmsg.ctx_label = prefs.include_snapshot and "snapshot" or "" end
    if raw_tok_in > 0 or raw_tok_out > 0 then
      -- Accumulate token / cache / cost across multiple round-trips in the
      -- same turn. The docs-gate retry, beta-header fallback, and intra-
      -- turn context fetches all re-enter this block; without accumulation
      -- the visible Details tile shows ONLY the last request's metrics
      -- and the user can't see they paid for two requests when api_calls=2.
      -- Session totals add the raw per-call values directly so they don't
      -- double-count the accumulated dmsg fields.
      dmsg.tok_in           = (dmsg.tok_in           or 0) + raw_tok_in
      dmsg.tok_out          = (dmsg.tok_out          or 0) + raw_tok_out
      dmsg.tok_cache_read   = (dmsg.tok_cache_read   or 0) + tok_in_read
      dmsg.tok_cache_create = (dmsg.tok_cache_create or 0) + tok_in_create
      if p.id == "google" then
        local gc = Net.gemini_cache_debug_state(
          "response", S.gemini_cache_last_used == true, tok_in_read)
        local req_gc = S.gemini_cache_last_state
        if type(req_gc) == "table" then
          gc.request_status = req_gc.status
          gc.request_reason = req_gc.reason
          gc.request_used   = req_gc.used == true
          gc.request_create_reason = req_gc.create_reason
        end
        dmsg.gemini_cache = gc
      end
      S.session_tok_in        = S.session_tok_in  + raw_tok_in
      S.session_tok_out       = S.session_tok_out + raw_tok_out
      -- Cost estimation: look up model entry from the provider/model indices
      -- that were snapshotted at send time, with a fallback linear search.
      local tok_in_base = raw_tok_in - tok_in_read - tok_in_create
      local mentry = nil
      local pi = S.pending_provider_idx or prefs.provider_idx
      local mi = S.pending_model_idx or prefs.model_idx
      local prov = PROVIDERS[pi]
      if prov and prov.models[mi] then
        mentry = prov.models[mi]
      end
      if not mentry then
        mentry = MODELS[mi] or MODELS[1]
      end
      local this_cost = MODELS.calc_cost(
        mentry, tok_in_base, tok_in_read, tok_in_create, raw_tok_out)
      dmsg.cost = (dmsg.cost or 0) + this_cost
      -- Gemini Free Tier stamp: every request on the free API tier costs
      -- the user nothing, but the token-math estimate reflects the paid
      -- per-million rates. Record the free-tier context on the message so
      -- downstream renderers (chat details, debug log) can frame the cost
      -- as "would have been ~$X" instead of misleading the user into
      -- thinking they're being billed.
      if prov and prov.id == "google" and S.gemini_paid_tier == false then
        dmsg.free_tier = true
      end
      -- Session total skips free-tier exchanges. Otherwise the session
      -- counter in the footer would climb as if the user were paying,
      -- undermining the "free tier" label everywhere else in the UI.
      if not dmsg.free_tier then
        S.session_cost = S.session_cost + this_cost
      end
    end
    if S.request_start_time then
      dmsg.response_time = reaper.time_precise() - S.request_start_time
      -- DO NOT nil request_start_time here. The docs-gate auto-retry below
      -- re-fires a curl after this cleanup runs, and the in-flight
      -- "Thinking..." timer reads request_start_time to stay ticking
      -- across the silent retry. Nil-ing here would freeze the timer at
      -- 0:00 for the duration of the retry. The same logic applies to
      -- S.pending_display_idx (see comment below). Both are cleared at
      -- end-of-turn (status -> idle) at the bottom of Net.process_response.
    end
    if S._fx_cache_events then
      local parts = {}
      local order = { "hit", "cached" }
      local labels = { hit = "Hit", cached = "Cached" }
      for _, key in ipairs(order) do
        local names = S._fx_cache_events[key]
        if names and #names > 0 then
          parts[#parts+1] = labels[key] .. " (" .. tbl_concat(names, ", ") .. ")"
          -- Phase 1 instrumentation: log the COUNT only, not the
          -- plugin names. Privacy contract bars surfacing
          -- plugin/track names through the diagnostics record.
          for _ = 1, #names do
            Probe.add_fx_cache(S.probe_turn, key)
          end
        end
      end
      if #parts > 0 then
        dmsg.fx_cache_label = tbl_concat(parts, ", ")
      end
    end
    -- Mirror the details bubble into the debug log so users sharing the log
    -- see the same per-exchange metadata (cost, tokens, FX cache) as the UI.
    Log.exchange_summary(dmsg)
  end
  S._fx_cache_events = nil
  -- DO NOT nil S.pending_display_idx here. The docs-gate auto-retry below
  -- re-fires a curl, and Net.fire_curl reads pending_display_idx to
  -- increment dmsg.api_calls (the silent-retry counter shown in Details).
  -- The retry's response also re-enters this block to overwrite dmsg with
  -- the FINAL request's tokens / cost / time -- which is what the user
  -- actually got -- and the docs-gate appends "+ docs" to ctx_label via
  -- the same idx. Nil-ing here breaks all three. End-of-turn cleanup at
  -- the bottom of Net.process_response handles the actual clear.

  -- Before appending the assistant turn, strip any bucket content that was
  -- baked into the user history entry during mid-turn context fetches.
  -- Sticky data (plugin_ref / pref_plugins / fx_params / fx_inspect) lives
  -- in S.sticky_context and is emitted as a pinned prefix slot by
  -- build_body_*, so keeping it in history would duplicate those bytes on
  -- every subsequent turn's cache breakpoint. Restoring history[last] to
  -- just "USER REQUEST: <text>" keeps the moving cache prefix lean.
  if S.pending_orig_prompt
     and #S.history > 0
     and S.history[#S.history].role == "user" then
    S.history[#S.history].content = "USER REQUEST:\n" .. S.pending_orig_prompt
  end

  -- Store assistant turn in history.
  S.history[#S.history+1] = { role = "assistant", content = text }
  -- Capture the row index now so per-turn run metadata writes below
  -- (run_status, code_hash, truncated, compact_summary) all target the
  -- same row even if some sub-call appends a defensive history entry
  -- between here and the end of try_finish_curl. The metadata is read
  -- by Net.trimmed_history when the compact-history flag is on; turns
  -- without metadata default to "no_code" / not-eligible-for-compaction.
  local _asst_hist_idx = #S.history
  S.history[_asst_hist_idx].run_status = "no_code"
  -- Snapshot the user prompt now -- the cleanup block at the end of
  -- this function nils S.pending_orig_prompt before the compact-summary
  -- builder runs, which would drop the intent: line from every summary.
  local _compact_user_intent = S.pending_orig_prompt

  -- Extract fenced code blocks.
  -- A response may contain both a JSFX block and a Lua block (e.g. "create this
  -- effect and add it to track 5"). Extract them separately so JSFX can be
  -- auto-saved and the Lua companion script can be auto-run.
  local explanation = text

  -- 1. Extract JSFX blocks (```jsfx or ```eel fences).
  local jsfx_parts = {}
  for block in text:gmatch("```jsfx%s*\n(.-)\n%s*```") do
    jsfx_parts[#jsfx_parts+1] = block
  end
  if #jsfx_parts == 0 then
    for block in text:gmatch("```eel%s*\n(.-)\n%s*```") do
      jsfx_parts[#jsfx_parts+1] = block
    end
  end
  local jsfx_code = #jsfx_parts > 0 and tbl_concat(jsfx_parts, "\n\n") or nil

  -- 2. Extract Lua blocks (```lua or ```reascript fences).
  local lua_parts = {}
  for block in text:gmatch("```lua%s*\n(.-)\n%s*```") do
    lua_parts[#lua_parts+1] = block
  end
  if #lua_parts == 0 then
    for block in text:gmatch("```reascript%s*\n(.-)\n%s*```") do
      lua_parts[#lua_parts+1] = block
    end
  end
  local lua_code = #lua_parts > 0 and tbl_concat(lua_parts, "\n\n") or nil
  local lua_artifact_info = nil

  -- Recover once when a model returns apparent Lua but omits or breaks the
  -- ```lua fence. Never execute unfenced text directly: bare-Lua recovery is
  -- gated by a sandboxed syntax check, then the model must re-emit the same
  -- script through the normal fenced extraction path.
  if not lua_code and not jsfx_code and not S.pending_jsfx_intent then
    local function retry_lua_fence_retry(kind, previous_lua, ctx_label,
                                         log_tag, log_message, user_note,
                                         fail_message)
      if #S.history > 0 and S.history[#S.history].role == "assistant" then
        S.history[#S.history] = nil
      end
      if #S.history > 0 and S.history[#S.history].role == "user" then
        S.history[#S.history] = nil
      end
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: "
        .. user_note
        .. " Re-send the EXACT SAME script inside ONE complete "
        .. "```lua ... ``` block. Do NOT change logic, names, positions, "
        .. "plugins, parameters, values, or comments. Do NOT emit "
        .. "<context_needed> -- all reference data is already pinned. "
        .. "Respond as if this is your FIRST reply -- do NOT apologize, "
        .. "do NOT mention a retry.)\n\nPrevious " .. kind
        .. " Lua:\n```text\n"
        .. previous_lua
        .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
      S.history[#S.history+1] = { role = "user", content = history_content }
      Probe.add_validator_retry(S.probe_turn, "parse")
      Log.line(log_tag, log_message)
      if S.pending_display_idx
         and S.display_messages[S.pending_display_idx] then
        local dmsg = S.display_messages[S.pending_display_idx]
        local existing = dmsg.ctx_label or ""
        if not existing:find(ctx_label, 1, true) then
          dmsg.ctx_label = existing ~= ""
            and (existing .. " + " .. ctx_label) or ctx_label
        end
      end
      if prefs.include_snapshot then
        S.pending_project  = _resolve_pending_project()
        S.pending_snapshot = CTX.build_snapshot(S.pending_project,
          S.pending_jsfx_intent and { minimal_tracks = true } or nil)
      end
      S.status = "waiting"
      Net._ensure_request_start_time()
      Code.safe_write(tmp.out, "")
      local ok, reason = Net.fire_curl(Net.build_body(Net.trimmed_history(),
        S.pending_snapshot, S.pending_attachments))
      if not ok and reason ~= "call_cap_exceeded" then
        Log.add_error(fail_message)
      end
      S.scroll_to_bottom = true
      return true
    end

    local fence_retry_used = S.bare_lua_retry_used
      or S.unclosed_fence_retry_used
    local unclosed_lua = text:match("```lua%s*\n(.+)$")
      or text:match("```reascript%s*\n(.+)$")
    if unclosed_lua and not fence_retry_used then
      S.unclosed_fence_retry_used = true
      if retry_lua_fence_retry("incomplete fenced", unclosed_lua,
          "unclosed_fence_retry", "UNCLOSED-FENCE-RETRY",
          "lua fence was opened but not closed; asking model to resend exactly",
          "Your previous reply opened a Lua code fence but did not close it, "
            .. "so ReaAssist could not safely extract the script.",
          "Auto-retry after unclosed Lua fence did not go through. "
            .. "Please resend the last message.") then
        return
      end
    end

    local bare_lua = text:match("^%s*(.-)%s*$")
    local looks_like_lua = bare_lua ~= ""
      and bare_lua:find("reaper%.")
      and (bare_lua:find("reaper%.Undo_")
        or bare_lua:find("reaper%.AddProjectMarker")
        or bare_lua:find("reaper%.InsertTrackAtIndex")
        or bare_lua:find("local%s+function")
        or bare_lua:find("function%s+main"))
    if looks_like_lua and not fence_retry_used then
      local _chunk = load(bare_lua, "bare_lua_preflight", "t", {})
      if _chunk then
        S.bare_lua_retry_used = true
        if retry_lua_fence_retry("unfenced", bare_lua,
            "bare_lua_retry", "BARE-LUA-RETRY",
            "valid-looking bare Lua without fence; asking model to wrap exactly",
            "Your previous reply appears to be valid Lua, but it was not "
              .. "inside a ```lua code fence, so ReaAssist cannot safely "
              .. "extract or run it.",
            "Auto-retry after unfenced Lua response did not go through. "
              .. "Please resend the last message.") then
          return
        end
      end
    end
  end

  local validator_gate_hit = false

  -- High-confidence void-return API assignment validator. Some REAPER API
  -- calls mutate project state but do not return the object just created; if a
  -- model assigns that nil return and then uses it as a track/item handle, the
  -- script can silently do nothing. Retry once with the documented pattern.
  if lua_code and not S.void_return_retry_used then
    local stripped = lua_code
      :gsub("%-%-%[%[.-%]%]", "")
      :gsub("%-%-[^\n]*", "")
    local void_funcs = {
      InsertTrackAtIndex = "InsertTrackAtIndex returns no track. Call it as a statement, then call reaper.GetTrack(0, index).",
    }
    local bad_name, bad_note
    for name, note in pairs(void_funcs) do
      local call_pat = "reaper%." .. name .. "%s*%("
      local assign_target = "[%a_][%w_%.%[%]%\"']*"
      local local_assign = "local%s+" .. assign_target .. "%s*=%s*" .. call_pat
      local plain_assign = "[\n;]%s*" .. assign_target .. "%s*=%s*" .. call_pat
      if stripped:find(local_assign) or stripped:find(plain_assign) then
        bad_name, bad_note = name, note
        break
      end
    end
    if bad_name then
      S.void_return_retry_used = true
      S.void_return_validator_retries =
        (S.void_return_validator_retries or 0) + 1
      Probe.add_validator_retry(S.probe_turn, "api")
      Log.line("VOID-RETURN-RETRY",
        "void-return API assignment to reaper." .. bad_name
        .. "; retrying with hint")
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: Your previous "
        .. "reply assigned the return value of reaper." .. bad_name .. "(), "
        .. "but that function does not return the object you need. "
        .. bad_note .. " Preserve the user's requested tracks, names, "
        .. "plugins, parameter values, MIDI notes, markers, routing, and "
        .. "ordering. Only fix the void-return API usage unless another "
        .. "change is required to make the script valid. Respond as if "
        .. "this is your FIRST reply -- do NOT apologize, do NOT mention "
        .. "a retry.)\n\nPrevious Lua to fix:\n```lua\n"
        .. lua_code
        .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
      if #S.history > 0 and S.history[#S.history].role == "assistant" then
        S.history[#S.history] = nil
      end
      if #S.history > 0 and S.history[#S.history].role == "user" then
        S.history[#S.history] = nil
      end
      S.history[#S.history+1] = { role = "user", content = history_content }
      if S.pending_display_idx
         and S.display_messages[S.pending_display_idx] then
        local dmsg = S.display_messages[S.pending_display_idx]
        local existing = dmsg.ctx_label or ""
        if not existing:find("void_return_retry", 1, true) then
          dmsg.ctx_label = existing ~= ""
            and (existing .. " + void_return_retry") or "void_return_retry"
        end
      end
      if prefs.include_snapshot then
        S.pending_project  = _resolve_pending_project()
        S.pending_snapshot = CTX.build_snapshot(S.pending_project,
          S.pending_jsfx_intent and { minimal_tracks = true } or nil)
      end
      S.status = "waiting"
      Net._ensure_request_start_time()
      Code.safe_write(tmp.out, "")
      local ok, reason = Net.fire_curl(Net.build_body(Net.trimmed_history(),
        S.pending_snapshot, S.pending_attachments))
      if not ok and reason ~= "call_cap_exceeded" then
        Log.add_error("Auto-retry after void-return API assignment did not go "
          .. "through. Please resend the last message.")
      end
      S.scroll_to_bottom = true
      return
    end
  end

  -- High-confidence create-track intent validator. Some weaker models answer a
  -- "create tracks" prompt by fetching GetTrack(0, 0/1) and renaming those
  -- handles, which passes syntax but does nothing in an empty project.
  if lua_code
      and not S.track_creation_retry_used
      and Code.prompt_requests_track_creation(S.pending_orig_prompt)
      and not Code.lua_creates_tracks(lua_code) then
    S.track_creation_retry_used = true
    S.track_creation_validator_retries =
      (S.track_creation_validator_retries or 0) + 1
    Probe.add_validator_retry(S.probe_turn, "api")
    Log.line("TRACK-CREATION-RETRY",
      "track-creation prompt without InsertTrackAtIndex; retrying with hint")
    local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
      .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user asked you "
      .. "to create one or more tracks, but your previous script only "
      .. "looked up existing tracks with reaper.GetTrack(...) and renamed "
      .. "them. That is inert when the project has no matching existing "
      .. "tracks. For each requested new track, call "
      .. "reaper.InsertTrackAtIndex(index, true) as a statement, then get "
      .. "the created track with reaper.GetTrack(0, index) and set its "
      .. "name. Preserve the requested order, exact track names, plugins, "
      .. "sends, markers, MIDI notes, and selections. Respond as if this "
      .. "is your FIRST reply -- do NOT apologize, do NOT mention a "
      .. "retry.)\n\nPrevious Lua to fix:\n```lua\n"
      .. lua_code
      .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
    if #S.history > 0 and S.history[#S.history].role == "assistant" then
      S.history[#S.history] = nil
    end
    if #S.history > 0 and S.history[#S.history].role == "user" then
      S.history[#S.history] = nil
    end
    S.history[#S.history+1] = { role = "user", content = history_content }
    if S.pending_display_idx
       and S.display_messages[S.pending_display_idx] then
      local dmsg = S.display_messages[S.pending_display_idx]
      local existing = dmsg.ctx_label or ""
      if not existing:find("track_creation_retry", 1, true) then
        dmsg.ctx_label = existing ~= ""
          and (existing .. " + track_creation_retry")
          or "track_creation_retry"
      end
    end
    if prefs.include_snapshot then
      S.pending_project  = _resolve_pending_project()
      S.pending_snapshot = CTX.build_snapshot(S.pending_project,
        S.pending_jsfx_intent and { minimal_tracks = true } or nil)
    end
    S.status = "waiting"
    Net._ensure_request_start_time()
    Code.safe_write(tmp.out, "")
    local ok, reason = Net.fire_curl(Net.build_body(Net.trimmed_history(),
      S.pending_snapshot, S.pending_attachments))
    if not ok and reason ~= "call_cap_exceeded" then
      Log.add_error("Auto-retry after inert track-creation script did not go "
        .. "through. Please resend the last message.")
    end
    S.scroll_to_bottom = true
    return
  end

  if lua_code
      and Code.prompt_requests_track_creation(S.pending_orig_prompt) then
    local bad_created_track_indices =
      Code.find_track_creation_index_misuse(lua_code, S.pending_orig_prompt,
        S.pending_snapshot)
    if bad_created_track_indices and #bad_created_track_indices > 0
        and not S.track_creation_index_retry_used then
      S.track_creation_index_retry_used = true
      S.track_creation_validator_retries =
        (S.track_creation_validator_retries or 0) + 1
      Probe.add_validator_retry(S.probe_turn, "api")
      local finding = bad_created_track_indices[1]
      Log.line("TRACK-CREATION-INDEX-RETRY",
        "new-track GetTrack index can be nil on line "
        .. tostring(finding.line or "?") .. "; retrying with creation-index hint")
      local details = {}
      for _, e in ipairs(bad_created_track_indices) do
        details[#details + 1] =
          "line " .. tostring(e.line or "?")
