  -- FX-CHECK VALIDATOR: After the API/arity validators pass, scan
  -- generated code for `local NAME = reaper.(Track|Take)FX_AddByName(...)`
  -- where NAME is never tested in a failure-direction comparison
  -- (NAME < 0 / NAME == -1 / NAME <= -1 / NAME < -1). Catches two
  -- silent-success patterns the model has shown:
  --   1. local fx = TrackFX_AddByName(...); -- no check, downstream
  --      use assumes fx is valid; failure produces silent skip + script
  --      reports OK.
  --   2. local fx = TrackFX_AddByName(...); if fx >= 0 then ... end
  --      with no else and no error -- the success-direction-only check
  --      means a failed AddByName silently skips configuration. The
  --      script appears to succeed but the chain is broken.
  -- Same recovery shape as the other validators: hidden retry with a
  -- focused hint, single retry per turn, auto-run blocked + visible
  -- error if the retry still fails. GetByName is intentionally NOT
  -- covered: returning -1 from GetByName is a legitimate "not present"
  -- signal in upsert patterns; flagging it would break the chain-build
  -- workflow this rule is meant to protect.
  local fxcheck_gate_hit = false
  if lua_code and not docs_gate_hit and not validator_gate_hit
     and not arity_gate_hit and not sendidx_gate_hit
     and not stockfx_gate_hit and not fxident_gate_hit then
    local unchecked = Code.find_unchecked_addbyname_results(lua_code)
    if unchecked and #unchecked > 0 then
      if (S.fxcheck_validator_retries or 0) < 1 then
        S.fxcheck_validator_retries = (S.fxcheck_validator_retries or 0) + 1
        Probe.add_validator_retry(S.probe_turn, "fxcheck")
        local lines = {}
        for _, e in ipairs(unchecked) do
          if e.unassigned then
            lines[#lines+1] = "  - unassigned TrackFX_AddByName / "
              .. "TakeFX_AddByName result near line " .. e.line
          else
            lines[#lines+1] = "  - " .. e.name
              .. " (assigned from TrackFX_AddByName / TakeFX_AddByName near "
              .. "line " .. e.line .. ")"
          end
        end
        Log.line("FX-CHECK-VALIDATOR",
          "unchecked AddByName result(s) (" .. #unchecked .. "): "
          .. (function()
              local names = {}
              for _, e in ipairs(unchecked) do names[#names+1] = e.name end
              return tbl_concat(names, ", ")
            end)()
          .. "; retrying with hint (user-invisible)")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT MENTION "
          .. "ANY OF THIS IN YOUR VISIBLE REPLY: Your previous reply called "
          .. "TrackFX_AddByName / TakeFX_AddByName without preserving and "
          .. "testing every result in a failure-direction comparison "
          .. "(`fx < 0`, `fx == -1`, `fx <= -1`). "
          .. "If the plugin fails to load, AddByName returns -1 and "
          .. "downstream code that assumes the fx is valid will silently "
          .. "produce the wrong result -- the script will report 'OK' "
          .. "while the user sees a missing or broken effect chain.\n\n"
          .. "Affected variable(s):\n"
          .. tbl_concat(lines, "\n") .. "\n\n"
          .. "Regenerate the code with an explicit failure check on EACH "
          .. "AddByName result. The standard pattern is:\n"
          .. "  local fx = reaper.TrackFX_AddByName(tr, ID, false, -1)\n"
          .. "  if fx < 0 then\n"
          .. "    reaper.ShowMessageBox(\"Failed to add <name>.\", "
          .. "\"ReaAssist\", 0)\n"
          .. "    return\n"
          .. "  end\n\n"
          .. "Do NOT use `if fx >= 0 then ... end` with no `else` -- that "
          .. "is the silent-skip anti-pattern this validator is catching. "
          .. "Either fail explicitly with ShowMessageBox + return on `< 0`, "
          .. "or track the failure in an errors list and report it at the "
          .. "end. Respond as if this is your FIRST reply -- do NOT "
          .. "apologize, do NOT mention a retry.)\n\n"
          .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
        if #S.history > 0 and S.history[#S.history].role == "assistant" then
          S.history[#S.history] = nil
        end
        if #S.history > 0 and S.history[#S.history].role == "user" then
          S.history[#S.history] = nil
        end
        S.history[#S.history+1] = { role = "user", content = history_content }
        if S.pending_display_idx
           and S.display_messages[S.pending_display_idx] then
          local dmsg = S.display_messages[S.pending_display_idx]
          local existing = dmsg.ctx_label or ""
          if not existing:find("fxcheck_retry", 1, true) then
            dmsg.ctx_label = existing ~= ""
              and (existing .. " + fxcheck_retry") or "fxcheck_retry"
          end
        end
        if prefs.include_snapshot then
          S.pending_project  = _resolve_pending_project()
          S.pending_snapshot = CTX.build_snapshot(S.pending_project,
            S.pending_jsfx_intent and { minimal_tracks = true } or nil)
        end
        S.status = "waiting"
        Code.safe_write(tmp.out, "")
        local ok, reason = Net.fire_curl(Net.build_body(Net.trimmed_history(),
          S.pending_snapshot, S.pending_attachments))
        if not ok and reason ~= "call_cap_exceeded" then
          Log.add_error("Auto-retry for unchecked AddByName result did "
            .. "not go through. Please resend the last message.")
        end
        S.scroll_to_bottom = true
        return
      end
      fxcheck_gate_hit = true
      Log.line("FX-CHECK-VALIDATOR",
        "unchecked AddByName result(s) persist after retry; auto-run blocked")
      local user_lines = {}
      for _, e in ipairs(unchecked) do
        user_lines[#user_lines+1] = e.name .. " (line ~" .. e.line .. ")"
      end
      Log.add_error("The model wrote TrackFX_AddByName / TakeFX_AddByName "
        .. "without checking the result, even after a retry: "
        .. tbl_concat(user_lines, ", ")
        .. ". If the plugin fails to load the script will silently report "
        .. "success. Auto-run is blocked; review and edit the code before "
        .. "clicking Run manually.")
    end
  end

  -- UPSERT VALIDATOR: Gated on chain-build follow-up turns -- when the
  -- prompt matches CHAIN_PHRASE_HINTS AND fx_chains was preempted (so
  -- prior plugins may already be on the target track from earlier
  -- turns). In that context, every plugin name in the script must
  -- appear in BOTH a TrackFX_GetByName AND a TrackFX_AddByName call.
  -- Catches the two opposite anti-patterns observed across providers
  -- in chain-build flows: Get-only with early bail (ChatGPT pattern)
  -- and Add-only without reuse check (Claude pattern). Both fail the
  -- user's "build me a chain" intent in different ways.
  local upsert_gate_hit = false
  local function _is_chain_build_prompt(t)
    if not t or t == "" then return false end
    local lo = t:lower()
    for _, hint in ipairs(CHAIN_PHRASE_HINTS) do
      if lo:find(hint[1]) then return true end
    end
    return false
  end
  if lua_code and not docs_gate_hit and not validator_gate_hit
     and not arity_gate_hit and not sendidx_gate_hit and not stockfx_gate_hit
     and not fxcheck_gate_hit
     and S.fx_chains_already_sent
     and _is_chain_build_prompt(S.pending_orig_prompt) then
    local upsert_bad = Code.find_chain_upsert_violations(lua_code)
    if upsert_bad and #upsert_bad > 0 then
      if (S.upsert_validator_retries or 0) < 1 then
        S.upsert_validator_retries = (S.upsert_validator_retries or 0) + 1
        Probe.add_validator_retry(S.probe_turn, "upsert")
        local lines = {}
        for _, e in ipairs(upsert_bad) do
          if e.kind == "get_only" then
            lines[#lines+1] = "  - " .. e.id
              .. ": GetByName called but no AddByName fallback if missing"
          else
            lines[#lines+1] = "  - " .. e.id
              .. ": AddByName called without GetByName reuse check"
          end
        end
        Log.line("UPSERT-VALIDATOR",
          "chain-upsert violations (" .. #upsert_bad .. "); retrying with "
          .. "hint (user-invisible)")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT MENTION "
          .. "ANY OF THIS IN YOUR VISIBLE REPLY: This is a chain-build "
          .. "follow-up turn (the prompt matched a chain phrase like "
          .. "\"build a vocal chain\" / \"set up a chain\"), and an earlier "
          .. "turn may have already placed plugins on the target track. "
          .. "fx_chains is pinned above so you can see what's currently "
          .. "there. Your previous reply violated the upsert pairing rule:\n"
          .. tbl_concat(lines, "\n") .. "\n\n"
          .. "Required pattern for EACH plugin in the chain:\n"
          .. "  local fx = reaper.TrackFX_GetByName(tr, \"<bare display "
          .. "name>\", false)\n"
          .. "  if fx < 0 then\n"
          .. "    fx = reaper.TrackFX_AddByName(tr, \"<format-prefixed "
          .. "AddByName id>\", false, -1)\n"
          .. "  end\n"
          .. "  if fx < 0 then\n"
          .. "    reaper.ShowMessageBox(\"Failed to load <name>.\", "
          .. "\"ReaAssist\", 0)\n"
          .. "    return\n"
          .. "  end\n\n"
          .. "Do NOT call GetByName for all plugins and bail with \"missing "
          .. "one or more plugins\" -- that fails the user's request to "
          .. "BUILD the chain. Do NOT call AddByName without GetByName "
          .. "first either -- that duplicates plugins already on the track. "
          .. "EVERY plugin in the chain needs both calls. Do NOT emit "
          .. "<context_needed> -- all reference data is already pinned "
          .. "(check PINNED REFERENCES manifest above). Regenerate the "
          .. "FULL script NOW. Respond as if this is your FIRST reply -- "
          .. "do NOT apologize, do NOT mention a retry.)\n\n"
          .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
        if #S.history > 0 and S.history[#S.history].role == "assistant" then
          S.history[#S.history] = nil
        end
        if #S.history > 0 and S.history[#S.history].role == "user" then
          S.history[#S.history] = nil
        end
        S.history[#S.history+1] = { role = "user", content = history_content }
        if S.pending_display_idx
           and S.display_messages[S.pending_display_idx] then
          local dmsg = S.display_messages[S.pending_display_idx]
          local existing = dmsg.ctx_label or ""
          if not existing:find("upsert_retry", 1, true) then
            dmsg.ctx_label = existing ~= ""
              and (existing .. " + upsert_retry") or "upsert_retry"
          end
        end
        if prefs.include_snapshot then
          S.pending_project  = _resolve_pending_project()
          S.pending_snapshot = CTX.build_snapshot(S.pending_project,
            S.pending_jsfx_intent and { minimal_tracks = true } or nil)
        end
        S.status = "waiting"
        Code.safe_write(tmp.out, "")
        local ok, reason = Net.fire_curl(Net.build_body(Net.trimmed_history(),
          S.pending_snapshot, S.pending_attachments))
        if not ok and reason ~= "call_cap_exceeded" then
          Log.add_error("Auto-retry for chain-upsert violation did not "
            .. "go through. Please resend the last message.")
        end
        S.scroll_to_bottom = true
        return
      end
      upsert_gate_hit = true
      Log.line("UPSERT-VALIDATOR",
        "chain-upsert violations persist after retry; auto-run blocked")
      Log.add_error("The model wrote chain-build code with an upsert "
        .. "pairing violation, even after a retry. Each plugin in the "
        .. "chain needs both a GetByName (reuse) and an AddByName (add "
        .. "if missing) call. Auto-run is blocked; review and edit the "
        .. "code before clicking Run manually.")
    end
  end

  -- DEFER VALIDATOR: After the API validator passes, scan the generated
  -- script for plugin-param Get/Set calls outside reaper.defer(function()
  -- ... end). Per the MANDATORY DEFER RULE in prompt_bundle:plugin, those
  -- calls MUST run inside a deferred callback -- some VST3 plugins silently
  -- ignore parameter writes that arrive in the same execution frame as
  -- TrackFX_AddByName. Without defer, the script appears to succeed (the
  -- API-VALIDATOR scan passes, "Script completed OK" gets logged) but the
  -- audio doesn't change. Observed in the cross-provider test matrix on
  -- gpt-5.4-mini with thinking=none -- the script ran cleanly and was
  -- behaviorally wrong. Same recovery shape as the API validator: model-
  -- only nudge, scrub the bad turn from history, single retry per user
  -- prompt, surface a visible error if the retry still fails.
  local defer_gate_hit = false
  if lua_code and not docs_gate_hit and not validator_gate_hit
     and not arity_gate_hit and not sendidx_gate_hit and not stockfx_gate_hit
     and not fxcheck_gate_hit and not upsert_gate_hit then
    local violations = Code.find_param_calls_outside_defer(lua_code)
    if violations and #violations > 0 then
      if (S.defer_validator_retries or 0) < 1 then
        S.defer_validator_retries = (S.defer_validator_retries or 0) + 1
        Probe.add_validator_retry(S.probe_turn, "defer")
        Log.line("DEFER-VALIDATOR",
          "param-touching calls outside reaper.defer (" .. #violations
          .. "): " .. tbl_concat(violations, ", ")
          .. "; retrying with hint (user-invisible)")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT MENTION "
          .. "ANY OF THIS IN YOUR VISIBLE REPLY: Your previous reply called "
          .. "REAPER plugin parameter functions OUTSIDE a reaper.defer() "
          .. "block. Per the MANDATORY DEFER RULE in your plugin workflow, "
          .. "these calls MUST run inside `reaper.defer(function() ... end)`:\n"
          .. "  - reaper." .. tbl_concat(violations, "\n  - reaper.")
          .. "\n\nWithout defer, some VST3 plugins silently ignore parameter "
          .. "changes -- the script appears to succeed but the audio doesn't "
          .. "change. Regenerate the code with all plugin param Get/Set "
          .. "calls inside a reaper.defer block.\n\n"
          .. "Required structure:\n"
          .. "  1. In the main body: create tracks/items/sends, add or find "
          .. "FX, and store any returned FX/send indices in variables.\n"
          .. "  2. Then use exactly one `reaper.defer(function() ... end)` "
          .. "callback for every plugin parameter read/write.\n"
          .. "  3. Put `reaper.TrackFX_SetParam*`, `reaper.TrackFX_GetParam*`, "
          .. "`reaper.TrackFX_GetFormattedParamValue`, and helper calls such "
          .. "as `set_param_display(...)` inside that callback.\n"
          .. "  4. `Undo_EndBlock`, `UpdateArrange`, and `PreventUIRefresh(-1)` "
          .. "may run after the parameter writes in that same callback.\n\n"
          .. "This is STILL WRONG and will be rejected: doing track/FX work "
          .. "and parameter writes in the main body, then deferring only "
          .. "`Undo_EndBlock`, `UpdateArrange`, or cleanup. Deferring cleanup "
          .. "does not defer the parameter writes.\n\n"
          .. "Correct skeleton:\n"
          .. "  reaper.Undo_BeginBlock()\n"
          .. "  reaper.PreventUIRefresh(1)\n"
          .. "  -- main body: create tracks, add FX, create sends, store "
          .. "indices\n"
          .. "  reaper.defer(function()\n"
          .. "    -- ALL TrackFX_Get/SetParam calls go here\n"
          .. "    reaper.PreventUIRefresh(-1)\n"
          .. "    reaper.UpdateArrange()\n"
          .. "    reaper.Undo_EndBlock(\"ReaAssist: ...\", -1)\n"
          .. "  end)\n\n"
          .. "Respond as if this is your FIRST "
          .. "reply to the user's request -- do NOT apologize, do NOT say "
          .. "'let me try again' or mention a retry. Just deliver the "
          .. "correct code with a normal brief description.)\n\n"
          .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
        if #S.history > 0 and S.history[#S.history].role == "assistant" then
          S.history[#S.history] = nil
        end
        if #S.history > 0 and S.history[#S.history].role == "user" then
          S.history[#S.history] = nil
        end
        S.history[#S.history+1] = { role = "user", content = history_content }
        if S.pending_display_idx
           and S.display_messages[S.pending_display_idx] then
          local dmsg = S.display_messages[S.pending_display_idx]
          local existing = dmsg.ctx_label or ""
          if not existing:find("defer_retry", 1, true) then
            dmsg.ctx_label = existing ~= ""
              and (existing .. " + defer_retry") or "defer_retry"
          end
        end
        if prefs.include_snapshot then
          S.pending_project  = _resolve_pending_project()
          -- See JSFX-intent comment on the analogous retry sites above:
          -- carry pending_jsfx_intent across snapshot rebuilds so the trim
          -- survives every retry path, not just the JSFX-validator's.
          S.pending_snapshot = CTX.build_snapshot(S.pending_project,
            S.pending_jsfx_intent and { minimal_tracks = true } or nil)
        end
        S.status = "waiting"
        Code.safe_write(tmp.out, "")
        local ok, reason = Net.fire_curl(Net.build_body(Net.trimmed_history(),
          S.pending_snapshot, S.pending_attachments))
        if not ok and reason ~= "call_cap_exceeded" then
          Log.add_error("Auto-retry for missing reaper.defer wrap did not "
            .. "go through. Please resend the last message.")
        end
        S.scroll_to_bottom = true
        return
      end
      -- Retry already used and the model STILL has param calls outside
      -- defer. Block auto-run + surface the diagnostic so the user can
      -- review/edit before clicking Run manually.
      defer_gate_hit = true
      Log.line("DEFER-VALIDATOR",
        "param-touching calls still outside defer after retry: "
        .. tbl_concat(violations, ", ") .. "; auto-run blocked")
      Log.add_error("The model emitted plugin parameter calls (reaper."
        .. tbl_concat(violations, ", reaper.")
        .. ") outside a reaper.defer() block, even after a retry. "
        .. "Some VST3 plugins silently ignore parameter changes that "
        .. "arrive in the same execution frame as TrackFX_AddByName -- "
        .. "the script may appear to run successfully but produce no "
        .. "audible change. Auto-run is blocked; review the code and "
        .. "wrap the param calls in `reaper.defer(function() ... end)` "
        .. "before clicking Run manually.")
    end
  end

  -- ADD-ONLY FX PARAM-SCOPE VALIDATOR: A passing script can still be too
  -- aggressive if the user only asked to add/load an FX and the model invents
  -- "helpful" default parameter writes. Retry once with an add-only correction
  -- before the script reaches auto-run.
  local fx_param_scope_gate_hit = false
  if lua_code and not docs_gate_hit and not validator_gate_hit
     and not arity_gate_hit and not sendidx_gate_hit and not stockfx_gate_hit
     and not fxcheck_gate_hit and not upsert_gate_hit and not defer_gate_hit
     and Code.prompt_is_fx_add_only(S.pending_orig_prompt or "")
     and Code.lua_has_fx_param_writes(lua_code) then
    if (S.fx_param_scope_validator_retries or 0) < 1 then
      S.fx_param_scope_validator_retries =
        (S.fx_param_scope_validator_retries or 0) + 1
      Probe.add_validator_retry(S.probe_turn, "fx_param_scope")
      Log.line("FX-PARAM-SCOPE-VALIDATOR",
        "add-only FX prompt emitted parameter writes; retrying")
      local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT "
        .. "MENTION ANY OF THIS IN YOUR VISIBLE REPLY: The user only asked "
        .. "to add/load/insert the FX. Your previous script wrote plugin "
        .. "parameters, which is extra configuration the user did not request. "
        .. "Regenerate the script without TrackFX_SetParam*, "
        .. "TakeFX_SetParam*, set_param_display, set_param_enum, or "
        .. "set_param_enum_paced. Preserve the requested tracks, FX, sends, "
        .. "items, MIDI, markers, and ordering. Keep required plugin-load "
        .. "checks. Respond as if this is your FIRST reply -- do NOT "
        .. "apologize or mention a retry.)\n\nPrevious Lua to fix:\n```lua\n"
        .. lua_code
        .. "\n```\n\nUSER REQUEST:\n" .. (S.pending_orig_prompt or "")
      if #S.history > 0 and S.history[#S.history].role == "assistant" then
        S.history[#S.history] = nil
      end
      if #S.history > 0 and S.history[#S.history].role == "user" then
        S.history[#S.history] = nil
      end
      S.history[#S.history+1] = { role = "user", content = history_content }
      if S.pending_display_idx
         and S.display_messages[S.pending_display_idx] then
        local dmsg = S.display_messages[S.pending_display_idx]
        local existing = dmsg.ctx_label or ""
        if not existing:find("fx_param_scope_retry", 1, true) then
          dmsg.ctx_label = existing ~= ""
            and (existing .. " + fx_param_scope_retry")
            or "fx_param_scope_retry"
        end
      end
      if prefs.include_snapshot then
        S.pending_project  = _resolve_pending_project()
        S.pending_snapshot = CTX.build_snapshot(S.pending_project,
          S.pending_jsfx_intent and { minimal_tracks = true } or nil)
      end
      S.status = "waiting"
      Code.safe_write(tmp.out, "")
      local ok, reason = Net.fire_curl(Net.build_body(Net.trimmed_history(),
        S.pending_snapshot, S.pending_attachments))
      if not ok and reason ~= "call_cap_exceeded" then
        Log.add_error("Auto-retry after unrequested FX parameter writes did "
          .. "not go through. Please resend the last message.")
      end
      S.scroll_to_bottom = true
      return
    end
    fx_param_scope_gate_hit = true
    Log.line("FX-PARAM-SCOPE-VALIDATOR",
      "unrequested FX parameter writes persisted after retry; auto-run blocked")
    Log.add_error("The model wrote plugin parameter changes even though the "
      .. "request only asked to add/load the FX. Auto-run is blocked because "
      .. "those extra parameter writes may change the sound beyond the user's "
      .. "request. Review and remove the TrackFX_SetParam*/TakeFX_SetParam* "
      .. "lines before running manually.")
  end

  -- HELPER-DEFINITION VALIDATOR: After defer-compliance check, scan for
  -- helper function calls (find_param, set_param_display, set_param_enum,
  -- set_param_enum_paced) that lack a matching `local function NAME(`
  -- definition in the same script. The model has seen these helpers in
  -- training data and CAN write the calls from memory without including
  -- the source -- producing a runtime `attempt to call a nil value` crash
  -- on the deferred tick. The plugin_helpers prompt bundle is the source
  -- of truth; this validator catches the case where the call ships without
  -- the definition. Same recovery shape as the other validators: model-
  -- only nudge with the helper bundle pinned, single retry per turn,
  -- auto-run block + visible error if it persists.
  local helper_gate_hit = false
  if lua_code and not docs_gate_hit and not validator_gate_hit
     and not arity_gate_hit and not sendidx_gate_hit and not stockfx_gate_hit
     and not fxcheck_gate_hit and not upsert_gate_hit and not defer_gate_hit
     and not fx_param_scope_gate_hit then
    local missing = Code.find_helper_calls_without_definition(lua_code)
    if missing and #missing > 0 then
      if (S.helper_validator_retries or 0) < 1 then
        S.helper_validator_retries = (S.helper_validator_retries or 0) + 1
        Probe.add_validator_retry(S.probe_turn, "helper")
        Log.line("HELPER-VALIDATOR",
          "helper calls without definitions (" .. #missing .. "): "
          .. tbl_concat(missing, ", ")
          .. "; pinning prompt_bundle:plugin_helpers + retrying (user-invisible)")
        -- Co-pin helpers in case they aren't already pinned -- the model
        -- needs the source to copy into the retry script.
        Net.copin_plugin_helpers(nil)
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT MENTION "
          .. "ANY OF THIS IN YOUR VISIBLE REPLY: Your previous reply called "
          .. "helper function(s) without a usable in-script definition. The "
          .. "definition was either missing OR placed LEXICALLY AFTER the "
          .. "first call site -- in Lua, a `local function NAME(...)` "
          .. "declared after the line that calls it is not yet a visible "
          .. "local at that line, so the call compiles to a global lookup "
          .. "and crashes at runtime with `attempt to call a nil value`. "
          .. "Confirmed in the deferred callback inside main().\n\n"
          .. "Affected helper(s):\n  - "
          .. tbl_concat(missing, "\n  - ")
          .. "\n\nThe definitions are ALREADY PRESENT in `prompt_bundle:"
          .. "plugin_helpers` (pinned above). Do NOT emit "
          .. "<context_needed>prompt_bundle:plugin_helpers</context_needed> "
          .. "or any other <context_needed> tag -- the data you need is "
          .. "already in this request. Regenerate the FULL script NOW with "
          .. "EACH called helper's `local function NAME(...) ... end` source "
          .. "pasted at the TOP of the script -- BEFORE `local function "
          .. "main()` and BEFORE any function body that calls it. Only "
          .. "include the helpers you actually call. Respond as if this is "
          .. "your FIRST reply to the user's request -- do NOT apologize, "
          .. "do NOT say 'let me try again', do NOT mention a retry, do "
          .. "NOT emit <context_needed>.)\n\n"
          .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
        if #S.history > 0 and S.history[#S.history].role == "assistant" then
          S.history[#S.history] = nil
        end
        if #S.history > 0 and S.history[#S.history].role == "user" then
          S.history[#S.history] = nil
        end
        S.history[#S.history+1] = { role = "user", content = history_content }
        if S.pending_display_idx
           and S.display_messages[S.pending_display_idx] then
          local dmsg = S.display_messages[S.pending_display_idx]
          local existing = dmsg.ctx_label or ""
          if not existing:find("helper_retry", 1, true) then
            dmsg.ctx_label = existing ~= ""
              and (existing .. " + helper_retry") or "helper_retry"
          end
        end
        if prefs.include_snapshot then
          S.pending_project  = _resolve_pending_project()
          -- See JSFX-intent comment on the analogous retry sites above:
          -- carry pending_jsfx_intent across snapshot rebuilds so the trim
          -- survives every retry path, not just the JSFX-validator's.
          S.pending_snapshot = CTX.build_snapshot(S.pending_project,
            S.pending_jsfx_intent and { minimal_tracks = true } or nil)
        end
        S.status = "waiting"
        Code.safe_write(tmp.out, "")
        local ok, reason = Net.fire_curl(Net.build_body(Net.trimmed_history(),
          S.pending_snapshot, S.pending_attachments))
        if not ok and reason ~= "call_cap_exceeded" then
          Log.add_error("Auto-retry for missing helper definitions did not "
            .. "go through. Please resend the last message.")
        end
        S.scroll_to_bottom = true
        return
      end
      -- Retry already used and the model STILL emitted helper calls without
      -- definitions. Block auto-run + surface diagnostic.
      helper_gate_hit = true
      Log.line("HELPER-VALIDATOR",
        "helper calls still missing definitions after retry: "
        .. tbl_concat(missing, ", ") .. "; auto-run blocked")
      Log.add_error("The model called helper function(s) without including "
        .. "their definitions, even after a retry: "
        .. tbl_concat(missing, ", ")
        .. ". These are local functions (not REAPER built-ins), so the "
        .. "script will crash at runtime with 'attempt to call a nil value' "
        .. "when these are reached. Auto-run is blocked; either paste the "
        .. "helper function definitions from prompt_bundle:plugin_helpers "
        .. "into the script before clicking Run, or refactor to use "
        .. "SetParamNormalized directly with verified normalized values.")
    end
  end

  -- HELPER-INTEGRITY VALIDATOR: After the helper-validator confirms each
  -- called helper has a definition, check that the definition matches the
  -- canonical body in prompt_bundle:plugin_helpers. Models occasionally
  -- rewrite or simplify pasted helper bodies in subtly broken ways --
  -- observed: ChatGPT 5.4 Mini dropped the parens on set_param_display's
  -- range guard ("vmin and vmax and target < vmin or target > vmax"
  -- instead of "... and (target < vmin or target > vmax)"). Lua's and/or
  -- precedence makes the bad form crash with "attempt to compare nil
  -- with number" inside reaper.defer, AFTER Code.run has already logged
  -- "Script completed OK." Same recovery shape as the other validators.
  local helper_int_gate_hit = false
  if lua_code and not docs_gate_hit and not validator_gate_hit
     and not arity_gate_hit and not sendidx_gate_hit and not stockfx_gate_hit
     and not fxcheck_gate_hit and not upsert_gate_hit and not defer_gate_hit
     and not fx_param_scope_gate_hit and not helper_gate_hit then
    local int_bad = Code.find_helper_integrity_violations(lua_code)
    if int_bad and #int_bad > 0 then
      if (S.helper_int_validator_retries or 0) < 1 then
        S.helper_int_validator_retries = (S.helper_int_validator_retries or 0) + 1
        Probe.add_validator_retry(S.probe_turn, "helper_int")
        local lines = {}
        for _, e in ipairs(int_bad) do
          lines[#lines+1] = "  - " .. e.name
            .. " (missing canonical fragment: `" .. e.missing .. "`)"
        end
        Log.line("HELPER-INTEGRITY-VALIDATOR",
          "rewritten/corrupted helper body (" .. #int_bad
          .. "); retrying with hint (user-invisible)")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT MENTION "
          .. "ANY OF THIS IN YOUR VISIBLE REPLY: Your previous reply pasted "
          .. "a bundled helper function but rewrote its body in a way that "
          .. "drops a required safety guard. Affected helper(s):\n"
          .. tbl_concat(lines, "\n") .. "\n\n"
          .. "Helpers in `prompt_bundle:plugin_helpers` are designed to be "
          .. "pasted VERBATIM from the bundle source. Do NOT rewrite, "
          .. "simplify, or paraphrase the body. The exact parenthesization "
          .. "of boolean expressions matters: Lua's `and`/`or` precedence "
          .. "makes\n"
          .. "  vmin and vmax and target < vmin or target > vmax\n"
          .. "parse as\n"
          .. "  (vmin and vmax and target < vmin) or (target > vmax)\n"
          .. "which evaluates `target > vmax` even when vmax is nil and "
          .. "crashes inside reaper.defer with `attempt to compare nil "
          .. "with number`. The canonical form\n"
          .. "  vmin and vmax and vmin < vmax and (target < vmin or target > vmax)\n"
          .. "short-circuits cleanly.\n\n"
          .. "Regenerate the FULL script. For each helper you call, paste "
          .. "the helper's source verbatim from `prompt_bundle:plugin_helpers` "
          .. "above main(). Respond as if this is your FIRST reply -- do "
          .. "NOT apologize, do NOT mention a retry.)\n\n"
          .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
        if #S.history > 0 and S.history[#S.history].role == "assistant" then
          S.history[#S.history] = nil
        end
        if #S.history > 0 and S.history[#S.history].role == "user" then
          S.history[#S.history] = nil
        end
        S.history[#S.history+1] = { role = "user", content = history_content }
        if S.pending_display_idx
           and S.display_messages[S.pending_display_idx] then
          local dmsg = S.display_messages[S.pending_display_idx]
          local existing = dmsg.ctx_label or ""
          if not existing:find("helper_int_retry", 1, true) then
            dmsg.ctx_label = existing ~= ""
              and (existing .. " + helper_int_retry") or "helper_int_retry"
          end
        end
        if prefs.include_snapshot then
          S.pending_project  = _resolve_pending_project()
          S.pending_snapshot = CTX.build_snapshot(S.pending_project,
            S.pending_jsfx_intent and { minimal_tracks = true } or nil)
        end
        S.status = "waiting"
        Code.safe_write(tmp.out, "")
        local ok, reason = Net.fire_curl(Net.build_body(Net.trimmed_history(),
          S.pending_snapshot, S.pending_attachments))
        if not ok and reason ~= "call_cap_exceeded" then
          Log.add_error("Auto-retry for corrupted helper body did not go "
            .. "through. Please resend the last message.")
        end
        S.scroll_to_bottom = true
        return
      end
      helper_int_gate_hit = true
      Log.line("HELPER-INTEGRITY-VALIDATOR",
        "helper body corruption persists after retry; auto-run blocked")
      local user_lines = {}
      for _, e in ipairs(int_bad) do
        user_lines[#user_lines+1] = e.name
      end
      Log.add_error("The model rewrote bundled helper function body "
        .. "in a way that drops a safety guard, even after a retry: "
        .. tbl_concat(user_lines, ", ")
        .. ". The corrupted helper would crash at runtime inside reaper.defer "
        .. "(after Code.run logs success). Auto-run is blocked; review and "
        .. "edit the code before clicking Run manually, or paste the helper "
        .. "definition verbatim from prompt_bundle:plugin_helpers.")
    end
  end

  -- JSFX VALIDATOR: After the Lua-focused validators, statically analyze
  -- generated JSFX before it gets auto-saved + auto-loaded. Catches EEL2
  -- syntax that won't compile (`{}`, `else`, `for(...)`, `math.X`, `reaper.X`)
  -- plus safety violations from Prompts.md (unclamped feedback >0.85, hard
  -- clipping without explicit user request, indexed memory with no base
  -- assignment). Same recovery shape as the other validators: model-only
  -- nudge, scrub the bad turn from history, single retry per turn, surface
  -- a visible error if the retry still fails.
  --
  -- Calibrated against C:\REAPER\Effects (264 standalone stock + community
  -- JSFX); each rule's false-positive rate sits at or below ~3.5%. See
  -- Code.validate_jsfx and Dev/Tests/corpus_audit.lua for details.
  local jsfx_gate_hit = false
  -- Single source of truth for "any validator hit its second-strike block
  -- this turn." Replaces three open-coded "and not docs_gate_hit and not
  -- validator_gate_hit and ..." chains that drift stale every time a new
  -- validator is added. A bug from exactly that drift slipped past the
  -- auto-run gate in commit 89cd276's predecessor: HELPER-INTEGRITY-VALIDATOR
  -- correctly set helper_int_gate_hit, but auto-run still ran the corrupted
  -- script because the gate list was stale. Defined here, after all validator
  -- flags are in scope, so adding a new gate now means updating one place.
  local function _any_gate_hit()
    return docs_gate_hit
        or validator_gate_hit
        or action_gate_hit
        or transient_gate_hit
        or drum_quantize_gate_hit
        or drum_marker_sync_gate_hit
        or arity_gate_hit
        or sendidx_gate_hit
        or stockfx_gate_hit
        or fxident_gate_hit
        or fxcheck_gate_hit
        or upsert_gate_hit
        or defer_gate_hit
        or fx_param_scope_gate_hit
        or helper_gate_hit
        or helper_int_gate_hit
        or jsfx_gate_hit
  end
  if jsfx_code and not _any_gate_hit() then
    local findings = Code.validate_jsfx(jsfx_code, S.pending_orig_prompt or "")
    -- Pass log: prove the validator actively ran on this response, regardless
    -- of provider, so an unexpected silent-pass is distinguishable from a
    -- skipped-run in the debug log. Mirrors the API-VALIDATOR pass log.
    if not (findings and Code.jsfx_findings_have_gate(findings)) then
      local warn_count = 0
      if findings then
        for _, f in ipairs(findings) do
          if f.severity == "warn" then warn_count = warn_count + 1 end
        end
      end
      Log.line("JSFX-VALIDATOR",
        "scanned JSFX (" .. tostring(#jsfx_code) .. " bytes), no fatal findings"
        .. (warn_count > 0
             and (" (" .. warn_count .. " advisory)") or ""))
    end
    if findings and Code.jsfx_findings_have_gate(findings) then
      -- Distinct fatal codes for the log + user-visible error (used in both
      -- the retry path and the post-retry gate-blocked path).
      local code_summary = {}
      do
        local seen = {}
        for _, f in ipairs(findings) do
          if f.severity == "fatal" and not seen[f.code] then
            seen[f.code] = true
            code_summary[#code_summary+1] = f.code
          end
        end
      end
      if (S.jsfx_validator_retries or 0) < 1 then
        S.jsfx_validator_retries = (S.jsfx_validator_retries or 0) + 1
        Probe.add_validator_retry(S.probe_turn, "jsfx")
        -- Build per-finding lines for the retry hint. Only fatal findings
        -- count toward the gate; warns are advisory and listed for context.
        local fatal_lines, warn_lines = {}, {}
        for _, f in ipairs(findings) do
          local entry = "  - [" .. f.code .. "] line " .. tostring(f.line)
            .. ": " .. f.message
          if f.severity == "fatal" then
            fatal_lines[#fatal_lines+1] = entry
          else
            warn_lines[#warn_lines+1] = entry
          end
        end
        Log.line("JSFX-VALIDATOR",
          "JSFX failed validation (" .. #fatal_lines .. " fatal, "
          .. #warn_lines .. " warn): "
          .. tbl_concat(code_summary, ", ")
          .. "; retrying with hint (user-invisible)")
        local history_content = "(INTERNAL NOTE TO THE MODEL -- DO NOT MENTION "
          .. "ANY OF THIS IN YOUR VISIBLE REPLY: Your previous JSFX failed "
          .. "ReaAssist's static JSFX validator. The following issues MUST be "
          .. "fixed:\n"
          .. tbl_concat(fatal_lines, "\n")
          .. (#warn_lines > 0
              and ("\n\nAdvisory (not blocking, but worth addressing):\n"
                   .. tbl_concat(warn_lines, "\n"))
              or "")
          .. "\n\nRegenerate the JSFX from scratch. Keep the same user-facing "
          .. "intent, but fix every fatal issue. EEL2 reminders: no `if`/`else`/"
          .. "`{}` blocks (use ternary `cond ? (...) : (...)` and grouping `(...)`); "
          .. "no `for(...)` (use `loop(N, ...)` or `while(cond) (...)`); bare math "
          .. "functions only (no `math.` prefix); no `reaper.*` calls. For any "
          .. "feedback path, hard-clamp the feedback coefficient to <= 0.85, add a "
          .. "DC blocker, and use soft saturation (tanh, x/(1+|x|)) instead of "
          .. "hard clipping unless the user explicitly asked for clipping/"
          .. "limiting/distortion. Initialize every persistent variable + buffer "
          .. "base in `@init`. Respond as if this is your FIRST reply to the "
          .. "user's request -- do NOT apologize, do NOT say 'let me try again', "
          .. "do NOT mention a retry.)\n\n"
          .. "USER REQUEST:\n" .. (S.pending_orig_prompt or "")
        if #S.history > 0 and S.history[#S.history].role == "assistant" then
          S.history[#S.history] = nil
        end
        if #S.history > 0 and S.history[#S.history].role == "user" then
          S.history[#S.history] = nil
        end
        S.history[#S.history+1] = { role = "user", content = history_content }
        if S.pending_display_idx
           and S.display_messages[S.pending_display_idx] then
          local dmsg = S.display_messages[S.pending_display_idx]
          local existing = dmsg.ctx_label or ""
          if not existing:find("jsfx_retry", 1, true) then
            dmsg.ctx_label = existing ~= ""
              and (existing .. " + jsfx_retry") or "jsfx_retry"
          end
        end
        if prefs.include_snapshot then
          S.pending_project  = _resolve_pending_project()
          -- Carry the original turn's JSFX intent into the rebuilt
          -- snapshot so the trimmed track-listing (selected only) used
          -- on the first request stays trimmed on the retry. Otherwise
          -- the retry would inject the full ~80-track listing on top of
          -- the cached prefix, busting the cache rung the retry was
          -- designed to ride for free.
          S.pending_snapshot = CTX.build_snapshot(S.pending_project,
            S.pending_jsfx_intent and { minimal_tracks = true } or nil)
        end
        S.status = "waiting"
        Code.safe_write(tmp.out, "")
        local ok, reason = Net.fire_curl(Net.build_body(Net.trimmed_history(),
          S.pending_snapshot, S.pending_attachments))
        if not ok and reason ~= "call_cap_exceeded" then
          Log.add_error("Auto-retry for invalid JSFX did not go through. "
            .. "Please resend the last message.")
        end
        S.scroll_to_bottom = true
        return
      end
      -- Retry already used and the JSFX still fails validation. Block
      -- auto-save + auto-run and surface diagnostic.
      jsfx_gate_hit = true
      Log.line("JSFX-VALIDATOR",
        "JSFX still fails validation after retry: "
        .. tbl_concat(code_summary, ", ") .. "; auto-run blocked")
      Log.add_error("The model emitted JSFX that fails ReaAssist's safety/"
        .. "syntax validator, even after a retry: "
        .. tbl_concat(code_summary, ", ")
        .. ". Auto-save and auto-run are blocked; review the code carefully "
        .. "and fix the listed issues before saving manually.")
    end
  end

  -- =============================================================================
  -- CEILING INJECTION (chat-display-time)
  -- =============================================================================
  -- After the JSFX validator passes, inject the output-ceiling safety layer.
  -- Runs BEFORE the chat bubble is built and BEFORE auto-save, so the visible
  -- code box, the copy button, the manual Save / Add to Track buttons, and
  -- auto-save all see the SAME injected source.
  --
  -- Without this, copying from the chat would produce un-injected JSFX that
  -- skips the safety layer when the user pastes it elsewhere or hand-saves.
  --
  -- Skipped if any prior validator gate is set (the source was already going
  -- to be blocked from auto-run; injection wouldn't change that), if there's
  -- no jsfx_code, or if the injector itself bails on a content check.
  -- Cache the inject info so the auto-save block below (which actually
  -- knows the saved file path) can record the slot metadata.
  local ceiling_inject_info = nil
  if jsfx_code and not _any_gate_hit() then
    local injected, info_or_reason = Code.inject_output_ceiling(jsfx_code)
    if injected then
      ceiling_inject_info = info_or_reason
      Log.line("CEILING-INJECT",
        ("injected: slot=%d slider=%d merged_options=%s created_init=%s created_slider=%s created_block=%s")
          :format(info_or_reason.slot_base, info_or_reason.slider_num,
                  tostring(info_or_reason.merged_options),
                  tostring(info_or_reason.created_init),
                  tostring(info_or_reason.created_slider),
                  tostring(info_or_reason.created_block)))
      -- Replace the JSFX fence content in the assistant message text so
      -- (a) the chat code box renders the injected version, (b) the copy
      -- button copies the injected version, and (c) any future re-extract
      -- (e.g. manual edit, history replay) sees the injected source.
      -- gsub with a function avoids %-substitution on injected.
      local replacement = function() return "```jsfx\n" .. injected .. "\n```" end
      local new_text, n = text:gsub("```jsfx%s*\n.-\n%s*```", replacement, 1)
      if n == 0 then
        -- ```eel fallback (less common label).
        new_text, n = text:gsub("```eel%s*\n.-\n%s*```",
          function() return "```eel\n" .. injected .. "\n```" end, 1)
      end
      if n > 0 then
        text = new_text
        if S.history[#S.history] and S.history[#S.history].role == "assistant" then
          S.history[#S.history].content = text
        end
      end
      -- Update locals used downstream by auto-save and the chat bubble.
      jsfx_code = injected
      if code_type == "jsfx" then code = injected end
      -- Also update the explanation text we built earlier, which had fences
      -- stripped from the ORIGINAL `text`. Re-strip from the updated `text`
      -- so the explanation matches what's actually rendered.
      explanation = text
        :gsub("```[^\n]*\n.-\n%s*```", "")
        :gsub("\n\n\n+", "\n\n")
        :match("^%s*(.-)%s*$") or ""
    else
      Log.line("CEILING-INJECT", "skipped: " .. tostring(info_or_reason))
    end
  end

  -- Auto-run handling.
  local jsfx_auto_status = nil
  local jsfx_saved_path_for_msg = nil   -- saved path to carry on the message
  local jsfx_saved_fx_name_for_msg = nil -- FX ref name to carry on the message
  local auto_ran_ok = false             -- V5: flag for the AUTO-RAN pill below code
  local typed_defer = { probe_turn = S.probe_turn }
  typed_defer.finish = function()
    if not (typed_defer.pending and typed_defer.done) then
      return
    end
    typed_defer.pending = false
    typed_action_metrics.deferred_pending = nil
    typed_action_metrics.executed = typed_defer.ok == true
    local dmsg = S.display_messages[typed_defer.message_idx]
    if typed_defer.ok then
      auto_ran_ok = true
      typed_action_metrics.error = nil
      if not explanation or explanation == ""
         or explanation == "Structured edit is applying..." then
        explanation = "Done."
      end
      if S.history[_asst_hist_idx] then
        S.history[_asst_hist_idx].run_status = "ran_ok"
        S.history[_asst_hist_idx].code_bytes = 0
        S.history[_asst_hist_idx].code_type  = "typed_actions"
      end
      if not typed_defer.pruned then
        Net.sticky_prune_after_plugin_success(_compact_user_intent,
          lua_code or code)
        typed_defer.pruned = true
      end
    else
      auto_ran_ok = false
      typed_action_metrics.error =
        (typed_defer.result and typed_defer.result.code) or "execution_failed"
      explanation = Code.typed_actions_user_failure_message(typed_defer.result)
      if S.history[_asst_hist_idx] then
        S.history[_asst_hist_idx].run_status = "errored"
        S.history[_asst_hist_idx].code_bytes = 0
        S.history[_asst_hist_idx].code_type  = "typed_actions"
      end
    end
    if dmsg then
      dmsg.content = explanation
      dmsg.auto_ran = auto_ran_ok
      dmsg.typed_actions = typed_action_metrics
    end
    Probe.mark_phase_end(typed_defer.probe_turn, "execution")
    Probe.add_typed_action(typed_defer.probe_turn, typed_action_metrics)
    if typed_defer.probe_turn then
      Probe.end_turn(typed_defer.probe_turn, "ok")
      if S.probe_turn == typed_defer.probe_turn then S.probe_turn = nil end
    end
    S.scroll_to_bottom = true
  end
  if prefs.auto_run and not _any_gate_hit() then
    if typed_action_ready then
      local skip_typed = false
      if prefs.auto_backup then
        local bok, berr = Code.safety_backup()
        if berr == "unsaved" then
          typed_action_metrics.error = "backup_required"
          explanation = "Structured edit validated, but auto-run is blocked until the project is saved for safety backup."
          skip_typed = true
          if S.history[_asst_hist_idx] then
            S.history[_asst_hist_idx].run_status = "manual_run"
          end
        elseif berr == "read_error" or berr == "write_error" then
          typed_action_metrics.error = "backup_failed"
          explanation = "Structured edit validated, but auto-run is blocked because ReaAssist could not create a safety backup."
          Log.add_error(explanation)
          skip_typed = true
          if S.history[_asst_hist_idx] then
            S.history[_asst_hist_idx].run_status = "manual_run"
          end
        end
      end
      if not skip_typed then
        Probe.mark_phase_start(S.probe_turn, "execution")
        local exec_ok, exec_result = Code.execute_typed_actions_from_text(text, {
          allow_raw_json = typed_action_response_format,
          user_text = S.pending_orig_prompt or "",
          profile = typed_action_profile,
          on_done = function(done_ok, done_result)
            typed_defer.done = true
            typed_defer.ok = done_ok == true
            typed_defer.result = done_result
            typed_defer.finish()
          end,
        })
        local exec_pending = exec_ok and exec_result
          and exec_result.deferred == true
          and exec_result.completed ~= true
        if exec_pending then
          typed_defer.pending = true
        else
          Probe.mark_phase_end(S.probe_turn, "execution")
        end
        typed_action_metrics.deferred =
          exec_result and exec_result.deferred == true or nil
        typed_action_metrics.deferred_pending = exec_pending or nil
        typed_action_metrics.executed = exec_ok == true and not exec_pending
        if exec_ok then
          if exec_pending then
            explanation = "Structured edit is applying..."
            if S.history[_asst_hist_idx] then
              S.history[_asst_hist_idx].run_status = "pending"
              S.history[_asst_hist_idx].code_bytes = 0
              S.history[_asst_hist_idx].code_type  = "typed_actions"
            end
          else
            auto_ran_ok = true
            explanation = (explanation and explanation ~= "") and explanation or "Done."
            if S.history[_asst_hist_idx] then
              S.history[_asst_hist_idx].run_status = "ran_ok"
              S.history[_asst_hist_idx].code_bytes = 0
              S.history[_asst_hist_idx].code_type  = "typed_actions"
            end
          end
        else
          local code_or_nil = exec_result and exec_result.code or nil
          typed_action_metrics.error = code_or_nil or "execution_failed"
          explanation = Code.typed_actions_user_failure_message(exec_result)
          Log.add_error("Structured edit failed: "
            .. tostring(explanation or code_or_nil or "unknown error"))
          if S.history[_asst_hist_idx] then
            S.history[_asst_hist_idx].run_status = "errored"
            S.history[_asst_hist_idx].code_bytes = 0
            S.history[_asst_hist_idx].code_type  = "typed_actions"
          end
        end
      end
    end

    -- JSFX: auto-save to Effects/ReaAssist/ folder ONLY when a Lua companion
    -- block is also present (meaning the user asked for it on a track).
    -- If the user just asked for an example, there is no Lua block and the
    -- JSFX is displayed but not saved.
    local jsfx_to_save = jsfx_code or (code_type == "jsfx" and code)
    if jsfx_to_save and lua_code then
      local saved_path, fx_name = Code.auto_save_jsfx(jsfx_to_save)
      if saved_path then
        jsfx_saved_path_for_msg = saved_path
        jsfx_saved_fx_name_for_msg = fx_name
        -- Record the ceiling slot allocation for the host poll loop now
        -- that we have a real on-disk file path to associate with it.
        -- (Pre-injection bails left ceiling_inject_info nil, so this
        -- no-ops on bail.)
        if ceiling_inject_info then
          Code.ceiling_record_slot(ceiling_inject_info, saved_path,
            ceiling_inject_info.desc)
        end
        -- Patch the Lua companion to use the actual saved filename (may have a
        -- numeric suffix if a file with the original name already existed).
        if lua_code and fx_name then
          local orig_name = Code.derive_filename_jsfx(jsfx_to_save)
          local orig_ref  = "ReaAssist/" .. orig_name
          if fx_name ~= orig_ref then
            -- Escape every Lua pattern magic char in orig_ref (the previous
            -- escape covered only . - + and missed ( ) [ ] ^ $ * ? %), and
            -- escape % in fx_name (replacement string treats %% as literal).
            -- Without these, a JSFX desc: line containing one of those chars
            -- (which sanitize_filename does not strip) would either silently
            -- fail to match or throw "invalid use of '%' in replacement
            -- string" and the auto-run companion script would land with the
            -- stale pre-rename ReaAssist/<orig> path.
            local pat = orig_ref:gsub("[%(%)%.%%%+%-%*%?%[%]%^%$]", "%%%0")
            local rep = fx_name:gsub("%%", "%%%%")
            lua_code = lua_code:gsub(pat, rep)
          end
        end
        if lua_code then
          jsfx_auto_status = "Done."
        else
          jsfx_auto_status = "JSFX saved to " .. saved_path
        end
      end
    end
    -- Lua: auto-run (handles both standalone Lua and JSFX companion scripts).
    local run_lua = lua_code or (code_type == "lua" and code)
    if run_lua then
      S.pending_code = run_lua
      local skip_run = false
      local run_lua_artifact = lua_artifact_info
      if not run_lua_artifact or run_lua ~= lua_code then
        run_lua_artifact = Code.classify_lua_artifact(run_lua,
          { context_text = text })
      end
      if not run_lua_artifact.runnable then
        local block_msg = Code.lua_artifact_block_message(run_lua_artifact)
        Log.line("AUTO-RUN", "blocked non-runnable Lua artifact: "
          .. tostring(run_lua_artifact.kind) .. " / "
          .. tostring(run_lua_artifact.reason))
        if explanation and explanation ~= "" then
          explanation = explanation .. "\n\n" .. block_msg
        else
          explanation = block_msg
        end
        skip_run = true
        S.pending_code = nil
        if S.history[_asst_hist_idx] then
          S.history[_asst_hist_idx].run_status = "blocked_fragment"
          S.history[_asst_hist_idx].code_bytes = #run_lua
          S.history[_asst_hist_idx].code_type  = "lua"
        end
      end
      -- Risky-code gate: if the scanner flags anything, require explicit
      -- confirmation before auto-executing. The modal index points to the
      -- message that will be appended just below this block.
      local auto_risk = (not skip_run) and Code.scan_risky(run_lua) or nil
      if auto_risk then
        S.risky_warn_code   = run_lua
        S.risky_warn_idx    = #S.display_messages + 1
        S.risky_warn_detail = auto_risk
        S.open_risky_warn   = true
        skip_run = true
        if S.history[_asst_hist_idx] then
          S.history[_asst_hist_idx].run_status = "manual_run"
        end
      elseif not skip_run and prefs.auto_backup then
        local bok, berr = Code.safety_backup()
        if berr == "unsaved" then
          S.backup_warn_code = run_lua
          S.backup_warn_idx  = #S.display_messages + 1
          S.open_backup_warn = true
          skip_run = true
          if S.history[_asst_hist_idx] then
            S.history[_asst_hist_idx].run_status = "manual_run"
          end
        end
      end
      if not skip_run then
        -- Phase 1 instrumentation: time the actual code execution.
        -- Skipped when skip_run is true (risky-code gate or backup
        -- requirement); execution measurement is for auto-run only.
        Probe.mark_phase_start(S.probe_turn, "execution")
        local run_ok = Code.run(run_lua)
        Probe.mark_phase_end(S.probe_turn, "execution")
        S.pending_code = nil
        -- AUTO-RAN pill (V5) reflects the actual run outcome -- a
        -- compile/runtime failure should NOT show as auto-ran. Mirror
        -- the same outcome onto the per-turn run record so the UI
        -- pill and the compact-history run_status agree.
        auto_ran_ok = (run_ok == true)
        if S.history[_asst_hist_idx] then
          S.history[_asst_hist_idx].run_status = run_ok and "ran_ok" or "errored"
          S.history[_asst_hist_idx].code_bytes = #run_lua
          S.history[_asst_hist_idx].code_type  = code_type
        end
      end
    end
  end
  if typed_action_ready
     and not typed_action_metrics.executed
     and (not explanation or explanation == "") then
    typed_action_metrics.error = typed_action_metrics.error or "auto_run_disabled"
    explanation = "Structured edit validated, but it was not run because Auto-run is off."
  end
  if code and not S.pending_code
     and (code_type ~= "lua"
       or not lua_artifact_info
       or lua_artifact_info.runnable) then
    S.pending_code = code
  end

  -- Truncation: model hit MAX_TOKENS but still emitted visible text. Stamp
  -- the message so the chat bubble renders a "cut off" banner + the same
  -- recovery buttons as the empty-response case. provider_id is always set
  -- below, so the thinking-level button scopes to the right provider.
  local was_truncated = (empty_reason == "length")
  if was_truncated and S.history[_asst_hist_idx] then
    S.history[_asst_hist_idx].truncated   = true
    S.history[_asst_hist_idx].run_status  = "truncated"
  end
  if not code and not (typed_action_metrics and typed_action_metrics.present) then
    local filtered_explanation, filtered_count =
      Code.filter_broad_fx_param_readout(_compact_user_intent, explanation)
    if filtered_count and filtered_count > 0 then
      explanation = filtered_explanation
      text = filtered_explanation
      if S.history[_asst_hist_idx] then
        S.history[_asst_hist_idx].content = filtered_explanation
      end
      Log.line("PARAM-READOUT",
        "filtered " .. tostring(filtered_count)
        .. " default utility parameter line(s) from broad readout")
    end
  end
  S.display_messages[#S.display_messages+1] = {
    role       = "assistant",
    content    = explanation,
    code_block = code,
    code_type  = code_type,
    provider_id     = PROVIDERS.active().id,
    -- model_id captured alongside provider_id so per-message recovery
    -- actions (Lower Thinking on a length-cap reply, etc.) can write
    -- their changes against the model that actually produced this
    -- response, not against whatever model the user happens to be on
    -- when they click the recovery button.
    model_id        = (function()
      local _m = MODELS[prefs.model_idx] or MODELS[1]
      return _m and _m.id or nil
    end)(),
    model_label     = PROVIDERS.active().label .. " " .. (function()
      -- Same fallback as the user-bubble model_label build: a brief
      -- post-provider-switch race or a 0-model custom provider would
      -- make MODELS[prefs.model_idx] nil, and indexing .label on it
      -- would crash the response handler.
      local _m = MODELS[prefs.model_idx] or MODELS[1]
      return _m and _m.label or "?"
    end)(),
    lua_companion   = jsfx_code and lua_code or nil,  -- store companion for manual run
    lua_artifact    = code_type == "lua" and lua_artifact_info or nil,
    lua_companion_artifact = jsfx_code and lua_code and lua_artifact_info or nil,
    jsfx_auto_saved = jsfx_auto_status,               -- status text from auto-save
    jsfx_saved_path = jsfx_saved_path_for_msg,        -- path if already saved (avoids re-save)
    jsfx_saved_fx_name = jsfx_saved_fx_name_for_msg,  -- FX ref name if already saved
    ceiling_injected = ceiling_inject_info ~= nil or nil,
    auto_ran        = auto_ran_ok,                    -- V5: show AUTO-RAN pill below code
    truncated       = was_truncated or nil,
    typed_action_token_cap = (was_truncated and typed_action_response_format
      and S.typed_action_escalation_used == true) or nil,
    recovery        = was_truncated and "token_limit" or nil,
    -- True when the response tripped the docs-gate (reaper.* emitted with no
    -- api_ref in session). Chat bubble renderers can key off this to show a
    -- warning banner; auto-run was already suppressed above.
    docs_gate_hit   = docs_gate_hit or nil,
    typed_actions   = typed_action_metrics,
  }
  typed_defer.message_idx = #S.display_messages
  typed_defer.finish()
  if code_type == "lua" and code then
    Code.record_latest_code_candidate(code, "assistant", {
      artifact = lua_artifact_info,
      context_text = text,
    })
  end
  if auto_ran_ok and not typed_defer.pruned then
    Net.sticky_prune_after_plugin_success(_compact_user_intent, lua_code or code)
    typed_defer.pruned = true
  end
  if not typed_defer.pending then
    Probe.add_typed_action(S.probe_turn, typed_action_metrics)
  end
  Net._restore_typed_action_escalation_model()

  -- Prune oldest display messages beyond the soft cap to prevent unbounded
  -- memory growth. History is bounded by CFG.MAX_HISTORY_TURNS for the API;
  -- this caps the UI-only list. When we prune, also dump the wrap cache --
  -- it's keyed on raw segment text and would otherwise accumulate entries for
  -- every message ever rendered across a long session. The next frame rewrap
  -- is one-shot and imperceptible.
  if #S.display_messages > CFG.MAX_DISPLAY_MSGS then
    if Diag.uploader_enabled and Diag.capture_current_chat then
      Diag.capture_current_chat()
    end
    local pruned_count = 0
    while #S.display_messages > CFG.MAX_DISPLAY_MSGS do
      tbl_remove(S.display_messages, 1)
      pruned_count = pruned_count + 1
    end
    if typed_defer.message_idx and pruned_count > 0 then
      typed_defer.message_idx = typed_defer.message_idx - pruned_count
      if typed_defer.message_idx < 1 then typed_defer.message_idx = nil end
    end
    S.wrap_cache = {}  -- invalidate per-bubble text-wrap cache
  end

  Code.safe_write(tmp.out, "")
  -- Response processing is complete. For deferred typed-action param writes,
  -- the execution result is finalized by typed_defer.finish() on the defer
  -- tick, but the request/resume state below is no longer needed. Leaves
  -- S.pending_code alone since that carries generated Lua the user may still
  -- want to Run manually.
  S.pending_orig_prompt = nil
  S.pending_typed_action_expected = false
  S.pending_typed_action_response_format = false
  S.pending_typed_action_profile = nil
  S.pending_snapshot    = nil
  S.pending_project     = nil
  S.pending_attachments = nil
  S.pending_display_idx = nil
  -- Final clear: this is the only spot in process_response that nils
  -- request_start_time. Earlier cleanup paths (empty-text error, normal
  -- cleanup at ~22087) deliberately leave it set so the docs-gate auto-
  -- retry can keep the in-flight "Thinking..." timer ticking across the
  -- silent retry curl. Once we reach here the turn is fully complete and
  -- the next send_to_api will overwrite anyway.
  S.request_start_time = nil
  S.status           = "idle"
  S.scroll_to_bottom = true
  -- Build the compact-history summary for this turn. The summary IS the
  -- compacted "content" sent for this row when it ages past T-1 and the
  -- compact_history flag is on. compact_eligible gates whether the
  -- compaction substitution actually fires; only ran_ok turns with a
  -- known code body produce a usable summary, everything else stays
  -- verbatim so the model can still see the original on a "fix that"
  -- follow-up.
  if S.history[_asst_hist_idx] and S.history[_asst_hist_idx].role == "assistant" then
    Net.assistant_attach_compact_metadata(_asst_hist_idx, {
      code            = code,
      code_type       = code_type,
      auto_ran_ok     = auto_ran_ok,
      was_truncated   = was_truncated,
      user_intent     = _compact_user_intent,
    })
  end
  -- Phase 1 instrumentation: canonical "turn completed successfully" site
  -- for non-deferred turns. Deferred typed-action param writes close the same
  -- probe from typed_defer.finish() after the REAPER defer tick reports the
  -- actual result. Probe is currently a no-op compatibility surface.
  if S.probe_turn and not typed_defer.pending then
    Probe.end_turn(S.probe_turn, "ok")
    S.probe_turn = nil
  end
end

Render = {}

-- =============================================================================
-- Diagnostics module (Phase 1 instrumentation)
-- =============================================================================
-- The historical local-only Temp-Probe module is retired. Keep Probe.* as
-- explicit no-op entries so instrumentation call sites remain harmless and
-- can be removed opportunistically without turning this cleanup into a broad
-- runtime refactor.
do
  local function noop() end
  Probe = {
    enabled = false,
    start_turn = function() return nil end,
    mark_phase_start = noop,
    mark_phase_end = noop,
    add_bytes = noop,
    set_body_total = noop,
    add_request = noop,
    add_request_usage = noop,
    add_validator_retry = noop,
    add_fx_cache = noop,
    add_typed_action = noop,
    end_turn = noop,
  }
end

-- =============================================================================
-- Diag module dofile (uploader pathway: manual feedback now, auto-tier in v1.1)
-- =============================================================================
-- Loaded AFTER the shared RA.JSON / RA.sha256_hex helpers above are visible and
-- BEFORE UI.lua (so the in-chat link guard `Diag.uploader_enabled` has a real
-- value when UI renders). Diag (the namespace) is already populated
-- with .errors / .add_error / .build_report from earlier in this file; this
-- dofile extends it with the network-uploader surface.
--
-- The fallback catches both a hard load failure and a module that loaded but
-- disabled itself (e.g. internal RA.JSON guard tripped). In that case we
-- install no-op stubs for tick / rotate_chat_id so UI guards and main-loop
-- call sites never see missing functions.
do
  local ok, err = pcall(dofile, RA.RESOURCES_DIR .. "Diag.lua")
  if not ok or Diag.uploader_enabled ~= true then
    Diag.uploader_enabled = false
    Diag.tick             = Diag.tick             or function() end
    Diag.rotate_chat_id   = Diag.rotate_chat_id   or function() end
    if not ok then
      Log.line("DIAG", "Diag.lua load failed: " .. tostring(err))
    end
  end
end

-- =============================================================================
-- Critical-files check + Render screen dofile
-- =============================================================================
-- Verify every critical file (UI chunk + every font the atlas expects) is
-- present before dofile()'ing the UI file. If anything is missing, flip
-- into bootstrap recovery: skip the dofile, set S.bootstrap_active, and
-- let the kick-off block at the bottom of the file register Bootstrap.loop
-- instead of the normal loop. Bootstrap uses default font / theme and
-- does not touch Render.* / UI.* / TK.* / FONT.* -- any of which may be
-- nil in recovery mode. CRITICAL_FILES is hardcoded (not manifest-driven)
-- because bootstrap has to run BEFORE any network activity.

S.bootstrap_active  = false
S.bootstrap_missing = {}

do
  -- Derive CRITICAL_FILES from FONT_FILES (the same table _mkfont calls
  -- consume) so the two lists cannot drift: add a font to FONT_FILES
  -- and the bootstrap check picks it up automatically.
  local CRITICAL_FILES = { "Resources/UI.lua" }
  -- Sort font filenames so the bootstrap-missing list is presented in
  -- a stable order across launches. `pairs` order is hash-bucket-
  -- dependent; without sorting, the recovery screen's "first 6 missing"
  -- entries shuffle between launches for the same filesystem state.
  do
    local fnames = {}
    for _, fname in pairs(FONT_FILES) do fnames[#fnames + 1] = fname end
    table.sort(fnames)
    for _, fname in ipairs(fnames) do
      CRITICAL_FILES[#CRITICAL_FILES + 1] = "Resources/fonts/" .. fname
    end
  end
  for _, rel in ipairs(CRITICAL_FILES) do
    local path = RA.script_path
                 .. (RA.SEP == "/" and rel or rel:gsub("/", RA.SEP))
    local probe = io.open(path, "r")
    if probe then
      probe:close()
    else
      S.bootstrap_missing[#S.bootstrap_missing + 1] = rel
    end
  end
  -- Catch present-but-unloadable fonts: io.open succeeds (file exists), but
  -- ImGui_CreateFontFromFile may have rejected it (truncated, header damaged,
  -- partial download). _mkfont returns nil in that case, so any nil FONT[key]
  -- whose file we DIDN'T already flag as missing must be corrupt. Suffix with
  -- "(load error)" to distinguish from missing in the recovery screen.
  for key, fname in pairs(FONT_FILES) do
    if not FONT[key] then
      local rel = "Resources/fonts/" .. fname
      local already_listed = false
      for _, e in ipairs(S.bootstrap_missing) do
        if e == rel then already_listed = true; break end
      end
      if not already_listed then
        S.bootstrap_missing[#S.bootstrap_missing + 1] = rel .. " (load error)"
      end
    end
  end
end

if #S.bootstrap_missing > 0 then
  S.bootstrap_active = true
  -- Distinguish "fresh install (stub installer just dropped ReaAssist.lua,
  -- supporting files not yet fetched)" from "existing install with corrupt
  -- or missing files." The former auto-installs without a Repair button;
  -- the latter shows the existing repair prompt. Signal: ExtState
  -- `first_launch_complete` is set once UI has loaded successfully at
  -- least once on this REAPER profile. Empty -> install mode.
  S.bootstrap_install_mode =
    (reaper.GetExtState(CFG.EXT_NS, "first_launch_complete") ~= "1")
  Log.line("BOOTSTRAP", string.format(
    "%d critical file%s missing; entering %s mode on this launch.",
    #S.bootstrap_missing,
    #S.bootstrap_missing == 1 and "" or "s",
    S.bootstrap_install_mode and "first-install" or "recovery"))
  for _, rel in ipairs(S.bootstrap_missing) do
    Log.line("BOOTSTRAP", "  missing: " .. rel)
  end
else
  -- All critical files present; dofile the UI file to populate Render.*
  -- before the main loop is registered below. Wrapped in pcall so a UI
  -- file that exists but is syntactically corrupt or throws a top-level
  -- runtime error routes into bootstrap recovery instead of crashing
  -- before the recovery screen can render.
  local ok_ui, err_ui = pcall(dofile, RA.RESOURCES_DIR .. "UI.lua")
  if not ok_ui then
    S.bootstrap_active = true
    S.bootstrap_install_mode =
      (reaper.GetExtState(CFG.EXT_NS, "first_launch_complete") ~= "1")
    S.bootstrap_missing[#S.bootstrap_missing + 1] =
      "Resources/UI.lua (load error)"
    -- Log only; do NOT call Updater._set_failure here. Same reason as
    -- the load_system_prompt branches above: this is a load-time
    -- detection of a recoverable file, not a failed repair, and
    -- pre-populating last_error would skip the recovery prompt and
    -- route straight to render_failed.
    Log.line("BOOTSTRAP", string.format(
      "ui_load: UI.lua failed to dofile (%s); routing to recovery prompt.",
      tostring(err_ui)))
  else
    -- UI loaded cleanly. Mark first launch as complete so any future
    -- bootstrap fires routes through the recovery (repair) UI instead
    -- of the first-install UI.
    reaper.SetExtState(CFG.EXT_NS, "first_launch_complete", "1", true)
  end
end

-- =============================================================================
-- Main loop
-- =============================================================================
-- Registered via reaper.defer() at the bottom of the file; runs every frame.
-- Handles close-signal handoff, curl polling, auto-retry on transient
-- errors, and dispatches the ImGui draw via Render.main_window (which
-- lives in Resources/UI.lua).
local Loop = {}

-- Second-instance close signal. request_close carries the new instance's ID;
-- a non-empty value that isn't our own triggers a graceful close.
function Loop.handle_close_signal()
  local close_req = reaper.GetExtState(CFG.EXT_NS, "request_close")
  if close_req ~= "" and close_req ~= S.INSTANCE_ID then
    S.script_open = false
  end
end

-- Dispatch one-shot commands from Dev/ReaAssist_Debug_Helper.lua. The helper
-- writes short strings to this ExtState key for actions it can't reach on its
-- own (in-memory state mutations). Cleared immediately so each signal fires
-- once. Add new arms here as dev-helper buttons are wired up.
function Loop.handle_dev_signal()
  local dev_sig = reaper.GetExtState(CFG.EXT_NS, "dev_signal")
  if dev_sig == "" then return end
  reaper.DeleteExtState(CFG.EXT_NS, "dev_signal", false)
  Log.line("DEV_SIGNAL", "received " .. dev_sig)
  if dev_sig == "clear_chat" then
    Net.clear_conversation()
  elseif dev_sig == "reset_window" then
    reaper.DeleteExtState(CFG.EXT_NS, "win_x", true)
    reaper.DeleteExtState(CFG.EXT_NS, "win_y", true)
    reaper.DeleteExtState(CFG.EXT_NS, "win_w", true)
    reaper.DeleteExtState(CFG.EXT_NS, "win_h", true)
    S._reset_window_size = true
  elseif dev_sig == "refresh_debug_log" then
    -- Match the default-ON pattern at the prefs load site (~= "0").
    -- Otherwise an unset ExtState would refresh OFF, contradicting the
    -- early-release default the user actually has in memory.
    prefs.debug_logging =
      reaper.GetExtState(CFG.EXT_NS, "debug_logging") ~= "0"
  elseif dev_sig == "refresh_fx_filter" then
    -- Dev helper toggled the FabFilter-hide flag. Invalidate the cached
    -- installed-FX lists so populate_installed_fx re-walks REAPER with
    -- the new filter, and drop pref_plugins.initialized so the
    -- Preferred Plugins page reloads rows with the filtered view on
    -- next render. Cache mutation isn't needed -- load_pref_plugins
    -- and CTX.preferred_plugins apply _is_fabfilter_ident as a
    -- read-time filter, reading directly from ExtState, so the flag
    -- takes effect even if this signal never fires (e.g. at boot, when
    -- the flag is already "1" in ExtState).
    Log.line("DEV_FILTER", "refresh_fx_filter fired; hide_fabfilter="
      .. (reaper.GetExtState(CFG.EXT_NS, "dev_hide_fabfilter") == "1"
          and "true" or "false"))
    CTX._installed_fx_list         = nil
    CTX._installed_fx_list_deduped = nil
    pref_plugins.initialized = false
  elseif dev_sig == "refresh_theme" then
    -- Dev helper flipped the saved theme pref. Re-read ExtState and
    -- re-apply the palette live, mirroring what the in-app Settings
    -- footer toggle does (see UI.lua "##fr_theme" handler). apply_palette
    -- swaps COL/TK and invalidates UI palette caches, so the change shows
    -- up on the next render without a restart. Match the boot-time
    -- normalization at the prefs load site so an unrecognized value falls
    -- back to "auto" instead of NULL-ing the palette.
    local v = reaper.GetExtState(CFG.EXT_NS, "theme")
    prefs.theme = (v == "dark" or v == "light") and v or "auto"
    apply_palette(PALETTES[resolve_theme(prefs.theme)])
    Log.line("DEV_THEME", "refresh_theme fired; pref=" .. prefs.theme
      .. " resolved=" .. resolve_theme(prefs.theme))
  end
end

-- Resolve-popup pending resume coordination. When the user picks a plugin in
-- the resolve popup we kick off fx_cache_rescan_start and stash the ident on
-- S.resolve_pending_resume. Once the scan drains, fire resolve_popup_resume so
-- the follow-up turn's preferred_plugins:<type> bucket has fresh params.
--
-- If needs_deep_scan is set and we haven't already tried a deep scan, kick one
-- off first -- some CLAP plugins have display-refresh lag and deliver bare
-- [norm:] data without enum/range annotations until a deep scan completes.
function Loop.handle_resolve_deep_scan()
  if S.resolve_pending_resume
     and not fx_cache_ui.rescan.active
     and not deep_scan.active
     and not S._resolve_deep_scan_attempted then
    local pdata = FXCache.get_plugin(S.resolve_pending_resume)
    if pdata and pdata.needs_deep_scan then
      S._resolve_deep_scan_attempted = true
      Log.line("DEEP_SCAN", "popup-resume: auto-triggering deep scan for "
        .. S.resolve_pending_resume)
      CTX.fx_cache_rescan_start(S.resolve_pending_resume, true)
      -- Start-of-deep-scan auto-scroll only fires when origin == "chat";
      -- fx_cache_rescan_start uses origin "fx_cache", so force scroll here.
      S.scroll_to_bottom = true
    end
  end
  if S.resolve_pending_resume
     and not fx_cache_ui.rescan.active
     and not deep_scan.active then
    local ident = S.resolve_pending_resume
    S.resolve_pending_resume = nil
    S._resolve_deep_scan_attempted = nil
    Log.line("RESOLVE", "scan finished; resuming for " .. ident)
    Net.resolve_popup_resume(ident)
  end
end

-- =============================================================================
-- Safety output ceiling: host-side gmem poll + popup state
-- =============================================================================
-- Per-frame defer hook that watches gmem-mirror flags written by the JSFX
-- safety injection. Cheap fast-path via a global "any engagement"
-- sentinel; full per-slot scan only when the sentinel is set.
--
-- gmem layout (set by inject_output_ceiling render template):
--   gmem[1]            : global "any-instance engagement" flag
--   gmem[<slot>+0]     : per-instance engagement flag (latched by JSFX)
--   gmem[<slot>+1]     : per-instance lifetime engagement-sample count
--   gmem[<slot>+4]     : per-instance mute latch (0/1)
-- Tracked slots come from ExtState (Code.ceiling_get_slots).
--
-- State updated:
--   S._ceiling_muted_fx[slot] = { slot=, file=, desc= }   -- currently muted
--   S._ceiling_alert_pending  -- newly muted; popup wants opening
--   S._ceiling_alert_dismissed -- user clicked "Don't show again" this session
--   S._ceiling_gmem_attached   -- one-time gmem_attach guard
local CEILING_POLL_THROTTLE = 0.20   -- seconds between gmem polls

function Loop.handle_ceiling_poll()
  local now = time_precise()
  if S._ceiling_last_poll and (now - S._ceiling_last_poll) < CEILING_POLL_THROTTLE then
    return
  end
  S._ceiling_last_poll = now

  -- Lazy gmem_attach. Older REAPER builds don't have gmem_attach -- in
  -- that case the safety ceiling still works inside the JSFX (uses local
  -- _ra_muted), we just lose the host alert path. Skip silently.
  if not S._ceiling_gmem_attached then
    if not reaper.gmem_attach then return end
    reaper.gmem_attach(Code.CEILING_NS)
    S._ceiling_gmem_attached = true
  end

  -- One-shot slot GC per session. Drops ExtState entries for JSFX files
  -- that were deleted, overwritten without our injection, or re-injected
  -- with a different slot. Without this, `ceiling_get_slots()` grows
  -- without bound (allocation is monotonic) and the per-poll cost rises
  -- because every poll's `Code.ceiling_slot_is_active` walks all tracks
  -- per slot. Once-per-session is enough -- file deletion is rare, and
  -- the active-instance filter handles same-session orphans correctly
  -- until the next launch GCs them out.
  if not S._ceiling_gc_done then
    S._ceiling_gc_done = true
    pcall(Code.ceiling_gc_slots)
  end

  S._ceiling_muted_fx = S._ceiling_muted_fx or {}

  -- Refresh-and-prune pass over every tracked entry.
  --   * gmem mirror still 1 AND at least one instance is "active"
  --     (track not muted, FX not bypassed, FX still in the chain)
  --     -> keep, mark is_active = true.
  --   * gmem mirror still 1 BUT no instance is active -> the user has
  --     muted the track, bypassed the FX, or removed it. Treat as
  --     user-resolved: clear the gmem mirror so a future re-enable
  --     starts from a clean slate, and drop the entry from the popup.
  --   * gmem mirror is 0 (JSFX-side auto-clear, e.g. slider change)
  --     -> keep entry as a record but mark is_active = false. The
  --     popup keeps it visible until the user dismisses.
  for slot, _entry in pairs(S._ceiling_muted_fx) do
    local mute_val = reaper.gmem_read(slot + Code.CEILING_GMEM_MUTE) or 0
    if mute_val >= 1 then
      if Code.ceiling_slot_is_active(slot) then
        _entry.is_active = true
      else
        -- Stale: track muted, FX bypassed/removed, or all instances
        -- offline. Don't keep showing it in the popup, and clear the
        -- gmem mirror so the next poll doesn't re-detect a phantom
        -- mute when (e.g.) the user re-enables the track later.
        reaper.gmem_write(slot + Code.CEILING_GMEM_MUTE, 0)
        S._ceiling_muted_fx[slot] = nil
      end
    else
      _entry.is_active = false
    end
  end

  -- Cheap fast path: skip the new-mute scan when nothing has fired
  -- anywhere since the last poll.
  local any_eng = reaper.gmem_read(Code.CEILING_GMEM_GLOBAL_ENG)
  if (any_eng or 0) == 0 then return end

  -- Clear sentinel so the next poll detects fresh activity.
  reaper.gmem_write(Code.CEILING_GMEM_GLOBAL_ENG, 0)

  -- Per-slot scan to find newly-muted FX. Iterate every tracked slot
  -- (not just currently-muted ones) so we pick up a fresh trip.
  local slots = Code.ceiling_get_slots()
  local newly_muted = false

  for _, e in ipairs(slots) do
    local mute_val = reaper.gmem_read(e.slot + Code.CEILING_GMEM_MUTE) or 0
    if mute_val >= 1 and not S._ceiling_muted_fx[e.slot] then
      -- Active-instance check: skip slots whose only instances are on
      -- muted tracks / behind a bypassed FX / no longer in any chain.
      -- A stale gmem `1` from a JSFX that was bypassed BEFORE the host
      -- poll started would otherwise pop a phantom alert on the next
      -- transport play. We also clear the mirror in that case so
      -- subsequent polls don't keep seeing it.
      if Code.ceiling_slot_is_active(e.slot) then
        newly_muted = true
        local locations = Code.ceiling_find_fx_locations(e.slot)
        S._ceiling_muted_fx[e.slot] = {
          slot      = e.slot,
          file      = e.file,
          desc      = e.desc or "",
          locations = locations,
          is_active = true,
        }
        Log.line("CEILING-POLL",
          ("mute detected: slot=%d desc=%s locations=%d"):format(
            e.slot, tostring(e.desc), #locations))
      else
        reaper.gmem_write(e.slot + Code.CEILING_GMEM_MUTE, 0)
      end
    end
  end

  if newly_muted and not S._ceiling_alert_dismissed then
    S._ceiling_alert_pending = true
  end
end

-- Walk every track's FX chain to find every instance of the JSFX whose
-- recorded slot matches `slot`. Returns a list of location records:
--   { track_idx (1-based, "M" for master), track_name, fx_idx (1-based),
--     fx_name }
-- The popup uses this to tell the user "Track 5 'Vocal' / FX 2: <name>"
-- per occurrence, since the same .jsfx file can be loaded on multiple
-- tracks and they ALL share one slot/_ra_muted state.
function Code.ceiling_find_fx_locations(slot)
  local out = {}
  local target_file
  for _, e in ipairs(Code.ceiling_get_slots()) do
    if e.slot == slot then target_file = e.file; break end
  end
  if not target_file then return out end
  local fname = target_file:match("[^/\\]+$") or target_file
  local fx_ref_low = ("reaassist/" .. fname):lower()

  local function walk(tr, idx_label, track_name)
    local fxc = reaper.TrackFX_GetCount(tr)
    for fi = 0, fxc - 1 do
      local _, fxname = reaper.TrackFX_GetFXName(tr, fi, "")
      if fxname and fxname:lower():find(fx_ref_low, 1, true) then
        out[#out + 1] = {
          track_idx  = idx_label,
          track_name = track_name or "",
          fx_idx     = fi + 1,
          fx_name    = fxname or "",
        }
      end
    end
  end

  -- Master track first.
  local master = reaper.GetMasterTrack(0)
  if master then
    local _, mname = reaper.GetTrackName(master, "")
    walk(master, "M", mname or "Master")
  end
  local tcount = reaper.CountTracks(0)
  for ti = 0, tcount - 1 do
    local tr = reaper.GetTrack(0, ti)
    if tr then
      local _, tname = reaper.GetTrackName(tr, "")
      walk(tr, ti + 1, tname or "")
    end
  end
  return out
end

-- Returns true if at least one instance of the JSFX bound to this slot
-- is "live" right now -- i.e. its track is not muted AND the FX itself
-- is enabled (not bypassed) AND it is still in a track's FX chain.
--
-- Used by the ceiling poll to filter out stale gmem mute mirrors when
-- the user has muted the track or bypassed the FX. Without this filter,
-- the mute mirror set during a previous run would sit at `1` forever
-- (a non-running JSFX cannot clear its own gmem) and the popup would
-- keep claiming the FX is muted on every replay -- which is the exact
-- bug this addresses.
--
-- Walks fresh FX locations (rather than relying on entry.locations
-- caches) so a moved/renamed FX is also handled correctly. The 200 ms
-- poll throttle keeps the cost negligible for typical sessions.
function Code.ceiling_slot_is_active(slot)
  local locs = Code.ceiling_find_fx_locations(slot)
  if #locs == 0 then return false end
  for _, loc in ipairs(locs) do
    local tr
    if loc.track_idx == "M" then
      tr = reaper.GetMasterTrack(0)
    elseif type(loc.track_idx) == "number" then
      tr = reaper.GetTrack(0, loc.track_idx - 1)
    end
    if tr then
      local muted   = (reaper.GetMediaTrackInfo_Value(tr, "B_MUTE") or 0) > 0.5
      local enabled = reaper.TrackFX_GetEnabled(tr, (loc.fx_idx or 1) - 1)
      if (not muted) and enabled then return true end
    end
  end
  return false
end

-- Diagnose-with-model: attach the JSFX file as an actual attachment and
-- prefill the chat input with a templated diagnostic prompt. Cross-
-- platform via Attach.file (io.open / os.* paths), no shell-out.
function Code.ceiling_diagnose_one(slot)
  local muted = S._ceiling_muted_fx and S._ceiling_muted_fx[slot]
  if not muted or not muted.file then return end

  -- Confirm file still exists before attempting attach (the user could
  -- have deleted it manually since the slot was recorded).
  local f = io.open(muted.file, "rb")
  if not f then
    Log.add_error("Could not read JSFX file for diagnosis: " .. tostring(muted.file))
    return
  end
  f:close()

  -- Use the existing attach pipeline. Attach.file handles read, size
  -- checks, classification, and queue add. Errors land in
  -- S.attach_error and surface in the chat input bar like any other
  -- failed attach.
  local ok = Attach.file(muted.file)
  if not ok then
    -- attach_error already set by Attach.file. User sees it next frame.
    return
  end

  -- Templated diagnostic prompt; user reviews and sends. Keep it short --
  -- the attached file carries the full code; the prompt just tells the
  -- model what we want analyzed.
  local fname = muted.file:match("[^/\\]+$") or muted.file
  S.input_buf = ([[The attached JSFX (%s%s) is muting itself because ReaAssist's safety output ceiling detected sustained signal above the configured ceiling for >50 ms -- a likely runaway-feedback or DSP math bug producing exponential growth. Please analyze the DSP and identify what's wrong.

What's causing the runaway, and what specific change would fix it? Do NOT modify the safety injection blocks (lines marked `// --- ReaAssist output ceiling`); only fix the user-facing DSP code.]]):format(
    fname,
    (muted.desc ~= "" and muted.desc ~= fname)
      and (' -- "' .. muted.desc .. '"') or "")

  -- Drop the entry so a fresh trip on the same slot later re-opens the
  -- popup. Without this, S._ceiling_muted_fx[slot] would still be set
  -- after Diagnose closes the popup, and the next mute on that slot
  -- wouldn't be flagged "newly muted" by the poll loop.
  S._ceiling_muted_fx     = S._ceiling_muted_fx or {}
  S._ceiling_muted_fx[slot] = nil

  -- Close the popup so the user can see the chat with the attachment.
  S._ceiling_alert_pending = false
  S._ceiling_alert_open    = false
end

-- Dispatch one tick of the curl pump. If an overload retry is scheduled and its
-- deadline has passed, re-fire the saved request body. Otherwise, when a
-- request is in flight, throttle-poll the response file (0.1s minimum).
function Loop.pump_curl_or_retry()
  if S.retry_scheduled then
    local now = time_precise()
    if now >= S.retry_fire_time then
      S.retry_scheduled = false
      Code.safe_write(tmp.out, "")
      if S.retry_saved_body then
        local ok, reason = Net.fire_curl(S.retry_saved_body)
        if ok then
          S.status = "waiting"
        else
          if reason ~= "call_cap_exceeded" then
            Log.add_error(
              "The servers are still busy and the automatic retry didn't "
              .. "go through. Please try again in a moment.")
          end
          S.retry_count = 0
          S.retry_max = CFG.MAX_RETRIES
        end
      else
        Log.add_error(
          "The servers are still busy and the automatic retry didn't "
          .. "go through. Please try again in a moment.")
        S.retry_count = 0
        S.retry_max = CFG.MAX_RETRIES
      end
    end
  elseif S.status == "waiting" or S.gemini_tier_pending then
    local now = time_precise()
    if now - S.last_poll_time >= CFG.POLL_THROTTLE then
      S.last_poll_time = now
      Net.try_finish_curl()
    end
  end
end

local function loop()
  if CFG._PRODUCT:lower() ~= CFG.EXT_NS then return end

  -- In-frame ReaImGui context check, one-shot. Mirror of the guard at
  -- the top of Bootstrap.loop -- defense in depth for the case where a
  -- freshly-installed ReaImGui dylib lets the script skip bootstrap
  -- entirely (resources already on disk) and lands directly here.
  if not S.imgui_in_frame_validated then
    if not RA.imgui_in_frame_context_ok() then
      S.script_open = false
      return
    end
    S.imgui_in_frame_validated = true
  end

  Loop.handle_close_signal()
  Loop.handle_dev_signal()

  -- Pump attachment base64 encoding one chunk per frame so large files
  -- don't block the UI thread when the user attaches them. The Send button
  -- stays disabled (via Attach.all_encoded()) until pumping completes.
  if #S.attachments > 0 then Attach.pump_encoding() end

  -- Preferred plugins parameter scan: phase 2 runs one frame after phase 1
  -- so that newly added FX have initialised their parameter lists.
  if pref_plugins.scan.active and pref_plugins.scan.phase == "reading" then
    CTX.pref_plugins_scan_read()
  end
  -- FX cache single-plugin rescan: same deferred pattern.
  if fx_cache_ui.rescan.active and fx_cache_ui.rescan.phase == "reading" then
    CTX.fx_cache_rescan_read()
  end
  Loop.handle_resolve_deep_scan()
  -- Deep FX param scan: resume one coroutine step per frame.
  if deep_scan.active then CTX.pump_deep_scan() end

  -- Refresh the running lock (instance_id|timestamp) once per second. The
  -- staleness detector's tolerance (STALE_LOCK_SECS = 15) makes per-frame
  -- writes redundant, and SetExtState allocates + formats a new string every
  -- call, so throttling drops ~60 unnecessary writes/sec during normal UI use.
  local now_hb = time_precise()
  if not S._last_heartbeat or now_hb - S._last_heartbeat >= 1.0 then
    S._last_heartbeat = now_hb
    reaper.SetExtState(CFG.EXT_NS, "running",
      S.INSTANCE_ID .. "|" .. tostring(now_hb), false)
  end

  Loop.pump_curl_or_retry()
  Loop.handle_ceiling_poll()

  -- Gemini tier auto-retest: armed at startup if the last result was
  -- ambiguous (so persisted tier is nil) and a Google key is configured.
  -- Wait until no other curl is in flight before firing -- the tier test
  -- shares the curl plumbing and would no-op silently otherwise.
  if S.gemini_auto_retest_pending and not S.curl_pid then
    S.gemini_auto_retest_pending = false
    Net.fire_gemini_tier_test()
  end

  -- Deferred key-test: fire_key_test parked here when curl_pid was busy
  -- (typically because the auto-retest tier test was in flight). Re-fire
  -- once curl clears. 30s armed-at ceiling so a stuck pending state
  -- can't trap the queue indefinitely -- surface the failure through
  -- the normal in-flight error path so the user gets a clear message
  -- instead of waiting forever.
  if S.key_test_armed and not S.curl_pid then
    local armed = S.key_test_armed
    if time_precise() - armed.armed_at > 30 then
      S.key_test_armed = nil
      local label   = armed.provider.label
      local prov_id = armed.provider.id
      local short_msg = "Another request was in progress for too long. "
        .. "Try Test API Keys again."
      if #api_keys.test_queue > 0
         and (api_keys.screen == "first_run" or api_keys.screen == "settings") then
        Net.advance_key_test_queue(prov_id, false, short_msg)
      elseif (api_keys.screen == "first_run" or api_keys.screen == "settings") then
        api_keys.key_validating = false
        api_keys.key_error      = short_msg
        api_keys.show_key_error_popup = true
        api_keys.key_error_provider   = label
        api_keys.key_error_detail     = short_msg
        api_keys.key_error_hint       = "Wait for any in-flight request "
          .. "to finish, then try again."
        api_keys.key_error_url        = nil
        api_keys.key_error_url_label  = nil
      else
        Log.add_error(short_msg)
      end
    else
      S.key_test_armed = nil
      Net.fire_key_test(armed.provider)
    end
  end

  -- Gemini cache-create poll runs independently of the main send pipeline
  -- (separate tmp files), so a cache create can complete in parallel with a
  -- user send without interfering with the response parse path.
  if S.gemini_cache_creating then
    local now = time_precise()
    if now - S.last_cache_poll_time >= CFG.POLL_THROTTLE then
      S.last_cache_poll_time = now
      Net.try_finish_gemini_cache_create()
    end
  end

  -- Deferred-kill watchdog: if Cancel was clicked before the launcher finished
  -- writing tmp.pid, retry the kill on every loop tick until the file lands or
  -- the deadline elapses. Cheap (one io.open per frame for ~2s).
  if S.kill_pending then
    Net.try_finish_kill_pending()
  end

  -- Drive the manual feedback uploader: polls in-flight POST exit/status
  -- files and fires the on_done callback when complete. Grouped here with
  -- the other network pollers above. Cheap when no send is in flight
  -- (early-returns on `not in_flight`).
  if Diag.uploader_enabled then Diag.tick() end

  -- Piggyback the once-per-session update check on the first chat-SEND in
  -- this session (transition idle -> waiting), not on the first chat
  -- completion. The reason is purely UX: the manifest fetch plus
  -- incremental SHA verification do real work (CFG.UPDATE_SHA_TIME_BUDGET
  -- per frame, spread across roughly 1-2 seconds total on commodity hardware,
  -- proportionally longer on slower CPUs but with no per-frame stutter). If
  -- that ran AFTER the response was shown, the user would feel subtle
  -- micro-stutters while typing their next message. Running it DURING the
  -- "Thinking..." phase absorbs it into time the user is already waiting,
  -- so by the time the response arrives the verify is usually complete
  -- and the post-response UI stays perfectly smooth.
  --
  -- The check is DEFERRED by CFG.UPDATE_CHECK_DEFER seconds rather than
  -- firing on the very next frame after idle->waiting. The chat curl's
  -- own ExecProcess fires on the send frame and blocks the main thread
  -- for ~1-3 s cold-start of PowerShell; stacking the update-check
  -- ExecProcess (another ~200 ms warm) onto the immediately-following
  -- frame extended the perceived Send-press freeze. Deferring 400 ms
  -- lands the update spawn after PS is warm and after the chat-curl
  -- freeze is fully done, so its 200 ms hitch falls inside "Thinking..."
  -- where the spinner is up and the user expects nothing else to happen.
  -- ExecProcess timeoutmsec must remain >= 0 -- timeoutmsec = -1 (true
  -- async no-wait) flashes a PowerShell/cmd window on Windows because
  -- REAPER's async path skips the hidden-window flag.
  --
  -- _session_check_fired is a session-level guard: it ensures only ONE
  -- piggyback fires per ReaAssist launch. Users who never send a message
  -- can still trigger a check manually via Settings > Check for Updates.
  -- _session_check_armed_at is the time of the idle->waiting edge; the
  -- defer compares against it on each subsequent frame until the budget
  -- elapses, then fires once and clears via _session_check_fired.
  -- check_start itself has a busy guard (Updater.is_busy) so an in-flight
  -- manual check or repair cannot be raced by this trigger.
  if not update._session_check_fired then
    if not update._session_check_armed_at
        and S._prev_status == "idle" and S.status == "waiting" then
      update._session_check_armed_at = time_precise()
    end
    if update._session_check_armed_at
        and (time_precise() - update._session_check_armed_at)
            >= CFG.UPDATE_CHECK_DEFER then
      update._session_check_fired = true
      Updater.check_start()
    end
  end
  S._prev_status = S.status

  -- One-time post-update nudge for power-user prompt overrides. Set by
  -- advance_after_rename when an update changed the stock system prompt
  -- while a custom override was active. Fired once per loop, gated so
  -- the toast appears immediately on launch (not after a chat). The
  -- ExtState is cleared the same frame we read it so the toast never
  -- repeats, even if the user closes the window before the toast fades.
  if not S._prompt_nudge_checked then
    S._prompt_nudge_checked = true
    if reaper.GetExtState(CFG.EXT_NS, "prompt_review_pending") == "1" then
      reaper.DeleteExtState(CFG.EXT_NS, "prompt_review_pending", true)
      UI.show_float_toast(
        "System prompt updated. Your custom override is unchanged; "
        .. "review the new stock prompt for changes worth merging.",
        "ok", true)  -- sticky: stays until replaced or window closes
    end
  end

  -- Auto-update polling (independent of main API pipeline).
  if update.state == "checking" then
    Updater.check_poll()
  elseif update.state == "verifying" then
    -- Dispatch to native-poll or pure-Lua tick based on which mode
    -- start_sha_diff selected (and which mode tick_native_sha may have
    -- since fallen back to). _sha_diff is cleared on completion so the
    -- nil-guard handles the rare "complete-on-this-frame" race.
    local s = update._sha_diff
    if s and s.mode == "native" then
      Updater.tick_native_sha()
    else
      Updater.tick_sha_diff()
    end
  elseif update.state == "downloading" then
    Updater.download_poll()
  elseif update.state == "rename_retry" then
    Updater.rename_retry_poll()
  end
  -- Stage 3.4 auto-restart: fires once after the apply completes and a
  -- short grace window elapses so the user sees the "Applied" message
  -- before the script relaunches itself.
  Updater.try_auto_restart()

  -- Main-window ImGui pipeline: style pushes, ImGui_Begin on the
  -- main window, full chat/settings/popup body (including the
  -- after_main_window first-frame boot-guard label), balancing
  -- PopStyleColor/PopStyleVar/PopFont, and the separate
  -- Update-Available / Repair dialog. Lives in
  -- Resources/UI.lua as Render.main_window so the UI half
  -- owns the draw path. Returns `open` so we can still detect the
  -- window's X button below (outside the visible-block scope).
  local open = Render.main_window()

  -- The open bool (window X button) must be checked OUTSIDE the visible block.
  if not open then S.script_open = false end

  if S.script_open then
    reaper.defer(loop)
  else
    -- Save window geometry for next launch. Skipped after Factory Reset
    -- so freshly-cleared keys don't reappear before the user can verify.
    if update._main_x and not S._suppress_geometry_save then
      reaper.SetExtState(CFG.EXT_NS, "win_x", tostring(math.floor(update._main_x)), true)
      reaper.SetExtState(CFG.EXT_NS, "win_y", tostring(math.floor(update._main_y)), true)
      reaper.SetExtState(CFG.EXT_NS, "win_w", tostring(math.floor(update._main_w)), true)
      reaper.SetExtState(CFG.EXT_NS, "win_h", tostring(math.floor(update._main_h)), true)
    end
    -- Intentional close: clean up ExtState (atexit handles crashes).
    set_toolbar(false)
    -- Only clear "running" if it still belongs to this instance. During
    -- auto-restart the new instance has already claimed the lock; we
    -- don't want to wipe its claim on our way out.
    local current = reaper.GetExtState(CFG.EXT_NS, "running")
    if current:match("^([^|]+)") == S.INSTANCE_ID then
      reaper.DeleteExtState(CFG.EXT_NS, "running", false)
    end
    reaper.DeleteExtState(CFG.EXT_NS, "request_close", false)
    -- Delete any hidden temp tracks still owned by in-flight scans so the
    -- user's project doesn't end with a stray hidden track if they close
    -- mid-scan or a second instance forces this one to exit.
    local _inflight = {}
    if pref_plugins.scan  and pref_plugins.scan.track  then _inflight[#_inflight+1] = pref_plugins.scan.track  end
    if fx_cache_ui.rescan and fx_cache_ui.rescan.track then _inflight[#_inflight+1] = fx_cache_ui.rescan.track end
    if S._fx_inspect_tmp  and S._fx_inspect_tmp.tr     then _inflight[#_inflight+1] = S._fx_inspect_tmp.tr     end
    if deep_scan.tr                                    then _inflight[#_inflight+1] = deep_scan.tr             end
    for _, _tr in ipairs(_inflight) do
      if reaper.ValidatePtr2(0, _tr, "MediaTrack*") then
        pcall(reaper.DeleteTrack, _tr)
      end
    end
    -- Close the Undo + PreventUIRefresh scopes those scans hold open.
    -- See the matching block in atexit (above) for the rationale.
    local _owners = 0
    if pref_plugins.scan  and pref_plugins.scan.track  then _owners = _owners + 1 end
    if fx_cache_ui.rescan and fx_cache_ui.rescan.track then _owners = _owners + 1 end
    if S._fx_inspect_tmp                               then _owners = _owners + 1 end
    local _refreshes = _owners
    if deep_scan._ui_refresh_released then _refreshes = _refreshes - 1 end
    if _refreshes < 0 then _refreshes = 0 end
    for _ = 1, _refreshes do pcall(reaper.PreventUIRefresh, -1) end
    for _ = 1, _owners do
      pcall(reaper.Undo_EndBlock, "ReaAssist: scan (closed at exit)", 0)
    end
  end
end

-- =============================================================================
-- Bootstrap: emergency recovery defer loop
-- =============================================================================
-- Runs in place of the normal loop when critical files are missing
-- (S.bootstrap_active). Uses default font and theme so it can draw
-- without touching Render.*, UI.*, TK.*, or FONT.* (any of which may
-- be nil in this mode) and drives Updater.force_reinstall to pull
-- the manifest files down. Once state reaches "available" or
-- "repair_available", Bootstrap auto-accepts without a user click.

Bootstrap = {}

-- Self-contained newline-aware TextWrapped used by Bootstrap.* render
-- functions. Bootstrap may run with Resources/UI.lua missing or
-- unloadable, in which case UI.text_multiline does not exist; this
-- helper mirrors the no-newline rule (ImGui_TextWrapped corrupts window
-- state when fed a literal \n) without depending on the UI namespace.
local function bootstrap_text_multiline(text)
  local t = tostring(text or "")
  if #t == 0 then ImGui.ImGui_TextWrapped(RA.ctx, " "); return end
  local pos = 1
  while pos <= #t do
    local nl   = t:find("\n", pos, true)
    local line = nl and t:sub(pos, nl - 1) or t:sub(pos)
    if line == "" then
      ImGui.ImGui_Spacing(RA.ctx)
    else
      ImGui.ImGui_TextWrapped(RA.ctx, line)
    end
    if not nl then break end
    pos = nl + 1
  end
end

-- Theme colors lifted from PALETTE_DARK. Bootstrap may run before COL
-- is built, so we duplicate the values rather than reference COL.
local BS_C = {
  WIN_BG     = 0x1A1A1AFF,
  ACCENT     = 0x83BCEBFF,  -- ASSIST ice-blue ("Assist" half of logo)
  ACCENT_DK  = 0x4A7DA8FF,  -- ASSIST_DK darker ice-blue ("Rea" half of logo)
  TEXT       = 0xFFFFFFFF,
  TEXT_DIM   = 0xB0BEC5FF,  -- CARD_HEAD
  TEXT_VDIM  = 0x78909CFF,  -- CARD_DESC
  ERROR      = 0xFF6060FF,
  SUCCESS    = 0x66CC66FF,
  BTN_BG     = 0x37474FFF,
  BTN_HOV    = 0x455A64FF,
  BTN_ACT    = 0x263238FF,
  PRIMARY    = 0x5D809CFF,
  PRIMARY_H  = 0x7A9BB2FF,
  PRIMARY_A  = 0x4A6A80FF,
  FRAME_BG   = 0x363636FF,
  PROG_FILL  = 0x83BCEBFF,
  BORDER     = 0x37474FFF,
}

-- Push the bootstrap window's chrome styles. Returns counts so the
-- matching pop call can balance the stack exactly.
local function bs_push_styles()
  ImGui.ImGui_PushStyleColor(RA.ctx, ImGui.ImGui_Col_WindowBg(),       BS_C.WIN_BG)
  ImGui.ImGui_PushStyleColor(RA.ctx, ImGui.ImGui_Col_TitleBg(),        BS_C.WIN_BG)
  ImGui.ImGui_PushStyleColor(RA.ctx, ImGui.ImGui_Col_TitleBgActive(),  BS_C.WIN_BG)
  ImGui.ImGui_PushStyleColor(RA.ctx, ImGui.ImGui_Col_FrameBg(),        BS_C.FRAME_BG)
  ImGui.ImGui_PushStyleColor(RA.ctx, ImGui.ImGui_Col_Button(),         BS_C.BTN_BG)
  ImGui.ImGui_PushStyleColor(RA.ctx, ImGui.ImGui_Col_ButtonHovered(),  BS_C.BTN_HOV)
  ImGui.ImGui_PushStyleColor(RA.ctx, ImGui.ImGui_Col_ButtonActive(),   BS_C.BTN_ACT)
  ImGui.ImGui_PushStyleColor(RA.ctx, ImGui.ImGui_Col_PlotHistogram(),  BS_C.PROG_FILL)
  ImGui.ImGui_PushStyleColor(RA.ctx, ImGui.ImGui_Col_Border(),         BS_C.BORDER)
  ImGui.ImGui_PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_WindowPadding(), 22, 22)
  ImGui.ImGui_PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_ItemSpacing(),    0, 10)
  ImGui.ImGui_PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_FrameRounding(),  4)
  ImGui.ImGui_PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_FramePadding(),  12, 6)
  return 9, 4  -- color count, var count
end

local function bs_pop_styles(n_color, n_var)
  ImGui.ImGui_PopStyleVar(RA.ctx, n_var)
  ImGui.ImGui_PopStyleColor(RA.ctx, n_color)
end

-- Render the ReaAssist wordmark, centered. Approximates the gradient
-- two-tone wordmark used on the TOS screen (UI.logo) but works inside
-- Bootstrap where UI.lua / RA.bold_font may not be loaded -- "Rea" in
-- the darker blue, "Assist" in the brighter ice-blue, both at the
-- default font at a larger size via PushFont(nil, size).
local function bs_logo()
  ImGui.ImGui_PushFont(RA.ctx, nil, 28)
  local rea_w = ImGui.ImGui_CalcTextSize(RA.ctx, "Rea")
  local ass_w = ImGui.ImGui_CalcTextSize(RA.ctx, "Assist")
  local total_w = rea_w + ass_w
  local win_w = ImGui.ImGui_GetWindowWidth(RA.ctx)
  ImGui.ImGui_SetCursorPosX(RA.ctx,
    math.max(0, math.floor((win_w - total_w) / 2)))
  ImGui.ImGui_TextColored(RA.ctx, BS_C.ACCENT_DK, "Rea")
  ImGui.ImGui_SameLine(RA.ctx, 0, 0)
  ImGui.ImGui_TextColored(RA.ctx, BS_C.ACCENT,    "Assist")
  ImGui.ImGui_PopFont(RA.ctx)
  ImGui.ImGui_Spacing(RA.ctx)
end

-- Centered text helper -- measures the string at the (optionally scaled)
-- font, then positions the cursor so the text is horizontally centered
-- in the window before drawing it. `size` is in pixels; nil means use
-- the current font unchanged.
local function bs_text_center(s, color, size)
  if size then ImGui.ImGui_PushFont(RA.ctx, nil, size) end
  local tw = ImGui.ImGui_CalcTextSize(RA.ctx, s)
  local win_w = ImGui.ImGui_GetWindowWidth(RA.ctx)
  ImGui.ImGui_SetCursorPosX(RA.ctx,
    math.max(0, math.floor((win_w - tw) / 2)))
  if color then
    ImGui.ImGui_TextColored(RA.ctx, color, s)
  else
    ImGui.ImGui_Text(RA.ctx, s)
  end
  if size then ImGui.ImGui_PopFont(RA.ctx) end
end

-- Render a title line with bigger font + accent color (left-aligned).
-- Kept for backward compatibility; new code prefers bs_text_center.
local function bs_title_text(s, color)
  ImGui.ImGui_PushFont(RA.ctx, nil, 20)
  ImGui.ImGui_TextColored(RA.ctx, color or BS_C.ACCENT, s)
  ImGui.ImGui_PopFont(RA.ctx)
end

-- Render the primary action button with accent colors.
local function bs_primary_button(label, w, h)
  ImGui.ImGui_PushStyleColor(RA.ctx, ImGui.ImGui_Col_Button(),         BS_C.PRIMARY)
  ImGui.ImGui_PushStyleColor(RA.ctx, ImGui.ImGui_Col_ButtonHovered(),  BS_C.PRIMARY_H)
  ImGui.ImGui_PushStyleColor(RA.ctx, ImGui.ImGui_Col_ButtonActive(),   BS_C.PRIMARY_A)
  local clicked = ImGui.ImGui_Button(RA.ctx, label, w, h)
  ImGui.ImGui_PopStyleColor(RA.ctx, 3)
  return clicked
end

-- Position the cursor for a centered group of buttons. Use total
-- combined width and call this before placing the first button.
local function bs_center_buttons(total_w)
  local win_w = ImGui.ImGui_GetWindowWidth(RA.ctx)
  ImGui.ImGui_SetCursorPosX(RA.ctx,
    math.max(0, math.floor((win_w - total_w) / 2)))
end

-- Discrete-progress cell row used by both the install minimal popup and
-- the styled repair view. One cell per file, fills ice-blue as each
-- file completes. Caller passes total and done counts; if total is 0
-- the row reserves vertical space but draws nothing (so layout above
-- stays anchored across phase changes).
local function bs_progress_cells(total, done)
  local cell_h  = 10
  local gap     = 3
  local cx, cy  = ImGui.ImGui_GetCursorScreenPos(RA.ctx)
  local avail_w = ImGui.ImGui_GetContentRegionAvail(RA.ctx)
  if total > 0 then
    local cell_w  = math.max(4,
      math.floor((avail_w - (total - 1) * gap) / total))
    local total_w = total * cell_w + (total - 1) * gap
    local start_x = cx + math.floor((avail_w - total_w) / 2)
    local dl      = ImGui.ImGui_GetWindowDrawList(RA.ctx)
    for i = 1, total do
      local x = start_x + (i - 1) * (cell_w + gap)
      local color = (i <= done) and BS_C.ACCENT or BS_C.FRAME_BG
      ImGui.ImGui_DrawList_AddRectFilled(dl, x, cy,
                                         x + cell_w, cy + cell_h,
                                         color, 2)
    end
  end
  ImGui.ImGui_Dummy(RA.ctx, avail_w, cell_h)
end

-- Minimal popup for install-mode success path. The auto-restart in
-- Bootstrap.loop will relaunch ReaAssist a moment after state="done",
-- at which point the real app window opens and this popup vanishes.
-- Small ReaAssist wordmark + "Installing..." status + animated band.
function Bootstrap.render_minimal()
  -- Small wordmark for color / polish. Same two-tone treatment as the
  -- styled installer's bigger version, just smaller.
  ImGui.ImGui_PushFont(RA.ctx, nil, 22)
  local rea_w = ImGui.ImGui_CalcTextSize(RA.ctx, "Rea")
  local ass_w = ImGui.ImGui_CalcTextSize(RA.ctx, "Assist")
  local total_w = rea_w + ass_w
  local win_w = ImGui.ImGui_GetWindowWidth(RA.ctx)
  ImGui.ImGui_SetCursorPosX(RA.ctx,
    math.max(0, math.floor((win_w - total_w) / 2)))
  ImGui.ImGui_TextColored(RA.ctx, BS_C.ACCENT_DK, "Rea")
  ImGui.ImGui_SameLine(RA.ctx, 0, 0)
  ImGui.ImGui_TextColored(RA.ctx, BS_C.ACCENT,    "Assist")
  ImGui.ImGui_PopFont(RA.ctx)
  ImGui.ImGui_Spacing(RA.ctx)

  -- Discrete progress: one cell per file in the download queue. Each
  -- cell turns from dim track-color to ice-blue accent as that file
  -- completes. Updates are pure discrete events tied to real install
  -- progress (not animation), so frame-rate stutter is invisible -- a
  -- skipped repaint just means the next cell-fill happens one frame
  -- later, not jumpily. During pre-download phases (checking /
  -- verifying) the queue isn't built yet; show status text only.
  local status_text  = "Installing..."
  local cells_total  = 0
  local cells_done   = 0

  if update.state == "checking" then
    status_text = "Checking for updates..."
  elseif update.state == "verifying" then
    status_text = "Verifying files..."
  elseif update.state == "downloading" or update.state == "rename_retry" then
    cells_total = #(update.download_queue or {})
    -- download_idx points at the file currently being fetched (1-indexed),
    -- not the count of completed files. Subtract one so the in-flight
    -- file's cell stays empty until it actually lands.
    cells_done  = math.max(0, math.min((update.download_idx or 0) - 1, cells_total))
    status_text = "Downloading..."
  elseif update.state == "done" then
    cells_total = #(update.download_queue or {})
    cells_done  = cells_total
    status_text = "Almost done..."
  end

  bs_text_center(status_text, BS_C.TEXT, 17)
  ImGui.ImGui_Spacing(RA.ctx)
  bs_progress_cells(cells_total, cells_done)
end

function Bootstrap.render_prompt()
  -- The install-mode auto-fire moved to Bootstrap.loop so it triggers
  -- regardless of which view (minimal or styled) is being rendered.
  -- This function only handles the repair-mode prompt now; install mode
  -- shouldn't ever reach here in normal flow (it routes to render_minimal
  -- for success path, render_failed for errors).
  if S.bootstrap_install_mode then
    -- Defensive fallback if dispatch routing changes -- show the
    -- minimal view rather than nothing.
    return Bootstrap.render_minimal()
  end

  -- Repair mode: surface the affected-file list + Repair / Quit buttons.
  -- "Some files need repair" covers all detected issues: missing on disk,
  -- present-but-unreadable (font load errors), and SHA mismatches that
  -- the regular update flow routes here as repair_available.
  bs_text_center("Some Files Need Repair", BS_C.ACCENT, 20)
  ImGui.ImGui_Spacing(RA.ctx)
  bs_text_center(string.format(
    "ReaAssist found %d critical file%s missing, modified, or unreadable.",
    #S.bootstrap_missing,
    #S.bootstrap_missing == 1 and "" or "s"),
    BS_C.TEXT_VDIM)
  ImGui.ImGui_Spacing(RA.ctx)

  -- File list. Two-column bulleted layout to halve vertical space.
  -- Drop the "Resources/" prefix on Resources/ entries (header context
  -- already implies it); other entries (e.g. ReaAssist.lua, README.md)
  -- render unchanged. Bullet char is ASCII; see comment by the items[]
  -- construction below for why.
  local n = #S.bootstrap_missing
  local show_n = math.min(n, 10)
  local items = {}
  for i = 1, show_n do
    local p = S.bootstrap_missing[i]:gsub("^Resources/", "")
    -- ASCII bullet (rather than U+2022) so it renders cleanly even on
    -- Mac/Linux where ImGui's default Proggy font is ASCII-only and
    -- would otherwise show a missing-glyph box.
    items[#items + 1] = "*  " .. p
  end
  local more_line = (n > show_n) and string.format("+ %d more", n - show_n) or nil

  ImGui.ImGui_PushFont(RA.ctx, nil, 12)
  ImGui.ImGui_PushStyleVar(RA.ctx, ImGui.ImGui_StyleVar_ItemSpacing(), 0, 3)

  local rows = math.ceil(#items / 2)
  -- Measure widest entry in each column independently for clean alignment.
  local col_l_w, col_r_w = 0, 0
  for i = 1, rows do
    local w = ImGui.ImGui_CalcTextSize(RA.ctx, items[i])
    if w > col_l_w then col_l_w = w end
  end
  for i = rows + 1, #items do
    local w = ImGui.ImGui_CalcTextSize(RA.ctx, items[i])
    if w > col_r_w then col_r_w = w end
  end
  local col_gap = 30
  local block_w = col_l_w + (col_r_w > 0 and (col_gap + col_r_w) or 0)
  local win_w   = ImGui.ImGui_GetWindowWidth(RA.ctx)
  local block_x = math.max(0, math.floor((win_w - block_w) / 2))
  local right_x = block_x + col_l_w + col_gap

  for r = 1, rows do
    ImGui.ImGui_SetCursorPosX(RA.ctx, block_x)
    ImGui.ImGui_TextColored(RA.ctx, BS_C.TEXT_DIM, items[r])
    local right = items[rows + r]
    if right then
      ImGui.ImGui_SameLine(RA.ctx, right_x, 0)
      ImGui.ImGui_TextColored(RA.ctx, BS_C.TEXT_DIM, right)
    end
  end
  if more_line then
    -- Centered "+ N more" on its own line, in the dimmer color.
    local mw = ImGui.ImGui_CalcTextSize(RA.ctx, more_line)
    ImGui.ImGui_SetCursorPosX(RA.ctx,
      math.max(0, math.floor((win_w - mw) / 2)))
    ImGui.ImGui_TextColored(RA.ctx, BS_C.TEXT_VDIM, more_line)
  end

  ImGui.ImGui_PopStyleVar(RA.ctx, 1)
  ImGui.ImGui_PopFont(RA.ctx)
  -- Extra 15px breathing room between the file list and the action prompt.
  ImGui.ImGui_Dummy(RA.ctx, 0, 15)

  if CFG.UPDATE_BASE_URL == "" then
    bs_text_center("Automatic recovery is not available (update URL not configured).",
                   BS_C.ERROR)
    bs_text_center("Please reinstall ReaAssist manually.", BS_C.TEXT)
    ImGui.ImGui_Spacing(RA.ctx)
    bs_center_buttons(100)
    if ImGui.ImGui_Button(RA.ctx, "Close", 100, 30) then S.script_open = false end
    return
  end

  if update.last_error then
    bs_text_center(string.format("Previous attempt failed (%s):",
                                 tostring(update.last_step or "unknown")),
                   BS_C.ERROR)
    bootstrap_text_multiline(update.last_error)
    ImGui.ImGui_Spacing(RA.ctx)
  end

  bs_text_center("Repair these and any other modified files from the current release?",
                 BS_C.TEXT)
  ImGui.ImGui_Spacing(RA.ctx)

  bs_center_buttons(110 + 12 + 80)
  if bs_primary_button("Repair", 110, 32) then
    update.last_error = nil
    update.last_step  = nil
    -- Bootstrap fast-path: we already have S.bootstrap_missing from the
    -- critical-files check at startup, so check_poll can skip the full
    -- per-file SHA verify (which re-hashes ~5-7s of fonts and Lua
    -- files for nothing -- those files are confirmed missing/broken
    -- already). Only set in repair mode; install mode needs the full
    -- diff because S.bootstrap_missing only covers critical files.
    if not S.bootstrap_install_mode then
      update._bootstrap_repair = true
    end
    Updater.force_reinstall()
  end
  ImGui.ImGui_SameLine(RA.ctx, 0, 12)
  if ImGui.ImGui_Button(RA.ctx, "Quit", 80, 32) then S.script_open = false end
end

function Bootstrap.render_progress()
  local title = S.bootstrap_install_mode and "Setting up ReaAssist" or "Repairing Files"
  bs_text_center(title, BS_C.ACCENT, 20)
  ImGui.ImGui_Spacing(RA.ctx)

  bs_text_center("Downloading...", BS_C.TEXT, 17)
  ImGui.ImGui_Spacing(RA.ctx)

  local idx   = update.download_idx or 0
  local total = #(update.download_queue or {})
  -- idx is the in-flight file's index (1-based); subtract one so the
  -- current file's cell only fills once it actually lands on disk.
  bs_progress_cells(total, math.max(0, math.min(idx - 1, total)))
end

function Bootstrap.render_checking()
  local title = S.bootstrap_install_mode and "Setting up ReaAssist" or "Repairing Files"
  bs_text_center(title, BS_C.ACCENT, 20)
  ImGui.ImGui_Spacing(RA.ctx)

  local status_text = "Checking for updates..."
  if update.state == "verifying" then
    status_text = "Verifying files..."
  end
  bs_text_center(status_text, BS_C.TEXT, 17)
  ImGui.ImGui_Spacing(RA.ctx)

  -- Reserve cell-row space even though we don't have a queue yet, so
  -- the status text above stays anchored when the dispatcher transitions
  -- from "checking" -> "downloading" and the cells become populated.
  bs_progress_cells(0, 0)
end

function Bootstrap.render_done()
  local title = S.bootstrap_install_mode and "Setup Complete" or "Repair Complete"
  bs_text_center(title, BS_C.SUCCESS, 20)
  ImGui.ImGui_Spacing(RA.ctx)

  local n = #(update.applied_files or {})
  local verb = S.bootstrap_install_mode and "Installed" or "Restored"
  bs_text_center(string.format("%s %d file%s successfully.",
                               verb, n, n == 1 and "" or "s"),
                 BS_C.TEXT_DIM)

  local auto_restart_pending = update.restart_after and not update.restart_fired
  if auto_restart_pending then
    bs_text_center("Restarting ReaAssist...", BS_C.TEXT_VDIM)
  else
    bs_text_center(
      S.bootstrap_install_mode
        and "Close and reopen ReaAssist to finish setup."
        or  "Close and reopen ReaAssist to finish the repair.",
      BS_C.TEXT_VDIM)
  end
  ImGui.ImGui_Spacing(RA.ctx)

  bs_center_buttons(100)
  if bs_primary_button("OK", 100, 32) then S.script_open = false end
end

function Bootstrap.render_failed()
  local title = S.bootstrap_install_mode and "Setup Failed" or "Repair Failed"
  bs_text_center(title, BS_C.ERROR, 20)
  ImGui.ImGui_Spacing(RA.ctx)

  if update.last_error then
    bs_text_center(string.format("Step: %s",
                                 tostring(update.last_step or "unknown")),
                   BS_C.TEXT_DIM)
    ImGui.ImGui_Spacing(RA.ctx)
    -- Centered, compact multi-line: skip empty lines (which would
    -- otherwise add Spacing and waste vertical room) and center each
    -- non-empty line individually instead of using TextWrapped's
    -- left-aligned default.
    for line in tostring(update.last_error):gmatch("[^\n]+") do
      bs_text_center(line, BS_C.TEXT)
    end
  end
  ImGui.ImGui_Spacing(RA.ctx)
  bs_text_center("If the problem persists, reinstall ReaAssist manually.",
                 BS_C.TEXT_VDIM)
  ImGui.ImGui_Spacing(RA.ctx)

  bs_center_buttons(100 + 12 + 80)
  if bs_primary_button("Retry", 100, 32) then
    update.last_error = nil
    update.last_step  = nil
    -- Allow install-mode auto-trigger to re-fire on the next prompt pass.
    S.bootstrap_install_fired = false
    -- Repair-mode Retry takes the same fast-path as the Repair button
    -- above (skip the full SHA verify; we already know the broken file
    -- list). Install mode keeps the full diff because S.bootstrap_missing
    -- only covers critical files.
    if not S.bootstrap_install_mode then
      update._bootstrap_repair = true
    end
    Updater.force_reinstall()
  end
  ImGui.ImGui_SameLine(RA.ctx, 0, 12)
  if ImGui.ImGui_Button(RA.ctx, "Close", 80, 32) then S.script_open = false end
end

function Bootstrap.loop()
  -- In-frame ReaImGui context check, one-shot. The init-time preflight
  -- can pass on macOS Tahoe even when the freshly-installed dylib isn't
  -- fully loaded; the failure surfaces on the first in-frame ImGui call
  -- below (SetNextWindowSize). Catching it here lets the user see the
  -- friendly "please restart REAPER" dialog instead of a raw Lua error.
  if not S.imgui_in_frame_validated then
    if not RA.imgui_in_frame_context_ok() then
      S.script_open = false
      return
    end
    S.imgui_in_frame_validated = true
  end

  -- Pump the Update state machine so check_poll / download_poll / retry
  -- all advance during bootstrap recovery. The normal main loop does this
  -- in its dev-signal handler; we do it inline here because the normal
  -- loop never runs in bootstrap mode.
  if update.state == "checking"      then Updater.check_poll()       end
  if update.state == "verifying" then
    local s = update._sha_diff
    if s and s.mode == "native" then Updater.tick_native_sha()
    else                             Updater.tick_sha_diff()
    end
  end
  if update.state == "downloading"   then Updater.download_poll()    end
  if update.state == "rename_retry"  then Updater.rename_retry_poll() end
  -- Auto-accept: in recovery we do not show an "Update Now" confirm step.
  if update.state == "available" or update.state == "repair_available" then
    Updater.download_start()
  end
  Updater.try_auto_restart()

  -- Install-mode auto-fire: kick off Updater.force_reinstall on the
  -- first tick when the state machine hasn't started yet. Lives here
  -- (rather than inside a render function) so it triggers whether we
  -- end up rendering the minimal popup OR the full styled view on a
  -- subsequent failure.
  if S.bootstrap_install_mode and not S.bootstrap_install_fired
     and (not update.state or update.state == "idle") then
    S.bootstrap_install_fired = true
    update.last_error = nil
    update.last_step  = nil
    Updater.force_reinstall()
  end

  -- View selection:
  --   * install-mode + non-failed state + no error -> minimal popup
  --   * install-mode + failed/error                -> full styled view
  --   * repair-mode (any state)                    -> full styled view
  -- Note we also check update.last_error: check_poll's "could not reach
  -- update server" branch sets last_error and reverts state to "idle"
  -- (rather than "failed") -- without checking last_error here, a network
  -- failure would silently leave the minimal popup stuck on "Installing...".
  local use_minimal = S.bootstrap_install_mode
                      and update.state ~= "failed"
                      and not update.last_error

  -- Center on the active monitor, but cache the screen bounds on the
  -- FIRST frame only so the popup doesn't follow the mouse around if
  -- the user moves it to another monitor mid-install. We re-center
  -- within the cached screen each frame (so a minimal -> styled view
  -- size change still recenters), but we never re-read mouse position.
  if not S.bootstrap_screen_bounds then
    local mx, my = reaper.GetMousePosition()
    local x1, y1, x2, y2 = reaper.my_getViewport(
      -10000, -10000, 10000, 10000, mx, my, mx + 1, my + 1, true)
    S.bootstrap_screen_bounds = {x1, y1, x2, y2}
  end
  local sx1, sy1, sx2, sy2 = table.unpack(S.bootstrap_screen_bounds)
  local W = use_minimal and 380 or 580
  local H = use_minimal and 175 or 410
  local px = sx1 + math.floor((sx2 - sx1 - W) / 2)
  local py = sy1 + math.floor((sy2 - sy1 - H) / 2)
  -- Cond_Always so the size + position track view-mode changes (minimal
  -- -> styled on failure). Position uses cached screen bounds so it
  -- doesn't follow the mouse cursor across monitors.
  ImGui.ImGui_SetNextWindowSize(RA.ctx, W, H, ImGui.ImGui_Cond_Always())
  ImGui.ImGui_SetNextWindowPos(RA.ctx,
    math.max(0, px), math.max(0, py), ImGui.ImGui_Cond_Always())
  local n_color, n_var = bs_push_styles()
  local flags = ImGui.ImGui_WindowFlags_NoCollapse()
              + ImGui.ImGui_WindowFlags_NoDocking()
              + ImGui.ImGui_WindowFlags_NoResize()
  -- Minimal popup hides the title bar entirely (no title, no X) -- the
  -- install runs autonomously in 5-15s, no user action expected. The
  -- styled view keeps the title bar so the user can drag/close.
  if use_minimal then
    flags = flags + ImGui.ImGui_WindowFlags_NoTitleBar()
                  + ImGui.ImGui_WindowFlags_NoMove()
  end
  local title = S.bootstrap_install_mode and "ReaAssist Installer" or "ReaAssist Recovery"
  local visible, open = ImGui.ImGui_Begin(RA.ctx, title, true, flags)
  if visible then
    if use_minimal then
      Bootstrap.render_minimal()
    else
      bs_logo()  -- brand wordmark only on the styled view
      -- Route to failed view when EITHER state=failed OR last_error is
      -- set. The latter catches the "manifest_fetch could not reach
      -- update server" case where check_poll sets last_error but
      -- transitions state back to "idle" rather than "failed".
      if update.state == "failed" or update.last_error then
        Bootstrap.render_failed()
      elseif update.state == "downloading" or update.state == "rename_retry" then
        Bootstrap.render_progress()
      elseif update.state == "checking" or update.state == "verifying" then
        Bootstrap.render_checking()
      elseif update.state == "done" then
        Bootstrap.render_done()
      else
        Bootstrap.render_prompt()
      end
    end
  end
  ImGui.ImGui_End(RA.ctx)
  bs_pop_styles(n_color, n_var)

  if not open then S.script_open = false end
  if S.script_open then reaper.defer(Bootstrap.loop) end
end

-- =============================================================================
-- Kick off
-- =============================================================================
-- Normal path runs full startup + registers loop(); recovery path
-- (S.bootstrap_active) registers Bootstrap.loop instead.
if not S.bootstrap_active then
  -- Defer system prompt load to here so a missing/corrupt stock prompt
  -- can route into bootstrap recovery instead of returning from the main
  -- chunk before recovery has a chance to render. A custom-override
  -- failure cannot be repaired (we don't ship the custom file); in that
  -- case load_system_prompt shows a message and we exit cleanly.
  if not load_system_prompt() and not S.bootstrap_active then
    return
  end
end
if S.bootstrap_active then
  -- Bootstrap skips chat/network/scan init - none of it is safe before
  -- the missing files are recovered.
  Bootstrap.loop()
else
  -- Clear any stale response file from a previous run, then start the defer loop.
  Code.safe_write(tmp.out, "")
  -- Auto-assign preferred_types from the fallback chains in Plugin_Ref.md.
  -- Runs at every launch; never overwrites existing user choices. Lets the
  -- Preferred Plugins page reflect the user's best installed plugin per type
  -- (e.g. Pro-Q 4 if installed, else ReEQ, else ReaEQ) and lets preempt
  -- injection fire for type keywords without any configuration.
  Code.ensure_preferred_from_chains()
  -- Restore any persisted Gemini explicit cache from a previous session. No-op
  -- if no cache was persisted, expired, or already nil; if valid, the next
  -- send to Gemini will skip the cache-create round trip.
  local ok_gcr, gcr_err = pcall(Net.gemini_cache_restore)
  if not ok_gcr then
    Log.line("GEMINI", "cache_restore (startup) failed: " .. tostring(gcr_err))
  end
  -- Do NOT fire the update check here. Updater.fire_get launches curl
  -- via PowerShell, and PowerShell's .NET cold start blocks the main
  -- thread for ~1-3s the first time it runs in a REAPER session. From
  -- startup that would paint a white window before the first ImGui
  -- frame renders. Instead loop() piggybacks the check on the first
  -- chat-response completion (see `update._session_check_fired`), by
  -- which point PowerShell is already warm from the chat's own curl
  -- launch and the check's ExecProcess cost is ~200ms (imperceptible).
  -- Users who never send a chat can trigger the check via Settings >
  -- Check for Updates, which routes to Updater.manual_check.
  loop()
end
